INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4980f344-c0de-4e80-babe-4980f3440000', 'Patada de tríceps en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Cable-Tricep-Kickback.gif', '{"- Configuración: Conecte un accesorio de un solo mango a la polea de la máquina de cable. Seleccione un peso apropiado que permita un movimiento controlado. Párese frente a la máquina, agarre el mango con un agarre por debajo y dé un paso atrás. Inclínese ligeramente hacia adelante a la altura de las caderas, manteniendo la espalda recta y el tronco enganchado. Mantenga la parte superior del brazo paralela al torso con el codo doblado a 90 grados.","- Conecte un accesorio de un solo mango a la polea de la máquina de cable.","- Párese frente a la máquina, agarre el mango con la mano hacia abajo y dé un paso atrás.","- Regrese lentamente a la posición inicial con control, permitiendo que el codo se doble nuevamente.","- Inhala mientras regresas a la posición inicial y exhala mientras extiendes el brazo hacia atrás.","- Utilice un peso más ligero para garantizar la técnica adecuada antes de aumentar la resistencia.","- Usar demasiado peso: conduce a una mala forma y reduce la efectividad.","###","- Seleccione un peso adecuado que permita un movimiento controlado.","- Inclínate ligeramente hacia adelante a la altura de las caderas, manteniendo la espalda recta y el core comprometido.","- Repeticiones y respiración: realiza de 10 a 15 repeticiones por serie. Inhala mientras regresas a la posición inicial y exhala mientras extiendes el brazo hacia atrás.","- Ejecución: Extienda el brazo hacia atrás enderezando completamente el codo mientras mantiene la parte superior del brazo inmóvil. Apriete el tríceps en la parte superior del movimiento. Regrese lentamente a la posición inicial con control, permitiendo que el codo se doble nuevamente. Repita el número deseado de repeticiones y cambie de brazo si realiza contragolpes con un solo brazo.","- Extienda el brazo hacia atrás enderezando completamente el codo mientras mantiene la parte superior del brazo inmóvil.","- Aprieta tus tríceps en la parte superior del movimiento.","- Balancear el brazo: reduce la activación del tríceps y convierte el movimiento en un ejercicio basado en el impulso.","- No extenderse completamente: Limita la activación del tríceps y reduce el rango de movimiento.","- Evite utilizar el impulso; centrarse en movimientos controlados.","- Involucre su núcleo para evitar un balanceo excesivo.","### Errores comunes:","- Mantenga la parte superior del brazo paralela al torso con el codo doblado a 90 grados.","- Repita hasta el número deseado de repeticiones y cambie de brazo si realiza contragolpes con un solo brazo.","- Realiza de 10 a 15 repeticiones por serie.","### Consejos para una forma adecuada:","- Mantenga la parte superior del brazo inmóvil para maximizar la participación de los tríceps.","- Mantenga una ligera flexión de las rodillas para mayor estabilidad.","- Redondear la espalda: Provoca tensión innecesaria en la zona lumbar.","- Sostener el mango incorrectamente: Agarrarlo con demasiada fuerza puede generar fatiga en el antebrazo antes de que los tríceps estén completamente trabajados."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0a0ebda7-c0de-4e80-babe-0a0ebda70000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Pike-to-Cobra.gif', '{"comience en una posición de perro boca abajo. Esto es similar a una postura de yoga. Comience con las manos y las rodillas, luego levante las caderas y estire las piernas para formar una V invertida con su cuerpo. Tus manos deben estar separadas al ancho de los hombros y tus pies deben estar separados al ancho de las caderas.","Mueva su peso hacia adelante, bajando la parte superior del cuerpo hacia el suelo mientras mantiene los brazos rectos.","Desde la posición del perro boca abajo, empuja las caderas hacia atrás y hacia arriba, moviéndolas hacia el techo. Tu cabeza debe mirar hacia atrás entre tus piernas.","Posición inicial: comience en una posición de perro boca abajo. Esto es similar a una postura de yoga. Comience con las manos y las rodillas, luego levante las caderas y estire las piernas para formar una V invertida con su cuerpo. Tus manos deben estar separadas al ancho de los hombros y tus pies deben estar separados al ancho de las caderas.","Descenso (fase de bombardero en picado): desplaza tu peso hacia adelante, bajando la parte superior del cuerpo hacia el suelo mientras mantienes los brazos rectos. Continúa avanzando hasta que tu pecho casi toque el suelo. Tus caderas estarán bajas y tu espalda arqueada, asemejándote a una postura de yoga de perro mirando hacia arriba. A medida que desciendes, asegúrate de mirar hacia arriba y hacia adelante, permitiendo que tu cabeza suba y tu espalda se arquee profundamente.","Continúe avanzando hasta que su pecho casi toque el suelo. Tus caderas estarán bajas y tu espalda arqueada, asemejándote a una postura de yoga de perro mirando hacia arriba.","Desde la posición del perro boca abajo, empuja las caderas hacia atrás y hacia arriba, moviéndolas hacia el techo. Su cabeza debe mirar hacia atrás entre sus piernas. A medida que sus caderas se elevan, doble los codos y baje el pecho hasta la posición inicial. Continúe este movimiento hasta que regrese a la posición del perro hacia abajo.","Ascenso: Desde la posición del perro boca abajo, empuja las caderas hacia atrás y hacia arriba, moviéndolas hacia el techo. Su cabeza debe mirar hacia atrás entre sus piernas. A medida que sus caderas se elevan, doble los codos y baje el pecho hasta la posición inicial. Continúe este movimiento hasta que regrese a la posición del perro hacia abajo.","A medida que las caderas se elevan, doble los codos y baje el pecho hasta la posición inicial.","Repetir: repita la secuencia durante el número deseado de repeticiones, manteniendo un flujo suave y controlado entre las diferentes posiciones.","Continúe este movimiento hasta que regrese a la posición del perro boca abajo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('14bf81b4-c0de-4e80-babe-14bf81b40000', 'Encogimiento de hombros', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Dumbbell-Seated-Gittleson-Shrug.gif', '{"Siéntate en un banco o silla con una mancuerna en una mano.","Agarre la parte inferior del banco justo detrás de su cadera con su mano libre (la que no sostiene la mancuerna).","Eleva el hombro hacia la oreja, enfatizando la contracción de los músculos trapecios superiores.","Deje que su hombro lateral cargado baje lo más posible.","Realice el número deseado de repeticiones en un lado antes de cambiar al otro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1c9b4d46-c0de-4e80-babe-1c9b4d460000', 'Fondos', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/parallel-bar-dip.gif', '{"Agarre las barras firmemente con las palmas hacia adentro.","Levanta tu cuerpo del suelo, apoyando tu peso con los brazos.","Colócate entre las barras paralelas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2b00daf7-c0de-4e80-babe-2b00daf70000', 'Extensión de tríceps en máquina', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Triceps-Extension-Machine.gif', '{"Ajuste la altura del asiento de modo que la parte superior de sus brazos descanse cómodamente sobre la almohadilla y los codos se alineen con el punto de giro de la máquina.","Seleccione un peso apropiado que permita un movimiento controlado sin sacrificar la forma."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2a530903-c0de-4e80-babe-2a5309030000', 'Elevación de pantorrillas de pie con mancuernas', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dumbbell-Calf-Raise.gif', '{"Párese erguido con los pies separados a la altura de las caderas, sosteniendo una mancuerna en cada mano, los brazos relajados a los lados, manteniendo una postura y alineación adecuadas.","Descenso controlado: baje gradualmente los talones hasta la posición inicial de forma controlada, asegurando una tensión muscular constante.","Posición inicial: Párese erguido con los pies separados a la altura de las caderas, sosteniendo una mancuerna en cada mano, los brazos relajados a los lados, manteniendo una postura y alineación adecuadas.","Movimiento de elevación: levántese lentamente sobre las puntas de los pies levantando los talones lo más alto posible, contrayendo completamente los músculos de la pantorrilla.","Repetir: realice las repeticiones deseadas, generalmente de 10 a 15 repeticiones por serie, enfatizando los movimientos lentos y controlados.","Alineación y estabilidad: Involucre los músculos centrales para lograr estabilidad, mantenga los hombros hacia atrás y mantenga una alineación neutra de la columna durante todo el movimiento."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('382fac8c-c0de-4e80-babe-382fac8c0000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Pike-to-Cobra.gif', '{"comience en una posición de perro boca abajo. Esto es similar a una postura de yoga. Comience con las manos y las rodillas, luego levante las caderas y estire las piernas para formar una V invertida con su cuerpo. Tus manos deben estar separadas al ancho de los hombros y tus pies deben estar separados al ancho de las caderas.","Mueva su peso hacia adelante, bajando la parte superior del cuerpo hacia el suelo mientras mantiene los brazos rectos.","Desde la posición del perro boca abajo, empuja las caderas hacia atrás y hacia arriba, moviéndolas hacia el techo. Tu cabeza debe mirar hacia atrás entre tus piernas.","Posición inicial: comience en una posición de perro boca abajo. Esto es similar a una postura de yoga. Comience con las manos y las rodillas, luego levante las caderas y estire las piernas para formar una V invertida con su cuerpo. Tus manos deben estar separadas al ancho de los hombros y tus pies deben estar separados al ancho de las caderas.","Descenso (fase de bombardero en picado): desplaza tu peso hacia adelante, bajando la parte superior del cuerpo hacia el suelo mientras mantienes los brazos rectos. Continúa avanzando hasta que tu pecho casi toque el suelo. Tus caderas estarán bajas y tu espalda arqueada, asemejándote a una postura de yoga de perro mirando hacia arriba. A medida que desciendes, asegúrate de mirar hacia arriba y hacia adelante, permitiendo que tu cabeza suba y tu espalda se arquee profundamente.","Continúe avanzando hasta que su pecho casi toque el suelo. Tus caderas estarán bajas y tu espalda arqueada, asemejándote a una postura de yoga de perro mirando hacia arriba.","Desde la posición del perro boca abajo, empuja las caderas hacia atrás y hacia arriba, moviéndolas hacia el techo. Su cabeza debe mirar hacia atrás entre sus piernas. A medida que sus caderas se elevan, doble los codos y baje el pecho hasta la posición inicial. Continúe este movimiento hasta que regrese a la posición del perro hacia abajo.","Ascenso: Desde la posición del perro boca abajo, empuja las caderas hacia atrás y hacia arriba, moviéndolas hacia el techo. Su cabeza debe mirar hacia atrás entre sus piernas. A medida que sus caderas se elevan, doble los codos y baje el pecho hasta la posición inicial. Continúe este movimiento hasta que regrese a la posición del perro hacia abajo.","A medida que las caderas se elevan, doble los codos y baje el pecho hasta la posición inicial.","Repetir: repita la secuencia durante el número deseado de repeticiones, manteniendo un flujo suave y controlado entre las diferentes posiciones.","Continúe este movimiento hasta que regrese a la posición del perro boca abajo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7c2e7dcd-c0de-4e80-babe-7c2e7dcd0000', 'Extensión de tríceps en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Cable-Side-Triceps-Extension.gif', '{"### Paso 1: Configuración y posición inicial","- Párese de lado de la máquina de cable, con el brazo de trabajo más cercano al cable.","- Agarre el mango con un agarre por encima de la cabeza y coloque el codo a la altura del hombro, doblado a 90 grados.","- Coloque la mano opuesta sobre la cadera o el estómago para mayor estabilidad.","- Regrese lentamente a la posición inicial, manteniendo el control en todo momento.","- Usar demasiado peso, comprometer la forma.","- Conecte una empuñadura monomando a una polea de cable alta.","- Extiende tu brazo hacia afuera, enderezando el codo hasta que tu brazo esté completamente extendido.","- Haga una pausa para realizar una breve contracción en la parte superior, apretando el tríceps.","- Mantenga el codo a la altura de los hombros durante todo el movimiento.","### Paso 2: Ejecución","- Utilice un movimiento controlado, evitando el impulso.","- No extienda demasiado el brazo para evitar tensión en las articulaciones.","- No extender completamente el brazo, lo que limita el rango de movimiento.","- Involucre su núcleo para lograr estabilidad.","### Errores comunes a evitar","- Dejar caer el codo, reduciendo la activación del tríceps.","- Mantenga la parte superior del brazo inmóvil, moviendo solo el antebrazo.","- Repita de 8 a 12 repeticiones por brazo, completando de 3 a 4 series.","### Consejos para una forma adecuada","- Asegúrese de que su muñeca permanezca neutral para evitar molestias.","- Depender del impulso, disminuyendo el compromiso muscular.","- Girando el torso, reduciendo la concentración en los tríceps."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2df57366-c0de-4e80-babe-2df573660000', 'Extensión de tríceps con mancuerna', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dumbbell-Triceps-Extension.gif', '{"Elija una mancuerna con un peso manejable.","Párese con los pies separados a la altura de los hombros para mayor estabilidad.","Agarre la mancuerna con ambas manos, colocando las palmas debajo de la placa superior de la mancuerna."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4cc85071-c0de-4e80-babe-4cc850710000', 'Extensión de tríceps de rodillas en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Kneeling-Cable-Extension.gif', '{"Configure la máquina de cable Conecte una barra recta, una barra de curl EZ o una cuerda a la polea alta de una máquina de cable. Seleccione un peso apropiado que permita un movimiento controlado sin comprometer la forma.","Colóquese Arrodíllese en el suelo frente a la máquina de cable, doblando el cuerpo para que los codos queden fijos al banco. Sujete el accesorio con un agarre por encima de la cabeza (con las palmas hacia abajo) y acérquelo a la frente. Mantenga los codos doblados y alineados con los hombros.","Arrodíllate en el suelo frente a la máquina de cable, doblando el cuerpo para que los codos queden fijos al banco.","Agarre el accesorio con las palmas hacia abajo y acérquelo a su frente.","Repetir Realice el número deseado de repeticiones manteniendo la forma adecuada.","Ejecución Involucre su núcleo y estabilice la parte superior de su cuerpo. Extienda los codos hacia adelante empujando el mango o el accesorio de cuerda lejos de su frente hasta que sus brazos estén completamente extendidos. Mantenga la parte superior de los brazos inmóvil mientras mueve solo los antebrazos. Apriete los tríceps al final del movimiento. Regrese lentamente a la posición inicial doblando los codos mientras mantiene el control.","Extienda los codos hacia adelante empujando el mango o la cuerda hacia afuera de su frente hasta que sus brazos estén completamente extendidos.","Aprieta tus tríceps al final del movimiento.","Mantenga la parte superior de los brazos inmóviles mientras mueve solo los antebrazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('46c42185-c0de-4e80-babe-46c421850000', 'Extensión de tríceps de rodillas en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Kneeling-Cable-Extension.gif', '{"Configure la máquina de cable Conecte una barra recta, una barra de curl EZ o una cuerda a la polea alta de una máquina de cable. Seleccione un peso apropiado que permita un movimiento controlado sin comprometer la forma.","Colóquese Arrodíllese en el suelo frente a la máquina de cable, doblando el cuerpo para que los codos queden fijos al banco. Sujete el accesorio con un agarre por encima de la cabeza (con las palmas hacia abajo) y acérquelo a la frente. Mantenga los codos doblados y alineados con los hombros.","Arrodíllate en el suelo frente a la máquina de cable, doblando el cuerpo para que los codos queden fijos al banco.","Agarre el accesorio con las palmas hacia abajo y acérquelo a su frente.","Repetir Realice el número deseado de repeticiones manteniendo la forma adecuada.","Ejecución Involucre su núcleo y estabilice la parte superior de su cuerpo. Extienda los codos hacia adelante empujando el mango o el accesorio de cuerda lejos de su frente hasta que sus brazos estén completamente extendidos. Mantenga la parte superior de los brazos inmóvil mientras mueve solo los antebrazos. Apriete los tríceps al final del movimiento. Regrese lentamente a la posición inicial doblando los codos mientras mantiene el control.","Extienda los codos hacia adelante empujando el mango o la cuerda hacia afuera de su frente hasta que sus brazos estén completamente extendidos.","Aprieta tus tríceps al final del movimiento.","Mantenga la parte superior de los brazos inmóviles mientras mueve solo los antebrazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4bdd2674-c0de-4e80-babe-4bdd26740000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Wall-Push-ups.gif', '{"- Párese frente a una pared, a aproximadamente 2 a 3 pies de distancia, dependiendo de la longitud de su brazo.","- Coloque las manos en la pared a la altura de los hombros y ligeramente más separadas que el ancho de los hombros.","- Empuja con las palmas de las manos para estirar los brazos y regresa a la posición inicial.","- Ajuste la ubicación de las manos: un agarre más amplio enfatiza el pecho, mientras que un agarre más estrecho se enfoca más en los tríceps.","###","- Deténgase cuando su pecho esté aproximadamente a una pulgada de la pared.","- Presionando Phase Empuje con las palmas de las manos para estirar los brazos y regresar a la posición inicial. Mantenga sus movimientos controlados y evite bloquear los codos.","- Fase de descenso Doble lentamente los codos y baje el pecho hacia la pared, manteniendo los codos en un ángulo de 45 grados con respecto al cuerpo. Deténgase cuando su pecho esté aproximadamente a una pulgada de distancia de la pared.","- Doble lentamente los codos y baje el pecho hacia la pared, manteniendo los codos en un ángulo de 45 grados con respecto al cuerpo.","- Aumente gradualmente la dificultad: para progresar, aleje los pies de la pared o haga la transición a flexiones inclinadas o en el piso.","- Respire adecuadamente: inhale mientras desciende y exhale mientras se aleja de la pared.","- Acelerar el movimiento: Realice el ejercicio lentamente y con control para lograr el máximo compromiso muscular.","- Repetir: Realice el número deseado de repeticiones manteniendo una buena forma.","- Combine con otros ejercicios: combine flexiones de pared con otros ejercicios de peso corporal, como sentadillas o estocadas, para un entrenamiento de cuerpo completo.","### Errores comunes a evitar","- Mantenga su cuerpo recto desde la cabeza hasta los talones, involucrando su núcleo para mantener una columna neutral.","- Mantenga sus movimientos controlados y evite bloquear los codos.","### Consejos para una máxima eficacia","- Centrarse en la forma: priorice la buena forma sobre el número de repeticiones para evitar lesiones y maximizar los resultados.","- Codos extendidos: Mantenga los codos en un ángulo de 45 grados para evitar tensiones innecesarias en los hombros.","- No involucrar el núcleo: Mantenga el núcleo apretado para evitar que la parte baja de la espalda se hunda o se arquee.","- Doblar las caderas: mantenga una línea recta desde la cabeza hasta los talones durante todo el movimiento.","- Parado demasiado cerca o demasiado lejos: Colóquese de manera que pueda realizar la flexión cómodamente sin forzar la espalda ni los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('018ca1eb-c0de-4e80-babe-018ca1eb0000', 'Fondos', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/parallel-bar-dip.gif', '{"- Agarre las barras firmemente con las palmas hacia adentro.","- Levanta tu cuerpo del suelo, apoyando tu peso con los brazos.","- Vuelve a subir a la posición inicial estirando los brazos.","- Empújate de nuevo hasta la posición inicial.","- Ajuste su inclinación: la inclinación hacia adelante apunta al pecho; La postura erguida enfatiza los tríceps.","- Utilice asistencia si es necesario: los principiantes pueden usar bandas de resistencia o una máquina de inmersión asistida para desarrollar fuerza.","- Incorporar progresiones: añade peso con un cinturón de fondos o realiza fondos explosivos para aumentar la intensidad.","- Colócate entre las barras paralelas.","- Incline ligeramente el torso hacia adelante con la barbilla doblada y las piernas dobladas hacia atrás.","- Deténgase cuando la parte superior de sus brazos esté paralela al suelo o ligeramente por debajo.","- Baje el cuerpo doblando los codos, manteniéndolos abiertos hacia afuera en un ángulo de aproximadamente 45 grados.","- Baje el cuerpo doblando los codos, manteniéndolos cerca de los costados.","- Controle el ritmo: los movimientos lentos y controlados mejoran la participación muscular y previenen lesiones.","- Calienta adecuadamente: Moviliza tus hombros y muñecas para prepararte para el rango de movimiento requerido.","- Falta de rango completo de movimiento: Evite caídas poco profundas; Baje el cuerpo hasta que la parte superior de sus brazos quede paralela al suelo.","- Movimientos oscilantes o bruscos: realice el ejercicio con movimientos controlados para maximizar la activación muscular y reducir el riesgo de lesiones.","- Ampliando la parte baja de la espalda: Involucre su núcleo para mantener una columna neutral durante todo el movimiento.","- Deténgase cuando la parte superior de sus brazos esté paralela al suelo.","### Errores comunes a evitar","- Mantenga el torso erguido con las piernas estiradas debajo de usted.","### Consejos para una máxima eficacia","- Codos ensanchados excesivamente: Mantenga los codos en un ángulo de aproximadamente 45 grados para los fondos de pecho y cerca de los costados para los fondos de tríceps.","- Ignorar el dolor en las articulaciones: deténgase si siente molestias en los hombros o las muñecas y modifique el ejercicio según sea necesario."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4d6deb84-c0de-4e80-babe-4d6deb840000', 'Extensión de tríceps', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Overhead-Triceps-Extension.gif', '{"Colóquese en la posición adecuada según la variante (de pie para polea, acostado para press francés o sentado).","Alinee las manos con la resistencia y mantenga el abdomen contraído para estabilizar el cuerpo.","Fije los codos cerca de la cabeza o de los costados del cuerpo.","Extienda completamente los codos empujando o presionando la resistencia de forma explosiva.","Sienta la contracción en la parte posterior del brazo al completar la extensión.","Regrese lentamente a la posición inicial flexionando los codos, sintiendo el estiramiento del tríceps.","No abra los codos hacia afuera durante el movimiento.","Evite utilizar el impulso del cuerpo o de los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('432b2161-c0de-4e80-babe-432b21610000', 'Estiramiento de pie', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Triceps-Stretch.gif', '{"Colóquese en la posición adecuada según la variante (de pie para polea, acostado para press francés o sentado).","Alinee las manos con la resistencia y mantenga el abdomen contraído para estabilizar el cuerpo.","Fije los codos cerca de la cabeza o de los costados del cuerpo.","Extienda completamente los codos empujando o presionando la resistencia de forma explosiva.","Sienta la contracción en la parte posterior del brazo al completar la extensión.","Regrese lentamente a la posición inicial flexionando los codos, sintiendo el estiramiento del tríceps.","No abra los codos hacia afuera durante el movimiento.","Evite utilizar el impulso del cuerpo o de los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('40e10737-c0de-4e80-babe-40e107370000', 'Extensión de tríceps con mancuerna', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dumbbell-Triceps-Extension.gif', '{"- Elija una mancuerna con un peso manejable.","- Párese con los pies separados a la altura de los hombros para mayor estabilidad.","- Agarre la mancuerna con ambas manos, colocando las palmas debajo de la placa superior de la mancuerna.","- Involucre sus tríceps y presione la mancuerna hacia arriba hasta la posición inicial.","###","### Paso 1: configuración","### Paso 2: levantar la mancuerna","- Levanta la mancuerna por encima de tu cabeza, manteniendo los brazos completamente extendidos.","- Doble lentamente los codos y baje la mancuerna detrás de la cabeza.","- Tus codos deben estar cerca de tus orejas, apuntando hacia adelante.","- Involucre su núcleo y glúteos para estabilizar su cuerpo.","### Paso 3: Fase de descenso","- Baje el peso hasta que sus antebrazos queden paralelos al suelo o un poco más profundos.","- Mantenga los codos inmóviles y evite que se abran.","- Repita para el número deseado de repeticiones.","### Repeticiones y Series:","- Principiantes: 3 series de 8 a 10 repeticiones","- Intermedio: 3 a 4 series de 10 a 12 repeticiones","- Avanzado: 4 series de 12 a 15 repeticiones","### Paso 4: Fase de prensado","- Extiende completamente los brazos manteniendo la tensión en los tríceps."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('037ea03e-c0de-4e80-babe-037ea03e0000', 'Extensión de tríceps acostado con barra EZ', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Barbell-Bench-Press.gif', '{"- Configuración Acuéstese en un banco plano con los ojos directamente debajo de la barra. Pies apoyados en el suelo, rodillas dobladas a ~90°. Agarre la barra con un agarre ligeramente más ancho que el ancho de los hombros (muñecas apiladas sobre los codos). Retraiga y presione las escápulas para estabilizar la parte superior de la espalda. Mantenga un arco natural en la parte baja de la espalda.","- Acuéstese en un banco plano con los ojos directamente debajo de la barra.","- Agarre la barra con un agarre ligeramente más ancho que el ancho de los hombros (las muñecas apiladas sobre los codos).","- Pies apoyados en el suelo, rodillas dobladas a ~90°.","- Retraiga y presione las escápulas para estabilizar la parte superior de la espalda.","- Empuja la barra hacia arriba formando un ligero arco hacia tus ojos.","- Exhala mientras avanzas por el pecho y los tríceps, bloqueando los codos en la parte superior.","- No ensanche excesivamente los codos; apunte a una distancia de entre 45° y 60° del cuerpo.","- Desmontar y descender Desmontar la barra y llevarla sobre el pecho, con los codos completamente extendidos. Inhale, contraiga el core y baje la barra lentamente hasta la parte inferior del pecho (alrededor del nivel de los pezones), manteniendo los codos a ~45° del torso.","- Retire la barra y colóquela sobre su pecho, con los codos completamente extendidos.","- Inhale, contraiga su núcleo y baje la barra lentamente hasta la parte inferior de su pecho (alrededor del nivel del pezón), manteniendo los codos a ~45° del torso.","- Presione Phase Empuje la barra hacia arriba formando un ligero arco hacia sus ojos. Exhale mientras avanza por el pecho y los tríceps, bloqueando los codos en la parte superior.","- Bajar la barra bajo control; no lo rebotes contra el cofre.","### Errores comunes a evitar","- Dejar que los codos se ensanchen demasiado, lo que aumenta la tensión en la articulación del hombro.","- Levantando los pies del suelo, reduciendo la estabilidad de la base.","- Mantenga un arco natural en la parte baja de la espalda.","- Reiniciar y repetir Mantenga la tensión en la parte superior de la espalda y repita las repeticiones prescritas.","- Mantenga la tensión superior de la espalda y repita las repeticiones prescritas.","### Consejos para una forma adecuada","- Mantenga los omóplatos retraídos durante todo el levantamiento para una mejor estabilidad de las articulaciones.","- Mantenga un impulso firme de los glúteos y las piernas para anclar su base.","- Mantenga la alineación de la muñeca neutral para evitar tensiones.","- Permitir que la parte baja de la espalda se arquee excesivamente, con el riesgo de sufrir estrés lumbar.","- Hacer rebotar la barra contra el pecho para ganar impulso.","- Ruta de barra inconsistente, lo que reduce la eficiencia mecánica."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0b9983ce-c0de-4e80-babe-0b9983ce0000', 'Extensión de tríceps acostado en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Cable-Lying-Triceps-Extensions.gif', '{"- Configure el equipo Conecte una barra recta o una barra EZ-curl a una máquina de cable de polea baja. Coloque un banco plano a unos pocos pies de distancia de la pila de cables.","- Conecte una barra recta o una barra EZ-curl a una máquina de cable de polea baja.","- Coloque un banco plano a unos metros de distancia de la pila de cables.","- Posición inicial Acuéstese en el banco con los pies plantados en el suelo. Agarre la barra con un agarre por encima del ancho de los hombros y extienda los brazos de modo que la barra quede por encima de la frente. Mantenga los codos ligeramente doblados pero bloqueados en su posición.","- Acuéstese en el banco con los pies apoyados en el suelo.","- Extiende tus brazos nuevamente a la posición inicial empujando la barra hacia arriba, contrayendo completamente los tríceps.","- Uso de peso excesivo, lo que provoca una forma inadecuada y riesgo de lesiones.","- Levantar las caderas del banco, lo que puede causar inestabilidad y disminuir la concentración en los tríceps.","###","- Agarre la barra con un agarre por encima de los hombros y extienda los brazos para que la barra quede por encima de su frente.","- Mantenga los codos ligeramente doblados pero bloqueados en su posición.","- Una vez que alcance un ángulo de 90 grados en los codos, haga una pausa breve.","- Ejecución Baje lentamente la barra hacia la frente o ligeramente detrás de ella doblando los codos. Mantenga la parte superior de los brazos inmóviles mientras activa los tríceps. Una vez que alcance un ángulo de 90 grados en los codos, haga una pausa breve. Extienda los brazos hasta la posición inicial empujando la barra hacia arriba, contrayendo completamente los tríceps.","- Baje lentamente la barra hacia su frente o ligeramente detrás de ella doblando los codos.","- Utilice un movimiento controlado para evitar el impulso y la tensión innecesaria en las articulaciones.","- Involucre su núcleo para estabilizar su cuerpo durante todo el movimiento.","- Baje el peso lentamente y bajo control, asegurando un rango de movimiento completo.","- Acelerar el movimiento, reducir el tiempo bajo tensión y efectividad.","- Repeticiones y series Realice de 3 a 4 series de 8 a 12 repeticiones, dependiendo de sus objetivos de entrenamiento.","- No bloquee los codos en la parte superior para evitar una tensión excesiva en las articulaciones.","### Errores comunes a evitar","- Mantenga la parte superior de los brazos inmóviles mientras ejercita los tríceps.","- Realiza de 3 a 4 series de 8 a 12 repeticiones, dependiendo de tus objetivos de entrenamiento.","### Consejos para una forma adecuada","- Mantenga los codos estacionarios para maximizar la activación de los tríceps.","- Ensanchar los codos hacia afuera, lo que reduce el compromiso de los tríceps y genera tensión en los hombros.","- Permitir que la barra se mueva demasiado hacia adelante, lo que aleja la tensión del tríceps."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4701e1f1-c0de-4e80-babe-4701e1f10000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Diamond-Push-up.gif', '{"### Paso 1: Configuración y posición inicial","- Comience en una posición de tabla alta, manteniendo las manos directamente debajo del pecho.","- Presione hacia atrás hasta la posición inicial extendiendo los brazos completamente.","###","- Junte las manos formando un diamante con los dedos pulgar e índice.","- Bájate hasta que tu pecho casi toque tus manos.","- No ensanches los codos; manténgalos escondidos cerca de sus costados.","### Paso 2: Ejecución","- Baje su pecho hacia la forma de diamante formada por sus manos.","- Baje lentamente para mantener el control y maximizar la participación de los músculos.","- Respira adecuadamente, inhalando mientras bajas y exhalando mientras empujas hacia arriba.","- Rango de movimiento incompleto, lo que limita el desarrollo muscular.","### Errores comunes a evitar","- Caderas caídas o levantar demasiado el trasero, lo que compromete el compromiso central.","- Codos ensanchados, lo que reduce la activación de los tríceps y aumenta la tensión en los hombros.","- Mantenga su cuerpo en línea recta desde la cabeza hasta los talones, involucrando su núcleo y glúteos para mantener la estabilidad.","- Mantenga los codos cerca del cuerpo para maximizar la participación de los tríceps.","- Repita de 3 a 4 series de 10 a 15 repeticiones, dependiendo de su nivel de fuerza.","### Consejos para una forma adecuada","- Mantenga su núcleo apretado para evitar que sus caderas se caigan.","- Mantenga una columna neutra para evitar tensiones innecesarias en la espalda.","- Moverse demasiado rápido, lo que reduce la tensión muscular y la efectividad.","- Manos demasiado separadas, lo que desvía la atención del tríceps."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7ce0c908-c0de-4e80-babe-7ce0c9080000', 'Postura de yoga', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Tiger-Yoga-Pose.gif', '{"Colóquese en la posición adecuada según la variante (de pie para polea, acostado para press francés o sentado).","Alinee las manos con la resistencia y mantenga el abdomen contraído para estabilizar el cuerpo.","Fije los codos cerca de la cabeza o de los costados del cuerpo.","Extienda completamente los codos empujando o presionando la resistencia de forma explosiva.","Sienta la contracción en la parte posterior del brazo al completar la extensión.","Regrese lentamente a la posición inicial flexionando los codos, sintiendo el estiramiento del tríceps.","No abra los codos hacia afuera durante el movimiento.","Evite utilizar el impulso del cuerpo o de los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('48630712-c0de-4e80-babe-486307120000', 'Extensión de tríceps sentado con mancuernas', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Seated-Dumbbell-Triceps-Extension.gif', '{"### Paso 1: Configuración y posición inicial","- Siéntese en un banco con respaldo para garantizar la estabilidad.","- Sostenga una mancuerna con ambas manos, agarrando el peso por la placa superior o el mango.","- Involucra tus tríceps para empujar la mancuerna de regreso a la posición inicial.","- Usar peso excesivo, lo que lleva a un control deficiente y posibles lesiones.","- Levanta la mancuerna por encima de tu cabeza, extendiendo completamente los brazos.","- Involucre su núcleo para mayor estabilidad.","- No bloquees los codos en la parte superior, ya que esto puede causar tensión en las articulaciones.","### Paso 2: Ejecución","- Baje lentamente la mancuerna detrás de su cabeza doblando los codos.","- Baje la mancuerna hasta que sus codos alcancen un ángulo de 90 grados.","- Baje la mancuerna de forma controlada para evitar tensiones innecesarias en los codos.","- Acelerar el movimiento, reduciendo el tiempo bajo tensión de los músculos.","### Errores comunes a evitar","- Ensanchar los codos hacia afuera, lo que reduce la activación de los tríceps.","- Redondear la espalda, lo que puede provocar molestias en la zona lumbar.","- Mantenga la parte superior de los brazos inmóviles mientras permite que los antebrazos se muevan.","- Repita de 8 a 12 repeticiones durante 3 a 4 series.","### Consejos para una forma adecuada","- Mantenga los codos cerca de la cabeza para asegurar el compromiso de los tríceps.","- Mantenga una columna neutra para evitar la tensión en la zona lumbar.","- No extender completamente los brazos en la parte superior, limitando la efectividad del ejercicio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('18581d8b-c0de-4e80-babe-18581d8b0000', 'Fondos', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Dips-Between-Chairs.gif', '{"- Coloque las sillas Coloque las sillas paralelas entre sí, ligeramente más separadas que el ancho de los hombros.","- Coloque las sillas paralelas entre sí, ligeramente más separadas que el ancho de los hombros.","- Posición inicial: Párese entre las sillas y coloque las manos en los bordes de los asientos de las sillas. Levante los pies del suelo y extienda las piernas hacia adelante, manteniéndolas rectas o ligeramente dobladas.","- Párese entre las sillas y coloque las manos en los bordes de los asientos de las sillas.","- Empuje hacia arribaPresione con las manos para extender los brazos y volver a la posición inicial. Evite bloquear los codos en la parte superior.","- Presione con las manos para extender los brazos y volver a la posición inicial.","- Agarre: Sujete los bordes de la silla con firmeza pero sin tensión excesiva en las muñecas.","- Levanta los pies del suelo y extiende las piernas hacia adelante manteniéndolas rectas o ligeramente flexionadas.","- Baje el cuerpo Doble lentamente los codos y baje el cuerpo hasta que la parte superior de los brazos quede paralela al suelo. Mantenga los codos cerca del torso y evite abrirlos hacia afuera.","- Repetir Realice de 8 a 12 repeticiones durante 3 a 4 series, manteniendo la forma adecuada.","- Doble lentamente los codos y baje el cuerpo hasta que la parte superior de los brazos quede paralela al suelo.","- Controle el movimiento: concéntrese en movimientos lentos y deliberados de bajar y presionar.","- Profundidad: baje el cuerpo sólo hasta donde la flexibilidad de sus hombros lo permita.","- Realice de 8 a 12 repeticiones durante 3 a 4 series, manteniendo la forma adecuada.","### Errores comunes","- Elija sillas resistentes Utilice dos sillas estables con asientos firmes. Asegúrese de que no se deslicen ni se vuelquen durante el ejercicio.","- Utilice dos sillas estables con asientos firmes. Asegúrese de que no se deslicen ni se vuelquen durante el ejercicio.","- Mantenga los codos cerca del torso y evite abrirlos hacia afuera.","- Evite bloquear los codos en la parte superior.","### Consejos para una forma adecuada","- Involucre su núcleo: mantenga sus abdominales contraídos para estabilizar su cuerpo.","- Mantenga la alineación: evite inclinarse demasiado hacia adelante o hacia atrás; mantenga el torso erguido.","- Uso de sillas inestables: asegúrese de que las sillas sean resistentes y seguras para evitar accidentes.","- Codos ensanchados: Mantenga los codos cerca del cuerpo para evitar tensión en los hombros.","- Caderas caídas: mantenga una línea recta desde la cabeza hasta los pies; no dejes caer tus caderas.","- Profundidad excesiva: Bajar demasiado puede estirar demasiado los hombros y provocar lesiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('41bf0c16-c0de-4e80-babe-41bf0c160000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Run-in-Place-exercise.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('14c4dbef-c0de-4e80-babe-14c4dbef0000', 'Fondos', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/CHAIR-DIPS.gif', '{"- Configure la posición Busque una silla o banco resistente que pueda soportar el peso de su cuerpo. Siéntese en el borde de la silla y separe las manos a la altura de los hombros, agarrando el borde del asiento con los dedos mirando hacia adelante.","- Busque una silla o banco resistente que pueda soportar su peso corporal.","- Siéntese en el borde de la silla y separe las manos a la altura de los hombros, agarrando el borde del asiento con los dedos hacia adelante.","- Posición inicial Extienda las piernas frente a usted, manteniendo los talones en el suelo. Deslice las caderas fuera de la silla mientras sostiene su peso con los brazos.","- Desliza las caderas fuera de la silla mientras soportas tu peso con los brazos.","- Haga una breve pausa en la parte inferior, luego empuje con las palmas de las manos para extender los brazos y volver a la posición inicial.","###","- Extiende las piernas frente a ti, manteniendo los talones en el suelo.","- Repeticiones y series Realice de 3 a 4 series de 10 a 15 repeticiones, dependiendo de su nivel de condición física.","- Controle el movimiento en lugar de apresurarse en las repeticiones para evitar lesiones.","- Involucre su núcleo para estabilizar su cuerpo durante todo el ejercicio.","- Ejecución Baje lentamente el cuerpo doblando los codos hasta que alcancen un ángulo de 90 grados. Mantenga la espalda cerca de la silla y evite abrir los codos hacia afuera. Haga una breve pausa en la parte inferior, luego empuje con las palmas de las manos para extender los brazos y volver a la posición inicial.","- Baje lentamente el cuerpo doblando los codos hasta que alcancen un ángulo de 90 grados.","- No bloquee completamente los codos en la parte superior para evitar tensión en las articulaciones.","### Errores comunes a evitar","- Ensanchar los codos hacia afuera, lo que reduce la activación de los tríceps y aumenta la tensión en los hombros.","- Usar una silla débil o inestable, lo que puede resultar inseguro y provocar lesiones.","- Mantenga la espalda pegada a la silla y evite extender los codos hacia afuera.","- Realiza de 3 a 4 series de 10 a 15 repeticiones, dependiendo de tu nivel de condición física.","### Consejos para una forma adecuada","- Mantenga los codos doblados para maximizar la participación de los tríceps y reducir la tensión en los hombros.","- Mantenga el torso recto sin inclinarse excesivamente hacia adelante.","- Bajar demasiado rápido aumenta el riesgo de sufrir lesiones en el hombro o el codo.","- No profundizar lo suficiente, lo que limita la eficacia del ejercicio.","- Colocar las manos demasiado separadas reduce el compromiso de los tríceps."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1839dca5-c0de-4e80-babe-1839dca50000', 'Extensión de tríceps de rodillas en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Kneeling-Cable-Extension.gif', '{"- Configure la máquina de cable Conecte una barra recta, una barra de curl EZ o una cuerda a la polea alta de una máquina de cable. Seleccione un peso apropiado que permita un movimiento controlado sin comprometer la forma.","- Conecte una barra recta, una barra de curl EZ o una cuerda a la polea alta de una máquina de cable.","- Colóquese Arrodíllese en el suelo frente a la máquina de cable, doblando el cuerpo para que los codos queden fijos al banco. Sujete el accesorio con un agarre por encima de la cabeza (con las palmas hacia abajo) y acérquelo a la frente. Mantenga los codos doblados y alineados con los hombros.","- Arrodíllate en el suelo frente a la máquina de cable, doblando el cuerpo para que los codos queden fijos al banco.","- Agarre el accesorio con las palmas hacia abajo y acérquelo a su frente.","- Regrese lentamente a la posición inicial doblando los codos mientras mantiene el control.","- Usar peso excesivo, lo que lleva a un control deficiente y una forma inadecuada.","- Seleccione un peso apropiado que permita un movimiento controlado sin comprometer la forma.","- Involucre su núcleo y estabilice la parte superior de su cuerpo.","- Repetir Realice el número deseado de repeticiones manteniendo la forma adecuada.","- Realice el número deseado de repeticiones manteniendo la forma adecuada.","- Ejecución Involucre su núcleo y estabilice la parte superior de su cuerpo. Extienda los codos hacia adelante empujando el mango o el accesorio de cuerda lejos de su frente hasta que sus brazos estén completamente extendidos. Mantenga la parte superior de los brazos inmóvil mientras mueve solo los antebrazos. Apriete los tríceps al final del movimiento. Regrese lentamente a la posición inicial doblando los codos mientras mantiene el control.","- Extienda los codos hacia adelante empujando el mango o la cuerda hacia afuera de su frente hasta que sus brazos estén completamente extendidos.","- Aprieta tus tríceps al final del movimiento.","- Utilice un tempo controlado, asegurando movimientos suaves durante todo el ejercicio.","- Extienda completamente los brazos sin bloquear los codos para evitar tensión en las articulaciones.","- Apresurarse en el movimiento, en lugar de centrarse en un movimiento lento y controlado.","- Mantenga los codos en una posición fija para asegurar la activación completa de los tríceps.","- Evite utilizar el impulso o balancear el peso para completar el movimiento.","### Errores comunes a evitar","- Ensanchar los codos hacia afuera, lo que reduce el compromiso de los tríceps y puede tensar los hombros.","- Mantenga los codos doblados y alineados con los hombros.","- Mantenga la parte superior de los brazos inmóviles mientras mueve solo los antebrazos.","### Consejos para una forma adecuada","- Involucre su núcleo y mantenga la espalda recta para mantener la estabilidad.","- No extender completamente los brazos, limitando la efectividad del ejercicio.","- Inclinarse demasiado hacia adelante, lo que reduce el aislamiento del tríceps."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('418dd044-c0de-4e80-babe-418dd0440000', 'Curl martillo sentado', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Seated-Hammer-Curl.gif', '{"Siéntese en un banco o silla con los pies apoyados en el suelo y sostenga una mancuerna en cada mano con un agarre neutral (martillo), con las palmas una frente a la otra.","Levanta lentamente las mancuernas hacia tus hombros flexionando los codos, manteniendo las muñecas y los antebrazos en una posición neutral.","Mantenga los codos cerca de los costados y active el núcleo para mantener una posición estable.","Haga una pausa por un momento en la parte superior del movimiento y luego baje lentamente las mancuernas hasta la posición inicial.","Repeat for the desired number of repetitions, maintaining control and avoiding swinging the weights or using momentum."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6a627179-c0de-4e80-babe-6a6271790000', 'Curl de bíceps sentado con mancuernas', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/06/Seated-dumbbell-alternating-curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6aad0343-c0de-4e80-babe-6aad03430000', 'Curl concentrado en polea', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Cable-Concentration-Curl.gif', '{"Configure la máquina de cable: conecte una manija única a una polea baja en la máquina de cable.","Siéntate en un banco: Siéntate en un banco con los pies apoyados en el suelo y las piernas separadas a la altura de los hombros. Coloque el codo del brazo que trabaja en la parte interna del muslo, con la palma hacia arriba.","Agarre el mango del cable: Sujete el mango del cable con la palma hacia arriba y deje que el brazo cuelgue hacia abajo, completamente extendido.","Doble el mango: Manteniendo la parte superior del brazo inmóvil, exhale y doble el mango del cable hacia su hombro mientras mantiene un agarre firme sobre el mango. Mantenga la muñeca recta y concéntrese en contraer los músculos bíceps.","Baje el mango: Inhale y baje lentamente el mango hasta la posición inicial, manteniendo la parte superior del brazo inmóvil durante todo el movimiento.","Repetir: Complete el número deseado de repeticiones con un brazo antes de cambiar al otro brazo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4fb9f7e3-c0de-4e80-babe-4fb9f7e30000', 'Curl de bíceps con barra', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/09/Barbell-Finger-Curl.gif', '{"Sujete el peso (mancuerna, barra o polea) con un agarre supino (palmas hacia arriba).","Mantenga los pies separados al ancho de los hombros y las rodillas ligeramente flexionadas.","Coloque los codos pegados a los costados del torso y mantenga la espalda recta.","Manteniendo inmóvil la parte superior de los brazos, flexione los codos y eleve la carga hacia los hombros.","Apriete fuertemente los bíceps en el punto de máxima contracción por un segundo.","Baje el peso de forma controlada y lenta hasta extender completamente los brazos.","Evite balancear la espalda o mover los hombros hacia adelante para ayudarse.","Mantenga las muñecas firmes y rectas durante todo el recorrido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('51c6dfcc-c0de-4e80-babe-51c6dfcc0000', 'Press declinado con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Decline-Dumbbell-Press.gif', '{"- Coloque un banco inclinado en un ángulo de 15 a 30 grados.","- Coge un par de mancuernas y siéntate en el banco con los pies asegurados debajo de las almohadillas de apoyo.","- Centrarse en la forma: priorice la forma adecuada sobre los pesos pesados ​​para maximizar la efectividad y la seguridad.","- Peso excesivo: usar demasiado peso puede comprometer la forma y aumentar el riesgo de lesiones.","###","- Recuéstese con las mancuernas sostenidas al nivel de los hombros, las palmas hacia adelante y los codos doblados en un ángulo de aproximadamente 90 grados.","- Baje lentamente: Inhale mientras baja las mancuernas a la posición inicial, manteniendo el control y asegurándose de que los codos permanezcan ligeramente por debajo del nivel del pecho para un estiramiento profundo.","- Presione hacia arriba: exhale mientras presiona las mancuernas hacia arriba con un movimiento suave y controlado hasta que sus brazos estén completamente extendidos (pero no bloqueados).","- Aprieta en la parte superior: contrae los músculos del pecho en el punto máximo del movimiento para un compromiso óptimo.","- Repeticiones apresuradas: realice el movimiento lentamente para maximizar el control y el compromiso.","- Tempo controlado: utilice un ritmo lento y controlado para mantener la tensión en los músculos del pecho.","- Combínelo con press inclinado y plano: combínelo con otras variaciones de press de banca para un desarrollo completo del pecho.","### Errores comunes","- Repita hasta el número deseado de repeticiones.","### Consejos para la eficacia","- Codos ensanchados: Mantenga los codos en un ángulo de 45 grados para reducir la tensión en los hombros.","- Ángulo de banco incorrecto: asegúrese de que el ángulo de descenso no sea demasiado pronunciado, ya que esto puede reducir la activación del pecho y generar una tensión indebida en los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('75a42851-c0de-4e80-babe-75a428510000', 'Curl de bíceps unilateral con banda de resistencia', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/One-Arm-Biceps-Curl.gif', '{"Sujete el peso (mancuerna, barra o polea) con un agarre supino (palmas hacia arriba).","Mantenga los pies separados al ancho de los hombros y las rodillas ligeramente flexionadas.","Coloque los codos pegados a los costados del torso y mantenga la espalda recta.","Manteniendo inmóvil la parte superior de los brazos, flexione los codos y eleve la carga hacia los hombros.","Apriete fuertemente los bíceps en el punto de máxima contracción por un segundo.","Baje el peso de forma controlada y lenta hasta extender completamente los brazos.","Evite balancear la espalda o mover los hombros hacia adelante para ayudarse.","Mantenga las muñecas firmes y rectas durante todo el recorrido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7a5ce7f6-c0de-4e80-babe-7a5ce7f60000', 'Curl de bíceps en máquina', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Bicep-Curl-Machine.gif', '{"Sujete el peso (mancuerna, barra o polea) con un agarre supino (palmas hacia arriba).","Mantenga los pies separados al ancho de los hombros y las rodillas ligeramente flexionadas.","Coloque los codos pegados a los costados del torso y mantenga la espalda recta.","Manteniendo inmóvil la parte superior de los brazos, flexione los codos y eleve la carga hacia los hombros.","Apriete fuertemente los bíceps en el punto de máxima contracción por un segundo.","Baje el peso de forma controlada y lenta hasta extender completamente los brazos.","Evite balancear la espalda o mover los hombros hacia adelante para ayudarse.","Mantenga las muñecas firmes y rectas durante todo el recorrido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('30bcdd09-c0de-4e80-babe-30bcdd090000', 'Fondos', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/11/Asisted-Triceps-Dips.gif', '{"### Paso 1: configurar la máquina","- Ajuste el peso de asistencia en la máquina. Cuanto mayor sea la asistencia, más fácil será el ejercicio.","- Sube a la plataforma y agarra las barras de inmersión paralelas con un agarre neutral (con las palmas hacia adentro).","- Coloque las rodillas o los pies sobre la almohadilla, según el diseño de la máquina.","### Paso 2: Posición inicial","- Agarre las barras firmemente con los brazos completamente extendidos.","- Empuja con las palmas de las manos para extender los brazos y llevar el cuerpo a la posición inicial.","### Paso 3: Fase de descenso","- Desciende hasta que la parte superior de tus brazos quede paralela al suelo o ligeramente por debajo.","- Baje lentamente el cuerpo doblando los codos mientras los mantiene doblados.","- Concéntrate en involucrar tus tríceps durante el movimiento ascendente.","### Paso 4: Fase de prensado","- Mantenga una postura erguida con el pecho erguido y el core comprometido.","- Mantenga los codos cerca del cuerpo para apuntar eficazmente a los tríceps.","- Mantenga los hombros estables y evite encogerse de hombros.","- Evite bloquear los codos en la parte superior para mantener la tensión muscular.","### Paso 5: repita para las repeticiones deseadas","- Realice de 3 a 4 series de 8 a 15 repeticiones, ajustando la asistencia según sea necesario."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('01fc44ed-c0de-4e80-babe-01fc44ed0000', 'Curl de bíceps unilateral', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/One-Arm-Biceps-Curl-1.gif', '{"Sujete el peso (mancuerna, barra o polea) con un agarre supino (palmas hacia arriba).","Mantenga los pies separados al ancho de los hombros y las rodillas ligeramente flexionadas.","Coloque los codos pegados a los costados del torso y mantenga la espalda recta.","Manteniendo inmóvil la parte superior de los brazos, flexione los codos y eleve la carga hacia los hombros.","Apriete fuertemente los bíceps en el punto de máxima contracción por un segundo.","Baje el peso de forma controlada y lenta hasta extender completamente los brazos.","Evite balancear la espalda o mover los hombros hacia adelante para ayudarse.","Mantenga las muñecas firmes y rectas durante todo el recorrido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5e8ee291-c0de-4e80-babe-5e8ee2910000', 'Curl concentrado', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Concentration-Curl.gif', '{"Siéntate en un banco o silla con los pies apoyados en el suelo y una mancuerna en una mano.","Coloque el codo en la parte interna del muslo, con el brazo completamente extendido y la mancuerna colgando hacia abajo.","Haga una pausa en la parte superior del movimiento, luego baje lentamente el peso hasta la posición inicial.","Doble el peso hacia el hombro, manteniendo el codo inmóvil y la parte superior del brazo presionada contra el muslo.","Repita hasta el número deseado de repeticiones, luego cambie al otro brazo y repita."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('11b4b4ce-c0de-4e80-babe-11b4b4ce0000', 'Curl de bíceps en polea', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/cable-curl.gif', '{"El curl con cable es un ejercicio de aislamiento para el músculo bíceps. Es una acción de tracción que se realiza con una máquina de cable y es apta para principiantes.","El objetivo principal del movimiento de curl con cable es el músculo bíceps braquial. Puedes conseguir brazos más anchos y gruesos apuntando a la cabeza del bíceps con este exclusivo ejercicio de curling con cable. El cable mantiene la tensión en los bíceps durante la parte de descenso y elevación de cada repetición para que siempre estén enganchados. La tensión constante del cable significa que trabajas duro tus bíceps."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('76bd0c30-c0de-4e80-babe-76bd0c300000', 'Curl de bíceps', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2023/09/waiter-curl.gif', '{"- Posición inicial: Párese erguido con los pies separados a la altura de los hombros, sosteniendo una mancuerna verticalmente frente a usted con ambas manos ahuecando la placa superior.","- Bajar bajo control: Regrese lentamente la mancuerna a la posición inicial sin dejarla caer.","- Sujete la mancuerna de forma segura para evitar que se mueva o se tambalee.","- Usar demasiado peso, lo que provoca balanceos o un control deficiente.","- Configuración de agarre: Mantenga los codos cerca del torso y las palmas hacia arriba, sosteniendo la mancuerna desde abajo.","- Repetir: Realice el número deseado de repeticiones manteniendo la forma estricta.","- Muévase lentamente para aumentar la activación muscular y el tiempo bajo tensión.","- Curl la mancuerna: doble los codos para levantar la mancuerna hacia el pecho mientras mantiene las muñecas estables.","### Errores comunes","- Dejar que los codos se abran, reduciendo el aislamiento del bíceps.","- Apresurar las repeticiones en lugar de controlar el movimiento.","- Apriete en la parte superior: haga una pausa de 1 a 2 segundos, contrayendo el bíceps por completo.","### Consejos para una forma adecuada","- Mantenga los codos doblados para evitar la afectación de los hombros.","- Mantenga una postura erguida; evite inclinarse hacia atrás.","- Evite la flexión de la muñeca; mantenga las muñecas en posición neutral por seguridad.","- Extenderse demasiado en la parte inferior, ejerciendo presión sobre la articulación del codo.","- Inclinar la mancuerna, lo que desplaza la carga de manera desigual."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0f80d022-c0de-4e80-babe-0f80d0220000', 'Dominadas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/jumping-pull-up.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('07021b0e-c0de-4e80-babe-07021b0e0000', 'Curl de piernas declinado con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Decline-Dumbbell-Leg-Curl.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3e0e82b1-c0de-4e80-babe-3e0e82b10000', 'Curl predicador con mancuernas', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dumbbell-Preacher-Curl.gif', '{"Siéntate en un banco de curl predicador y toma una mancuerna con una mano.","Coloque la parte superior del brazo en el banco de modo que quede apoyado y el codo apunte hacia arriba.","Aprieta los bíceps en la parte superior del movimiento, luego baja lentamente la mancuerna a la posición inicial.","Manteniendo la parte superior del brazo inmóvil, doble la mancuerna hacia el hombro.","Repita hasta el número deseado de repeticiones en un brazo antes de cambiar al otro brazo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0beb160a-c0de-4e80-babe-0beb160a0000', 'Remo inclinado con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Incline-Reverse-Grip-Dumbbell-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('70d81957-c0de-4e80-babe-70d819570000', 'Curl de bíceps sentado con banda de resistencia', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/06/Seated-Bicep-Curl-With-Resistance-Band.gif', '{"Sujete el peso (mancuerna, barra o polea) con un agarre supino (palmas hacia arriba).","Mantenga los pies separados al ancho de los hombros y las rodillas ligeramente flexionadas.","Coloque los codos pegados a los costados del torso y mantenga la espalda recta.","Manteniendo inmóvil la parte superior de los brazos, flexione los codos y eleve la carga hacia los hombros.","Apriete fuertemente los bíceps en el punto de máxima contracción por un segundo.","Baje el peso de forma controlada y lenta hasta extender completamente los brazos.","Evite balancear la espalda o mover los hombros hacia adelante para ayudarse.","Mantenga las muñecas firmes y rectas durante todo el recorrido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4eee69bc-c0de-4e80-babe-4eee69bc0000', 'Curl de bíceps inclinado en polea', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Cable-Incline-Biceps-Curl.gif', '{"Sujete el peso (mancuerna, barra o polea) con un agarre supino (palmas hacia arriba).","Mantenga los pies separados al ancho de los hombros y las rodillas ligeramente flexionadas.","Coloque los codos pegados a los costados del torso y mantenga la espalda recta.","Manteniendo inmóvil la parte superior de los brazos, flexione los codos y eleve la carga hacia los hombros.","Apriete fuertemente los bíceps en el punto de máxima contracción por un segundo.","Baje el peso de forma controlada y lenta hasta extender completamente los brazos.","Evite balancear la espalda o mover los hombros hacia adelante para ayudarse.","Mantenga las muñecas firmes y rectas durante todo el recorrido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('54475734-c0de-4e80-babe-544757340000', 'Curl martillo con banda de resistencia', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Hammer-Curl-with-Resistance-Band.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6d2eaca0-c0de-4e80-babe-6d2eaca00000', 'Curl de bíceps unilateral con banda de resistencia', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/One-Arm-Biceps-Curl.gif', '{"Sujete el peso (mancuerna, barra o polea) con un agarre supino (palmas hacia arriba).","Mantenga los pies separados al ancho de los hombros y las rodillas ligeramente flexionadas.","Coloque los codos pegados a los costados del torso y mantenga la espalda recta.","Manteniendo inmóvil la parte superior de los brazos, flexione los codos y eleve la carga hacia los hombros.","Apriete fuertemente los bíceps en el punto de máxima contracción por un segundo.","Baje el peso de forma controlada y lenta hasta extender completamente los brazos.","Evite balancear la espalda o mover los hombros hacia adelante para ayudarse.","Mantenga las muñecas firmes y rectas durante todo el recorrido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6ad4ea56-c0de-4e80-babe-6ad4ea560000', 'Curl predicador con barra EZ', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Z-Bar-Preacher-Curl.gif', '{"Ajuste el banco del predicador: Ajuste la altura del banco del predicador de modo que la parte superior de los brazos descanse cómodamente sobre la almohadilla en ángulo. Asegúrese de que su pecho esté en contacto con la almohadilla.","Seleccione el peso adecuado: seleccione un peso adecuado en la barra EZ que desafíe sus bíceps pero le permita mantener la forma adecuada.","Sujete la barra EZ: Sujete la barra EZ con un agarre por debajo (con las palmas hacia arriba) y con las manos ligeramente más juntas que el ancho de los hombros.","Coloque sus brazos: Coloque sus brazos sobre la almohadilla en ángulo, con la parte superior de sus brazos perpendicular al suelo y los codos ligeramente flexionados.","Baja la barra: Inhala y baja lentamente la barra hasta la posición inicial, manteniendo el control y la tensión en tus bíceps.","Flexiona la barra: Manteniendo la parte superior de los brazos inmóviles, exhala y flexiona la barra hacia el pecho, concentrándote en contraer los bíceps. Mantenga la contracción máxima por un segundo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('468ae205-c0de-4e80-babe-468ae2050000', 'Curl de bíceps inclinado en polea', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Cable-Incline-Biceps-Curl.gif', '{"Sujete el peso (mancuerna, barra o polea) con un agarre supino (palmas hacia arriba).","Mantenga los pies separados al ancho de los hombros y las rodillas ligeramente flexionadas.","Coloque los codos pegados a los costados del torso y mantenga la espalda recta.","Manteniendo inmóvil la parte superior de los brazos, flexione los codos y eleve la carga hacia los hombros.","Apriete fuertemente los bíceps en el punto de máxima contracción por un segundo.","Baje el peso de forma controlada y lenta hasta extender completamente los brazos.","Evite balancear la espalda o mover los hombros hacia adelante para ayudarse.","Mantenga las muñecas firmes y rectas durante todo el recorrido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('15eddb9c-c0de-4e80-babe-15eddb9c0000', 'Curl de bíceps unilateral en polea', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/High-Cable-Single-Arm-Bicep-Curl.gif', '{"Párese frente a una máquina de cable con la manija unida a la polea más alta. Agarre el asa con una mano y retroceda unos metros.","Mantenga la contracción máxima durante un segundo, luego baje lentamente el mango hasta la posición inicial.","Con el brazo completamente extendido y la palma hacia arriba, doble el mango hacia el hombro doblando el codo y contrayendo el bíceps.","Repita hasta obtener el número deseado de repeticiones, luego cambie de brazo y repita."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('370c89a5-c0de-4e80-babe-370c89a50000', 'Curl de bíceps de rodillas en polea', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Cable-Kneeling-Biceps-Curl.gif', '{"Sujete el peso (mancuerna, barra o polea) con un agarre supino (palmas hacia arriba).","Mantenga los pies separados al ancho de los hombros y las rodillas ligeramente flexionadas.","Coloque los codos pegados a los costados del torso y mantenga la espalda recta.","Manteniendo inmóvil la parte superior de los brazos, flexione los codos y eleve la carga hacia los hombros.","Apriete fuertemente los bíceps en el punto de máxima contracción por un segundo.","Baje el peso de forma controlada y lenta hasta extender completamente los brazos.","Evite balancear la espalda o mover los hombros hacia adelante para ayudarse.","Mantenga las muñecas firmes y rectas durante todo el recorrido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('25ab9817-c0de-4e80-babe-25ab98170000', 'Curl de bíceps unilateral', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/One-Arm-Biceps-Curl-1.gif', '{"Sujete el peso (mancuerna, barra o polea) con un agarre supino (palmas hacia arriba).","Mantenga los pies separados al ancho de los hombros y las rodillas ligeramente flexionadas.","Coloque los codos pegados a los costados del torso y mantenga la espalda recta.","Manteniendo inmóvil la parte superior de los brazos, flexione los codos y eleve la carga hacia los hombros.","Apriete fuertemente los bíceps en el punto de máxima contracción por un segundo.","Baje el peso de forma controlada y lenta hasta extender completamente los brazos.","Evite balancear la espalda o mover los hombros hacia adelante para ayudarse.","Mantenga las muñecas firmes y rectas durante todo el recorrido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7707705b-c0de-4e80-babe-7707705b0000', 'Ejercicio sentado', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Seated-Ballerina.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0a71714c-c0de-4e80-babe-0a71714c0000', 'Curl predicador', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Lever-Preacher-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('04294463-c0de-4e80-babe-042944630000', 'Curl martillo', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Hammer-Curl.gif', '{"Párese o siéntese con una buena postura: sostenga una pesa en cada mano con un agarre neutral, con las palmas una frente a la otra. Tus brazos deben estar completamente extendidos y colgando a los costados.","Baja el peso: Inhala y baja lentamente el peso hasta la posición inicial, manteniendo el codo cerca del cuerpo y manteniendo el control durante todo el movimiento.","Repite con el otro brazo: Repite el movimiento con el otro brazo, curvando el peso hacia tu hombro mientras mantienes el otro brazo extendido y colgando a tu lado.","Doble un brazo a la vez: exhale y doble un peso hacia su hombro, mientras mantiene el otro peso extendido y colgando a su lado.","Contrae tus bíceps: en la parte superior del movimiento, aprieta los bíceps para contraer completamente los músculos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('51df4107-c0de-4e80-babe-51df41070000', 'Curl de bíceps en máquina', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Bicep-Curl-Machine.gif', '{"Sujete el peso (mancuerna, barra o polea) con un agarre supino (palmas hacia arriba).","Mantenga los pies separados al ancho de los hombros y las rodillas ligeramente flexionadas.","Coloque los codos pegados a los costados del torso y mantenga la espalda recta.","Manteniendo inmóvil la parte superior de los brazos, flexione los codos y eleve la carga hacia los hombros.","Apriete fuertemente los bíceps en el punto de máxima contracción por un segundo.","Baje el peso de forma controlada y lenta hasta extender completamente los brazos.","Evite balancear la espalda o mover los hombros hacia adelante para ayudarse.","Mantenga las muñecas firmes y rectas durante todo el recorrido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('09be7b08-c0de-4e80-babe-09be7b080000', 'Curl martillo sentado', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Seated-Hammer-Curl.gif', '{"Siéntese en un banco o silla con los pies apoyados en el suelo y sostenga una mancuerna en cada mano con un agarre neutral (martillo), con las palmas una frente a la otra.","Levanta lentamente las mancuernas hacia tus hombros flexionando los codos, manteniendo las muñecas y los antebrazos en una posición neutral.","Mantenga los codos cerca de los costados y active el núcleo para mantener una posición estable.","Haga una pausa por un momento en la parte superior del movimiento y luego baje lentamente las mancuernas hasta la posición inicial.","Repita hasta el número deseado de repeticiones, manteniendo el control y evitando balancear las pesas o usar el impulso."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5d2d5c27-c0de-4e80-babe-5d2d5c270000', 'Curl de bíceps con barra', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Barbell-Reverse-Curl.gif', '{"Si fortaleces las muñecas y los antebrazos podrás levantar más peso mientras realizas otros ejercicios. La razón por la que no puede levantar el peso del cuerpo puede deberse a la debilidad de las muñecas y los brazos. Agregar ejercicios de muñeca y antebrazo a su programa de entrenamiento creará flexores de muñeca fuertes.","El curl inverso con barra es uno de los ejercicios de brazos más eficaces dirigidos a las muñecas y los bíceps.","Este ejercicio puede aumentar su capacidad para levantar pesas más pesadas durante la flexión de bíceps estándar. Además, puede corregir el desequilibrio muscular entre los músculos extensores y flexores. Además, es un ejercicio eficaz para desarrollar brazos más grandes y mejorar la flexibilidad de los bíceps."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('324da66f-c0de-4e80-babe-324da66f0000', 'Curl martillo', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Hammer-Curl.gif', '{"Párese o siéntese con una buena postura: sostenga una pesa en cada mano con un agarre neutral, con las palmas una frente a la otra. Tus brazos deben estar completamente extendidos y colgando a los costados.","Baja el peso: Inhala y baja lentamente el peso hasta la posición inicial, manteniendo el codo cerca del cuerpo y manteniendo el control durante todo el movimiento.","Repite con el otro brazo: Repite el movimiento con el otro brazo, curvando el peso hacia tu hombro mientras mantienes el otro brazo extendido y colgando a tu lado.","Doble un brazo a la vez: exhale y doble un peso hacia su hombro, mientras mantiene el otro peso extendido y colgando a su lado.","Contrae tus bíceps: en la parte superior del movimiento, aprieta los bíceps para contraer completamente los músculos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('43c4de3e-c0de-4e80-babe-43c4de3e0000', 'Curl de bíceps sentado con barra', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2025/07/seated-barbell-finger-curl.gif', '{"- Siéntese en un banco plano con los pies apoyados en el suelo y las rodillas dobladas a 90 grados.","- Sostenga una barra con un agarre por debajo (con las palmas hacia arriba), con las manos separadas al ancho de los hombros.","- Utilice un peso de ligero a moderado para evitar sobrecargar las delicadas articulaciones de los dedos.","- Apoye los antebrazos sobre los muslos de modo que las muñecas cuelguen justo por encima de las rodillas.","- Vuelva a doblar la barra hacia arriba flexionando los dedos y apretando con fuerza en la parte superior.","- Realice de 10 a 15 repeticiones lentas y controladas, concentrándose en la contracción de los antebrazos.","- Mantenga los antebrazos planos y estables contra los muslos durante todo el movimiento.","- Deje que la barra baje lentamente por sus dedos hasta las yemas.","- Muévase lentamente en todo el rango de movimiento, sin sacudidas.","- Respire constantemente, exhale mientras se curva e inhala mientras suelta.","- Aprieta con fuerza en la parte superior para una máxima activación muscular.","### Errores comunes","- Usar peso excesivo, que puede forzar los dedos y limitar el rango de movimiento.","- Levantando los antebrazos de los muslos, reduciendo el aislamiento.","### Consejos para una forma adecuada","- Realizar repeticiones rápidas o entrecortadas, disminuyendo el control muscular.","- No permitir que la barra ruede completamente, lo que limita la efectividad de la fase de estiramiento.","- Despreciando el apretón en la parte superior, lo que minimiza el compromiso muscular."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('63234f7d-c0de-4e80-babe-63234f7d0000', 'Curl de bíceps inclinado en polea', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Cable-Two-Arm-Curl-on-Incline-Bench.gif', '{"Sujete el peso (mancuerna, barra o polea) con un agarre supino (palmas hacia arriba).","Mantenga los pies separados al ancho de los hombros y las rodillas ligeramente flexionadas.","Coloque los codos pegados a los costados del torso y mantenga la espalda recta.","Manteniendo inmóvil la parte superior de los brazos, flexione los codos y eleve la carga hacia los hombros.","Apriete fuertemente los bíceps en el punto de máxima contracción por un segundo.","Baje el peso de forma controlada y lenta hasta extender completamente los brazos.","Evite balancear la espalda o mover los hombros hacia adelante para ayudarse.","Mantenga las muñecas firmes y rectas durante todo el recorrido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('588170a9-c0de-4e80-babe-588170a90000', 'Fondos en máquina', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Triceps-Dip-Machine.gif', '{"### Paso 1: ajustar la máquina","- Ajuste la altura del asiento de modo que la parte superior de sus brazos quede alineada con las manijas.","- Agarre las manijas firmemente.","- Coloque los pies apoyados en el suelo para estabilizar su posición.","- Regrese lentamente a la posición inicial, controlando el peso mientras dobla los codos.","- Elija un peso que permita una forma adecuada y un movimiento controlado.","### Paso 2: configuración y posicionamiento","### Paso 3: Ejecución","- Presione las manijas hacia abajo, extendiendo completamente los brazos mientras activa los tríceps.","- Haga una pausa de un segundo en la parte inferior para maximizar la activación muscular.","- Mantenga los codos pegados al cuerpo.","- Repita durante la cantidad deseada de repeticiones, manteniendo los movimientos controlados y constantes."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6d4209c4-c0de-4e80-babe-6d4209c40000', 'Curl de bíceps con barra', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/09/Barbell-Finger-Curl.gif', '{"Sujete el peso (mancuerna, barra o polea) con un agarre supino (palmas hacia arriba).","Mantenga los pies separados al ancho de los hombros y las rodillas ligeramente flexionadas.","Coloque los codos pegados a los costados del torso y mantenga la espalda recta.","Manteniendo inmóvil la parte superior de los brazos, flexione los codos y eleve la carga hacia los hombros.","Apriete fuertemente los bíceps en el punto de máxima contracción por un segundo.","Baje el peso de forma controlada y lenta hasta extender completamente los brazos.","Evite balancear la espalda o mover los hombros hacia adelante para ayudarse.","Mantenga las muñecas firmes y rectas durante todo el recorrido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5b5cc53a-c0de-4e80-babe-5b5cc53a0000', 'Estiramiento', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Sitting-Rotation-Hip-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('664cfce7-c0de-4e80-babe-664cfce70000', 'Curl de bíceps inclinado en polea', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Cable-Two-Arm-Curl-on-Incline-Bench.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('56ea42b6-c0de-4e80-babe-56ea42b60000', 'Estiramiento', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Side-Push-Neck-Stretch.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3fc3b890-c0de-4e80-babe-3fc3b8900000', 'Elevaciones frontales con barra', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Barbell-Front-Raise.gif', '{"El levantamiento frontal con barra es un ejercicio simple con barra que apunta a las cabezas anterior y lateral de los hombros. Adecuado para todos los niveles, este ejercicio de flexión de hombros es una buena opción para desarrollar fuerza, mejorar la movilidad de los hombros y dar forma a la cabeza de los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0fce32ac-c0de-4e80-babe-0fce32ac0000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2023/06/Vibrate-Plate-Standing.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('714cdc90-c0de-4e80-babe-714cdc900000', 'Ejercicio en polea', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/High-Cable-Crossover.gif', '{"Ajuste los cables: Ajuste los cables a la posición más alta en ambos lados de la máquina de cable. Conecte las manijas a cada cable.","Párese en el centro: Párese en el centro de la máquina, de espaldas a ella. Sostenga las manijas con las palmas hacia abajo.","Colóquese: dé un paso hacia adelante con una pierna o inclínese ligeramente hacia adelante, manteniendo los pies separados al ancho de los hombros. Tus brazos deben estar extendidos a los lados, paralelos al suelo.","Regreso a la posición inicial: Baja lentamente las asas hasta la posición inicial, manteniendo los brazos ligeramente flexionados.","Cruza las manijas: lentamente acerca ambas manijas, cruzándolas frente a tu cuerpo. Tus brazos deben estar ligeramente doblados a la altura del codo.","Aprieta tu pecho: haz una pausa por un momento y aprieta los músculos del pecho.","Repetir: Repita el ejercicio durante el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0c9cbcd0-c0de-4e80-babe-0c9cbcd00000', 'Zancadas declinado con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Decline-Bench-Dumbbell-Lunge.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0e0e18d1-c0de-4e80-babe-0e0e18d10000', 'Ejercicio', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Foam-Roller-Posterior-Shoulder.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('39f67326-c0de-4e80-babe-39f673260000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Leg-Pull-In-Knee-ups.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0b9e42ce-c0de-4e80-babe-0b9e42ce0000', 'Remo con mancuerna', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dumbbell-Row.gif', '{"Coloque la rodilla izquierda y la mano izquierda sobre un banco, manteniendo la espalda plana y el torso paralelo al suelo.","Baja la mancuerna lentamente hasta la posición inicial bajo control.","Sostenga una mancuerna en su mano derecha, con el brazo completamente extendido hacia el piso y la palma hacia adentro.","Involucre su núcleo y levante la mancuerna, llevando su codo hacia su cadera.","Haga una pausa en la parte superior, apretando el omóplato hacia la columna.","Complete las repeticiones y luego cambie de lado."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('306077ff-c0de-4e80-babe-306077ff0000', 'Aperturas de pecho inclinado en máquina', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2023/06/Incline-Chest-Fly-Machine.gif', '{"- Mantenga la espalda apoyada contra el banco para evitar la tensión lumbar.","- Mantenga una ligera flexión de los codos durante todo el movimiento.","- Evite un rango de movimiento excesivo para proteger las articulaciones de los hombros.","- Controla el tempo, especialmente durante la fase excéntrica (de descenso).","- Involucre su núcleo para estabilizar su torso durante toda la serie.","### Errores comunes a evitar","- Bloquear los codos, lo que aumenta la tensión en las articulaciones.","- Dejar las manijas demasiado atrás, corre el riesgo de lesionarse el hombro.","### Consejos para una forma adecuada","- Apresurarse en las repeticiones sin centrarse en la contracción muscular.","- Arquear la espalda excesivamente, lo que reduce la activación del pecho.","- Colocar el asiento demasiado bajo o alto, desviando la atención de la parte superior del pecho."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4e6ba039-c0de-4e80-babe-4e6ba0390000', 'Remo de rodillas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Kneeling-High-Pulley-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('524587ea-c0de-4e80-babe-524587ea0000', 'Dominadas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Archer-Pull-up.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('10c6b425-c0de-4e80-babe-10c6b4250000', 'Remo con mancuerna', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dumbbell-Row.gif', '{"Coloque la rodilla izquierda y la mano izquierda sobre un banco, manteniendo la espalda plana y el torso paralelo al suelo.","Baja la mancuerna lentamente hasta la posición inicial bajo control.","Sostenga una mancuerna en su mano derecha, con el brazo completamente extendido hacia el piso y la palma hacia adentro.","Involucre su núcleo y levante la mancuerna, llevando su codo hacia su cadera.","Haga una pausa en la parte superior, apretando el omóplato hacia la columna.","Complete las repeticiones y luego cambie de lado."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6bd0790e-c0de-4e80-babe-6bd0790e0000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/Right-Cross-Boxing.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0615cd10-c0de-4e80-babe-0615cd100000', 'Remo con barra en T', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/t-bar-rows.gif', '{"Configure el equipo: Primero, configure la máquina de remo con barra en T con la cantidad adecuada de peso. Si no tienes acceso a una máquina de remo con barra en T, también puedes usar una barra y un accesorio para minas terrestres.","Levante el peso: levante el peso del suelo y déjelo colgar frente a su cuerpo. Esta es tu posición inicial.","Mantenga la contracción: Mantenga la contracción durante uno o dos segundos, luego baje lentamente el peso a la posición inicial.","Colóquese: doble las caderas, mantenga la espalda recta y estírese hacia abajo para agarrar las manijas de la barra en V con un agarre neutral (las palmas una frente a la otra).","Involucre los músculos de la espalda: tire lentamente del peso hacia el pecho retrayendo los omóplatos y apretando los músculos de la espalda. Mantenga los codos cerca del cuerpo y los antebrazos paralelos al suelo.","Repetir: Complete el número deseado de repeticiones, luego descanse y repita para series adicionales."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('397c6df1-c0de-4e80-babe-397c6df10000', 'Ejercicio acostado en polea', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Lying-Extension-Pullover.gif', '{"- Configure la máquina de cable: conecte una cuerda o una barra recta a la polea. Acuéstese boca arriba sobre un banco plano o en el suelo.","- Agarre el mango con los brazos rectos: sostenga la barra o la cuerda por encima de la cabeza con una ligera flexión de los codos. Mantenga los pies apoyados en el banco o las rodillas dobladas sobre el suelo.","- Regrese lentamente al inicio: controle el cable mientras tira de sus brazos hacia atrás, manteniendo la tensión en los músculos.","- Elija un peso que permita un rango completo de movimiento sin compensaciones.","### Errores comunes","- Tire del cable hacia abajo con los dorsales y los pectorales: baje el mango formando un arco hacia las caderas mientras mantiene los brazos extendidos.","- Involucre su núcleo para estabilizar su columna durante el movimiento.","- Bloquear completamente los codos, lo que puede causar tensión y reducir la activación muscular.","- Dejando que los hombros se encojan hacia arriba durante el ejercicio.","- Balancear los brazos o usar el impulso en lugar del control muscular.","- Haga una pausa y contraiga en la parte inferior: apriete los dorsales y los músculos del pecho, manteniendo los hombros estables y bajos.","### Consejos para una forma adecuada","- Mantenga una ligera flexión de los codos para proteger las articulaciones.","- Evite utilizar el impulso; Realiza repeticiones lentas y controladas.","- Mantenga los hombros deprimidos y las escápulas estables.","- Arquear excesivamente la zona lumbar al tirar.","- Moverse demasiado rápido durante la fase excéntrica, perdiendo tensión muscular."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7032d138-c0de-4e80-babe-7032d1380000', 'Estiramiento', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2023/03/Wrist-Stretch.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('606612ce-c0de-4e80-babe-606612ce0000', 'Estiramiento sentado', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Seated-Chest-Stretch.gif', '{"- Comience en posición sentada: siéntese en el suelo con las piernas dobladas y los pies apoyados en el suelo. Coloque las manos detrás de la espalda, con los dedos hacia el cuerpo.","- Coloque las manos detrás de la espalda, con los dedos hacia el cuerpo.","- Suelte lentamente: relájese y regrese a la posición inicial. Repita de 2 a 3 series, ajustando la intensidad según sea necesario.","- Relax and return to the starting position.","- Ajuste la colocación de las manos para encontrar la posición más cómoda.","### Guía paso a paso","- Siéntate en el suelo con las piernas dobladas y los pies apoyados en el suelo.","- Empuja tu pecho hacia arriba y hacia adelante, abriendo los hombros y el pecho.","- Mantenga la posición: mantenga el estiramiento durante 10 a 20 segundos mientras respira profundamente. Sienta el estiramiento suave en el pecho y los hombros sin forzar.","- Realice el estiramiento: empuje el pecho hacia arriba y hacia adelante, abriendo los hombros y el pecho. Mantenga los brazos ligeramente doblados pero estables para evitar una presión excesiva en las muñecas.","- Siente el suave estiramiento en tu pecho y hombros sin forzar.","- Repita durante 2 a 3 series, ajustando la intensidad según sea necesario.","- Respire profundamente para mejorar la relajación y la eficacia del estiramiento.","### Errores comunes a evitar","- Extender demasiado la zona lumbar, lo que provoca molestias o tensión.","- Mantenga los brazos ligeramente doblados pero estables para evitar una presión excesiva en las muñecas.","- Mantenga el estiramiento durante 10 a 20 segundos mientras respira profundamente.","### Consejos para una forma adecuada","- Mantenga los hombros relajados y evite encogerse de hombros.","- Mantenga una ligera flexión de los codos para reducir la tensión en las articulaciones.","- Evite arquear excesivamente la zona lumbar para evitar molestias.","- Contener la respiración, lo que limita la relajación y la flexibilidad.","- Descuidar la postura: asegúrese de que el pecho esté levantado y los hombros echados hacia atrás.","- Colocar las manos demasiado cerca reduce la efectividad del estiramiento.","- Forzar el estiramiento, lo que puede provocar tensión muscular o lesiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('06731aac-c0de-4e80-babe-06731aac0000', 'Face pull en polea', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Face-Pull.gif', '{"conecte un mango de cuerda a una máquina de cable o use bandas de resistencia al nivel del pecho o de los ojos.","Agarre: Sujete las manijas con un agarre por encima de la cabeza, con las palmas hacia abajo.","Posición: Párese erguido con los pies separados a la altura de los hombros, involucrando su núcleo.","Configuración: conecte un mango de cuerda a una máquina de cable o use bandas de resistencia al nivel del pecho o de los ojos.","Ejecución: Tire de la cuerda hacia su cara, con los codos extendidos hacia afuera. Apriete los omóplatos en el punto máximo del movimiento. Regrese lentamente a la posición inicial.","Tire de la cuerda hacia su cara, con los codos extendidos hacia afuera. Apriete los omóplatos en el punto máximo del movimiento. Regrese lentamente a la posición inicial.","Apriete los omóplatos en la cima del movimiento."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('66e38048-c0de-4e80-babe-66e380480000', 'Ejercicio acostado', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Lying-Scissor-Kick.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6ae7fcde-c0de-4e80-babe-6ae7fcde0000', 'Dominadas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Assisted-Pull-up.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('14f8b3b7-c0de-4e80-babe-14f8b3b70000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2023/06/Back-Lever.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('412bd029-c0de-4e80-babe-412bd0290000', 'Jalón al pecho', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Reverse-Lat-Pulldown.gif', '{"Ajuste el asiento en la máquina de dominadas para que sus muslos queden asegurados debajo de las almohadillas para las piernas. Sujete la barra con un agarre inverso, con las palmas hacia usted y las manos ligeramente más anchas que el ancho de los hombros.","Sujete la barra con un agarre inverso, con las palmas hacia usted y un poco más anchas que el ancho de los hombros.","Posición del cuerpo: Siéntese con la espalda recta y el pecho erguido. Mantenga los pies apoyados en el suelo. Sostenga la barra con un agarre firme.","Baja la barra de forma controlada hasta la posición inicial sin dejar que la pila de pesas se toque.","Configuración: Ajuste el asiento en la máquina de dominadas para que sus muslos queden asegurados debajo de las almohadillas para las piernas. Sujete la barra con un agarre inverso, con las palmas hacia usted y las manos ligeramente más anchas que el ancho de los hombros.","Siéntate con la espalda recta y el pecho erguido.","Movimiento: Comience con los brazos completamente extendidos por encima de la cabeza. Tire de la barra hacia el pecho bajando los codos hacia abajo y hacia atrás. Concéntrese en apretar los omóplatos mientras baja la barra. Baje la barra de manera controlada hasta la posición inicial sin dejar que la pila de pesas se toque.","Comience con los brazos completamente extendidos por encima de la cabeza. Tire de la barra hacia el pecho bajando los codos hacia abajo y hacia atrás. Concéntrese en apretar los omóplatos mientras baja la barra. Baje la barra de manera controlada hasta la posición inicial sin dejar que la pila de pesas se toque.","Tire de la barra hacia su pecho bajando los codos hacia abajo y hacia atrás.","Inhala mientras extiendes los brazos por encima de la cabeza.","Concéntrate en juntar los omóplatos mientras bajas la barra.","Respiración: Inhale mientras extiende los brazos por encima de la cabeza. Exhale mientras tira de la barra hacia abajo.","Inhale mientras extiende los brazos por encima de la cabeza. Exhale mientras tira de la barra hacia abajo.","Exhala mientras bajas la barra."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5516129a-c0de-4e80-babe-5516129a0000', 'Ejercicio con pesa rusa / kettlebell', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Kettlebell-Swings.gif', '{"Párese con los pies entre 6 y 12 pulgadas fuera del ancho de los hombros a cada lado, cada pie apuntando hacia afuera unos 30 grados.","Imagínese pellizcando una moneda entre sus nalgas cuando mueve sus caderas hacia adelante.","El swing con pesas rusas es un movimiento dinámico; debe fluir continuamente sin detenerse en la parte superior o inferior.","El movimiento de descenso (backswing) es un movimiento para sentarse en una silla, no un movimiento para ponerse en cuclillas.","En la parte superior del swing, la pesa rusa debe estar a la altura de los hombros y el cuerpo debe formar una línea recta desde la cabeza hasta los talones.","Mantenga los hombros hacia atrás (retraídos) y hacia abajo para evitar arquear la espalda."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('34cd99fc-c0de-4e80-babe-34cd99fc0000', 'Dominada', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Pull-up.gif', '{"- Agarre una barra de dominadas con las manos separadas a la altura de los hombros y las palmas hacia afuera.","- Baja lentamente y con control hasta la posición inicial.","- Comience desde una posición muerta con extensión completa del brazo.","###","- Cuélgate de la barra con los brazos completamente extendidos y las piernas estiradas o ligeramente flexionadas.","- Mueva los codos hacia abajo, apretando los omóplatos.","- Haga una breve pausa en la parte superior, con la barbilla por encima de la barra.","- Involucre su núcleo y espalda, luego tire de su pecho hacia la barra.","- Tire en un camino vertical recto, evitando que el pecho se ensanche.","- Usar impulso o dar saltos sin querer para engañar al movimiento.","- Enganche primero la escápula para iniciar el tirón con la espalda, no solo con los brazos.","### Errores comunes","- Encogerse de hombros en lugar de retraer la escápula.","### Consejos para una forma adecuada","- Evite balancearse o dar saltos si hace repeticiones estrictas.","- Mantenga el cuello neutral y los hombros hacia abajo.","- Medias repeticiones sin llegar a la extensión total ni al mentón por encima de la barra.","- Dejar que las piernas se balanceen, lo que reduce el control.","- Depender demasiado de los bíceps y descuidar la activación de los dorsales."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('73873d82-c0de-4e80-babe-73873d820000', 'Peso muerto', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Barbell-Deadlift.gif', '{"Comience parándose con los pies separados a la altura de los hombros y con los dedos apuntando hacia adelante. La barra debe estar en el suelo frente a ti.","Inclínese y agarre la barra con las manos ligeramente más separadas que el ancho de los hombros, usando un agarre por encima o mixto (una mano por encima y otra por debajo).","Una vez que hayas levantado la barra hasta la posición de pie, haz una pausa por un momento, luego bájala nuevamente hasta el suelo, manteniendo la espalda recta y el core comprometido.","Respira profundamente y fortalece tus músculos centrales. Esto ayudará a estabilizar su columna y protegerá su espalda baja.","Doble las rodillas y baje las caderas, manteniendo la espalda recta y el pecho erguido. Mantenga la cabeza y el cuello en una posición neutral y concéntrese en mirar hacia adelante.","Mantenga la barra cerca de su cuerpo mientras levanta y use las piernas, los glúteos y los músculos de la espalda para impulsar el levantamiento."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('464f040a-c0de-4e80-babe-464f040a0000', 'Patada de tríceps con banda de resistencia', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Banded-Glute-Kickbacks.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4cb4618c-c0de-4e80-babe-4cb4618c0000', 'Remo', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Inverted-Row.gif', '{"- Ajuste la altura Coloque la barra o las correas al nivel de la cintura o ligeramente más abajo. Cuanto más baja la barra, más difícil será el ejercicio.","- Coloque la barra o las correas al nivel de la cintura o ligeramente más abajo. Cuanto más baja la barra, más difícil será el ejercicio.","- Posición inicial Acuéstese debajo de la barra con el pecho alineado directamente debajo de ella. Agarre la barra con un agarre por encima o por debajo, con las manos separadas al ancho de los hombros. Extienda las piernas rectas con los talones en el suelo, manteniendo el cuerpo en línea recta desde la cabeza hasta los talones.","- Agarre la barra con un agarre por encima o por debajo, con las manos separadas al ancho de los hombros.","- Lower DownExtiende lentamente los brazos para volver a la posición inicial, manteniendo el cuerpo recto.","- Extiende lentamente los brazos para volver a la posición inicial, manteniendo el cuerpo recto.","- Encuentre un entrenador de barra o suspensión Utilice una barra baja en una rejilla para sentadillas, una máquina Smith o correas de suspensión (por ejemplo, TRX). Asegúrese de que el equipo sea resistente.","- Utilice una barra baja en una rejilla para sentadillas, una máquina Smith o correas de suspensión (por ejemplo, TRX). Asegúrese de que el equipo sea resistente.","- Acuéstese debajo de la barra con el pecho alineado directamente debajo de ella.","- Extiende las piernas rectas con los talones en el suelo, manteniendo el cuerpo en línea recta desde la cabeza hasta los talones.","- Tire hacia arriba Involucra la espalda y el core, luego tira del pecho hacia la barra doblando los codos. Mantén los codos cerca del cuerpo y junta los omóplatos en la parte superior.","- Involucre la espalda y el core, luego tire del pecho hacia la barra doblando los codos.","- Repetir Realice de 8 a 12 repeticiones durante 3 a 4 series, concentrándose en el movimiento controlado.","- Realice de 8 a 12 repeticiones durante 3 a 4 series, concentrándose en el movimiento controlado.","- Alineación de la barra: la barra debe tocar tu pecho o acercarse a él en la parte superior del movimiento.","- Rango de movimiento incompleto: no acercar el pecho a la barra limita la activación muscular.","- Columna Neutral: Mantenga una línea recta desde la cabeza hasta los talones durante todo el movimiento.","- Posición del codo: Mantenga los codos cerca del torso para evitar una tensión excesiva en los hombros.","### Errores comunes","- Mantenga los codos cerca del cuerpo y junte los omóplatos en la parte superior.","### Consejos para una forma adecuada","- Involucre el núcleo: mantenga los abdominales contraídos para evitar que las caderas se caigan.","- Movimiento controlado: evite sacudidas o utilizar el impulso; Concéntrese en repeticiones lentas y deliberadas.","- Arqueando la espalda baja. Mantenga una columna neutra involucrando el núcleo y los glúteos.","- Caderas caídas: dejar caer las caderas reduce el compromiso del núcleo y compromete la forma.","- Codos ensanchados: Permitir que los codos se ensanchen puede tensar los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('74d9e0a5-c0de-4e80-babe-74d9e0a50000', 'Dominadas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Assisted-Pull-up.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('771d095d-c0de-4e80-babe-771d095d0000', 'Remo inclinado con barra', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Incline-Barbell-Row.gif', '{"El remo inclinado con barra, que se dirige a toda la cadena de la espalda, se dirige al dorsal ancho, el infraespinoso, el trapecio, los deltoides posteriores y los romboides, por lo que agregar ejercicios como el remo con barra y el remo con barra en T a sus programas de entrenamiento será beneficioso para el desarrollo de los músculos de la espalda."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('057f0819-c0de-4e80-babe-057f08190000', 'Encogimiento de hombros inclinado', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Dumbbell-Decline-Shrug.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5212d65a-c0de-4e80-babe-5212d65a0000', 'Dominadas con agarre inverso', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Reverse-grip-Pull-up.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2bf94bf9-c0de-4e80-babe-2bf94bf90000', 'Peso muerto rumano', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Barbell-Romanian-Deadlift.gif', '{"Desarrollar fuerza y ​​​​masa muscular:"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('282d431a-c0de-4e80-babe-282d431a0000', 'Elevación de pantorrillas de pie con mancuernas', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dumbbell-Calf-Raise.gif', '{"- Posición inicial: Párese erguido con los pies separados a la altura de las caderas, sosteniendo una mancuerna en cada mano, los brazos relajados a los lados, manteniendo una postura y alineación adecuadas.","- Descenso controlado: baje gradualmente los talones hasta la posición inicial de forma controlada, asegurando una tensión muscular constante.","- Manténgase brevemente en la posición superior para maximizar la participación de los músculos.","- Seleccione el peso de mancuerna adecuado para garantizar la técnica adecuada y evitar lesiones.","- Uso de peso excesivo: seleccionar mancuernas demasiado pesadas puede comprometer la forma, reducir la activación de la pantorrilla y aumentar el riesgo de lesiones.","- Alineación y estabilidad: Involucre los músculos centrales para lograr estabilidad, mantenga los hombros hacia atrás y mantenga una alineación neutra de la columna durante todo el movimiento.","### Errores comunes","- Movimiento de elevación: levántese lentamente sobre las puntas de los pies levantando los talones lo más alto posible, contrayendo completamente los músculos de la pantorrilla.","- Repetir: realice las repeticiones deseadas, generalmente de 10 a 15 repeticiones por serie, enfatizando los movimientos lentos y controlados.","- Mantén los movimientos controlados, evitando impulsos o rebotes.","- Rango de movimiento limitado: no levantar completamente los talones o bajarlos por completo disminuye la efectividad y el potencial de desarrollo muscular.","- Movimientos rápidos y entrecortados: las repeticiones rápidas o los movimientos de rebote aumentan la tensión en los tendones y las articulaciones, lo que reduce la seguridad del ejercicio.","### Consejos para una forma adecuada","- Mantenga una columna neutra y una postura erguida durante todo el ejercicio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0a45a46d-c0de-4e80-babe-0a45a46d0000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/wall-slide.gif', '{"Párese con la espalda contra la pared, con los pies separados aproximadamente a la altura de las caderas.","Coloque los brazos contra la pared con los codos doblados en un ángulo de 90 grados y las palmas hacia adelante.","Haga una pausa por un momento en la parte superior, luego deslice lentamente los brazos hacia abajo hasta la posición inicial.","Desliza suavemente los brazos hacia arriba por la pared, manteniendo el contacto entre las manos, los codos y la pared.","Mientras desliza los brazos hacia arriba, trate de mantener los omóplatos juntos y hacia abajo.","Vaya tan lejos como pueda cómodamente sin dolor ni tensión excesiva.","Repita el movimiento durante el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7cc25ec9-c0de-4e80-babe-7cc25ec90000', 'Dominadas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Weighted-Pull-up.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('07b1c648-c0de-4e80-babe-07b1c6480000', 'Remo en polea sentado', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Seated-Cable-Row.gif', '{"Coloque sus pies firmemente sobre el reposapiés o plataforma proporcionada por la máquina de cable.","Antes de comenzar el ejercicio, retrae los omóplatos y mantenlos en esta posición durante todo el movimiento. Esto ayudará a activar los músculos de la parte superior de la espalda y evitará una tensión excesiva en los hombros y el cuello.","Mientras tiras de las manijas del cable hacia ti, mantén los codos extendidos hacia los lados y junta los omóplatos al final del movimiento. Esto ayudará a activar los músculos de la parte superior de la espalda y evitará una tensión excesiva en los hombros.","Haga una pausa por un segundo en la parte superior del movimiento y luego suéltelo lentamente hasta la posición inicial. Exhala mientras tiras del cable hacia tu cuerpo e inhala mientras regresas a la posición inicial.","Mantenga la espalda recta y evite encorvarse o doblar los hombros hacia adelante. Involucre sus músculos centrales para ayudar a mantener una buena postura. Esto le ayudará a mantener la estabilidad y evitará que la zona lumbar se doble.","Repita hasta el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4a2bcf7a-c0de-4e80-babe-4a2bcf7a0000', 'Press de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Close-Grip-Bench-Press.gif', '{"Acuéstate en un banco plano con los pies apoyados en el suelo y la espalda en posición neutra.","Agarre la barra con fuerza, con las manos separadas un poco menos que el ancho de los hombros.","Haga una pausa breve en la parte inferior del movimiento, luego presione la barra hacia arriba hasta la posición inicial, apretando los tríceps en la parte superior.","Retire la barra y bájela lentamente hacia su pecho mientras mantiene los codos pegados al cuerpo.","Repita hasta obtener el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2765ed6a-c0de-4e80-babe-2765ed6a0000', 'Peso muerto rumano', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Barbell-Romanian-Deadlift.gif', '{"Desarrollar fuerza y ​​​​masa muscular:"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('19d21bf8-c0de-4e80-babe-19d21bf80000', 'Remo en máquina', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Rowing-Machine.gif', '{"Posición inicial (The Catch): Siéntese en el asiento con los pies atados. Doble las rodillas, inclínese ligeramente hacia adelante a la altura de las caderas y sostenga el mango con un agarre por encima de la cabeza.","Posición final: Piernas completamente extendidas, torso ligeramente inclinado hacia atrás, mango tirado justo debajo del pecho.","Fase de impulso: Empuje explosivamente a través de las piernas, extienda las caderas, luego tire del mango hacia la parte superior del abdomen mientras mantiene los codos cerca del cuerpo.","Fase de recuperación: primero extienda los brazos hacia adelante, luego gire las caderas y finalmente doble las rodillas para regresar a la captura.","Mantenga un ritmo constante, coordinando suavemente las piernas, el tronco y los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('11b150fb-c0de-4e80-babe-11b150fb0000', 'Ejercicio', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Scapular-Protraction-and-Retraction.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('63bc4001-c0de-4e80-babe-63bc40010000', 'Ejercicio', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Superman-exercise.gif', '{"Los ejercicios de Superman son un excelente ejercicio que fortalece el core, la espalda baja, los glúteos y los isquiotibiales.","Este movimiento fortalece los músculos erectores de la columna que brindan soporte a la columna. Unos músculos fuertes de la espalda pueden prevenir desviaciones posturales que provocan malas posturas y molestias, como la cifosis (“jorobada”). El movimiento de Superman mejora tu postura al extender los músculos de la espalda y reducir la tensión entre la zona lumbar y la zona central. También mejora la fuerza de la espalda baja, lo que facilita mantenerse erguido durante todo el día.","También es beneficioso para la salud de la espalda baja, ya que algunos dolores lumbares pueden deberse a glúteos débiles y tendones de la corva tensos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4ab28645-c0de-4e80-babe-4ab286450000', 'Remo con mancuerna', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dumbbell-Row.gif', '{"Coloque la rodilla izquierda y la mano izquierda sobre un banco, manteniendo la espalda plana y el torso paralelo al suelo.","Baja la mancuerna lentamente hasta la posición inicial bajo control.","Sostenga una mancuerna en su mano derecha, con el brazo completamente extendido hacia el piso y la palma hacia adentro.","Involucre su núcleo y levante la mancuerna, llevando su codo hacia su cadera.","Haga una pausa en la parte superior, apretando el omóplato hacia la columna.","Complete las repeticiones y luego cambie de lado."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7b50a225-c0de-4e80-babe-7b50a2250000', 'Elevaciones laterales', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2023/06/Lateral-Raise-with-Towel-on-Wall.gif', '{"Comience con el brazo que sostiene la toalla descansando cómodamente a su costado. Mantenga una postura natural con su núcleo comprometido.","Sostener y sentir: haga una pausa breve en la posición elevada, sintiendo la contracción en el músculo deltoides lateral. Mantén la estabilidad en todo tu cuerpo.","Baje con control: baje gradualmente el brazo hasta la posición inicial a su lado. Mantenga la tensión de la toalla durante la fase de descenso.","Posición inicial: Comience con el brazo que sostiene la toalla descansando cómodamente a su costado. Mantenga una postura natural con su núcleo comprometido.","Posición Paralela: Continúa el movimiento hasta que tu brazo quede paralelo al suelo.","Levante con control: manteniendo una ligera flexión en el codo, inicie el movimiento levantando lentamente el brazo hacia un lado al nivel del hombro. Concéntrese en un movimiento controlado y deliberado.","Respiración: Respire naturalmente durante todo el ejercicio, exhalando mientras levanta el brazo e inhalando mientras lo baja.","Compromiso del hombro: Concéntrese en usar los músculos deltoides laterales para levantar el brazo. Evite utilizar el impulso para mover el brazo hacia arriba.","Repetición: complete el número deseado de repeticiones en un lado antes de cambiar al otro lado. Concéntrate en la calidad de cada repetición.","Respire naturalmente durante todo el ejercicio, exhalando mientras levanta el brazo e inhalando mientras lo baja."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7d6fc231-c0de-4e80-babe-7d6fc2310000', 'Ejercicio en máquina', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/HIP-ADDUCTION-MACHINE.gif', '{"Ajusta la máquina: Antes de comenzar, ajusta la máquina a tu altura y selecciona el peso adecuado. Asegúrese de que las almohadillas estén colocadas cómodamente sobre sus piernas y que sus pies estén firmemente sobre los reposapiés.","Siéntate en la máquina: Siéntate en el asiento con la espalda apoyada en el respaldo y los pies en los reposapiés.","Coloque sus piernas: Coloque sus piernas de modo que sus rodillas estén dobladas en un ángulo de 90 grados y sus muslos estén ligeramente separados.","Liberación: Libere lentamente la resistencia y permita que sus piernas regresen a la posición inicial. Inhala mientras liberas.","Repetir: Complete el número deseado de repeticiones y series, y ajuste el peso según sea necesario.","Involucre la parte interna de los muslos: apriete la parte interna de los muslos y empuje las piernas contra la resistencia. Exhala mientras juntas las piernas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('68fd09cf-c0de-4e80-babe-68fd09cf0000', 'Fondos', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Impossible-Dips.gif', '{"### Paso 1: Configuración y posición inicial","- Agarre las barras con firmeza y empújese hacia arriba hasta la posición de inmersión superior.","- Agarre las barras con fuerza para mantener el control y evitar resbalones.","- Colóquese entre dos barras paralelas a una distancia cómoda al ancho de los hombros.","- Mantenga las piernas extendidas y rectas y mantenga una posición del cuerpo hueca (involucre su núcleo para evitar la flacidez).","- Baja el cuerpo lentamente y de forma controlada, manteniendo el torso recto y ligeramente inclinado hacia adelante.","- Desciende hasta que la parte superior de tus brazos quede paralela a las barras o ligeramente más abajo.","### Paso 2: Ejecución","- Empuje hacia arriba usando los tríceps, los hombros y el core mientras mantiene el cuerpo rígido.","- Mantén las piernas estiradas y juntas durante todo el movimiento.","- Doblar las rodillas, haciendo el movimiento más fácil pero menos efectivo.","- No involucrar el core, provocando inestabilidad y dificultando el movimiento.","- Involucre su núcleo para evitar que se hunda o pierda el equilibrio.","- Bájate lentamente, concentrándote en el control más que en la velocidad.","- Inclínese ligeramente hacia adelante para optimizar la activación muscular en los tríceps y los hombros.","### Errores comunes a evitar","- Mantenga la tensión de todo el cuerpo, asegurándose de que las caderas y las piernas no caigan.","- Complete de 3 a 5 series de 3 a 8 repeticiones, dependiendo de su nivel de fuerza.","### Consejos para una forma adecuada","- Apresurarse en las repeticiones, lo que puede provocar una mala forma y una reducción de la ganancia de fuerza.","- Dejar caer las caderas, lo que reduce el compromiso del core y rompe la forma.","- Utilizar el impulso en lugar de un control estricto, disminuyendo la dificultad del ejercicio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('37d2276d-c0de-4e80-babe-37d2276d0000', 'Sentadilla con barra', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Barbell-Hack-Squat.gif', '{"- Coloque una barra detrás de las piernas en el suelo, con los pies separados a la altura de las caderas y los dedos apuntando ligeramente hacia afuera.","- Usar demasiado peso demasiado pronto, compromete la técnica.","- Póngase en cuclillas con el pecho alto y la columna neutra, agarrando la barra con ambas manos a la altura de los hombros.","- Involucra tu core y conduce a través de tus talones para levantar la barra en línea recta hacia arriba detrás de tu cuerpo.","- Baje la barra bajo control, manteniendo una postura adecuada y repitiendo las repeticiones.","- Conduce con los talones para activar los glúteos y mantener el equilibrio.","- Extienda completamente las caderas y las rodillas en la parte superior mientras mantiene la barra cerca de la parte posterior de las piernas.","- No calentar ni movilizar los tobillos, limitando la profundidad y el rango de movimiento.","- Utilice un tempo controlado tanto en el ascenso como en el descenso.","- Calienta las rodillas y los tobillos para prepararte para la flexión profunda de la rodilla involucrada.","### Errores comunes","- Redondear la zona lumbar, lo que aumenta el riesgo de lesiones.","### Consejos para una forma adecuada","- Mantenga el torso erguido durante todo el levantamiento para enfatizar los cuádriceps y reducir la tensión en la espalda.","- Mantenga la barra cerca de su cuerpo para evitar alejar la carga de su centro de masa.","- Dejar que la barra se aleje de tus piernas, provocando problemas de equilibrio y forma.","- Empujar a través de los dedos de los pies, lo que reduce la estabilidad y la activación de los glúteos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('184afa36-c0de-4e80-babe-184afa360000', 'Ejercicio de pie', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Standing-Hip-Abduction-1.gif', '{"El foco de este ejercicio está en el glúteo medio y el glúteo menor que se encuentra debajo. Si el objetivo es fortalecer y dar forma a la cadera (glúteos superiores y externos), entonces la abducción de cadera es una excelente opción."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('16a81233-c0de-4e80-babe-16a812330000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Squat-Tuck-Jump.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6bb130f2-c0de-4e80-babe-6bb130f20000', 'Elevación', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Hanging-Knee-Raises.gif', '{"Su propio peso corporal actúa como resistencia que ayuda a aumentar su resistencia y desarrollar su resistencia. Este ejercicio que trabaja los flexores de la cadera mejora los músculos centrales, especialmente los músculos abdominales inferiores. Es uno de los mejores ejercicios para abdominales que activa todo el core ejercitando no sólo los abdominales inferiores sino también los músculos abdominales superiores."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1f5d2959-c0de-4e80-babe-1f5d29590000', 'Sentadilla con barra', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/BARBELL-SQUAT.gif', '{"Coloque la barra en una rejilla para sentadillas justo debajo de la altura de los hombros. Pase debajo y apoye la barra sobre los trapecios superiores o los deltoides posteriores.","Conduce con los talones para volver a la posición de pie, manteniendo la columna neutra.","Agarre la barra con firmeza, tire de los codos hacia abajo y hacia abajo y levante la barra del soporte.","Da un paso atrás, separa los pies a la altura de los hombros y refuerza el core.","Baje el cuerpo empujando las caderas hacia atrás y doblando las rodillas, manteniendo el pecho erguido.","Desciende hasta que tus muslos queden paralelos al suelo o más abajo si la movilidad lo permite."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4be6cb4e-c0de-4e80-babe-4be6cb4e0000', 'Curl de bíceps acostado en polea', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/lying-cable-curl.gif', '{"Recuéstese en un banco plano, con los pies apoyados en el suelo y la cabeza y los hombros apoyados en el banco.","Agarre el cable de la polea baja con un agarre desde abajo, manteniendo las manos separadas al ancho de los hombros.","Mantenga las muñecas rectas y los codos cerca de los costados durante todo el movimiento.","Cuando llegues a la parte superior del curl, concéntrate en apretar los bíceps y mantener la contracción por un momento.","Extiende completamente los brazos, de modo que el cable tire del bíceps.","Flexione lentamente los codos y doble el accesorio del cable hacia los hombros, mientras contrae los bíceps.","Baje lentamente el cable hasta la posición inicial, manteniendo la tensión en los bíceps durante todo el movimiento.","Repita para el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('10197e0d-c0de-4e80-babe-10197e0d0000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Skater-Squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4de19cb1-c0de-4e80-babe-4de19cb10000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Astride-Jumps.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6dd1d5c3-c0de-4e80-babe-6dd1d5c30000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/bodyweight-squat-full-version.gif', '{"Párese con los pies separados a la altura de los hombros y los dedos ligeramente apuntando hacia afuera.","Apoye su núcleo y mantenga su pecho elevado mientras comienza el movimiento.","Desciende hasta que tus muslos queden paralelos al suelo o tan bajos como te resulte cómodo.","Empuje las caderas hacia atrás y doble las rodillas para ponerse en cuclillas.","Conduce con los talones para volver a levantarte, apretando los glúteos en la parte superior."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('30896252-c0de-4e80-babe-308962520000', 'Sentadilla con barra', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/BARBELL-SQUAT.gif', '{"- Coloque la barra en una rejilla para sentadillas justo debajo de la altura de los hombros. Pase debajo y apoye la barra sobre los trapecios superiores o los deltoides posteriores.","- Conduce con los talones para volver a la posición de pie, manteniendo la columna neutra.","- Agarre la barra con fuerza para enganchar la parte superior de la espalda y los dorsales.","- Posición inadecuada de la barra, que provoca malestar o inestabilidad.","###","- Agarre la barra con firmeza, tire de los codos hacia abajo y hacia abajo y levante la barra del soporte.","- Da un paso atrás, separa los pies a la altura de los hombros y refuerza el core.","- Desciende hasta que tus muslos queden paralelos al suelo o más abajo si la movilidad lo permite.","- Baje el cuerpo empujando las caderas hacia atrás y doblando las rodillas, manteniendo el pecho erguido.","- Empuje las rodillas alineadas con los dedos de los pies durante el descenso.","- Ponerse en cuclillas demasiado superficialmente, lo que reduce el rango de movimiento y la efectividad.","- Apoye su núcleo antes de cada repetición para proteger su espalda baja.","### Errores comunes","- Dejar que las rodillas colapsen hacia adentro, lo que tensiona las articulaciones.","### Consejos para una forma adecuada","- Mantenga el pecho erguido y evite inclinarse demasiado hacia adelante.","- Mantenga la espalda plana y evite arquear la columna.","- Levantar los talones del suelo, lo que reduce la estabilidad.","- Inclinación excesiva hacia adelante, lo que aumenta el riesgo de tensión en la espalda."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('455e1e23-c0de-4e80-babe-455e1e230000', 'Ejercicio de pie', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Standing-Hip-Abduction-1.gif', '{"El foco de este ejercicio está en el glúteo medio y el glúteo menor que se encuentra debajo. Si el objetivo es fortalecer y dar forma a la cadera (glúteos superiores y externos), entonces la abducción de cadera es una excelente opción."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0fdd9fd4-c0de-4e80-babe-0fdd9fd40000', 'Elevaciones frontales sentado con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/seated-dumbbell-front-raise.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('449dc8ac-c0de-4e80-babe-449dc8ac0000', 'Postura de yoga', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Tiger-Yoga-Pose.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('549c2856-c0de-4e80-babe-549c28560000', 'Sentadilla con barra', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Barbell-Bulgarian-Split-Squat.gif', '{"- Coloque un banco detrás de usted aproximadamente a la altura de las rodillas.","- Cargue una barra en la parte superior de la espalda en una posición de barra baja o alta.","- Párese aproximadamente a dos pies frente al banco con los pies separados a la altura de las caderas.","- Coloque la parte superior de su pie trasero en el banco y active su núcleo.","- Presione a través del talón delantero para regresar a la posición inicial.","### Paso 1: configuración y posicionamiento","- Bájese doblando la rodilla delantera y manteniendo el pecho erguido.","### Paso 2: Ejecución","- Desciende hasta que tu muslo delantero quede paralelo al suelo o ligeramente por debajo.","- Repita para las repeticiones deseadas, luego cambie de pierna."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('06f038c9-c0de-4e80-babe-06f038c90000', 'Ejercicio de pie', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Standing-Toe-Touch.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1be7707e-c0de-4e80-babe-1be7707e0000', 'Prensa de piernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2015/11/Leg-Press.gif', '{"Ajuste la posición del asiento: Siéntese en el asiento con la espalda contra el respaldo y los pies apoyados sobre la plataforma. Tus rodillas deben estar dobladas en un ángulo de 90 grados.","Ajuste el peso: agregue placas de peso a la máquina según el nivel de intensidad deseado. Comienza con un peso que puedas manejar cómodamente y auméntalo gradualmente a medida que avances.","Colocación de los pies: Coloque los pies separados a la altura de las caderas en la plataforma, con los dedos apuntando hacia adelante o ligeramente hacia afuera. Asegúrese de que sus pies estén colocados firme y seguramente en la plataforma.","Preparación: Agarre las manijas o soportes laterales de la máquina para mayor estabilidad. Respira profundamente y fortalece tus músculos centrales.","Ejecución: Empuja contra la plataforma con los pies y extiende las piernas alejando la plataforma de tu cuerpo. Mantenga la espalda contra el asiento durante todo el movimiento y evite bloquear las rodillas en la parte superior del movimiento.","Empuja contra la plataforma con los pies y extiende las piernas alejando la plataforma de tu cuerpo. Mantenga la espalda contra el asiento durante todo el movimiento y evite bloquear las rodillas en la parte superior del movimiento.","Bajar el peso: Doble lentamente las rodillas y baje el peso hacia abajo, permitiendo que las rodillas alcancen un ángulo de 90 grados o un poco más sin dejar que el peso toque el suelo por completo.","Repetir: Completa el número deseado de repeticiones, manteniendo el control y la forma adecuada durante todo el ejercicio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('16a2c5d0-c0de-4e80-babe-16a2c5d00000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Jump-Squat.gif', '{"Párese erguido con los pies separados a la altura de los hombros y los brazos a los costados.","Explota hacia arriba, saltando lo más alto que puedas mientras mueves los brazos para ganar impulso.","Baje hasta ponerse en cuclillas doblando las rodillas y las caderas hasta que los muslos queden paralelos al suelo.","Aterriza suavemente doblando las rodillas y absorbiendo el impacto a través de las piernas.","Reinicie inmediatamente en su siguiente sentadilla y repita para las repeticiones deseadas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6f5f2410-c0de-4e80-babe-6f5f24100000', 'Sentadilla con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/09/Dumbbell-Squat.gif', '{"- Configuración: Párese con los pies separados a la altura de los hombros. Puede sostener una mancuerna en cada mano a los costados o usar una sola mancuerna sostenida con ambas manos frente a su pecho (estilo sentadilla en copa).","- Ascenso: empuja los talones y mueve las caderas hacia adelante para volver a levantarte. Mantenga la espalda recta mientras se levanta. Exhala mientras regresas a la posición inicial.","###","- Mueva las rodillas alineadas con los dedos de los pies mientras desciende.","- Sujete las mancuernas de forma segura y evite el balanceo excesivo.","- Controle el tempo para maximizar el compromiso muscular.","- Descenso: Comienza el movimiento empujando las caderas hacia atrás, como si estuvieras sentado en una silla. Mantenga las rodillas alineadas con los dedos de los pies y permita que se doblen mientras baja. Es importante mantener la columna neutra durante todo el movimiento.","- Profundidad: baje el cuerpo hasta que los muslos queden al menos paralelos al suelo, o profundice si puede sin comprometer la forma. Lo ideal es que tus muslos estén paralelos al suelo o por debajo del paralelo para lograr un rango completo de movimiento.","- Mantén los talones en el suelo y evita que se levanten.","- Permitir que las rodillas se doblen hacia adentro, lo que reduce la seguridad de las articulaciones.","### Errores comunes","- Inclinarse demasiado hacia adelante, alejando la tensión de las piernas.","- Usar el impulso para levantar en lugar de la fuerza controlada.","- Postura: Mantenga el pecho erguido y los hombros hacia atrás. Mantenga un arco natural en la parte baja de la espalda y active los músculos centrales para lograr estabilidad.","- Repetición: repita la sentadilla durante el número deseado de repeticiones.","### Consejos para una forma adecuada","- Mantenga el pecho erguido y los hombros retraídos.","- No agacharse lo suficientemente profundo, lo que limita la efectividad.","- Redondear la espalda, lo que aumenta el riesgo de lesiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6723e0a5-c0de-4e80-babe-6723e0a50000', 'Peso muerto sumo', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Barbell-Sumo-Deadlift.gif', '{"Aumenta la testosterona: Se ha demostrado mediante investigaciones que los ejercicios con pesas ayudan a aumentar los niveles de testosterona a corto y largo plazo. Ejercicios como press de banca, sentadillas y peso muerto son los ejercicios más efectivos que aumentan los niveles de testosterona.","Fortalece la capacidad de agarre. Le permite agarrar un objeto con más firmeza cuando lo sostiene. Además, los estudios demuestran que el peso muerto es un ejercicio eficaz para mejorar la fuerza explosiva y el rendimiento del salto vertical.","Sumo Deadlift ayuda al desarrollo de los músculos de las piernas, los músculos de la cadera y los músculos centrales, al mismo tiempo que apoya la formación de músculos y fuerza en el cuerpo. Además, agregar peso muerto a tus entrenamientos ayuda a fortalecer tus tendones, ligamentos y huesos.","El peso muerto de sumo también activa los glúteos y los músculos de la espalda. Los ejercicios funcionales como el peso muerto son aquellos que facilitan las actividades del cuerpo en la vida real.","El peso muerto de sumo se enfoca en muchos de los mismos músculos que desarrolla un peso muerto convencional, pero enfatiza más los músculos de la espalda, los isquiotibiales y la cadera. Es el movimiento más popular de fuerza y ​​entrenamiento de fuerza ya que trabaja muchos grupos de músculos.","La forma correcta es muy importante en este ejercicio. Para empezar, hacer mal puede provocar lesiones. Tras algunos intentos con la barra vacía o acompañado de un entrenador, el proceso de adaptación al movimiento puede verse acortado.","Sumo Deadlift se enfoca en todos los músculos responsables de su postura y le permite mantener la espalda recta durante las actividades diarias habituales."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2521ff9e-c0de-4e80-babe-2521ff9e0000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Pistol-Squat.gif', '{"Los beneficios de la sentadilla con pistola son notables en muchos sentidos. La finalidad de este ejercicio con peso corporal es mejorar el equilibrio, la fuerza y ​​la coordinación. La sentadilla con pistola aumenta la movilidad y la flexibilidad de la articulación del tobillo. Es un gran ejercicio para fortalecer los músculos estabilizadores y aumentar la resistencia de la pierna.","Los ejercicios con peso corporal son muy eficaces para desarrollar músculos y fuerza, además de mejorar la coordinación y la aptitud funcional. Gracias a la sentadilla Pistol, puedes desarrollar la fuerza y ​​los músculos de una sola pierna por igual y así beneficiar tu estructura atlética general.","El ejercicio de sentadilla con pistola requiere un alto nivel de equilibrio, coordinación, estabilidad básica y fuerza en las piernas. Este movimiento es uno de los ejercicios más difíciles, incluso para deportistas avanzados."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('637b31e8-c0de-4e80-babe-637b31e80000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Leg-Raise-Dragon-Flag.gif', '{"Acuéstese boca arriba sobre un banco resistente o una superficie plana. Asegúrese de que su cabeza esté apoyada, ya sea agarrándose del banco o usando un cojín para el cuello. Coloque sus manos firmemente sobre el banco o agárrese de una superficie estable sobre su cabeza.","Levanta la bandera: una vez que tus piernas estén cerca del banco o del suelo (pero sin tocarse), invierte el movimiento usando tu fuerza central para levantar las piernas y las caderas hasta la posición inicial.","Configuración: Acuéstese boca arriba sobre un banco resistente o una superficie plana. Asegúrese de que su cabeza esté apoyada, ya sea agarrándose del banco o usando un cojín para el cuello. Coloque sus manos firmemente sobre el banco o agárrese de una superficie estable sobre su cabeza.","Elevación de piernas: levante las piernas y las caderas del banco o del suelo, manteniéndolas rectas. Tu cuerpo debe formar una línea recta desde tu cabeza hasta tus pies. Involucre sus músculos centrales para estabilizar su cuerpo.","Descenso controlado: baja lentamente las piernas y las caderas hacia el banco manteniendo una línea recta del cuerpo. Concéntrate en usar tus músculos abdominales para controlar el movimiento. Esta es la parte más desafiante del ejercicio, así que tómate tu tiempo.","Repetir: realice el ejercicio con el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('38fe9b40-c0de-4e80-babe-38fe9b400000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/sissy-squat.gif', '{"Párese erguido con los pies separados a la altura de las caderas y los talones ligeramente elevados o apoyados.","Conduce a través de los dedos de los pies para volver a la posición inicial, manteniendo el cuerpo alineado.","Permita que las rodillas avancen sobre los dedos de los pies mientras la parte superior del cuerpo se inclina hacia atrás en línea recta.","Baja hasta sentir un estiramiento profundo en los cuádriceps o alcanzar tu límite de movilidad.","Apoye su núcleo y mantenga un pecho alto mientras comienza a inclinarse hacia atrás desde las rodillas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2cb8c7c3-c0de-4e80-babe-2cb8c7c30000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/09/Depth-Jump-to-Hurdle-Hop.gif', '{"Salto de profundidad: Párese encima de la caja o plataforma pliométrica con los pies separados a la altura de las caderas. Comience bajando de la caja y dejándose caer rápidamente al suelo, permitiendo que sus rodillas se doblen ligeramente para absorber el impacto. Tan pronto como sus pies entren en contacto con el suelo, inmediatamente salte explosivamente, usando sus brazos para generar impulso. El salto de profundidad está diseñado para ser un salto rápido y poderoso, así que asegúrese de no pasar mucho tiempo en el suelo.","Salto de vallas: después del salto de profundidad, haga la transición inmediatamente al salto de vallas. A medida que asciende desde el salto de profundidad, intente superar el primer obstáculo levantando las rodillas en alto. Aterrice en el otro lado de la valla y prepárese rápidamente para el siguiente salto.","Coloca los obstáculos: organiza una serie de obstáculos a diferentes alturas en línea recta, dejando suficiente espacio entre ellos para poder aterrizar y saltar entre cada uno de ellos.","Tan pronto como tus pies entren en contacto con el suelo, salta inmediatamente de manera explosiva, usando tus brazos para ganar impulso.","El salto de profundidad está pensado para ser un salto rápido y potente, así que asegúrate de no pasar mucho tiempo en el suelo.","Comience bajando de la caja y dejándose caer rápidamente al suelo, permitiendo que las rodillas se doblen ligeramente para absorber el impacto.","Después del salto de profundidad, haga la transición inmediatamente al salto de vallas.","A medida que asciendes desde el salto de profundidad, intenta superar el primer obstáculo levantando las rodillas en alto.","Repetir: continúe realizando la secuencia de salto de profundidad a salto de vallas durante el número deseado de repeticiones o durante un período de tiempo establecido.","Aterriza al otro lado del obstáculo y prepárate rápidamente para el siguiente salto."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0ec0908f-c0de-4e80-babe-0ec0908f0000', 'Elevaciones laterales con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Dumbbell-Lateral-to-Front-Raise.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5a4453ff-c0de-4e80-babe-5a4453ff0000', 'Dominadas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2023/06/Front-Lever-Pull-up.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3805b83c-c0de-4e80-babe-3805b83c0000', 'Plancha', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2023/07/High-Plank.gif', '{"- Comience en posición de flexión de brazos, con las manos directamente debajo de los hombros y las piernas extendidas detrás de usted.","- Presione firmemente con las manos, manteniendo los hombros activos y estables.","- Mantenga la posición mientras respira de manera constante, evitando hundirse o arquearse.","- Comience con 20 a 30 segundos y aumente gradualmente el tiempo a medida que mejora la fuerza.","- Involucre los cuádriceps para mantener una línea de cuerpo rígida.","- Distribuya la presión uniformemente entre los dedos de las manos y los pies.","### Errores comunes","- Dejar que las caderas se caigan, lo que genera tensión en la parte baja de la espalda.","- Levantar demasiado las caderas reduce el compromiso del core.","- Encogimiento de hombros, provocando tensión en el cuello.","- Involucre su núcleo, apriete sus glúteos y mantenga su cuerpo en línea recta desde la cabeza hasta los talones.","### Consejos para una forma adecuada","- Mantenga la cabeza neutral, sin dejar caer ni estirar el cuello.","- Apriete los glúteos para proteger la zona lumbar.","- Mantenga una respiración constante sin contener la respiración.","- Bloquear completamente los codos, reduciendo la estabilidad de los hombros.","- No involucrar al núcleo, lo que lleva a una mala alineación y efectividad."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('72c79766-c0de-4e80-babe-72c797660000', 'Remo', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/09/Ball-Russian-Twist-throw-with-partner.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2392c17f-c0de-4e80-babe-2392c17f0000', 'Postura de yoga', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Crab-Pose.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('61fcf5b0-c0de-4e80-babe-61fcf5b00000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/push-up-with-rotation.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('55af6bed-c0de-4e80-babe-55af6bed0000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Pike-to-Cobra.gif', '{"comience en una posición de perro boca abajo. Esto es similar a una postura de yoga. Comience con las manos y las rodillas, luego levante las caderas y estire las piernas para formar una V invertida con su cuerpo. Tus manos deben estar separadas al ancho de los hombros y tus pies deben estar separados al ancho de las caderas.","Mueva su peso hacia adelante, bajando la parte superior del cuerpo hacia el suelo mientras mantiene los brazos rectos.","Desde la posición del perro boca abajo, empuja las caderas hacia atrás y hacia arriba, moviéndolas hacia el techo. Tu cabeza debe mirar hacia atrás entre tus piernas.","Posición inicial: comience en una posición de perro boca abajo. Esto es similar a una postura de yoga. Comience con las manos y las rodillas, luego levante las caderas y estire las piernas para formar una V invertida con su cuerpo. Tus manos deben estar separadas al ancho de los hombros y tus pies deben estar separados al ancho de las caderas.","Descenso (fase de bombardero en picado): desplaza tu peso hacia adelante, bajando la parte superior del cuerpo hacia el suelo mientras mantienes los brazos rectos. Continúa avanzando hasta que tu pecho casi toque el suelo. Tus caderas estarán bajas y tu espalda arqueada, asemejándote a una postura de yoga de perro mirando hacia arriba. A medida que desciendes, asegúrate de mirar hacia arriba y hacia adelante, permitiendo que tu cabeza suba y tu espalda se arquee profundamente.","Continúe avanzando hasta que su pecho casi toque el suelo. Tus caderas estarán bajas y tu espalda arqueada, asemejándote a una postura de yoga de perro mirando hacia arriba.","Desde la posición del perro boca abajo, empuja las caderas hacia atrás y hacia arriba, moviéndolas hacia el techo. Su cabeza debe mirar hacia atrás entre sus piernas. A medida que sus caderas se elevan, doble los codos y baje el pecho hasta la posición inicial. Continúe este movimiento hasta que regrese a la posición del perro hacia abajo.","Ascenso: Desde la posición del perro boca abajo, empuja las caderas hacia atrás y hacia arriba, moviéndolas hacia el techo. Su cabeza debe mirar hacia atrás entre sus piernas. A medida que sus caderas se elevan, doble los codos y baje el pecho hasta la posición inicial. Continúe este movimiento hasta que regrese a la posición del perro hacia abajo.","A medida que las caderas se elevan, doble los codos y baje el pecho hasta la posición inicial.","Repetir: repita la secuencia durante el número deseado de repeticiones, manteniendo un flujo suave y controlado entre las diferentes posiciones.","Continúe este movimiento hasta que regrese a la posición del perro boca abajo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('281388f0-c0de-4e80-babe-281388f00000', 'Prensa de piernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Lever-Horizontal-Leg-Press.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('78e84b5f-c0de-4e80-babe-78e84b5f0000', 'Postura de yoga', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Frog-Pose-mandukasana.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7e50736c-c0de-4e80-babe-7e50736c0000', 'Curl de bíceps inclinado con mancuernas', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Flexor-Incline-Dumbbell-Curls.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('682629a3-c0de-4e80-babe-682629a30000', 'Flexión de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Push-Up.gif', '{"- Posición inicial: Comience en una posición de tabla alta con las manos ligeramente más separadas que el ancho de los hombros. Mantenga el cuerpo en línea recta desde la cabeza hasta los talones. Involucre su núcleo y mantenga el cuello neutral.","- Comience en una posición de tabla alta con las manos ligeramente más separadas que el ancho de los hombros.","- Exhala mientras empujas con las palmas de las manos para volver a la posición inicial.","- Coloque sus manos firmemente en el suelo para una mejor estabilidad.","###","- Realice repeticiones controladas a un ritmo constante para maximizar la participación muscular.","- Evite bloquear los codos en la parte superior del movimiento.","- Fase de descenso: Inhale mientras dobla los codos y baja el pecho hacia el suelo. Mantenga los codos en un ángulo de 45 grados con respecto al torso. Baje hasta que el pecho esté justo por encima del suelo o hasta donde la movilidad lo permita.","- Inhala mientras doblas los codos y bajas el pecho hacia el suelo.","- Baje hasta que su pecho esté justo por encima del suelo o hasta donde la movilidad lo permita.","- Fase de presión: exhale mientras empuja con las palmas de las manos para volver a la posición inicial. Extienda completamente los brazos mientras mantiene el compromiso central.","- Extienda completamente los brazos mientras mantiene el compromiso central.","### Errores comunes:","- Permitir que las caderas se hunda: esto reduce el compromiso del core y puede tensar la espalda baja.","- Ensanchar los codos: Mantener los codos demasiado anchos genera tensión en los hombros.","- Mantenga su cuerpo en línea recta desde la cabeza hasta los talones.","- Involucre su núcleo y mantenga su cuello neutral.","- Mantenga los codos en un ángulo de 45 grados con respecto al torso.","- Repetición y respiración: realice repeticiones controladas a un ritmo constante para maximizar la participación de los músculos.","### Consejos para una forma adecuada:","- Mantenga su núcleo apretado para evitar que la zona lumbar se hunda.","- Mantenga una línea corporal recta desde la cabeza hasta los talones.","- Contener la respiración: Respirar adecuadamente garantiza el flujo de oxígeno y una mejor resistencia.","- Rango de movimiento incompleto: realizar medias repeticiones limita la activación muscular y el aumento de fuerza."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('05e53574-c0de-4e80-babe-05e535740000', 'Flexiones de pecho declinado', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2015/07/Decline-Push-Up.gif', '{"- Establezca su posición: Coloque los pies sobre una superficie elevada (banco, escalón o plataforma resistente). Coloque las manos en el suelo separadas al ancho de los hombros. Mantenga el cuerpo en línea recta desde la cabeza hasta los talones.","- Coloque los pies sobre una superficie elevada (banco, escalón o plataforma resistente).","- Coloque las manos en el suelo separadas a la altura de los hombros.","- Presione con las palmas y empújese hacia atrás a la posición inicial.","###","### Guía paso a paso","- Empuje hacia arriba: presione con las palmas y empújese hacia atrás a la posición inicial. Mantenga el núcleo y los glúteos comprometidos para lograr estabilidad. Extienda completamente los brazos en la parte superior sin bloquear los codos.","- Extiende completamente los brazos en la parte superior sin bloquear los codos.","- Baje el cuerpo: active su núcleo y baje lentamente el pecho hacia el suelo. Mantenga los codos en un ángulo de 45 grados con respecto al cuerpo. Mantenga un movimiento controlado sin dejar que las caderas se doblen o se levanten.","- Involucre su núcleo y baje lentamente su pecho hacia el piso.","- Mantenga un movimiento controlado sin dejar que las caderas se doblen o se levanten.","- Controla la fase de descenso y flexiones para maximizar la activación muscular.","- Respire adecuadamente: inhale mientras baja, exhale mientras empuja hacia arriba.","- Dejar que las caderas se doblen o se eleven, lo que reduce la eficacia y tensa la zona lumbar.","- Acelerar el movimiento, reduciendo el tiempo bajo tensión y compromiso muscular.","- Falta de rango completo de movimiento, lo que impide la activación óptima del pecho.","- No dejes que la parte baja de tu espalda se hunda, ya que esto puede causar tensión.","- Elija una altura de descenso adecuada: una elevación más alta aumenta la dificultad.","### Errores comunes a evitar","- Mantenga su cuerpo en línea recta desde la cabeza hasta los talones.","- Mantenga los codos en un ángulo de 45 grados con respecto a su cuerpo.","- Mantenga el núcleo y los glúteos comprometidos para lograr estabilidad.","- Repeticiones y series: intente realizar de 3 a 4 series de 10 a 15 repeticiones, ajustando la dificultad según el nivel de condición física.","- Intente realizar de 3 a 4 series de 10 a 15 repeticiones, ajustando la dificultad según el nivel de condición física.","### Consejos para una forma adecuada","- Mantenga su núcleo comprometido para mantener una columna neutral.","- Colocar las manos demasiado hacia adelante, lo que genera una tensión innecesaria en los hombros.","- Arquear la zona lumbar, provocando una forma inadecuada y posibles lesiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('22b9ba3b-c0de-4e80-babe-22b9ba3b0000', 'Elevación de piernas', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/arm-leg-raise.gif', '{"Es un ejercicio diseñado para trabajar las caderas, la espalda, los hombros y los músculos centrales y fortalecer la estabilidad general.","Las elevaciones de brazos y piernas también son un ejercicio que requiere concentración mental, obliga a que los movimientos se realicen en armonía y ayuda a mejorar el equilibrio y la coordinación.","Este ejercicio, que también se aplica como ejercicio de calentamiento, puede trabajar incluso las fibras musculares más pequeñas desde diferentes ángulos para fortalecer los músculos centrales. También es una forma segura y eficaz de fortalecer y equilibrar los músculos de la columna, la espalda y el cuello. Una estructura sólida de la columna y músculos fuertes de la espalda pueden ayudar a mejorar la postura y aliviar y prevenir el dolor de espalda."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3a42ec33-c0de-4e80-babe-3a42ec330000', 'Elevación de piernas', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Hanging-Leg-Raises.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3d71371b-c0de-4e80-babe-3d71371b0000', 'Dominadas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/neutral-grip-pull-up.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4cbf7b69-c0de-4e80-babe-4cbf7b690000', 'Zancadas con barra', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Barbell-Lateral-Lunge.gif', '{"Las estocadas laterales con barra desarrollan el equilibrio, la estabilidad y la fuerza. Trabajan la parte interna y externa de los muslos e incluso pueden ayudar a reducir la apariencia de la celulitis."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('621042ba-c0de-4e80-babe-621042ba0000', 'Ejercicio con banda de resistencia', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Banded-Glute-Bridge.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3fff8599-c0de-4e80-babe-3fff85990000', 'Puente de glúteos', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Glute-Bridge-.gif', '{"El grupo de músculos objetivo del ejercicio del puente de glúteos son los músculos de la cadera. Puedes incluirlo en tu programa de ejercicios para tensar y tonificar los músculos de la cadera, así como mejorar la movilidad de la cadera y fortalecer tu cintura.","Fortalece los músculos centrales: el ejercicio del puente activa todos los músculos centrales, incluidos el transverso del abdomen, el recto abdominal y los oblicuos. El puente de glúteos te ayudará a estabilizar el centro del cuerpo, los isquiotibiales, la espalda, el vientre y también los glúteos. Aunque el ejercicio se dirige al área de los glúteos, el puente de glúteos hace un gran trabajo al activar y fortalecer los músculos estabilizadores centrales.","Los ejercicios de puente generalmente son seguros para personas con problemas crónicos de espalda y pueden ayudar a controlar el dolor."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('316cfbbf-c0de-4e80-babe-316cfbbf0000', 'Ejercicio con banda de resistencia', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Banded-Glute-Bridge.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('68c4a81e-c0de-4e80-babe-68c4a81e0000', 'Remo en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Cable-Upright-Row.gif', '{"El remo vertical con cable es un ejercicio de aislamiento dirigido al trapecio y los deltoides, que son responsables de agregar ancho a los hombros.","El remo vertical con cable es uno de los ejercicios efectivos para construir trampas más grandes, pero también es un movimiento en el que es fácil cometer errores. Una de las formas más sencillas de asegurarse de que su forma sea óptima es evitar el uso de mancuernas que sean demasiado pesadas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('74bc814b-c0de-4e80-babe-74bc814b0000', 'Ejercicio', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Barbell-Power-Snatch.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0a2274f3-c0de-4e80-babe-0a2274f30000', 'Giro ruso sentado con barra', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Barbell-Seated-Twist.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('26202389-c0de-4e80-babe-262023890000', 'Curl de muñeca con mancuernas', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Dumbbell-Wrist-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('094c57f2-c0de-4e80-babe-094c57f20000', 'Estiramiento', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Stretch-With-Towel.gif', '{"### Paso 1: póngase en posición","- Párese con los pies separados a la altura de los hombros para mayor estabilidad.","- Libera lentamente la tensión, bajando los brazos hasta la posición inicial.","- Sostenga una toalla detrás de su espalda con una mano agarrando el extremo superior y la otra sosteniendo el extremo inferior.","- Cambie de lado y repita, asegurando una flexibilidad uniforme en ambos hombros.","### Paso 2: realice el estiramiento","- Tire suavemente de la toalla hacia arriba con la mano superior y lleve la mano inferior a lo largo de la espalda.","- No fuerces el movimiento; trabaje dentro de su cómodo rango de movimiento.","- Respire profundamente mientras mantiene el estiramiento para mejorar la relajación.","- Mantenga el estiramiento durante 15 a 30 segundos y sienta un estiramiento en los hombros y tríceps.","### Paso 3: Respiración y Control"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6084ac72-c0de-4e80-babe-6084ac720000', 'Estiramiento', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2023/03/Wrist-Stretch.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('47031718-c0de-4e80-babe-470317180000', 'Curl de muñeca con mancuernas', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Dumbbell-Wrist-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('70413e2e-c0de-4e80-babe-70413e2e0000', 'Curl de muñeca con mancuernas', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Dumbbell-Wrist-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5c0926a9-c0de-4e80-babe-5c0926a90000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Farmers-walk_Cardio.gif', '{"Comience seleccionando dos objetos pesados ​​o pesos de igual peso. Pueden ser mancuernas, pesas rusas, barras, sacos de arena u otros objetos pesados ​​con asas.","Párese erguido con la columna neutra y el núcleo apretado.","Levante las pesas, una en cada mano, con un agarre neutral (las palmas una frente a la otra).","Camine una distancia predeterminada o durante un tiempo determinado mientras sostiene las pesas a los costados.","Una vez que llegue al final de la distancia o el tiempo de caminata, coloque las pesas con cuidado.","Mantenga una postura erguida, mantenga los hombros hacia atrás y evite inclinarse excesivamente hacia adelante o hacia atrás."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2ad55afa-c0de-4e80-babe-2ad55afa0000', 'Elevación', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Hanging-Knee-Raises.gif', '{"Su propio peso corporal actúa como resistencia que ayuda a aumentar su resistencia y desarrollar su resistencia. Este ejercicio que trabaja los flexores de la cadera mejora los músculos centrales, especialmente los músculos abdominales inferiores. Es uno de los mejores ejercicios para abdominales que activa todo el core ejercitando no sólo los abdominales inferiores sino también los músculos abdominales superiores."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4bb5e1ef-c0de-4e80-babe-4bb5e1ef0000', 'Curl de bíceps en polea', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/overhead-cable-curl.gif', '{"Seleccione una máquina de cable asegurándose de que ambas empuñaduras estén colocadas en alto.","Seleccione el peso apropiado para las repeticiones requeridas. Sujete ambas uniones de cables y tense la tensión, moviéndose hacia el centro.","Permita que sus brazos estén hacia los lados y en una posición elevada. (Esta es su posición inicial).","En este punto, comience a invertir lentamente el movimiento de regreso a su posición inicial.","Desde esta posición, genere movimiento flexionando los codos.","Continúe flexionando hasta que sus antebrazos y la región del bíceps hagan contacto.","Esta es una repetición. Continúe hasta completar las repeticiones necesarias."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('45a98835-c0de-4e80-babe-45a988350000', 'Curl de bíceps inclinado en polea', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Cable-Two-Arm-Curl-on-Incline-Bench.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('32ae29c7-c0de-4e80-babe-32ae29c70000', 'Estiramiento', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Toe-Extensor-Stretch.gif', '{"párese erguido con los pies separados a la altura de las caderas.","Cambie el peso hacia adelante: transfiera su peso ligeramente a la pierna delantera, permitiendo que el pie trasero presione suavemente el piso para crear un estiramiento en la parte superior del pie y la espinilla.","Cambiar de lado: regrese a la posición inicial y repita con el pie opuesto.","Posición inicial: párese erguido con los pies separados a la altura de las caderas.","Paso atrás: Extienda una pierna detrás de usted y coloque la parte superior de los dedos de los pies en el suelo con el pie apuntando hacia abajo.","Mantenga la posición: mantenga el torso erguido, los hombros relajados y la columna neutra mientras mantiene el equilibrio.","Duración: Mantén el estiramiento durante 20 a 30 segundos, respirando profundamente y evitando rebotes."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0c1c02b2-c0de-4e80-babe-0c1c02b20000', 'Curl de muñeca con mancuernas', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Dumbbell-Wrist-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('29368129-c0de-4e80-babe-293681290000', 'Estiramiento', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2023/03/Wrist-Stretch.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('03578a70-c0de-4e80-babe-03578a700000', 'Ejercicio', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Human-Flag.gif', '{"Busque un poste o barra vertical resistente que pueda soportar su peso. Párate al lado del poste y sujétalo con tu mano más fuerte. Tu mano debe estar a la altura del hombro.","Su mano superior asumirá un agarre por encima de la cabeza y tirará de la barra. Luego, coloque la mano inferior en el extremo inferior del poste con un agarre por debajo. Esta mano empujará la barra y, juntos, estos dos movimientos elevarán gradualmente el torso del suelo.","Levanta los pies del suelo y coloca las piernas paralelas al suelo. Debes apoyar todo el peso de tu cuerpo sobre las manos y la parte superior del cuerpo.","Mantén la posición de bandera humana todo el tiempo que puedas antes de volver a bajar lentamente al suelo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3c54f20c-c0de-4e80-babe-3c54f20c0000', 'Zancadas en polea', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Cable-Forward-Lunge.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7d224da3-c0de-4e80-babe-7d224da30000', 'Curl de bíceps con barra', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/09/Barbell-Finger-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('77661c6d-c0de-4e80-babe-77661c6d0000', 'Ejercicio', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/StrongMan-Tire-Flip.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2b252e17-c0de-4e80-babe-2b252e170000', 'Ejercicio', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/wrist-roller.gif', '{"Haga rodar el rodillo de muñeca hacia su cuerpo, usando solo sus muñecas para mover el peso por la cuerda y hacia sus manos.","Párate o siéntate con los brazos extendidos frente a ti, manteniendo los codos cerca del cuerpo y las manos al nivel de los hombros.","Haga una pausa por un momento en la parte superior del movimiento, luego haga rodar lentamente el peso por la cuerda hacia el piso.","Repita el movimiento durante varias repeticiones, concentrándose en mantener las muñecas estables y comprometidas durante todo el ejercicio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6e8ac20d-c0de-4e80-babe-6e8ac20d0000', 'Estiramiento', 'Antebrazos', '', '{"Los estiramientos de cuello también participan en la fisioterapia que tiene como objetivo rehabilitar los músculos, las articulaciones y los huesos del cuello. Los estiramientos de cuello tienen como objetivo aumentar la fuerza, el tono y la flexibilidad de los músculos del cuello. También permite que los ligamentos de las articulaciones del cuello se vuelvan más flexibles y resistan una mayor tensión en el área.","Cuando la cabeza y los hombros se inclinan hacia adelante debido a una mala postura, algunos músculos del pecho y el cuello pueden acortarse y tensarse con el tiempo, lo que puede perpetuar la mala postura que causa el dolor de cuello. Los ejercicios de estiramiento del cuello pueden ayudar a relajar los músculos posturales y reducir el dolor de cuello."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('12cc5ecd-c0de-4e80-babe-12cc5ecd0000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/push-up-with-rotation.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('639e81a0-c0de-4e80-babe-639e81a00000', 'Press de pecho inclinado en máquina', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Incline-Chest-Press-Machine.gif', '{"Siéntese en la máquina con la espalda firmemente apoyada en el respaldo. Coloque los pies apoyados en el suelo, separados a la altura de los hombros. Mantenga una columna neutra y active los músculos centrales para lograr estabilidad.","Sujete las manijas o empuñaduras a ambos lados de la máquina. Las palmas de las manos deben mirar hacia adelante y las manos deben estar separadas al ancho de los hombros o un poco más anchas, según su preferencia.","Con los brazos flexionados, acerca las asas al pecho. Tus codos deben estar a unos 45 grados o un poco más. Esta es tu posición inicial.","Posición inicial: Con los brazos flexionados, acerca las asas al pecho. Tus codos deben estar a unos 45 grados o un poco más. Esta es tu posición inicial.","Movimiento: Empuje las manijas hacia adelante y lejos de su cuerpo, extendiendo los brazos completamente pero sin bloquear los codos. Exhala mientras alejas las manijas.","Empuje las manijas hacia adelante y lejos de su cuerpo, extendiendo los brazos completamente pero sin bloquear los codos. Exhala mientras alejas las manijas.","Retorno controlado: Lleve lentamente las manijas a la posición inicial, manteniendo el control sobre el movimiento. Inhale mientras regresa a la posición inicial, permitiendo que los músculos del pecho se estiren.","Repetir: Complete el número deseado de repeticiones según su nivel de condición física y sus objetivos. Trate de realizar un movimiento controlado y suave durante todo el ejercicio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('651ac328-c0de-4e80-babe-651ac3280000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/push-up-with-rotation.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('23fdc76f-c0de-4e80-babe-23fdc76f0000', 'Zancadas declinado con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Decline-Bench-Dumbbell-Lunge.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1d7206e6-c0de-4e80-babe-1d7206e60000', 'Ejercicio en máquina', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Donkey-Kick-on-Smith-Machine.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7c0abb2c-c0de-4e80-babe-7c0abb2c0000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Close-Grip-Knee-Push-up.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0069b186-c0de-4e80-babe-0069b1860000', 'Press de pecho en máquina', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Smith-Machine-Bench-Press.gif', '{"- Coloque un banco plano debajo de la barra de la máquina Smith.","- Ajuste el banco para que la barra quede alineada con la mitad de su pecho cuando esté acostado.","- Recuéstese en el banco con los pies apoyados en el suelo y la espalda ligeramente arqueada.","- Agarre la barra ligeramente más ancha que el ancho de los hombros con las palmas hacia adelante.","- Fase de press: Empuja la barra hacia arriba para volver a la posición inicial. Extiende completamente los brazos pero evita bloquear los codos en la parte superior.","- Empuja la barra hacia arriba para volver a la posición inicial.","- Ajuste el banco correctamente: asegúrese de que el banco esté alineado correctamente para apuntar eficazmente al pecho.","- Utilice un peso apropiado: comience con un peso manejable para concentrarse en la forma antes de aumentar la resistencia.","- Experimente con la colocación de las manos: un agarre más amplio se dirige más al pecho, mientras que un agarre más estrecho desplaza el énfasis hacia los tríceps.","- Desenganche la barra girando las muñecas para soltar los ganchos de seguridad.","- Fase de descenso: baje lentamente la barra hacia el pecho doblando los codos. Mantenga los codos en un ángulo de aproximadamente 45 grados con respecto al torso. Deténgase cuando la barra esté justo encima del pecho o la toque ligeramente sin rebotar.","- Detente cuando la barra esté justo encima de tu pecho o la toque ligeramente sin rebotar.","- Baje lentamente la barra hacia su pecho doblando los codos.","- Controle el movimiento: realice el ejercicio con movimientos lentos y controlados para una máxima activación muscular.","- Descuidar el rango completo de movimiento: realice el ejercicio con un rango completo de movimiento para maximizar la participación de los músculos.","- Extienda completamente los brazos pero evite bloquear los codos en la parte superior.","- Repetir: Realiza el número deseado de repeticiones, manteniendo el control durante todo el movimiento.","### Errores comunes a evitar","- Mantenga los codos en un ángulo de aproximadamente 45 grados con respecto al torso.","### Consejos para una máxima eficacia","- Involucre el núcleo: mantenga su núcleo apretado para mantener la estabilidad y proteger su espalda baja.","- Hacer rebotar la barra: evite hacer rebotar la barra contra su pecho, lo que puede provocar lesiones y reducir la eficacia.","- Arquear la espalda: Mantenga un ligero arco en la parte baja de la espalda, pero evite arquearlo excesivamente para proteger su columna.","- Desalineación de la trayectoria de la barra: asegúrese de que la barra baje hacia la mitad de su pecho, no hacia el cuello o el abdomen.","- Bloquear los codos: No bloquee los codos en la parte superior para evitar tensión en las articulaciones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1eaf2cd6-c0de-4e80-babe-1eaf2cd60000', 'Flexiones de pecho inclinado', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Incline-Push-Up.gif', '{"- Elija una superficie elevada Utilice un banco resistente, una encimera o incluso una pared para pendientes más altas. Cuanto menor sea la inclinación, más desafiante será el ejercicio.","- Utilice un banco resistente, una encimera o incluso una pared para pendientes más altas. Cuanto menor sea la inclinación, más desafiante será el ejercicio.","- Posición inicial Da un paso con los pies hacia atrás hasta que tu cuerpo forme una línea recta desde la cabeza hasta los talones. Involucra tu núcleo y tus glúteos para mantener una columna neutral.","- Exhala mientras presionas las manos contra la superficie, estirando los brazos para volver a la posición inicial.","- ColóqueseColoque las manos a la altura de los hombros sobre la superficie elevada. Asegúrese de que sus dedos apunten hacia adelante y sus palmas estén planas.","- Coloque las manos a la altura de los hombros sobre la superficie elevada. Asegúrese de que sus dedos apunten hacia adelante y sus palmas estén planas.","- Da un paso atrás con los pies hasta que tu cuerpo forme una línea recta desde la cabeza hasta los talones.","- Involucre su núcleo y glúteos para mantener una columna neutral.","- Baje su cuerpo Inhale mientras dobla lentamente los codos, bajando el pecho hacia la superficie. Mantenga los codos en un ángulo de 45 grados con respecto al torso, evitando ensancharlos.","- Inhale mientras dobla lentamente los codos y baja el pecho hacia la superficie.","- Empuje hacia arriba Exhale mientras presiona las manos contra la superficie, estirando los brazos para volver a la posición inicial. Concéntrese en apretar el pecho y los tríceps mientras empuja hacia arriba.","- Controle el movimiento: muévase lenta y deliberadamente para maximizar la participación de los músculos.","- Ajuste la inclinación: comience con una inclinación más alta (por ejemplo, flexiones de pared) y baje gradualmente la superficie a medida que gane fuerza.","- Rango de movimiento inconsistente Baje el pecho completamente hacia la superficie para obtener un rango de movimiento completo.","- Baje el pecho completamente hacia la superficie para lograr un rango de movimiento completo.","- Acelerar el movimiento Realice el ejercicio lentamente para maximizar la activación muscular y reducir el riesgo de lesiones.","- Realice el ejercicio lentamente para maximizar la activación muscular y reducir el riesgo de lesiones.","- Concéntrate en apretar el pecho y los tríceps mientras empujas hacia arriba.","- Repetir Realice de 10 a 15 repeticiones para 2 a 3 series, según su nivel de condición física.","- Realice de 10 a 15 repeticiones durante 2 a 3 series, según su nivel de condición física.","### Errores comunes a evitar","- Mantenga los codos en un ángulo de 45 grados con respecto al torso, evitando ensancharlos.","### Consejos para una forma adecuada","- Involucre su núcleo: mantenga sus abdominales contraídos para evitar la flacidez de las caderas o la espalda arqueada.","- Mantenga la alineación: su cuerpo debe permanecer en línea recta durante todo el movimiento. Evite dejar caer las caderas o encoger los hombros.","- Codos ensanchados Mantenga los codos en un ángulo de 45 grados para reducir la tensión en los hombros.","- Mantenga los codos en un ángulo de 45 grados para reducir la tensión en los hombros.","- Caderas caídas Involucre su núcleo y glúteos para mantener una línea corporal recta.","- Involucre su núcleo y glúteos para mantener una línea corporal recta."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('14bbdf50-c0de-4e80-babe-14bbdf500000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Pike-Push-up.gif', '{"Muévase lentamente y con control para maximizar las ganancias de fuerza.","Empuje con las palmas de las manos para enganchar completamente los hombros.","Involucre sus piernas para mantener su cuerpo estable.","Mantenga su núcleo apretado para mantener el equilibrio y el control.","Mantenga los codos ligeramente doblados para proteger las articulaciones de los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0d89eae4-c0de-4e80-babe-0d89eae40000', 'Estiramiento', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Dynamic-Chest-Stretch.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7e01bb64-c0de-4e80-babe-7e01bb640000', 'Prensa de piernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Leg-Press-Calf-Raise.gif', '{"Siéntese en la máquina de prensa de piernas y coloque las puntas de los pies separadas al ancho de los hombros en la parte inferior de la plataforma para los pies, con los talones colgando.","Ajuste la carga: cargue la máquina con un peso de moderado a pesado que permita un rango completo de movimiento sin rebotar ni bloquear las rodillas.","Extienda las rodillas completamente (sin bloquearlas) para estabilizar la posición. Mantenga las piernas rectas y las caderas apoyadas contra la almohadilla.","Configuración: Siéntese en la máquina de prensa de piernas y coloque las puntas de los pies separadas al ancho de los hombros en la parte inferior de la plataforma para los pies, con los talones colgando.","Posición inicial: Extienda las rodillas completamente (sin bloquearlas) para estabilizar la posición. Mantenga las piernas rectas y las caderas apoyadas contra la almohadilla.","Elevar: Presione a través de las puntas de los pies y levante los talones lo más alto posible, involucrando las pantorrillas en el pico de contracción.","Baje lentamente: baje los talones bajo control hasta que sienta un estiramiento profundo en las pantorrillas.","Pausa y contracción: mantenga la posición superior durante 1 a 2 segundos para enfatizar el reclutamiento muscular máximo.","Repetir: realice el número deseado de repeticiones, manteniendo un tempo y una tensión constantes en todo momento."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('12f681f5-c0de-4e80-babe-12f681f50000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Pike-Push-up.gif', '{"- Comience en una posición de flexión con las manos separadas al ancho de los hombros y los pies juntos.","- Empuja hacia atrás hasta la posición inicial extendiendo los brazos.","- Mantenga los brazos extendidos y la cabeza en posición neutral entre los brazos.","- Haga una pausa cuando su cabeza esté justo por encima del suelo.","- Muévase lentamente y con control para maximizar las ganancias de fuerza.","- Levante las caderas hacia el techo, formando una V invertida (similar a un perro boca abajo en yoga).","- Baje la cabeza hacia el suelo doblando los codos.","- Empuje con las palmas de las manos para enganchar completamente los hombros.","- Acelerar el movimiento: reduce la eficacia y aumenta el riesgo de lesiones.","- Colocar las manos demasiado hacia adelante reduce la efectividad del movimiento.","- Involucre sus piernas para mantener su cuerpo estable.","### Errores comunes a evitar","- Dejar que los codos se abran demasiado puede provocar tensión en los hombros.","- Mantenga los codos en un ángulo de 45 grados para reducir la tensión en los hombros.","- Repita de 8 a 15 repeticiones para 3 a 4 series.","### Consejos para una forma adecuada","- Mantenga su núcleo apretado para mantener el equilibrio y el control.","- Mantenga los codos ligeramente doblados para proteger las articulaciones de los hombros.","- No levantar las caderas lo suficiente, esto reduce la activación de los hombros.","- No controlar el descenso puede provocar lesiones en el cuello o la cabeza."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('020beecf-c0de-4e80-babe-020beecf0000', 'Press de banca con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dumbbell-Press.gif', '{"Acuéstese en un banco con los pies firmemente plantados en el suelo. Sostenga una mancuerna en cada mano y apóyela sobre los muslos.","Acuéstese sobre un banco con los pies firmemente plantados en el suelo.","Con un movimiento controlado, suba las mancuernas hasta el nivel de los hombros mientras está sentado en el banco. Esta es tu posición inicial. Tus palmas deben mirar hacia adelante y tus muñecas deben estar en una posición neutral.","Exhala y empuja las mancuernas hacia arriba hasta la posición inicial, extendiendo completamente los brazos sin bloquear los codos.","Configuración: Acuéstese en un banco con los pies firmemente plantados en el suelo. Sostenga una mancuerna en cada mano y apóyela sobre los muslos.","Sostenga una mancuerna en cada mano, apoyándola sobre sus muslos.","Posición inicial: Con un movimiento controlado, suba las mancuernas hasta el nivel de los hombros mientras está sentado en el banco. Esta es tu posición inicial. Tus palmas deben mirar hacia adelante y tus muñecas deben estar en una posición neutral.","Inhale y active los músculos centrales. Baje lentamente las mancuernas hacia el pecho de forma controlada, manteniendo los codos en un ángulo de aproximadamente 45 grados con respecto al cuerpo. La parte superior de tus brazos debe estar paralela al suelo. Baje las mancuernas hasta que los codos estén ligeramente por debajo del nivel del banco o hasta que sienta un suave estiramiento en los músculos del pecho.","Inhala y activa tus músculos centrales.","Baje lentamente las mancuernas hacia su pecho de manera controlada, manteniendo los codos en un ángulo de aproximadamente 45 grados con respecto a su cuerpo. La parte superior de tus brazos debe estar paralela al suelo.","Fase de empuje: exhale y empuje las mancuernas hacia arriba hasta la posición inicial, extendiendo completamente los brazos sin bloquear los codos. Mantenga el pecho contraído y mantenga un ligero arco en la zona lumbar durante todo el movimiento.","Ejecución: Inhale y active los músculos centrales. Baje lentamente las mancuernas hacia el pecho de forma controlada, manteniendo los codos en un ángulo de aproximadamente 45 grados con respecto al cuerpo. La parte superior de tus brazos debe estar paralela al suelo. Baje las mancuernas hasta que los codos estén ligeramente por debajo del nivel del banco o hasta que sienta un suave estiramiento en los músculos del pecho.","Baje las mancuernas hasta que sus codos estén ligeramente por debajo del nivel del banco o hasta que sienta un suave estiramiento en los músculos del pecho.","Repetir: Realice el número deseado de repeticiones, manteniendo la forma y el control adecuados."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('21689cc8-c0de-4e80-babe-21689cc80000', 'Press de banca con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dumbbell-Press.gif', '{"Acuéstese en un banco con los pies firmemente plantados en el suelo. Sostenga una mancuerna en cada mano y apóyela sobre los muslos.","Acuéstese sobre un banco con los pies firmemente plantados en el suelo.","Con un movimiento controlado, suba las mancuernas hasta el nivel de los hombros mientras está sentado en el banco. Esta es tu posición inicial. Tus palmas deben mirar hacia adelante y tus muñecas deben estar en una posición neutral.","Exhala y empuja las mancuernas hacia arriba hasta la posición inicial, extendiendo completamente los brazos sin bloquear los codos.","Configuración: Acuéstese en un banco con los pies firmemente plantados en el suelo. Sostenga una mancuerna en cada mano y apóyela sobre los muslos.","Sostenga una mancuerna en cada mano, apoyándola sobre sus muslos.","Posición inicial: Con un movimiento controlado, suba las mancuernas hasta el nivel de los hombros mientras está sentado en el banco. Esta es tu posición inicial. Tus palmas deben mirar hacia adelante y tus muñecas deben estar en una posición neutral.","Inhale y active los músculos centrales. Baje lentamente las mancuernas hacia el pecho de forma controlada, manteniendo los codos en un ángulo de aproximadamente 45 grados con respecto al cuerpo. La parte superior de tus brazos debe estar paralela al suelo. Baje las mancuernas hasta que los codos estén ligeramente por debajo del nivel del banco o hasta que sienta un suave estiramiento en los músculos del pecho.","Inhala y activa tus músculos centrales.","Baje lentamente las mancuernas hacia su pecho de manera controlada, manteniendo los codos en un ángulo de aproximadamente 45 grados con respecto a su cuerpo. La parte superior de tus brazos debe estar paralela al suelo.","Fase de empuje: exhale y empuje las mancuernas hacia arriba hasta la posición inicial, extendiendo completamente los brazos sin bloquear los codos. Mantenga el pecho contraído y mantenga un ligero arco en la zona lumbar durante todo el movimiento.","Ejecución: Inhale y active los músculos centrales. Baje lentamente las mancuernas hacia el pecho de forma controlada, manteniendo los codos en un ángulo de aproximadamente 45 grados con respecto al cuerpo. La parte superior de tus brazos debe estar paralela al suelo. Baje las mancuernas hasta que los codos estén ligeramente por debajo del nivel del banco o hasta que sienta un suave estiramiento en los músculos del pecho.","Baje las mancuernas hasta que sus codos estén ligeramente por debajo del nivel del banco o hasta que sienta un suave estiramiento en los músculos del pecho.","Repetir: Realice el número deseado de repeticiones, manteniendo la forma y el control adecuados."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('34f41a7c-c0de-4e80-babe-34f41a7c0000', 'Flexiones de pecho con balón medicinal', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/Medicine-Ball-Push-Up.gif', '{"- Coloque un balón medicinal estable en el suelo y colóquelo debajo del centro de su pecho.","- Agarre la parte superior de la pelota con ambas manos juntas, manteniendo los dedos abiertos para controlarla.","- Vuelva a colocarse en una tabla con el cuerpo en línea recta y los pies separados a la altura de los hombros para mantener el equilibrio.","###","- Apoye el núcleo y los glúteos, manteniendo la columna neutra.","- Elija una pelota firme y antideslizante: la estabilidad es crucial para evitar que se vuelque o ruede.","- Baje el cuerpo lentamente doblando los codos cerca de las costillas. Trate de acercar su pecho a la pelota.","- Empuje hacia arriba con control, extendiendo los codos completamente mientras mantiene la tensión en todo el cuerpo.","- Involucre su núcleo: evita la flacidez o el arqueamiento durante el movimiento.","- Controla el descenso y el ascenso: El movimiento lento mejora la tensión y la seguridad.","- Rango de movimiento inadecuado: No bajar lo suficientemente cerca de la pelota limita la efectividad.","### Errores comunes","- Dejar que los codos se ensanchen: reduce la concentración del tríceps y puede tensar la articulación del hombro.","- Usar una pelota inestable: Las pelotas blandas o demasiado redondas aumentan el riesgo de lesiones.","### Consejos para una forma adecuada","- Mantenga la alineación del cuerpo: mantenga los hombros, las caderas y los tobillos en línea recta.","- Mantenga los codos doblados: esto enfatiza los tríceps y protege los hombros.","- Apresurarse en las repeticiones: las repeticiones rápidas en una superficie inestable reducen la activación y el control de los músculos.","- Caderas caídas: conduce a una mala postura y tensión en la espalda baja."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3a913536-c0de-4e80-babe-3a9135360000', 'Aperturas de pecho declinado con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Decline-Dumbbell-Fly.gif', '{"- Elija un banco declinado","- Colóquese: recuéstese en el banco con la cabeza más baja que el torso y mancuernas en la mano.","- Posición inicial Sostenga las mancuernas sobre su pecho con una ligera flexión de los codos. Las palmas deben estar frente a frente y los brazos deben estar perpendiculares al torso.","- Aprieta los músculos del pecho y lleva las mancuernas a la posición inicial, manteniendo el movimiento del arco.","- Utilice peso moderado: priorice la técnica sobre el levantamiento de objetos pesados ​​para apuntar eficazmente al pecho.","- Usar peso excesivo: comenzar con demasiado peso puede comprometer la forma y aumentar el riesgo de lesiones.","- Ángulo de banco incorrecto: usar una pendiente demasiado pronunciada puede desviar la atención del pecho hacia otros músculos.","- Seleccione mancuernas adecuadas","- Sostenga las mancuernas por encima de su pecho con una ligera flexión de los codos.","- Las palmas deben estar enfrentadas y los brazos deben estar perpendiculares al torso.","- Fase de descenso Baje lentamente las mancuernas hacia afuera formando un arco amplio, manteniendo una ligera flexión de los codos. Baje hasta que sienta un estiramiento en el pecho sin ir más allá de su nivel de comodidad.","- Baje lentamente las mancuernas hacia afuera formando un arco amplio, manteniendo los codos ligeramente doblados.","- Baje hasta que sienta un estiramiento en el pecho sin sobrepasar su nivel de comodidad.","- RepetirRealice el número deseado de repeticiones con movimientos controlados.","- Aprieta en la parte superior: contrae los músculos del pecho en la parte superior del movimiento para maximizar la activación.","- Combínelo con ejercicios compuestos: combínelo con prensas o flexiones para un entrenamiento integral del pecho.","- Bajar demasiado profundo: Extender demasiado el rango de movimiento puede forzar los hombros.","- Acelerar el movimiento: Realizar el ejercicio demasiado rápido reduce la efectividad y el control.","- Fase de levantamiento Apriete los músculos del pecho y lleve las mancuernas a la posición inicial, manteniendo el movimiento del arco. Evite golpear las mancuernas en la parte superior.","- Realiza el número deseado de repeticiones con movimientos controlados.","- Involucre su núcleo: mantenga su núcleo apretado para estabilizar su cuerpo en el banco de descenso.","- Evite golpear las mancuernas en la parte superior.","### Consejos para una máxima eficacia","- Concéntrese en la forma: mantenga los codos ligeramente doblados y muévase en un arco controlado para evitar tensión en los hombros.","### Errores comunes a evitar","- Bloquear los codos: los brazos completamente extendidos ejercen una tensión innecesaria en las articulaciones del codo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('47563c74-c0de-4e80-babe-47563c740000', 'Press de pecho inclinado en máquina', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Incline-Chest-Press-Machine.gif', '{"Siéntese en la máquina con la espalda firmemente apoyada en el respaldo. Coloque los pies apoyados en el suelo, separados a la altura de los hombros. Mantenga una columna neutra y active los músculos centrales para lograr estabilidad.","Sujete las manijas o empuñaduras a ambos lados de la máquina. Las palmas de las manos deben mirar hacia adelante y las manos deben estar separadas al ancho de los hombros o un poco más anchas, según su preferencia.","Con los brazos flexionados, acerca las asas al pecho. Tus codos deben estar a unos 45 grados o un poco más. Esta es tu posición inicial.","Posición inicial: Con los brazos flexionados, acerca las asas al pecho. Tus codos deben estar a unos 45 grados o un poco más. Esta es tu posición inicial.","Movimiento: Empuje las manijas hacia adelante y lejos de su cuerpo, extendiendo los brazos completamente pero sin bloquear los codos. Exhala mientras alejas las manijas.","Empuje las manijas hacia adelante y lejos de su cuerpo, extendiendo los brazos completamente pero sin bloquear los codos. Exhala mientras alejas las manijas.","Retorno controlado: Lleve lentamente las manijas a la posición inicial, manteniendo el control sobre el movimiento. Inhale mientras regresa a la posición inicial, permitiendo que los músculos del pecho se estiren.","Repetir: Complete el número deseado de repeticiones según su nivel de condición física y sus objetivos. Trate de realizar un movimiento controlado y suave durante todo el ejercicio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('57b42f10-c0de-4e80-babe-57b42f100000', 'Press de hombros', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Bodyweight-Military-Press.gif', '{"Comience parándose con los pies separados a la altura de los hombros y los brazos a los costados.","Baje lentamente las manos hasta la posición inicial, manteniendo el control y un ritmo controlado.","Involucre su núcleo y apriete sus glúteos para mantener la estabilidad durante todo el movimiento.","Presione lentamente las manos directamente sobre la cabeza, extendiendo los brazos por completo sin bloquear los codos. Imagínese alejando el techo de usted.","Levante los brazos hasta el nivel de los hombros, doblando los codos en un ángulo de 90 grados y con las palmas hacia adelante.","Haga una pausa por un momento en la parte superior, asegurándose de que sus brazos estén completamente extendidos.","Repita hasta el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('32788dd3-c0de-4e80-babe-32788dd30000', 'Elevación de piernas', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Crunch-With-Leg-Raise.gif', '{"Los ejercicios abdominales generalmente están diseñados para fortalecer y desarrollar los músculos centrales del cuerpo. El ejercicio ayuda a fortalecer los músculos centrales, mejorar la postura y aumentar la movilidad y flexibilidad de los músculos.","Se dirige a los músculos abdominales inferiores y superiores al mismo tiempo: El ejercicio de abdominales con elevación de piernas se dirige al recto abdominal y a los músculos oblicuos, de modo que los músculos abdominales superiores e inferiores se desarrollan simultáneamente."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('77143d0e-c0de-4e80-babe-77143d0e0000', 'Ejercicio', 'Abdomen', '', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('016484f0-c0de-4e80-babe-016484f00000', 'Elevación de piernas', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Captains-Chair-Leg-Raise.gif', '{"Este ejercicio que trabaja los flexores de la cadera mejora los músculos centrales, especialmente los músculos abdominales inferiores. Además, los músculos de la espalda, el pecho y el trapecio actúan como estabilizadores durante el ejercicio.","Según un estudio del American Ejercicio Council, este ejercicio es uno de los más eficaces para fortalecer los oblicuos y el segundo más eficaz para fortalecer los músculos abdominales."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('666baf99-c0de-4e80-babe-666baf990000', 'Extensión de tríceps en máquina', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Triceps-Extension-Machine.gif', '{"### Paso 1: ajustar la máquina","- Ajuste la altura del asiento de modo que la parte superior de sus brazos descanse cómodamente sobre la almohadilla y los codos se alineen con el punto de giro de la máquina.","- Siéntese erguido con la espalda firmemente apoyada en la almohadilla y los pies apoyados en el suelo.","- Agarre las manijas en una posición neutral con las palmas hacia el cuerpo.","- Regrese lentamente a la posición inicial, controlando el peso mientras dobla los codos.","- Seleccione un peso apropiado que permita un movimiento controlado sin sacrificar la forma.","### Paso 2: configuración y posicionamiento","- Asegúrese de que sus codos estén alineados con el eje de la máquina para optimizar la eficiencia del movimiento.","### Paso 3: Ejecución","- Empuja las manijas hacia abajo, extendiendo los brazos completamente mientras contraes los tríceps.","- Mantenga la contracción por un segundo en la parte inferior del movimiento.","- Repita para las repeticiones deseadas, manteniendo sus movimientos suaves y controlados."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('73873be9-c0de-4e80-babe-73873be90000', 'Ejercicio sentado', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Seated-Flutter-Kick.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6d7e9869-c0de-4e80-babe-6d7e98690000', 'Elevación de piernas', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Crunch-With-Leg-Raise.gif', '{"Los ejercicios abdominales generalmente están diseñados para fortalecer y desarrollar los músculos centrales del cuerpo. El ejercicio ayuda a fortalecer los músculos centrales, mejorar la postura y aumentar la movilidad y flexibilidad de los músculos.","Se dirige a los músculos abdominales inferiores y superiores al mismo tiempo: El ejercicio de abdominales con elevación de piernas se dirige al recto abdominal y a los músculos oblicuos, de modo que los músculos abdominales superiores e inferiores se desarrollan simultáneamente."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('649304f4-c0de-4e80-babe-649304f40000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Reverse-Crunch-1.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1dfed819-c0de-4e80-babe-1dfed8190000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Dead-Bug.gif', '{"Este ejercicio, que también se aplica como ejercicio de calentamiento, puede trabajar incluso las fibras musculares más pequeñas desde diferentes ángulos para fortalecer los músculos centrales. También es una forma segura y eficaz de fortalecer y equilibrar los músculos de la columna, la espalda y el cuello. Una estructura sólida de la columna y músculos fuertes de la espalda pueden ayudar a mejorar la postura y aliviar y prevenir el dolor de espalda.","El movimiento del insecto muerto, que se utiliza con frecuencia en Pilates, yoga y entrenamiento abdominal, es un ejercicio diseñado para fortalecer la estabilidad general y el core. Este movimiento es un ejercicio funcional de fortalecimiento del núcleo que trabaja los músculos de la parte inferior y superior del cuerpo.","Dead Bug también es un ejercicio que requiere concentración mental, obliga a que los movimientos se realicen en armonía y ayuda a mejorar el equilibrio y la coordinación."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7ab7b33b-c0de-4e80-babe-7ab7b33b0000', 'Estiramiento', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Corner-Wall-Stretch.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4bf052d4-c0de-4e80-babe-4bf052d40000', 'Ejercicio', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/wall-slide.gif', '{"Párese con la espalda contra la pared, con los pies separados aproximadamente a la altura de las caderas.","Coloque los brazos contra la pared con los codos doblados en un ángulo de 90 grados y las palmas hacia adelante.","Haga una pausa por un momento en la parte superior, luego deslice lentamente los brazos hacia abajo hasta la posición inicial.","Desliza suavemente los brazos hacia arriba por la pared, manteniendo el contacto entre las manos, los codos y la pared.","Mientras desliza los brazos hacia arriba, trate de mantener los omóplatos juntos y hacia abajo.","Vaya tan lejos como pueda cómodamente sin dolor ni tensión excesiva.","Repita el movimiento durante el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4e7d884a-c0de-4e80-babe-4e7d884a0000', 'Curl concentrado en polea', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Cable-Concentration-Curl.gif', '{"Configure la máquina de cable: conecte una manija única a una polea baja en la máquina de cable.","Siéntate en un banco: Siéntate en un banco con los pies apoyados en el suelo y las piernas separadas a la altura de los hombros. Coloque el codo del brazo que trabaja en la parte interna del muslo, con la palma hacia arriba.","Agarre el mango del cable: Sujete el mango del cable con la palma hacia arriba y deje que el brazo cuelgue hacia abajo, completamente extendido.","Doble el mango: Manteniendo la parte superior del brazo inmóvil, exhale y doble el mango del cable hacia su hombro mientras mantiene un agarre firme sobre el mango. Mantenga la muñeca recta y concéntrese en contraer los músculos bíceps.","Baje el mango: Inhale y baje lentamente el mango hasta la posición inicial, manteniendo la parte superior del brazo inmóvil durante todo el movimiento.","Repetir: Complete el número deseado de repeticiones con un brazo antes de cambiar al otro brazo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('031de003-c0de-4e80-babe-031de0030000', 'Estiramiento', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Toe-Extensor-Stretch.gif', '{"- Posición inicial: párese erguido con los pies separados a la altura de las caderas.","- Cambie el peso hacia adelante: transfiera su peso ligeramente a la pierna delantera, permitiendo que el pie trasero presione suavemente el piso para crear un estiramiento en la parte superior del pie y la espinilla.","- Cambiar de lado: regrese a la posición inicial y repita con el pie opuesto.","- Paso atrás: Extienda una pierna detrás de usted y coloque la parte superior de los dedos de los pies en el suelo con el pie apuntando hacia abajo.","- Mantenga la posición: mantenga el torso erguido, los hombros relajados y la columna neutra mientras mantiene el equilibrio.","- Duración: Mantén el estiramiento durante 20 a 30 segundos, respirando profundamente y evitando rebotes.","- Utilice una pared o una silla para mantener el equilibrio si es necesario, especialmente si es nuevo en el puesto.","- Realice descalzo o con zapatos blandos para un mejor contacto y retroalimentación con los pies.","- Aplique una presión suave; el estiramiento debe sentirse en la parte superior del pie y la espinilla, no en la articulación del tobillo.","### Errores comunes","- Forzar el estiramiento: una presión excesiva puede provocar tensión o malestar en el tobillo.","- Torcer el pie: la desalineación reduce la efectividad del estiramiento y puede irritar las articulaciones.","### Consejos para una forma adecuada","- Mantenga el pie alineado; evite girar los dedos hacia adentro o hacia afuera excesivamente.","- Mantenga su postura erguida para evitar trasladar la tensión a la zona lumbar.","- Contener la respiración: la respiración ayuda a que los músculos se relajen y mejora la calidad del estiramiento.","- Rebotar o balancearse: puede reducir la efectividad del estiramiento y aumentar el riesgo de tensión.","- Ignorar la posición de los pies: asegúrese de que los dedos de los pies estén en punta y apoyados en el suelo, no doblados hacia abajo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1a6f1824-c0de-4e80-babe-1a6f18240000', 'Estiramiento', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Foam-Roller-Chest-Stretch.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('34880cbb-c0de-4e80-babe-34880cbb0000', 'Estiramiento', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Corner-Wall-Stretch.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7ed6fe5b-c0de-4e80-babe-7ed6fe5b0000', 'Estiramiento', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/07/Rotating-Neck-Stretch.gif', '{"Regrese lentamente la cabeza a la posición central y repita el estiramiento en el otro lado.","Gire lentamente la cabeza hacia un lado, con el objetivo de acercar la oreja al hombro.","Mantenga un estiramiento cómodo; Evite forzar la cabeza a una posición extrema.","Deberías sentir un suave tirón a lo largo del costado de tu cuello. Mantenga esta posición durante 15 a 30 segundos, asegurando una respiración constante y relajada en todo momento.","Apunta a 2-4 repeticiones en cada lado."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1a8b2916-c0de-4e80-babe-1a8b29160000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Toe-Reaches.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1a5fffaa-c0de-4e80-babe-1a5fffaa0000', 'Estiramiento', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Calf-Stretch-with-Rope.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4bb4213c-c0de-4e80-babe-4bb4213c0000', 'Curl martillo', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/06/Water-Bottle-Hammer-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1bf4c2fd-c0de-4e80-babe-1bf4c2fd0000', 'Remo en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Cable-Upright-Row.gif', '{"El remo vertical con cable es un ejercicio de aislamiento dirigido al trapecio y los deltoides, que son responsables de agregar ancho a los hombros.","El remo vertical con cable es uno de los ejercicios efectivos para construir trampas más grandes, pero también es un movimiento en el que es fácil cometer errores. Una de las formas más sencillas de asegurarse de que su forma sea óptima es evitar el uso de mancuernas que sean demasiado pesadas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5bb5bca5-c0de-4e80-babe-5bb5bca50000', 'Ejercicio', 'Abdomen', '', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2e77c7b5-c0de-4e80-babe-2e77c7b50000', 'Plancha', 'Abdomen', '', '{"Coloque su hombro derecho directamente encima de su codo derecho, manteniendo sus hombros, caderas y rodillas en línea recta.","Empuja hacia arriba para que tu cuerpo quede recto... Mantén la posición durante 10 segundos para principiantes y 1 minuto si eres más avanzado. Repita en su lado izquierdo.","Acuéstese sobre su lado derecho, levantándose sobre su antebrazo derecho.","Apoye su brazo izquierdo a lo largo del costado de su cuerpo.","Antes de presionar hacia arriba, contraiga los abdominales, aleje los hombros de las orejas y alargue la columna."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('595903a7-c0de-4e80-babe-595903a70000', 'Estiramiento', 'Hombros', '', '{"Los estiramientos de cuello también participan en la fisioterapia que tiene como objetivo rehabilitar los músculos, las articulaciones y los huesos del cuello. Los estiramientos de cuello tienen como objetivo aumentar la fuerza, el tono y la flexibilidad de los músculos del cuello. También permite que los ligamentos de las articulaciones del cuello se vuelvan más flexibles y resistan una mayor tensión en el área.","Cuando la cabeza y los hombros se inclinan hacia adelante debido a una mala postura, algunos músculos del pecho y el cuello pueden acortarse y tensarse con el tiempo, lo que puede perpetuar la mala postura que causa el dolor de cuello. Los ejercicios de estiramiento del cuello pueden ayudar a relajar los músculos posturales y reducir el dolor de cuello."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('57093369-c0de-4e80-babe-570933690000', 'Extensión de tríceps', 'Hombros', '', '{"Mantén la posición durante unos segundos y luego regresa lentamente a la posición inicial.","Siéntate erguido con los hombros relajados.","Incline lentamente la cabeza hacia atrás, mirando hacia arriba. Imagine un estiramiento suave a lo largo de la parte posterior de su cuello.","Repita unas cuantas veces."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('37da5f97-c0de-4e80-babe-37da5f970000', 'Estiramiento', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2026/01/Unilateral-Lat-Stretch-on-the-Wall.gif', '{"### Posición inicial:","- Párese frente a una pared con el brazo extendido.","- Coloque una palma contra la pared aproximadamente a la altura de los hombros o ligeramente por encima.","- Regrese a la posición inicial.","- Mueva el pie del mismo lado ligeramente hacia atrás para mayor estabilidad.","### Iniciar el estiramiento:","- Empuja tus caderas hacia atrás mientras permites que tu pecho caiga hacia el suelo.","- Doble ligeramente las caderas y las rodillas.","### Profundizar el movimiento:","- Repite el movimiento en el lado opuesto.","- Gire el torso ligeramente lejos de la pared para aumentar el estiramiento lateral.","### Sostenga y respire:","- Mantener el estiramiento durante el tiempo deseado.","- Mantenga el brazo recto y presione suavemente la palma contra la pared.","- Respire lenta y profundamente, concentrándose en relajar la parte superior de la espalda y los hombros.","### Cambiar de lado:"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('10709847-c0de-4e80-babe-107098470000', 'Elevación de pantorrillas de pie', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Standing-Calf-Raise.gif', '{"- Posición inicial: Párese erguido con los pies separados a la altura de las caderas, manteniendo una buena postura con los hombros hacia atrás, el pecho abierto y el core comprometido.","- Alineación de pies y cuerpo: Coloque los dedos de los pies en el extremo de una plataforma alta y distribuya su peso uniformemente entre ambas piernas.","- Manténgalo en la parte superior brevemente para activar completamente los músculos de la pantorrilla.","### Errores comunes:","- Movimiento de elevación: levántese lentamente sobre las puntas de los pies, levantando los talones del suelo lo más alto posible cómodamente y contrayendo las pantorrillas por completo.","- Descenso controlado: baje suavemente los talones hasta el suelo, manteniendo el control durante todo el movimiento.","- Repetir: realice de 15 a 25 repeticiones por serie, enfatizando los movimientos controlados y deliberados.","- Realice movimientos suave y lentamente para maximizar la participación de los músculos.","- Movimiento rápido: rebotar rápidamente o utilizar el impulso reduce la activación muscular y puede provocar lesiones.","- Rango de movimiento limitado: no levantarse completamente sobre los dedos de los pies limita el compromiso de la pantorrilla.","- Postura incorrecta: inclinarse hacia adelante o hacia atrás genera una tensión innecesaria en las articulaciones y reduce la efectividad.","### Consejos para una forma adecuada:","- Mantenga una postura recta, evitando inclinarse hacia adelante o balancearse hacia atrás.","- Mantenga las rodillas ligeramente dobladas para reducir la tensión en las articulaciones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('726851ae-c0de-4e80-babe-726851ae0000', 'Flexiones de pecho', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2025/08/Burpee-with-Push-Up.gif', '{"- Posición inicial: Párese erguido con los pies separados a la altura de los hombros y los brazos a los costados.","- Sentadilla: bájese hasta ponerse en cuclillas y coloque las manos planas en el suelo frente a usted.","- Patada hacia atrás: salte con los pies hacia atrás en una posición de tabla alta, manteniendo el cuerpo en línea recta.","- Regreso: Salta con los pies hacia adelante y vuelve a la posición de sentadilla.","- Salto explosivo: conduce hacia arriba para realizar un salto vertical, llegando por encima de tu cabeza.","- Aterriza suavemente durante el salto para reducir la tensión en las articulaciones.","- Flexiones: realice una flexión controlada, bajando el pecho hacia el suelo y presionando hacia arriba.","- Realice la flexión con movimiento controlado; Evite que su pecho colapse.","- Respira rítmicamente: inhala durante la flexión, exhala mientras saltas.","- Flexiones superficiales que reducen el compromiso de la parte superior del cuerpo.","### Errores comunes a evitar","- Dejar caer las caderas durante la plancha o la flexión, lo que puede tensar la zona lumbar.","- Repita durante la cantidad deseada de repeticiones o tiempo.","### Consejos para una forma adecuada","- Mantenga su núcleo comprometido durante la tabla y la flexión para evitar que la espalda baja se hunda.","- Saltarse el salto y acelerar las repeticiones sin mantener la intensidad.","- Mecánica de aterrizaje deficiente, como rodillas rígidas o golpe excesivo del talón."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3836b0b6-c0de-4e80-babe-3836b0b60000', 'Zancadas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2025/09/pendulum-lunge.gif', '{"- Posición inicial: Párese erguido con los pies separados a la altura de las caderas y las manos entrelazadas en las caderas o delante del pecho para mantener el equilibrio.","- Estocada hacia adelante: Da un paso hacia adelante con una pierna, bajando las caderas hasta que el muslo delantero esté casi paralelo al piso, manteniendo el torso erguido.","- Transición: sin detenerte, empuja el pie delantero y mueve la misma pierna hacia atrás en una estocada inversa.","- Regreso al inicio: Empuje con el talón delantero para regresar a la posición inicial, completando un movimiento pendular completo.","- Repetir: realice las repeticiones deseadas en una pierna antes de cambiar de lado.","- Estocada inversa: baje las caderas nuevamente, con la rodilla trasera doblada hacia el suelo mientras la pierna delantera permanece a 90 grados.","- Acelerar el movimiento: Reduce la estabilidad y aumenta el riesgo de lesiones.","- Pasos cortos: Impide el rango completo de movimiento, lo que limita la efectividad.","- Mantenga el torso erguido y el núcleo comprometido durante todo el movimiento.","- Concéntrese en transiciones suaves entre estocadas hacia adelante y hacia atrás.","- Dé un paso lo suficientemente hacia adelante y hacia atrás para permitir una alineación adecuada de la rodilla a 90 grados.","- Mantenga una respiración constante: inhale durante el descenso y exhale durante el ascenso.","### Consejos para una forma adecuada","### Errores comunes","- Permitir que la rodilla colapse hacia adentro: ejerce presión sobre las articulaciones y reduce la activación muscular."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('77abfb7b-c0de-4e80-babe-77abfb7b0000', 'Ejercicio con mancuernas', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2026/01/Single-Leg-Dumbbell-Side-Bridge.gif', '{"### Posición inicial:","- Acuéstese de lado. Coloque su antebrazo en el suelo con el codo directamente debajo del hombro.","- Coloque las piernas exactamente como se muestra: una pierna permanece recta con el pie en el suelo (esta es su pierna de apoyo). La otra pierna está doblada por la rodilla y levantada, sin apoyarla en el suelo.","- Respira lentamente sin perder la posición.","- Una pierna permanece recta con el pie en el suelo (esta es tu pierna de apoyo).","- La otra pierna se dobla por la rodilla y se levanta, sin apoyarse en el suelo.","- Sostenga una mancuerna cerca de su costado/cadera con la mano superior.","### Construya el pilar de apoyo:","- Levante las caderas para que su cuerpo forme una línea fuerte desde el pie de apoyo → caderas → hombro.","- Presione el pie de apoyo contra el suelo.","- Presiona el antebrazo contra el suelo.","### Estabilizar y bloquear la alineación:","### Sostenga y respire:","### Cambiar de lado:","- Mantenga el hombro inferior “empacado” (estable), el cuello neutral y las costillas controladas.","- Mantenga la pelvis apilada y nivelada; no permita que las caderas se muevan hacia adelante o hacia atrás.","- Mantenga la tensión a través del costado del núcleo para resistir la flexión lateral.","- Mantenga la mancuerna pegada al cuerpo para reducir la rotación no deseada.","- Mantenga estable el hombro de apoyo y evite encogerse de hombros.","- Bajar con control.","- Repita en el lado opuesto."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('34632527-c0de-4e80-babe-346325270000', 'Curl martillo unilateral en polea', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2025/07/cable-single-arm-hammer-curl.gif', '{"- Coloque el cable en la posición más baja de la polea y sujete una cuerda o un mango en D.","- Párese de lado de la máquina, agarre el mango con un agarre neutral (con el pulgar hacia arriba).","- Aléjese un poco de la máquina y apoye su núcleo, manteniendo el brazo a su costado.","- Apriete en la parte superior y luego baje lentamente el mango hasta la posición inicial.","- Utilice un agarre neutral con el pulgar apuntando hacia arriba para enfatizar el braquial.","- Aprovechar el impulso o inclinarse hacia atrás para levantar el peso.","- Realice de 8 a 12 repeticiones por brazo, concentrándose en el control y la simetría.","- Mantenga el codo pegado al torso durante todo el movimiento.","- No balancee ni gire el torso; manténgase erguido y controlado.","- Doble el mango hacia arriba, flexionando el codo sin rotar la muñeca ni mover el hombro.","- Exhala mientras te curvas, inhala mientras regresas al fondo.","- Dejar que el codo se desplace hacia adelante, alejando la tensión de los músculos objetivo.","- Rotar la muñeca, lo que cambia el patrón de movimiento y reduce la efectividad.","- Concéntrese en el tiempo bajo tensión, especialmente durante la fase de descenso.","### Errores comunes","- Saltarse la fase excéntrica, perdiendo beneficios de fuerza e hipertrofia.","### Consejos para una forma adecuada","- Agarrar demasiado flojo, lo que disminuye el compromiso del antebrazo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('32acd98d-c0de-4e80-babe-32acd98d0000', 'Remo', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2024/03/Step-Behind-Rotational-Med-Ball-Throw.gif', '{"- Párese erguido con los pies separados a la altura de los hombros y el balón sostenido a la altura de la cintura.","- Coloque el pie trasero detrás y a través del pie delantero (como un paso cruzado).","- Cuando su pie trasero aterrice, gire sus caderas hacia la pared y transfiera su peso hacia adelante.","- Comience de lado hacia una pared sólida o un espacio abierto, sosteniendo un balón medicinal liviano (de 2 a 6 kg).","- Permita una rotación completa de la cadera y los hombros, terminando erguido y equilibrado.","- Empieza ligero (pelota de 2 a 4 kg) para priorizar la velocidad y la mecánica.","- Da un paso atrás con control, pero gira explosivamente durante el lanzamiento.","- Mantener el balón cerca del torso antes de soltarlo para evitar armar el lanzamiento.","- Gire explosivamente el torso y los hombros, soltando la pelota con un movimiento de lanzamiento lateral.","- Termine erguido: no se caiga hacia adelante ni se desplome después del lanzamiento.","- Exhala con fuerza mientras sueltas la pelota para lograr una mayor participación del core.","- Utilice una pared que no rebote o un campo abierto para mayor seguridad y fluidez.","### Errores comunes","- Armar el lanzamiento sin utilizar las caderas y las piernas.","- Saltarse el paso atrás, haciéndolo más bien un lanzamiento estacionario.","- Reinicie entre repeticiones y repita en el lado opuesto.","### Consejos para una forma adecuada","- Lanzar demasiado pesado, lo que ralentiza la rotación y reduce la transferencia.","- Rotación excesiva o pérdida de equilibrio después del lanzamiento.","- No cambiar de bando, creando asimetrías de fuerza."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('70384b74-c0de-4e80-babe-70384b740000', 'Curl de bíceps con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2025/08/Dumbbell-jefferson-curl.gif', '{"- Mantener el control en todo momento; nunca “dejar caer” a la posición inferior.","- Configuración: Párese sobre una pequeña plataforma o escalón para permitir un mayor rango de movimiento. Sostenga una mancuerna liviana en cada mano con los brazos extendidos frente a los muslos.","- Fase de estiramiento: en la parte inferior, deje que las mancuernas cuelguen naturalmente mientras mantiene una ligera tensión, sintiendo un estiramiento profundo de los isquiotibiales y la columna.","- Regreso al inicio: invierta lentamente el movimiento para regresar a la posición vertical.","- Repita: realice las series y repeticiones deseadas, centrándose en el control y la segmentación de la columna.","- Descenso controlado: comience metiendo la barbilla y luego flexione lentamente la parte superior, media y baja de la espalda en secuencia. Permita que las mancuernas se muevan hacia abajo a medida que avanza gradualmente a través de cada vértebra.","- Acelerar el movimiento: el ejercicio debe realizarse lentamente para entrenar la segmentación de la columna.","- Comienza con mancuernas muy ligeras y progresa gradualmente a medida que mejore la movilidad y el control.","- Muévase lentamente, tratando el ejercicio como un entrenamiento de fuerza y ​​movilidad.","### Errores comunes","### Consejos para una forma adecuada","- Mantenga las rodillas rectas pero no bloqueadas para maximizar la participación de los isquiotibiales.","- Volverse demasiado pesado y demasiado pronto: la sobrecarga aumenta el riesgo de lesiones y reduce los beneficios de movilidad.","- Bloqueo de rodillas: puede reducir la activación de los isquiotibiales y aumentar la tensión en las articulaciones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5b27d484-c0de-4e80-babe-5b27d4840000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2025/07/plate-push.gif', '{"- Coloque una placa de pesas sobre un piso liso (césped, caucho, madera o baldosas).","- Mire ligeramente hacia adelante, no hacia abajo, para mantener una posición neutral del cuello.","- Adopte una postura atlética baja: caderas hacia atrás, pecho hacia abajo, manos en el borde del plato y brazos extendidos.","- Involucra tu núcleo y conduce a través de las puntas de tus pies para empujar la placa hacia adelante.","- Continúe presionando para ganar distancia o tiempo, usando pasos cortos y poderosos.","- Conduce desde las piernas, no desde los brazos; la parte inferior del cuerpo debería hacer la mayor parte del trabajo.","- Dejar que los talones se levanten excesivamente, lo que disminuye el impulso y la estabilidad.","- Utilice pasos explosivos pero controlados para mantener la tracción y la potencia.","### Errores comunes","- Estar demasiado erguido, lo que reduce la potencia y la eficiencia.","- Redondear la espalda, aumentando el riesgo de lesiones.","- Mantenga la espalda plana, la cabeza alineada con la columna y evite doblar los hombros.","### Consejos para una forma adecuada","- Mantenga las caderas bajas para involucrar los glúteos y evitar una tensión excesiva en la columna.","- Mantenga la tensión central para estabilizar la columna durante todo el empujón.","- Usando solo tus brazos, en lugar de piernas y core para generar fuerza.","- Mala elección de la superficie, generando demasiada fricción o deslizamiento incontrolado."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3fac0d5e-c0de-4e80-babe-3fac0d5e0000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2025/07/Heel-Elevated-Goblet-Squat.gif', '{"- Párese con los talones elevados sobre discos de pesas, cuñas para sentadillas o una tabla inclinada, y los dedos de los pies apoyados en el suelo.","- Sostenga una mancuerna o pesa rusa verticalmente al nivel del pecho con ambas manos (agarre de copa).","- Levantar los dedos de los pies, lo que desestabiliza la sentadilla y desplaza el peso demasiado hacia atrás.","- Mantener el peso alejado del pecho, lo que aumenta la tensión en los hombros y la columna.","- Agáchese lentamente, permitiendo que las rodillas avancen sobre los dedos de los pies mientras mantiene el contacto del talón con la superficie elevada.","- Realice de 8 a 12 repeticiones, concentrándose en el control y la postura.","- Utilice una superficie estable (por ejemplo, placas o cuñas) para elevar los talones de manera uniforme.","- Baje hasta la profundidad máxima, idealmente hasta que las caderas estén debajo de las rodillas, luego presione hacia arriba a través de la parte media del pie y los talones.","- Permita que las rodillas se desplacen hacia adelante, especialmente para apuntar a los cuádriceps.","- Apoye su núcleo durante todo el movimiento para proteger su espalda baja.","### Errores comunes","- Dejar que el pecho caiga hacia adelante, reduciendo el énfasis en los cuádriceps.","- Usar una elevación inestable o desigual, con riesgo de desequilibrio o mala mecánica.","- Mantenga el pecho erguido y el núcleo comprometido mientras comienza a descender.","### Consejos para una forma adecuada","- Mantenga el torso erguido, especialmente al final de la sentadilla.","- Mantenga la mancuerna cerca de su pecho para evitar inclinarse hacia adelante.","- No agacharse lo suficiente, lo que limita la movilidad y la activación de los cuádriceps."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6a63e947-c0de-4e80-babe-6a63e9470000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2026/01/forward-bend.gif', '{"Párese erguido con los pies separados a la altura de las caderas. Mantenga el peso distribuido uniformemente y el core suavemente enganchado.","Vuelva a ponerse de pie: active el núcleo y los glúteos. Gire o gire lentamente hacia la posición inicial.","Gire o gire lentamente hasta la posición inicial.","Posición inicial: Párese erguido con los pies separados a la altura de las caderas. Mantenga el peso distribuido uniformemente y el core suavemente enganchado.","Mantenga su peso distribuido uniformemente y el núcleo enganchado suavemente.","Baje hacia el estiramiento: Deje que sus brazos cuelguen naturalmente hacia el piso. Mantenga las rodillas ligeramente dobladas si la flexibilidad de los isquiotibiales es limitada.","Inicie el movimiento: Inhale y prepárese alargando la columna. Exhale y gire las caderas, permitiendo que el torso se mueva hacia adelante.","Inhala y prepárate alargando la columna.","Exhale y gire las caderas, permitiendo que el torso avance.","Deje que sus brazos cuelguen naturalmente hacia el suelo.","Sostenga y respire: Relaje el cuello y los hombros. Mantenga la posición mientras respira lenta y profundamente.","Relaja el cuello y los hombros.","Involucre su núcleo y glúteos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7b4fc630-c0de-4e80-babe-7b4fc6300000', 'Plancha', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2025/07/body-saw-plank.gif', '{"- Comience con una plancha de antebrazo con los codos debajo de los hombros, los pies juntos y el core comprometido.","- Mueva su cuerpo hacia adelante, moviendo los hombros frente a los codos, manteniendo el core apretado.","- Sierra hacia atrás, volviendo los hombros justo detrás de los codos, sin dejar caer la cadera.","- Involucre sus glúteos y abdominales para evitar que sus caderas se caigan.","- Continúe este movimiento controlado hacia adelante y hacia atrás durante 30 a 60 segundos, manteniendo la tensión de todo el cuerpo.","- Empuje con los dedos de los pies para iniciar el movimiento de aserrado.","- Concéntrese en la calidad sobre la velocidad o el rango de movimiento.","- Dejar caer las caderas durante el movimiento hacia atrás, tensionando la zona lumbar.","- Mantenga los movimientos pequeños y controlados, sin balanceos excesivos.","### Errores comunes","- Empujar demasiado hacia adelante, perdiendo tensión y forma.","- Mantenga su cuerpo en línea recta desde la cabeza hasta los talones.","### Consejos para una forma adecuada","- Mantenga una columna neutra con la cabeza alineada con el cuerpo.","- Contener la respiración, lo que reduce el compromiso central.","- Encogerse de hombros hacia las orejas en lugar de mantener activas las escápulas.","- Usar el impulso en lugar de la fuerza central para moverse."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('501bb77e-c0de-4e80-babe-501bb77e0000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2025/10/Burpee-Long-Jump.gif', '{"- Posición inicial: Párese erguido con los pies separados a la altura de los hombros. Mantenga el núcleo reforzado y los brazos relajados a los lados.","- Párese erguido con los pies separados a la altura de los hombros.","- Fase de burpee: Póngase en cuclillas y coloque las manos en el suelo frente a usted. Salte o retroceda los pies hasta una posición de tabla alta. Realice una flexión (opcional pero común en esta variación).","- Póngase en cuclillas y coloque las manos en el suelo frente a usted.","- Salta o retrocede con los pies hasta la posición de tabla alta.","- Fase de salto de longitud: mueve los brazos hacia atrás y luego salta explosivamente hacia adelante lo más lejos posible. Aterriza suavemente con las rodillas dobladas y el peso distribuido uniformemente.","- Aterriza suavemente con las rodillas dobladas y el peso distribuido uniformemente.","- Salta o da un paso con los pies hacia adelante para que aterricen justo fuera de tus manos.","- Mantén el pecho elevado mientras te preparas para saltar.","- Mueva los brazos hacia atrás y luego salte explosivamente hacia adelante lo más lejos posible.","- Date la vuelta o camina hacia atrás hasta tu punto de partida.","- Realice una flexión (opcional pero común en esta variación).","- Dejar que las rodillas se doblen hacia adentro en el aterrizaje del salto de longitud.","- Aterriza silenciosamente con las rodillas dobladas para proteger tus articulaciones.","- Usa tus brazos para ganar impulso en el salto de longitud.","- Concéntrate en los saltos de calidad, no sólo en la distancia.","### Errores comunes a evitar","- Colapsar la zona lumbar durante la plancha/flexión.","- Mantenga su núcleo reforzado y los brazos relajados a los lados.","- Vuelva a ponerse en cuclillas: salte o dé un paso hacia adelante con los pies para que aterricen justo fuera de sus manos. Mantenga el pecho elevado mientras se prepara para saltar.","- Restablecer: date la vuelta o camina hacia atrás hasta tu punto de partida. Repita hasta obtener el número deseado de repeticiones o distancia.","- Repita para la cantidad deseada de repeticiones o distancia.","### Consejos para una forma adecuada","- Mantenga su núcleo apretado durante las fases de flexión y salto.","- Aterrizar con las piernas rígidas, lo que aumenta el riesgo de lesiones.","- Apresurarse por la fase de burpee sin control."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('15057d50-c0de-4e80-babe-15057d500000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2025/07/Pvc-Hip-Hinge.gif', '{"- Párese con los pies separados a la altura de las caderas y las rodillas ligeramente flexionadas.","- Baje el torso hasta que sienta un estiramiento en los isquiotibiales, luego regrese a la posición inicial impulsando las caderas hacia adelante.","- Cambie su peso a los talones, no a los dedos de los pies.","- Sostenga un tubo de PVC verticalmente a lo largo de su columna, usando una mano detrás de su cuello y la otra detrás de su espalda baja.","- Comience la bisagra empujando las caderas hacia atrás, manteniendo la columna recta y el PVC en contacto con los tres puntos.","- Mantenga los tres puntos de contacto en el PVC durante todo el movimiento.","- Doble solo las caderas, no la cintura ni la columna.","- Permitir que las rodillas se doblen excesivamente, convirtiendo la bisagra en una sentadilla.","- Apresurar el movimiento, lo que reduce la eficacia del ejercicio.","- Muévete lentamente y con control para reforzar la técnica adecuada.","### Errores comunes","- Perder contacto con el PVC en la zona lumbar o cabeza.","- Asegúrese de tres puntos de contacto: la parte posterior de la cabeza, entre los omóplatos y el coxis.","### Consejos para una forma adecuada","- Mantenga el pecho erguido y los hombros hacia atrás mientras gira.","- Doblar la columna, en lugar de doblar las caderas.","- Empujar las caderas hacia abajo en lugar de hacia atrás."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1b603c37-c0de-4e80-babe-1b603c370000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2025/07/Leg-Swings-Front-to-Back.gif', '{"- Párese erguido junto a una pared u objeto resistente para mantener el equilibrio.","- Cambie su peso a una pierna y levante ligeramente la pierna opuesta del suelo.","- Gire la pierna levantada hacia adelante, manteniendo la rodilla recta o ligeramente doblada.","- Permita que la pierna se balancee hacia atrás, creando un arco suave de adelante hacia atrás.","- Cambia de lado y repite con la pierna opuesta.","- Mantenga el torso erguido y el núcleo comprometido durante todo el movimiento.","- Realice de 10 a 15 movimientos por pierna, aumentando el rango de movimiento gradualmente con cada repetición.","- Respire constantemente para mantenerse relajado y concentrado en el movimiento.","- Comience con un rango pequeño y aumente a medida que su cuerpo se caliente.","- Evite los cambios bruscos o incontrolados; mantener el movimiento fluido.","### Errores comunes","- Arquear la zona lumbar, lo que puede tensar la columna.","- Balancearse con demasiada fuerza, lo que puede provocar un control deficiente o lesiones.","### Consejos para una forma adecuada","- Mantenga el equilibrio sobre la pierna de apoyo, utilizando apoyo sólo si es necesario.","- Girar las caderas hacia afuera, reduciendo la efectividad del estiramiento.","- Inclinarse demasiado hacia adelante o hacia atrás, alterando la alineación del cuerpo.","- Usar el impulso, en lugar del control muscular, para mover la pierna."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('48298a19-c0de-4e80-babe-48298a190000', 'Ejercicio de pie', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2025/05/Standing-Stomach-Vacuum.gif', '{"- Párese erguido con los pies separados a la altura de los hombros y los hombros relajados.","- Dibuja tu ombligo hacia adentro, hacia tu columna, como si intentaras hacer tu cintura lo más pequeña posible.","- Realizar en ayunas, preferiblemente por la mañana.","- Involucre solo los músculos abdominales, no los glúteos ni la parte superior del cuerpo.","- Respire superficialmente si es necesario mientras mantiene el vacío.","- Exhale completamente para eliminar el aire de sus pulmones.","- Inhale lentamente para relajarse y repita el proceso durante 3 a 5 series.","- Progrese lentamente, aumentando el tiempo de espera a medida que mejora la fuerza.","### Errores comunes","- Succionando el pecho, en lugar de tirar de la parte inferior del abdomen.","- Utilizar la tensión de la parte superior del cuerpo, en lugar de aislar el núcleo.","- Mantenga la contracción sin inhalar, manteniendo una postura firme durante 10 a 20 segundos.","### Consejos para una forma adecuada","- Mantenga el pecho elevado y la columna neutra.","- Contener la respiración demasiado tiempo, provocando mareos.","- Realizarse después de una comida, lo que limita la contracción abdominal.","- Dejar que la postura colapse, reduciendo la efectividad."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2d53fb34-c0de-4e80-babe-2d53fb340000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2025/07/Weighted-Muscle-Up.gif', '{"- Coloque pesas de forma segura en un cinturón de inmersión, chaleco o mochila. Utilice un peso moderado para comenzar.","- Agarre la barra un poco más ancha que el ancho de los hombros, con un agarre falso o un agarre por encima de la cabeza estándar.","- Presione su cuerpo hacia arriba, terminando en una posición de inmersión bloqueada sobre la barra.","- Utilice un agarre falso si es necesario para facilitar la transición sobre la barra.","- Usar demasiado peso demasiado pronto, lo que compromete la forma.","- Inicie una dominada poderosa, empujando los codos hacia abajo y hacia atrás agresivamente.","- Haga una transición explosiva sobre la barra, levantando el pecho y moviendo las muñecas hacia arriba.","- Tira alto y rápido, con el objetivo de llevar la parte superior del pecho por encima de la barra rápidamente.","- Lleva los codos hacia atrás, no sólo hacia arriba, para guiar la transición.","### Errores comunes","- Dar saltos o balanceos excesivos, lo que reduce las ganancias de fuerza.","- Bajando demasiado, lo que hace que la transición sea casi imposible.","- Bájese bajo control y repita las repeticiones deseadas o mantenga la posición superior para realizar trabajos de estabilidad.","### Consejos para una forma adecuada","- Mantenga el núcleo apretado y evite balancearse durante el tirón.","- Mantenga el control durante el descenso para proteger hombros y codos.","- No entrenar la transición por separado, lo que provoca paradas a mitad de repetición.","- Ignorando la movilidad, especialmente en hombros y muñecas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7282ddf4-c0de-4e80-babe-7282ddf40000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Bear-Crawl.gif', '{"- Muévete lenta y deliberadamente para controlar la posición de tu cuerpo.","- Comience a cuatro patas, con las manos debajo de los hombros y las rodillas debajo de las caderas.","- Apoye su núcleo y mantenga la espalda plana durante todo el movimiento.","- Avanza avanzando simultáneamente con la mano derecha y el pie izquierdo, luego con la mano izquierda y el pie derecho.","- Continúe hasta la distancia deseada, manteniendo las caderas bajas y el cuerpo alineado.","- Levante ligeramente las rodillas del suelo, manteniéndolas dobladas a unas 2 o 3 pulgadas del suelo.","- Perder la alineación, lo que hace que la columna se doble o se tuerza.","- Dejar que las rodillas se desplacen demasiado hacia adelante o fuera de debajo de las caderas.","- Minimiza la rotación del torso para una mejor activación del núcleo.","- Respire constantemente para mantener la tensión sin fatiga.","### Errores comunes","- Las caderas se elevan demasiado, lo que reduce la participación del core.","### Consejos para una forma adecuada","- Mantenga las rodillas cerca del suelo para un compromiso óptimo del núcleo.","- Mantenga una columna neutra, evitando hundirse o arquearse.","- Moverse demasiado rápido, sacrificando control y estabilidad.","- No reforzar el núcleo, lo que conduce a un control y una compensación deficientes."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('30a27f00-c0de-4e80-babe-30a27f000000', 'Dominadas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2025/07/Top-Half-Pull-up.gif', '{"- Párate sobre una caja o salta para que tu barbilla comience por encima de la barra.","- Haz una pausa breve y luego vuelve a subir hasta que tu barbilla vuelva a sobrepasar la barra.","- Respire constantemente para mantener la estabilidad y el ritmo del núcleo.","- Utilice un tempo controlado para evitar el uso del impulso.","- Baje hasta la mitad (los codos alcanzan aproximadamente una curva de 90 grados).","- Involucre la escápula y los dorsales durante todo el movimiento.","### Errores comunes","- Caer demasiado en una repetición completa, frustrando el propósito de la parcial.","- Encogerse de hombros, lo que limita el compromiso de los dorsales y romboides.","- Balancearse o dar saltos, reduciendo el tiempo bajo tensión.","- Repita de 3 a 8 repeticiones, manteniendo la tensión y el control en todo momento.","- Evite la extensión total en la parte inferior; permanecer en la mitad superior del rango.","### Consejos para una forma adecuada","- Mantenga los codos ligeramente doblados hacia los costados.","- Evite la relajación total en la parte inferior del rango medio.","- Dejar que el núcleo se desconecte, lo que lleva a una mala alineación.","- Despreciando la pausa en la parte inferior del rango superior."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('026db0b0-c0de-4e80-babe-026db0b00000', 'Ejercicio con banda de resistencia', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2025/07/How-to-do-Band-Assisted-Muscle-Up.gif', '{"- Pase una banda de resistencia de forma segura sobre una barra de dominadas y coloque los pies o las rodillas en la banda.","- Agarre la barra firmemente con las manos ligeramente más anchas que el ancho de los hombros, utilizando un agarre falso si es posible.","- Presione hacia arriba en una posición de inmersión hasta que sus brazos estén completamente extendidos.","- Practica el falso agarre, que acorta el recorrido de tracción y mejora el apalancamiento.","- Utilizar un agarre de dominadas estándar, lo que dificulta la transición.","- Involucre su núcleo e inicie una dominada poderosa con velocidad hacia la barra.","- Utilice fuerza de tracción explosiva: esta es la clave para despejar la barra.","- Inclínese hacia adelante sobre la barra durante la transición para activar los tríceps desde el principio.","- A medida que su pecho se acerca a la barra, inclínese hacia adelante y lleve los codos hacia la transición.","- Baje lentamente, regresando a través de la fase de inmersión y dominadas. Repetir.","- Ir demasiado rápido, saltándose los pasos técnicos del movimiento.","- Controlar el descenso, especialmente al volver por el chapuzón.","### Errores comunes","- Depender demasiado de la banda, en lugar de tirar explosivamente.","### Consejos para una forma adecuada","- Mantenga el cuerpo tenso para reducir las fugas de energía durante la transición.","- Perder tensión central, lo que reduce la producción de energía.","- No inclinarse hacia adelante, lo que lleva a transiciones fallidas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('76635c80-c0de-4e80-babe-76635c800000', 'Dominadas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2025/05/eccentric-pull-up-female.gif', '{"- Utilice una caja o salte para llegar a la posición superior de dominadas (barbilla por encima de la barra).","- Utilice una caja o un banco para lograr una altura y seguridad constantes.","- Involucre sus estabilizadores centrales y escapulares.","- Controla el descenso sin dejarte caer ni balancearte.","- Involucre su espalda y brazos durante todo el descenso.","- Baje lentamente el cuerpo en línea recta, tardando entre 3 y 8 segundos en alcanzar la extensión completa del brazo.","- Baje lentamente para lograr la máxima participación de los músculos (objetivo de 5 a 8 segundos).","### Errores comunes","- Apresurar el descenso, lo que resta efectividad.","- Dejar que el cuerpo se balancee, perdiendo tensión y control muscular.","- Da un paso atrás y repite para las repeticiones deseadas.","### Consejos para una forma adecuada","- Mantenga su núcleo reforzado para evitar balancearse o arquearse.","- Evite bloquear los codos repentinamente en la parte inferior.","- Saltarse el descanso adecuado entre repeticiones, lo que lleva a una alteración de la forma.","- No involucrar la escápula, lo que provoca una mala mecánica del hombro.","- Caer abruptamente, con riesgo de lesiones o tensión en las articulaciones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2d617805-c0de-4e80-babe-2d6178050000', 'Fondos unilateral', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2025/04/One-arm-Single-leg-Bench-Dips.gif', '{"- Siéntese en el borde de un banco plano con las piernas extendidas frente a usted y las manos apoyadas en el banco justo afuera de sus caderas.","- Coloque la mano opuesta detrás de usted en el banco y levante las caderas de la superficie, sosteniendo su cuerpo con ese brazo y su talón apoyado en el suelo.","- Empuja con la palma de la mano para volver a la posición inicial.","- Levanta una pierna del suelo y extiéndela recta.","- Baje el cuerpo doblando el codo de trabajo, manteniendo la espalda cerca del banco.","- Desciende hasta que tu codo forme un ángulo de 90 grados o tan bajo como te permita tu movilidad.","- Mantenga el torso erguido y cerca del banco para reducir la tensión en los hombros.","- Extienda completamente la pierna que no trabaja para aumentar el desafío del equilibrio y el compromiso central.","- Usar impulso en lugar de movimientos estrictos y controlados.","- Apoye su núcleo en todo momento para estabilizar su cuerpo y evitar torceduras.","- Baje lentamente y mantenga el control, especialmente al empujar hacia arriba.","### Errores comunes","- Inclinarse demasiado hacia adelante, genera tensión en la parte delantera del hombro.","- Dejar que el torso gire o gire, lo que reduce el control y el aislamiento muscular.","- Repita para las repeticiones, luego cambie de lado para equilibrar el entrenamiento.","### Consejos para una forma adecuada","- Asegúrese de que su codo permanezca metido hacia adentro, sin extenderse hacia afuera durante la inmersión.","- Caer demasiado rápido en el chapuzón, lo que corre el riesgo de lesionarse debido a la falta de control.","- Ensanchando el codo hacia afuera, reduciendo el compromiso del tríceps y aumentando la tensión articular."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7cd28622-c0de-4e80-babe-7cd286220000', 'Ejercicio con barra', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Barbell-Hip-Thrust.gif', '{"Siéntate en el suelo con la parte superior de la espalda apoyada en un banco y una barra sobre las caderas.","Haga rodar la barra para que descanse sobre el pliegue de sus caderas, colocando una almohadilla o toalla debajo para mayor comodidad.","Doble las rodillas y plante los pies planos, separados a la altura de las caderas.","Apoye su núcleo y empuje los talones para levantar las caderas hacia arriba.","En la parte superior, aprieta los glúteos y haz una pausa cuando tu torso esté paralelo al suelo.","Baje lentamente hacia abajo y repita hasta el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('53021bd9-c0de-4e80-babe-53021bd90000', 'Ejercicio', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2025/07/wrist-rotations.gif', '{"- Párate o siéntate erguido, manteniendo los hombros relajados.","- Haga los puños flojos o abra las palmas, luego gire las muñecas en círculos lentos y controlados.","- Realice de 10 a 15 rotaciones en el sentido de las agujas del reloj y luego invierta la dirección durante 10 a 15 repeticiones en el sentido contrario a las agujas del reloj.","- Respire naturalmente y evite mover los codos u hombros durante el movimiento.","- Mueva sólo las muñecas, no los antebrazos ni los hombros.","- Extienda ambos brazos hacia adelante, con los codos ligeramente doblados o bloqueados según su preferencia.","- Concéntrese en el rango circular completo, no solo en movimientos rápidos hacia adelante y hacia atrás.","- Mantenga el movimiento suave, evitando círculos entrecortados o apresurados.","- Relaje los dedos para evitar tensiones innecesarias.","- Incluir en calentamientos antes de ejercicios de fuerza o con las manos.","### Errores comunes","- Mover los codos o los brazos, en lugar de aislar las muñecas.","- Girar demasiado rápido, lo que reduce la eficacia del cebado de las articulaciones.","### Consejos para una forma adecuada","- Olvidar ambos sentidos, limitando la movilidad y el equilibrio muscular.","- Tensar los antebrazos, generando fatiga o malestar.","- Olvidar incluirlo en los calentamientos, especialmente antes de los ejercicios de carga de muñeca."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('39de05bd-c0de-4e80-babe-39de05bd0000', 'Ejercicio', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2025/06/clean-and-jerk.gif', '{"- Colóquese con los pies separados a la altura de las caderas, la barra sobre la mitad del pie y las manos ligeramente más anchas que el ancho de los hombros.","- Déjate caer debajo de la barra y cógela en una posición frontal con los codos en alto.","- Estabilice y párese erguido para completar el levantamiento.","- Conduce a través de los talones y extiende las caderas completamente antes del agarre.","- Practique la movilidad del estante delantero para mantener una posición limpia y segura.","- Mala posición de la parrilla delantera, lo que provoca inestabilidad en la limpieza.","- Fase limpia: Mantenga la espalda plana y el pecho hacia arriba mientras levanta la barra del suelo. Extiéndase explosivamente a través de las caderas y encoja los hombros, tirando de la barra hacia arriba. Déjese caer debajo de la barra y cógela en una posición frontal con los codos en alto.","- Extiéndete explosivamente a través de las caderas y encógete de hombros, tirando de la barra hacia arriba.","- Fase de sacudida: Sumérgete ligeramente doblando las rodillas, luego conduce hacia arriba a través de las piernas. Divide o empuja debajo de la barra rápidamente, bloqueando los brazos por encima de la cabeza. Estabiliza y párate erguido para completar el levantamiento.","- Sumérgete ligeramente doblando las rodillas y luego sube por las piernas.","- Mantenga la espalda apretada durante el tirón inicial para evitar que se doble.","- Divida o empuje debajo de la barra rápidamente, bloqueando los brazos por encima de la cabeza.","- Utilice un descenso controlado y un impulso agresivo en la fase de sacudida.","- Coge la barra con una base sólida, especialmente en el split Jerk.","### Errores comunes","- Tirar demasiado pronto, lo que reduce la altura de la barra y altera el tiempo.","- Mantenga la espalda plana y el pecho hacia arriba mientras levanta la barra del suelo.","### Consejos para una forma adecuada","- No extender completamente las caderas antes de caer debajo de la barra.","- Acelerar el tirón, sin una secuencia adecuada de inmersión y conducción.","- No lograr estabilizar la cabeza, especialmente bajo fatiga."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6e2e18df-c0de-4e80-babe-6e2e18df0000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2025/04/Full-Planche.gif', '{"- Comience en una posición de flexión: comience en una posición de flexión, con las manos ligeramente más separadas que el ancho de los hombros.","- Equilibrio y sujeción: mientras levanta las piernas, use las manos y los hombros para ayudar a equilibrar el cuerpo en una posición horizontal. Mantén la mirada hacia adelante y concéntrate en mantener la sujeción.","- Doblar los codos: Doblar los codos compromete la posición y ejerce una tensión excesiva en los brazos y los hombros.","- Colocación incorrecta de las manos: Colocar las manos demasiado hacia adelante o hacia atrás puede afectar el equilibrio y dificultar el mantenimiento de la posición.","- No mantener las piernas rectas: Doblar las rodillas reduce la intensidad del ejercicio y hace que la posición sea inestable.","- Mantenga la posición: mantenga la plancha completa el mayor tiempo posible, concentrándose en el equilibrio y la alineación adecuada del cuerpo. A medida que desarrolle fuerza, trate de aguantar por períodos más prolongados.","- Involucre el núcleo: apriete los abdominales y los músculos de la espalda baja para mantener una posición recta del cuerpo.","- Involucre el núcleo y los hombros: empuje los hombros hacia adelante y active el núcleo para evitar que la espalda baja se hunda. Tus brazos deben estar rectos y completamente bloqueados.","- Levante los pies del suelo: levante lentamente las piernas del suelo, manteniéndolas rectas, hasta que su cuerpo forme una línea recta desde la cabeza hasta los dedos de los pies.","- Empuje con las manos: presione las manos contra el suelo para estabilizar los hombros y mantener el equilibrio.","- Falta de compromiso del core: No involucrar el core puede provocar flacidez de la espalda baja e inestabilidad en el movimiento.","- Trabajar la movilidad de la muñeca: La flexibilidad de la muñeca es crucial para realizar la Plancha Completa sin molestias.","### Errores comunes","### Consejos para una forma adecuada","- Mantenga los brazos rectos: asegúrese de que sus brazos estén completamente extendidos y bloqueados a la altura de los codos para evitar tensiones.","- Concéntrese en su mirada: mantenga la mirada hacia adelante para ayudar con la alineación del cuerpo y evitar una tensión excesiva en el cuello.","- Acelerar la progresión: saltarse las progresiones puede provocar lesiones y dificultades para dominar la plancha completa."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('24ee1cae-c0de-4e80-babe-24ee1cae0000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2025/04/Bodyweight-Plie-Squat.gif', '{"- Párese con los pies más anchos que el ancho de los hombros y gire los dedos de los pies hacia afuera en un ángulo de aproximadamente 45 grados.","- Conduce con los talones para volver a la posición inicial, apretando los glúteos en la parte superior.","- Empuje las rodillas alineadas con los dedos de los pies mientras comienza a descender hasta la posición en cuclillas.","- Haga una breve pausa en la parte inferior, manteniendo la espalda recta y el núcleo reforzado.","- Involucre su núcleo en todo momento para apoyar su espalda baja.","- Doble las rodillas y baje las caderas hacia abajo hasta que los muslos queden paralelos al suelo o ligeramente más bajos.","- Utilice un espejo para comprobar que sus rodillas se desplacen correctamente sobre sus pies.","- Dejar que las rodillas se doblen hacia adentro, lo que puede forzar las articulaciones y reducir el compromiso de los aductores.","- Apresurar el movimiento, lo que reduce el control y la activación muscular.","- Baja lentamente con control para activar la parte interna de los muslos y los glúteos.","### Errores comunes","- Girar demasiado los pies, lo que puede provocar inestabilidad en los tobillos y las rodillas.","- Mantenga el pecho erguido y active el núcleo para sostener la columna.","### Consejos para una forma adecuada","- Mantenga las rodillas alineadas con los dedos de los pies para evitar tensión en las rodillas.","- Evite inclinarse hacia adelante; Mantenga el pecho elevado y la columna neutra.","- Inclinarse excesivamente hacia adelante, alejando la carga de los músculos previstos.","- No ponerse en cuclillas lo suficientemente profundo, lo que limita las ganancias de movilidad y el compromiso muscular."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('37f29c56-c0de-4e80-babe-37f29c560000', 'Ejercicio', 'Abdomen', '', '{"- Comience en una posición de flexión: comience en una posición de flexión tradicional con las manos ligeramente más separadas que el ancho de los hombros.","- No utilizar soporte para las muñecas: si las muñecas no están alineadas correctamente, puede provocar tensión e incomodidad. Asegúrese de que sus muñecas estén directamente debajo de sus hombros y que los dedos estén separados para un mejor agarre.","- Levante los pies del suelo: comience a levantar los pies del suelo cambiando lentamente más peso sobre las manos y ejerciendo más presión sobre su núcleo. Sólo las puntas de los dedos de los pies deben tocar ligeramente el suelo, proporcionando un apoyo mínimo.","- Mantenga la posición: mantenga la inclinación hacia adelante, manteniendo su cuerpo lo más horizontal posible. Mantenga esta posición durante un tiempo determinado, con el objetivo de aumentar su sujeción a medida que aumenta su fuerza.","- Estire los brazos: mantenga los brazos completamente extendidos con los codos bloqueados para evitar tensiones y involucrar los hombros de manera más efectiva.","- Empuje los hombros hacia adelante: mientras involucra los brazos y los hombros, empuje el cuerpo hacia adelante, de modo que los hombros se extiendan más allá de las manos. Tus codos deben permanecer rectos.","- Empuje con las palmas: presione activamente el suelo con las palmas para estabilizar el cuerpo y evitar que se incline hacia adelante.","- Inclinarse demasiado hacia adelante: Extender demasiado la inclinación puede dificultar el mantenimiento del equilibrio. Concéntrate en movimientos controlados y evita ir más allá de tu capacidad.","- Involucrar el núcleo: Tensa los músculos abdominales para evitar que la parte baja de la espalda se arquee o se hunda.","- Comience con pequeñas inclinaciones: comience con una ligera inclinación y aumente gradualmente el ángulo a medida que desarrolla fuerza en los hombros y el tronco.","### Errores comunes","- Involucre su núcleo: apriete los músculos centrales para evitar la flacidez en la parte baja de la espalda, manteniendo su cuerpo en línea recta desde la cabeza hasta los pies.","### Consejos para una forma adecuada","- Mantenga su mirada neutral: mire ligeramente hacia adelante para ayudar con la alineación del cuerpo y reducir la tensión en el cuello.","- Doblar los codos: Doblar los codos compromete la alineación y hace que el ejercicio sea menos efectivo. Mantenga siempre los brazos rectos.","- No activar el core: No activar el core puede hacer que la parte baja de la espalda se hunda, disminuyendo la estabilidad y ejerciendo una tensión innecesaria en la columna.","- Saltarse progresiones: intentar realizar la Lean Planche completa sin aumentar gradualmente la inclinación puede provocar una mala forma y posibles lesiones. Utilice progresiones para desarrollar fuerza con el tiempo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('40bba705-c0de-4e80-babe-40bba7050000', 'Press de pecho con barra', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2024/12/Barbell-JM-Press.gif', '{"Acuéstese en un banco plano con una barra colocada encima de usted sobre una rejilla.","Agarre la barra con las manos un poco más estrechas que el ancho de los hombros (un agarre cercano).","Presione la barra hacia atrás a la posición inicial extendiendo los codos completamente.","Saque la barra y colóquela sobre su pecho, con los brazos completamente extendidos.","Baje la barra hacia su pecho, pero permita que sus codos se desplacen ligeramente hacia adelante como si realizara una extensión de tríceps.","Detenga la barra entre 1 y 2 pulgadas por encima de su pecho, asegurándose de que sus codos permanezcan doblados y bajo control.","Repita para el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('44b5af13-c0de-4e80-babe-44b5af130000', 'Press de hombros sentado con barra', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Barbell-Shoulder-Press.gif', '{"- Siéntese derecho en un banco plano, manteniendo los pies planos y plantados ligeramente más anchos que el ancho de las caderas.","- Coloque la barra a la altura de los hombros sobre una rejilla y sujétela un poco más ancha que el ancho de los hombros.","- Siéntese erguido y active su núcleo para evitar arquear la zona lumbar.","- Agarre el suelo con los pies para crear una base estable para sentarse.","- Usar demasiado peso, lo que compromete la forma sin el soporte.","###","- Involucre su núcleo y glúteos para mantener el equilibrio sin respaldo.","- Presione la barra por encima de su cabeza, extendiendo los brazos sin inclinarse hacia atrás.","- Conduce la barra en línea recta, ligeramente detrás de tu cabeza en la parte superior.","- Retire la barra y llévela al nivel de los hombros con los codos ligeramente por delante de la barra.","- Baje la barra bajo control hasta la parte superior del pecho o la línea de los hombros.","- Exhala mientras presionas e inhala mientras bajas la barra.","### Errores comunes","- Inclinándose demasiado hacia atrás, convirtiendo la prensa en una prensa de pecho inclinada.","- Dejar que los codos se ensanchen, lo que tensa las articulaciones de los hombros.","### Consejos para una forma adecuada","- Mantenga la caja torácica hacia abajo para evitar una extensión excesiva de la columna.","- Perder el compromiso central, provocando inestabilidad y mala postura.","- Hacer rebotar la barra contra el pecho, en lugar de controlar el descenso."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('744cf2ff-c0de-4e80-babe-744cf2ff0000', 'Sentadilla en máquina', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2024/10/smith-machine-squat.gif', '{"- Coloque la barra a la altura de la parte superior del pecho y cargue el peso deseado. Coloque los pies ligeramente por delante de la barra.","- Páse debajo de la barra, colóquela sobre los trapecios superiores y agarre un poco más que el ancho de los hombros.","- Conduce con los talones para empujar hacia atrás hasta la posición inicial, extendiendo completamente las caderas y las rodillas.","- Coloque la barra en las trampas, no en el cuello: previene la tensión y mantiene una mejor postura.","###","- Desciende hasta que tus muslos queden al menos paralelos al suelo o más bajos si la movilidad lo permite.","- Controla cada repetición: evita rebotar o usar el impulso en la parte inferior.","- Retire la barra girándola ligeramente, luego apoye su núcleo y manténgase erguido.","- Baje hasta ponerse en cuclillas doblando las rodillas y las caderas, manteniendo el pecho elevado y las rodillas siguiendo los dedos de los pies.","- Empuje con los talones: Ayuda a activar los glúteos y mantener el equilibrio.","- Dejar que las rodillas se doblen hacia adentro: aumenta el riesgo de lesiones y debilita la alineación.","### Errores comunes","- Pararse directamente debajo de la barra: limita la profundidad y ejerce presión sobre las rodillas.","- Redondear la espalda: un control central débil puede provocar lesiones.","- Repita para las repeticiones, luego vuelva a colocar la barra girándola nuevamente sobre los ganchos.","### Consejos para una forma adecuada","- Mantenga los pies ligeramente hacia adelante: esto compensa la trayectoria fija de la barra y reduce la tensión en las rodillas.","- Involucre su núcleo: estabilice su columna y mantenga el torso erguido.","- Levantar los talones: Indica mal equilibrio y reduce la afectación de los glúteos.","- Sentadilla demasiado superficial: Limita el compromiso y la progresión de los músculos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('170a6a34-c0de-4e80-babe-170a6a340000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/12/5-Dot-drills-agility-exercise.gif', '{"- Coloque cinco marcadores en el suelo en la secuencia A-B-C-D-E para formar el diseño.","- Párese en los marcadores iniciales, A y B.","- Inmediatamente realiza otro salto hacia atrás para volver a la posición inicial, marcadores A y B, con ambos pies juntos.","- Comience con los pies juntos en los marcadores A y B.","- Salta rápidamente hacia adelante hasta el marcador C, asegurándote de que tu pie izquierdo aterrice exactamente en el marcador.","- Ejecute un salto rápido hacia atrás con ambos pies, aterrizando en el marcador C con el pie izquierdo.","- Mantener el control y el equilibrio durante todo el movimiento.","- Siguiendo el marcador C, realiza otro salto explosivo, pero esta vez separa los pies. Aterriza con un pie en el marcador D y el otro en el marcador E.","- Duplica la secuencia, esta vez liderando con la pierna derecha. Esfuércese por ejecutar el ejercicio a la máxima velocidad manteniendo la forma adecuada."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('74ea4f41-c0de-4e80-babe-74ea4f410000', 'Sentadilla con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2024/09/dumbbell-cossack-squat.gif', '{"- Cambie su peso hacia un lado, doblando la rodilla de trabajo y empujando las caderas hacia atrás mientras la otra pierna permanece recta.","- Inclinarse demasiado hacia adelante: esto desplaza el peso de los glúteos hacia la columna.","- Sostenga una mancuerna verticalmente frente a su pecho con ambas manos, como si fuera una copa.","- Párate con los pies abiertos, los dedos ligeramente hacia afuera y el core comprometido.","- Utilice una postura amplia: una postura más amplia permite un descenso lateral más profundo y seguro.","- Baje hasta donde la movilidad lo permita, manteniendo el talón plano sobre la pierna doblada y el pie ligeramente girado hacia afuera.","- Empuje a través del talón de la pierna doblada para volver a ponerse de pie, luego repita del otro lado.","- Redondear la espalda: a menudo causado por dejar que la mancuerna se desplace hacia adelante o por un compromiso débil del core.","- No calentar: las caderas frías y los aductores son más propensos a sufrir tensiones durante el movimiento lateral profundo.","- Mantenga la mancuerna cerca: esto agrega resistencia y ayuda con el contrapeso.","- Controla el descenso: Muévete lentamente para mantener el control y proteger las rodillas y las caderas.","### Errores comunes","- Mantenga el pecho elevado y la mancuerna cerca de su cuerpo para mantener el equilibrio.","### Consejos para una forma adecuada","- Mantenga el torso erguido: evite colapsar hacia adelante apuntalando el núcleo y levantando el pecho.","- Mantenga el contacto con los pies: mantenga el talón de la pierna en cuclillas apoyado en el suelo en todo momento.","- Levantar el talón demasiado pronto: Mantenga el talón de la pierna doblada en el suelo para lograr estabilidad y compromiso total.","- Acelerar el movimiento: las repeticiones rápidas reducen el control y aumentan el riesgo de lesiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4d5ba91b-c0de-4e80-babe-4d5ba91b0000', 'Zancadas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/09/curtsy-lunge.gif', '{"Empuja con el talón derecho para volver a la posición inicial. Mantenga el torso erguido y el pecho elevado durante todo el movimiento.","Colóquese con los pies separados a la altura de las caderas y mantenga las manos frente al pecho para ayudar a mantener el equilibrio.","Doble ambas rodillas, bajando el cuerpo hasta que el muslo derecho quede paralelo al suelo y la rodilla izquierda casi toque el suelo.","Da un paso en diagonal detrás de ti con el pie izquierdo, cruzándolo por detrás de la pierna derecha como si estuvieras haciendo una reverencia.","Continúe alternando lados para el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1354dc9c-c0de-4e80-babe-1354dc9c0000', 'Sentadilla con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/Dumbbell-Goblet-Squat.gif', '{"- Sostenga una mancuerna verticalmente con ambas manos debajo de la parte superior (el extremo con peso), cerca de su pecho.","- Párese con los pies separados a la altura de los hombros y los dedos ligeramente hacia afuera.","- Conduce con los talones para volver a la posición de pie, extendiendo completamente las caderas en la parte superior.","- Involucre su núcleo y mantenga su pecho elevado durante todo el movimiento.","- Profundice lo suficiente como para sentir un estiramiento en las caderas y los glúteos mientras mantiene el control.","### Errores comunes","- Empuje las caderas hacia atrás y doble las rodillas, bajando hasta hacer una sentadilla profunda mientras mantiene la mancuerna al nivel del pecho.","- Empuje las rodillas alineadas con los dedos de los pies para evitar el colapso en valgo.","- Apoye su núcleo durante todo el movimiento para lograr estabilidad.","- Acelerar el movimiento, reduciendo la activación y el control muscular.","- Sentadillas poco profundas, que limitan el rango de movimiento y el beneficio.","- Dejar que la mancuerna se desplace hacia adelante, lo que desplaza el peso y tensiona la zona lumbar.","- Las rodillas se hunden hacia adentro, lo que reduce la estabilidad de la rodilla y aumenta el riesgo de lesiones.","- Mantenga los codos dentro de las rodillas a medida que alcanza la profundidad máxima y evite dejar que las rodillas colapsen hacia adentro.","### Consejos para una forma adecuada","- Mantenga la mancuerna cerca de su pecho para mantener el equilibrio y la postura erguida.","- Mantenga una columna neutral y evite inclinarse demasiado hacia adelante.","- Redondear la parte baja de la espalda, a menudo causado por una movilidad deficiente de la cadera o un compromiso central."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4c2d5de9-c0de-4e80-babe-4c2d5de90000', 'Remo con balón medicinal', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2023/12/Medicine-Ball-Rotational-Throw.gif', '{"Párese a una distancia de entre dos y cuatro pies de la pared, de cara a ella, con un balón medicinal sostenido con ambas manos. Balón medicinal (elija un peso adecuado según su nivel de condición física y sus objetivos).","Transferencia de peso: transfiera su peso desde la cadera trasera a la cadera delantera. Este cambio dinámico de peso es un componente crucial para generar potencia en el lanzamiento.","Posición inicial: Párese a una distancia de entre dos y cuatro pies de la pared, de cara a ella, con un balón medicinal sostenido con ambas manos. Balón medicinal (elija un peso adecuado según su nivel de condición física y sus objetivos).","Preparación del movimiento: lleve el balón medicinal a la parte trasera de la cadera. Este movimiento inicial implica una rotación del torso mientras cargas la pelota en tu cadera trasera, preparándote para el lanzamiento explosivo.","Atrapar y repetir: después de que la pelota rebote en la pared, cógela con ambas manos. Tómate un momento para descansar y luego repite el movimiento.","Rotación de cadera: rota tus caderas explosivamente mientras lanzas la pelota contra la pared. La rotación explosiva de la cadera es un elemento clave para generar potencia en este ejercicio. Enfatice el poder generado desde las caderas, no solo los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2d2ea3f1-c0de-4e80-babe-2d2ea3f10000', 'Plancha', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2025/03/Side-Plank-Hip-Adduction-Copenhagen-adduction.gif', '{"- Configuración: Colóquese junto a un banco o una superficie elevada. Acuéstese de costado con la pierna superior apoyada en el banco. Apóyese en el antebrazo o la mano, manteniendo la columna neutra.","- Colóquese junto a un banco o una superficie elevada.","- Acuéstese de costado con la pierna superior apoyada en el banco.","- Involucre su núcleo y levante: presione a través de la pierna superior y levante las caderas en una posición de tabla lateral. La pierna inferior debe colgar debajo del banco. Mantenga su cuerpo en línea recta desde la cabeza hasta los pies.","- La pierna de abajo debe colgar debajo del banco.","- Ajusta la dificultad: si la versión completa es demasiado desafiante, comienza con la rodilla apoyada en el banco en lugar de tu pie.","###","### Guía paso a paso","- Apóyate sobre tu antebrazo o mano, manteniendo la columna neutra.","- Presione a través de la pierna superior y levante las caderas hasta adoptar una posición de tabla lateral.","- Realice la aducción de la cadera: levante la pierna de abajo hacia la pierna de arriba usando la fuerza interna del muslo. Manténgala brevemente en la parte superior para maximizar la activación muscular. Baje lentamente la pierna de abajo bajo control.","- Levante la pierna de abajo hacia la pierna de arriba usando la fuerza de la parte interna del muslo.","- Baje lentamente la pierna de abajo bajo control.","- Involucre su núcleo durante todo el movimiento para mantener el equilibrio.","- Respire adecuadamente: exhale al levantar la pierna, inhale al bajar.","- Usar impulso en lugar de movimiento controlado.","- Mantén presionado brevemente en la parte superior para maximizar la activación muscular.","- Repeticiones y series: Realice de 3 a 4 series de 8 a 12 repeticiones por lado, dependiendo de su nivel de condición física.","- Muévase de manera controlada para maximizar la participación de los músculos y prevenir lesiones.","### Errores comunes a evitar","- Dejar caer las caderas: esto reduce la activación del núcleo y los aductores.","- Mantenga su cuerpo en línea recta desde la cabeza hasta los pies.","- Realiza de 3 a 4 series de 8 a 12 repeticiones por lado, dependiendo de tu nivel de condición física.","### Consejos para una forma adecuada","- Evite las caderas caídas; mantenga el cuerpo en línea recta desde los hombros hasta los pies.","- Conteniendo la respiración: respire siempre rítmicamente para apoyar la resistencia muscular.","- Descuidar el compromiso central, lo que lleva a una falta de estabilidad.","- Comenzando con dificultad excesiva; modifique si es necesario para mantener la forma adecuada."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('08545745-c0de-4e80-babe-085457450000', 'Zancadas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/09/High-Knee-Lunge-on-Bosu-Ball.gif', '{"- Utilice los brazos como contrapeso, especialmente durante el impulso de rodilla.","- Dale la vuelta a la Bosu Ball para que el lado plano quede hacia arriba.","- Levante un pie y párese en el centro de la Bosu Ball, asegurándose de que su pie esté centrado en la plataforma.","- Baje su cuerpo a una posición de estocada inversa.","- Mientras empuja hacia arriba desde la posición de estocada, levante la rodilla trasera hacia el pecho, llevándola tan alto como le resulte cómodo.","- Después de completar el movimiento con una pierna, retroceda al suelo y cambie a la otra pierna, repitiendo la estocada y el levantamiento alto de la rodilla.","- Involucre su núcleo durante todo el movimiento para mantener el equilibrio.","- Levante la rodilla con control, no con impulso, para activar los flexores de la cadera.","- Perder el equilibrio debido a una mala colocación del pie BOSU o a un movimiento apresurado.","- La inestabilidad de la superficie activará los músculos estabilizadores. Durante todo el movimiento, mantenga el equilibrio sobre la Bosu Ball. Utilice los músculos centrales y de las piernas para estabilizarse.","- Realice el ejercicio durante un número específico de repeticiones o duración de tiempo.","### Errores comunes","- Inclinarse demasiado hacia adelante, generando tensión innecesaria en la rodilla o la espalda baja.","- No retroceder lo suficiente, lo que limita el alcance y la efectividad.","### Consejos para una forma adecuada","- Mantenga el pie delantero centrado en el BOSU para mayor estabilidad.","- Asegúrese de que su rodilla delantera permanezca alineada con los dedos de los pies durante la fase de estocada.","- Usar el impulso durante la elevación de la rodilla en lugar del control muscular.","- Si no se involucran los glúteos, se reducen los beneficios generales de fuerza."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('18231a1e-c0de-4e80-babe-18231a1e0000', 'Ejercicio con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2025/03/Single-Leg-Dumbbell-Hip-Thrust.gif', '{"Siéntese en el suelo con la parte superior de la espalda apoyada contra un banco o una superficie elevada. Coloque una mancuerna sobre las caderas y sosténgala de forma segura. Doble las rodillas con un pie apoyado en el suelo y la otra pierna extendida y recta.","Coloque una mancuerna sobre sus caderas y sosténgala firmemente.","Fase de descenso: baje lentamente las caderas hasta la posición inicial bajo control. Repita el número deseado de repeticiones y luego cambie de pierna.","Baje lentamente las caderas hasta la posición inicial bajo control.","Configuración: Siéntese en el suelo con la parte superior de la espalda apoyada contra un banco o una superficie elevada. Coloque una mancuerna sobre las caderas y sosténgala de forma segura. Doble las rodillas con un pie apoyado en el suelo y la otra pierna extendida y recta.","Posicionamiento del cuerpo: Involucre su núcleo y glúteos antes de comenzar el movimiento. Mantenga la barbilla doblada y la mirada hacia adelante.","Conduce a través del talón de tu pie plantado, empujando tus caderas hacia arriba.","Aprieta los glúteos en la parte superior y asegúrate de que las caderas estén completamente extendidas.","Mantenga la barbilla recogida y la mirada hacia adelante.","Movimiento de empuje: conduzca a través del talón del pie plantado, empujando las caderas hacia arriba. Apriete los glúteos en la parte superior y asegúrese de que las caderas estén completamente extendidas. Mantenga una columna neutra sin arquear demasiado la zona lumbar.","Repita hasta el número deseado de repeticiones, luego cambie de pierna.","Realiza de 3 a 4 series de 8 a 12 repeticiones por pierna, dependiendo de tu nivel de condición física.","Repeticiones y series: Realice de 3 a 4 series de 8 a 12 repeticiones por pierna, dependiendo de su nivel de condición física."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('77247922-c0de-4e80-babe-772479220000', 'Ejercicio de pie', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/10/Standing-Leg-Circles.gif', '{"- Párese erguido con los pies separados a la altura de los hombros y las manos en las caderas o extendidas para mantener el equilibrio.","- Cambie su peso a una pierna y levante ligeramente el pie opuesto del suelo.","- Cambia de pierna y repite.","- Involucre su núcleo para mantenerse equilibrado y estable.","- Comience con círculos pequeños y aumente gradualmente el alcance.","- Dibuja pequeños círculos en el aire con la pierna levantada, moviéndola hacia adelante, hacia afuera y luego hacia atrás con un movimiento lento y controlado.","- Realice de 8 a 10 círculos en una dirección y luego invierta la dirección.","- Utilice movimientos lentos y controlados en lugar de impulso.","- Balancear la pierna en lugar de controlar el movimiento.","- Acelerar el movimiento, lo que reduce el compromiso muscular.","- Utilice una pared o una silla como apoyo si es necesario, especialmente para principiantes.","### Errores comunes","- Inclinarse excesivamente hacia un lado, reduciendo los beneficios del equilibrio.","### Consejos para una forma adecuada","- Mantenga la parte superior del cuerpo erguida y evite inclinarse.","- Olvidar invertir la dirección conduce a un desarrollo desequilibrado.","- No mantener activada la pierna de apoyo, perderse el entrenamiento de estabilidad."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('28fb1779-c0de-4e80-babe-28fb17790000', 'Curl de bíceps sentado', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2023/10/Seated-Zottman-Curl.gif', '{"- Posición sentada: comience sentándose en un banco o silla con la espalda recta y los pies apoyados en el suelo. Esta posición sentada ayuda a estabilizar su cuerpo, aislando los músculos que desea trabajar.","- Agarre en supinación: sostenga una mancuerna en cada mano con las palmas hacia arriba (agarre en supinación). Comienza con los brazos completamente extendidos, colgando a los costados.","- Regreso a la posición inicial: comience a bajar las mancuernas lentamente hasta la posición inicial, mientras mantiene las palmas hacia abajo. Una vez que sus brazos estén completamente extendidos, gire las muñecas hacia la posición con las palmas hacia arriba y repita el movimiento durante la cantidad deseada de repeticiones.","- Fase de pronación: en la parte superior del curl, cuando los bíceps estén completamente contraídos, gire las muñecas en la parte superior del movimiento girando las palmas hacia abajo en un agarre en pronación.","- Fase de flexión: doble las mancuernas hacia los hombros mientras mantiene la parte superior de los brazos inmóviles. Mientras levantas las pesas, tus palmas deben permanecer hacia arriba.","### Consejos para una forma adecuada:"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('79c11a93-c0de-4e80-babe-79c11a930000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2023/10/Navy-Seal-Burpee.gif', '{"- Comience desde una posición de pie con los pies separados a la altura de los hombros.","- Ponte en cuclillas, coloca las manos en el suelo y patea los pies hacia atrás hasta colocarlos en posición de flexión.","- Realice una tercera flexión, luego salte con los pies hacia adelante para volver a la posición en cuclillas.","- Explota hacia arriba dando un salto, extendiendo la mano por encima de tu cabeza.","- Aterriza suavemente y repite.","- Mantenga su núcleo reforzado durante cada flexión y movimiento de rodilla.","- Realice una flexión y luego lleve la rodilla derecha hacia el codo derecho.","- Realice una segunda flexión y luego lleve la rodilla izquierda hacia el codo izquierdo.","- Dejar que las caderas se hundan durante las flexiones, lo que genera tensión en la zona lumbar.","- Profundidad inconsistente en flexiones o sentadillas.","- Controla tu respiración, exhalando durante el esfuerzo e inhalando al bajar.","- Mantenga los codos en un ángulo de 45 grados durante las flexiones para proteger sus hombros.","- Mantenga una columna neutra durante las flexiones y los saltos.","- Aterrice suavemente para reducir el impacto en las articulaciones.","### Errores comunes","### Consejos para una forma adecuada","- Apresurarse en las repeticiones, lo que compromete la forma y aumenta el riesgo de lesiones.","- Saltarse los impulsos de rodilla, lo que reduce la activación del núcleo.","- Descuidar el salto, lo que reduce la intensidad metabólica."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('08c1b44e-c0de-4e80-babe-08c1b44e0000', 'Zancadas con mancuernas', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2023/09/dumbbell-lunges.gif', '{"- Párese erguido con los pies separados a la altura de las caderas y active su núcleo.","- Sostenga una mancuerna en cada mano, con los brazos extendidos a los lados y las palmas hacia adentro.","- Da un gran paso hacia adelante con la pierna derecha, bajando ambas rodillas hasta que la rodilla trasera quede justo por encima del suelo.","- Empuja con el talón delantero para levantarte y lleva la pierna trasera hacia adelante para dar el siguiente paso.","- Da un paso lo suficientemente ancho como para que la rodilla delantera no pase los dedos del pie.","- Dejar que las rodillas se doblen hacia adentro, lo que puede dañar la articulación.","- Controle su ritmo para garantizar la forma adecuada y la activación muscular.","### Errores comunes","- Dar un paso demasiado corto y ejercer presión sobre la rodilla delantera.","- Balancear las mancuernas, lo que altera el equilibrio y la postura.","- Mantenga el pecho erguido y la rodilla delantera directamente por encima del tobillo.","- Continúe alternando piernas mientras camina hacia adelante durante la cantidad deseada de repeticiones o distancia.","### Consejos para una forma adecuada","- Mantenga su núcleo comprometido para mantener el equilibrio y la estabilidad.","- Mantenga el torso erguido para evitar inclinarse hacia adelante.","- Utilice un paso firme y evite apresurarse al dar los pasos.","- Inclinarse excesivamente hacia adelante, desviando el énfasis de las piernas.","- Permitir que la rodilla trasera caiga al suelo, aumentando el riesgo de lesiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3e6e9509-c0de-4e80-babe-3e6e95090000', 'Zancadas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/10/Static-Lunge.gif', '{"- Párese con los pies separados a la altura de las caderas.","- Mantenga la posición baja por un momento y luego empuje con el talón del pie delantero para regresar a la posición inicial.","- Repita el movimiento durante el número deseado de repeticiones en una pierna antes de cambiar a la otra pierna.","- Involucre su núcleo para lograr equilibrio y estabilidad.","- Empuja el talón de tu pie delantero para activar los glúteos.","- Da un paso hacia adelante con un pie y luego da un paso más grande hacia atrás con el otro pie. Sus pies deben colocarse de manera que cuando baje el cuerpo hacia la estocada, ambas rodillas formen ángulos de 90 grados.","- Baje el cuerpo doblando ambas rodillas simultáneamente.","- Permitir que el talón trasero se levante, lo que hace perder el equilibrio.","- Acelerar el movimiento, en lugar de utilizar un movimiento controlado.","### Errores comunes","- Dejar que la rodilla delantera pase los dedos del pie, lo que puede tensar la rodilla.","- Inclinarse hacia adelante, reduciendo la efectividad de la estocada.","- Mantenga el torso erguido con el pecho levantado y los hombros relajados. Su núcleo debe estar comprometido para lograr estabilidad.","### Consejos para una forma adecuada","- Mantenga la rodilla delantera alineada con los dedos del pie, sin dejar que se colapse hacia adentro.","- Mantenga una postura erguida con el pecho levantado y la espalda recta.","- Mantenga ambos pies apoyados en el suelo para obtener un apoyo adecuado.","- Colocar los pies demasiado juntos, lo que afecta la estabilidad."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('20346d61-c0de-4e80-babe-20346d610000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2023/09/shadow-boxing-workout.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('310e9231-c0de-4e80-babe-310e92310000', 'Zancadas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/09/power-lunge.gif', '{"Párese con los pies separados a la altura de las caderas.","Mantenga las manos en las caderas o a los costados para mantener el equilibrio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4b2a0c0c-c0de-4e80-babe-4b2a0c0c0000', 'Curl concentrado de pie con barra', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2023/10/Standing-Barbell-Concentration-Curl.gif', '{"- Comience parándose con los pies separados a la altura de los hombros.","- Sostenga una barra con ambas manos usando un agarre supinado (con las palmas hacia adelante), con las manos ligeramente más separadas que el ancho de los hombros.","- Coloque los codos sobre los muslos o las rodillas como apoyo, permitiendo que los brazos cuelguen hacia abajo, completamente extendidos.","- Baje lentamente la barra hasta la posición inicial, extendiendo completamente los brazos.","- Utilice un peso moderado para mantener una forma estricta y evitar reclutar otros músculos.","- Concéntrese en apretar los músculos en lugar de simplemente mover el peso.","- Ir demasiado pesado: El peso excesivo compromete el control y la forma.","- Incline la parte superior del cuerpo hacia adelante a la altura de las caderas hasta que quede casi paralela al suelo. Esta inclinación hacia adelante ayuda a aislar los bíceps y a activar los músculos estabilizadores.","- Elimine el balanceo del cuerpo manteniendo el torso fijo durante todo el levantamiento.","- Con la parte superior de los brazos inmóviles, doble la barra hacia el pecho flexionando los codos.","- Aprieta tus bíceps en la parte superior del movimiento.","- Exhale mientras curva la barra e inhale mientras baja.","### Errores comunes","### Consejos para una forma adecuada","- Mantenga la muñeca en posición neutra; evite doblarla hacia adelante o hacia atrás.","- Ensanchando el codo: Mantenga el codo doblado hacia un lado para mantener la alineación.","- Extender demasiado en la parte inferior: Evite bloquear completamente para mantener la tensión en el músculo.","- Usar el impulso: balancear la barra reduce el aislamiento del bíceps."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('04278173-c0de-4e80-babe-042781730000', 'Ejercicio con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2023/10/Dumbbell-Good-Morning.gif', '{"- Párese erguido con los pies separados a la altura de las caderas, las rodillas ligeramente flexionadas y el núcleo comprometido.","- Impulsa las caderas hacia adelante para volver a la posición inicial, apretando los glúteos en la parte superior.","###","- Sostenga una mancuerna horizontalmente sobre la parte superior de la espalda, no sobre el cuello, agarrando cada extremo con ambas manos.","- Gire las caderas, empujándolas hacia atrás mientras mantiene la columna neutra y el pecho hacia arriba.","- Mantenga la espalda plana durante todo el movimiento para proteger su columna.","- Utilice una ligera flexión de las rodillas para mantener la tensión en los isquiotibiales.","- Baje el torso hasta que esté casi paralelo al suelo o sienta un estiramiento profundo en los isquiotibiales.","- Involucre su núcleo para estabilizar el torso y evitar que se doble.","- Muévete lentamente y con control para concentrarte en la activación muscular.","- Comience con un peso liviano para dominar el patrón de movimiento de la bisagra de la cadera.","### Errores comunes","- Redondear la zona lumbar, lo que aumenta el riesgo de lesiones.","- Dejar que las rodillas se bloqueen, lo que limita la movilidad y puede provocar tensión.","- Repita durante la cantidad deseada de repeticiones, manteniendo el control y la postura en todo momento.","### Consejos para una forma adecuada","- Inclinar la cabeza hacia arriba, lo que altera la alineación de la columna.","- Sostener la mancuerna en el cuello, lo que ejerce presión sobre la columna cervical.","- Doblar la cintura en lugar de las caderas, lo que reduce la activación de la cadena posterior."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('627ba309-c0de-4e80-babe-627ba3090000', 'Ejercicio', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2023/06/Frog-Stand.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('566062cc-c0de-4e80-babe-566062cc0000', 'Postura de yoga', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/Warrior-1-Pose.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('566062ce-c0de-4e80-babe-566062ce0000', 'Postura de yoga', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/Warrior-3-Pose.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('566062cd-c0de-4e80-babe-566062cd0000', 'Postura de yoga', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/Warrior-2-Pose.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('68a8fa2e-c0de-4e80-babe-68a8fa2e0000', 'Press de hombros de pie con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2023/09/Standing-Dumbbell-Overhead-Press.gif', '{"- Párese erguido con los pies separados a la altura de los hombros y las rodillas ligeramente dobladas.","- Sostenga una mancuerna en cada mano a la altura de los hombros con las palmas hacia adelante.","- Presione las mancuernas sobre su cabeza, extendiendo los brazos sin arquear la espalda.","- Involucre su núcleo para evitar inclinarse o arquear demasiado la parte baja de la espalda.","- Aprieta tus glúteos para estabilizar la pelvis y proteger tu columna.","- Baje las mancuernas bajo control hasta el nivel de los hombros para completar una repetición.","- Exhala mientras presionas, inhala mientras bajas.","- Presione las mancuernas ligeramente hacia atrás, no solo hacia arriba, para alinearlas con la mecánica de los hombros.","### Errores comunes","- Arquear excesivamente la zona lumbar, lo que genera tensión en la columna.","- Presionar de manera desigual, provocando un desequilibrio muscular.","- Permitir que los codos se abran demasiado, con el riesgo de sufrir tensión en los hombros.","- Apoye su núcleo y mantenga el pecho erguido y la columna neutral.","- Repita para las repeticiones deseadas, manteniendo una postura estable durante toda la serie.","### Consejos para una forma adecuada","- Mantenga las muñecas apiladas directamente sobre los codos.","- Usar el impulso de las piernas, lo que reduce el compromiso de la parte superior del cuerpo.","- Empezar con las mancuernas demasiado delante, lo que puede tensar los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('141f31c8-c0de-4e80-babe-141f31c80000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/03/Bulgarian-Jump-Squat.gif', '{"Párese frente al banco o dé un paso con los pies separados a la altura de los hombros.","Coloque el pie izquierdo detrás de usted en el banco o escalón, manteniendo el pie derecho apoyado en el suelo.","Salta explosivamente con tu pie derecho, agachándote hasta que tu pierna forme un ángulo de 90 grados.","Baje el cuerpo doblando la rodilla y la cadera derechas, manteniendo el pie izquierdo elevado detrás de usted.","Baje su cuerpo nuevamente a una posición de 90 grados, luego repita el salto durante la cantidad deseada de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('27f3966e-c0de-4e80-babe-27f3966e0000', 'Zancadas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/07/bodyweight-lunges.gif', '{"- Párese erguido con los pies separados a la altura de las caderas.","- Empuja con el talón delantero y activa los músculos de las piernas para volver a la posición inicial.","- Da un gran paso hacia adelante con un pie, asegurándote de que el talón aterrice primero.","- Verifique que su rodilla delantera esté directamente encima de su tobillo, formando un ángulo de 90 grados.","- Evite permitir que la rodilla se extienda más allá de los dedos de los pies para evitar tensiones innecesarias.","- Baje el cuerpo doblando ambas rodillas hasta que el muslo delantero quede paralelo al suelo.","- Permitir que la rodilla delantera se doble hacia adentro: asegúrese de que su rodilla permanezca alineada con su tobillo durante todo el movimiento.","- Principiantes: comience con estocadas estacionarias, donde da un paso hacia adelante pero mantiene el movimiento restringido a un rango de movimiento más pequeño. (ejemplo estocada caminando)","- Intermedio: Progrese a estocadas caminando, donde da un paso adelante y continúa el movimiento alternando las piernas en un movimiento de caminar.","- Mantenga su peso centrado y distribuido uniformemente entre ambas piernas.","- Da un paso adelante con el pie opuesto y repite la estocada en el otro lado.","- Zancada excesiva: Da un paso cómodo hacia adelante, evitando una longitud excesiva que comprometa el equilibrio y la estabilidad.","- Mantenga su núcleo comprometido y los hombros relajados.","- Mantenga la parte superior del cuerpo erguida, con el pecho elevado y la mirada hacia adelante.","- Asegúrese de que la rodilla trasera quede justo por encima del suelo.","- Intente realizar el mismo número de repeticiones en cada pierna para mantener el equilibrio y la simetría.","### Consejos:","- Inclinarse demasiado hacia adelante: Mantenga una postura erguida, con el pecho elevado y los hombros relajados.","- Descuidar la pierna trasera: Mantenga activa la pierna trasera y evite que se desplome hacia el suelo.","### Modificaciones para diferentes niveles de condición física:","- Avanzado: agregue resistencia sosteniendo mancuernas o usando un chaleco con peso mientras realiza estocadas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5f8048a8-c0de-4e80-babe-5f8048a80000', 'Postura de yoga', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/Reverse-Warrior-Viparita-Virabhadrasana.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7c2acbc1-c0de-4e80-babe-7c2acbc10000', 'Postura de yoga', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/Humble-Warrior-Pose.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6b641cf9-c0de-4e80-babe-6b641cf90000', 'Remo con balón medicinal', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2023/05/Backward-Medicine-Ball-Throw.gif', '{"Comience parándose con los pies separados a la altura de los hombros, las rodillas ligeramente dobladas y el core comprometido.","Desde esta posición por encima de la cabeza, lanza con fuerza y ​​explosivamente el balón medicinal hacia atrás.","Extienda los brazos hacia arriba, elevando completamente el balón medicinal por encima de su cabeza.","Mientras lanzas la pelota hacia atrás, deja que tus brazos sigan el movimiento, extendiéndolos completamente.","Mantenga un agarre firme de la pelota y asegúrese de que sus muñecas estén rectas.","Mantenga una postura recta y active los músculos centrales para brindar estabilidad durante el lanzamiento.","Recupere el balón medicinal y repita el ejercicio hasta el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('33514820-c0de-4e80-babe-335148200000', 'Press de pecho con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2023/10/Dumbbell-Push-Press.gif', '{"- Posición inicial: Párese con los pies separados a la altura de los hombros. Sostenga una mancuerna en cada mano, con los brazos doblados en un ángulo de 90 grados y las palmas una frente a la otra. Las mancuernas deben colocarse justo fuera de los hombros. Esta es tu posición inicial.","- Párese con los pies separados a la altura de los hombros.","- Las mancuernas deben colocarse justo por fuera de los hombros. Esta es tu posición inicial.","- Baje las mancuernas: baje las mancuernas a la posición inicial doblando los codos y controlando el descenso. Mantenga una buena forma y control mientras baja las mancuernas.","- Baja las mancuernas hasta la posición inicial doblando los codos y controlando el descenso.","- Utiliza un peso adecuado: Comienza con un peso que te permita realizar el ejercicio con buena técnica. Aumente gradualmente el peso a medida que se fortalezca.","- Sostenga una mancuerna en cada mano, con los brazos doblados en un ángulo de 90 grados y las palmas una frente a la otra.","- Empuja explosivamente hacia arriba con las piernas. Este impulso de las piernas genera la fuerza necesaria para levantar las mancuernas por encima de la cabeza.","- Posición superior: en la parte superior del movimiento, los brazos deben estar completamente extendidos por encima de la cabeza. Las muñecas deben estar apiladas sobre los hombros y las palmas aún deben estar una frente a la otra.","- Sumerge las rodillas: Comience el movimiento doblando ligeramente las rodillas, iniciando una pequeña inmersión.","- Comience el movimiento doblando ligeramente las rodillas, iniciando una pequeña inmersión.","- Empuje explosivo (fase de conducción): Empuja explosivamente hacia arriba con las piernas. Este impulso de las piernas genera la fuerza necesaria para levantar las mancuernas por encima de la cabeza. Simultáneamente, presione las mancuernas directamente sobre los hombros, extendiendo los brazos completamente en la parte superior del movimiento.","- Al mismo tiempo, presione las mancuernas directamente sobre sus hombros, extendiendo los brazos completamente en la parte superior del movimiento.","- En la parte superior del movimiento, los brazos deben estar completamente extendidos por encima de la cabeza.","- Tus muñecas deben estar apiladas sobre tus hombros y tus palmas aún deben estar una frente a la otra.","- Repetir: realice la cantidad deseada de repeticiones, generalmente dentro de un rango de repeticiones específico según sus objetivos de acondicionamiento físico y el peso que está usando.","- Realice la cantidad deseada de repeticiones, generalmente dentro de un rango de repeticiones específico según sus objetivos de acondicionamiento físico y el peso que está usando.","- Mantenga una buena forma y control mientras baja las mancuernas.","### Consejos:","- Asegure la forma adecuada: mantenga un núcleo estable, mantenga la espalda recta y evite arquear o redondear la columna.","- Tempo controlado: mantenga un ritmo controlado y constante durante las fases de ascenso (presionando las mancuernas) y descenso (bajando las mancuernas) del ejercicio. Evite movimientos bruscos.","- Calentamiento: Priorice los ejercicios de calentamiento de hombros y el trabajo de movilidad para preparar sus hombros para las demandas del push press."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2dd5dc46-c0de-4e80-babe-2dd5dc460000', 'Ejercicio', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/Ustrasana.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4f5ef79d-c0de-4e80-babe-4f5ef79d0000', 'Ejercicio', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/Utthita-Trikonasana-Extended-Triangle-Pose.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5cedd09b-c0de-4e80-babe-5cedd09b0000', 'Ejercicio con pesa rusa / kettlebell', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Kettlebell-Hang-Clean.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5b8e90a4-c0de-4e80-babe-5b8e90a40000', 'Ejercicio en máquina', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Ab-Coaster-Machine.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5cecd404-c0de-4e80-babe-5cecd4040000', 'Ejercicio con mancuernas', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Dumbbell-Power-Clean.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('564f4dca-c0de-4e80-babe-564f4dca0000', 'Press de pecho con mancuernas', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Dumbbell-Devil-Press.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2abe14c2-c0de-4e80-babe-2abe14c20000', 'Peso muerto con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/09/dumbbell-sumo-deadlift.gif', '{"Párese con los pies más separados que el ancho de los hombros y los dedos de los pies apuntando ligeramente hacia afuera. La postura más amplia es una característica clave del peso muerto de sumo. Coloque una mancuerna en el suelo entre sus pies. Puede utilizar una o dos mancuernas, según sus preferencias y el peso con el que se sienta cómodo.","Párate con los pies más separados que el ancho de los hombros, con los dedos apuntando ligeramente hacia afuera. La postura más amplia es una característica clave del peso muerto de sumo.","Coloca una mancuerna en el suelo entre tus pies. Puede utilizar una o dos mancuernas, según sus preferencias y el peso con el que se sienta cómodo.","Agarre las mancuernas: doble las caderas y las rodillas para bajar el cuerpo. Mantenga la espalda recta, el pecho erguido y el core comprometido. Sujete las mancuernas con ambas manos con un agarre por encima de la cabeza (con las palmas una frente a la otra) entre las piernas.","Sujete las mancuernas con ambas manos usando un agarre por encima de la cabeza (con las palmas una frente a la otra) entre las piernas.","Configuración: Párese con los pies más separados que el ancho de los hombros y los dedos de los pies apuntando ligeramente hacia afuera. La postura más amplia es una característica clave del peso muerto de sumo. Coloque una mancuerna en el suelo entre sus pies. Puede utilizar una o dos mancuernas, según sus preferencias y el peso con el que se sienta cómodo.","Doble las caderas y las rodillas para bajar el cuerpo. Mantenga la espalda recta, el pecho erguido y el core comprometido.","Finalizar: En la parte superior del movimiento, manténgase erguido con las caderas completamente extendidas y los hombros hacia atrás. Haga una pausa por un momento y luego invierta el movimiento doblando las caderas y las rodillas para bajar las mancuernas al suelo. Controle el descenso para evitar golpear las pesas contra el suelo.","En la parte superior del movimiento, mantente erguido con las caderas completamente extendidas y los hombros hacia atrás.","Controla el descenso para evitar golpear las pesas contra el suelo.","Levantar: Mientras exhala, levántese impulsando los talones, extendiendo las caderas y las rodillas simultáneamente. Mantenga las mancuernas cerca de su cuerpo mientras las levanta. Asegúrese de mantener una columna neutra durante todo el movimiento. No redondees la zona lumbar.","Repetir: Realice el número deseado de repeticiones y luego regrese con cuidado las mancuernas a la posición inicial."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7d9966bc-c0de-4e80-babe-7d9966bc0000', 'Encogimiento de hombros', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/overhead-shrug.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7b0c43d8-c0de-4e80-babe-7b0c43d80000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/overhead-squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0bbcc2b5-c0de-4e80-babe-0bbcc2b50000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/wall-walk-muscles.gif', '{"### Paso 1: Colóquese en una posición de flexión","- Coloque las manos ligeramente más separadas que el ancho de los hombros en una posición de flexión.","### Paso 3: alcanzar la posición de parada de manos","- Regrese a la posición inicial de flexión.","- Los atletas avanzados pueden realizar múltiples series o aumentar el tiempo bajo tensión en la posición de parada de manos.","- Acuéstese boca abajo en el suelo con los pies apoyados en la pared.","### Paso 2: sube los pies por la pared","- Presione con las manos y comience a caminar con los pies por la pared.","- Al mismo tiempo, acerque las manos a la pared.","- Continúe moviéndose hasta que su pecho esté cerca de la pared y sus brazos estén completamente extendidos.","- Mantenga esta posición brevemente mientras mantiene el control.","- Mantenga su núcleo comprometido y las piernas rectas.","- Mantenga una línea corporal recta sin arquear la espalda.","- Mantenga su núcleo apretado y evite que su cuerpo colapse.","### Repeticiones y series","- Los principiantes pueden comenzar con tres a cinco repeticiones con control total.","### Paso 4: caminar de regreso hacia abajo","- Aleje lentamente las manos de la pared mientras baja los pies al suelo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('076913b3-c0de-4e80-babe-076913b30000', 'Ejercicio con barra', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/03/Barbell-Glute-Bridge-Two-Legs-on-Bench.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2b7c3816-c0de-4e80-babe-2b7c38160000', 'Ejercicio', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/zercher-carry.gif', '{"- Coloque una barra en una rejilla para sentadillas a la altura de la cintura.","- Camine hacia adelante con pasos pequeños y controlados, manteniéndose erguido y evitando inclinarse hacia atrás o curvar la columna.","- Continúe caminando durante una distancia o tiempo determinados, luego baje la barra con cuidado hacia el estante o sobre las almohadillas.","- Aprieta tu núcleo con fuerza antes de cada paso.","- Utilice una toalla o almohadilla si es necesario para reducir la presión sobre los codos.","- Levante la barra manteniéndose erguido, apuntalando su núcleo y manteniendo su pecho alto.","- Comience ligero para concentrarse en la forma antes de progresar con la carga.","### Errores comunes","- Dejar que la barra se hunda relajando el núcleo o la parte superior de la espalda.","- Inclinarse excesivamente hacia atrás, ejerciendo presión sobre la columna lumbar.","- Sube a la barra, dobla los brazos y coloca la barra en la curva de los codos. Mantenga los puños juntos y los codos debajo de la barra.","### Consejos para una forma adecuada","- Mantenga los codos doblados y pegados al cuerpo durante toda la caminata.","- Mantenga una postura erguida, evitando inclinarse hacia atrás para compensar la carga.","- Descuidar la respiración, lo que reduce la tensión central y el control.","- Mantener la barra demasiado baja, lo que puede alterar el equilibrio y estresar los hombros.","- Zancadas excesivas, lo que hace que la caminata sea inestable e ineficiente."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6ac9f741-c0de-4e80-babe-6ac9f7410000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Riding-Outdoor-Bicycle.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4613fc45-c0de-4e80-babe-4613fc450000', 'Peso muerto con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/09/dumbbell-deadlifts.gif', '{"Párese con los pies separados a la altura de las caderas. Coloque una mancuerna a cada lado de sus pies. Las mancuernas deben colocarse paralelas a sus pies, de modo que las manijas queden perpendiculares a su cuerpo.","Párese con los pies separados a la altura de las caderas. Coloca una mancuerna a cada lado de tus pies.","Postura: Doble las caderas y las rodillas para bajar. Mantenga la espalda recta, el pecho hacia arriba y los hombros hacia atrás. Sujete las mancuernas con un agarre firme, con las palmas hacia el cuerpo. Tus manos deben estar justo fuera de tus rodillas.","Configuración: Párese con los pies separados a la altura de las caderas. Coloque una mancuerna a cada lado de sus pies. Las mancuernas deben colocarse paralelas a sus pies, de modo que las manijas queden perpendiculares a su cuerpo.","Las mancuernas deben colocarse paralelas a tus pies, de modo que los mangos queden perpendiculares a tu cuerpo.","Empuja con los talones y levanta las mancuernas enderezando las caderas y las rodillas.","Levantamiento: Empuje con los talones y levante las mancuernas enderezando las caderas y las rodillas. Mantenga una columna neutra durante todo el movimiento. No doble la espalda. Mantenga las mancuernas cerca de su cuerpo mientras las levanta. Párese completamente erguido con el pecho hacia afuera y los hombros hacia atrás.","Invierta el movimiento empujando primero las caderas hacia atrás y luego doblando las rodillas para bajar las mancuernas al suelo.","Repetición: repita el levantamiento durante el número deseado de repeticiones. Exhale mientras levanta las mancuernas e inhale mientras las baja.","Exhala mientras levantas las mancuernas e inhala mientras las bajas.","Mantenga la columna neutra durante todo el movimiento. No redondees tu espalda.","Bajar: invierta el movimiento empujando primero las caderas hacia atrás y luego doblando las rodillas para bajar las mancuernas al suelo. Mantenga las mancuernas cerca de su cuerpo y mantenga una buena forma.","Repita el levantamiento durante el número deseado de repeticiones.","Mantén las mancuernas cerca de tu cuerpo y mantén una buena forma."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0de5ed63-c0de-4e80-babe-0de5ed630000', 'Ejercicio', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Log-Lift.gif', '{"- Párese con los pies separados al ancho de los hombros y coloque las manos sobre el tronco o la barra, manteniendo el agarre separado al ancho de los hombros.","- Una vez que el tronco esté sobre su hombro, sosténgalo firmemente, manteniendo el codo cerca del costado y manténgase de pie.","- Mantenga la espalda recta, doble las rodillas y levante el tronco, llevándolo hasta la cintura.","- Haga una pausa de unos segundos y luego baje el tronco hasta la cintura, manteniendo el control del peso durante todo el movimiento.","- Con el tronco apoyado sobre su cintura, respire profundamente, apriete su núcleo y use sus piernas para empujar hacia arriba, levantando el tronco hasta su hombro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2ef0b844-c0de-4e80-babe-2ef0b8440000', 'Ejercicio', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Tire-SledgeHammer.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1777c307-c0de-4e80-babe-1777c3070000', 'Ejercicio con barra', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Barbell-Snatch.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('22ac580c-c0de-4e80-babe-22ac580c0000', 'Ejercicio', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Barbell-Muscle-Snatch.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('167d14df-c0de-4e80-babe-167d14df0000', 'Ejercicio', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Barbell-Heaving-Snatch-Balance.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1902a889-c0de-4e80-babe-1902a8890000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Cross-Crunch.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3726258e-c0de-4e80-babe-3726258e0000', 'Elevaciones laterales', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/arm-circles.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4c672814-c0de-4e80-babe-4c6728140000', 'Ejercicio', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Ski-Ergometer.gif', '{"Párese frente a la máquina con los pies separados a la altura de los hombros. Agarre las manijas firmemente con ambas manos.","Recuperación: Regresar las manijas suavemente a la posición inicial, manteniendo el ritmo y el control.","Posición inicial: Párese frente a la máquina con los pies separados a la altura de los hombros. Agarre las manijas firmemente con ambas manos.","Movimiento de tracción: mueva las manijas hacia abajo con un movimiento fuerte usando dorsales, hombros, tríceps y core. Doble ligeramente las rodillas y active la parte inferior del cuerpo para generar más potencia.","Finalizar: Extienda los brazos completamente hacia abajo cerca de los muslos mientras mantiene la postura erguida y controlada.","Involucre el núcleo y las caderas: incline ligeramente las caderas, mantenga las rodillas suaves y active los músculos centrales."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2eb399fa-c0de-4e80-babe-2eb399fa0000', 'Ejercicio unilateral en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/11/One-arm-triceps-pushdown.gif', '{"- Configure el equipo Coloque una manija única en la polea alta de una máquina de cable. Seleccione un peso apropiado que permita un movimiento controlado.","- Conecte una sola manija a la polea alta de una máquina de cable.","- ColóquesePárate con los pies separados al ancho de los hombros para mantener el equilibrio.Agarra el mango con un agarre por encima de la cabeza (con la palma hacia abajo).Mantén el codo cerca del torso y mantén las rodillas ligeramente dobladas.","- Párese con los pies separados a la altura de los hombros para mantener el equilibrio.","- Agarre el mango con la palma hacia abajo.","- Inhala mientras regresas lentamente a la posición inicial con control.","- Ajuste el peso en consecuencia para mantener la forma adecuada durante toda la serie.","- Usar demasiado peso, lo que puede provocar una forma inadecuada y una reducción de la activación del tríceps.","- Seleccione un peso apropiado que permita un movimiento controlado.","- Haga una breve pausa en la parte inferior para maximizar la participación de los tríceps.","- Repetir Realice el número deseado de repeticiones antes de cambiar de brazo.","- Realice el número deseado de repeticiones antes de cambiar de brazo.","- EjecuciónExhale mientras empuja el mango hacia abajo extendiendo el codo por completo. Mantenga la muñeca en posición neutral y evite doblarla durante el movimiento. Baje el mango hasta que su brazo esté completamente extendido pero no bloqueado. Haga una breve pausa en la parte inferior para maximizar el compromiso de los tríceps. Inhale mientras regresa lentamente a la posición inicial con control.","- Exhale mientras empuja el mango hacia abajo extendiendo el codo por completo.","- Baje la manija hasta que su brazo esté completamente extendido pero no bloqueado.","- Utilice un movimiento controlado en lugar de depender del impulso.","- Dejar que el codo se desplace hacia adelante o hacia afuera, reduciendo la efectividad del ejercicio.","- Involucre sus músculos centrales para estabilizar su cuerpo.","### Errores comunes a evitar","- Depender del impulso en lugar del compromiso muscular controlado.","- Mantenga el codo cerca del torso y mantenga las rodillas ligeramente dobladas.","- Mantenga la muñeca neutral y evite doblarla durante el movimiento.","### Consejos para una forma adecuada","- Mantenga una columna neutra y evite inclinarse hacia adelante o hacia atrás.","- Mantenga el codo inmóvil para asegurarse de que los tríceps hagan el trabajo.","- Doblar excesivamente la muñeca, lo que puede provocar tensión y reducir la eficiencia.","- No extender completamente el codo, limitando la activación del tríceps."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0dc72354-c0de-4e80-babe-0dc723540000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Walking.gif', '{"Caminar es una de las actividades físicas más sencillas. Esta sencilla actividad te permite trabajar muchos grupos de músculos grandes y pequeños de la parte inferior del cuerpo. Además, caminar consume algo de energía y, si tu objetivo es quemar calorías, puedes crear un mayor déficit calórico caminando junto con tu dieta nutricional."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('34405161-c0de-4e80-babe-344051610000', 'Ejercicio', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Arm-Scissors.gif', '{"Párese erguido con los pies separados a la altura de las caderas.","Posición inicial: Párese erguido con los pies separados a la altura de las caderas.","Extienda los brazos: Estire los brazos hacia los lados a la altura de los hombros.","Cruzar: balancee los brazos sobre el pecho, superponiendo uno sobre el otro como si fueran tijeras.","Regresar y repetir: abra los brazos hacia los lados y repita durante 15-20 repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4158462e-c0de-4e80-babe-4158462e0000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Briskly-Walking.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('606e8faf-c0de-4e80-babe-606e8faf0000', 'Ejercicio sentado', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Seated-Bench-Leg-Pull-in.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4ba78925-c0de-4e80-babe-4ba789250000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Lying-Weighted-Lateral-Neck-Flexion.gif', '{"Sujete firmemente el arnés para la cabeza a su cabeza y sujete una placa de pesas.","Acuéstese de costado en un banco inclinado con la cabeza extendida hacia el extremo.","Baje la placa de pesas suspendida por el arnés para la cabeza sobre el suelo.","Baje la cabeza hasta que sienta un leve estiramiento en el lado opuesto del cuello."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('694ada07-c0de-4e80-babe-694ada070000', 'Ejercicio con barra', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Barbell-Hang-Clean.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3562fde6-c0de-4e80-babe-3562fde60000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2023/06/sprint.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('50be7ea7-c0de-4e80-babe-50be7ea70000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/07/Run.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6ddee741-c0de-4e80-babe-6ddee7410000', 'Ejercicio de pie en polea', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Standing-Cable-Crunch.gif', '{"Coloque la máquina de cable en una posición alta y sujete una cuerda o mango al cable.","Párese de espaldas a la máquina con los pies separados a la altura de los hombros.","Agarre la cuerda o el asa con ambas manos, colocándolas cerca de las orejas o las sienes.","Aléjese uno o dos pasos de la máquina para crear tensión en el cable.","Regrese lentamente a la posición inicial extendiendo el torso hacia arriba, permitiendo que los brazos se extiendan por completo.","Colóquese de modo que sus codos apunten hacia los lados y la parte superior de su cuerpo esté erguida.","Inicie el movimiento doblándose por la cintura y llevando los codos y la cabeza hacia abajo, hacia las rodillas.","Mantenga la posición de abdominales brevemente, apretando los abdominales.","Mientras haces abdominales, concéntrate en contraer los músculos abdominales y exhalar.","Repita hasta el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3d86271c-c0de-4e80-babe-3d86271c0000', 'Press de hombros en máquina', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Smith-Machine-Shoulder-Press.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0dd965e3-c0de-4e80-babe-0dd965e30000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Cross-Body-Mountain-Climber.gif', '{"Comience en una posición de tabla alta con las manos directamente debajo de los hombros y el cuerpo formando una línea recta desde la cabeza hasta los talones.","Mientras acercas la rodilla, involucra tu core y mantén una posición de tabla fuerte.","Extiende tu pierna derecha hacia la posición inicial mientras repites simultáneamente el movimiento en el otro lado.","Involucre sus músculos centrales llevando su ombligo hacia su columna y manteniendo un núcleo estable durante todo el ejercicio.","Levanta el pie derecho del suelo y lleva la rodilla derecha hacia el codo izquierdo, cruzando el cuerpo en diagonal.","Levanta el pie izquierdo del suelo y lleva la rodilla izquierda hacia el codo derecho, cruzando el cuerpo en diagonal.","Repita durante la cantidad deseada de repeticiones o siga un período de tiempo establecido para su entrenamiento."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('31b19ac3-c0de-4e80-babe-31b19ac30000', 'Elevaciones laterales con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dumbbell-Lateral-Raise.gif', '{"- Posición inicial: Párese erguido con los pies separados a la altura de los hombros, sosteniendo las mancuernas a los costados con las palmas hacia adentro.","- Retorno controlado: baje las pesas lenta y suavemente hasta la posición inicial mientras mantiene el control y la tensión en los hombros.","- Levantar demasiado peso: elegir pesas pesadas a menudo resulta en una mala forma y un uso excesivo del impulso, lo que reduce la efectividad y aumenta el riesgo de lesiones.","###","- Prepárese y alinee: active los músculos centrales y doble ligeramente las rodillas para mantener la estabilidad.","- Movimiento: Levante las mancuernas hacia los costados, manteniendo una ligera flexión de los codos y las muñecas rectas. Levanta las mancuernas hasta que tus brazos lleguen al nivel de los hombros, paralelos al suelo.","- No se balancee ni utilice el impulso; Levante pesas lentamente y con movimientos controlados.","- Mantenga su núcleo comprometido y la columna neutral durante todo el movimiento.","- Concéntrese en levantar los codos en lugar de las muñecas para enfatizar la activación del deltoides.","- Repetir: continúe durante la cantidad deseada de repeticiones, generalmente de 10 a 12 repeticiones.","### Consejos para una forma adecuada:","- Mantenga los codos ligeramente doblados para evitar tensión en las articulaciones.","- Levantar mancuernas demasiado alto: evite levantar mancuernas por encima del nivel de los hombros para evitar tensiones innecesarias en las articulaciones de los hombros.","- Flexión excesiva del codo: Demasiada flexión de los codos reduce la carga de trabajo en los hombros y desplaza la tensión a otros lugares. Mantenga sólo una ligera curvatura.","### Errores comunes:"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3c3ea5fe-c0de-4e80-babe-3c3ea5fe0000', 'Ejercicio', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/07/Arm-Circles_Shoulders.gif', '{"Párese erguido con los pies separados a la altura de las caderas y los brazos extendidos a los lados a la altura de los hombros.","Comience a hacer pequeños círculos hacia adelante con los brazos, aumentando gradualmente el tamaño.","Realice durante 20 a 30 segundos, luego invierta la dirección durante el mismo período.","Baja los brazos y sacúdelos después de completar ambas direcciones.","Involucre su núcleo y mantenga su columna neutral para mantener una buena postura."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('04a5904b-c0de-4e80-babe-04a5904b0000', 'Press de hombros con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dumbbell-Shoulder-Press.gif', '{"- Posición inicial: Siéntese en un banco con respaldo o párese con los pies separados a la altura de las caderas. Sostenga una mancuerna en cada mano a la altura de los hombros con las palmas hacia adelante o ligeramente hacia adentro.","###","- Prepárese y alinee: active su núcleo, mantenga la columna neutral y retraiga los omóplatos ligeramente.","- Presione sobre la cabeza: presione las mancuernas hacia arriba y ligeramente hacia adentro hasta que sus brazos estén completamente extendidos sin bloquear los codos.","- Baja bajo control: baja lentamente las mancuernas hasta la altura de los hombros manteniendo el control y la tensión.","- Presione formando un ligero arco en lugar de hacerlo directamente sobre la cabeza para mayor comodidad en las articulaciones.","### Errores comunes","- Inclinarse hacia atrás excesivamente y convertir el press en un press de pecho inclinado.","### Consejos para una forma adecuada","- Mantenga sus muñecas neutrales y alineadas con sus antebrazos.","- Evite arquear demasiado la zona lumbar; refuerce el núcleo para mantener la integridad de la columna.","- Usar el impulso para “rebotar” las mancuernas sobre tu cabeza.","- Ensanchar demasiado los codos, estresando las articulaciones de los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('721acd70-c0de-4e80-babe-721acd700000', 'Elevaciones laterales en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/07/one-arm-Cable-Lateral-Raise.gif', '{"- Para comenzar: párese junto a una máquina de cable con la polea en la posición más baja. Agarre el mango del lado opuesto con la mano más alejada de la polea, manteniendo la palma hacia adentro.","- Utilice un peso más ligero con un ritmo controlado para evitar el impulso.","- Usar peso excesivo, lo que lleva a balancearse o a tener mala forma.","###","- Levante el peso: levante el brazo hacia un lado hasta que el codo alcance la altura del hombro, manteniendo la muñeca alineada con el codo.","- Dirija el movimiento con el codo, no con la mano, para activar el deltoides lateral.","### Errores comunes","- Doblar demasiado el codo y convertir la elevación en una elevación frontal.","- Establece tu postura: mantén el core comprometido, el pecho elevado y los hombros relajados. Mantenga una ligera flexión del codo durante todo el levantamiento.","- Pausa y baja: haz una breve pausa en la parte superior, luego baja lentamente la manija hacia tu costado con control. Repita para las repeticiones deseadas.","### Consejos para una forma adecuada","- Mantenga los trapecios relajados y evite encogerse de hombros mientras levanta.","- Encogerse de hombros y activar los trapecios superiores en lugar de aislar los deltoides."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('555782e1-c0de-4e80-babe-555782e10000', 'Ejercicio en máquina', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Walk-Wave-Machine.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('77544117-c0de-4e80-babe-775441170000', 'Ejercicio acostado', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Weighted-Lying-Neck-Flexion.gif', '{"Configure su equipo: Utilice un arnés para el cuello diseñado para levantamiento de pesas. Conecte de forma segura una pequeña placa de pesas a la cadena del arnés. Asegúrese de que el arnés se ajuste cómodamente alrededor de su cabeza sin causar molestias.","Prepare el banco: Coloque un banco de ejercicios con una inclinación de 45 grados. Siéntese en el banco e inclínese hacia atrás para que la parte superior de su espalda quede apoyada mientras su cabeza se extiende más allá del borde del banco.","Coloque el arnés para el cuello en su cabeza, asegurándose de que esté centrado. Deje que su cabeza cuelgue ligeramente hacia atrás en una posición neutral.","Posición inicial: Coloque el arnés para el cuello en su cabeza, asegurándose de que esté centrado. Deje que su cabeza cuelgue ligeramente hacia atrás en una posición neutral.","Ejecute el movimiento: Flexione el cuello hacia adelante, llevando la barbilla hacia el pecho en un movimiento lento y controlado. Haga una breve pausa en la parte superior del movimiento para contraer completamente los músculos del cuello. Regrese lentamente la cabeza a la posición inicial, resistiendo el peso a medida que baja.","Flexiona el cuello hacia adelante, llevando la barbilla hacia el pecho con un movimiento lento y controlado.","Haga una pausa breve en la parte superior del movimiento para contraer completamente los músculos del cuello.","Repeticiones: realice de 2 a 4 series de 8 a 15 repeticiones según su nivel de condición física y sus objetivos.","realice de 2 a 4 series de 8 a 15 repeticiones según su nivel de condición física y sus objetivos.","Realice de 2 a 4 series de 8 a 15 repeticiones según su nivel de condición física y sus objetivos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('13ce3729-c0de-4e80-babe-13ce37290000', 'Remo inclinado con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/45-Degree-Incline-Row.gif', '{"- Posición inicial: ajuste un banco inclinado a un ángulo de 45 grados. Acuéstese boca abajo en el banco con el pecho firmemente presionado contra él. Sostenga las mancuernas con los brazos extendidos directamente debajo de los hombros, con las palmas hacia adentro.","- Descenso controlado: Baja lentamente las mancuernas hasta la posición inicial, extendiendo completamente los brazos sin liberar la tensión de los hombros.","- Utilice un peso manejable para garantizar la técnica y la activación muscular adecuadas.","- Levantar demasiado peso: el peso excesivo genera impulso, mala forma y activación muscular reducida.","###","- Alineación y agarre: Mantenga el cuello neutral, la columna alineada y el núcleo ligeramente enganchado para estabilizar el cuerpo.","- Repetir: complete de 8 a 12 repeticiones controladas por serie, concentrándose en movimientos suaves y deliberados.","- Movimiento de tracción: tire de las mancuernas hacia arriba, doblando los codos y retrayendo los omóplatos, levantándolas hasta que los codos se alineen con el torso o ligeramente más arriba.","- Enganche los omóplatos apretándolos en la parte superior del movimiento.","- Redondear los hombros: Permitir que los hombros se doblen hacia adelante puede comprometer la postura y reducir la efectividad.","- Rango de movimiento incompleto: no contraer completamente los músculos de la espalda limita el desarrollo muscular potencial.","- Evite el impulso excesivo o el balanceo; levantar pesas con movimiento controlado.","- Mantenga una posición neutral del cuello y la columna en todo momento.","### Consejos para una forma adecuada:","### Errores comunes:"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0e38f6fc-c0de-4e80-babe-0e38f6fc0000', 'Press de pecho en máquina', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Smith-Machine-Behind-Neck-Press.gif', '{"- Posición inicial: siéntese en un banco vertical o párese dentro de la máquina Smith, colocándose de modo que la barra descanse detrás de su cabeza, justo por encima de la altura de los hombros.","- Agarre y postura: Sujete la barra con un agarre por encima de la cabeza ligeramente más ancho que el ancho de los hombros. Involucre su núcleo y mantenga el torso erguido.","- Peso excesivo: usar una carga demasiado pesada puede tensar las articulaciones de los hombros y provocar lesiones.","- Evite el uso de pesos excesivamente pesados ​​para mantener la seguridad de los hombros.","- Asegúrese de que la barra se desplace verticalmente a lo largo de los rieles de la máquina Smith.","- Movimiento de presión: Empuja la barra hacia arriba extendiendo completamente los brazos, manteniendo la cabeza ligeramente hacia adelante para evitar el contacto.","- Descenso controlado: baje lentamente la barra detrás del cuello hasta que los codos formen un ángulo de aproximadamente 90 grados, manteniendo la tensión controlada en los hombros.","- Realice siempre este ejercicio de forma lenta y bajo control.","- Ruta de barra incorrecta: Permitir que la barra se desplace hacia adelante o hacia atrás fuera de la ruta guiada aumenta el riesgo de lesiones.","- Movimiento rápido: realizar el ejercicio demasiado rápido reduce la activación muscular y aumenta el potencial de lesiones.","### Errores comunes:","- Repetir: complete las repeticiones deseadas, generalmente de 8 a 12 repeticiones por serie.","### Consejos para una forma adecuada:","- Mantenga el núcleo tenso y la columna neutra para garantizar la estabilidad."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4c6b387c-c0de-4e80-babe-4c6b387c0000', 'Curl de muñeca sentado con mancuernas', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Dumbbell-Seated-Neutral-Wrist-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2f389434-c0de-4e80-babe-2f3894340000', 'Press de hombros de pie', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Standing-Barbell-Close-Grip-Military-Press.gif', '{"Párese con los pies separados a la altura de los hombros.","Agarre la barra con un agarre ligeramente más estrecho que el ancho de los hombros. Las palmas de las manos deben mirar hacia adelante y los codos deben estar ligeramente por delante de la barra.","Levante la barra del soporte o límpiela hasta el nivel de los hombros y manténgala allí con la parte superior de los brazos paralela al suelo. Esta es tu posición inicial.","Haga una breve pausa en la parte superior y luego baje lentamente la barra a la posición inicial doblando los codos y bajándola bajo control.","Respire profundamente, refuerce su núcleo y active sus glúteos para lograr estabilidad.","Presione la barra hacia arriba de manera controlada extendiendo los brazos por encima de la cabeza. Mantenga los codos apuntando hacia adelante y las muñecas en posición neutral.","Continúe presionando hasta que sus brazos estén completamente extendidos y la barra esté directamente sobre su cabeza. Asegúrese de mantener la forma adecuada y evite arquear excesivamente la zona lumbar.","Repita hasta el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1b3b1a69-c0de-4e80-babe-1b3b1a690000', 'Curl de muñeca con barra', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Barbell-Reverse-Wrist-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('34a7e022-c0de-4e80-babe-34a7e0220000', 'Press de hombros', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Lever-Shoulder-Press.gif', '{"- Posición inicial: Siéntese erguido en la máquina de prensa de hombros con palanca, asegurándose de que su espalda esté firmemente contra la almohadilla. Ajuste la altura del asiento de modo que las manijas queden al nivel de los hombros.","- Agarre y alineación: Sujete las manijas de la máquina con un agarre por encima de la cabeza. Tus brazos deben estar hacia los lados, mirando hacia adelante, con los codos colocados directamente debajo de tus manos.","- Elija un peso manejable para mantener el control y la técnica adecuada.","- Uso de peso excesivo: demasiado peso a menudo resulta en una mala forma y un mayor riesgo de lesiones.","- Movimiento de presión: presione las manijas hacia arriba extendiendo los codos completamente, empujando a través de los hombros hasta que los brazos queden rectos por encima de la cabeza, pero evite bloquear los codos por completo.","- Evite bloquear los codos completamente en la posición superior para mantener la tensión y proteger las articulaciones.","- Descenso controlado: baje lentamente las manijas hasta el nivel de los hombros, manteniendo el control y la tensión durante todo el movimiento.","- Repetir: realice el ejercicio de 8 a 12 repeticiones por serie, asegurando movimientos suaves y controlados.","- Exhale durante el movimiento de presión hacia arriba e inhale durante la fase de descenso.","- Rango de movimiento parcial: no extender o bajar completamente los mangos limita la activación muscular y la efectividad general.","### Errores comunes:","### Consejos para una forma adecuada:","- Mantenga la espalda plana contra la almohadilla durante todo el ejercicio.","- Arquear la espalda: El arqueamiento excesivo de la espalda puede provocar tensión en la zona lumbar; mantenga la alineación adecuada involucrando su núcleo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1403836f-c0de-4e80-babe-1403836f0000', 'Extensión de tríceps acostado', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Weighted-Lying-Neck-Extension.gif', '{"Configure su equipo: use un arnés para el cuello con un accesorio de cadena para pesas. Coloque una pequeña placa de pesas en la cadena, asegurándose de que esté segura.","Coloque una pequeña placa de peso en la cadena, asegurándose de que esté segura.","Ajuste el banco: coloque un banco inclinado en un ángulo de 45 grados. Este ángulo permite que su cabeza se mueva libremente durante el ejercicio mientras mantiene su cuerpo apoyado.","Coloque un banco inclinado en un ángulo de 45 grados.","Póngase en posición: Acuéstese boca abajo en el banco inclinado con el pecho y el abdomen apoyados. Deje que su cabeza se extienda más allá del borde superior del banco. Coloque el arnés para el cuello sobre su cabeza, ajustándolo para que quede ceñido y cómodo.","Coloque el arnés para el cuello en su cabeza, ajustándolo para que quede ceñido y cómodo.","permita que la cabeza cuelgue ligeramente hacia adelante, dejando que el peso cree un estiramiento natural en la parte posterior del cuello. Mantenga el cuerpo quieto, con las manos agarrando los lados del banco para mayor estabilidad.","Deje que su cabeza cuelgue ligeramente hacia adelante, dejando que el peso cree un estiramiento natural en la parte posterior de su cuello.","Regreso a la posición inicial: Baje la cabeza hacia la posición inicial de manera lenta y controlada, resistiendo el tirón del peso.","Utilice un arnés para el cuello con una cadena para colocar pesas.","Posición inicial: permita que la cabeza cuelgue ligeramente hacia adelante, dejando que el peso cree un estiramiento natural en la parte posterior del cuello. Mantenga el cuerpo quieto, con las manos agarrando los lados del banco para mayor estabilidad.","Realice el movimiento: Extienda lentamente el cuello hacia arriba, levantando la cabeza y el peso adjunto. Continúe el movimiento hasta que la cabeza esté alineada con la parte superior de la espalda (evite extender demasiado). Haga una breve pausa en la parte superior para contraer completamente los músculos del cuello.","Continúe el movimiento hasta que su cabeza esté alineada con la parte superior de su espalda (evite extenderse demasiado).","Repeticiones y series: realice de 8 a 15 repeticiones por serie. Complete de 2 a 4 series, ajustándolas según su nivel de condición física y sus objetivos.","Realice de 8 a 15 repeticiones por serie."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5a483296-c0de-4e80-babe-5a4832960000', 'Press de hombros con barra', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/07/Barbell-Standing-Military-Press.gif', '{"Trapecio: El trapecio superior, que corre a lo largo de la parte superior de la espalda y el cuello, participa en la estabilización y el soporte de la cintura escapular durante el movimiento.","Romboides: Los romboides, ubicados entre los omóplatos, ayudan a retraer y estabilizar las escápulas durante el ejercicio.","Deltoides (hombros): el press militar con barra se dirige principalmente a la cabeza anterior (frontal) de los deltoides. Al realizar el ejercicio, el movimiento implica presionar la barra sobre la cabeza en un plano vertical, lo que enfatiza la activación de los deltoides anteriores. Sin embargo, es importante tener en cuenta que las cabezas lateral (lateral) y posterior (trasera) de los deltoides también contribuyen al movimiento como músculos secundarios, proporcionando estabilidad y asistencia. Si bien los deltoides anteriores son el foco principal, el press militar con barra involucra las tres cabezas de los deltoides en diversos grados.(1)","Tríceps braquial: los músculos tríceps ubicados en la parte posterior de la parte superior del brazo ayudan a extender el codo durante el movimiento de presión.","Músculos centrales: los músculos del núcleo, incluidos los abdominales y los oblicuos, desempeñan un papel en la estabilización del tronco y el mantenimiento de una postura adecuada durante todo el movimiento.","Serrato Anterior: Los músculos serrato anterior, ubicados a los lados de la caja torácica, ayudan a estabilizar y prolongar las escápulas durante la fase ascendente del ejercicio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1f356965-c0de-4e80-babe-1f3569650000', 'Estiramiento', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Side-Neck-Stretch.gif', '{"Los estiramientos de cuello también participan en la fisioterapia que tiene como objetivo rehabilitar los músculos, las articulaciones y los huesos del cuello. Los estiramientos de cuello tienen como objetivo aumentar la fuerza, el tono y la flexibilidad de los músculos del cuello. También permite que los ligamentos de las articulaciones del cuello se vuelvan más flexibles y resistan una mayor tensión en el área.","Cuando la cabeza y los hombros se inclinan hacia adelante debido a una mala postura, algunos músculos del pecho y el cuello pueden acortarse y tensarse con el tiempo, lo que puede perpetuar la mala postura que causa el dolor de cuello. Los ejercicios de estiramiento del cuello pueden ayudar a relajar los músculos posturales y reducir el dolor de cuello."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4c310995-c0de-4e80-babe-4c3109950000', 'Ejercicio', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Chin-Tuck.gif', '{"Los estiramientos de cuello también participan en la fisioterapia que tiene como objetivo rehabilitar los músculos, las articulaciones y los huesos del cuello. Los estiramientos de cuello tienen como objetivo aumentar la fuerza, el tono y la flexibilidad de los músculos del cuello. También permite que los ligamentos de las articulaciones del cuello se vuelvan más flexibles y resistan una mayor tensión en el área.","Cuando la cabeza y los hombros se inclinan hacia adelante debido a una mala postura, algunos músculos del pecho y el cuello pueden acortarse y tensarse con el tiempo, lo que puede perpetuar la mala postura que causa el dolor de cuello. Los ejercicios de estiramiento del cuello pueden ayudar a relajar los músculos posturales y reducir el dolor de cuello."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5512dea9-c0de-4e80-babe-5512dea90000', 'Estiramiento', 'Hombros', '', '{"Regrese lentamente la cabeza a la posición neutral y repita el estiramiento en el otro lado.","Gira el cuello en diagonal hacia el lado derecho en un ángulo de 45 grados.","Incline lentamente la cabeza hacia el pecho mientras mantiene la rotación lateral.","Deberías sentir un ligero estiramiento en el costado y la parte posterior del cuello.","Mantenga esta posición durante 15 a 30 segundos mientras mantiene una respiración constante y relajada.","Apunta a 2-4 repeticiones por lado."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7f256408-c0de-4e80-babe-7f2564080000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Assault-Air-Runner.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('761975a4-c0de-4e80-babe-761975a40000', 'Ejercicio en máquina', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Elliptical-Machine.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('489efc47-c0de-4e80-babe-489efc470000', 'Estiramiento', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Front-and-Back-Neck-Stretch.gif', '{"Mantén la posición durante 10-15 segundos y regresa a la posición inicial y luego inclina la cabeza hacia adelante para revertir el movimiento, juntando las manos detrás de la cabeza para sostenerlas. Haga esto de 3 a 4 veces.","Mantenga la cabeza en una posición neutral en todo momento.","Inclina la cabeza hacia atrás lo más que puedas.","Entrelaza tus dedos y coloca tus manos sobre tu frente.","Intenta llevar lentamente la cabeza hacia adelante como si intentaras tocar tu pecho con la barbilla y resiste con las manos y los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7fa33fa7-c0de-4e80-babe-7fa33fa70000', 'Ejercicio inclinado', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Incline-Treadmill.gif', '{"Comience calentando con 3 a 5 minutos de caminata plana.","Aumente gradualmente la inclinación entre un 5 y un 12 por ciento, dependiendo de su nivel de condición física.","Utilice la inclinación durante 15 a 30 minutos, luego bájela y enfríe durante 3 a 5 minutos.","Mantenga un ritmo constante al caminar o trote ligero mientras mantiene la postura erguida.","Evite inclinarse hacia adelante y deje que sus glúteos e isquiotibiales hagan el trabajo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('28ccdbd2-c0de-4e80-babe-28ccdbd20000', 'Salto de cuerda', 'Cardio', '', '{"Sujete los mangos de la cuerda en cada mano con los codos cerca del cuerpo.","Coloque la cuerda detrás de sus talones.","Mantenga las rodillas ligeramente flexionadas y el abdomen firme.","Mueva las muñecas en círculos para pasar la cuerda por encima de su cabeza.","Salte ligeramente sobre la cuerda apoyando la parte delantera de los pies.","Mantenga los saltos bajos y el ritmo constante.","Salte con la punta de los pies para absorber el impacto adecuadamente.","No levante demasiado las piernas para no cansarse prematuramente."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('159c79cd-c0de-4e80-babe-159c79cd0000', 'Elevación con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Dumbbell-6-Ways-Raise.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7b17925a-c0de-4e80-babe-7b17925a0000', 'Extensión de tríceps', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Prone-Cervical-Extension.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('78bc98ca-c0de-4e80-babe-78bc98ca0000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Treadmill-.gif', '{"Ajuste la inclinación según sea necesario para simular colinas y aumentar la intensidad.","Súbase a la caminadora con el cinturón estacionario. Enganche la llave de seguridad.","Comience con un calentamiento caminando a ritmo lento durante 3 a 5 minutos.","Aumente la velocidad al ritmo deseado para caminar, trotar o correr.","Mantenga una postura erguida y balancee los brazos de forma natural.","Enfríe reduciendo gradualmente la velocidad durante los últimos 3 a 5 minutos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('20b3ea74-c0de-4e80-babe-20b3ea740000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Bike.gif', '{"Siéntese erguido con un agarre firme en el manillar y los pies firmemente en los pedales.","Ajuste la altura del asiento para que la rodilla se doble ligeramente en la parte inferior del pedaleo.","Empiece a pedalear lentamente para calentar músculos y articulaciones.","Aumente la resistencia o la velocidad según sea necesario, según su tipo de entrenamiento.","Mantenga una respiración y una postura constantes mientras conduce.","Enfríe bajando la resistencia y pedaleando suavemente durante 3 a 5 minutos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4d7afdd0-c0de-4e80-babe-4d7afdd00000', 'Estiramiento de rodillas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Kneeling-Neck-Stretch.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0da9a0e5-c0de-4e80-babe-0da9a0e50000', 'Elevaciones laterales con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Dumbbell-Chest-Supported-Lateral-Raises.gif', '{"La posición del ángulo que establezca en este ejercicio es importante porque si baja la inclinación, el enfoque estará completamente en los músculos deltoides posteriores, y si eleva la inclinación completamente, el objetivo estará en los músculos deltoides laterales. Se recomienda ajustar la inclinación según el grupo de músculos que quieras enfatizar en este ejercicio.","La elevación lateral con apoyo del pecho es un ejercicio de fortalecimiento de los hombros que se dirige a los deltoides laterales y posteriores. Además, debido a la posición del movimiento, permite trabajar los músculos trapecios."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0fce54ea-c0de-4e80-babe-0fce54ea0000', 'Ejercicio en máquina', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Walking-on-Stepmill.gif', '{"Suba con cuidado a la máquina, comenzando con la velocidad más baja.","Sujete ligeramente los pasamanos para mantener el equilibrio y mantenga una postura erguida.","Concéntrate en el movimiento controlado, evitando pasos cortos o apresurados.","Sube paso a paso, impulsando los talones y activando los glúteos.","Aumente la velocidad o la duración gradualmente según su nivel de condición física y sus objetivos.","Enfríe disminuyendo la velocidad durante los últimos 2 o 3 minutos antes de bajarse de manera segura."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('089b5413-c0de-4e80-babe-089b54130000', 'Elevaciones laterales con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Dumbbell-4-Ways-Lateral-Raise.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('40f421e6-c0de-4e80-babe-40f421e60000', 'Curl de bíceps con mancuernas', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Double-Arm-Dumbbell-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1b71a28d-c0de-4e80-babe-1b71a28d0000', 'Extensión de espalda sentado', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/seated-back-extension.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1a5ce0f1-c0de-4e80-babe-1a5ce0f10000', 'Encogimiento de hombros con barra', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2023/03/Behind-The-Back-Barbell-Shrug-Reverse-Barbell-Shrug.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('23712e30-c0de-4e80-babe-23712e300000', 'Patada de tríceps en máquina', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Smith-Machine-Reverse-Kickback.gif', '{"Ajuste la altura de la barra de la máquina Smith a la altura de la cadera.","Acuéstese boca abajo en el banco, de espaldas a la máquina, con los pies separados a la altura de las caderas y las manos debajo del banco para apoyarse.","Baje lentamente las piernas hasta la posición inicial y repita hasta el número deseado de repeticiones.","Manteniendo la espalda recta y el core comprometido, levante ambas piernas detrás de usted lo más que pueda mientras aprieta los glúteos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4f5c5bdb-c0de-4e80-babe-4f5c5bdb0000', 'Encogimiento de hombros en polea', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Cable-Shrug.gif', '{"Es un ejercicio aislado que desarrolla los músculos del cuello. Fortalecer los músculos trapecios ayuda a estabilizar el cuello y la espalda, así como a reducir la tensión en los músculos del cuello y los hombros. Si está buscando aumentar la fuerza de los músculos de los hombros, el cuello o la parte superior de la espalda, o si desea mejorar su postura, puede agregar el encogimiento de hombros con cables a su rutina de ejercicios."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('330a4ddb-c0de-4e80-babe-330a4ddb0000', 'Encogimiento de hombros inclinado con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Dumbbell-Incline-Shrug.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3a25dfef-c0de-4e80-babe-3a25dfef0000', 'Estiramiento', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Wrist-Circles-Stretch.gif', '{"Mejora la eficiencia del agarre: mejora la preparación neuromuscular para ejercicios de tracción y sujeción.","Calienta músculos y tendones: aumenta el flujo sanguíneo y la temperatura en antebrazos y manos.","Prepara las muñecas para soportar cargas: Ideal antes del levantamiento de pesas, yoga, calistenia o escalada.","Mejora el rango de movimiento de las articulaciones: mejora la flexibilidad y la libertad de movimiento tanto en flexión como en extensión.","Reduce el riesgo de lesiones: previene problemas de uso excesivo como tendinitis, esguinces o pinzamientos.","Admite tolerancia a tareas repetitivas: útil para trabajadores, escritores o artistas que pasan largas horas usando sus manos.","Apoya la función general de las extremidades superiores: moviliza estructuras clave vinculadas a la mecánica del codo, el hombro y la mano."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('30a3642e-c0de-4e80-babe-30a3642e0000', 'Encogimiento de hombros', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Lever-Shrug.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1e8e24b6-c0de-4e80-babe-1e8e24b60000', 'Encogimiento de hombros con barra', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Barbell-Shrug.gif', '{"El objetivo del ejercicio de encogimiento de hombros con barra son los músculos trapecios. El encogimiento de hombros con barra es el ejercicio más importante para desarrollar fuerza en los músculos trapecios, ya que activa completamente las fibras musculares de la parte superior de la espalda.","Un músculo trapecio fuerte y tenso sostiene su cuello evitando que su cabeza caiga hacia adelante y le permite mantenerse erguido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5a17b20a-c0de-4e80-babe-5a17b20a0000', 'Elevaciones frontales con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Alternating-Dumbbell-Front-Raise.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('10f29099-c0de-4e80-babe-10f290990000', 'Elevaciones frontales en polea', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Two-Arm-Cable-Front-Raise.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('045662c3-c0de-4e80-babe-045662c30000', 'Elevaciones frontales con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Two-Arm-Dumbbell-Front-Raise.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7ed100bf-c0de-4e80-babe-7ed100bf0000', 'Encogimiento de hombros con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Dumbbell-Shrug.gif', '{"Comience con un peso liviano: es importante comenzar con un peso liviano que pueda controlar cómodamente con la forma adecuada. A medida que se sienta cómodo con el ejercicio, puede aumentar gradualmente el peso.","Párese derecho: Párese con los pies separados a la altura de los hombros y mantenga la espalda recta y los hombros relajados.","Baja las mancuernas: baja lentamente las mancuernas hasta la posición inicial, manteniendo los brazos rectos.","Sujeta las mancuernas correctamente: Sostén una mancuerna en cada mano con las palmas hacia tu cuerpo. Tus brazos deben estar rectos a los costados.","Levante los hombros: levante lentamente los hombros hacia las orejas lo más alto posible, manteniendo los brazos rectos. Asegúrate de usar la escápula y los trapecios para levantar el peso, no los bíceps ni el cuello.","Mantenga la posición superior: Mantenga la posición superior por un momento, asegurándose de contraer completamente las trampas.","Repita para obtener la cantidad deseada de repeticiones: intente realizar 3-4 series de 10-15 repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('44b3a8c0-c0de-4e80-babe-44b3a8c00000', 'Elevaciones frontales con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dumbbell-Front-Raise.gif', '{"El levantamiento frontal con mancuernas es un ejercicio aislado que se dirige a la parte frontal y lateral de los hombros. Adecuado para todos los niveles, este ejercicio de flexión de hombros es una buena opción para desarrollar fuerza, mejorar la movilidad de los hombros y dar forma a la cabeza de los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7d7f1b5c-c0de-4e80-babe-7d7f1b5c0000', 'Elevaciones laterales unilateral con mancuerna', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Leaning-Single-Arm-Dumbbell-Lateral-Raise.gif', '{"La elevación lateral inclinada con mancuernas con un solo brazo es un ejercicio de aislamiento que fortalece todo el hombro. En comparación con la elevación lateral con mancuernas, la elevación lateral con mancuernas inclinada pone el deltoides lateral bajo tensión durante una mayor parte del rango de movimiento, lo que hace que cada repetición sea más efectiva. La posición inclinada crea apalancamiento al tiempo que maximiza el aislamiento de los hombros durante todo el movimiento. También coloca una mayor sobrecarga en la parte superior del movimiento."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('52b789f7-c0de-4e80-babe-52b789f70000', 'Press de pecho sentado', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Seated-Behind-the-Neck-Press.gif', '{"La prensa de cuello es un ejercicio eficaz para desarrollar los músculos del hombro, aumentar la estabilidad del hombro y el rango de movimiento, pero ejerce presión sobre los músculos del manguito rotador que estabilizan las articulaciones del hombro. Por eso es más importante realizar el movimiento correcto que levantar demasiado peso."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5c3133d5-c0de-4e80-babe-5c3133d50000', 'Press de pecho', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Half-Arnold-Press.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4edd3553-c0de-4e80-babe-4edd35530000', 'Elevaciones frontales en polea', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Cable-Front-Raise.gif', '{"El ejercicio de elevación frontal con máquinas de cable proporciona tensión constante y resistencia continua mientras se levanta y baja el peso. Debido a que el crecimiento muscular y las ganancias de fuerza dependen directamente de cuánto se estira el músculo durante el ejercicio, las máquinas de cable cansan los músculos más rápido y proporcionan una mayor ganancia de fuerza.","El levantamiento frontal con cable es el ejercicio de fortalecimiento y desarrollo del hombro más popular dirigido al deltoides anterior.","El ejercicio frontal con cable fortalece los músculos estabilizadores de los hombros y mejora el equilibrio muscular."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('386c6e49-c0de-4e80-babe-386c6e490000', 'Pájaro / Vuelos posteriores en máquina', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Rear-Delt-Machine-Flys.gif', '{"Una máquina de deltoides traseros es una excelente manera de trabajar el deltoides posterior, los romboides y el trapecio medio. Trabajar los músculos deltoides posterior y escapular puede aumentar significativamente la estabilidad del hombro, y trabajar estos músculos puede tener un efecto positivo en la postura del hombro.","El ejercicio deltoides posterior te ayudará a desarrollar una espalda y unos hombros definidos. Es uno de los mejores ejercicios que debes hacer si quieres tener un músculo de la espalda definido y más definido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('08fe1eee-c0de-4e80-babe-08fe1eee0000', 'Elevaciones laterales sentado con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Seated-Dumbbell-Lateral-Raise.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('48dc1973-c0de-4e80-babe-48dc19730000', 'Elevaciones laterales sentado con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Seated-Rear-Lateral-Dumbbell-Raise.gif', '{"El levantamiento lateral trasero con mancuernas sentado es un ejercicio de pesas libres que se dirige principalmente a los hombros traseros. Es un ejercicio eficaz que puedes incluir en tu programa para aislar los músculos posteriores del hombro y fortalecer los músculos del manguito rotador."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0e9c265b-c0de-4e80-babe-0e9c265b0000', 'Encogimiento de hombros', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Lever-Gripless-Shrug.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3f484c10-c0de-4e80-babe-3f484c100000', 'Press de pecho', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Arnold-Press.gif', '{"Siéntese en un banco con respaldo o párese erguido. Sostenga las mancuernas a la altura de los hombros con las palmas hacia el cuerpo.","Bajar y restablecer: baje las mancuernas a la posición inicial mientras gira las muñecas hacia adentro y regrese las palmas hacia el pecho.","Baje las mancuernas a la posición inicial mientras gira las muñecas hacia adentro y devuelva las palmas hacia el pecho.","Posición inicial: Siéntese en un banco con respaldo o párese erguido. Sostenga las mancuernas a la altura de los hombros con las palmas hacia el cuerpo.","Presione y gire: mientras presiona las mancuernas sobre su cabeza, gire las muñecas hacia afuera para que las palmas miren hacia adelante en la parte superior del movimiento.","Mientras presionas las mancuernas sobre tu cabeza, gira las muñecas hacia afuera para que las palmas miren hacia adelante en la parte superior del movimiento."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('54974d52-c0de-4e80-babe-54974d520000', 'Elevaciones laterales inclinado', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Bent-Over-Lateral-Raise.gif', '{"También conocido como Flyes inversos, el levantamiento lateral inclinado es un excelente ejercicio de espalda para equilibrar la fuerza de los hombros. Este ejercicio trabaja el deltoides posterior (parte posterior del hombro) y el trapecio y romboides en la parte superior y media de la espalda entre los omóplatos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6df2a261-c0de-4e80-babe-6df2a2610000', 'Elevaciones laterales en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Leaning-Cable-Lateral-Raise.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('43ec26b2-c0de-4e80-babe-43ec26b20000', 'Pájaro / Vuelos posteriores en polea', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/cable-rear-delt-fly.gif', '{"El cable delt fly es un excelente ejercicio de fortalecimiento que trabaja eficazmente muchos músculos, incluidos el hombro, el manguito rotador y el trapecio. Al afectar los músculos infraespinoso y subescápula que cubren la escápula, puede ayudar a protegerlo de dolencias causadas por la debilidad muscular, como el trastorno de la postura y la protrusión de la escápula. Además, fortalecer estos músculos mediante el ejercicio del deltoides trasero con cable ayudará a mejorar la mala postura, promoverá una postura erguida y mejorará el equilibrio.","El ejercicio con cable deltoides traseros te ayudará a desarrollar una espalda y unos hombros definidos. Es uno de los mejores ejercicios que debes hacer si quieres tener un músculo de la espalda definido y más definido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('489c6fac-c0de-4e80-babe-489c6fac0000', 'Giro ruso', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Elbow-To-Knee-Twists.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('656a62ff-c0de-4e80-babe-656a62ff0000', 'Remo de rodillas en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Half-Kneeling-High-Cable-Row-Rope.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1bb3876c-c0de-4e80-babe-1bb3876c0000', 'Elevación con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Dumbbell-Raise.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2b017923-c0de-4e80-babe-2b0179230000', 'Remo con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Dumbbell-Upright-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4eb6c3e5-c0de-4e80-babe-4eb6c3e50000', 'Extensión de tríceps', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Weighted-Neck-Harness-Extension.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3a22a13a-c0de-4e80-babe-3a22a13a0000', 'Ejercicio acostado', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Lying-Weighted-Neck-Flexion.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('309bfc0a-c0de-4e80-babe-309bfc0a0000', 'Extensión de tríceps acostado', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Lying-Weighted-Neck-Extension.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7263a460-c0de-4e80-babe-7263a4600000', 'Extensión de tríceps', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Lever-Neck-Extension-plate-loaded.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4a9118fc-c0de-4e80-babe-4a9118fc0000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Lever-Neck-Right-Side-Flexion-plate-loaded.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('691522a4-c0de-4e80-babe-691522a40000', 'Extensión de tríceps sentado en polea', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Cable-Seated-Neck-Extension-with-head-harness.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1769a2fd-c0de-4e80-babe-1769a2fd0000', 'Ejercicio sentado en polea', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Cable-Seated-Neck-Flexion-with-head-harness.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1b92c500-c0de-4e80-babe-1b92c5000000', 'Postura de yoga', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Bhekasana.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7505d960-c0de-4e80-babe-7505d9600000', 'Postura de yoga', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Balasana-Child-Pose.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('02b9b60a-c0de-4e80-babe-02b9b60a0000', 'Elevación de piernas alterno', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/Alternate-Leg-Raises.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5e92f3fd-c0de-4e80-babe-5e92f3fd0000', 'Postura de yoga de pie', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Anuvittasana-Standing-Backbend-Pose.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4da02872-c0de-4e80-babe-4da028720000', 'Zancadas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Anjaneyasana-Low-Lunge-Pose.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('43594c6f-c0de-4e80-babe-43594c6f0000', 'Elevaciones laterales', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Dumbbell-Bent-Arm-Laterl-Raise.gif', '{"Párese con los pies separados a la altura de los hombros. Sostenga una mancuerna en cada mano, con las palmas hacia el cuerpo. Deje que los brazos cuelguen a los costados.","Descenso controlado: baje las pesas hasta la posición inicial de forma controlada.","Baje las pesas hasta la posición inicial de forma controlada.","Posición inicial: Párese con los pies separados a la altura de los hombros. Sostenga una mancuerna en cada mano, con las palmas hacia el cuerpo. Deje que los brazos cuelguen a los costados.","Deja que tus brazos cuelguen a los costados.","Doble los codos en un ángulo de 90 grados, de modo que la parte superior de sus brazos quede paralela al suelo y sus antebrazos perpendiculares.","Levante las pesas: Manteniendo los codos doblados a 90 grados, levante los brazos hacia los lados hasta que la parte superior de los brazos quede paralela al suelo. Concéntrese en usar los músculos de los hombros para levantar las pesas, no la espalda ni los trapecios.","Manteniendo los codos doblados a 90 grados, levante los brazos hacia los lados hasta que la parte superior de sus brazos quede paralela al suelo.","Posición del brazo doblado: Doble los codos en un ángulo de 90 grados, de modo que la parte superior de los brazos quede paralela al suelo y los antebrazos perpendiculares.","Concéntrese en usar los músculos de los hombros para levantar las pesas, no la espalda ni los trampas.","Realiza el número deseado de repeticiones.","Repetir: Realice el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('42fd4134-c0de-4e80-babe-42fd41340000', 'Ejercicio con banda de resistencia', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Eka-Pada-Setu-Bandha-Sarvangasana.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0b52403e-c0de-4e80-babe-0b52403e0000', 'Postura de yoga', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Bitilasana-Cow-Pose.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('16df4e1e-c0de-4e80-babe-16df4e1e0000', 'Plancha', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Chaturanga-Dandasana-Low-Plank-Pose.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
