INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('44b83150-c0de-4e80-babe-44b831500000', 'Ejercicio', 'Otros', '', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5a8d80d0-c0de-4e80-babe-5a8d80d00000', 'Postura de yoga', 'Otros', '', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6c245989-c0de-4e80-babe-6c2459890000', 'Elevación de pantorrillas con banda de resistencia', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Calf-Raise-with-Resistance-Band.gif', '{"- Agarre la banda: coloque las manijas en los extremos de la banda y agarre una manija en cada mano, con los brazos rectos y las palmas hacia atrás.","- Posición inicial: Párese erguido con los pies separados a la altura de las caderas. Mantenga la columna erguida, los hombros ligeramente retraídos y los brazos relajados detrás de usted sosteniendo la banda tensa.","- Encogerse de hombros o tensar los trapecios superiores debido a una mala posición del mango.","- Configuración: Asegure una banda de resistencia a un punto de anclaje bajo detrás de sus pies.","- Pausa y contracción: en la parte superior del movimiento, apriete las pantorrillas y manténgalas así durante 1 a 2 segundos para enfatizar la contracción máxima.","- Repetir: realice la cantidad deseada de repeticiones mientras mantiene una tensión constante en la banda.","- Levantar: Presione a través de las puntas de los pies y levante los talones del suelo lentamente, involucrando las pantorrillas a medida que se eleva.","- Baje lentamente: descienda bajo control, permitiendo que sus talones regresen justo por debajo del paralelo para un estiramiento completo.","- Maximice el rango de movimiento: levante lo más alto posible sobre los dedos de los pies, luego bájelo hasta que los talones estén ligeramente por debajo del paralelo si la movilidad lo permite.","- Usar una banda demasiado suelta, lo que reduce la resistencia efectiva en la parte superior del movimiento.","- Rebotar el movimiento, eliminando el control y aumentando la tensión articular.","- Acortar el rango de movimiento, particularmente al no permitir una caída total del talón en la parte inferior.","- Dejar que los brazos se doblen, lo que disminuye el estiramiento y la tensión en la banda.","- Párese erguido y alineado: mantenga la cabeza, los hombros y las caderas apilados verticalmente para una mejor forma y aislamiento de las pantorrillas.","- Estabilice con su núcleo: active sus músculos abdominales para evitar inclinarse o balancearse hacia adelante.","### Consejos para una forma adecuada","- Mantenga la contracción máxima: hacer una pausa en la parte superior aumenta el tiempo bajo tensión y el reclutamiento de fibras musculares.","- Evite doblar los brazos: mantenga los codos extendidos para mantener una tensión constante de la banda desde el punto de anclaje.","### Errores comunes"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2085981f-c0de-4e80-babe-2085981f0000', 'Postura de yoga', 'Piernas', '', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('435d0c7c-c0de-4e80-babe-435d0c7c0000', 'Sentadilla', 'Piernas', '', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('49544e6d-c0de-4e80-babe-49544e6d0000', 'Postura de yoga', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Samakonasana-Straight-Angle-Pose.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('23e94ff4-c0de-4e80-babe-23e94ff40000', 'Giro ruso', 'Abdomen', '', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('76466ac5-c0de-4e80-babe-76466ac50000', 'Remo', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Rowing-Boat-Yoga-Pose.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7a363fb2-c0de-4e80-babe-7a363fb20000', 'Ejercicio', 'Hombros', '', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
