INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('56d27f86-c0de-4e80-babe-56d27f860000', 'Jalón al pecho', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Front-Pulldown.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('38d0f692-c0de-4e80-babe-38d0f6920000', 'Postura de yoga', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Bridge-Pose.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4d4cbd8a-c0de-4e80-babe-4d4cbd8a0000', 'Postura de yoga', 'Otros', '', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5df2c250-c0de-4e80-babe-5df2c2500000', 'Ejercicio', 'Otros', '', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('442d9b3e-c0de-4e80-babe-442d9b3e0000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Push-up-Toe-Touch.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5f29ee8b-c0de-4e80-babe-5f29ee8b0000', 'Remo inclinado con barra', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Barbell-Bent-Over-Row.gif', '{"Mantenga la cabeza en una posición neutral, mirando ligeramente hacia adelante, para mantener la alineación adecuada de la columna.","No utilices el impulso para levantar el peso; Concéntrese en usar los músculos de la espalda y los brazos para realizar el movimiento de remo.","Puede utilizar un cinturón de levantamiento de pesas para obtener apoyo adicional si es necesario, especialmente al levantar cargas pesadas.","Evite arquear la espalda durante el ejercicio, ya que esto puede provocar lesiones. Mantenga la espalda recta y active su núcleo para lograr estabilidad."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7624341e-c0de-4e80-babe-7624341e0000', 'Pullover en polea en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Cable-Straight-Arm-Pulldown.gif', '{"Tener una espalda fuerte ayuda a mantener la columna vertebral en la alineación adecuada y permite realizar las tareas cotidianas con un riesgo reducido de lesiones. Además de ayudar a fortalecer la espalda, el ejercicio trabaja secundariamente los tríceps y los hombros.","El ejercicio de jalones con los brazos estirados es una variación del clásico jalones laterales. Mantener los brazos rectos evita que la parte media de la espalda y los bíceps se hagan cargo del movimiento, por lo que puedes concentrarte en los músculos dorsales que estás tratando de trabajar más directamente."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('57eb7ad4-c0de-4e80-babe-57eb7ad40000', 'Jalón al pecho en polea alta', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Lat-Pulldown.gif', '{"Siéntese en la máquina de dominadas con los pies apoyados en el suelo y las rodillas firmemente presionadas contra la almohadilla. Tus muslos deben estar paralelos al suelo.","Agarre la barra con ambas manos, asegurándose de que las palmas estén de espaldas a usted y que su agarre esté más ancho que el ancho de los hombros.","Haga una pausa por un segundo cuando la barra llegue a su pecho y luego suéltela lentamente hasta la posición inicial, extendiendo los brazos completamente.","Comience fijando un manillar ancho al cable.","Mientras mantiene la espalda recta y el pecho erguido, tire de la barra hacia el pecho contrayendo los músculos de la espalda. Tus codos deben apuntar hacia abajo y permanecer cerca de tu cuerpo.","Repita para el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0c096e2c-c0de-4e80-babe-0c096e2c0000', 'Remo', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Lever-T-bar-Row.gif', '{"El remo con barra en T es un ejercicio de entrenamiento de fuerza que imita el movimiento de remar en un bote. El objetivo es fortalecer los músculos que acercan los brazos al cuerpo, así como los que mueven los omóplatos hacia la columna. El remo con barra en T puede permitirle levantar más peso. Debido a la naturaleza de este movimiento, puedes aprovechar más peso.","La barra en T, que se dirige a toda la cadena de la espalda, se dirige al dorsal ancho, el infraespinoso, el trapecio, los deltoides posteriores y los romboides, por lo que agregar ejercicios como remo con barra y remo con barra en T a sus programas de entrenamiento será beneficioso para el desarrollo de los músculos de la espalda."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3a74cb8f-c0de-4e80-babe-3a74cb8f0000', 'Remo inclinado con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Dumbbell-Bent-Over-Reverse-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('470bf9cd-c0de-4e80-babe-470bf9cd0000', 'Remo sentado en máquina', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Seated-Row-Machine.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('21a10b47-c0de-4e80-babe-21a10b470000', 'Remo unilateral en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/One-arm-Cable-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('58f45543-c0de-4e80-babe-58f455430000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Rope-Climb.gif', '{"Posición del cuerpo hueco: mientras levanta las piernas del suelo, active los músculos centrales para crear una posición de \"cuerpo hueco\".","Tirón inicial: comience la escalada levantándose usando los brazos y la fuerza central. Es importante involucrar la espalda, los hombros y los brazos para iniciar el tirón.","Subir continuamente: Continúe el movimiento de mano sobre mano mientras mantiene la posición del cuerpo hueco. Utilice sus brazos para generar la potencia de tracción y mantener el agarre de la cuerda.","Posición superior: sigue subiendo hasta llegar a la parte superior de la cuerda o a la altura deseada. En la cima, puedes usar tus brazos para agarrar la cuerda y estabilizarte si es necesario.","Agarre: Comience parándose frente a la cuerda. Levante ambas manos y agarre la cuerda firmemente. Tus manos deben estar separadas aproximadamente al ancho de los hombros y las palmas deben estar enfrentadas.","Mano sobre mano: Utilice un movimiento de mano sobre mano para agarrar la cuerda alternativamente. Tire hacia abajo con una mano mientras levanta la otra mano. Este movimiento te ayuda a ascender por la cuerda. Recuerde, sus piernas no participan en el movimiento.","Fuerza central y superior del cuerpo: los músculos centrales son cruciales para mantener la estabilidad y la fuerza de la parte superior del cuerpo impulsará la escalada. Concéntrate en movimientos controlados y mantén la tensión en todo tu cuerpo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4e8c1149-c0de-4e80-babe-4e8c11490000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2015/11/Crunch.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5ef5205d-c0de-4e80-babe-5ef5205d0000', 'Remo inclinado con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Bent-Over-Dumbbell-Row.gif', '{"- Posición inicial: sostenga una mancuerna en cada mano con las palmas hacia el torso. Párese con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas.","- Descenso controlado: baje lentamente las mancuernas hasta la posición inicial, manteniendo la forma y el control.","- Usar demasiado peso: conduce a una mala forma y a una dependencia del impulso en lugar del compromiso muscular.","###","- Bisagra de cadera: empuje las caderas hacia atrás e incline el torso hacia adelante hasta formar un ángulo de aproximadamente 45 grados. Mantenga la espalda plana y el núcleo comprometido.","- Apretar y mantener: en la parte superior del movimiento, apriete los omóplatos durante una breve pausa.","- Repetir: realice de 8 a 12 repeticiones por serie.","- Movimiento de remo: tire de las mancuernas hacia la caja torácica empujando los codos hacia atrás, manteniéndolos cerca del cuerpo.","- Involucre su núcleo para evitar la tensión en la espalda baja.","- Mueve las mancuernas de forma suave y controlada sin sacudidas.","- Lidera el tirón con los codos, no con las manos.","### Errores comunes","### Consejos para una forma adecuada","- Mantenga la espalda recta y evite doblar los hombros.","- Redondear la espalda: coloca una tensión innecesaria en la columna y reduce la eficacia.","- Codos ensanchados demasiado anchos: Reduce la activación de los dorsales y puede causar tensión en los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0e0cae1c-c0de-4e80-babe-0e0cae1c0000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Muscle-up-vertical-bar.gif', '{"Comience colgando de la barra con los brazos completamente extendidos y las palmas hacia afuera del cuerpo. Su agarre debe estar ligeramente más ancho que el ancho de los hombros.","Comience con una dominada potente, utilizando los músculos de la espalda y los brazos para levantar el cuerpo hacia la barra. Utilice un agarre falso (muñecas giradas sobre la barra) para ayudar con la fase de transición.","A medida que realiza la transición, mantenga su núcleo apretado y active sus tríceps para impulsarse hacia la posición de inmersión. Concéntrate en la potencia explosiva en tu dominada y en la fase de transición del levantamiento muscular.","En la posición de inmersión, los brazos deben estar completamente extendidos con los hombros bloqueados y el cuerpo debe estar en una posición hueca con los pies ligeramente por delante de usted. Mantenga su núcleo apretado durante todo el movimiento para ayudar a mantener el control y la estabilidad.","Una vez que su pecho alcance la altura de la barra, comience a girar las muñecas hacia adelante y lleve los codos hacia las caderas. Esto te permitirá hacer la transición de tu cuerpo sobre la barra.","Baje desde la posición de inmersión, invirtiendo el movimiento de regreso a la posición inicial."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6035157a-c0de-4e80-babe-6035157a0000', 'Remo con agarre inverso con barra', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Reverse-Grip-Barbell-Row.gif', '{"Párese con los pies separados a la altura de los hombros, los dedos de los pies apuntando hacia adelante y la barra frente a usted en el piso. Para el remo con barra con agarre inverso, agarre la barra por debajo (con las palmas hacia arriba), con las manos colocadas ligeramente más separadas que el ancho de los hombros.","Agarre la barra: bájese y agarre la barra con el agarre por debajo. Tus brazos deben estar completamente extendidos y tu agarre debe ser firme.","la espalda debe estar plana, el pecho hacia afuera y los omóplatos hacia atrás y hacia abajo. Esta es la posición inicial.","Baje la barra: baje lentamente la barra hasta la posición inicial mientras mantiene el control. No permitas que el peso te empuje hacia adelante; en cambio, controla el descenso.","Configuración: Párese con los pies separados a la altura de los hombros, los dedos de los pies apuntando hacia adelante y la barra frente a usted en el piso. Para el remo con barra con agarre inverso, agarre la barra por debajo (con las palmas hacia arriba), con las manos colocadas ligeramente más separadas que el ancho de los hombros.","Doble las caderas: doble las caderas mientras mantiene la espalda recta. Baja el torso hasta que quede casi paralelo al suelo. Mantenga las rodillas ligeramente flexionadas durante todo el movimiento.","El remo: tire de la barra hacia la parte superior del abdomen o la parte inferior del pecho mientras mantiene los codos cerca del cuerpo. Concéntrate en juntar los omóplatos en la parte superior del movimiento para involucrar completamente los músculos de la espalda.","Posición inicial: la espalda debe estar plana, el pecho hacia afuera y los omóplatos hacia atrás y hacia abajo. Esta es la posición inicial.","Repetir: Realiza el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('59c66f99-c0de-4e80-babe-59c66f990000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Mountain-climber.gif', '{"Los alpinistas son un ejercicio cardiovascular y de fortalecimiento central eficaz. Puede ayudarle a fortalecer y desarrollar los músculos de la parte superior e inferior del cuerpo.","Al ser un movimiento multifuncional, este ejercicio se dirige no solo a los músculos abdominales sino también a la columna y los glúteos. El alpinista fortalece y tonifica todo el cuerpo, mejora la postura y el equilibrio, reduce la grasa corporal y puede ayudar a acelerar el metabolismo.","Los alpinistas son beneficiosos para la salud porque combinan la aptitud cardiovascular con el entrenamiento de fuerza. Debido a que las zancadas rápidas aumentan su frecuencia cardíaca, también pueden aumentar su condición cardiovascular."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0e9a960d-c0de-4e80-babe-0e9a960d0000', 'Elevación de piernas', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Lying-Leg-Raise.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7f77db55-c0de-4e80-babe-7f77db550000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Oblique-Floor-Crunches.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('03350632-c0de-4e80-babe-033506320000', 'Curl de bíceps con barra', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Barbell-Curl.gif', '{"Párese derecho con los pies separados al ancho de los hombros y agarre la barra con un agarre por debajo, con las manos separadas al ancho de los hombros.","Baje lentamente la barra hasta la posición inicial, manteniendo los bíceps enganchados durante todo el movimiento.","Mantén los codos pegados a los costados y levanta la barra hacia el pecho, mientras contraes los bíceps. Asegúrese de mantener los codos fijos y evite balancear el peso.","Repita hasta el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('40e831fb-c0de-4e80-babe-40e831fb0000', 'Jalón al pecho en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Cable-Rear-Pulldown.gif', '{"Utilice una máquina de dominadas con una barra de agarre ancha adjunta. Ajuste la máquina a un peso adecuado. Siéntese en el banco de la máquina frente a la barra y asegure sus muslos debajo de los soportes provistos.","Siéntese en el banco de la máquina frente a la barra y asegure los muslos debajo de los soportes provistos.","Agarre: Agarra la barra con ambas manos usando un agarre amplio. En un agarre amplio, las manos se colocan a una distancia mayor que la anchura de los hombros.","Agarre la barra con ambas manos con un agarre amplio. En un agarre amplio, las manos se colocan a una distancia mayor que la anchura de los hombros.","Posición del cuerpo: Inclínese ligeramente hacia adelante mientras mantiene la espalda recta. Asegúrese de que sus muslos estén colocados de forma segura debajo de los soportes para estabilizar su cuerpo.","Configuración: Utilice una máquina de dominadas con una barra de agarre ancha adjunta. Ajuste la máquina a un peso adecuado. Siéntese en el banco de la máquina frente a la barra y asegure sus muslos debajo de los soportes provistos.","Movimiento: tire de la barra hacia abajo detrás de la cabeza llevando los codos hacia los lados. Concéntrese en apretar los omóplatos mientras tira de la barra hacia abajo. Baje la barra hasta que esté cerca de la parte posterior del cuello y sienta una contracción en los músculos dorsales.","tire de la barra hacia abajo detrás de la cabeza llevando los codos hacia los lados. Concéntrese en apretar los omóplatos mientras tira de la barra hacia abajo. Baje la barra hasta que esté cerca de la parte posterior del cuello y sienta una contracción en los músculos dorsales.","Tire de la barra hacia abajo detrás de su cabeza llevando los codos hacia los lados.","Baje la barra hasta que esté cerca de la parte posterior de su cuello y sienta una contracción en los músculos dorsales.","Liberación controlada: permita que el cable levante la barra lentamente. Extienda completamente los brazos y los hombros en la parte superior del movimiento.","Deje que el cable levante la barra lentamente.","Concéntrate en juntar los omóplatos mientras tiras la barra hacia abajo.","Repetir: Realiza el número de repeticiones deseado, manteniendo el control durante todo el ejercicio.","Realiza el número deseado de repeticiones, manteniendo el control durante todo el ejercicio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('064b652f-c0de-4e80-babe-064b652f0000', 'Curl de piernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Leg-Curl.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('45c4af3f-c0de-4e80-babe-45c4af3f0000', 'Sentadilla con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/Sumo-Plie-Dumbbell-Squat.gif', '{"- Párese con los pies más anchos que el ancho de los hombros y gire los dedos hacia afuera en un ángulo de 30 a 45 grados.","- Sostenga una mancuerna verticalmente con ambas manos, ya sea en posición de copa en el pecho o entre las piernas con el brazo extendido.","- Haga una breve pausa en la parte inferior, luego empuje los talones para volver a la posición inicial, apretando los glúteos.","- Usar demasiado peso demasiado pronto, comprometiendo la forma y el control.","- Mueva las rodillas en dirección a los dedos de los pies para activar la parte interna de los muslos.","- Agáchate hasta que tus muslos queden al menos paralelos o ligeramente por debajo si tu movilidad lo permite.","- Involucre su núcleo para apoyar su espalda baja y mejorar el equilibrio.","- Baja con control, especialmente si la mancuerna se sostiene por delante o por debajo.","- Doble las rodillas y baje las caderas directamente hacia abajo mientras mantiene el torso erguido.","- Empuje las rodillas hacia afuera en línea con los dedos de los pies para evitar colapsar hacia adentro.","- Dejar que las rodillas se doblen hacia adentro, lo que reduce el compromiso de los aductores y aumenta el riesgo de lesiones.","- Vaya tan profundo como lo permita su movilidad, apuntando a muslos paralelos o más bajos.","### Errores comunes","- Inclinarse demasiado hacia adelante, lo que aleja la carga de los músculos objetivo.","- Involucre su núcleo y mantenga la espalda erguida mientras comienza a ponerse en cuclillas.","### Consejos para una forma adecuada","- Mantenga la columna neutra y el pecho elevado durante toda la sentadilla.","- Mantener la mancuerna demasiado lejos de su cuerpo, lo que puede dañar su espalda.","- Girar excesivamente los dedos de los pies, lo que puede generar tensión en las rodillas y los tobillos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('365c66d7-c0de-4e80-babe-365c66d70000', 'Curl de bíceps con mancuernas', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dumbbell-Curl.gif', '{"Párese con una postura adecuada: párese derecho con los pies separados al ancho de los hombros y los hombros hacia atrás. Esto ayudará a mantener una alineación adecuada y a involucrar su núcleo.","Comience con un peso cómodo: seleccione un peso que pueda levantar cómodamente para la cantidad deseada de repeticiones. Es mejor comenzar con un peso más liviano e ir subiendo, en lugar de usar un peso demasiado pesado y sacrificar la forma.","Sujeta las mancuernas correctamente: Sujeta las mancuernas con un agarre neutro (las palmas hacia adentro) y mantén las muñecas rectas. Evite utilizar un agarre demasiado apretado, ya que esto puede provocar una tensión innecesaria en las muñecas.","Doble un brazo a la vez: comience doblando una mancuerna hacia su hombro, manteniendo el codo cerca de su costado. Mientras levantas el peso, concéntrate en apretar el bíceps en la parte superior del movimiento.","Respire adecuadamente: inhale mientras baja el peso y exhale mientras dobla el peso hacia su hombro.","Mantenga los codos cerca de los costados: Mantenga los codos cerca de los costados durante todo el movimiento. Esto ayudará a aislar los bíceps y evitará que se balanceen.","Baje el peso de forma controlada: baje el peso de forma controlada, asegurándose de mantener el codo cerca del costado. Evite dejar que el peso baje rápidamente, ya que esto puede ejercer una tensión innecesaria en las articulaciones.","Alternar entre brazos: una vez que hayas completado una repetición completa con un brazo, cambia al otro brazo y repite el ejercicio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('16ffd13e-c0de-4e80-babe-16ffd13e0000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/T-Cross-Sit-up.gif', '{"Trabaja todos los músculos abdominales: el ejercicio de abdominales T-Cross se centra en el recto abdominal y los músculos oblicuos. Es un ejercicio beneficioso para perder grasa y tonificar ya que tiene un efecto intenso sobre los músculos oblicuos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('39bf30fc-c0de-4e80-babe-39bf30fc0000', 'Curl de piernas sentado', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Seated-Leg-Curl.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('286dc8c2-c0de-4e80-babe-286dc8c20000', 'Ejercicio declinado', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Decline-Sit-up.gif', '{"Los abdominales declinados se dirigen al recto abdominal y a los músculos oblicuos para fortalecer los músculos centrales. Es un ejercicio que puedes aplicar para moldear los músculos abdominales superiores y los músculos abdominales."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6914866d-c0de-4e80-babe-6914866d0000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Bicycle-Crunch.gif', '{"Acuéstese boca arriba sobre una colchoneta o una superficie cómoda. Coloque las manos detrás de la cabeza, con los codos apuntando hacia afuera. Levante las piernas del suelo y doble las rodillas en un ángulo de 90 grados. Esta es tu posición inicial.","Levanta las piernas del suelo, doblando las rodillas en un ángulo de 90 grados. Esta es tu posición inicial.","Posición inicial: Acuéstese boca arriba sobre una colchoneta o una superficie cómoda. Coloque las manos detrás de la cabeza, con los codos apuntando hacia afuera. Levante las piernas del suelo y doble las rodillas en un ángulo de 90 grados. Esta es tu posición inicial.","Ejecución: Levante la cabeza, los hombros y los pies del suelo, activando los músculos centrales. Mientras levanta, acerque el codo derecho y la rodilla izquierda entre sí en un movimiento giratorio. Al mismo tiempo, estire la pierna derecha, manteniéndola elevada sobre el suelo. Simule un movimiento de ciclismo llevando alternativamente el codo izquierdo hacia la rodilla derecha mientras estira la pierna izquierda. Continúe con este movimiento de pedaleo, asegurándose de involucrar su núcleo y evitando tirar del cuello con las manos.","Respiración: Exhale mientras gira y lleva el codo a la rodilla opuesta. Inhale mientras cambia al otro lado.","Levante la cabeza, los hombros y los pies del suelo, activando los músculos centrales. Mientras levanta, acerque el codo derecho y la rodilla izquierda entre sí en un movimiento giratorio. Al mismo tiempo, estire la pierna derecha, manteniéndola elevada sobre el suelo. Simule un movimiento de ciclismo llevando alternativamente el codo izquierdo hacia la rodilla derecha mientras estira la pierna izquierda. Continúe con este movimiento de pedaleo, asegurándose de involucrar su núcleo y evitando tirar del cuello con las manos.","Mientras levanta, acerque el codo derecho y la rodilla izquierda con un movimiento giratorio.","Al mismo tiempo, estire la pierna derecha, manteniéndola elevada por encima del suelo.","Inhala mientras cambias al otro lado.","Exhala mientras giras y llevas el codo a la rodilla opuesta.","Repetir: continuar el movimiento de pedaleo durante un número específico de repeticiones o una duración determinada.","Exhale mientras gira y lleva el codo a la rodilla opuesta. Inhale mientras cambia al otro lado.","Continúe el movimiento de pedaleo durante un número específico de repeticiones o una duración determinada."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0c5805b5-c0de-4e80-babe-0c5805b50000', 'Patada de tríceps con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dumbbell-Kickback.gif', '{"- Configure su posición Sostenga una mancuerna en una mano con un agarre neutral. Coloque la mano opuesta en un banco como apoyo. Mantenga los pies separados al ancho de los hombros para mantener el equilibrio.","- Sostenga una mancuerna en una mano con agarre neutral.","- Coloque su mano opuesta en un banco como apoyo.","- Inhala mientras regresas lentamente a la posición inicial con control.","- Seleccione un peso apropiado que permita una buena forma sin tensión excesiva.","- Usar demasiado peso, comprometer la forma y aumentar el riesgo de lesiones.","###","- Mantenga los pies separados a la altura de los hombros para mantener el equilibrio.","- Gire las caderas e inclínese ligeramente hacia adelante.","- La parte superior de tu brazo debe estar paralela al suelo, con el codo doblado en un ángulo de 90 grados.","- Repetir y cambiar de lado Realice el número deseado de repeticiones antes de cambiar de brazo.","- Realice el movimiento Exhale mientras extiende el brazo completamente hacia atrás, manteniendo el codo inmóvil. Apriete el tríceps en la parte superior del movimiento. Inhale mientras regresa lentamente a la posición inicial con control.","- Exhale mientras extiende el brazo completamente hacia atrás, manteniendo el codo inmóvil.","- Aprieta tus tríceps en la parte superior del movimiento.","- Asegure un rango completo de movimiento, extendiendo el brazo por completo.","- Realice el número deseado de repeticiones antes de cambiar de brazo.","- Involucre sus músculos centrales para mantener la estabilidad.","### Errores comunes a evitar","- Balancear la mancuerna, lo que reduce la activación del tríceps.","- Mantenga una postura adecuada Gire las caderas e inclínese ligeramente hacia adelante. Mantenga la espalda recta y active su núcleo. La parte superior de su brazo debe estar paralela al piso, con el codo doblado en un ángulo de 90 grados.","- Mantenga la espalda recta y active su núcleo.","### Consejos para una forma adecuada","- Mantenga la parte superior del brazo inmóvil para asegurarse de que los tríceps hagan el trabajo.","- Evite utilizar el impulso moviéndose lentamente y con control.","- Dejar caer el codo, lo que provoca una participación inadecuada del músculo objetivo.","- No extender completamente el brazo, limitando la efectividad del ejercicio.","- Redondear la espalda, lo que puede provocar tensión en la zona lumbar."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('12056ac4-c0de-4e80-babe-12056ac40000', 'Extensión de piernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/LEG-EXTENSION.gif', '{"Coloque la máquina de extensión de piernas a su altura adecuada y ajuste el respaldo y el reposapiés para alinearlos con su cuerpo.","Siéntese en la máquina con la espalda apoyada en el respaldo y los pies firmemente apoyados en el reposapiés. Asegúrese de que sus rodillas estén alineadas con el punto de pivote de la máquina.","Coloque las piernas debajo de la palanca o rodillo acolchado de la máquina. La almohadilla debe descansar contra la parte delantera de los tobillos, justo encima de los pies.","Sujete las manijas provistas en la máquina para obtener estabilidad y apoyo durante todo el ejercicio. Mantenga la parte superior del cuerpo relajada y mantenga una buena postura."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('19d7371f-c0de-4e80-babe-19d7371f0000', 'Ejercicio de rodillas en polea', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Kneeling-Cable-Crunch.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4787a60f-c0de-4e80-babe-4787a60f0000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Heel-Touch.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4800bdba-c0de-4e80-babe-4800bdba0000', 'Curl de bíceps sentado con mancuernas', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Seated-Incline-Dumbbell-Curl.gif', '{"Configure el banco: ajuste el banco a una inclinación de 45 grados y asegúrese de que esté estable y seguro. Siéntate en el banco con la espalda recta y los pies apoyados en el suelo.","Elija el peso correcto: elija un peso que sea apropiado para su nivel de condición física y sus objetivos. Comience con un peso más liviano y aumente gradualmente a medida que se vuelva más fuerte.","Agarre las mancuernas: sostenga una mancuerna en cada mano con las palmas hacia arriba. Su agarre debe ser cómodo y firme.","Curl las mancuernas: levante lentamente una mancuerna hacia su hombro, manteniendo el codo inmóvil. Mientras levantas la mancuerna, gira la palma de tu mano para que mire hacia tu hombro en la parte superior del movimiento. Mientras bajas la primera mancuerna, comienza a levantar la otra mancuerna y gira la otra palma para que también mire hacia tu hombro en la parte superior del movimiento.","Respira adecuadamente: Inhala mientras bajas las mancuernas y exhala mientras las levantas.","Controle el movimiento: durante todo el ejercicio, concéntrese en mantener el control y evitar cualquier movimiento de balanceo o sacudida. Utilice un movimiento lento y controlado para involucrar completamente sus músculos.","Coloca tus brazos: Coloca tus brazos de manera que queden completamente extendidos y paralelos al suelo. Mantenga los codos cerca de su cuerpo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('55518da2-c0de-4e80-babe-55518da20000', 'Elevación de pantorrillas sentado con barra', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Barbell-Seated-Calf-Raise.gif', '{"- Configuración: Siéntese en un banco plano con los pies separados a la altura de los hombros sobre una superficie o plataforma elevada (de 2 a 4 pulgadas de alto). Tus rodillas deben estar dobladas aproximadamente a 90 grados.","- Posición inicial: siéntese erguido con la columna neutra, el núcleo reforzado y los dedos de los pies apuntando hacia adelante. Los tacones deben colgar del borde de la plataforma.","- Cargue la barra: coloque con cuidado una barra acolchada sobre la parte inferior de los muslos, justo por encima de las rótulas. Utilice una almohadilla para sentadillas o una toalla para mayor comodidad.","- Pausa y contracción: mantenga la posición superior durante 1 a 2 segundos para maximizar el compromiso del sóleo.","- Aprieta en la parte superior de cada repetición para activar el sóleo de manera más efectiva.","- No gire los tobillos: mantenga los pies planos y estables durante todo el rango de movimiento.","- Levantar: Presione a través de las puntas de los pies y levante los talones lo más alto posible, contrayendo las pantorrillas en la parte superior.","- Baje lentamente: descienda bajo control, permitiendo que los talones se hundan debajo de la plataforma para estirar la pantorrilla.","- Utilice una plataforma estable debajo del antepié para permitir un rango completo de movimiento.","- Baje los talones lentamente para beneficiarse de la parte excéntrica del movimiento.","### Errores comunes","- Usar demasiado peso, lo que reduce el rango de movimiento o rebota.","- No utilizar plataforma, lo que acorta el alcance y limita el tramo en la parte inferior.","- Saltarse la pausa en la parte superior, lo que reduce el tiempo bajo tensión.","- Repetir: Complete el número deseado de repeticiones sin rebotes ni sacudidas.","### Consejos para una forma adecuada","- Mantenga la columna neutra y evite inclinarse excesivamente hacia adelante durante el levantamiento.","- Permitir que las rodillas se muevan, lo que reduce la estabilidad y aísla el sóleo de manera menos efectiva.","- No controlar la fase excéntrica, perdiendo la oportunidad de crecimiento muscular."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3b196429-c0de-4e80-babe-3b1964290000', 'Ejercicio en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Pushdown.gif', '{"- Configure el equipo Conecte una barra recta, una cuerda o una barra en V a la polea alta de una máquina de cable. Seleccione un peso moderado que permita un movimiento controlado.","- Conecte una barra recta, una cuerda o una barra en V a la polea alta de una máquina de cable.","- ColóquesePárese con los pies separados a la altura de los hombros para mayor estabilidad.Sujete el accesorio con un agarre por encima de la cabeza (con las palmas hacia abajo).Mantenga los codos cerca del torso y dóblelos en un ángulo de 90 grados.","- Párese con los pies separados a la altura de los hombros para mayor estabilidad.","- Agarre el accesorio con las manos en pronación (con las palmas hacia abajo).","- Inhala mientras regresas lentamente a la posición inicial con control.","- Usar peso excesivo, lo que lleva a una forma inadecuada y una activación reducida del tríceps.","###","- Seleccione un peso moderado que permita un movimiento controlado.","- Exhala mientras empujas la barra hacia abajo extendiendo los codos por completo.","- Haga una breve pausa en la parte inferior para maximizar la participación de los tríceps.","- Repetir Realice el número deseado de repeticiones manteniendo la forma adecuada.","- Ejecución Exhale mientras empuja la barra hacia abajo extendiendo los codos por completo. Mantenga las muñecas en posición neutra y los codos inmóviles. Baje el mango hasta que los brazos estén completamente extendidos pero no bloqueados. Haga una breve pausa en la parte inferior para maximizar el compromiso de los tríceps. Inhale mientras regresa lentamente a la posición inicial con control.","- Baje la manija hasta que sus brazos estén completamente extendidos pero no bloqueados.","- Muévase con movimiento controlado en lugar de utilizar el impulso.","- No extender completamente los codos, limitando el rango de movimiento y la activación muscular.","- Realice el número deseado de repeticiones manteniendo la forma adecuada.","- Involucre sus músculos centrales para mayor estabilidad.","- Seleccione un peso apropiado que permita un rango completo de movimiento.","### Errores comunes a evitar","- Usar peso excesivo, lo que lleva a una forma inadecuada y reduce la activación de los tríceps. Ensanchar los codos hacia afuera, lo que desvía la atención de los tríceps. Inclinarse demasiado hacia adelante, lo que reduce la efectividad del ejercicio. Extender demasiado las muñecas, lo que puede causar tensión. No extender completamente los codos, lo que limita el rango de movimiento y la activación muscular.","- Mantenga los codos cerca del torso y dóblelos en un ángulo de 90 grados.","- Mantenga las muñecas neutrales y los codos estacionarios.","### Consejos para una forma adecuada","- Mantenga los codos doblados hacia adentro para aislar los tríceps de manera efectiva.","- Mantenga la columna neutra y evite inclinarse hacia adelante.","- Ensanchando los codos hacia afuera, lo que desvía la atención de los tríceps.","- Inclinarse demasiado hacia adelante, reduciendo la efectividad del ejercicio.","- Extender demasiado las muñecas, lo que puede provocar tensión."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0b75c77b-c0de-4e80-babe-0b75c77b0000', 'Ejercicio unilateral en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/One-Arm-Reverse-Push-Down.gif', '{"Configure el equipo Coloque una sola manija en la polea alta de una máquina de cable. Seleccione un peso moderado que permita un movimiento controlado.","Conecte una sola manija a la polea alta de una máquina de cable.","ColóquesePárate con los pies separados al ancho de los hombros para mantener el equilibrio.Agarra el mango con la mano hacia abajo (con la palma hacia arriba).Mantén el codo cerca del torso y la muñeca recta.","Párese con los pies separados a la altura de los hombros para mantener el equilibrio.","Agarre el mango con la palma hacia arriba.","Inhala mientras regresas lentamente a la posición inicial con control.","Haga una breve pausa en la parte inferior para involucrar completamente el tríceps.","EjecuciónExhale mientras empuja el mango hacia abajo extendiendo el codo por completo. Mantenga el codo inmóvil y evite movimientos excesivos de la muñeca. Baje el mango hasta que el brazo esté completamente extendido pero no bloqueado. Haga una breve pausa en la parte inferior para enganchar completamente los tríceps. Inhale mientras regresa lentamente a la posición inicial con control.","Baje la manija hasta que su brazo esté completamente extendido pero no bloqueado.","Repetir Realice el número deseado de repeticiones antes de cambiar de brazo.","Mantenga el codo cerca del torso y la muñeca recta."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1d30bbb0-c0de-4e80-babe-1d30bbb00000', 'Aperturas de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Pec-Deck-Fly.gif', '{"Ajuste la máquina: coloque el asiento de modo que las manijas queden al nivel del pecho. Para comenzar, ajuste las almohadillas para los brazos de modo que sus brazos queden ligeramente detrás de su torso.","Siéntese erguido: coloque los pies planos, con la espalda presionada contra la almohadilla y agarre las manijas o apoye los antebrazos contra las almohadillas (según el tipo de máquina).","Establezca la posición de los brazos: Mantenga los codos ligeramente doblados para proteger las articulaciones.","Inicie el movimiento: exhale y junte los brazos frente a su pecho en un movimiento de abrazo. Concéntrate en contraer los músculos del pecho al máximo.","Regrese con control: invierta lentamente el movimiento hasta que sienta un leve estiramiento en el pecho. Evite dejar que las pesas golpeen o se estiren demasiado."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4f54ae07-c0de-4e80-babe-4f54ae070000', 'Fondos', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Triceps-Dips.gif', '{"- Configure su posición Agarre las barras paralelas con las manos ligeramente más separadas que el ancho de los hombros. Extienda completamente los brazos y apoye el peso de su cuerpo por encima de las barras.","- Agarre las barras paralelas con las manos ligeramente más separadas que el ancho de los hombros.","- Extiende completamente los brazos y apoya el peso de tu cuerpo por encima de las barras.","- Exhala mientras presionas con las palmas para extender los brazos y volver a la posición inicial.","###","### Usar barras paralelas o una estación de fondos","- Haga una breve pausa en la parte inferior, asegurando la participación completa de los tríceps.","- Repetir Realice el número deseado de repeticiones manteniendo la forma adecuada.","- Coloque su cuerpo Mantenga el pecho ligeramente hacia adelante y active su núcleo. Doble las rodillas o extienda las piernas rectas, según su comodidad y nivel de dificultad.","- Doble las rodillas o extienda las piernas rectas, según su comodidad y nivel de dificultad.","- Ejecución Inhale mientras baja el cuerpo doblando los codos hasta que la parte superior de los brazos quede paralela al suelo. Mantenga los codos cerca del torso y evite abrirlos hacia afuera. Haga una breve pausa en la parte inferior, asegurando el compromiso completo de los tríceps. Exhale mientras presiona con las palmas para extender los brazos y regresar a la posición inicial.","- Inhale mientras baja el cuerpo doblando los codos hasta que la parte superior de sus brazos quede paralela al suelo.","- Bájese con un movimiento controlado para evitar tensiones articulares innecesarias.","- Respira adecuadamente, inhalando mientras bajas y exhalando mientras empujas hacia arriba.","- No bajar lo suficiente, limitando el rango de movimiento y la efectividad.","- Usar el impulso, en lugar de movimientos controlados para el compromiso muscular.","- Realice el número deseado de repeticiones manteniendo la forma adecuada.","- Involucre su núcleo y glúteos para mantener la estabilidad.","- Evite bloquear los codos en la parte superior del movimiento.","### Errores comunes a evitar","- Inclinarse demasiado hacia adelante, lo que hace que la atención se centre en el pecho en lugar de en los tríceps.","- Mantenga su pecho ligeramente hacia adelante y active su núcleo.","- Mantenga los codos cerca del torso y evite abrirlos hacia afuera.","### Consejos para una forma adecuada","- Mantenga los codos doblados hacia adentro en lugar de dejar que se abran hacia afuera.","- Ensanchando los codos hacia afuera, reduciendo la activación de los tríceps y aumentando el riesgo de lesiones.","- Bloquear los codos, lo que puede generar una tensión excesiva en las articulaciones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0d9442f4-c0de-4e80-babe-0d9442f40000', 'Fondos entre bancos', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Bench-Dips.gif', '{"- Configure su posición Siéntese en el borde de un banco resistente o de una superficie elevada. Coloque las manos junto a las caderas y sujete el banco con los dedos apuntando hacia adelante.","- Siéntese en el borde de un banco resistente o de una superficie elevada.","- Coloque sus manos al lado de sus caderas, agarrando el banco con los dedos apuntando hacia adelante.","- Coloque sus pies Coloque sus piernas en un banco alto. Mantenga las rodillas dobladas a 90 grados con los pies apoyados en el piso para una versión más fácil.","- Coloque las piernas sobre un banco alto.","- Ejecución Deslice las caderas fuera del banco, soportando su peso con los brazos. Baje el cuerpo doblando los codos hasta que formen un ángulo de 90 grados. Mantenga los codos cerca del torso y mantenga el control durante todo el movimiento. Presione con las palmas para extender los brazos y volver a la posición inicial.","- Desliza las caderas fuera del banco, apoyando tu peso con los brazos.","- Presione con las palmas para extender los brazos y volver a la posición inicial.","###","- Mantenga los codos cerca del torso y mantenga el control durante todo el movimiento.","- Repetir Realice el número deseado de repeticiones manteniendo la forma adecuada.","- Realice el número deseado de repeticiones manteniendo la forma adecuada.","- Baje el cuerpo doblando los codos hasta que formen un ángulo de 90 grados.","- Bájese con un movimiento controlado para evitar tensiones innecesarias.","- Respire constantemente, exhalando al subir e inhalando al bajar.","- Utilizar el impulso, en lugar de controlar el movimiento.","- Involucre su núcleo y glúteos para mantener la estabilidad.","- Evite bloquear los codos en la parte superior del movimiento.","### Errores comunes a evitar","- Bajar demasiado, lo que puede tensar los hombros.","- Permitir que los codos se abran hacia afuera, reduciendo la activación de los tríceps.","- Mantenga las rodillas dobladas a 90 grados con los pies apoyados en el suelo para una versión más fácil.","### Consejos para una forma adecuada","- Mantenga los codos metidos hacia adentro en lugar de abrirlos hacia afuera.","- Redondear los hombros, lo que provoca una mala postura y posibles lesiones.","- Bloquear los codos, lo que puede generar una tensión excesiva en las articulaciones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('422c4980-c0de-4e80-babe-422c49800000', 'Ejercicio en polea', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Cable-Upper-Chest-Crossovers.gif', '{"Ajuste los cables: Ajuste los cables a la posición más alta en ambos lados de la máquina de cable. Conecte las manijas a cada cable.","Párese en el centro: Párese en el centro de la máquina, de espaldas a ella. Sostenga las manijas con las palmas hacia abajo.","Colóquese: dé un paso hacia adelante con una pierna o inclínese ligeramente hacia adelante, manteniendo los pies separados al ancho de los hombros. Tus brazos deben estar extendidos a los lados, paralelos al suelo.","Regreso a la posición inicial: Baja lentamente las asas hasta la posición inicial, manteniendo los brazos ligeramente flexionados.","Cruza las manijas: lentamente acerca ambas manijas, cruzándolas frente a tu cuerpo. Tus brazos deben estar ligeramente doblados a la altura del codo.","Aprieta tu pecho: haz una pausa por un momento y aprieta los músculos del pecho.","Repetir: Repita el ejercicio durante el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4fd469ed-c0de-4e80-babe-4fd469ed0000', 'Ejercicio con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dumbbell-Pullover.gif', '{"- Agarre la mancuerna: sostenga una mancuerna con ambas manos debajo de la placa interior, con los brazos extendidos sobre el pecho.","- Conduzca a través de sus dorsales o pecho en el regreso; no se limite a mover el peso hacia atrás.","- Usar un peso demasiado pesado y dejar que el impulso haga el trabajo.","- Perder el control del agarre: siempre asegure firmemente la mancuerna con ambas manos.","###","- Configuración: Acuéstese en un banco plano con solo la parte superior de la espalda y los hombros apoyados. Mantenga los pies apoyados en el suelo.","- Comience ligero para aprender el camino correcto y el control de los hombros.","- Prepárese y baje: Inhale, fortalezca su núcleo y lentamente arquee la mancuerna hacia atrás y hacia abajo detrás de su cabeza. Mantenga una ligera flexión de los codos.","- Estiramiento y retorno: una vez que sienta un estiramiento en los dorsales y el pecho, invierta el movimiento tirando de la mancuerna hacia atrás sobre el pecho usando los dorsales o el pecho.","- Finalizar controlado: exhale en la parte superior y repita para las repeticiones deseadas con un movimiento suave y controlado.","- Baje la mancuerna solo hasta donde pueda controlar sin hiperextender la columna.","- Rango de movimiento incompleto, especialmente en la fase de estiramiento.","### Errores comunes","- Arquear la zona lumbar, lo que aleja la tensión de los músculos objetivo.","### Consejos para una forma adecuada","- Mantenga los codos ligeramente doblados para reducir la tensión en las articulaciones.","- Mantenga la caja torácica baja si desea una mayor activación de los dorsales; permita un ligero arco para enfocar el pecho.","- Doblar demasiado los codos, convirtiéndolo en una extensión de tríceps."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5252cfcd-c0de-4e80-babe-5252cfcd0000', 'Ejercicio en polea', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Low-Cable-Crossover.gif', '{"Comience configurando la máquina de cable en la configuración más baja y colocando una manija a cada lado.","Párese en el centro de la máquina de cable con los pies separados a la altura de los hombros y mirando hacia la máquina. Agarre un asa en cada mano y llévelas hasta la altura de los hombros. Esta es la posición inicial.","Haga una pausa por un momento, luego libere lentamente la tensión y regrese a la posición inicial.","Da un paso hacia adelante con un pie, manteniendo las rodillas ligeramente dobladas e inclínate hacia adelante por la cintura manteniendo la espalda recta.","Con una ligera flexión de los brazos, lleve las pesas hacia arriba y hacia la línea media de su cuerpo. Asegúrate de mantener los codos ligeramente doblados durante todo el movimiento.","Tus manos deben terminar a los lados, justo debajo de tus caderas.","Repita hasta el número deseado de repeticiones, luego cambie de lado y repita con el otro brazo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7a1b0c8c-c0de-4e80-babe-7a1b0c8c0000', 'Aperturas de pecho con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dumbbell-Fly.gif', '{"- Acuéstese en un banco.","- Sostenga una mancuerna en cada mano con un agarre neutral (con las palmas una frente a la otra).","- Invierta el movimiento apretando los músculos del pecho y volviendo a subir las mancuernas en el mismo arco hasta la posición inicial.","###","- Concéntrese en sentir un estiramiento en los músculos del pecho sin estirar demasiado ni comprometer la estabilidad del hombro.","- Extienda los brazos rectos por encima del pecho, manteniendo los codos ligeramente doblados para reducir la tensión en las articulaciones.","- Baje lentamente las mancuernas formando un arco amplio, manteniendo la ligera flexión de los codos. Tus brazos deben moverse hacia afuera y hacia abajo hasta que estén al nivel de tu pecho o ligeramente por debajo.","- Concéntrese en un movimiento controlado para maximizar el estiramiento y la contracción.","- Utilice pesas ligeras a moderadas para mantener el control y evitar forzar los hombros.","### Consejos para el entrenador:","- Evite bloquear los codos o dejar que los brazos caigan demasiado por debajo del nivel del pecho."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1172a34b-c0de-4e80-babe-1172a34b0000', 'Press de pecho inclinado con barra', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Incline-Barbell-Bench-Press.gif', '{"Configure el banco inclinado en el ángulo deseado. (30 a 45 grados)","Cargue la barra con un peso adecuado para su nivel de condición física y sus objetivos.","Acuéstate en el banco con los pies firmemente apoyados en el suelo y la cabeza apoyada en el banco.","Agarre la barra con un agarre ligeramente más ancho que el ancho de los hombros.","Presione la barra hacia arriba hasta la posición inicial, exhalando mientras empuja.","Quita la barra y bájala hasta la parte superior del pecho, con los codos extendidos hacia los lados.","Repita para el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('13dac963-c0de-4e80-babe-13dac9630000', 'Ejercicio en polea', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Cable-Crossover.gif', '{"Ajuste las poleas a la altura deseada:","Coloque manijas en D a cada polea.","Polea alta: apunta a la parte inferior del pecho.","Polea media: trabaja la parte media del pecho.","Polea baja: involucra la parte superior del pecho."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('65756f78-c0de-4e80-babe-65756f780000', 'Press de pecho unilateral en polea', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/12/One-Arm-Cable-Chest-Press.gif', '{"Ajustar la máquina de cables: Comience ajustando la máquina de cables para que el mango quede a la altura del pecho.","Regrese lentamente a la posición inicial: regrese lentamente el mango a su pecho y repita hasta el número deseado de repeticiones.","Colóquese: dé un paso hacia adelante con un pie y mantenga los pies separados a la altura de los hombros. Sostenga el mango con una mano y llévelo hacia su pecho.","Involucra tu núcleo: Involucra tus músculos centrales para mantener tu torso estable durante todo el ejercicio.","Empuje la manija: presione la manija hacia adelante hasta que su brazo esté completamente extendido pero no bloqueado. Mantenga el codo cerca del cuerpo y evite torcer el torso.","Cambie de lado: una vez que haya completado el número deseado de repeticiones, cambie de lado y repita el ejercicio con el otro brazo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('559834af-c0de-4e80-babe-559834af0000', 'Fondos', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Lever-Overhand-Triceps-Dip.gif', '{"- Configuración: Ajuste la altura del asiento para que sus brazos queden cómodamente colocados en las manijas. Siéntese y coloque los pies apoyados en el piso o en el reposapiés designado. Sujete las manijas firmemente de acuerdo con el diseño de la máquina.","- Ajuste la altura del asiento para que sus brazos queden cómodamente colocados en las manijas.","- Siéntese y coloque los pies apoyados en el suelo o en el reposapiés designado.","- Sujete firmemente las manijas según el diseño de la máquina.","- Posición inicial: Mantenga el pecho ligeramente inclinado hacia adelante mientras mantiene la espalda recta. Involucre su núcleo y coloque los codos en un ángulo de aproximadamente 90 grados.","- Involucre su núcleo y coloque sus codos en un ángulo de aproximadamente 90 grados.","- Regrese lentamente a la posición inicial con movimientos controlados para mantener la tensión muscular.","- Utilice un peso que le permita completar cada repetición con la forma adecuada.","###","- Presione hacia abajo las manijas extendiendo los codos y levantando el cuerpo contra la resistencia.","- Realice de 10 a 15 repeticiones por serie, dependiendo de su nivel de condición física.","- Avoid using excessive momentum to push the weight down.","- Ejecución: Presione hacia abajo las manijas extendiendo los codos, levantando el cuerpo contra la resistencia. Extienda completamente los brazos en la parte inferior para enganchar los tríceps por completo. Regrese lentamente a la posición inicial con movimientos controlados para mantener la tensión muscular.","- Extienda completamente los brazos en la parte inferior para enganchar completamente los tríceps.","- Repeticiones y respiración: realice de 10 a 15 repeticiones por serie, dependiendo de su nivel de condición física. Inhale mientras baja y exhale mientras presiona hacia abajo.","- Inhala mientras vuelves a bajar y exhala mientras presionas hacia abajo.","- Control the movement throughout the entire range of motion.","- Maintain a neutral spine and avoid excessive forward leaning.","### Errores comunes:","- Codos ensanchados: reduce el compromiso de los tríceps y aumenta la tensión en los hombros.","- Usar demasiado impulso: limita la efectividad del ejercicio al reducir la activación muscular.","- No extender completamente los brazos: evita la contracción completa del tríceps, lo que reduce la participación de los músculos.","- Mantenga el pecho ligeramente inclinado hacia adelante mientras mantiene la espalda recta.","### Consejos para una forma adecuada:","- Mantenga los codos cerca del cuerpo para maximizar la activación de los tríceps.","- Inclinarse demasiado hacia adelante: cambia el enfoque hacia el pecho en lugar de aislar los tríceps.","- Lifting Too Heavy: Can compromise form and increase injury risk."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('307e4dcf-c0de-4e80-babe-307e4dcf0000', 'Extensión de tríceps acostado', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/One-Arm-Lying-Triceps-Extension.gif', '{"- Configuración: Acuéstese en un banco o en el piso con la espalda completamente apoyada. Sostenga una mancuerna en una mano con un agarre neutral o supinado (con la palma hacia arriba). Extienda el brazo recto por encima del hombro.","- Acuéstese sobre un banco o en el suelo con la espalda totalmente apoyada.","- Sostenga una mancuerna en una mano con un agarre neutral o supinado (con la palma hacia arriba).","- Involucre sus tríceps para extender su brazo de regreso a la posición inicial.","- Utilice un peso moderado que permita una forma adecuada sin tensión excesiva.","- Involucre su núcleo para mantener la estabilidad mientras está acostado en el banco.","- Uso de peso excesivo: compromete la forma y aumenta el riesgo de lesiones.","- No controlar la fase excéntrica: bajar el peso demasiado rápido minimiza la activación muscular.","###","- Extiende tu brazo recto por encima de tu hombro.","- Fase de levantamiento: active el tríceps para extender el brazo de regreso a la posición inicial. Mantenga el control durante todo el movimiento, evitando movimientos rápidos o bruscos. Extienda completamente el codo, pero sin bloquearlo.","- Doble lentamente el codo para bajar la mancuerna hacia la frente o justo detrás de la cabeza.","- Extienda completamente el codo pero no lo bloquee.","- Inhala mientras bajas la mancuerna y exhala mientras extiendes el brazo.","- Baje la mancuerna con control para evitar forzar la articulación del codo.","- Realice el ejercicio en un rango completo de movimiento para una activación muscular óptima.","- Acelerar el movimiento: Reduce el tiempo bajo tensión, limitando el compromiso muscular.","- Mantenga el control durante todo el movimiento, evitando movimientos rápidos o bruscos.","### Errores comunes:","- Ensanchar el codo: reduce el aislamiento del tríceps y puede provocar tensión en el hombro.","- Fase de descenso: Doble lentamente el codo para bajar la mancuerna hacia la frente o justo detrás de la cabeza. Mantenga la parte superior del brazo inmóvil y perpendicular al suelo. Evite ensanchar el codo hacia afuera; mantenlo alineado con tu hombro.","- Mantenga la parte superior del brazo inmóvil y perpendicular al suelo.","- Evite ensanchar el codo hacia afuera; mantenlo alineado con tu hombro.","- Repeticiones y respiración: realiza de 8 a 15 repeticiones por brazo, dependiendo de tus objetivos de entrenamiento. Inhala mientras bajas la mancuerna y exhala mientras extiendes el brazo.","- Realiza de 8 a 15 repeticiones por brazo, dependiendo de tus objetivos de entrenamiento.","### Consejos para una forma adecuada:","- Mantenga el codo fijo en su lugar para maximizar la activación del tríceps.","- Arquear la espalda baja: puede causar tensión innecesaria en la columna."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('51098ecd-c0de-4e80-babe-51098ecd0000', 'Extensión de tríceps en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Cable-Rope-Overhead-Triceps-Extension.gif', '{"- Configuración: Conecte el accesorio de cuerda a la polea de la máquina de cable. Párese de espaldas a la máquina y agarre la cuerda con ambas manos usando un agarre neutral (con las palmas una frente a la otra). Dé un paso ligeramente hacia adelante para crear tensión en el cable y coloque los pies separados al ancho de los hombros.","- Conecte el accesorio de cuerda a la polea de la máquina de cable.","- Párese de espaldas a la máquina y agarre la cuerda con ambas manos usando un agarre neutral (con las palmas una frente a la otra).","- Posición inicial: levante los brazos por encima de la cabeza, manteniendo los codos doblados y apuntando hacia adelante. Las manos deben estar detrás de la cabeza y el core debe estar comprometido para mantener la estabilidad.","- Elegir el peso incorrecto: el peso excesivo puede provocar una forma inadecuada, mientras que una resistencia muy pequeña puede no proporcionar suficiente estimulación muscular.","###","- Da un paso ligeramente hacia adelante para crear tensión en el cable y separa los pies a la altura de los hombros.","- Levanta los brazos por encima de la cabeza, manteniendo los codos doblados y apuntando hacia adelante.","- Tus manos deben estar detrás de tu cabeza y tu núcleo debe estar comprometido para mantener la estabilidad.","- Ejecución:Extiende los brazos completamente empujando la cuerda hacia arriba y hacia adelante hasta que los codos queden rectos.Aprieta los tríceps en la parte superior del movimiento para una contracción máxima.Baja lentamente la cuerda hasta la posición inicial, controlando el movimiento para mantener la tensión.","- Extienda los brazos completamente empujando la cuerda hacia arriba y hacia adelante hasta que los codos queden rectos.","- Aprieta tus tríceps en la parte superior del movimiento para lograr la máxima contracción.","- Inhala mientras bajas la cuerda y exhala mientras extiendes los brazos.","- Utilice un movimiento controlado para maximizar la participación de los tríceps.","- No extender completamente los brazos: Disminuye el compromiso de los tríceps y limita el rango de movimiento.","- Baje lentamente la cuerda hasta la posición inicial, controlando el movimiento para mantener la tensión.","- Evite el uso de peso excesivo que comprometa su forma.","- Extiende completamente los codos en la parte superior para activar los tríceps por completo.","### Errores comunes:","- Repeticiones y respiración: realiza de 10 a 15 repeticiones por serie, dependiendo de tus objetivos de entrenamiento. Inhala mientras bajas la cuerda y exhala mientras extiendes los brazos.","- Realiza de 10 a 15 repeticiones por serie, dependiendo de tus objetivos de entrenamiento.","### Consejos para una forma adecuada:","- Mantenga los codos cerca de la cabeza y evite abrirlos hacia afuera.","- Mantenga una columna neutral y active su núcleo para lograr estabilidad.","- Codos ensanchados: reduce el aislamiento del tríceps y aumenta la tensión en los hombros.","- Inclinarse demasiado hacia adelante: puede desviar la atención del tríceps y causar tensión en la parte baja de la espalda.","- Usar demasiado impulso: limita la activación muscular y reduce la eficacia."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('282a4bfa-c0de-4e80-babe-282a4bfa0000', 'Press inclinado con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Incline-Dumbbell-Press.gif', '{"Ajuste un banco a un ángulo de inclinación de 30 a 45 grados.","Toma una mancuerna en cada mano y siéntate en el banco, con los pies apoyados en el suelo.","Coloque las mancuernas con las palmas hacia adelante y los codos doblados a unos 90 grados.","Apoye las mancuernas sobre los muslos, luego recuéstese mientras lleva las pesas al nivel de los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('78fb6468-c0de-4e80-babe-78fb64680000', 'Aperturas de pecho inclinado con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Incline-dumbbell-Fly.gif', '{"Ajuste un banco a un ángulo de inclinación, generalmente de 30 a 45 grados.","Siéntese en el banco y coloque los pies apoyados en el suelo para mayor estabilidad.","Sostenga una mancuerna en cada mano con un agarre neutral (con las palmas una frente a la otra).","Recuéstese en el banco con las mancuernas sostenidas sobre el pecho, los brazos extendidos pero los codos ligeramente doblados."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7f5c8282-c0de-4e80-babe-7f5c82820000', 'Estiramiento', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Sphinx-Stretch.gif', '{"La Esfinge es una maravillosa postura de yoga para abrir la parte superior del cuerpo y ganar más fuerza y ​​movilidad en la parte media de la espalda y la columna torácica. Este movimiento fortalece los músculos erectores de la columna que brindan soporte a la columna. Unos músculos fuertes de la espalda pueden prevenir desviaciones posturales que provocan malas posturas y molestias, como la cifosis (“jorobada”). El movimiento de la esfinge mejora su postura al extender los músculos de la espalda y reducir la tensión entre la zona lumbar y las áreas centrales. También mejora la fuerza de la espalda baja, lo que facilita mantenerse erguido durante todo el día."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0aa2f622-c0de-4e80-babe-0aa2f6220000', 'Ejercicio de pie', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Standing-Rotation.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2b12daca-c0de-4e80-babe-2b12daca0000', 'Estiramiento', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Upper-Back-Stretch.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('024c4490-c0de-4e80-babe-024c44900000', 'Curl de bíceps unilateral en polea', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/One-Arm-Cable-Curl.gif', '{"- Comience conectando un accesorio de cable de un solo mango a la posición más baja de una máquina de cable.","- Párese de espaldas a la máquina de cable, con los pies separados a la altura de los hombros y las rodillas ligeramente dobladas.","- Sujete el mango con la palma hacia arriba y párese lo suficientemente lejos de la máquina de cable para que su brazo esté completamente extendido y haya tensión en el cable.","- Ajuste la altura de la polea para mantener un ángulo de resistencia cómodo.","- Usar demasiado peso, lo que reduce el control y aumenta la tensión en las articulaciones.","###","- Mantenga la contracción por un segundo, luego inhale y baje lentamente el mango hasta la posición inicial, manteniendo la tensión en el cable.","- Evite balancearse o utilizar el impulso del cuerpo para levantar el peso.","- Manteniendo el codo pegado al costado, exhale y doble el mango hacia el hombro, contrayendo los músculos del bíceps.","- No extender completamente el brazo en la parte inferior de la repetición, lo que reduce el rango de movimiento.","- Mantenga una posición neutra de la muñeca para lograr un movimiento suave del cable.","- Concéntrese en el descenso excéntrico controlado para maximizar la participación de los músculos.","### Errores comunes a evitar","- Repita hasta el número deseado de repeticiones, luego cambie de brazo y repita.","### Consejos para una forma adecuada","- Mantenga el codo fijo cerca de la caja torácica; no dejes que avance.","- Permitir que el hombro gire hacia adelante o que el codo se aleje del cuerpo.","- Sacudiendo o balanceando el torso para ayudar al levantamiento."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('00f4847b-c0de-4e80-babe-00f4847b0000', 'Press de pecho inclinado con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Reverse-Grip-Incline-Dumbbell-Press.gif', '{"Ajuste el banco a un ángulo de inclinación de 30 a 45 grados.","Coge un par de mancuernas y siéntate en el banco con los pies apoyados en el suelo.","Sostenga las mancuernas con agarre inverso (con las palmas hacia usted) y colóquelas al nivel de los hombros con los codos doblados."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6899fbf1-c0de-4e80-babe-6899fbf10000', 'Curl de muñeca unilateral en polea', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Cable-One-Arm-Wrist-Curl-On-Floor.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6d71b538-c0de-4e80-babe-6d71b5380000', 'Aperturas de pecho en máquina', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/10301301-Lever-Pec-Deck-Fly_Chest_720.gif', '{"- Ajuste la altura del asiento para que las manijas queden al nivel del pecho.","- Siéntese en la máquina con la espalda firmemente presionada contra la almohadilla.","- Sujete las manijas o las almohadillas con un agarre neutral (con las palmas hacia adentro).","- Inhala mientras regresas lentamente a la posición inicial, sintiendo un estiramiento en el pecho.","- Altura del asiento incorrecta: ajuste el asiento para alinear las manijas con la mitad de su pecho.","###","- Coloque los brazos doblados a la altura de los codos (mantenga esta flexión durante todo el ejercicio).","- Peso moderado: utilice un peso que permita la forma adecuada para todas las repeticiones sin sacrificar el control.","- Exhale mientras junta las manijas o las almohadillas frente a su pecho con un movimiento suave y controlado.","- Aprieta los músculos del pecho en el punto máximo del movimiento durante una breve pausa.","- Usando Momentum: Realice el movimiento lentamente para mantener la tensión en los músculos del pecho.","- Sobrecarga progresiva: aumente gradualmente el peso o las repeticiones para continuar desarrollando fuerza y ​​​​tamaño.","- Combínelo con ejercicios compuestos: combínelo con prensas y fondos para un entrenamiento de pecho completo.","- Repita hasta el número deseado de repeticiones.","### Consejos para la eficacia","- Apriete en la parte superior: concéntrese en contraer los músculos del pecho al juntar las manijas.","- Bloqueo de los codos: Mantenga los codos doblados para evitar tensiones articulares innecesarias.","- Estiramiento excesivo: evite bajar los brazos demasiado hacia atrás, lo que puede tensar los hombros.","### Errores comunes"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1148aa16-c0de-4e80-babe-1148aa160000', 'Ejercicio de pie', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Lever-Standing-Rear-Kick.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5bff7a07-c0de-4e80-babe-5bff7a070000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Barbell-Good-Morning.gif', '{"Cuando se hace correctamente, un buen ejercicio matutino es eficaz para fortalecer la espalda y hacerla más flexible. Sin embargo, si acabas de empezar, se recomienda probar el movimiento con peso vacío.","Un buen ejercicio matutino es un movimiento de la bisagra de la cadera que ayuda a fortalecer los glúteos y las piernas al enfocarse en la espalda, los isquiotibiales, los glúteos y los aductores."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5f60e9b7-c0de-4e80-babe-5f60e9b70000', 'Extensión de tríceps acostado con barra', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Barbell-Triceps-Extension.gif', '{"- Configuración: Acuéstese en un banco plano con los pies firmemente plantados en el suelo. Sostenga una barra con un agarre por encima de la cabeza, separada al ancho de los hombros. Extienda los brazos completamente por encima del pecho, manteniendo los codos ligeramente doblados para evitar la tensión en las articulaciones.","- Acuéstese en un banco plano con los pies firmemente plantados en el suelo.","- Sostenga una barra con un agarre por encima de la cabeza, separada al ancho de los hombros.","- Exhala y extiende los codos para empujar la barra hacia la posición inicial.","- Utilice un observador o un peso adecuado para evitar la pérdida de control.","- Uso de peso excesivo: puede provocar una forma inadecuada y posibles lesiones.","###","- Mantenga los codos inmóviles y apuntando hacia arriba durante todo el movimiento.","- Concéntrate en contraer los tríceps mientras estiras los brazos.","- Mantener la respiración controlada durante todo el movimiento.","- Mantenga los codos en una posición fija para maximizar la activación de los tríceps.","- Extienda los brazos completamente por encima del pecho, manteniendo los codos ligeramente doblados para evitar tensión en las articulaciones.","- Fase de descenso: Inhale y baje lentamente la barra hacia la frente doblando los codos. Mantenga los codos inmóviles y apuntando hacia arriba durante todo el movimiento. Baje la barra hasta que esté justo encima de la frente o ligeramente detrás de la cabeza.","- Inhala y baja lentamente la barra hacia tu frente doblando los codos.","- Baje la barra hasta que esté justo encima de su frente o ligeramente detrás de su cabeza.","- Fase de levantamiento: Exhale y extienda los codos para empujar la barra hacia la posición inicial. Concéntrese en contraer los tríceps mientras estira los brazos. Evite bloquear los codos en la parte superior para mantener la tensión muscular.","- Baje la barra de forma lenta y controlada para evitar tensiones innecesarias.","- Mantenga una posición neutra de la muñeca para reducir la tensión en las articulaciones.","- Involucre su núcleo para estabilizar su cuerpo durante el ejercicio.","### Errores comunes:","- Permitir que los codos se ensanchen: reduce el compromiso de los tríceps y aumenta la tensión en los hombros.","- Evite bloquear los codos en la parte superior para mantener la tensión muscular.","- Repeticiones y respiración: Realiza de 8 a 12 repeticiones por serie, dependiendo de tu objetivo de entrenamiento. Mantén la respiración controlada durante todo el movimiento.","- Realiza de 8 a 12 repeticiones por serie, dependiendo de tu objetivo de entrenamiento.","### Consejos para una forma adecuada:","- Bajar la barra demasiado rápido: aumenta el riesgo de golpearse la cabeza o perder el control.","- No extenderse completamente: Previene la contracción máxima y reduce la efectividad.","- Arquear la zona lumbar: puede causar molestias y reducir la estabilidad."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('315c7e29-c0de-4e80-babe-315c7e290000', 'Extensión de espalda', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Weighted-Back-Extension.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('66030c57-c0de-4e80-babe-66030c570000', 'Ejercicio en polea', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Single-Arm-Cable-Crossover.gif', '{"Configure la máquina de cable. Ajuste la polea a la altura de los hombros. Coloque una manija única en la polea y seleccione un peso apropiado.","Coloque una sola manija en la polea y seleccione un peso apropiado.","PosiciónesePárese con los pies escalonados para mantener el equilibrio. Sujete el mango con una mano y aléjese ligeramente de la máquina para crear tensión en el cable.","Realiza el MovimientoComience con el brazo extendido hacia el costado a la altura del hombro. Tire con control del mango frente a su cuerpo, apretando el pecho en el punto máximo. Regrese lentamente a la posición inicial manteniendo la tensión en el cable.","Tire de la manija frente a su cuerpo con control, apretando su pecho en la cima.","Comienza con el brazo extendido hacia un lado a la altura del hombro.","Involucre su núcleo Apriete los músculos abdominales para estabilizar su cuerpo. Mantenga los hombros hacia abajo y hacia atrás para mantener una postura adecuada.","Repetir Complete el número deseado de repeticiones antes de cambiar al otro brazo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('25eebc29-c0de-4e80-babe-25eebc290000', 'Press de pecho inclinado', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Lever-Incline-Chest-Press.gif', '{"- Ajuste el asiento: ajuste la altura del asiento de modo que las manijas queden alineadas con su pecho. Esto es importante para garantizar que la prensa apunte eficazmente a la parte superior del pecho.","- Agarre las manijas: siéntese en la máquina con la espalda firmemente contra la almohadilla. Sujete las manijas con las palmas hacia adelante (generalmente, la máquina tiene agarres neutrales o en pronación).","- Coloque sus pies: Coloque sus pies apoyados en el piso para mayor estabilidad.","- Elija el peso: seleccione el peso apropiado que pueda controlar en todo el rango de movimiento.","- Conexión mente-músculo: concéntrese en apretar el pecho en la parte superior de cada repetición para maximizar la activación de los músculos pectorales.","### Errores comunes","- Presione las manijas hacia arriba: empuje las manijas hacia adelante con un movimiento controlado, extendiendo completamente los brazos sin bloquear los codos.","- Aprieta en la parte superior: en la cima del movimiento, aprieta brevemente el pecho para maximizar la participación de los músculos.","- Baje lentamente: lleve lentamente las manijas hacia su pecho, sintiendo un estiramiento en la parte superior del pecho y los hombros.","- Repetir: realice la cantidad deseada de repeticiones, enfocándose en mantener un movimiento controlado en todo momento.","- Tempo controlado: realice el ejercicio con un ritmo lento para mantener una tensión constante en los músculos del pecho, lo que mejora el crecimiento muscular.","- Rango completo de movimiento: asegúrese de presionar completamente sin bloquear los codos y lleve las manijas hacia su pecho para un estiramiento completo.","- Extensión excesiva: evite bloquear los codos en la parte superior del movimiento. Esto puede generar una tensión innecesaria en las articulaciones.","- Demasiado peso: el uso de pesos excesivos puede comprometer la forma y aumentar el riesgo de lesiones. Concéntrate en las repeticiones y la forma controladas.","### Consejos para la eficacia","- Movimiento apresurado: Evite movimientos rápidos o bruscos. Los movimientos lentos y controlados maximizan la activación muscular y reducen el riesgo de lesiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('408abaca-c0de-4e80-babe-408abaca0000', 'Sentadilla con barra', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Barbell-sumo-squat.gif', '{"- Coloque los pies más anchos que el ancho de los hombros, con los dedos girados unos 30 grados.","- Utilice un agarre cómodo sobre la barra, manteniendo los codos apuntando hacia abajo.","###","- Coloca una barra en tus trapecios superiores en una rejilla para sentadillas y párate debajo de ella con una postura amplia.","- Desciende hasta que tus muslos queden paralelos al suelo o ligeramente por debajo si la movilidad lo permite.","- Conduce a través de los talones y la parte media del pie para volver a pararte, apretando los glúteos en la parte superior.","- Mantenga el pecho alto y la columna recta durante todo el movimiento.","- Baje las caderas hacia abajo, manteniendo las rodillas alineadas con los dedos de los pies.","- No utilizar un rango completo de movimiento, lo que limita la activación muscular.","- Apoye su núcleo para sostener su espalda baja.","- Concéntrate en separar el suelo con los pies para enganchar la parte interna de los muslos.","### Errores comunes","- Dejar que las rodillas colapsen hacia adentro, lo que reduce el compromiso interno del muslo.","- Apoye su núcleo y mantenga su pecho erguido mientras quita la barra y da un paso atrás.","### Consejos para una forma adecuada","- Mantenga las rodillas sobre los dedos de los pies para evitar la tensión en las rodillas.","- Inclinarse demasiado hacia adelante, generando tensión en la zona lumbar.","- Redondear la espalda, especialmente bajo carga pesada.","- Colocar la barra demasiado alta o demasiado baja provocando desequilibrio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5bf385ba-c0de-4e80-babe-5bf385ba0000', 'Sentadilla con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Dumbbell-Bulgarian-Split-Squat.gif', '{"- Párese aproximadamente a dos pies frente a un banco o escalón, sosteniendo una mancuerna en cada mano a los costados.","- Coloque el pie trasero sobre el banco con la parte superior del pie apoyada sobre él.","- Empuja con el talón de tu pie delantero para volver a la posición inicial.","### Paso 1: configuración y posicionamiento","- Desciende hasta que tu muslo delantero esté paralelo al suelo o ligeramente por debajo, asegurándote de que tu rodilla no pase los dedos de los pies.","### Paso 2: Ejecución","- Baje la rodilla trasera hacia el suelo mientras mantiene la rodilla delantera alineada con los dedos de los pies.","- Realice de 8 a 12 repeticiones por pierna, luego cambie de lado.","- Mantenga el pie delantero plantado firmemente, con los dedos apuntando hacia adelante y la postura separada a la altura de las caderas.","- Involucre su núcleo y mantenga su pecho erguido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1e80d19e-c0de-4e80-babe-1e80d19e0000', 'Ejercicio', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Hand-Gripper.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('122a0cca-c0de-4e80-babe-122a0cca0000', 'Press de pecho', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/push-press-1.gif', '{"Párese con los pies separados a la altura de los hombros. Los dedos de los pies deben estar ligeramente hacia afuera. Coloque la barra sobre la parte superior del pecho, justo debajo del cuello. Si usa mancuernas, sostenga una en cada mano a la altura de los hombros con las palmas hacia adelante.","Párese con los pies separados a la altura de los hombros. Los dedos de tus pies deben estar ligeramente hacia afuera.","Coloque la barra sobre la parte superior de su pecho, justo debajo de su cuello. Si usa mancuernas, sostenga una en cada mano a la altura de los hombros con las palmas hacia adelante.","Posición de la rejilla: levante la barra de la rejilla o límpiela hasta los hombros si comienza desde el suelo. Mantenga los codos ligeramente por delante de la barra y la parte superior de los brazos paralela al suelo. Esta es tu posición inicial.","Mientras te sumerges, concéntrate en mantener el peso equilibrado en la parte media del pie y los talones.","Regreso: Baje la barra hasta la posición inicial doblando las rodillas y las caderas. Deje que el peso descienda bajo control.","Coloque la barra: si usa una barra, colóquela nuevamente sobre los soportes o el suelo.","Si usa una barra, colóquela sobre los soportes o el suelo.","Configuración: Párese con los pies separados a la altura de los hombros. Los dedos de los pies deben estar ligeramente hacia afuera. Coloque la barra sobre la parte superior del pecho, justo debajo del cuello. Si usa mancuernas, sostenga una en cada mano a la altura de los hombros con las palmas hacia adelante.","Agarre: Para el press de empuje con barra, su agarre debe ser ligeramente más ancho que el ancho de los hombros. Agarre la barra con las palmas hacia adelante y los codos apuntando hacia abajo. Asegúrese de que sus muñecas estén alineadas con sus antebrazos. Si usa mancuernas, sujételas firmemente con las palmas una frente a la otra.","Levante la barra de la rejilla o límpiela hasta los hombros si comienza desde el suelo.","Impulso: Extienda explosivamente las caderas y las rodillas para generar un impulso hacia arriba. Este movimiento debe ser potente y rápido. Mientras conduces hacia arriba, presiona la barra sobre tu cabeza usando la fuerza de tus hombros y tríceps. Si usa mancuernas, presiónelas sobre la cabeza simultáneamente.","Bloqueo: Extienda completamente los brazos por encima de la cabeza, bloqueando los codos. Tu cabeza debe moverse ligeramente hacia adelante cuando la barra pasa por tu frente.","Para el press de hombros con barra, el agarre debe ser ligeramente más ancho que el ancho de los hombros. Agarre la barra con las palmas hacia adelante y los codos apuntando hacia abajo. Asegúrese de que sus muñecas estén alineadas con sus antebrazos.","Inmersión: Comience doblando ligeramente las rodillas para iniciar una inmersión. Mantenga el torso erguido y el pecho elevado. Mientras se inclina, concéntrese en mantener el peso equilibrado en la parte media del pie y los talones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('066532fe-c0de-4e80-babe-066532fe0000', 'Fondos', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Triceps-dips-on-floors.gif', '{"- Posición inicial: Siéntese en el suelo con las rodillas dobladas y los pies apoyados en el suelo. Coloque las manos detrás de usted, un poco más anchas que el ancho de los hombros, con los dedos apuntando hacia adelante o ligeramente hacia afuera. Levante las caderas del suelo para que sus brazos soporten el peso de la parte superior del cuerpo.","- Coloque las manos detrás de usted, un poco más anchas que el ancho de los hombros, con los dedos apuntando hacia adelante o ligeramente hacia afuera.","- Levante las caderas del suelo para que sus brazos soporten el peso de la parte superior del cuerpo.","- Empuja con las palmas y estira los brazos para volver a la posición inicial.","- Siéntate en el suelo con las rodillas dobladas y los pies apoyados en el suelo.","- Evite bloquear los codos en la parte superior del movimiento para evitar tensiones.","- Involucre su núcleo para mantener la estabilidad durante todo el ejercicio.","- Muévase lentamente y con control para maximizar la participación de los músculos.","- Ejecución: Baje lentamente el cuerpo doblando los codos hasta que los tríceps queden paralelos al suelo o ligeramente por debajo. Mantenga los codos cerca del cuerpo para maximizar la activación de los tríceps. Empuje con las palmas y estire los brazos para volver a la posición inicial. Repita el número deseado de repeticiones.","- Baje lentamente el cuerpo doblando los codos hasta que los tríceps queden paralelos al suelo o ligeramente por debajo.","- Repeticiones y respiración: realice de 10 a 15 repeticiones por serie. Inhale mientras baja el cuerpo y exhale mientras empuja hacia arriba.","- Inhala mientras bajas el cuerpo y exhala mientras vuelves a subir.","### Errores comunes:","- No bajar lo suficiente: Reduce el compromiso de los tríceps y limita la efectividad del ejercicio.","- Uso de Momentum: rebotar hacia arriba y hacia abajo minimiza la activación muscular y aumenta el riesgo de lesiones.","- Codos ensanchados: desvía la atención del tríceps y puede tensar los hombros.","- Mantenga los codos cerca del cuerpo para maximizar la activación de los tríceps.","- Repita hasta el número deseado de repeticiones.","- Realiza de 10 a 15 repeticiones por serie.","### Consejos para una forma adecuada:","- Mantenga los codos apuntando hacia atrás en lugar de extenderse hacia los lados.","- Mantenga los hombros bajos y alejados de las orejas para evitar la acumulación de tensión.","- Hombros encorvados: conduce a una mala postura y a una tensión innecesaria en el cuello.","- Colocación incorrecta de las manos: Las manos demasiado atrás o demasiado juntas pueden causar molestias en la muñeca."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1d4ae6b9-c0de-4e80-babe-1d4ae6b90000', 'Jalón al pecho de rodillas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Half-Kneeling-Lat-Pulldown.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('22e29b88-c0de-4e80-babe-22e29b880000', 'Press de pecho sentado con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Dumbbell-Seated-Front-and-Back-Tate-Press.gif', '{"- Posición inicial: Siéntese en un banco plano con la espalda recta y los pies firmemente plantados en el suelo. Sostenga una mancuerna en cada mano y tenga las palmas hacia adelante. Levante las mancuernas al nivel de los hombros con los codos doblados aproximadamente a 90 grados.","- Siéntate en un banco plano con la espalda recta y los pies firmemente plantados en el suelo.","- Sostenga una mancuerna en cada mano y coloque las palmas hacia adelante.","- Front Tate Press: Extienda los brazos hacia arriba mientras mantiene las mancuernas frente a su cabeza. Extiende completamente los codos y luego baja las mancuernas a la posición inicial.","- Back Tate Press: presione las mancuernas por encima de la cabeza pero ligeramente detrás de la cabeza. Controla el movimiento mientras regresas a la posición inicial.","- Uso de peso excesivo: puede provocar una forma inadecuada y aumentar el riesgo de lesiones.","- Mantenga su núcleo comprometido para mantener la estabilidad durante todo el movimiento.","- Mueve las mancuernas de forma controlada para maximizar la activación del tríceps.","### Errores comunes:","- Levante las mancuernas al nivel de los hombros con los codos doblados aproximadamente a 90 grados.","- Ejecución: Front Tate Press: Extiende los brazos hacia arriba manteniendo las mancuernas delante de tu cabeza. Extienda completamente los codos, luego baje las mancuernas a la posición inicial. Press de espalda Tate: presione las mancuernas por encima de la cabeza pero ligeramente detrás de la cabeza. Controle el movimiento a medida que regresa a la posición inicial. Repita las prensas delanteras y traseras en un patrón alterno para el número deseado de repeticiones.","- Repeticiones y respiración: Realice de 8 a 12 repeticiones por serie. Inhale mientras baja las mancuernas y exhale mientras las presiona sobre su cabeza.","- Inhala mientras bajas las mancuernas y exhala mientras las presionas sobre tu cabeza.","- No apresures el movimiento; céntrese en un ritmo suave y constante.","- No involucrar el Core: conduce a inestabilidad y ejecución inadecuada del ejercicio.","- Inclinarse demasiado hacia adelante o hacia atrás: reduce la estabilidad y aleja la tensión del tríceps.","- Bloquear los codos: puede tensar las articulaciones y reducir la participación de los músculos.","- Repita las prensas delanteras y traseras en un patrón alterno para el número deseado de repeticiones.","- Realiza de 8 a 12 repeticiones por serie.","### Consejos para una forma adecuada:","- Evite arquear la zona lumbar manteniendo una postura fuerte y erguida.","- Asegúrese de que sus codos permanezcan doblados en un ángulo constante durante la prensa.","- Dejar caer las mancuernas demasiado rápido: aumenta el riesgo de perder el control y posibles lesiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0156cffa-c0de-4e80-babe-0156cffa0000', 'Peso muerto con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dumbbell-Romanian-Deadlift.gif', '{"Párese con los pies separados a la altura de las caderas y sostenga un par de mancuernas frente a los muslos con las palmas hacia el cuerpo.","Regrese a la posición inicial levantándose erguido, manteniendo su núcleo comprometido y manteniendo una columna neutral.","Involucre su núcleo, mantenga el pecho elevado y mantenga una ligera flexión de las rodillas durante todo el movimiento.","Comience el movimiento flexionando las caderas, empujando los glúteos hacia atrás mientras mantiene la espalda recta.","Baje las mancuernas a lo largo de la parte delantera de sus piernas, manteniendo una ligera flexión de las rodillas y manteniendo las pesas cerca de su cuerpo.","Continúe bajando las mancuernas hasta que sienta un estiramiento en los isquiotibiales o hasta que alcance un rango de movimiento cómodo.","Haga una pausa breve en la parte inferior del movimiento, luego invierta el movimiento impulsando las caderas hacia adelante y apretando los glúteos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2eae2bd0-c0de-4e80-babe-2eae2bd00000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Power-Skips.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('43032f73-c0de-4e80-babe-43032f730000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Plyo-Jacks.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('31d8a35d-c0de-4e80-babe-31d8a35d0000', 'Sentadilla en máquina', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Sled-Hack-Squat.gif', '{"Suba a la plataforma y coloque la espalda plana contra la almohadilla con los hombros debajo de las almohadillas de soporte.","Coloque los pies separados a la altura de los hombros con los dedos ligeramente hacia afuera en la plataforma para los pies.","Empuja con los talones para extender las piernas y vuelve a la posición inicial sin bloquear las rodillas.","Desbloquee las manijas de seguridad, apoye su núcleo y comience a bajar el trineo doblando las rodillas.","Desciende hasta que tus muslos queden paralelos o ligeramente por debajo mientras mantienes los talones planos y las rodillas alineadas.","Repita para las repeticiones deseadas, manteniendo el control y la tensión durante todo el movimiento."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
