INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('50c96eea-c0de-4e80-babe-50c96eea0000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Split-Jacks.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2c4f9fc9-c0de-4e80-babe-2c4f9fc90000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Wheel-Run.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('61588a86-c0de-4e80-babe-61588a860000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Hawaiian-Squat-exercise.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('51c3adf7-c0de-4e80-babe-51c3adf70000', 'Peso muerto con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Dumbbell-Straight-Leg-Deadlift.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5bcdce5b-c0de-4e80-babe-5bcdce5b0000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Lever-Side-Hip-Abduction.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4f02632e-c0de-4e80-babe-4f02632e0000', 'Elevación de piernas de pie', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Lever-Standing-Leg-Raise.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('67787281-c0de-4e80-babe-677872810000', 'Zancadas con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dumbbell-Lunge.gif', '{"Las estocadas con mancuernas son un ejercicio fácil de realizar para principiantes. Puede ayudar a fortalecer los músculos de las piernas, tensar los músculos de la cadera y quemar calorías para perder peso.","Desarrolla tamaño y fuerza en cuádriceps, glúteos e isquiotibiales. Las estocadas con mancuernas son uno de los ejercicios eficaces para la parte inferior del cuerpo que mejoran por completo la fuerza, la estabilidad y el equilibrio de las piernas. Las estocadas con mancuernas se dirigen con mayor intensidad a los cuádriceps y los músculos de la cadera, pero también afectan a los tendones de las rodillas, los muslos y el core.","Aprieta el trasero. Las estocadas con mancuernas son uno de los mejores ejercicios que pueden ayudarte a conseguir unos glúteos más firmes y tonificados actuando sobre los músculos más profundos de los glúteos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5e8b2406-c0de-4e80-babe-5e8b24060000', 'Zancadas con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Dumbbell-Rear-Lunge.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('008b019b-c0de-4e80-babe-008b019b0000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Lever-Side-Hip-Adduction.gif', '{"La aducción de cadera con palanca es un ejercicio de aislamiento eficaz para la parte interna de la cadera que desarrolla fuerza y ​​​​músculo en los aductores responsables de la rotación de la articulación de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7a79a976-c0de-4e80-babe-7a79a9760000', 'Zancadas con barra', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Barbell-Lunge.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('57d19d04-c0de-4e80-babe-57d19d040000', 'Zancadas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Side-Lunge-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('61e3fc40-c0de-4e80-babe-61e3fc400000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/BODYWEIGHT-SUMO-SQUAT.gif', '{"- Párese con los pies más separados que el ancho de los hombros y los dedos de los pies ligeramente hacia afuera.","- Conduce con los talones para volver a la posición inicial, apretando los glúteos en la parte superior.","###","- Apoye su núcleo y mantenga su pecho elevado durante todo el movimiento.","- Desciende hasta que tus muslos queden paralelos al suelo o tan bajos como te permita la movilidad.","- Baje el cuerpo doblando las rodillas y las caderas, hundiendo las caderas hacia abajo.","- Empuje las rodillas hacia afuera en línea con los dedos de los pies durante el descenso.","- Baje con control y haga una breve pausa en la parte inferior para una mayor activación muscular.","- Dejar que las rodillas se doblen hacia adentro, lo que reduce la efectividad y aumenta el riesgo de lesiones.","- Ir demasiado rápido, sacrificando control y rango de movimiento.","- Involucre su núcleo para mantener el equilibrio y proteger su espalda baja.","### Errores comunes","- Estar demasiado estrecho, lo que desvía el énfasis de los músculos objetivo.","### Consejos para una forma adecuada","- Mantenga el torso erguido para evitar inclinarse hacia adelante.","- Mantenga una presión uniforme sobre los pies para evitar que se incline hacia adelante.","- Redondear la espalda inclinándose demasiado hacia adelante.","- Subir a los dedos de los pies, lo que disminuye la activación de los glúteos y los isquiotibiales."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('423a5fab-c0de-4e80-babe-423a5fab0000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Zig-Zag-Hops-Plyometric.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1e9c677c-c0de-4e80-babe-1e9c677c0000', 'Ejercicio en polea', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Cable-Hips-Adduction.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('780cece4-c0de-4e80-babe-780cece40000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Upavistha-Konasana.gif', '{"La Upavistha Konasana es una postura de yoga desafiante. La asana forma un ángulo que le da un gran estiramiento al cuerpo, especialmente a la parte inferior del cuerpo. Estira las piernas, las caderas, los hombros y los músculos de la ingle, fortalece la espalda y mejora la postura. Estirar el cuerpo aumenta la flexibilidad de los músculos y reduce el riesgo de lesiones y previene el dolor muscular."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6d80bc91-c0de-4e80-babe-6d80bc910000', 'Estiramiento sentado', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Seated-Hamstring-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('19c3972c-c0de-4e80-babe-19c3972c0000', 'Ejercicio acostado', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Side-Lying-Clam.gif', '{"La almeja acostada de lado es un ejercicio sencillo que comienza a tonificar las caderas y los muslos. Este ejercicio trabaja los músculos de la cadera más pequeños y menos conocidos. También enseña la estabilidad pélvica a medida que la pierna gira hacia adentro y hacia afuera en la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4a907998-c0de-4e80-babe-4a9079980000', 'Peso muerto', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Lever-Deadlift.gif', '{"Es adecuado para principiantes. Dado que este ejercicio se realiza en una máquina y mientras lo hace no necesita concentrarse en equilibrar los músculos, le permite agregar más peso para ganar más músculo.","Aumenta la testosterona: Se ha demostrado mediante investigaciones que los ejercicios con pesas ayudan a aumentar los niveles de testosterona a corto y largo plazo. Ejercicios como press de banca, sentadillas y peso muerto son los ejercicios más efectivos que aumentan los niveles de testosterona.","Fortalece la capacidad de agarre. Le permite agarrar un objeto con más firmeza cuando lo sostiene. Además, los estudios demuestran que el peso muerto es un ejercicio eficaz para mejorar la fuerza explosiva y el rendimiento del salto vertical.","El peso muerto ayuda al desarrollo de los músculos de las piernas, los músculos de la cadera y los músculos centrales, al mismo tiempo que apoya la formación de músculos y la fuerza en el cuerpo. Además, agregar peso muerto a tus entrenamientos ayuda a fortalecer tus tendones, ligamentos y huesos.","El peso muerto también activa tus glúteos y músculos de la espalda. Los ejercicios funcionales como el peso muerto son aquellos que facilitan las actividades del cuerpo en la vida real.","El peso muerto se dirige a todos los músculos responsables de la postura y le permite mantener la espalda recta durante las actividades diarias habituales.","El peso muerto es uno de los ejercicios compuestos más eficaces. Se expresa como un ejercicio de fuerza básico en deportes de fuerza como el levantamiento de pesas. Es el movimiento más popular de fuerza y ​​entrenamiento de fuerza ya que trabaja muchos grupos de músculos.","La forma correcta es muy importante en este ejercicio. Para empezar, hacer mal puede provocar lesiones. Tras algunos intentos con la barra vacía o acompañado de un entrenador, el proceso de adaptación al movimiento puede verse acortado."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1ffc92e5-c0de-4e80-babe-1ffc92e50000', 'Estiramiento de rodillas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Kneeling-Quad-Stretch.gif', '{"Se aplica para estirar los músculos cuádriceps. Estirar los músculos con regularidad puede mejorar su flexibilidad y rendimiento, y también prevenir lesiones y rigidez."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('30e293a5-c0de-4e80-babe-30e293a50000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Lateral-Speed-Step.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('427bfd7d-c0de-4e80-babe-427bfd7d0000', 'Peso muerto con pesa rusa / kettlebell', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Kettlebell-Single-Leg-Deadlift.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('63c2ce31-c0de-4e80-babe-63c2ce310000', 'Estiramiento sentado', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Seated-Adductor-Groin-Stretch.gif', '{"El estiramiento de la ingle del aductor sentado forma un ángulo que le da un gran estiramiento al cuerpo, especialmente a la parte inferior del cuerpo. Estira las piernas, las caderas, los hombros y los músculos de la ingle, fortalece la espalda y mejora la postura. Estirar el cuerpo aumenta la flexibilidad de los músculos y reduce el riesgo de lesiones y previene el dolor muscular."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5be510a4-c0de-4e80-babe-5be510a40000', 'Zancadas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Reverse-Lunge-Knee.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2cf6432c-c0de-4e80-babe-2cf6432c0000', 'Estiramiento acostado', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Hamstrings-Lying-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('031aaa35-c0de-4e80-babe-031aaa350000', 'Patada de tríceps en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Cable-Donkey-Kickback.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0d9ba310-c0de-4e80-babe-0d9ba3100000', 'Elevación de pantorrillas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Hack-Squat-Calf-Raise.gif', '{"- Configuración: Párese dentro de la máquina de sentadillas con los hombros debajo de las almohadillas y los pies colocados en lo alto de la plataforma para los pies. Mantenga los dedos de los pies apuntando hacia adelante o ligeramente hacia afuera.","- Coloque los pies para un estiramiento completo: las puntas de los pies deben descansar sobre el borde de la plataforma para que los talones puedan moverse libremente en un estiramiento profundo sin resbalar.","- Desbloquee la máquina: Extienda las piernas completamente para levantar el carro y soltar las manijas de seguridad.","- Comience a levantar: con las rodillas completamente extendidas, presione los pies delanteros para levantar los talones lo más alto posible.","- Pausa y contracción: manténgalo en la parte superior durante 1 a 2 segundos, enfatizando una contracción máxima en las pantorrillas.","- Repetir: realice la cantidad deseada de repeticiones, manteniendo el control en todo momento.","- Baje lentamente: deje que los talones caigan por debajo del nivel de la plataforma para lograr un estiramiento completo del gastrocnemio y el sóleo.","- Dejar que las rodillas se doblen, lo que aleja la carga del gemelo.","- Utilizar un rango de movimiento parcial, limitando el estiramiento y la contracción.","- Muévase lenta y deliberadamente, especialmente durante la fase excéntrica (de descenso).","### Errores comunes a evitar","- Rebotar en el fondo, lo que elimina la tensión muscular y corre el riesgo de sufrir tensión en las articulaciones.","### Consejos para una forma adecuada","- Mantenga las rodillas rectas pero no bloqueadas para enfatizar los gastrocnemios.","- Evite doblar las caderas o las rodillas; esto mantiene la atención en las pantorrillas, no en los cuádriceps.","- Asegúrese de que los pies estén colocados de forma segura; use suelas de goma o cinta adhesiva si es necesario.","- Apriete en la parte superior durante 1 a 2 segundos para maximizar el reclutamiento de fibras musculares.","- Permitir que los pies resbalen, lo que puede reducir la eficacia o provocar lesiones.","- Sobrecarga demasiado pronto, comprometiendo el control y la estabilidad."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3ea67639-c0de-4e80-babe-3ea676390000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Bridge-Hip-Abduction.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('45f6ecad-c0de-4e80-babe-45f6ecad0000', 'Patada de tríceps en máquina', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Glute-Kickback-Machine.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0c272a34-c0de-4e80-babe-0c272a340000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Curtsey-Squat.gif', '{"- Párate erguido con los pies separados a la altura de las caderas y mantén el core comprometido.","- Coloque la pierna derecha en diagonal detrás de la pierna izquierda, bajando las caderas hasta quedar en cuclillas.","- Presione con el talón de su pie delantero para regresar a la posición inicial.","### Paso 1: configuración y posicionamiento","- Junte las manos en las caderas o delante del pecho para mantener el equilibrio.","### Paso 2: Ejecución","- Mantenga la rodilla delantera alineada con los dedos de los pies y baje la rodilla trasera cerca del suelo.","- Repita en el lado opuesto y continúe alternando piernas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2281fd88-c0de-4e80-babe-2281fd880000', 'Sentadilla en polea', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Cable-Squat.gif', '{"Conecte una barra recta o un mango de cuerda a la polea inferior de una máquina de cable.","Colóquese frente a la máquina y agarre el mango con ambas manos, sujetándolo a la altura del pecho.","Retroceda un poco para que el peso tire hacia adelante, luego párese con los pies separados a la altura de los hombros.","Conduce con los talones para volver a la posición inicial, manteniendo la tensión del cable en todo momento.","Apoye su núcleo y comience la sentadilla doblando las caderas y las rodillas simultáneamente.","Baja el cuerpo hasta que los muslos queden paralelos al suelo o ligeramente por debajo, manteniendo el pecho erguido.","Repita para las repeticiones, asegurando el control y un torso erguido durante el movimiento."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('039d0d89-c0de-4e80-babe-039d0d890000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Split-Squat.gif', '{"Comience en una posición de estocada con el pie derecho hacia adelante y el pie izquierdo hacia atrás. Mantenga los pies separados a la altura de los hombros y los dedos de los pies apuntando hacia adelante.","Salta explosivamente y cambia la posición de tus pies en el aire, de modo que tu pie izquierdo ahora esté al frente y tu pie derecho atrás.","Aterriza suavemente en el suelo con el pie izquierdo hacia adelante y el pie derecho hacia atrás, bajando el cuerpo nuevamente a una posición de estocada.","Repita el movimiento durante el número deseado de repeticiones o tiempo, alternando entre cada pierna."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('023cfb3d-c0de-4e80-babe-023cfb3d0000', 'Aperturas de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Adductor-Magnus-Stretch.gif', '{"- Posición inicial: Acuéstese boca arriba con las piernas juntas, levantadas hacia el techo. Asegúrese de que sus caderas estén firmemente ancladas al suelo.","- Regreso a la posición inicial: Vuelva a juntar suavemente las piernas y regrese a la posición inicial.","- Posición inicial: comience en la misma posición inicial que el estiramiento estático.","### The Thigh Fly como estiramiento estático:","- Movimiento de estiramiento: abra lentamente las piernas hacia los lados tanto como le resulte cómodo, sintiendo un estiramiento a lo largo de la parte interna de los muslos. Mantenga esta posición durante 10 a 15 segundos mientras respira de manera constante.","- Movimiento continuo: abra las piernas hacia los lados y luego vuelva a cerrarlas con un movimiento fluido sin detenerse en la posición estirada.","### El Muslo Fly como movimiento dinámico:","- Mantén la cadera anclada al suelo durante todo el movimiento.","- Si siente molestias o tensión, reduzca el rango de movimiento o detenga el ejercicio.","- Uso del impulso: realice el movimiento con control en lugar de depender del impulso.","- Repeticiones: realice el Thigh Fly dinámico durante el número especificado de repeticiones sin descansar entre cada repetición.","- Respiración: Inhala mientras abres las piernas y exhala mientras las cierras.","- Muévase lentamente y con control para maximizar el estiramiento y activar los músculos de manera efectiva.","- Repeticiones: repita el estiramiento durante 2 a 4 repeticiones, tomando breves períodos de descanso entre ellas si es necesario.","### Consejos para una forma adecuada","- Arqueando la parte baja de la espalda: asegúrese de que su espalda permanezca plana sobre el suelo para evitar tensiones.","- Extender demasiado: Evite separar demasiado las piernas, ya que esto puede provocar tensión muscular.","- Conteniendo la respiración: Mantenga una respiración constante para mejorar la relajación y la eficacia.","- Respire profunda y constantemente durante todo el ejercicio.","### Errores comunes a evitar"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('14a816bc-c0de-4e80-babe-14a816bc0000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Cossack-Squat.gif', '{"Párese con los pies bien separados y los dedos ligeramente hacia afuera.","Cambie su peso hacia un lado, doblando la rodilla mientras mantiene recta la pierna opuesta.","Empuje a través de la pierna doblada para regresar a la posición inicial, luego repita en el otro lado.","Permita que el talón de la pierna estirada se levante ligeramente si la flexibilidad es limitada.","Mantenga el pecho alto y el torso erguido mientras se agacha lo más bajo posible con la pierna doblada."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4c262f41-c0de-4e80-babe-4c262f410000', 'Elevación de piernas acostado', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Alternate-Lying-Floor-Leg-Raise.gif', '{"Se dirige a los músculos abdominales inferiores y superiores al mismo tiempo: la elevación alterna de las piernas en el suelo actúa sobre el recto abdominal y los músculos oblicuos, de modo que los músculos abdominales superiores e inferiores se desarrollan simultáneamente."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('50c69342-c0de-4e80-babe-50c693420000', 'Fondos', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Chest-Dips.gif', '{"- Posiciónate: Coloca tus manos sobre las barras paralelas, manteniendo los brazos rectos y el cuerpo ligeramente inclinado hacia adelante. Tus pies deben estar separados del suelo y tu cuerpo debe estar en una posición erguida o ligeramente inclinada hacia adelante, dependiendo de tu concentración.","- Agarre: Sujete las barras firmemente con las palmas hacia adentro y los codos ligeramente doblados para comenzar.","- Press Up: Empújese hacia arriba estirando los brazos y volviendo a la posición inicial.","- Utilice la sobrecarga progresiva: a medida que se fortalezca, puede agregar peso usando un cinturón de inmersión para continuar progresando y desarrollando músculo.","- Posición de las piernas: Mantenga las piernas dobladas a la altura de las rodillas y los pies juntos para mayor estabilidad, o extiéndalas para mayor dificultad.","- Involucre el pecho: concéntrese en apretar los músculos del pecho mientras baja el cuerpo. Esta inclinación hacia adelante enfatiza más el pecho que los tríceps.","- Repetir: Realiza el número deseado de repeticiones, manteniendo el control durante todo el movimiento.","- Baje el cuerpo: baje lentamente el cuerpo doblando los codos y manteniendo la parte superior del cuerpo ligeramente inclinada hacia adelante. Bájate hasta que la parte superior de tus brazos quede paralela al suelo o ligeramente por debajo.","- Lento y controlado: realice cada repetición lentamente y con control para maximizar la participación de los músculos. Concéntrese en estirar en la parte inferior y apretar en la parte superior.","- Conexión mente-músculo: concéntrese en sentir los músculos del pecho trabajando durante todo el movimiento, especialmente durante la fase de descenso.","- Calienta adecuadamente: asegúrate de que tus hombros y pecho estén calientes antes de realizar fondos para evitar lesiones.","### Errores comunes a evitar","### Consejos para la eficacia","- No inclinarse lo suficiente hacia adelante: para activar el pecho, asegúrese de inclinarse ligeramente hacia adelante mientras baja el cuerpo. Esto ayuda a apuntar a los músculos del pecho. Si te mantienes demasiado erguido, la atención se centrará en los tríceps.","- Codos ensanchados: Mantenga los codos cerca del cuerpo para reducir la tensión en los hombros y prevenir lesiones.","- No profundizar lo suficiente: asegúrese de bajar lo suficiente (al menos hasta que la parte superior de sus brazos quede paralela al piso) para maximizar el compromiso del pecho y la activación muscular.","- Bloquear los codos en la parte superior: evite bloquear los codos en la parte superior del movimiento, lo que puede generar una tensión innecesaria en las articulaciones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0406c145-c0de-4e80-babe-0406c1450000', 'Elevación de pantorrillas en máquina', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Hack-Machine-One-Leg-Calf-Raise.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('477ae377-c0de-4e80-babe-477ae3770000', 'Elevación de pantorrillas', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Single-Leg-Calf-Raises.gif', '{"Párese cerca de un banco, estante u otro soporte para mantener el equilibrio. Coloque la punta de un pie sobre una superficie elevada (como un escalón o un plato) con el talón colgando.","Configuración: Párese cerca de un banco, estante u otro soporte para mantener el equilibrio. Coloque la punta de un pie sobre una superficie elevada (como un escalón o un plato) con el talón colgando.","Coloque la pierna que no trabaja: levante el pie opuesto del suelo, doblando la rodilla para que no ayude.","Levante a través del antepié: presione a través de la punta del pie y levante el talón lo más alto posible con un movimiento controlado.","Baje lentamente: deje que el talón regrese por debajo del escalón en un descenso lento y controlado para enfatizar la carga excéntrica.","Comience con un estiramiento completo: permita que el talón caiga por debajo del escalón para sentir un estiramiento en la pantorrilla de la pierna que trabaja.","Pausa y contracción: apriete la pantorrilla en la parte superior durante 1 a 2 segundos.","Repetir: realice la cantidad deseada de repeticiones, luego cambie de lado."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('62e979be-c0de-4e80-babe-62e979be0000', 'Elevación de pantorrillas sentado', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Lever-Seated-Calf-Raise.gif', '{"- Configuración: Siéntese en la máquina con las rodillas dobladas a 90 grados y los pies colocados a la altura de los hombros en la plataforma para los pies. La almohadilla para los muslos debe descansar firmemente sobre los muslos, justo por encima de las rodillas.","- Posición inicial: Suelte el mecanismo de seguridad. Deje que los talones bajen lentamente para sentir un estiramiento profundo en las pantorrillas.","- Bajar bajo control: Deje que sus talones regresen a la posición inicial bajo un control lento y deliberado para un estiramiento excéntrico completo.","- Usar demasiado peso, comprometer el control y aumentar el riesgo de lesiones.","###","- Ajustar carga: cargue el peso deseado en los brazos de palanca. Comience de manera conservadora y concéntrese en el rango completo de movimiento.","- Elevar: Presione a través de las puntas de los pies para levantar los talones lo más alto posible, concentrándose en una fuerte contracción en el sóleo.","- Pausa y contracción: manténgalo en la parte superior durante 1 a 2 segundos, contrayendo completamente las pantorrillas sin rebotar.","- Utilice un rango completo de movimiento: permita un estiramiento completo y una elevación completa del talón.","- Rango de movimiento parcial, lo que limita el desarrollo de la pantorrilla.","- Dejar que las rodillas se levanten de la almohadilla, lo que disminuye la eficiencia mecánica.","- Repetir: realice la cantidad deseada de repeticiones manteniendo una forma estricta.","- Evite los rebotes: utilice movimientos lentos y deliberados, especialmente al final de la repetición.","- Controle lo excéntrico: enfatice la fase de descenso para obtener un beneficio hipertrófico adicional.","- Pausa en la parte superior: manténgalo presionado brevemente durante 1 a 2 segundos para mejorar la conexión mente-músculo con el sóleo.","### Consejos para una forma adecuada","- Mantenga las rodillas y las caderas quietas: no use el impulso ni mueva los muslos hacia arriba para ayudar al levantamiento.","- Acelerar las repeticiones y aprovechar el impulso, reduciendo la tensión en el sóleo.","### Errores comunes","- Descuidar el control excéntrico, perder un estímulo clave para el crecimiento muscular."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7ee2fae6-c0de-4e80-babe-7ee2fae60000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Drop-Push-Up.gif', '{"- Coloca dos bancos o cajas resistentes paralelos entre sí, dejando suficiente espacio para que puedas moverte cómodamente entre ellos.","- Asegúrate de que los bancos o cajas sean estables y no se vuelquen durante el ejercicio.","- Colócate de manera que puedas colocar las manos en los bancos y los pies en el suelo.","- Durante la fase de aterrizaje, soltarás las manos de los bancos y apuntarás a aterrizar con las manos en el suelo.","- Mientras desciendes hacia el suelo, retira las manos del banco y dirígelas hacia el suelo para lograr un aterrizaje suave.","- Vuelva a colocar las manos en los bancos en la posición inicial.","- Haz una flexión","- Tu cuerpo debe formar una línea recta.","- Comience el ejercicio realizando una flexión regular. Baje el pecho hacia el banco doblando los codos.","- Mantenga su cuerpo en línea recta y mantenga la forma adecuada de flexión de brazos. Tu pecho debe acercarse al banco sin tocarlo.","- Aterriza con control para minimizar cualquier impacto discordante en tus muñecas y hombros.","- Después de completar la flexión en el suelo, levántate explosivamente con la mayor fuerza posible.","- Utilice su pecho, tríceps y hombros para generar la fuerza hacia arriba.","- Realice el ejercicio durante el número deseado de repeticiones.","- Primero domine las flexiones: asegúrese de poder realizar flexiones estándar con la forma adecuada antes de intentar hacer flexiones de brazos.","- Concéntrese en el control: durante la fase de caída, controle su descenso para minimizar el impacto y prevenir lesiones.","### Consejos para la eficacia","- Explota con poder: empuja hacia arriba explosivamente durante la fase de flexión para maximizar el beneficio pliométrico.","- Calienta a fondo: prepara tus muñecas, hombros y abdomen con estiramientos dinámicos para reducir el riesgo de tensión.","- Progrese gradualmente: comience con menos repeticiones o versiones modificadas, como dejarse caer desde una posición de rodillas, si es un principiante."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('64c6e285-c0de-4e80-babe-64c6e2850000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Weighted-Crunch.gif', '{"El movimiento Weighted Crunch es un ejercicio avanzado que se aplica con la ayuda de un peso para moldear, tensar y fortalecer los músculos abdominales. En este ejercicio que haces con peso, puedes tener más interacción con los músculos del sixpack."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('273e22e6-c0de-4e80-babe-273e22e60000', 'Aperturas de pecho acostado en polea', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Lying-Cable-Fly.gif', '{"- Coloque el banco: coloque un banco plano en el centro de una máquina cruzada de cables o cerca de dos sistemas de poleas ajustables.","- Ajuste las poleas: coloque las poleas del cable ligeramente por debajo o a la misma altura que sus hombros cuando esté acostado.","- Coloque manijas: coloque manijas de un solo agarre en cada polea.","- Agarre las manijas: Acuéstese en el banco y sostenga las manijas con las palmas hacia adentro (agarre neutral).","- Posición inicial: Extienda los brazos hacia arriba para que las manijas se junten por encima de su pecho. Mantenga los codos ligeramente doblados para reducir la tensión en las articulaciones. Las muñecas deben permanecer neutrales (no dobladas).","- Aprieta los músculos del pecho y lleva los brazos a la posición inicial de forma controlada.","- Ajuste la altura de la polea: experimente con alturas de polea para apuntar a diferentes partes del cofre.","- Extiende tus brazos hacia arriba para que las manijas se encuentren por encima de tu pecho.","- Tus muñecas deben permanecer neutrales (no dobladas).","- Fase de descenso: baje lentamente los brazos hacia los lados formando un arco amplio. Mantenga los codos ligeramente doblados y concéntrese en sentir el estiramiento en el pecho. Baje hasta que los brazos estén alineados con el torso o justo debajo del nivel de los hombros.","- Baja lentamente los brazos hacia los lados formando un amplio arco.","- Baje hasta que sus brazos estén alineados con su torso o justo debajo del nivel de los hombros.","- Conexión mente-músculo: Concéntrese en apretar los músculos del pecho en la parte superior del movimiento para una activación máxima.","- Controla los cables: evita que los cables tiren de tus brazos demasiado rápido durante la fase de descenso.","- Rango de movimiento limitado: no bajar los brazos por completo reduce el estiramiento y la efectividad del ejercicio.","- Movimientos apresurados: realizar el ejercicio demasiado rápido puede provocar una mala forma y una disminución del compromiso muscular.","- Fase de elevación: Apriete los músculos del pecho y lleve los brazos a la posición inicial de forma controlada. Evite que las manijas choquen en la parte superior; mantener la tensión en los cables.","- Repetir: Realiza el número deseado de repeticiones, manteniendo el control durante todo el movimiento.","- Concéntrese en la forma: utilice pesas livianas inicialmente para garantizar una técnica adecuada y un rango completo de movimiento.","### Errores comunes a evitar","- Mantenga los codos ligeramente doblados para reducir la tensión en las articulaciones.","- Mantenga los codos ligeramente doblados y concéntrese en sentir el estiramiento en el pecho.","- Evite que las manijas choquen en la parte superior; mantener la tensión en los cables.","### Consejos para la eficacia","- Extender demasiado los brazos: Enderezar completamente los codos puede ejercer una tensión excesiva en las articulaciones. Mantenga una ligera curvatura.","- Arqueando la espalda: Mantenga la parte baja de la espalda en contacto con el banco para evitar tensiones y mantener la forma adecuada.","- Asas que chocan: Dejar que las asas choquen en la parte superior reduce la tensión en los músculos del pecho."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('793bd85a-c0de-4e80-babe-793bd85a0000', 'Elevación de pantorrillas', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Donkey-Calf-Raise.gif', '{"- Posición de los pies: Párese con las puntas de los pies sobre un borde elevado o bloque, con los talones colgando. Los dedos de los pies deben apuntar rectos o ligeramente hacia afuera.","- Sostenga las manijas de soporte ligeramente; son para brindar estabilidad, no para impulsarse hacia arriba.","- Alineación del torso: inclínese hacia adelante a la altura de las caderas hasta aproximadamente 90°, manteniendo la columna neutra. Sostenga las empuñaduras o la superficie de apoyo para estabilizar.","- Comience con un estiramiento profundo: permita que los talones desciendan lentamente hasta que sienta un estiramiento completo en las pantorrillas.","- Levantar: Conduzca a través de las puntas de los pies para elevar los talones lo más alto posible, manteniendo las rodillas extendidas.","- Contraer y mantener: haga una pausa en la parte superior durante 1 a 2 segundos, apretando las pantorrillas con fuerza.","- Bajar bajo control: baje lentamente los talones hasta la posición estirada.","- Utilice un rango completo de movimiento, enfatizando tanto el estiramiento profundo como la contracción completa.","- Acelerar el movimiento, lo que minimiza la carga excéntrica y la tensión de estiramiento.","- Repetir: realice el número deseado de repeticiones manteniendo un control y una postura estrictos.","- Mantenga una posición con la cadera articulada y la espalda plana durante todo el movimiento.","### Errores comunes a evitar","- Doblar las rodillas, lo que disminuye la activación de los gastrocnemios y limita el rango.","### Consejos para una forma adecuada","- Evite doblar la rodilla, ya que esto desplaza la tensión del gemelo al sóleo.","- Aprieta en la parte superior, en lugar de rebotar durante las repeticiones.","- Depender del impulso, especialmente en la parte inferior, aumenta el riesgo para el tendón de Aquiles.","- Permitir que la parte superior del cuerpo se redondee, reduciendo la alineación de la columna y la seguridad de la carga.","- Colocación desalineada del pie, que puede forzar los tobillos y reducir el compromiso de las pantorrillas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('63c32efa-c0de-4e80-babe-63c32efa0000', 'Ejercicio sentado', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Seated-Side-Crunches.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6b970041-c0de-4e80-babe-6b9700410000', 'Fondos', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Assisted-Chest-Dip.gif', '{"- Establezca la resistencia: ajuste el contrapeso de la máquina a un nivel apropiado. Un peso más alto proporciona más asistencia, facilitando el ejercicio.","- Colóquese: coloque las rodillas o los pies en la plataforma de asistencia y agarre las manijas firmemente con las palmas hacia adentro o ligeramente hacia adelante.","- Presione hacia arriba: empújese hacia atrás hasta la posición inicial, concentrándose en involucrar su pecho y tríceps.","- Inclínese hacia adelante: para enfatizar el pecho, incline ligeramente el torso hacia adelante, manteniendo los hombros hacia abajo y los codos ligeramente ensanchados (en un ángulo de aproximadamente 45 grados).","- Progrese gradualmente: disminuya gradualmente el nivel de asistencia con el tiempo para desarrollar fuerza y ​​trabajar hacia fondos sin ayuda.","- Concéntrese en la forma: mantenga el núcleo contraído, los hombros hacia abajo y el pecho comprometidos durante todo el movimiento.","- Respiración: Exhala mientras presionas hacia arriba e inhala mientras bajas el cuerpo.","- Baje el cuerpo: doble lentamente los codos para bajar el cuerpo hasta que la parte superior de los brazos quede paralela al suelo o ligeramente por debajo.","- Movimiento apresurado: realizar fondos demasiado rápido reduce la participación de los músculos y aumenta el riesgo de lesiones. Utilice movimientos lentos y controlados.","- Estiramiento y calentamiento: caliente los hombros, el pecho y los tríceps antes de realizar fondos para evitar tensiones o lesiones.","### Errores comunes a evitar","- Inclinación insuficiente hacia adelante: Mantener el torso demasiado erguido desplaza la atención hacia los tríceps en lugar del pecho.","- Repetir: Realizar el número deseado de repeticiones con control.","### Consejos para la eficacia","- Codos ensanchados: Los codos excesivamente ensanchados pueden aumentar la tensión en los hombros. Mantenlos en un ángulo de 45 grados.","- Configuración de resistencia inadecuada: usar demasiada o muy poca ayuda puede comprometer la forma. Elige un nivel que te desafíe pero que permita la técnica adecuada."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('132ad2b2-c0de-4e80-babe-132ad2b20000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Backward-Jumping.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('38fbf5f8-c0de-4e80-babe-38fbf5f80000', 'Press de pecho de pie en máquina', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Bench-Press-Machine-Standing-Calf-Raise.gif', '{"- Configuración: Súbase a la plataforma de la máquina con las puntas de los pies firmemente en el borde y los talones colgando.","- Posición: Párese erguido y agarre las manijas laterales para lograr equilibrio y estabilidad.","- Posición inicial: mantenga el núcleo comprometido, la espalda recta y las piernas casi rectas (pero no bloqueadas).","- Concéntrate en la conexión mente-músculo, especialmente durante la pausa en la cima.","### Errores comunes","- Usar el impulso: rebotar hacia arriba y hacia abajo reduce la activación muscular y aumenta el riesgo de lesiones.","- Levante los talones: presione las puntas de los pies para levantar los talones lo más alto posible. Concéntrate en contraer las pantorrillas en la parte superior.","- Bajar bajo control: baje lentamente los talones por debajo del nivel de la plataforma para estirarse por completo antes de repetir.","- Utilice un rango completo de movimiento, bajando completamente los talones y levantándose completamente sobre los dedos de los pies.","- Controlar el descenso; no bajes los talones rápidamente.","- Rango de movimiento parcial: no subir o bajar completamente los talones limita el estiramiento y la contracción.","- Rodillas bloqueadas: Esto aleja la tensión de las pantorrillas y puede estresar las articulaciones.","- Repeticiones apresuradas: los movimientos rápidos y descontrolados minimizan el tiempo de los músculos bajo tensión.","- Haga una pausa y apriete: mantenga la posición superior durante 1 a 2 segundos para maximizar la participación de los músculos.","### Consejos para una forma adecuada","- Mantenga su núcleo apretado para mantener una postura erguida y evite arquear la espalda baja.","- Evite bloquear las rodillas: una ligera flexión mantiene la tensión en las pantorrillas.","- Inclinarse hacia adelante: Reduce la efectividad y ejerce una tensión innecesaria en la espalda."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('674823c9-c0de-4e80-babe-674823c90000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Jumping-jack.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('28b5750c-c0de-4e80-babe-28b5750c0000', 'Elevación de pantorrillas', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Lever-Donkey-Calf-Raise.gif', '{"- Configure la máquina: ajuste la altura de la palanca acolchada para que descanse de forma segura en la parte baja de la espalda o las caderas cuando se agache.","- Posición de los pies: Párese sobre el bloque de pantorrillas con las puntas de los pies apoyadas y los talones colgando. Los pies deben estar separados a la altura de las caderas o un poco más estrechos.","- Posición inicial: deje caer los talones por debajo del nivel de la plataforma para lograr un estiramiento completo de las pantorrillas.","- Coloque los pies en el medio de la plataforma para evitar resbalones y mantener la presión sobre las puntas de los pies.","- Alineación del torso: Inclínese hacia adelante a la altura de las caderas hasta formar un ángulo de aproximadamente 90°, manteniendo la columna neutra. La palanca acolchada debe descansar sobre el sacro o la parte superior de los glúteos, no sobre la columna.","- Inicie el movimiento: presione a través de las puntas de los pies para levantar la palanca haciendo una flexión plantar de los tobillos. Mantenga las rodillas rectas durante todo el movimiento.","- Contracción máxima: en la parte superior, haga una pausa de 1 a 2 segundos mientras aprieta activamente las pantorrillas.","- Concéntrese en el ritmo: utilice un estiramiento de 2 segundos, un levantamiento de 1 segundo y una excéntrica de 2 segundos.","- Descenso controlado: baje lentamente la palanca hasta que los talones estén por debajo del paralelo para estirar el músculo por completo.","- Repetir: realice la cantidad deseada de repeticiones con tempo controlado y rango de movimiento completo.","- Aprieta las pantorrillas con fuerza en la parte superior para aumentar el tiempo bajo tensión y desarrollar la conexión mente-músculo.","### Errores comunes a evitar","- Doblar las rodillas, lo que desplaza el énfasis hacia el sóleo.","- Redondear la columna, especialmente bajo cargas pesadas.","### Consejos para una forma adecuada","- Mantenga las rodillas completamente extendidas para maximizar la activación de los gastrocnemios.","- Utilice una columna neutra en todo momento. Evite redondear la espalda o hiperextender el cuello.","- Rebotar en la parte inferior, lo que reduce el tiempo bajo tensión y corre el riesgo de sufrir una lesión en el tendón de Aquiles.","- Usar demasiado peso, lo que lleva a repeticiones cortas e incompletas.","- Estar demasiado erguido, reduciendo el estiramiento mecánico del gastrocnemio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5b308295-c0de-4e80-babe-5b3082950000', 'Estiramiento de pie', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Standing-Cross-Leg-Hamstring-Stretch.gif', '{"- Posición inicial: Párese erguido con ambos pies juntos y los brazos a los costados.","- Cambiar de lado: regrese lentamente a la posición inicial, luego cambie la pierna cruzada y repita el estiramiento en el otro lado.","- Mantén el estiramiento: agarra tus tobillos, espinillas o el piso, donde tu flexibilidad lo permita. Mantenga esta posición durante 20 a 30 segundos mientras respira profundamente.","- No bloquees tus rodillas; una curva suave evita tensiones innecesarias.","- Evite movimientos de rebote o sacudidas; El estiramiento debe ser lento y controlado.","- Concéntrese en la bisagra de la cadera, no en la flexión de la espalda, para apuntar correctamente a los isquiotibiales.","- Exhale profundamente mientras se inclina hacia adelante para ayudar a relajar los músculos.","### Errores comunes","- Redondear demasiado la espalda: esto reduce la eficacia del estiramiento de los isquiotibiales y puede forzar la columna.","- Rebotar para profundizar: los estiramientos estáticos deben mantenerse, no rebotar.","- Cruza las piernas: coloca el pie derecho sobre el izquierdo para cruzar las piernas. Mantenga ambos pies apoyados en el suelo y las rodillas ligeramente dobladas o rectas dependiendo de la flexibilidad.","- Inclínese hacia adelante: Gire lentamente las caderas e inclínese hacia adelante, alcanzando los dedos de los pies o el piso. Deje que la cabeza cuelgue y mantenga la columna relajada.","### Consejos para una forma adecuada","- Mantenga la espalda relajada y permita que la columna se alargue de forma natural.","- Respiración incorrecta: contener la respiración puede aumentar la tensión y reducir la eficacia del estiramiento.","- Bloquear las rodillas: esto puede tensar las articulaciones y reducir la participación de los músculos.","- Estirarse demasiado: intentar tocar el suelo antes de desarrollar flexibilidad puede provocar lesiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('79e84418-c0de-4e80-babe-79e844180000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Single-Leg-Broad-Jump.gif', '{"El salto apunta a los músculos abdominales, los músculos de la cadera y los flexores de la cadera y también trabaja los muslos, los tendones de las rodillas y los cuádriceps.","Los saltos son un ejercicio pliométrico. Los ejercicios pliométricos son movimientos aeróbicos explosivos que aumentan la velocidad, la rapidez y la potencia y trabajan todo el cuerpo.","Los saltos son beneficiosos para la salud porque combinan el acondicionamiento cardiovascular con el trabajo de fuerza. Dado que los saltos elevan tu frecuencia cardíaca, también pueden mejorar tu condición cardiovascular."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6b0facc1-c0de-4e80-babe-6b0facc10000', 'Elevación de piernas inclinado', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Incline-Leg-Hip-Raise.gif', '{"La elevación de cadera con piernas inclinadas es un ejercicio diseñado para moldear, tensar y fortalecer los músculos abdominales. Con este ejercicio realizado en el banco inclinado, podrás concentrarte más en los músculos abdominales inferiores y fortalecer los músculos centrales."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4782f891-c0de-4e80-babe-4782f8910000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Bodyweight-Windmill.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7f4d2b45-c0de-4e80-babe-7f4d2b450000', 'Plancha', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Front-to-Side-Plank.gif', '{"Las planchas de frente a lado son un ejercicio cardiovascular y de fortalecimiento central eficaz. Puede ayudarle a fortalecer y desarrollar los músculos de la parte superior e inferior del cuerpo.","Al ser un movimiento multifuncional, este ejercicio se dirige no solo a los músculos abdominales sino también a la columna y los glúteos. Plank fortalece y tonifica todo el cuerpo, mejora la postura y el equilibrio, reduce la grasa corporal y puede ayudar a acelerar el metabolismo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('24b8d8a1-c0de-4e80-babe-24b8d8a10000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Tuck-Crunch.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6010c907-c0de-4e80-babe-6010c9070000', 'Estiramiento', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Double-Leg-Stretch.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('385736ab-c0de-4e80-babe-385736ab0000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Bench-Side-Bend.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('42ab5040-c0de-4e80-babe-42ab50400000', 'Ejercicio con mancuernas', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Dumbbell-Side-Bend.gif', '{"Este ejercicio, dirigido a los músculos oblicuos, es muy útil para tensar y desarrollar la grasa abdominal. Puede trabajar más músculos objetivo aumentando el peso según su nivel de condición física."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7fdf66b2-c0de-4e80-babe-7fdf66b20000', 'Plancha', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Spider-Plank.gif', '{"Spider Plank es un entrenamiento abdominal de alta intensidad que trabaja los músculos centrales. Además de ser beneficioso para reafirmar y fortalecer, puede mejorar la postura y el equilibrio, reducir la grasa corporal y ayudar a acelerar el metabolismo.","También es un ejercicio eficaz que aumenta la estabilidad en las zonas del core, la columna y la cadera proporcionando una contracción isométrica. Puedes agregarlo a tus entrenamientos para moldear y fortalecer los músculos de la cadera, el abdomen y las piernas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('76259669-c0de-4e80-babe-762596690000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/weightedsitups.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('391b5342-c0de-4e80-babe-391b53420000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Quarter-Sit-up.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('45df1ab3-c0de-4e80-babe-45df1ab30000', 'Elevación acostado', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Lying-Knee-Raise.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('514e9fc8-c0de-4e80-babe-514e9fc80000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Floor-Crunch.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('37cd35e9-c0de-4e80-babe-37cd35e90000', 'Giro ruso', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Crab-Twist-Toe-Touch.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7e9a9b2e-c0de-4e80-babe-7e9a9b2e0000', 'Remo con barra EZ', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Barbell-Upright-Row.gif', '{"El remo vertical con barra EZ es un ejercicio de la parte superior del cuerpo que se dirige predominantemente al trapecio y los deltoides, que son responsables de agregar ancho a los hombros. Por lo general, se realiza utilizando una barra estándar o una barra EZ.","El remo vertical con barra EZ es uno de los ejercicios efectivos para construir trampas más grandes, pero también es un movimiento en el que es fácil cometer errores. Una de las formas más sencillas de asegurarse de que su forma sea óptima es evitar el uso de mancuernas que sean demasiado pesadas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('56425861-c0de-4e80-babe-564258610000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Short-Stride-Run.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('13366383-c0de-4e80-babe-133663830000', 'Elevaciones laterales en máquina', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Lateral-Raise-Machine.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('16dd02eb-c0de-4e80-babe-16dd02eb0000', 'Press de pecho inclinado con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Incline-Dumbbel-Hammer-Press.gif', '{"Ajuste el banco: coloque el banco inclinado en un ángulo de 30 a 45 grados.","Seleccione mancuernas: elija un peso que le permita mantener la forma adecuada.","Colóquese: siéntese en el banco con los pies apoyados en el suelo y la espalda totalmente apoyada.","Agarre: Sostenga las mancuernas con un agarre neutral (martillo), con las palmas una frente a la otra."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4920b7c0-c0de-4e80-babe-4920b7c00000', 'Plancha', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Reverse-plank.gif', '{"La plancha inversa es un entrenamiento de cuerpo completo muy eficaz que se dirige a todos los grupos de músculos principales del cuerpo. La plancha inversa fortalece y tonifica todo el cuerpo, mejora la postura y el equilibrio, reduce la grasa corporal y puede ayudar a acelerar el metabolismo. Si tiene problemas de espalda y lumbares, una plancha invertida realizada correctamente podría aliviar el dolor fortaleciendo los músculos centrales. Sin embargo, si no lo estás haciendo bien y sientes dolor de cuello o espalda durante el ejercicio, comienza primero con una variación más fácil, como una plancha normal."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('55fbef43-c0de-4e80-babe-55fbef430000', 'Extensión de tríceps', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/hyperextension.gif', '{"Los ejercicios de hiperextensión son un excelente ejercicio que fortalece el core, la espalda baja, los glúteos y los isquiotibiales.","El movimiento de hiperextensión mejora su postura al extender los músculos de la espalda y reducir la tensión entre la zona lumbar y las áreas centrales. También mejora la fuerza de la espalda baja, lo que facilita mantenerse erguido durante todo el día.","También es beneficioso para la salud de la espalda baja, ya que algunos dolores lumbares pueden deberse a glúteos débiles y tendones de la corva tensos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('250ff9a5-c0de-4e80-babe-250ff9a50000', 'Elevaciones laterales acostado con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Dumbbell-Lying-One-Arm-Rear-Lateral-Raise.gif', '{"La elevación lateral trasera con un brazo acostado con mancuernas es un ejercicio que se utiliza para fortalecer los músculos laterales y posteriores del hombro y los grupos de músculos más pequeños adjuntos a ellos. Levantar demasiado peso en este movimiento puede no ser saludable, hacer el ejercicio con pesas livianas y con muchas repeticiones puede ser más beneficioso para los músculos deltoides y del manguito rotador."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6b8ad60a-c0de-4e80-babe-6b8ad60a0000', 'Pájaro / Vuelos posteriores inclinado en polea', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/bent-over-reverse-cable-fly.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('578cb9d6-c0de-4e80-babe-578cb9d60000', 'Ejercicio con banda de resistencia', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Band-pull-apart.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3629e84d-c0de-4e80-babe-3629e84d0000', 'Elevación inclinado con barra', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Bent-Over-Barbell-Reverse-Raise.gif', '{"La elevación inversa con barra inclinada es un ejercicio isola que se dirige a la parte posterior y a los lados de los hombros. Adecuado para todos los niveles, este entrenamiento de hombros es una buena opción para desarrollar fuerza, mejorar la movilidad del hombro y dar forma a los músculos posteriores del hombro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6e46e173-c0de-4e80-babe-6e46e1730000', 'Ejercicio', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/weighted-round-arm.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3101a70b-c0de-4e80-babe-3101a70b0000', 'Press de pecho en máquina', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Inner-Chest-Press-Machine.gif', '{"Comience con las manijas cerca de su pecho.","Fase de retorno Lleve lentamente las manijas a la posición inicial mientras mantiene el control. Evite que las pesas vuelvan a golpear la pila.","Posición inicial: Comience con las manijas cerca de su pecho.","Comience con las asas cerca de su pecho.","Press Phase Empuje las manijas hacia adelante y ligeramente hacia adentro, extendiendo completamente los brazos sin bloquear los codos. Concéntrese en apretar los músculos del pecho al final del movimiento.","Concéntrate en apretar los músculos del pecho al final del movimiento.","Repetir: realice el número deseado de repeticiones, manteniendo un tempo constante."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1ff484d9-c0de-4e80-babe-1ff484d90000', 'Press de pecho', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/scott-press.gif', '{"Sostenga una mancuerna en cada mano y comience con los brazos al nivel de los hombros, doblados en ángulos de aproximadamente 90 grados. Con las palmas una frente a la otra.","Antes de que las mancuernas alcancen la parte superior del movimiento, gírelas ligeramente hacia arriba y hacia afuera, baje las muñecas a la posición inicial (con las palmas una frente a la otra) y repita el movimiento.","Realice un movimiento de rotación como con Arnold Press.","Repita el movimiento durante el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('459ece0a-c0de-4e80-babe-459ece0a0000', 'Elevaciones laterales en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Two-Arm-Cable-Lateral-Raise.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2bcac9f6-c0de-4e80-babe-2bcac9f60000', 'Elevaciones frontales', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Weight-Plate-Front-Raise-1.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('409a9ef9-c0de-4e80-babe-409a9ef90000', 'Press de hombros en polea', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Cable-Shoulder-Press.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2873c995-c0de-4e80-babe-2873c9950000', 'Elevaciones frontales en polea', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Double-Cable-Front-Raise.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('067158df-c0de-4e80-babe-067158df0000', 'Extensión de tríceps de pie', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Standing-Hip-Extension.gif', '{"La extensión de cadera de pie es un ejercicio sencillo que ayuda a desarrollar y fortalecer los músculos de la cadera. Incorporar una banda de resistencia en estos ejercicios de extensión de cadera ayudará a aumentar la resistencia contra la que trabaja su cuerpo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('64848650-c0de-4e80-babe-648486500000', 'Elevación con barra', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Barbell-Rear-Delt-Raise.gif', '{"El levantamiento del deltoides trasero con barra es un ejercicio con barra que se dirige principalmente a los hombros laterales y posteriores. Es un ejercicio eficaz que puedes incluir en tu programa para aislar los músculos posteriores del hombro y fortalecer los músculos del manguito rotador.","También activa los músculos trapecios y puede beneficiar las molestias causadas por la debilidad muscular, como la postura postural y la protrusión del omóplato, al afectar los músculos infraespinoso y subescápula que cubren la escápula."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5ae220ba-c0de-4e80-babe-5ae220ba0000', 'Press de pecho', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Landmine-Press.gif', '{"Es un ejercicio funcional avanzado que aumenta la fuerza, la resistencia y el rendimiento. La prensa de minas terrestres ayuda a mejorar la coordinación, la resistencia muscular y el equilibrio. Le ayudan a ganar fuerza en la parte superior e inferior del cuerpo trabajando los músculos centrales, los cuádriceps, los glúteos y los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3672399e-c0de-4e80-babe-3672399e0000', 'Ejercicio en polea', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Cable-Rear-Drive.gif', '{"- Configure la máquina de cable Coloque una manija única en la polea alta de una máquina de cable. Seleccione un peso apropiado que le permita mantener el control y la forma adecuada.","- Conecte una sola manija a la polea alta de una máquina de cable.","- Seleccione un peso apropiado que le permita mantener el control y la forma adecuada.","- ColóquesePárate con el costado mirando hacia la máquina de cable.Agarra el mango con un agarre por encima de la mano usando la mano más alejada.Coloca la mano cerca del hombro opuesto con el codo doblado.Mantén los pies separados al ancho de los hombros y activa el core para lograr estabilidad.","- Párese con el costado hacia la máquina de cable.","- Agarre el mango con un agarre por encima de la cabeza con la mano más alejada.","- Coloque su mano cerca de su hombro opuesto con el codo doblado.","- Haga una breve pausa al final del movimiento antes de volver a la posición inicial.","- Utilice un peso de ligero a moderado para centrarse en la contracción muscular en lugar de simplemente levantar cargas más pesadas.","- Usar demasiado peso, lo que lleva a un control deficiente y a una forma comprometida.","- Mantenga los pies separados a la altura de los hombros y active el núcleo para lograr estabilidad.","- Extiende completamente el brazo hasta que el tríceps esté completamente contraído.","- Mantenga un movimiento lento y controlado durante todo el ejercicio.","- Mantenga el codo fijo en una posición para garantizar la participación completa del tríceps.","- EjecuciónComience extendiendo el brazo hacia atrás con un movimiento controlado. Mantenga el codo en su lugar mientras mueve solo el antebrazo. Extienda completamente el brazo hasta que el tríceps esté completamente contraído. Haga una breve pausa al final del movimiento antes de volver a la posición inicial. Mantenga un movimiento lento y controlado durante todo el ejercicio.","- Comience extendiendo el brazo hacia atrás con un movimiento controlado.","- Extienda el brazo por completo pero sin bloquear el codo para evitar tensión en las articulaciones.","- Mantenga una postura recta con el core comprometido para evitar movimientos innecesarios.","- Controle el movimiento y evite sacudidas o utilizar el impulso para mover el peso.","### Errores comunes a evitar","- Permitir que el codo se mueva hacia adelante o hacia afuera, lo que reduce la activación del tríceps.","- Inclinar excesivamente el torso, en lugar de mantener una postura estable.","- Mantenga el codo en su lugar mientras mueve solo el antebrazo.","- Repetir Complete el número deseado de repeticiones antes de cambiar al otro brazo.","- Complete el número deseado de repeticiones antes de cambiar al otro brazo.","### Consejos para una forma adecuada","- No extender completamente el brazo, limitando la efectividad del ejercicio.","- Apresurarse en las repeticiones, en lugar de utilizar movimientos lentos y controlados para maximizar la participación de los músculos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4bf4dfc6-c0de-4e80-babe-4bf4dfc60000', 'Ejercicio con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Dumbbell-Scaption.gif', '{"La escapción con mancuernas es un ejercicio de aislamiento que favorece el desarrollo de los músculos del hombro y especialmente del músculo supraespinoso. Al apuntar a los músculos estabilizadores, protege la articulación del hombro y los ligamentos que la rodean. Sin embargo, también se utiliza para fortalecer el hombro y prevenir lesiones en los manguitos rotadores. Se recomienda realizarlo con poco peso en lugar de levantar demasiado peso."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0ecfb3af-c0de-4e80-babe-0ecfb3af0000', 'Ejercicio con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Dumbbell-Cuban-External-Rotation.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('779d35c8-c0de-4e80-babe-779d35c80000', 'Press de hombros unilateral con mancuerna', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Dumbbell-One-Arm-Shoulder-Press.gif', '{"Párese con los pies separados a la altura de los hombros y sostenga una mancuerna en una mano al nivel de los hombros con la palma hacia adelante. Mantenga su núcleo comprometido y su pecho erguido.","Presione la mancuerna hacia arriba y por encima de su cabeza, estirando el brazo por completo.","Haga una pausa breve en la parte superior del movimiento, luego baje lentamente la mancuerna hasta el nivel de los hombros.","Repita hasta el número deseado de repeticiones, luego cambie de lado y repita con el otro brazo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('476906f2-c0de-4e80-babe-476906f20000', 'Press de pecho con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Dumbbell-W-Press.gif', '{"Dumbbell W Press es un ejercicio de aislamiento que apoya el desarrollo de los músculos del hombro y especialmente del músculo deltoides anterior y lateral. Se recomienda realizarlo con poco peso en lugar de levantar demasiado peso.","Muchos de los movimientos que trabajan el mismo grupo de músculos pueden parecer similares, pero se enfocan en diferentes partes de los músculos porque están en diferentes ángulos. Si desea desarrollar mejores músculos específicamente, tenga en cuenta que es más beneficioso incluir ejercicios que se centren en diferentes aspectos de su programa de entrenamiento."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('079fe089-c0de-4e80-babe-079fe0890000', 'Press de hombros de pie en máquina', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Standing-Smith-Machine-Shoulder-Press.gif', '{"Coloque la barra de la máquina Smith a una altura adecuada. La barra debe estar al nivel de tus hombros cuando estés de pie.","Párese con los pies separados a la altura de los hombros, de cara a la máquina Smith. Colóquese debajo de la barra, asegurándose de que esté equilibrada y estable.","Sujete la barra con un agarre por encima de la cabeza, ligeramente más ancha que el ancho de los hombros. Tus palmas deben mirar hacia adelante.","Comienza doblando los codos y bajando la barra hacia los hombros, con los antebrazos perpendiculares al suelo.","Haga una pausa breve en la parte superior del movimiento, asegurándose de que sus brazos estén completamente extendidos pero no bloqueados.","Baje la barra nuevamente bajo control, inhalando mientras desciende y repita hasta el número deseado de repeticiones.","Presione la barra hacia arriba extendiendo los brazos completamente y exhalando mientras levanta.","Involucre su núcleo y mantenga una postura adecuada durante todo el ejercicio, con el pecho levantado y los hombros hacia atrás."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0a9ffecf-c0de-4e80-babe-0a9ffecf0000', 'Aperturas de pecho con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Dumbbell-Upward-Fly.gif', '{"Párese con los pies separados a la altura de los hombros. Sostenga una mancuerna en cada mano, con las palmas hacia adelante. Para comenzar, elija un peso adecuado para su nivel de condición física.","Comience con los brazos extendidos hacia los costados y las mancuernas cerca de los muslos.","Configuración: Párese con los pies separados a la altura de los hombros. Sostenga una mancuerna en cada mano, con las palmas hacia adelante. Para comenzar, elija un peso adecuado para su nivel de condición física.","Posición inicial: Comience con los brazos extendidos hacia los costados y las mancuernas cerca de los muslos.","El movimiento: Inhale y levante lentamente ambas mancuernas hacia adelante y hacia arriba en un arco amplio. Mientras levanta, concéntrese en apretar los músculos de la parte superior del pecho. Continúe levantando hasta que las mancuernas se encuentren frente a su pecho, o ligeramente por encima del nivel del pecho. Haga una breve pausa en la parte superior del movimiento, sintiendo la contracción en la parte superior del pecho.","Inhale y levante lentamente ambas mancuernas hacia adelante y hacia arriba formando un amplio arco.","Haga una pausa breve en la parte superior del movimiento y sienta la contracción en la parte superior del pecho.","Mientras levantas, concéntrate en apretar los músculos de la parte superior del pecho.","Regreso a la posición inicial: Exhale mientras baja lentamente las mancuernas a lo largo del mismo arco amplio hasta la posición inicial, con los brazos extendidos a los lados."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('37b1845a-c0de-4e80-babe-37b1845a0000', 'Press de hombros de pie con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Standing-Alternating-Dumbbell-Shoulder-Press.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('09739cf2-c0de-4e80-babe-09739cf20000', 'Remo', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Narrow-Grip-Wall-Push-Up.gif', '{"- Párese frente a una pared, aproximadamente a 1 o 2 pies de distancia, según su nivel de comodidad y fuerza.","- Coloque las manos en la pared a la altura del pecho, un poco más juntas que el ancho de los hombros.","- Posición inicial: con los brazos rectos pero no bloqueados, mantenga el cuello y la columna en posición neutra.","- Fase de empuje: Empuje con las palmas de las manos para estirar los brazos y volver a la posición inicial.","- Pausa: deténgase cuando sus codos formen un ángulo de 90 grados o lo más cerca que pueda llegar cómodamente.","- Progrese gradualmente: comience más cerca de la pared y aumente la distancia a medida que gana fuerza.","- Involucre el núcleo: apriete los abdominales durante todo el movimiento para evitar que se arqueen o se caigan.","- Fase de descenso: doble lentamente los codos, manteniéndolos cerca del cuerpo mientras el pecho se mueve hacia la pared.","- Repetir: Realice el número deseado de repeticiones con movimiento controlado.","- Combínelo con otros ejercicios: combínelo con flexiones o fondos tradicionales para un entrenamiento integral de la parte superior del cuerpo.","- Acelerar el movimiento: realice el ejercicio lentamente y con control para maximizar la activación muscular.","- Controle su respiración: inhale mientras desciende hacia la pared y exhale mientras empuja hacia la posición inicial.","### Errores comunes a evitar","- Involucre su núcleo y mantenga su cuerpo en línea recta desde la cabeza hasta los talones.","### Consejos para una máxima eficacia","- Espalda caída o arqueada: mantenga su núcleo comprometido para mantener una línea recta desde la cabeza hasta los talones.","- Codos extendidos: asegúrese de que sus codos permanezcan cerca de su cuerpo para apuntar a los tríceps de manera efectiva.","- Colocación inadecuada de las manos: Las manos deben estar un poco más juntas que el ancho de los hombros para lograr la forma adecuada."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2f33ee1b-c0de-4e80-babe-2f33ee1b0000', 'Ejercicio en polea', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Cable-External-Shoulder-Rotation.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('529f986b-c0de-4e80-babe-529f986b0000', 'Press de pecho con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/dumbbell-cuban-press-.gif', '{"El manguito rotador es el grupo de músculos y tendones que mantienen la cabeza del hueso de la parte superior del brazo firmemente dentro de la cavidad del hombro. El propósito de este ejercicio es fortalecer los músculos del manguito conectados con el hombro y proteger la salud del hombro.","El press cubano es uno de los ejercicios integrales destinados a desarrollar la fuerza funcional en los hombros y el manguito rotador. A menudo se utiliza como movimiento avanzado para entrenar los músculos del manguito rotador. Este ejercicio trabaja todas las posiciones de la cabeza de los músculos del hombro, al mismo tiempo que estimula los músculos de la parte superior de la espalda y el pecho.","Es muy importante realizar el movimiento con la técnica adecuada, y levantar exceso de peso puede ser más perjudicial que beneficioso, por lo que se recomienda poco peso. Puedes practicar el ejercicio con la ayuda de una barra, mancuerna o un palo vacío."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1364110f-c0de-4e80-babe-1364110f0000', 'Elevaciones laterales inclinado con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Incline-Dumbbell-Side-Lateral-Raise.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('56e587d7-c0de-4e80-babe-56e587d70000', 'Ejercicio en polea', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Cable-Internal-Shoulder-Rotation.gif', '{"Los ejercicios de rotación son ejercicios diseñados para fortalecer los músculos del manguito rotador conectados a los músculos del hombro. Fortalecer los músculos del manguito rotador con estos ejercicios antes del entrenamiento de hombros es beneficioso para la salud de su hombro.","Para renovar todo el músculo para lograr un mejor equilibrio muscular y estabilidad de las articulaciones, debe trabajarlo en un rango completo de movimiento. Realizar ejercicios de hombro diseñados para fortalecer los músculos y mejorar el rango de movimiento del hombro reducirá la tensión en la articulación, haciéndola menos susceptible a inflamaciones articulares como tendinitis y bursitis."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6f0f0d14-c0de-4e80-babe-6f0f0d140000', 'Estiramiento de pie', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Standing-Reach-Up-Back-rotation-Stretch.gif', '{"Puede utilizar este ejercicio para estirar más de un grupo de músculos. Especialmente al estirar los músculos de la espalda, los músculos del pecho, los hombros y los tríceps también ganarán flexibilidad. Agregar estiramientos a su entrenamiento general ayudará a aumentar la movilidad y flexibilidad de sus músculos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('66a1cfb1-c0de-4e80-babe-66a1cfb10000', 'Elevaciones laterales acostado con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Dumbbell-Side-Lying-Rear-Delt-Raise.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3a5f21d7-c0de-4e80-babe-3a5f21d70000', 'Estiramiento', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Across-Chest-Shoulder-Stretch.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('42f97dfa-c0de-4e80-babe-42f97dfa0000', 'Estiramiento', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Shoulder-Stretch-Behind-Back.gif', '{"- Párate en una postura neutral con los pies separados a la altura de los hombros.","- ¿Se tocan o están a punto de tocarse? ¿Se superponen? ¿Un lado se siente más apretado que el otro?","- Cambie de lado y observe sus resultados.","- Sostenga una toalla o banda de resistencia con ambas manos detrás de la espalda.","- Utilice la toalla para ayudar a estirar los brazos si juntar las manos le resulta difícil.","- Siga la misma técnica anterior, asegurando un estiramiento controlado.","- Levante un brazo por encima y doble el codo para alcanzar la espalda.","- Al mismo tiempo, lleve el otro brazo detrás de la espalda desde abajo, con el objetivo de tocar o superponer los dedos.","- Comience gradualmente: comience con un rango de movimiento más pequeño y aumente a medida que mejore su flexibilidad.","- Combínelo con otros estiramientos de hombros: combine este estiramiento con movimientos como estiramientos inversos de hombros o estiramientos asistidos para una rutina integral.","- Usando Momentum: Realice el estiramiento lentamente y con control para evitar movimientos bruscos que puedan tensar los músculos.","### Prueba de flexibilidad del hombro","- Los dedos se superponen / Excelente","- Los dedos se tocan / Bien","- Las yemas de los dedos no se tocan, pero están a menos de 5 cm (2 pulgadas) de distancia. / Justo","- Las yemas de los dedos están separadas por más de dos pulgadas (5 cm). / Pobre","- Incorporar en los descansos laborales: utilice este estiramiento durante largos períodos de estar sentado para reducir la tensión y mejorar la postura.","### Consejos para una máxima eficacia","- Arqueando la espalda: Mantenga su núcleo comprometido para evitar un arqueo excesivo en la columna lumbar.","- Encorvar los hombros: asegúrese de que los hombros estén hacia atrás y hacia abajo, en lugar de encogerse de hombros hacia arriba.","- Respire profundamente: respire lenta y profundamente durante el estiramiento para ayudar a relajar los músculos y mejorar la flexibilidad.","### Errores comunes a evitar","- Forzar el rango de movimiento: estírese sólo hasta un punto cómodo; Evite extender demasiado los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3fc03c59-c0de-4e80-babe-3fc03c590000', 'Press de pecho con barra', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Barbell-Clean-and-Press-.gif', '{"Fortalece la capacidad de agarre. Le permite agarrar un objeto con más firmeza cuando lo sostiene. Además, los estudios demuestran que el clean and press es un ejercicio eficaz para mejorar la fuerza explosiva y el rendimiento del salto vertical.","La limpieza y prensa con barra ayuda al desarrollo de los músculos de las piernas, los músculos de la cadera y los músculos centrales, al mismo tiempo que apoya la formación de músculos y fuerza en el cuerpo. Además, agregar clean y press a tus entrenamientos ayuda a fortalecer tus tendones, ligamentos y huesos.","La limpieza y el press con barra también activan los glúteos y los músculos de la espalda. Los ejercicios funcionales como clean y press son aquellos que facilitan las actividades del cuerpo en la vida real.","El músculo principal que se trabaja en una limpieza y prensa son los hombros, pero el movimiento también trabaja los tríceps, los trapecios, la espalda media y baja, los abdominales, los cuádriceps, los glúteos, los isquiotibiales y las pantorrillas. Es un ejercicio de cuerpo completo, que no sólo se puede realizar para hipertrofia, sino también para fuerza. Este ejercicio te permite desarrollar resistencia y resistencia cardiovascular, así como resistencia muscular e incluso fuerza. Es el movimiento más popular de fuerza y ​​entrenamiento de fuerza ya que trabaja muchos grupos de músculos.","La forma correcta es muy importante en este ejercicio. Para empezar, hacer mal puede provocar lesiones. Tras algunos intentos con la barra vacía o acompañado de un entrenador, el proceso de adaptación al movimiento puede verse acortado.","La limpieza y el press con barra se dirigen a todos los músculos responsables de la postura y le permiten mantener la espalda recta durante las actividades diarias habituales."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('403cc8e7-c0de-4e80-babe-403cc8e70000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/12/Bench-Glute-Flutter-Kicks.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('660019a2-c0de-4e80-babe-660019a20000', 'Ejercicio con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Dumbbell-Lateral-Step-Up.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('23e29797-c0de-4e80-babe-23e297970000', 'Remo inclinado en máquina', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Smith-Machine-Bent-Over-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('48784605-c0de-4e80-babe-487846050000', 'Giro ruso', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Step-Up-Opposite-Elbow-to-Knee-Twist.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('70bf095d-c0de-4e80-babe-70bf095d0000', 'Ejercicio', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Power-Clean-.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('58d30985-c0de-4e80-babe-58d309850000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Lateral-Step-up.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('654d1d91-c0de-4e80-babe-654d1d910000', 'Ejercicio con banda de resistencia', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Band-Assisted-Sprinter-Run.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2e12be6c-c0de-4e80-babe-2e12be6c0000', 'Ejercicio con barra', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Barbell-Step-Up.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('07f0c6d5-c0de-4e80-babe-07f0c6d50000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Close-Grip-Chin-Up.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('71ad19a9-c0de-4e80-babe-71ad19a90000', 'Ejercicio', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Body-Ups.gif', '{"- Posición inicial Comience en una posición de plancha con el antebrazo con los codos directamente debajo de los hombros. Mantenga los pies separados a la altura de las caderas y mantenga una línea recta desde la cabeza hasta los talones. Involucre el núcleo y los glúteos para estabilizar el cuerpo.","- Comience en una posición de plancha con el antebrazo con los codos directamente debajo de los hombros.","- Baje lentamente hasta la posición inicial sin colapsar el torso.","- Concéntrese en una distribución uniforme del peso entre ambos brazos para evitar desequilibrios.","- Mantenga los pies separados a la altura de las caderas y mantenga una línea recta desde la cabeza hasta los talones.","- Involucre su núcleo y glúteos para estabilizar su cuerpo.","- Mantenga su núcleo apretado y mantenga el control durante todo el movimiento.","- Mantenga una alineación recta del cuerpo desde la cabeza hasta los talones durante todo el movimiento.","- EjecuciónPresione a través de sus antebrazos y empuje la parte superior de su cuerpo hacia arriba hasta que sus codos estén completamente extendidos. Mantenga su núcleo apretado y mantenga el control durante todo el movimiento. Baje lentamente hasta la posición inicial sin colapsar su torso. Repita hasta el número deseado de repeticiones mientras mantiene la forma adecuada.","- Presione con los antebrazos y empuje la parte superior del cuerpo hacia arriba hasta que los codos estén completamente extendidos.","- Involucre su núcleo y glúteos para evitar un movimiento excesivo de la cadera.","- Utilice movimientos controlados en lugar de depender del impulso.","### Errores comunes a evitar","- Permitir que las caderas se hundan, lo que reduce la activación del núcleo y puede tensar la zona lumbar.","- Depender del impulso en lugar del compromiso muscular controlado.","- Repita hasta el número deseado de repeticiones manteniendo la forma adecuada.","### Consejos para una forma adecuada","- Mantenga los codos cerca del cuerpo para maximizar la participación de los tríceps.","- Contener la respiración, en lugar de mantener una respiración constante para mejorar el rendimiento.","- Ensanchar los codos hacia afuera, lo que puede disminuir la activación de los tríceps y aumentar la tensión en los hombros.","- No extender completamente los codos, limitando la efectividad del ejercicio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4141a2b7-c0de-4e80-babe-4141a2b70000', 'Estiramiento acostado', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Lying-glute-stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('15dbbcbb-c0de-4e80-babe-15dbbcbb0000', 'Extensión de tríceps', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Floor-Hyperextension-1.gif', '{"Este movimiento fortalece los músculos erectores de la columna que brindan soporte a la columna. Unos músculos fuertes de la espalda pueden prevenir desviaciones posturales que provocan malas posturas y molestias, como la cifosis (“jorobada”). El movimiento de hiperextensión del piso mejora su postura al extender los músculos de la espalda y reducir la tensión entre la zona lumbar y las áreas centrales. También mejora la fuerza de la espalda baja, lo que facilita mantenerse erguido durante todo el día."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2d1e2fe5-c0de-4e80-babe-2d1e2fe50000', 'Ejercicio unilateral', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Single-Arm-Circles.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0dcf0bf5-c0de-4e80-babe-0dcf0bf50000', 'Pájaro / Vuelos posteriores acostado en polea', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Lying-Cable-Reverse-Fly.gif', '{"El objetivo del ejercicio de vuelo inverso con cable tumbado son los músculos de la espalda y los hombros. Es un excelente ejercicio de fortalecimiento que trabaja eficazmente muchos músculos, incluidos el hombro, el manguito rotador y el trapecio. Al afectar el músculo infraespinoso que cubre la escápula, puede ayudar a protegerlo de dolencias causadas por la debilidad muscular, como el trastorno de la postura y la protrusión de la escápula. Además, fortalecer estos músculos mediante el ejercicio de vuelo inverso con cable ayudará a mejorar la mala postura, promoverá una postura erguida y mejorará el equilibrio.","El ejercicio de vuelo inverso con cable te ayudará a desarrollar una espalda y unos hombros definidos. Es uno de los ejercicios que debes hacer si quieres tener el músculo del hombro definido y más desmenuzado."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('67bc4176-c0de-4e80-babe-67bc41760000', 'Ejercicio con barra', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Barbell-Bent-Arm-Pullover.gif', '{"- Acuéstese en un banco plano, sosteniendo la barra sobre su pecho con una ligera flexión de los codos.","- Controla el movimiento en todo momento, especialmente al volver a la posición inicial.","- Utilice un ancho de agarre moderado para lograr un compromiso equilibrado del pecho y los dorsales.","- Baje hasta que sienta un estiramiento profundo en los dorsales y el pecho; evite ir demasiado lejos si la movilidad del hombro es limitada.","- Exhala y tira de la barra hacia atrás sobre tu pecho usando tu pecho y tus dorsales.","- Controle la fase excéntrica para lograr el máximo estiramiento y seguridad.","- Inhale profundamente, contraiga su núcleo y baje la barra formando un arco detrás de su cabeza, manteniendo los brazos casi rectos.","- Detenga el descenso si siente molestias en el hombro; nunca fuerce el rango de movimiento.","- Usar impulso en lugar de movimiento controlado.","### Errores comunes a evitar","- Arqueando la zona lumbar, ejerciendo presión sobre la columna lumbar.","- Dejar que la barra caiga demasiado detrás de la cabeza, corre el riesgo de sufrir tensión en el hombro.","- Repita para el número deseado de repeticiones.","### Consejos para una forma adecuada","- Mantenga los codos ligeramente doblados, no bloqueados ni extendidos hacia afuera.","- Mantenga la extensión torácica (parte superior de la espalda ligeramente arqueada).","- Descuidar el control de la respiración, reduciendo la estabilidad central y la tensión.","- Bloquear los codos, lo que transfiere la carga al tríceps y la articulación del codo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2da6c68b-c0de-4e80-babe-2da6c68b0000', 'Curl de piernas acostado con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Lying-Dumbbell-Leg-Curl.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5ebb5438-c0de-4e80-babe-5ebb54380000', 'Extensión de tríceps', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Flat-Bench-Hyperextension.gif', '{"Los ejercicios de hiperextensión son un excelente ejercicio que fortalece el core, la espalda baja, los glúteos y los isquiotibiales.","El movimiento de hiperextensión mejora su postura al extender los músculos de la espalda y reducir la tensión entre la zona lumbar y las áreas centrales. También mejora la fuerza de la espalda baja, lo que facilita mantenerse erguido durante todo el día.","También es beneficioso para la salud de la espalda baja, ya que algunos dolores lumbares pueden deberse a glúteos débiles y tendones de la corva tensos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0cb7404a-c0de-4e80-babe-0cb7404a0000', 'Press de pecho declinado en máquina', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Decline-Chest-Press-Machine.gif', '{"- Ajuste el asiento de modo que las manijas queden al nivel del pecho cuando esté sentado.","- Siéntese en la máquina con la espalda firmemente apoyada en el respaldo y los pies apoyados en el suelo.","- Sujete las manijas con un agarre neutral o en pronación, según el diseño de la máquina.","- Posición inicial: Sostenga las manijas con los brazos extendidos pero los codos ligeramente doblados para evitar bloquearse. Involucre su núcleo y mantenga los hombros hacia abajo y hacia atrás.","- Ajuste el agarre: experimente con diferentes agarres (neutrales o por encima de la cabeza) para variar ligeramente la activación muscular.","- Sobrecargar la máquina: utilice un peso manejable para mantener la forma adecuada y evitar depender del impulso.","- Sostenga las manijas con los brazos extendidos pero los codos ligeramente doblados para evitar bloquearse.","- Fase de prensado: Empuje las manijas hacia la posición inicial extendiendo los brazos y apretando el pecho en la parte superior del movimiento.","- Empuje las manijas hacia la posición inicial extendiendo los brazos y apretando el pecho en la parte superior del movimiento.","- Fase de descenso: Lleve lentamente las manijas hacia su pecho, manteniendo el control y manteniendo los codos en un ángulo natural (no ensanchados).","- Lleve lentamente las manijas hacia su pecho, manteniendo el control y manteniendo los codos en un ángulo natural (no ensanchados).","- Controle lo negativo: baje las manijas lentamente para mejorar el tiempo bajo tensión y estimular un mayor crecimiento muscular.","- Combine con otros ejercicios para el pecho: combínelo con movimientos de presión planos e inclinados para lograr un desarrollo integral del pecho.","- Acelerar el movimiento: realice el ejercicio lentamente y con control para maximizar la participación de los músculos y reducir el riesgo de lesiones.","- Repetir: realice la cantidad deseada de repeticiones, manteniendo la forma adecuada en todo momento.","- Respire adecuadamente: inhale mientras baja las manijas y exhale mientras las empuja hacia la posición inicial.","### Errores comunes a evitar","- Involucre su núcleo y mantenga los hombros hacia abajo y hacia atrás.","### Consejos para una máxima eficacia","- Concéntrese en la contracción muscular: apriete el pecho en la parte superior de cada presión para una activación máxima.","- Arqueando la espalda: Mantenga la espalda firmemente presionada contra el respaldo para evitar tensión en la zona lumbar.","- Bloquear los codos: evite bloquear completamente los codos en la parte superior para mantener la tensión en los músculos del pecho.","- Altura del asiento incorrecta: asegúrese de que las manijas estén alineadas con su pecho para optimizar la activación muscular y evitar movimientos incómodos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('424e3d75-c0de-4e80-babe-424e3d750000', 'Press de pecho acostado en máquina', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Lying-Chest-Press-Machine.gif', '{"- Ajuste la altura del asiento para que las manijas se alineen con el nivel de la mitad del pecho cuando esté sentado.","- Siéntese con la columna firmemente apoyada en el respaldo y los pies apoyados en el suelo.","- Agarre las manijas con un agarre por encima, asegurándose de que sus muñecas permanezcan rectas.","- Posición inicial Sostenga las manijas con los brazos extendidos pero los codos ligeramente doblados para evitar bloquearse. Involucre su núcleo y mantenga los hombros hacia abajo y hacia atrás.","- Varíe las posiciones de agarre: use diferentes agarres (estrechos o anchos) para apuntar a diferentes áreas del pecho.","- Sostenga las manijas con los brazos extendidos pero los codos ligeramente doblados para evitar bloquearse.","- Deténgase cuando sus codos estén al nivel del pecho o ligeramente por debajo.","- Presionando PhaseEmpuje las manijas hacia la posición inicial extendiendo los brazos y apretando el pecho en la parte superior del movimiento.","- Fase de descenso Lleve lentamente las manijas hacia su pecho, manteniendo un movimiento controlado. Deténgase cuando sus codos estén al nivel del pecho o ligeramente por debajo.","- Lleve lentamente las manijas hacia su pecho, manteniendo un movimiento controlado.","- Controle la fase excéntrica: baje las manijas lentamente para aumentar el tiempo bajo tensión y promover el crecimiento muscular.","- Respire adecuadamente: exhale mientras presiona las manijas hacia arriba e inhale mientras las baja.","- Empuje las manijas hacia la posición inicial extendiendo los brazos y apretando el pecho en la parte superior del movimiento.","- Repetir: realice la cantidad deseada de repeticiones mientras mantiene el control y la forma adecuada.","- Involucre su núcleo y mantenga los hombros hacia abajo y hacia atrás.","### Consejos para una máxima eficacia","- Concéntrese en la contracción muscular: apriete el pecho en la parte superior de la prensa para maximizar la participación de los músculos.","- Combínelo con pesas libres: combínelo con ejercicios como el press de banca o el vuelo con mancuernas para un entrenamiento de pecho completo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7ca906fe-c0de-4e80-babe-7ca906fe0000', 'Remo', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Table-Inverted-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2a7c7f5c-c0de-4e80-babe-2a7c7f5c0000', 'Elevaciones laterales', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Hanging-Side-Knee-Raises.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7d512d06-c0de-4e80-babe-7d512d060000', 'Ejercicio sobre pelota de estabilidad', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Stability-Ball-Knee-Tuck.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('018bf953-c0de-4e80-babe-018bf9530000', 'Extensión de tríceps en máquina', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Reverse-Hyperextension-Machine.gif', '{"El músculo principal que activa la máquina de hiperextensión inversa es el glúteo mayor. Es uno de los ejercicios que puedes incluir en tus entrenamientos para tensar y tonificar los glúteos, mejorar la movilidad de la cadera y fortalecer la zona lumbar."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3872dc10-c0de-4e80-babe-3872dc100000', 'Encogimiento de hombros en máquina', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/smith-machine-shrug.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('41beee67-c0de-4e80-babe-41beee670000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Toes-to-Bar.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5a2ce960-c0de-4e80-babe-5a2ce9600000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Hanging-Windshield-Wiper.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7451f2f1-c0de-4e80-babe-7451f2f10000', 'Elevación', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/weighted-hanging-knee-raises.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('00a602f4-c0de-4e80-babe-00a602f40000', 'Press de pecho inclinado con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Close-grip-Incline-Dumbbell-Press.gif', '{"Ajuste un banco a una inclinación de aproximadamente 30 a 45 grados.","Siéntate en el banco con una mancuerna en cada mano, apoyándolas sobre tus muslos.","Recuéstese en el banco y junte las mancuernas sobre su pecho, con las palmas una frente a la otra en un agarre neutral."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('05c224d7-c0de-4e80-babe-05c224d70000', 'Elevación de pantorrillas de pie con barra', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Standing-Barbell-Calf-Raise.gif', '{"Coloque una plataforma elevada resistente o pise el piso. Cargue una barra y colóquela en la parte superior de la espalda, como en una sentadilla trasera.","Configuración: Coloque una plataforma elevada resistente o pise el piso. Cargue una barra y colóquela en la parte superior de la espalda, como en una sentadilla trasera.","Posición de los pies: Súbase a la plataforma de modo que solo las puntas de los pies estén en contacto. Tus talones deben colgar del borde para permitir un rango completo de movimiento.","Levante los talones: empuje las puntas de los pies para elevar los talones lo más alto posible, contrayendo completamente los músculos de las pantorrillas.","Pausa en la parte superior: Mantenga la posición superior durante 1 a 2 segundos para maximizar la tensión.","Alineación del cuerpo: Párate erguido, mantén el core apretado, el pecho erguido y los hombros hacia atrás. Mantenga una columna neutra en todo momento.","Repetir: Realiza el número deseado de repeticiones con precisión y equilibrio.","Baja lentamente: Baja los talones por debajo del nivel de la plataforma de forma controlada, logrando un estiramiento completo en las pantorrillas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4315735c-c0de-4e80-babe-4315735c0000', 'Press de pecho en máquina', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Smith-Machine-Hex-Press.gif', '{"- Colóquese en el banco debajo de la barra de la máquina Smith.","- Utilice un accesorio de agarre en V, agarrando las manijas con las palmas una frente a la otra y los nudillos alineados.","- Concéntrese en mantener un ritmo controlado, permitiendo que las manijas de agarre en V se acerquen a su pecho.","- Una vez que el agarre en V toque ligeramente su pecho, presione explosivamente la barra hacia arriba usando los músculos del pecho.","- Sobrecargar la barra: utilice un peso manejable para garantizar la forma adecuada y evitar depender del impulso.","- Asegúrese de que sus muñecas estén en una posición neutral, lo que ayuda a reducir la tensión y mejora la potencia de presión.","- Empuje la barra hacia arriba para desbloquearla de su posición de reposo.","- Sostenga la barra con los brazos extendidos, directamente encima de su pecho.","- Imagínese empujar el suelo lejos de usted, ejerciendo la máxima fuerza con su pecho.","- En la parte superior del movimiento, cuando los brazos estén completamente extendidos, haga una pausa y apriete los músculos del pecho durante un segundo.","- Esta contracción intensifica el compromiso y promueve la activación muscular.","- Comienza el movimiento bajando lentamente la barra hacia tu pecho.","- Vuelva a bajar lentamente la barra, concentrándose en la fase excéntrica (negativa) del levantamiento.","- Controla el descenso y mantén la tensión en los músculos del pecho en todo momento.","- Realice el número deseado de repeticiones manteniendo la forma y el control adecuados.","- Mantenga un ritmo controlado durante las fases excéntrica y concéntrica del movimiento para maximizar la participación muscular.","- Concéntrese en su patrón de respiración, inhalando durante la fase excéntrica (descenso) y exhalando durante la fase concéntrica (presión).","### Errores comunes a evitar","### Consejos para el éxito:","- Mantenga los omóplatos retraídos y presionados durante todo el ejercicio para garantizar una activación óptima del pecho.","- Codos ensanchados: Mantenga los codos pegados al cuerpo para evitar tensiones innecesarias en los hombros.","- Ancho de agarre incorrecto: Usar un agarre demasiado ancho reduce la activación interna del pecho; mantenga un agarre estrecho.","- Arqueando la espalda: Mantenga la espalda plana sobre el banco para evitar tensiones en la parte baja de la espalda.","- Repeticiones apresuradas: realice el ejercicio lentamente y con control para maximizar la participación de los músculos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4cd5840f-c0de-4e80-babe-4cd5840f0000', 'Jalón al pecho unilateral en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Cable-One-Arm-Lat-Pulldown.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1de94e4e-c0de-4e80-babe-1de94e4e0000', 'Curl de bíceps', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/zottman-curl.gif', '{"Párese con los pies separados a la altura de los hombros y sostenga un par de mancuernas a los costados, con las palmas hacia adentro.","En la parte superior del movimiento, sostenga las mancuernas en posición supina durante un segundo, luego gire las palmas hacia abajo (pronación) y baje lentamente las pesas hasta la posición inicial.","Doble las mancuernas hacia los hombros, manteniendo los codos cerca de los costados y girando las palmas hacia arriba (supinación).","Repita hasta obtener el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('02a26762-c0de-4e80-babe-02a267620000', 'Flexiones de pecho de rodillas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Kneeling-Push-up.gif', '{"- Coloque las manos ligeramente más separadas que el ancho de los hombros, asegurándose de que los dedos apunten hacia adelante.","- Posición inicial: Alinee su cuerpo desde la cabeza hasta las rodillas en línea recta. Involucre su núcleo para evitar que la espalda baja se hunda o se arquee.","- Fase de empuje: Empuje con las manos para extender los brazos y volver a la posición inicial. Concéntrese en apretar el pecho y mantener la línea recta del cuerpo.","- Empuja con las manos para extender los brazos y volver a la posición inicial.","- Comience sobre manos y rodillas sobre una superficie cómoda, como una colchoneta.","- Coloca las rodillas en el suelo y mantén los pies relajados.","- Alinee su cuerpo desde la cabeza hasta las rodillas en línea recta.","- Involucre su núcleo para evitar que la espalda baja se hunda o se arquee.","- Fase de descenso: doble los codos y baje el pecho hacia el suelo mientras mantiene los codos en un ángulo de aproximadamente 45 grados con respecto al cuerpo. Descienda hasta que el pecho esté justo por encima del suelo o tan bajo como lo permita su movilidad.","- Doble los codos y baje el pecho hacia el suelo mientras mantiene los codos en un ángulo de aproximadamente 45 grados con respecto al cuerpo.","- Controle el movimiento: realice las fases de descenso y empuje lentamente para maximizar la activación y el control de los músculos.","- Progrese gradualmente: a medida que desarrolle fuerza, haga la transición a variaciones de flexiones más desafiantes, como flexiones inclinadas o flexiones estándar.","- Repeticiones superficiales: baje el pecho lo más cerca posible del suelo para lograr un rango de movimiento completo.","- Desciende hasta que tu pecho esté justo por encima del suelo o tan bajo como te permita tu movilidad.","- Concéntrate en apretar el pecho y mantener una línea recta del cuerpo.","- Repetir: realice el número deseado de repeticiones manteniendo la forma adecuada.","### Consejos para una máxima eficacia","- Involucre su núcleo: mantenga su núcleo apretado para mantener una línea corporal recta y evitar arquear excesivamente la parte inferior de la espalda.","- Centrarse en la calidad: priorice la forma adecuada sobre el número de repeticiones para reducir el riesgo de lesiones.","- Caderas o espalda caídas: Mantenga el cuerpo en línea recta desde la cabeza hasta las rodillas para evitar forzar la zona lumbar.","- Codos ensanchados: Evite que los codos se ensanchen excesivamente para proteger sus hombros. Apunte a un ángulo de 45 grados desde su torso.","- Colocación inadecuada de las manos: asegúrese de que sus manos estén ligeramente más separadas que el ancho de los hombros y alineadas con el pecho.","- Aguantar la respiración: Mantenga una respiración constante durante todo el ejercicio para mejorar el rendimiento y evitar la fatiga.","- Utilice una colchoneta para mayor comodidad: Proteja sus rodillas realizando el ejercicio sobre una superficie suave o una colchoneta de ejercicios.","### Errores comunes a evitar"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7d9134d7-c0de-4e80-babe-7d9134d70000', 'Curl concentrado', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Biceps-Leg-Concentration-Curl.gif', '{"El curl de concentración de bíceps con piernas es un ejercicio de aislamiento que se puede realizar con el peso corporal sin necesidad de equipo.","La flexión de concentración de piernas es un excelente movimiento del brazo para estimular las fibras musculares en la parte superior del músculo braquial y el bíceps. Debido a que giras el brazo hacia el cuerpo cuando haces flexiones de concentración, es útil centrarse más en la cabeza larga del bíceps, que constituye la masa del pico del bíceps."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('723a4484-c0de-4e80-babe-723a44840000', 'Curl de bíceps con mancuernas', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/dumbbell-reverse-curl.gif', '{"Párese con los pies separados a la altura de los hombros y sostenga un par de mancuernas frente a los muslos, con las palmas hacia abajo (agarre en pronación).","Baja lentamente las mancuernas hasta la posición inicial extendiendo los codos y manteniendo el control del peso.","Mantenga los codos cerca de los costados y levante lentamente las mancuernas hacia los hombros flexionando los codos. Mantenga las muñecas rectas y las palmas hacia abajo durante todo el movimiento.","Haz una pausa en la parte superior del movimiento y aprieta los antebrazos y los bíceps durante un segundo.","Repita hasta el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7a8391b3-c0de-4e80-babe-7a8391b30000', 'Curl concentrado sentado', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Seated-close-grip-concentration-curl.gif', '{"Siéntese en un banco o silla con los pies apoyados en el suelo y sostenga una barra con un agarre por debajo (con las palmas hacia arriba) con las manos separadas entre 6 y 8 pulgadas.","Apoye los codos en la parte interna de los muslos y permita que la barra cuelgue hacia el suelo.","Manteniendo la parte superior de los brazos inmóviles, doble la barra hacia los hombros y apriete los músculos del bíceps mientras levanta.","Haga una pausa por un momento en la parte superior del movimiento, luego baje lentamente la barra hasta la posición inicial.","Repita para el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7e0185cd-c0de-4e80-babe-7e0185cd0000', 'Aperturas de pecho declinado en polea', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Decline-Cable-Fly.gif', '{"Coloque las poleas en una máquina de cable en una posición alta, por encima del nivel de los hombros.","Párate en el medio de la máquina de cable con un mango en cada mano.","Conecte manijas en D a cada cable.","Incline el torso ligeramente hacia adelante y extienda los brazos hacia los lados con una ligera flexión de los codos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('44eb8b4e-c0de-4e80-babe-44eb8b4e0000', 'Curl de bíceps inclinado con barra', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Prone-Incline-Biceps-Curl.gif', '{"Ajuste un banco inclinado a un ángulo de 45 grados.","Acuéstese boca abajo en el banco, con el pecho y el estómago presionando contra la inclinación.","Sostenga una barra con un agarre hacia abajo, con las manos separadas al ancho de los hombros.","Aprieta los bíceps en la parte superior del movimiento, luego baja lentamente la barra hasta la posición inicial.","Deje que sus brazos cuelguen hacia el suelo, manteniendo los codos cerca del cuerpo.","Doble la barra hacia los hombros, manteniendo los codos inmóviles."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3c0148e4-c0de-4e80-babe-3c0148e40000', 'Remo con agarre inverso en máquina', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Reverse-Grip-Machine-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('02eb9c54-c0de-4e80-babe-02eb9c540000', 'Curl de bíceps sentado', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/seated-biceps-curl.gif', '{"Utilice un rango completo de movimiento: al realizar la flexión de bíceps sentado, es importante utilizar un rango completo de movimiento, levantando el peso completamente hacia los hombros y luego bajándolo nuevamente a la posición inicial.","Comience con pesas livianas: cuando comience con la flexión de bíceps sentado, es importante comenzar con pesas livianas. Esto le ayudará a concentrarse en la forma y la técnica adecuadas y a evitar lesiones.","Siéntate derecho: cuando realices la flexión de bíceps sentado, es importante sentarte derecho en el banco con los pies firmemente plantados en el suelo. Esto le ayudará a involucrar su núcleo y mantener la forma adecuada durante todo el ejercicio.","Mantenga los codos hacia adentro: mientras levanta el peso, es importante mantener los codos cerca del cuerpo. Esto le ayudará a trabajar los músculos bíceps de forma más eficaz y evitará tensión en los hombros.","Mantenga la posición durante uno o dos segundos, mientras contrae los músculos bíceps. Baje lentamente las mancuernas hasta la posición inicial, mientras mantiene el control y los codos cerca de los costados. Repita hasta el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('028a5af1-c0de-4e80-babe-028a5af10000', 'Press de pecho inclinado en máquina', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Smith-Machine-Incline-Bench-Press.gif', '{"- Ajuste el banco inclinado a un ángulo de 30 a 45 grados y colóquelo debajo de la barra de la máquina Smith.","- Siéntese en el banco con los pies apoyados en el suelo, la espalda firmemente presionada contra el banco y la barra alineada con la parte superior del pecho.","- Agarre la barra un poco más ancha que el ancho de los hombros, con las palmas hacia adelante.","- Empuja la barra hacia arriba hasta la posición inicial con un movimiento controlado.","- Desenganche la barra girando las muñecas para soltar los ganchos de seguridad.","- Detente cuando la barra esté justo encima o toque ligeramente tu pecho.","- Fase de descenso: baje lentamente la barra hacia la parte superior del pecho, manteniendo los codos en un ángulo de 45 grados con respecto al torso. Deténgase cuando la barra esté justo encima o toque ligeramente el pecho.","- Baje lentamente la barra hacia la parte superior del pecho, manteniendo los codos en un ángulo de 45 grados con respecto al torso.","- Fase de prensado: Empuje la barra hacia arriba hasta la posición inicial con un movimiento controlado. Extienda completamente los brazos sin bloquear los codos.","- Extienda completamente los brazos sin bloquear los codos.","- Repetir: Realiza el número deseado de repeticiones con movimientos suaves y controlados."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0e396d1f-c0de-4e80-babe-0e396d1f0000', 'Curl de bíceps con agarre inverso con barra EZ', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Reverse-Grip-EZ-Bar-Curl.gif', '{"Párese derecho con los pies separados a la altura de los hombros y agarre la barra EZ con agarre inverso. Tus manos deben estar ligeramente más estrechas que el ancho de los hombros.","Permita que sus brazos se extiendan completamente, manteniéndolos cerca de su cuerpo. Esta es tu posición inicial.","Haga una pausa breve en la parte superior del curl, luego baje lentamente la barra hasta la posición inicial mientras inhala.","Mantenga la parte superior de los brazos inmóviles, exhale y doble la barra hacia arriba contrayendo los bíceps. Concéntrate en apretar los músculos en la parte superior del movimiento.","Repita hasta el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('649df2a0-c0de-4e80-babe-649df2a00000', 'Curl predicador unilateral en polea', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/cable-preacher-curls.gif', '{"Ajuste el accesorio de curl predicador de la máquina de cable para que el asiento y el reposabrazos estén en una posición cómoda para usted.","Elija el peso adecuado y coloque un asa en el cable.","Siéntese en el asiento y coloque el brazo sobre el reposabrazos con el codo ligeramente doblado y la mano sujetando el asa.","Haga una pausa por un momento en la parte superior del movimiento, luego baje lentamente el mango hasta la posición inicial.","Manteniendo el codo inmóvil, doble el mango hacia el hombro, contrayendo el músculo bíceps.","Repita el ejercicio durante el número deseado de repeticiones, luego cambie de brazo y realice el mismo movimiento con el otro brazo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('18e9b18a-c0de-4e80-babe-18e9b18a0000', 'Curl martillo con mancuernas', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Dumbbell-Scott-Hammer-Curl.gif', '{"El ejercicio se realiza parándose detrás del banco del predicador y colocando la parte posterior de los brazos sobre el banco. Sosteniendo las mancuernas con un agarre neutral, con las palmas una frente a la otra, doblará las pesas hacia los hombros mientras mantiene la parte superior de los brazos inmóviles.","Aprieta los bíceps en la parte superior del movimiento y luego baja lentamente las mancuernas hasta la posición inicial.","Repita para la cantidad deseada de repeticiones y series."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7f3473e2-c0de-4e80-babe-7f3473e20000', 'Giro ruso sentado', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Seated-Oblique-Twist.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('356a3c17-c0de-4e80-babe-356a3c170000', 'Extensión de tríceps sentado con mancuernas', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Seated-One-Arm-Dumbbell-Triceps-Extension.gif', '{"- Configure la posición Siéntese en un banco resistente con respaldo para garantizar una postura adecuada. Sostenga una mancuerna en una mano con un agarre neutral (con la palma hacia adentro). Extienda el brazo por encima, manteniendo el codo cerca de la cabeza.","- Siéntese en un banco resistente con respaldo para garantizar una postura adecuada.","- Sostenga una mancuerna en una mano con un agarre neutral (con la palma hacia adentro).","- Posición inicial La parte superior del brazo debe permanecer perpendicular al suelo. Mantenga el núcleo enganchado y la columna en posición neutral para mayor estabilidad.","- Haga una breve pausa en la parte inferior, luego presione la mancuerna hacia la posición inicial extendiendo el codo.","- Usar demasiado peso, lo que lleva a una forma inadecuada y a un mayor riesgo de lesiones.","- La parte superior de tu brazo debe permanecer perpendicular al suelo.","- Ejecución Baje lentamente la mancuerna detrás de la cabeza doblando el codo. Mantenga el codo inmóvil mientras permite que la mancuerna descienda tanto como lo permita su movilidad. Haga una breve pausa en la parte inferior, luego presione la mancuerna hacia la posición inicial extendiendo el codo.","- Repeticiones y series Realice de 3 a 4 series de 10 a 15 repeticiones por brazo.","- Mantenga el codo inmóvil durante todo el movimiento para maximizar la activación del tríceps.","- Extienda el brazo por encima de la cabeza, manteniendo el codo cerca de la cabeza.","- Baje lentamente la mancuerna detrás de su cabeza doblando el codo.","- Baje la mancuerna de forma controlada para evitar una tensión excesiva en el codo.","- Involucre su núcleo para mantener una postura estable y evitar movimientos innecesarios.","- Acelerar el movimiento, reduciendo el compromiso muscular.","- Utilice un peso cómodo que permita un rango completo de movimiento sin comprometer la forma.","### Errores comunes a evitar","- Ensanchar el codo hacia afuera, lo que reduce la activación del tríceps y aumenta la tensión del hombro.","- Mantenga su núcleo comprometido y la columna neutral para mayor estabilidad.","- Mantenga el codo inmóvil mientras permite que la mancuerna descienda tanto como lo permita su movilidad.","- Realiza de 3 a 4 series de 10 a 15 repeticiones por brazo.","### Consejos para una forma adecuada","- Evite arquear excesivamente la espalda para mantener la alineación adecuada de la columna.","- Inclinarse excesivamente hacia atrás, lo que puede tensar la zona lumbar.","- No bajar la mancuerna del todo, limitando la efectividad del ejercicio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('367328e5-c0de-4e80-babe-367328e50000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Teaser-Pilates.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('396eaffb-c0de-4e80-babe-396eaffb0000', 'Remo en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/close-grip-cable-row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('67bc9fe1-c0de-4e80-babe-67bc9fe10000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/bodyweight-hip-thrust.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1f969991-c0de-4e80-babe-1f9699910000', 'Fondos', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Triceps-Dips-on-Floor.gif', '{"Empuja con las palmas de las manos para estirar los brazos y volver a la posición inicial.","Baje el cuerpo doblando los codos hasta que la parte superior de los brazos quede paralela al suelo.","Haga una breve pausa al final del movimiento.","Mantenga los codos doblados hacia adentro y evite abrirlos hacia afuera.","Repita de 10 a 15 repeticiones durante 3 a 4 series."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('13bfb54d-c0de-4e80-babe-13bfb54d0000', 'Jalón al pecho', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/V-bar-Lat-Pulldown.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3b2f0a2c-c0de-4e80-babe-3b2f0a2c0000', 'Pullover en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Rope-Straight-Arm-Pulldown.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('29c8a71e-c0de-4e80-babe-29c8a71e0000', 'Remo unilateral con barra', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/One-Arm-Barbell-Row-.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('41cf2609-c0de-4e80-babe-41cf26090000', 'Ejercicio con banda de resistencia', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Resistance-Band-Bicycle-Crunch.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('53f6a3ce-c0de-4e80-babe-53f6a3ce0000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Backwards-Running.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('65d15a35-c0de-4e80-babe-65d15a350000', 'Ejercicio', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Turkish-Get-Up-Squat-style.gif', '{"Paso 1: Acuéstese en el suelo con la rodilla derecha doblada y el pie derecho apoyado en el suelo. Mantenga la pierna izquierda estirada para la posición inicial.","Paso 7: A partir de ahí, coloque la mano izquierda en el suelo, extienda la pierna izquierda frente a usted y siéntese sin extender la rodilla derecha. Mantenga la pesa rusa sobre su hombro derecho.","Paso 8: Doble el brazo izquierdo para bajar aún más el torso y acuéstese boca arriba con cuidado en la posición inicial sin doblar el brazo derecho.","Paso 3: Contrae los abdominales, respira y levanta el torso del suelo, asegurándote de mantener el brazo derecho recto y la pesa rusa sobre la articulación del hombro. Empújate con el brazo izquierdo hasta que tu torso esté vertical y estés sentado.","Paso 5: Cuadre las caderas para crear una posición de estocada sólida, respire otra vez y levante la rodilla izquierda, pisando el pie izquierdo. Mientras haces eso, ponte de pie extendiendo las rodillas y las caderas. Mantenga la pesa rusa sobre su hombro y no doble el codo.","Paso 6: Invierta el movimiento lanzándose hacia atrás, levantando el pie izquierdo del suelo, aterrizando sobre la rodilla izquierda y girando la pierna izquierda detrás del cuerpo.","Paso 2: Sostenga una pesa rusa o una mancuerna en su mano derecha y mantenga la muñeca, el codo y el hombro alineados verticalmente. Mueva el brazo izquierdo hacia un lado con la mano apoyada en el suelo para mantener el equilibrio.","Paso 4: Con la pesa rusa todavía sobre tu hombro derecho y la mano izquierda sosteniéndote, dobla la pierna izquierda y coloca la rodilla en el suelo, levantándote. Mantenga la espalda recta mientras levanta el torso y retira la mano izquierda del suelo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('40739770-c0de-4e80-babe-407397700000', 'Remo inclinado en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Incline-Cable-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6faab429-c0de-4e80-babe-6faab4290000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Side-Bridge.gif', '{"### Posición inicial:","- Coloque el codo directamente debajo del hombro.","- Regrese a una posición del cuerpo recta sin extenderse demasiado.","- Acuéstese de lado con el antebrazo en el suelo.","- Apila las piernas una encima de la otra, con los pies alineados.","### Bajar las caderas:","- Baje lentamente las caderas hacia el suelo de forma controlada.","### Continuar el movimiento:","### Levanta las caderas:","- Involucre los oblicuos para levantar las caderas nuevamente.","- Repita el movimiento controlado de descenso y elevación durante el número deseado de repeticiones.","- Mantenga el cuerpo en línea recta desde la cabeza hasta los talones.","- Mantenga la alineación de los hombros y evite colapsar sobre el codo.","- Complete todas las repeticiones de un lado antes de cambiar de lado.","- Mantenga el movimiento suave y estable.","### Cambiar de lado:"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('63cccdc4-c0de-4e80-babe-63cccdc40000', 'Extensión de tríceps', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Lever-Tricep-Extension.gif', '{"- Ajuste la máquina Configure la altura del asiento para que sus brazos se alineen correctamente con las palancas de la máquina. Ajuste la pila de pesas a un nivel de resistencia manejable.","- Ajuste la altura del asiento para que sus brazos se alineen correctamente con las palancas de la máquina.","- Ajuste la pila de pesas a un nivel de resistencia manejable.","- Colóquese Siéntese con la espalda firmemente contra la almohadilla y los pies apoyados en el suelo. Sujete las manijas de la máquina con las palmas hacia abajo y los codos doblados a aproximadamente 90 grados.","- Siéntese con la espalda firmemente apoyada en la almohadilla y los pies apoyados en el suelo.","- Agarre las manijas de la máquina con las palmas hacia abajo y los codos doblados a aproximadamente 90 grados.","- Vuelve lentamente a la posición inicial, controlando el movimiento.","- Elija un peso moderado para evitar tensiones en los codos y los hombros.","- Usar demasiado peso, lo que provoca una forma inadecuada y tensión en las articulaciones.","- Hacer rebotar el peso hacia arriba y hacia abajo, lo que reduce la efectividad.","###","- Haga una pausa breve en la parte inferior para maximizar la contracción muscular.","- Repeticiones y series Realice de 3 a 4 series de 10 a 15 repeticiones para obtener resultados óptimos.","- EjecuciónEmpuje las manijas hacia abajo extendiendo los codos hasta que los brazos estén completamente rectos. Haga una breve pausa en la parte inferior para maximizar la contracción muscular. Vuelva lentamente a la posición inicial, controlando el movimiento.","- Empuje las manijas hacia abajo extendiendo los codos hasta que los brazos estén completamente rectos.","- Utilice un rango completo de movimiento, asegurándose de extender los brazos por completo.","- Controla el movimiento para evitar utilizar el impulso.","- Realice de 3 a 4 series de 10 a 15 repeticiones para obtener resultados óptimos.","### Errores comunes a evitar","- Inclinarse excesivamente hacia adelante, lo que reduce la activación del tríceps.","### Consejos para una forma adecuada","- Mantenga los codos inmóviles para enganchar completamente los tríceps.","- Mantenga la espalda contra la almohadilla para mantener la estabilidad.","- Permitir que los codos se muevan hacia afuera, lo que desvía la atención del tríceps.","- No extender los brazos por completo, lo que limita la participación de los músculos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('281e0c1a-c0de-4e80-babe-281e0c1a0000', 'Elevaciones laterales inclinado en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/One-Arm-Bent-Over-Cable-Lateral-Raise.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7d8229c8-c0de-4e80-babe-7d8229c80000', 'Remo inclinado en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Cable-Bent-Over-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('79d7bc7a-c0de-4e80-babe-79d7bc7a0000', 'Plancha', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Plank-with-Arm-and-Leg-Lift.gif', '{"A diferencia de otros ejercicios de plancha, es un tipo de plancha más difícil que se realiza levantando brazos y piernas en direcciones opuestas al mismo tiempo.","Las planchas son un ejercicio versátil que se dirige a muchos de los grupos de músculos más importantes del cuerpo, por lo que cualquier persona puede aplicarlas para mejorar la resistencia y la fuerza general del cuerpo.","Como movimiento multifuncional, la plancha no solo apunta a los músculos abdominales sino también a la columna y la cadera. Plank fortalece y tonifica todo el cuerpo, mejora la postura y el equilibrio, reduce la grasa corporal y puede ayudar a acelerar el metabolismo.","Plank es un ejercicio eficaz que aumenta la estabilidad en las zonas del core, la columna y la cadera proporcionando una contracción isométrica. Puedes agregarlo a tus entrenamientos para dar forma y fortalecer los músculos de la cadera, el tronco y las piernas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('63cbc2b7-c0de-4e80-babe-63cbc2b70000', 'Estiramiento de pie', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Standing-Side-Bend-Stretch.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('41254f36-c0de-4e80-babe-41254f360000', 'Plancha', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Weighted-Front-Plank.gif', '{"Es una variación de la tabla que se realiza agregando peso. Es sobre todo preferido por los atletas avanzados. Como movimiento multifuncional, la plancha no solo apunta a los músculos abdominales sino también a la columna y la cadera. Plank fortalece y tonifica todo el cuerpo, mejora la postura y el equilibrio, reduce la grasa corporal y puede ayudar a acelerar el metabolismo.","Plank es un ejercicio eficaz que aumenta la estabilidad en las zonas del core, la columna y la cadera proporcionando una contracción isométrica. Puedes agregarlo a tus entrenamientos para dar forma y fortalecer los músculos de la cadera, el tronco y las piernas.","La plancha frontal con pesas es un ejercicio versátil que se dirige a muchos de los grupos de músculos más importantes del cuerpo, por lo que pueden ser aplicados por atletas avanzados para aumentar la resistencia y la fuerza general del cuerpo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('050f4b01-c0de-4e80-babe-050f4b010000', 'Press de pecho con barra EZ', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/EZ-Bar-Underhand-Press.gif', '{"Cargue un peso adecuado en la barra de curl EZ.","Párese con los pies separados a la altura de los hombros.","Agarre la barra EZ con un agarre por debajo, con las manos ligeramente más estrechas que el ancho de los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('47d63b12-c0de-4e80-babe-47d63b120000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Single-Leg-Bridge.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('62328eac-c0de-4e80-babe-62328eac0000', 'Curl de bíceps acostado con barra', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Lying-High-Bench-Barbell-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('01a9919f-c0de-4e80-babe-01a9919f0000', 'Ejercicio acostado con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Dumbbell-Lying-External-Shoulder-Rotation.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3865222d-c0de-4e80-babe-3865222d0000', 'Ejercicio en polea', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Cable-Side-Bend.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('72770bfa-c0de-4e80-babe-72770bfa0000', 'Jalón al pecho en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Double-Cable-Neutral-Grip-Lat-Pulldown-On-Floor.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('50a03fa8-c0de-4e80-babe-50a03fa80000', 'Elevación inclinado con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Dumbbell-Incline-T-Raise.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6fff4322-c0de-4e80-babe-6fff43220000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/handstand-push-up.gif', '{"- Encuentre una pared como apoyo (para principiantes) Mire hacia una pared y coloque las manos en el suelo separadas a la altura de los hombros. Levante las piernas hasta colocarse en posición de parada de manos con los talones tocando la pared para mantener el equilibrio.","- Mire hacia una pared y coloque las manos en el suelo separadas a la altura de los hombros.","- Opción independiente (para atletas avanzados) Comience en posición de parada de manos sin soporte en la pared. Involucre su núcleo y glúteos para mantener el equilibrio.","- Comience en posición de pino sin apoyo en la pared.","- Empuja hacia atrás hasta la posición inicial extendiendo los brazos completamente.","- Levante las piernas hasta ponerse en posición de parada de manos con los talones tocando la pared para mantener el equilibrio.","- Involucre su núcleo y glúteos para mantener el equilibrio.","- Baja el cuerpo doblando los codos hasta que tu cabeza toque suavemente el suelo.","- Involucre su núcleo para mantener el equilibrio y el control.","- Muévase con un movimiento controlado para evitar una tensión excesiva en los hombros.","- Falta de movilidad: la movilidad insuficiente del hombro hace que el movimiento sea ineficaz.","- Utilice una colchoneta acolchada debajo de la cabeza por seguridad si es necesario.","### Errores comunes a evitar","- Arquear excesivamente la zona lumbar: esto reduce la estabilidad y aumenta el riesgo de lesiones.","- Ensanchar los codos: esto genera una tensión innecesaria en los hombros.","- Mantenga los codos en un ángulo de 45 grados para proteger sus hombros.","- Repita de 4 a 12 repeticiones dependiendo de su nivel de fuerza.","### Consejos para una forma adecuada","- Mantenga las manos separadas a la altura de los hombros para mayor estabilidad.","- Apunte los dedos de los pies y apriete los glúteos para mantener una línea corporal recta.","- Caer demasiado rápido: el control es clave para evitar lesiones.","- No involucrar el núcleo: un compromiso débil del núcleo conduce a un equilibrio y una técnica deficientes."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('127c5660-c0de-4e80-babe-127c56600000', 'Pájaro / Vuelos posteriores inclinado con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dumbbell-Reverse-Fly.gif', '{"El vuelo inverso con mancuernas es un ejercicio de pesas libres que se dirige principalmente a los hombros traseros. Es un ejercicio eficaz que puedes incluir en tu programa para aislar los músculos posteriores del hombro y fortalecer los músculos del manguito rotador.","También activa los músculos trapecios y puede beneficiar las molestias causadas por la debilidad muscular, como la postura postural y la protrusión del omóplato, al afectar los músculos infraespinoso y subescápula que cubren la escápula."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1413ce2e-c0de-4e80-babe-1413ce2e0000', 'Estiramiento', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Back-Pec-Stretch.gif', '{"- Párese y colóquese Párese aproximadamente a un pie de distancia del banco, frente a él. Coloque las manos a la altura de los hombros en el borde de la superficie.","- Párese aproximadamente a un pie de distancia del banco, frente a él. Coloque las manos a la altura de los hombros en el borde de la superficie.","- Busque un banco resistente, una plataforma elevada o una mesa a la altura de la cintura. Asegúrese de que la superficie sea estable y segura.","- Realice el estiramiento. Mantenga los brazos rectos y permita que el pecho se hunda hacia abajo. Tu cabeza debe permanecer alineada con tus brazos, o puedes dejarla caer ligeramente para un estiramiento más profundo.","- Bisagra en las caderas Retroceda lentamente mientras dobla las caderas. Baje el torso hasta que quede paralelo al suelo o ligeramente por debajo.","- Da un paso atrás lentamente mientras doblas las caderas. Baje el torso hasta que quede paralelo al suelo o ligeramente por debajo.","- Siga la misma configuración y posicionamiento que el estiramiento estático. En lugar de mantener el estiramiento, realiza el siguiente movimiento dinámico:","- Mueva suavemente el torso hacia arriba y hacia abajo, profundizando el estiramiento con cada movimiento hacia abajo. Realice de 10 a 15 repeticiones.","- Tensión en los hombros: relaje los hombros y permita que el pecho baje para lograr un estiramiento más profundo y eficaz.","- Respirar y sostenerMantener el estiramiento durante 20 a 30 segundos mientras respira profunda y controladamente. Concéntrate en sentir cómo se libera la tensión de tu espalda y pecho.","### Errores comunes a evitar","- Mantenga los brazos rectos y permita que su pecho se hunda hacia abajo. Tu cabeza debe permanecer alineada con tus brazos, o puedes dejarla caer ligeramente para un estiramiento más profundo.","- Mantenga el estiramiento durante 20 a 30 segundos mientras respira profunda y controladamente. Concéntrate en sentir cómo se libera la tensión de tu espalda y pecho.","- Realiza de 10 a 15 repeticiones.","### Consejos para el entrenador:","- Mantenga las rodillas ligeramente dobladas si siente los isquiotibiales tensos.","- Evite arquear excesivamente la zona lumbar; mantener una columna neutra.","- Ampliar la parte baja de la espalda: concéntrese en girar desde las caderas y mantener el núcleo comprometido para proteger la columna lumbar. Deténgase si siente algún dolor agudo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4551e4c0-c0de-4e80-babe-4551e4c00000', 'Press de pecho inclinado', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Lever-Incline-Hammer-Chest-Press.gif', '{"- Ajuste la máquina Configure la altura del asiento para que las manijas se alineen con la parte media y superior del pecho cuando esté sentado. Ajuste la pila de pesas o la carga del plato a una resistencia manejable.","- Ajuste la altura del asiento de modo que las manijas se alineen con la parte media y superior del pecho cuando esté sentado.","- Ajuste la pila de pesas o la carga del plato a una resistencia manejable.","- Colóquese Siéntese en el banco inclinado con la espalda presionada firmemente contra la almohadilla. Sujete las manijas con un agarre neutral (con las palmas hacia adentro). Coloque los pies apoyados en el suelo para mayor estabilidad.","- Siéntese en el banco inclinado con la espalda presionada firmemente contra la almohadilla.","- Sujete las manijas con un agarre neutral (las palmas hacia adentro).","- Coloque los pies apoyados en el suelo para mayor estabilidad.","- Posición inicial Comience con los brazos doblados y los codos ligeramente por debajo del nivel de los hombros. Mantenga el pecho erguido y los hombros hacia atrás.","- Uso de peso excesivo: priorice la forma sobre el peso para evitar lesiones o un reclutamiento muscular inadecuado.","- Comience con los brazos doblados y los codos ligeramente por debajo del nivel de los hombros.","- Baje las manijas Inhale y baje lentamente las manijas hasta la posición inicial. Mantenga el control y evite que la pila de pesas se golpee.","- Inhale y baje lentamente las manijas hasta la posición inicial.","- Presione las manijas. Exhale y empuje las manijas hacia arriba y ligeramente hacia adentro con un movimiento controlado. Extienda completamente los brazos sin bloquear los codos.","- Exhale y empuje las manijas hacia arriba y ligeramente hacia adentro con un movimiento controlado.","- Extienda completamente los brazos sin bloquear los codos.","- Rango de movimiento incompleto: baje las manijas completamente para enganchar el cofre en todo su rango.","- Repetir Realice de 8 a 12 repeticiones para hipertrofia o de 12 a 15 para resistencia, según su objetivo de acondicionamiento físico.","- Realice de 8 a 12 repeticiones para hipertrofia o de 12 a 15 para resistencia, según su objetivo de acondicionamiento físico.","- Mantenga las muñecas en posición neutra para evitar tensiones innecesarias.","- Mantenga el pecho erguido y los hombros hacia atrás.","- Mantenga el control y evite que la pila de pesas golpee.","### Consejos para una forma adecuada:","- Evite encogerse de hombros para evitar la sobreactivación de las trampas.","- Mantenga un ritmo lento y controlado para maximizar el compromiso muscular.","- Codos ensanchados demasiado anchos: Mantenga los codos en un ángulo de aproximadamente 45 grados para evitar tensión en los hombros.","### Errores comunes:"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('59dedf43-c0de-4e80-babe-59dedf430000', 'Elevación inclinado con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Incline-Dumbbell-Y-Raise.gif', '{"Acuéstese boca abajo sobre una pelota de ejercicios o un banco, con el pecho y las caderas apoyados y los pies en el suelo.","Sostenga una mancuerna liviana en cada mano, con las palmas hacia adentro y los brazos rectos.","Manteniendo los brazos rectos y la cabeza alineada con la columna, levante los brazos hacia arriba y hacia afuera para formar una \"Y\" con su cuerpo.","Haga una pausa breve en la parte superior del movimiento, luego baje las pesas a la posición inicial."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6eeb450a-c0de-4e80-babe-6eeb450a0000', 'Extensión de tríceps acostado con mancuernas', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Dumbbell-Skull-Crusher.gif', '{"### Paso 1: Configuración y posición inicial","- Acuéstese sobre un banco con los pies firmemente plantados en el suelo.","- Sostenga una mancuerna en cada mano con un agarre por encima de la cabeza, con los brazos extendidos directamente sobre su pecho.","- Extiende los brazos hacia la posición inicial, estirando completamente los codos.","- Involucre su núcleo para mantener su cuerpo estable en el banco.","- Usar demasiado peso, lo que lleva a la pérdida de control.","- Una vez que las mancuernas estén justo encima de tu frente, haz una breve pausa.","- Utilice un peso cómodo para mantener una buena forma durante todo el movimiento.","### Errores comunes a evitar","### Paso 2: Ejecución","- Baje lentamente las mancuernas hacia la frente doblando los codos.","- Baje las mancuernas de forma controlada para evitar una tensión excesiva.","- No extender completamente los brazos, limitando la efectividad del movimiento.","- Dejar que los codos se abran: esto reduce la activación del tríceps.","- Mover los hombros en exceso, quitando tensión al tríceps.","- Mantenga los codos fijos en su lugar y evite el movimiento excesivo de los hombros.","- Mantenga la parte superior de los brazos inmóviles, permitiendo que solo se muevan los antebrazos.","- Repita de 8 a 12 repeticiones durante 3 a 4 series.","### Consejos para una forma adecuada","- Mantenga los codos estables y evite estirarlos.","- Evite bloquear los codos en la parte superior para reducir la tensión en las articulaciones.","- Bajar las mancuernas demasiado rápido, con riesgo de lesionarse."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('074eb824-c0de-4e80-babe-074eb8240000', 'Curl martillo en polea', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/rope-bicep-curls.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('24c877c7-c0de-4e80-babe-24c877c70000', 'Elevación de pantorrillas', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Weighted-Donkey-Calf-Raise.gif', '{"- Colocación de los pies: Párese sobre un bloque o plataforma segura con solo las puntas de los pies apoyadas y los talones colgando del borde.","- Posición del torso: Inclínese hacia adelante a la altura de las caderas para formar un ángulo de aproximadamente 90°. Coloque las manos sobre un banco, barandilla o plataforma segura para mayor estabilidad. Mantenga la espalda plana y las rodillas completamente extendidas.","- Posición inicial: comience con los talones completamente bajados para lograr un estiramiento profundo de la pantorrilla.","- Elija un compañero cercano a su categoría de peso para comenzar y luego aumente.","- Carga del compañero: su compañero monta con cuidado sus caderas/zona lumbar y se sienta uniformemente. Deben distribuir el peso sin aplicar presión directa sobre la columna o las costillas.","- Top Squeeze: manténgalo en la parte superior durante 1 a 2 segundos, concentrándose en la flexión plantar completa.","- Evite rebotar o aprovechar el impulso; concéntrese en movimientos lentos y deliberados.","### Errores comunes a evitar","- Inicie el levantamiento: levante los talones presionando las puntas de los pies y contrayendo las pantorrillas con fuerza.","- Descenso controlado: Baje los talones por debajo del nivel del bloque bajo control lento, restableciendo el estiramiento.","- Dejar que la pareja se siente demasiado alto, lo que sobrecarga la columna lumbar y reduce la tensión mecánica en las pantorrillas.","- Doblar las rodillas, lo que desvía la atención hacia el sóleo y compromete la forma.","- No utilizar una superficie estable: una plataforma para los pies resbaladiza puede provocar caídas.","- Repetir: complete la cantidad deseada de repeticiones, manteniendo un ritmo y una postura constantes en todo momento.","### Consejos para una forma adecuada","- Asegúrese de que la carga se distribuya uniformemente: el compañero debe sentarse sobre las caderas, no sobre la mitad de la espalda.","- Mantenga las rodillas completamente bloqueadas para priorizar el reclutamiento de gastrocnemios.","- Mantenga una columna neutra y una articulación de cadera constante durante toda la serie.","- Sobrecargar demasiado pronto, arriesgarse a lesionarse o romper la forma.","- Usar los brazos para tirar o empujar, reduciendo el aislamiento de la parte inferior del cuerpo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('26aeaebc-c0de-4e80-babe-26aeaebc0000', 'Ejercicio', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Lever-Crossovers.gif', '{"- Ajuste la máquina Ajuste la altura del asiento de modo que las manijas se alineen con la mitad de su pecho cuando esté sentado. Ajuste el respaldo para lograr una posición cómoda y estable.","- Ajuste la altura del asiento de modo que las manijas se alineen con la mitad de su pecho cuando esté sentado.","- Ajuste el respaldo para lograr una posición cómoda y estable.","- PosicióneseSiéntese en la máquina con la espalda presionada firmemente contra el respaldo. Coloque los pies apoyados en el suelo, separados aproximadamente a la altura de los hombros.","- Siéntese en la máquina con la espalda firmemente apoyada contra el respaldo.","- Coloque los pies apoyados en el suelo, separados aproximadamente a la altura de los hombros.","- Posición inicial Agarre las manijas firmemente con las palmas hacia adentro. Mantenga los codos ligeramente doblados para proteger sus articulaciones.","- Agarre las manijas firmemente con las palmas hacia adentro.","- Regrese a StartInhale y lentamente permita que las manijas regresen a la posición inicial, manteniendo la tensión en su pecho en todo momento.","- Inhale y permita lentamente que las manijas regresen a la posición inicial, manteniendo la tensión en el pecho en todo momento.","- Usar peso excesivo: Seleccionar un peso demasiado pesado puede comprometer la forma y reducir la efectividad del ejercicio.","- Elija su pesoSeleccione un peso que le permita completar la cantidad deseada de repeticiones con la forma adecuada.","- Seleccione un peso que le permita completar la cantidad deseada de repeticiones con la forma adecuada.","- Repetir Realice de 8 a 12 repeticiones para hipertrofia o de 12 a 15 repeticiones para resistencia.","- Realice el CrossoverExhale mientras baja lentamente los brazos. Concéntrate en apretar el pecho en el punto máximo del movimiento.","- Exhala mientras bajas lentamente los brazos. Concéntrate en apretar el pecho en el punto máximo del movimiento.","- Confiar en el impulso: evitar movimientos bruscos; Utilice movimientos controlados para una participación muscular óptima.","- Realice de 8 a 12 repeticiones para hipertrofia o de 12 a 15 repeticiones para resistencia.","- Muévase de manera lenta y controlada para maximizar la tensión en los músculos del pecho.","### Errores comunes a evitar","- Mantenga los codos ligeramente doblados para proteger sus articulaciones.","### Consejos para una forma adecuada","- Mantenga una ligera flexión de los codos para evitar extender demasiado las articulaciones.","- Evite inclinarse hacia adelante o hacia atrás durante el movimiento; mantenga la columna neutra.","- Extender demasiado los codos: estirar completamente los brazos aumenta el riesgo de tensión en las articulaciones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2d0efaef-c0de-4e80-babe-2d0efaef0000', 'Ejercicio en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Cable-Pull-Through.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('69f30b09-c0de-4e80-babe-69f30b090000', 'Ejercicio con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Bench-Supported-Dumbbell-External-Rotation.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('05f2328b-c0de-4e80-babe-05f2328b0000', 'Extensión de tríceps inclinado con mancuernas', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Dumbbell-Incline-Two-Arm-Extension.gif', '{"### Paso 1: Configuración y posición inicial","- Coloque un banco inclinado entre 30 y 45 grados.","- Siéntate en el banco con una mancuerna en cada mano, con las palmas una frente a la otra. (Se puede hacer con una sola mancuerna)","- Haga una pausa breve y luego extienda los brazos hasta la posición inicial.","- Usar demasiado peso, lo que lleva a un control deficiente y riesgo de lesiones.","- Presione las mancuernas sobre su cabeza hasta que sus brazos estén completamente extendidos.","- Mantenga su núcleo comprometido y la espalda firmemente contra el banco.","- Baja las mancuernas hasta que sientas un estiramiento en el tríceps.","- Baja las mancuernas lentamente y de forma controlada para evitar lesiones.","### Paso 2: Ejecución","- Baje lentamente las mancuernas detrás de la cabeza doblando los codos.","- Inhale mientras baja las mancuernas y exhale mientras las vuelve a subir.","- Acelerar el movimiento, reduciendo la efectividad y aumentando el riesgo de lesiones.","- Utilice un peso cómodo que permita un rango completo de movimiento sin tensión excesiva.","### Errores comunes a evitar","- Ensanchar los codos, lo que reduce el compromiso de los tríceps.","- Mantenga la parte superior de los brazos inmóviles mientras los antebrazos se mueven hacia abajo.","- Aprieta los tríceps en la parte superior y luego repite de 8 a 12 repeticiones durante 3 a 4 series.","### Consejos para una forma adecuada","- Mantenga los codos juntos para maximizar la activación de los tríceps.","- Evite arquear la espalda; mantenga la columna neutral contra el banco.","- Dejar caer las mancuernas demasiado bajo, ejerciendo una tensión innecesaria sobre los hombros.","- Arquear la espalda excesivamente, lo que puede provocar molestias o lesiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('137ddbdd-c0de-4e80-babe-137ddbdd0000', 'Remo de rodillas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Kneeling-Single-Arm-High-Pulley-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1cab0fa9-c0de-4e80-babe-1cab0fa90000', 'Ejercicio con barra', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Barbell-Side-Bend.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('025ddbc7-c0de-4e80-babe-025ddbc70000', 'Giro ruso inclinado', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Bent-Over-Twist.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2aaf2154-c0de-4e80-babe-2aaf21540000', 'Extensión de tríceps sentado con barra EZ', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Seated-EZ-Bar-Overhead-Triceps-Extension.gif', '{"### Paso 1: Configuración y posición inicial","- Siéntese en un banco plano con respaldo para mantener la estabilidad.","- Agarre la barra EZ con un agarre firme y por encima de la cabeza (con las palmas hacia adelante).","- Haga una pausa breve, luego presione la barra para regresar a la posición inicial extendiendo los codos.","- Elija un peso adecuado para mantener la técnica adecuada.","- Usar peso excesivo, lo que lleva a una mala forma y a un mayor riesgo de lesiones.","- Levanta la barra por encima de tu cabeza, manteniendo los brazos completamente extendidos.","- Baja la barra hasta que sientas un estiramiento profundo en el tríceps.","- Involucre su núcleo para mantener una postura erguida.","### Paso 2: Ejecución","- Baje lentamente la barra EZ detrás de su cabeza doblando los codos.","- Utilice un movimiento controlado, evitando sacudidas bruscas o movimientos de rebote.","- Inhala mientras bajas la barra y exhala mientras extiendes los brazos.","### Errores comunes a evitar","- Ensanchando los codos hacia afuera, reduciendo la activación de los tríceps.","- Arquear la zona lumbar, lo que puede provocar molestias.","- Asegúrese de que sus codos estén cerca de su cabeza y su núcleo esté comprometido.","- Mantenga la parte superior de los brazos inmóviles mientras mueve solo los antebrazos.","- Repita de 8 a 12 repeticiones, completando de 3 a 4 series.","### Consejos para una forma adecuada","- Mantenga los codos cerca de la cabeza para maximizar la participación de los tríceps.","- Dejar caer la barra demasiado bajo, ejerciendo una tensión innecesaria sobre los hombros.","- Moverse demasiado rápido, disminuyendo la participación y el control de los músculos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3b963061-c0de-4e80-babe-3b9630610000', 'Extensión de tríceps unilateral con mancuernas', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/One-Arm-Pronated-Dumbbell-Triceps-Extension-.gif', '{"### Paso 1: Configuración y posición inicial","- Acuéstese en un banco con una mancuerna en una mano.","- Sostenga la mancuerna con un agarre en pronación (con la palma hacia adelante).","- Haga una pausa breve y luego extienda el brazo hasta la posición inicial.","- Usar peso excesivo, lo que puede provocar un mal control y lesiones.","- Extiende el brazo hacia arriba, colocando la mancuerna por encima del hombro.","- Baja la mancuerna hasta que sientas un estiramiento profundo en el tríceps.","- Mantenga una posición neutra de la muñeca para reducir la tensión en las articulaciones.","### Paso 2: Ejecución","- Baje lentamente la mancuerna doblando el codo y llevándolo hacia el costado de la cabeza.","- Utilice un movimiento controlado para evitar el impulso y la tensión.","- Involucre su núcleo para evitar movimientos excesivos o arqueamiento.","- Inhala mientras bajas la mancuerna y exhala mientras la extiendes.","- Permitir que el codo se desplace hacia afuera, reduciendo el aislamiento del tríceps.","- Apresurarse en el movimiento, disminuyendo el compromiso muscular.","### Errores comunes a evitar","- Arquear la zona lumbar, lo que puede provocar molestias o tensión.","- Mantenga el codo inmóvil, con la parte superior del brazo perpendicular al suelo.","- Mantenga el codo en su lugar mientras se mueve el antebrazo.","- Repita de 8 a 12 repeticiones, luego cambie de brazo. Completa de 3 a 4 series.","### Consejos para una forma adecuada","- Mantenga el codo estable para garantizar la activación adecuada del tríceps.","- Dejar caer la mancuerna demasiado bajo, lo que genera una tensión innecesaria en el hombro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0f60fa9c-c0de-4e80-babe-0f60fa9c0000', 'Ejercicio en máquina', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Smith-Machine-Good-Morning.gif', '{"Párate frente a la máquina Smith con los pies separados a la altura de los hombros y la barra apoyada sobre tus hombros.","Mantén el pecho erguido y el core comprometido.","Bájate hasta que tu torso quede paralelo al suelo.","Doble lentamente las caderas, empujando los glúteos hacia atrás y bajando el torso hacia el suelo.","Haga una pausa breve en la parte inferior del movimiento, luego levante lentamente el torso hasta la posición inicial.","Repita hasta el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0539dce1-c0de-4e80-babe-0539dce10000', 'Remo sentado con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Dumbbell-Seated-Bent-Over-Rear-Delt-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('60f5ea0e-c0de-4e80-babe-60f5ea0e0000', 'Press de pecho con agarre inverso con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Reverse-Grip-Dumbbell-Bench-Press.gif', '{"Elija sus mancuernasSeleccione un peso que le permita mantener la forma adecuada durante todo el ejercicio.","Colóquese Recuéstese en un banco plano con los pies apoyados en el suelo. Sostenga una mancuerna en cada mano con un agarre inverso (con las palmas hacia la cara).","Sostenga una mancuerna en cada mano con agarre inverso (con las palmas hacia la cara)."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('42ecedc3-c0de-4e80-babe-42ecedc30000', 'Press de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Lever-Chest-Press.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('15b0732e-c0de-4e80-babe-15b0732e0000', 'Ejercicio con mancuernas', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Dumbbell-V-up.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7da774b6-c0de-4e80-babe-7da774b60000', 'Curl de bíceps con mancuernas', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Dumbbell-High-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6a27ccea-c0de-4e80-babe-6a27ccea0000', 'Press de pecho de pie con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Dumbbell-Standing-Palms-In-Press.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7f9cf3a4-c0de-4e80-babe-7f9cf3a40000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Reverse-Push-up.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('228e0198-c0de-4e80-babe-228e01980000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Side-Shuttle.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('458e90f0-c0de-4e80-babe-458e90f00000', 'Remo con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Dumbbell-Rear-Delt-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('66a9789b-c0de-4e80-babe-66a9789b0000', 'Press de hombros acostado', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Lying-Shoulder-Press.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0ec2a9a1-c0de-4e80-babe-0ec2a9a10000', 'Extensión de tríceps inclinado en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Cable-Incline-Triceps-Extension.gif', '{"### Paso 1: Configuración y posición inicial","- Ajuste un banco inclinado a un ángulo de 45 a 60 grados y colóquelo cerca de una polea de cable baja.","- Conecte una barra recta o un mango de cuerda a la máquina de cable.","- Acuéstese boca arriba en el banco y agarre el asa desde abajo, con las manos separadas a la altura de los hombros.","- Haga una breve pausa y luego extienda los brazos para volver a la posición inicial.","- Usar peso excesivo, lo que lleva a comprometer la forma.","- Extiende los brazos hacia arriba, colocándolos perpendiculares al suelo.","- Mueva solo los antebrazos, manteniendo la parte superior de los brazos inmóviles.","- Utilice un tempo controlado para evitar que el impulso se apodere de usted.","- Mantenga una posición neutra de la muñeca para evitar tensiones innecesarias.","### Paso 2: Ejecución","- Baje lentamente el mango detrás de su cabeza doblando los codos.","- Baje el mango hasta que sienta un estiramiento profundo en el tríceps.","- Involucre su núcleo para estabilizar su cuerpo durante todo el movimiento.","### Errores comunes a evitar","- Ensanchando los codos hacia afuera, reduciendo el compromiso de los tríceps.","- Bajar el mango demasiado rápido aumenta el riesgo de lesiones.","- Mantenga la parte superior de los brazos inmóviles mientras permite que solo se muevan los antebrazos.","- Repita de 8 a 12 repeticiones, completando de 3 a 4 series.","### Consejos para una forma adecuada","- Mantenga los codos juntos para maximizar la activación de los tríceps.","- Arquear la zona lumbar, lo que puede provocar molestias.","- No extenderse completamente, limitando la activación muscular."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1ffd0192-c0de-4e80-babe-1ffd01920000', 'Press de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Svend-Press.gif', '{"- Agarre la placa Sostenga la placa de pesas entre las palmas y presione firmemente para mantenerla en su lugar. Tus dedos deben apuntar hacia afuera.","- Posición inicial: Párese erguido con los pies separados a la altura de los hombros y el core enganchado. Sostenga la placa contra el centro de su pecho, manteniendo los codos doblados y cerca de los costados.","- Párate erguido con los pies separados a la altura de los hombros y el core comprometido.","- Usar demasiado peso: comience con un disco más liviano para garantizar la forma y el compromiso muscular adecuados.","- Seleccione un disco de pesas Comience con un disco liviano (de 5 a 10 kg o de 10 a 25 libras) y aumente a medida que desarrolle fuerza y ​​control.","- Comience con una placa liviana (de 5 a 10 kg o de 10 a 25 libras) y aumente a medida que desarrolle fuerza y ​​control.","- Sostenga la placa de pesas entre las palmas y presione firmemente para mantenerla en su lugar. Tus dedos deben apuntar hacia afuera.","- Presione la placa hacia adelante Extienda lentamente los brazos hacia adelante mientras presiona las palmas de las manos contra la placa para mantenerla estable. Concéntrese en apretar los músculos del pecho mientras presiona.","- Extienda lentamente los brazos hacia adelante mientras presiona las palmas de las manos contra el plato para mantenerlo estable.","- Regrese al inicio Lleve lentamente la placa hacia su pecho, manteniendo la tensión en su pecho en todo momento.","- Lentamente, lleve la placa de regreso a su pecho, manteniendo la tensión en su pecho en todo momento.","- Concéntrese en el rango de movimiento: extienda completamente los brazos mientras presiona la placa, pero no bloquee los codos.","- Confiar en los brazos en lugar del pecho: concéntrate en apretar los músculos del pecho para iniciar el movimiento, en lugar de dejar que tus brazos se hagan cargo.","- Sostenga el plato contra el centro de su pecho, manteniendo los codos doblados y cerca de los costados.","- Concéntrate en apretar los músculos del pecho mientras presionas.","- Al final del movimiento, haga una pausa de 1 a 2 segundos y contraiga los músculos del pecho.","- Haga una pausa y apriete Al final del movimiento, haga una pausa de 1 a 2 segundos y contraiga los músculos del pecho.","### Consejos para una forma adecuada","- Mantenga la tensión en el pecho: mantenga una presión constante sobre la placa de pesas para asegurarse de que los músculos del pecho estén activos en todo momento.","- Evite el uso de Momentum: muévase de manera lenta y controlada para maximizar la activación muscular.","- Involucre su núcleo: mantenga sus abdominales contraídos para mantener una postura estable y evitar un arqueo excesivo de la espalda baja.","- Arqueando la espalda: Mantenga una columna neutral involucrando los músculos centrales durante todo el ejercicio.","### Errores comunes a evitar","- Permitir que la placa se deslice: presione firmemente las palmas de las manos contra la placa para evitar perder el control."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1baff8c8-c0de-4e80-babe-1baff8c80000', 'Elevaciones laterales', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Lever-Lateral-Raise.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6b6e1418-c0de-4e80-babe-6b6e14180000', 'Ejercicio acostado', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Lever-Lying-Crunch.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5befecf0-c0de-4e80-babe-5befecf00000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/12/Ab-Roller-Crunch.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2547783e-c0de-4e80-babe-2547783e0000', 'Extensión de tríceps', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Twisting-Hyperextension.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4a263940-c0de-4e80-babe-4a2639400000', 'Press de pecho alterno con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Alternate-Dumbbell-Bench-Press.gif', '{"- Instale el banco Acuéstese sobre un banco resistente con los pies firmemente plantados en el suelo.","- Acuéstese sobre un banco resistente con los pies firmemente plantados en el suelo.","- Posición inicial Baje una mancuerna lentamente hacia el costado de su pecho mientras mantiene el otro brazo extendido por encima de su hombro.","- Exhala mientras presionas la mancuerna de regreso a la posición inicial.","- Uso de peso excesivo Comience con mancuernas más livianas para dominar la forma adecuada antes de aumentar el peso.","- Comience con mancuernas más livianas para dominar la forma adecuada antes de aumentar el peso.","- Elija mancuernas adecuadas Seleccione mancuernas que le permitan mantener la forma adecuada durante todo el ejercicio.","- Selecciona mancuernas que te permitan mantener la forma adecuada durante todo el ejercicio.","- Colóquese Sostenga una mancuerna en cada mano con los brazos extendidos directamente sobre los hombros, con las palmas hacia adelante.","- Sostenga una mancuerna en cada mano con los brazos extendidos directamente sobre los hombros, con las palmas hacia adelante.","- Presione la mancuerna hacia arriba y exhale mientras presiona la mancuerna hacia la posición inicial.","- Baja la mancuerna opuesta manteniendo el primer brazo extendido en la parte superior.","- Baje una mancuerna lentamente hacia el costado de su pecho mientras mantiene el otro brazo extendido por encima de su hombro.","- Cambiar de brazo Baje la mancuerna opuesta mientras mantiene el primer brazo extendido en la parte superior.","- Controle el movimiento: evite las prisas; Baje y presione las mancuernas de manera lenta y controlada.","- Rango completo de movimiento: baje la mancuerna hasta que esté al nivel de su pecho para garantizar un rango completo de movimiento.","- Realice cada repetición lenta y deliberadamente para maximizar la participación de los músculos.","- Repeticiones alternas Continúe alternando brazos durante el número deseado de repeticiones, manteniendo el control durante todo el movimiento.","- Continúe alternando brazos durante el número deseado de repeticiones, manteniendo el control durante todo el movimiento.","- Involucre su núcleo: mantenga su núcleo apretado para evitar que su torso gire durante el movimiento alterno.","### Errores comunes a evitar","- Rango de movimiento desigual Asegúrese de que ambos brazos sigan el mismo rango de movimiento para evitar desequilibrios musculares.","- Asegúrese de que ambos brazos sigan el mismo rango de movimiento para evitar desequilibrios musculares.","- Finalización Una vez que termines tu serie, baja con cuidado ambas mancuernas hasta tu pecho y siéntate con control.","- Una vez que termines tu serie, baja con cuidado ambas mancuernas hasta tu pecho y siéntate con control.","### Consejos para una forma adecuada","- Mantenga la alineación: sus muñecas deben permanecer alineadas con sus antebrazos y sus codos deben permanecer en un ángulo de 45 grados con respecto a su torso.","- Base estable: Mantenga los pies firmemente plantados en el suelo para proporcionar una base estable para el elevador.","- Ensanchamiento de los codos Evite que los codos se ensanchen demasiado, ya que esto puede tensar los hombros.","- Evite que los codos se abran demasiado, ya que esto puede tensar los hombros.","- Repeticiones apresuradas Realice cada repetición lenta y deliberadamente para maximizar la participación de los músculos.","- Arqueando la parte baja de la espalda Mantenga la espalda plana sobre el banco involucrando el core y los glúteos.","- Mantenga la espalda plana en el banco involucrando el núcleo y los glúteos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1a76edb6-c0de-4e80-babe-1a76edb60000', 'Giro ruso de pie en polea', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Standing-Cable-High-To-Low-Twist.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('622c3fb8-c0de-4e80-babe-622c3fb80000', 'Giro ruso de pie en polea', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Standing-Cable-low-to-high-Twist.gif', '{"El ejercicio ejercita los músculos oblicuos, abdominales y lumbares. Los oblicuos son los músculos que conectan los dorsales y los abdominales. Estos músculos ayudan a torcer o girar la parte superior del cuerpo. Este ejercicio, dirigido a los músculos oblicuos, es muy útil para tensar y desarrollar la grasa abdominal."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2a8540b0-c0de-4e80-babe-2a8540b00000', 'Ejercicio en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Rope-Pushdown.gif', '{"### Paso 1: Configuración y posición inicial","- Conecte un mango de cuerda a una máquina de cable de polea alta.","- Párese frente a la máquina con una ligera inclinación hacia adelante, manteniendo los pies separados a la altura de los hombros.","- Sujete la cuerda con ambas manos, usando un agarre neutral (con las palmas una frente a la otra).","- Mantén la contracción por un segundo, luego regresa lentamente a la posición inicial mientras controlas la resistencia.","- Usar peso excesivo, lo que lleva a un control deficiente y una forma inadecuada.","- Seleccione un peso apropiado que permita un movimiento controlado.","- Empuja la cuerda hacia abajo extendiendo los codos y manteniendo la parte superior de los brazos inmóviles.","- Al llegar abajo, separe las asas de la cuerda, enfatizando una contracción completa del tríceps.","- Separe la cuerda en la parte inferior para una mejor contracción del tríceps.","### Paso 2: Ejecución","- Utilice un movimiento controlado para evitar balancearse o utilizar el impulso.","- Involucre su núcleo para mantener la estabilidad durante todo el movimiento.","### Errores comunes a evitar","- Ensanchando los codos hacia afuera, reduciendo la activación de los tríceps.","- Inclinarse demasiado hacia adelante, desviando la atención del tríceps.","- Mantenga los codos cerca del torso y active el núcleo.","- Repita de 3 a 4 series de 10 a 12 repeticiones con la forma adecuada.","### Consejos para una forma adecuada","- Mantenga los codos doblados hacia adentro para maximizar la activación de los tríceps.","- Asegúrese de que el codo esté completamente extendido en la parte inferior para activar todas las cabezas de los tríceps.","- No extender completamente los brazos, limitando la efectividad del ejercicio.","- Dejar que la pila de pesas caiga de golpe, lo que reduce la participación de los músculos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0c5b985b-c0de-4e80-babe-0c5b985b0000', 'Giro ruso de pie en polea', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/standing-cable-twist.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('05b6d6c8-c0de-4e80-babe-05b6d6c80000', 'Extensión de tríceps inclinado con barra EZ', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/EZ-Barbell-Incline-Triceps-Extension.gif', '{"### Paso 1: Configuración y posición inicial","- Coloque un banco inclinado en un ángulo de 30 a 45 grados.","- Recuéstate en el banco con los pies apoyados en el suelo.","- Sostenga una barra EZ con un agarre por encima de la cabeza, colocando las manos un poco más juntas que el ancho de los hombros.","- Presione la barra hacia arriba hasta la posición inicial, extendiendo completamente los brazos pero sin bloquear los codos.","- Utilice un peso moderado para mantener el control y evitar tensiones.","- Usar peso excesivo, lo que lleva a un control deficiente y posibles lesiones.","- Baja la barra hasta que tus codos estén completamente doblados y sientas un estiramiento en tus tríceps.","### Errores comunes a evitar","- Ensanchar los codos hacia afuera, lo que reduce la activación del tríceps.","- Extienda los brazos por encima del pecho, manteniendo los codos ligeramente doblados.","### Paso 2: Ejecución","- Baje la barra detrás de su cabeza doblando los codos, manteniéndolos estacionarios.","- Realice de 3 a 4 series de 8 a 12 repeticiones con movimiento controlado.","- Baje la barra detrás de la cabeza en lugar de hacia la frente para una mejor activación muscular.","- Involucre su núcleo para estabilizar la parte superior de su cuerpo durante el movimiento.","- Acercar demasiado la barra a la frente, limitando el estiramiento y la participación de los músculos.","- No extender completamente los brazos, reduciendo la efectividad del ejercicio.","### Consejos para una forma adecuada","- Mantenga los codos estables; no dejes que se expandan hacia afuera.","- Mantenga sus muñecas neutrales para evitar tensiones innecesarias.","- Arquear excesivamente la zona lumbar, provocando tensiones innecesarias."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5ee38567-c0de-4e80-babe-5ee385670000', 'Ejercicio con agarre inverso en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Reverse-Grip-Pushdown.gif', '{"### Paso 1: Configuración y posición inicial","- Conecte una barra recta o una barra EZ a una máquina de cable de polea alta.","- Párese frente a la máquina y agarre la barra con un agarre por debajo (supinado), manteniendo las manos separadas aproximadamente al ancho de los hombros.","- Coloque los codos cerca de su torso y active su núcleo.","- Regresa lentamente la barra a la posición inicial, controlando la resistencia.","- Usar peso excesivo, lo que lleva a un control deficiente y una forma inadecuada.","- Seleccione un peso apropiado que permita un movimiento controlado.","- Da un paso atrás ligeramente, manteniendo la columna neutra y una ligera flexión de las rodillas.","- Empuja la barra hacia abajo extendiendo los codos y manteniendo la parte superior de los brazos inmóviles.","### Paso 2: Ejecución","- Utilice un movimiento controlado para evitar balancearse o utilizar el impulso.","- Involucre su núcleo para mantener la estabilidad durante todo el movimiento.","- No bloquees completamente los codos en la parte inferior del movimiento.","- Presiona la barra hacia abajo hasta que tus brazos estén completamente extendidos, apretando tus tríceps en la parte inferior.","### Errores comunes a evitar","- Ensanchando los codos hacia afuera, lo que reduce el compromiso de los tríceps.","- Repita de 3 a 4 series de 10 a 12 repeticiones con la forma adecuada.","### Consejos para una forma adecuada","- Mantenga los codos doblados hacia adentro para maximizar la activación de los tríceps.","- Mantenga una ligera inclinación hacia adelante para mantener el equilibrio y una postura adecuada.","- Apresurarse en las repeticiones, reduciendo la activación y el control de los músculos.","- Inclinarse demasiado hacia adelante, desviando la atención del tríceps.","- No extender completamente los brazos, limitando la efectividad del ejercicio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('693f9124-c0de-4e80-babe-693f91240000', 'Extensión de tríceps', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/High-Pulley-Overhead-Tricep-Extension.gif', '{"### Paso 1: Configuración y posición inicial","- Conecte una cuerda o un mango de barra recta a una polea alta en una máquina de cable.","- Párese de espaldas a la máquina, agarrando el mango con ambas manos.","- Da un paso ligeramente hacia adelante, manteniendo los pies separados a la altura de los hombros para mantener el equilibrio.","- Regrese lentamente a la posición inicial, asegurando un movimiento controlado.","- Utilice un peso que permita la forma adecuada sin tensión excesiva.","- Usar demasiado peso, lo que lleva a una forma inadecuada.","- Extiende los brazos hacia adelante y hacia arriba, estirando los codos hasta que los brazos estén completamente extendidos.","- Evite utilizar el impulso; Controla el peso en todo el rango de movimiento.","### Errores comunes a evitar","- Levante la manija por encima de su cabeza, colocando los codos cerca de las orejas y doblados a 90 grados.","### Paso 2: Ejecución","- Aprieta tus tríceps en la parte superior del movimiento.","- Ensanchando los codos, reduciendo el compromiso de los tríceps.","- Inclinarse demasiado hacia adelante, provoca una tensión innecesaria en la zona lumbar.","- Repita de 8 a 12 repeticiones, completando de 3 a 4 series.","### Consejos para una forma adecuada","- Mantenga su núcleo comprometido para estabilizar su cuerpo.","- Mantenga los codos cerca de la cabeza para involucrar completamente los tríceps.","- No arquees demasiado la zona lumbar; Mantenga una columna neutral.","- Acelerar las repeticiones y reducir el tiempo bajo tensión.","- No extender completamente los brazos, limitando la efectividad del ejercicio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1740da86-c0de-4e80-babe-1740da860000', 'Elevación de pantorrillas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/12/Squat-Hold-Calf-Raise.gif', '{"- Posición inicial: Párese con los pies separados a la altura de los hombros y los brazos extendidos hacia adelante o juntos a la altura del pecho para mantener el equilibrio.","- Descender a sentadilla: bájese hasta ponerse en cuclillas paralelas, manteniendo las rodillas alineadas con los dedos de los pies, la espalda recta y el pecho erguido.","- Establezca la sujeción: mantenga la posición en cuclillas; sus muslos deben estar paralelos al piso o tan bajos como le resulte cómodo.","- Repita: realice múltiples elevaciones de pantorrillas mientras mantiene la posición en cuclillas durante toda la serie.","- Mantenga el torso erguido con el núcleo comprometido durante toda la posición en cuclillas.","- Levante los talones: mientras realiza la sentadilla, levante los talones del suelo presionando las puntas de los pies.","- Pausa y descenso: manténgalo en la parte superior brevemente, luego baje los talones nuevamente bajo control.","- Controle la elevación del talón con movimientos deliberados y contracción total de la pantorrilla.","- Romper la forma de sentadilla: levantar o dejar que las caderas se desplacen hacia arriba anula el propósito de la sujeción isométrica.","- No bajar completamente los talones: acortar el rango de movimiento reduce la activación de la pantorrilla.","- Concéntrese en el equilibrio manteniendo la mirada hacia adelante y los brazos extendidos para lograr estabilidad.","- No rebotes: realiza cada repetición con intención y control.","### Errores comunes","### Consejos para una forma adecuada","- Mantenga las rodillas alineadas con los dedos de los pies; evite el colapso hacia adentro (valgo).","- Contener la respiración: la respiración adecuada favorece la estabilidad y la resistencia.","- Las rodillas se hunden: provoca tensión en las articulaciones y reduce la eficacia; manténgalas orientadas hacia afuera.","- Falta de equilibrio: apresurar las repeticiones o colocar mal los pies puede causar tambaleos o movimientos ineficaces."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('65db61a0-c0de-4e80-babe-65db61a00000', 'Dominadas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Upside-Down-Pull-up.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5044f679-c0de-4e80-babe-5044f6790000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Tuck-Jump.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1bf3475b-c0de-4e80-babe-1bf3475b0000', 'Zancadas', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2023/09/bodyweight-walking-lunge.gif', '{"- Posición inicial: Párese erguido con los pies separados a la altura de las caderas, los brazos a los costados o las manos en las caderas.","- Continúe caminando: alterne las piernas con un movimiento suave y continuo hasta completar todas las repeticiones.","- Mantenga el pecho elevado y la columna neutra durante todo el movimiento.","- Tome medidas deliberadas y controladas para mantener el equilibrio.","- Paso adelante: Da un paso controlado hacia adelante con una pierna, bajando las caderas hasta que ambas rodillas se doblen a 90 grados.","- Empuje a través del talón: presione a través del talón de su pie delantero para elevarse y llevar la pierna trasera hacia adelante para dar el siguiente paso.","- Involucre el núcleo para estabilizar su cuerpo y evitar que se tambalee.","### Errores comunes","- Sobrepasar o subestimar: conduce a una mala alineación y reduce la eficacia.","- Fase de descenso: mantenga el torso erguido y el núcleo enganchado mientras la rodilla trasera se cierne justo sobre el suelo.","### Consejos para una forma adecuada","- Asegúrese de que la rodilla delantera permanezca alineada sobre el tobillo y no colapse hacia adentro.","- Inclinarse demasiado hacia adelante: genera un exceso de tensión en la zona lumbar.","- Dejar que la rodilla colapse hacia adentro: aumenta el riesgo de tensión en las articulaciones y reduce la activación de los glúteos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('27df15b9-c0de-4e80-babe-27df15b90000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/L-Sit.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('063bb502-c0de-4e80-babe-063bb5020000', 'Ejercicio', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Swimming.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4e753f47-c0de-4e80-babe-4e753f470000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/11/High-Knee-Squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3e913f4c-c0de-4e80-babe-3e913f4c0000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Boxer-Shuffle-Cardio.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('62ab3f7f-c0de-4e80-babe-62ab3f7f0000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Cross-Arm-Push-up.gif', '{"Comience en una posición de tabla alta: comience en una posición de tabla alta con las manos separadas al ancho de los hombros y los pies juntos.","Empuje hacia arriba: Empuje hacia atrás hasta la posición inicial, manteniendo los brazos cruzados sobre el pecho.","Cruza los brazos sobre el pecho: Cruza los brazos de modo que tu mano derecha quede frente a tu pecho izquierdo y tu mano izquierda frente a tu pecho derecho.","Baje el cuerpo: baje el cuerpo doblando los codos, manteniendo la espalda recta y el núcleo comprometido hasta que el pecho casi toque el suelo.","Repetir: repite el movimiento durante el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5eabb428-c0de-4e80-babe-5eabb4280000', 'Ejercicio', 'Piernas', '', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('49eddde6-c0de-4e80-babe-49eddde60000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Punches.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4b632a81-c0de-4e80-babe-4b632a810000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Jab-Boxing.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('11d092d7-c0de-4e80-babe-11d092d70000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/Right-Uppercut-Boxing.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('56f6ac96-c0de-4e80-babe-56f6ac960000', 'Extensión de tríceps en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Cable-Concentration-Extension-on-knee.gif', '{"### Paso 1: Configuración y posición inicial","- Conecte una sola manija a una máquina de cable a la altura de los hombros o ligeramente por encima.","- Agarre el mango con una mano, manteniendo el codo doblado y cerca del torso.","- Regrese lentamente a la posición inicial de forma controlada.","- Usar peso excesivo, lo que lleva a una forma e impulso inadecuados.","- Seleccione un peso apropiado que permita un movimiento controlado.","- Arrodíllate sobre una rodilla mientras mantienes la espalda recta y el core comprometido.","- Extiende tu brazo hacia abajo, alejando el mango de tu cuerpo.","- Concéntrese en enderezar completamente el codo mientras mantiene fija la parte superior del brazo.","### Paso 2: Ejecución","- Asegure la extensión completa del codo para trabajar los tríceps en un rango completo de movimiento.","- Acelerando el movimiento, disminuyendo el tiempo bajo tensión.","- Mantenga un núcleo fuerte para evitar el movimiento excesivo del cuerpo.","- Utilice un tempo controlado para maximizar el tiempo bajo tensión.","### Errores comunes a evitar","- Permitir que el codo se mueva, lo que reduce el aislamiento del tríceps.","- Asegúrese de que la parte superior de su brazo permanezca estacionaria durante todo el ejercicio.","- Mantenga la contracción durante un segundo para maximizar la activación del tríceps.","- Repita de 3 a 4 series de 10 a 12 repeticiones por brazo.","### Consejos para una forma adecuada","- Mantenga el codo inmóvil para enganchar completamente el tríceps.","- Evite inclinarse hacia adelante o hacia atrás, ya que esto puede reducir la efectividad.","- No extender completamente el brazo, limitando la activación muscular.","- Inclinarse demasiado hacia adelante, desviando la atención del tríceps."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3b49eb50-c0de-4e80-babe-3b49eb500000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Hook-Kick-Kickboxing-with-boxing-bag.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
