INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('05fc58b9-c0de-4e80-babe-05fc58b90000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Boxing-Right-Cross-with-boxing-bag.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('39f8f658-c0de-4e80-babe-39f8f6580000', 'Zancadas', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Walking-High-Knee-Lunges.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1894d15c-c0de-4e80-babe-1894d15c0000', 'Sentadilla con pesa rusa / kettlebell', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Kettlebell-Pistol-Squats.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('56dbfc39-c0de-4e80-babe-56dbfc390000', 'Estiramiento', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Above-Head-Chest-Stretch.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6aa69611-c0de-4e80-babe-6aa696110000', 'Extensión de tríceps', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Reverse-Hyperextensions.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0f015b8c-c0de-4e80-babe-0f015b8c0000', 'Press de hombros unilateral con pesa rusa / kettlebell', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Kettlebell-One-Arm-Military-Press.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('342f40eb-c0de-4e80-babe-342f40eb0000', 'Ejercicio con pesa rusa / kettlebell', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Kettlebell-Split-Snatch.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('25e38320-c0de-4e80-babe-25e383200000', 'Pájaro / Vuelos posteriores inclinado', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Bent-Over-Rear-Delt-Fly-Gymstick.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7baeee07-c0de-4e80-babe-7baeee070000', 'Press de pecho con pesa rusa / kettlebell', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Kettlebell-Arnold-Press.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7eb92333-c0de-4e80-babe-7eb923330000', 'Ejercicio con pesa rusa / kettlebell', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Kettlebell-Windmill.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1bdb7671-c0de-4e80-babe-1bdb76710000', 'Press de pecho con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Close-Grip-Dumbbell-Press.gif', '{"- Configuración: Acuéstese en un banco con una mancuerna en cada mano. Coloque las mancuernas directamente sobre su pecho, con las palmas una frente a la otra (agarre neutral) y los codos doblados en un ángulo de 90 grados.","- Acuéstese en un banco con una mancuerna en cada mano.","- Coloque las mancuernas directamente sobre su pecho, con las palmas una frente a la otra (agarre neutral) y los codos doblados en un ángulo de 90 grados.","- Fase de descenso: baje lentamente las mancuernas hasta la posición inicial, manteniendo el control y apretando las mancuernas tanto como sea posible.","- Baje lentamente las mancuernas hasta la posición inicial, manteniendo el control y apretando las mancuernas tanto como sea posible.","- Usar demasiado peso: Levantar mancuernas excesivamente pesadas puede comprometer la forma y provocar lesiones.","- Mantenga los codos cerca del cuerpo durante todo el levantamiento, manteniendo un agarre firme.","- Repetir: Realice el número deseado de repeticiones, manteniendo la forma y el control adecuados durante toda la serie.","- Realice el número deseado de repeticiones, manteniendo la forma y el control adecuados durante toda la serie.","- Ejecución: Comienza el movimiento extendiendo los brazos completamente y presionando las mancuernas directamente hacia arriba. Mientras presionas, concéntrate en apretar las mancuernas con fuerza. Imagina que estás tratando de aplastarlos o apretarlos durante todo el movimiento. Mantén los codos cerca del cuerpo durante todo el levantamiento, manteniendo un agarre firme. Haz una pausa por un momento en la parte superior del movimiento, manteniendo la tensión en los tríceps.","- Comienza el movimiento extendiendo los brazos completamente y presionando las mancuernas directamente hacia arriba.","- Mientras presionas, concéntrate en apretar las mancuernas con fuerza. Imagina que estás tratando de aplastarlos o apretarlos durante todo el movimiento.","- Haga una pausa por un momento en la parte superior del movimiento, manteniendo la tensión en el tríceps.","- Utilice un movimiento controlado en lugar de depender del impulso.","- Acelerar el movimiento: Realizar el ejercicio demasiado rápido reduce el tiempo bajo tensión y limita la activación muscular.","- Mantenga una posición neutra de la muñeca para evitar tensiones innecesarias.","### Errores comunes:","- Ensanchar los codos: esto cambia el énfasis hacia el pecho y reduce la activación del tríceps.","### Consejos para una forma adecuada:","- Mantenga los codos cerca del cuerpo para maximizar la activación de los tríceps.","- Mantenga los hombros retraídos y comprometidos para evitar tensiones innecesarias en las articulaciones.","- Arquear la parte baja de la espalda: Arquearse demasiado puede ejercer una tensión innecesaria en la columna."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3ab2a2eb-c0de-4e80-babe-3ab2a2eb0000', 'Ejercicio en máquina', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Full-Crunch-Machine.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('795716a4-c0de-4e80-babe-795716a40000', 'Peso muerto', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Bodyweight-Single-Leg-Deadlift.gif', '{"El peso muerto con una sola pierna es un ejercicio eficaz para fortalecer, tonificar, tensar los músculos de los glúteos y mejorar el equilibrio.","El peso muerto con una sola pierna trabaja secundariamente los músculos centrales, mientras los abdominales y oblicuos se contraen para estabilizar el cuerpo. Este ejercicio también trabaja los músculos erectores de la columna en la espalda que ayudan a sostener la columna y brindan flexibilidad al doblarse en múltiples direcciones.","El peso muerto con una sola pierna puede mejorar el equilibrio y corregir los desequilibrios de fuerza en las caderas. Cada vez que te paras sobre una pierna, utilizas los mismos músculos para mantener el equilibrio y la estabilidad que a menudo se utilizan para desarrollar fuerza. ¡Mejorar la capacidad de cada pierna para trabajar y producir fuerza te ayudará a disparar tus números de sentadilla trasera y peso muerto!"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('068c42aa-c0de-4e80-babe-068c42aa0000', 'Dominadas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Brachialis-Pull-up.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5c2b5d17-c0de-4e80-babe-5c2b5d170000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Bodyweight-Box-Squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('259bc21a-c0de-4e80-babe-259bc21a0000', 'Plancha', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Front-Plank-with-Arm-Lift.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0ea2df01-c0de-4e80-babe-0ea2df010000', 'Estiramiento', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/abdominal-stretch.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5bda76ea-c0de-4e80-babe-5bda76ea0000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Bird-Dog.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('37525720-c0de-4e80-babe-375257200000', 'Curl de piernas', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Step-Up-Single-Leg-Balance-with-Bicep-Curl.gif', '{"Sujete el peso (mancuerna, barra o polea) con un agarre supino (palmas hacia arriba).","Mantenga los pies separados al ancho de los hombros y las rodillas ligeramente flexionadas.","Coloque los codos pegados a los costados del torso y mantenga la espalda recta.","Manteniendo inmóvil la parte superior de los brazos, flexione los codos y eleve la carga hacia los hombros.","Apriete fuertemente los bíceps en el punto de máxima contracción por un segundo.","Baje el peso de forma controlada y lenta hasta extender completamente los brazos.","Evite balancear la espalda o mover los hombros hacia adelante para ayudarse.","Mantenga las muñecas firmes y rectas durante todo el recorrido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2e372b46-c0de-4e80-babe-2e372b460000', 'Ejercicio con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/12/Dumbeel-Step-Up.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('390db4fb-c0de-4e80-babe-390db4fb0000', 'Remo sentado en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Seated-Cable-Rope-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('510c2da5-c0de-4e80-babe-510c2da50000', 'Jalón al pecho', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Close-Grip-Lat-Pulldown.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('133776c3-c0de-4e80-babe-133776c30000', 'Press de pecho con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Single-Dumbbell-Close-grip-Press.gif', '{"### Paso 1: Configuración y posición inicial","- Acuéstese en un banco plano, asegurándose de que sus pies estén firmemente plantados en el suelo.","- Coloque la mancuerna sobre su pecho, manteniendo los codos doblados.","- Involucre su núcleo para mantener su cuerpo estable en el banco.","- Usar demasiado peso, lo que provoca un control deficiente y posibles lesiones.","- Sostenga una mancuerna con ambas manos, sujetándola por los lados de las placas de pesas.","- Baja la mancuerna lentamente hacia tu pecho, manteniéndola bajo control.","- Una vez que la mancuerna llegue justo por encima de tu pecho, haz una breve pausa.","- Presiona la mancuerna hacia arriba, extendiendo los brazos completamente mientras aprietas los tríceps.","### Paso 2: Ejecución","- No extienda demasiado los codos en la parte superior para evitar tensión en las articulaciones.","- Mantenga un movimiento controlado para evitar utilizar el impulso.","- Utilice un peso que pueda controlar para lograr una forma adecuada y un rango de movimiento completo.","### Errores comunes a evitar","- Ensanchar los codos, lo que reduce la activación de los tríceps y aumenta la tensión en los hombros.","- Mantenga un núcleo apretado y evite el ensanchamiento excesivo de los codos.","- Repita de 3 a 4 series de 8 a 12 repeticiones.","### Consejos para una forma adecuada","- Mantenga los codos pegados al cuerpo para maximizar la participación de los tríceps.","- Acelerar las repeticiones y reducir el tiempo bajo tensión.","- Hacer rebotar la mancuerna contra el pecho, lo que reduce la participación de los músculos.","- No extender completamente los brazos, limitando la activación de los tríceps."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1fc6e271-c0de-4e80-babe-1fc6e2710000', 'Zancadas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/bodyweight-reverse-lunge.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('27368e8f-c0de-4e80-babe-27368e8f0000', 'Curl de piernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Lever-Single-Leg-Curl.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('64996304-c0de-4e80-babe-649963040000', 'Elevación de piernas', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Ab-Straps-Leg-Raise.gif', '{"Este ejercicio que trabaja los flexores de la cadera mejora los músculos centrales, especialmente los músculos abdominales inferiores. Es uno de los ejercicios abdominales efectivos que activa todo el núcleo ejercitando no solo los abdominales inferiores sino también los músculos abdominales superiores."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5dcf933e-c0de-4e80-babe-5dcf933e0000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Clap-Push-Up.gif', '{"- Posición inicial: Comience en una posición de flexión regular con las manos colocadas en el suelo ligeramente más separadas que el ancho de los hombros. Su cuerpo debe formar una línea recta desde la cabeza hasta los talones. Involucre sus músculos centrales para mantener la estabilidad.","- Comience en una posición de flexión regular con las manos colocadas en el suelo ligeramente más separadas que el ancho de los hombros.","- Después de aplaudir, extiende inmediatamente los brazos para sostenerte y volver a la posición de flexión.","- Tu cuerpo debe formar una línea recta desde la cabeza hasta los talones. Involucre sus músculos centrales para mantener la estabilidad.","- Bájate tanto como lo harías en una flexión estándar, con el pecho cerca del suelo.","- El aplauso: empuja explosivamente el suelo con las manos, generando suficiente fuerza hacia arriba para levantar la parte superior del cuerpo del suelo. Mientras estás en el aire, junta rápidamente las manos frente al pecho y aplaude. Esto requiere velocidad y coordinación. Intente aplaudir lo más cerca posible del pecho.","- Empuja explosivamente el suelo con las manos, generando suficiente fuerza hacia arriba para levantar la parte superior del cuerpo del suelo.","- Mientras estás en el aire, junta rápidamente las manos frente al pecho y aplaude. Esto requiere velocidad y coordinación.","- Intenta aplaudir lo más cerca posible de tu pecho.","- El Descenso: Baje el pecho hacia el suelo doblando los codos. Mantén el cuerpo en línea recta durante todo el descenso. Bájate tanto como lo harías en una flexión estándar, con el pecho cerca del suelo.","- Baje el pecho hacia el suelo doblando los codos. Mantén tu cuerpo en línea recta durante todo el descenso.","- Empuje incompleto: no generar suficiente fuerza puede resultar en aplausos incompletos o aterrizajes fallidos.","- Dejar caer las caderas: Permitir que las caderas se doblen tensa la zona lumbar y reduce la eficiencia.","- El aterrizaje: Después de aplaudir, extienda inmediatamente los brazos para detenerse y volver a la posición de flexión. Aterrice con las manos un poco más separadas que el ancho de los hombros, listo para la siguiente repetición. Aterrice con los codos doblados para absorber el impacto y proteger sus muñecas y codos.","- Aterriza con las manos un poco más separadas que el ancho de los hombros, listo para la siguiente repetición.","- Aterriza con los codos doblados para absorber el impacto y proteger tus muñecas y codos.","- Repetir: Realice múltiples repeticiones de la flexión con palmada, concentrándose en la potencia explosiva y un aterrizaje controlado. Aumente gradualmente el número de repeticiones a medida que se sienta más cómodo con el ejercicio.","- Realice múltiples repeticiones de la flexión con palmada, concentrándose en la potencia explosiva y un aterrizaje controlado.","- Usa tu pecho, hombros y tríceps para generar poder explosivo.","- Aterriza suavemente con los codos doblados para reducir la tensión en las articulaciones.","- Aumente gradualmente el número de repeticiones a medida que se sienta más cómodo con el ejercicio.","### Consejos para una forma adecuada:","- Mantenga un núcleo fuerte para evitar la flacidez o el arqueamiento de la espalda baja.","- Mantenga su respiración controlada: inhale mientras baja y exhale mientras empuja hacia arriba.","### Errores comunes:","- Mala colocación de las manos: Colocar las manos demasiado anchas o demasiado estrechas puede reducir la potencia y aumentar el riesgo de lesiones.","- Bloquear los codos al aterrizar: esto aumenta la tensión en las articulaciones y puede provocar lesiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('21e484a7-c0de-4e80-babe-21e484a70000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Single-Leg-Step-Down.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1d4aaf4f-c0de-4e80-babe-1d4aaf4f0000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/belt-squat.gif', '{"Asegure el cinturón de sentadillas alrededor de su cintura y fíjelo al peso de la máquina o al pasador de carga.","Sube a las plataformas de modo que el peso cuelgue entre tus piernas y tus pies estén separados a la altura de los hombros.","Empuja con los talones para volver a la posición de pie, manteniendo el torso erguido.","Mantente erguido y fortalece tu núcleo. Comienza el descenso empujando las caderas hacia atrás y doblando las rodillas.","Baje hasta que sus muslos estén al menos paralelos al suelo.","Repita para las repeticiones deseadas, manteniendo una columna neutral y un ritmo controlado."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0fdd6dc8-c0de-4e80-babe-0fdd6dc80000', 'Ejercicio de rodillas en polea', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Half-Kneeling-Cable-External-Rotation.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5ab6a501-c0de-4e80-babe-5ab6a5010000', 'Curl de muñeca con barra', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Behind-The-Back-Barbell-Wrist-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6488dd91-c0de-4e80-babe-6488dd910000', 'Ejercicio sentado en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Cable-Seated-Pullover.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1216f715-c0de-4e80-babe-1216f7150000', 'Elevaciones laterales', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Landmine-Lateral-Raise.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('26868a5d-c0de-4e80-babe-26868a5d0000', 'Ejercicio sentado en polea', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Cable-Seated-Shoulder-Internal-Rotation.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('21f8be09-c0de-4e80-babe-21f8be090000', 'Flexiones de pecho de rodillas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Knee-Push-Up.gif', '{"### Paso 1: Configuración y posición inicial","- Coloque sus manos directamente debajo de su pecho, formando una forma de diamante tocando los pulgares y los dedos índice.","- Empuje hacia atrás hasta la posición inicial extendiendo completamente los brazos mientras mantiene la tensión en los tríceps.","- Ajuste ligeramente la colocación de su mano si siente molestias en la muñeca.","###","- Comience arrodillado en el suelo o sobre una colchoneta para mayor comodidad.","- Detente cuando tu pecho casi toque tus manos.","### Paso 2: Ejecución","- Baje el pecho hacia el suelo, manteniendo los codos pegados al cuerpo.","- Respira adecuadamente, inhalando mientras bajas y exhalando mientras empujas hacia arriba.","- No bajar lo suficiente, lo que limita el rango de movimiento y la activación muscular.","- No dejes que tus codos se ensanchen; manténgalos cerca de sus costados para una mejor participación de los tríceps.","### Errores comunes a evitar","- Permitir que la parte baja de la espalda se hunda, lo que reduce el compromiso del core y puede causar tensión.","- Mantenga su núcleo comprometido y mantenga una línea recta desde las rodillas hasta la cabeza.","- Repita de 3 a 4 series de 10 a 15 repeticiones, dependiendo de su nivel de condición física.","### Consejos para una forma adecuada","- Mantenga su núcleo comprometido para evitar que la parte baja de la espalda se arquee o se hunda.","- Mantenga un ritmo controlado para maximizar la activación muscular.","- Acelerar las repeticiones, disminuir el tiempo bajo tensión y la efectividad.","- Ensanchar los codos, lo que lleva a una forma inadecuada y una activación reducida de los tríceps.","- Colocar las manos demasiado separadas, desviando la atención del tríceps."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('59f467fe-c0de-4e80-babe-59f467fe0000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Jack-Burpees.gif', '{"Este ejercicio se dirige a los músculos abdominales, los músculos de la cadera y los flexores de la cadera y también trabaja los muslos, los tendones de las rodillas, los cuádriceps y los hombros.","Jack Burpees es uno de los ejercicios para todo el cuerpo más efectivos que ayudan a quemar calorías rápidamente mientras se enfocan en todos los músculos del cuerpo. Jack Burpees son un ejercicio pliométrico. Los ejercicios pliométricos son movimientos aeróbicos explosivos que aumentan la velocidad, la rapidez y la potencia y trabajan todo el cuerpo.","Los saltos son beneficiosos para la salud porque combinan el acondicionamiento cardiovascular con el trabajo de fuerza. Dado que los saltos elevan tu frecuencia cardíaca, también pueden mejorar tu condición cardiovascular. Comience lentamente hasta que se acostumbre al ejercicio y aumente gradualmente hasta hacer más repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2ee900d0-c0de-4e80-babe-2ee900d00000', 'Postura de yoga', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Boat-Pose-Stretch.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('470a553c-c0de-4e80-babe-470a553c0000', 'Ejercicio con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Dumbbell-Glute-Bridge.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0ad64f90-c0de-4e80-babe-0ad64f900000', 'Giro ruso sentado en máquina', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Lever-Seated-Twist.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4f79770e-c0de-4e80-babe-4f79770e0000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/03/Long-Jump-Plyometrics.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('229ef1e0-c0de-4e80-babe-229ef1e00000', 'Prensa de piernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Lever-Assisted-Leg-Press.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6f00c335-c0de-4e80-babe-6f00c3350000', 'Remo', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Ring-Inverted-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3a2779c9-c0de-4e80-babe-3a2779c90000', 'Curl de bíceps', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Nordic-Hamstring-Curl.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3b7dffb2-c0de-4e80-babe-3b7dffb20000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Push-up-With-Push-up-Bars.gif', '{"- Agarre las barras Sujete las barras firmemente con un agarre neutral, manteniendo las muñecas rectas y alineadas con los antebrazos.","- Sostenga las barras firmemente con un agarre neutral, manteniendo las muñecas rectas y alineadas con los antebrazos.","- Posición inicial Asuma una posición de tabla alta con las manos agarrando las barras, los brazos completamente extendidos y el cuerpo en línea recta desde la cabeza hasta los talones.","- Asuma una posición de tabla alta con las manos agarrando las barras, los brazos completamente extendidos y el cuerpo en línea recta desde la cabeza hasta los talones.","- Exhala mientras presionas a través de las barras para volver a la posición inicial.","- Coloque las barras Coloque las barras de flexión a la altura de los hombros sobre una superficie estable. Asegúrese de que estén seguros y no se resbalen.","- Coloque las barras de flexión a la altura de los hombros sobre una superficie estable. Asegúrese de que estén seguros y no se resbalen.","- Inhala mientras doblas los codos, bajando el pecho hasta que esté justo por debajo de la altura de tus manos. Mantenga los codos en un ángulo de 45 grados con respecto al torso.","- Push Back UpExhale mientras presiona a través de las barras para regresar a la posición inicial.","- Baje su cuerpo Inhale mientras dobla los codos, bajando el pecho hasta que esté justo por debajo de la altura de sus manos. Mantenga los codos en un ángulo de 45 grados con respecto al torso.","- Respiración: Inhale mientras baja y exhale mientras empuja hacia arriba.","- Rango de movimiento inadecuado: no bajar el pecho por completo disminuye la efectividad del ejercicio.","- Acelerar el movimiento: realice cada repetición con control para maximizar la participación de los músculos y reducir el riesgo de lesiones.","- Repetir Realice de 10 a 15 repeticiones durante 2 a 3 series, manteniendo la forma adecuada en todo momento.","- Realice de 10 a 15 repeticiones durante 2 a 3 series, manteniendo la forma adecuada en todo momento.","- Involucre su núcleo: mantenga sus abdominales contraídos para evitar que sus caderas se hunda o se levanten.","- Controle el movimiento: evite las prisas; Concéntrese en un descenso y ascenso lento y controlado.","- Posición del codo: Mantenga los codos en un ángulo moderado (no ensanchados) para proteger sus hombros.","### Consejos para una forma adecuada","- Columna Neutral: Mantenga una línea recta desde la cabeza hasta los talones.","- Caderas caídas: Dejar caer las caderas puede tensar la zona lumbar. Mantenga su núcleo comprometido para evitar esto.","### Errores comunes","- Codos ensanchados: Permitir que los codos se ensanchen excesivamente puede generar una tensión indebida en los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1b9f05a0-c0de-4e80-babe-1b9f05a00000', 'Curl de bíceps', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Close-Grip-Z-Bar-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0f5bcd28-c0de-4e80-babe-0f5bcd280000', 'Jalón al pecho en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Lever-Cable-Rear-Pulldown.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5d48e7c4-c0de-4e80-babe-5d48e7c40000', 'Aperturas de pecho declinado en polea', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/One-Arm-Decline-Cable-Fly.gif', '{"- Ajuste la máquina de cable a una posición baja. Conecte una sola manija al cable.","- Instale un banco inclinado (alrededor de 15 a 30 grados) cerca de la máquina de cable.","- Asegure sus pies en las almohadillas del banco para mantener la estabilidad.","- Agarre el asa con una mano y recuéstese en el banco, manteniendo la mano que no trabaja sobre el torso o agarrando el banco como apoyo.","- Posición inicial: Extienda el brazo recto por encima del pecho con una ligera flexión del codo. Mantenga la palma hacia adentro (pronación neutra o leve).","- Usar demasiado peso: priorice el control y la conexión mente-músculo.","- Realice primero el vuelo con cable en un banco plano o en una máquina.","- Deténgase cuando sienta un estiramiento profundo en el pecho (el codo debe estar ligeramente por debajo del nivel del hombro).","### Errores comunes a evitar","- Dejar caer el brazo demasiado bajo: deténgase al nivel del pecho o ligeramente por debajo.","### Variables de entrenamiento y modificaciones","- Extienda el brazo recto por encima del pecho con una ligera flexión del codo.","- Fase de descenso (movimiento excéntrico): baje lentamente el brazo formando un amplio arco hacia un lado. Deténgase cuando sienta un estiramiento profundo en el pecho (el codo debe estar ligeramente por debajo del nivel del hombro).","- Baje lentamente el brazo formando un amplio arco hacia un lado.","- Fase de elevación (movimiento concéntrico): Involucre su pecho y levante su brazo formando un arco suave. Apriete su pectoral en la parte superior del movimiento.","- Enganche su pecho y levante el brazo formando un arco suave.","- Aprieta tu pectoral en la parte superior del movimiento.","- Cambie de lado y realice el mismo movimiento en el otro brazo.","- Acelerar el movimiento: actúe con un tempo lento y controlado.","- Realice primero con ambos brazos antes de pasar a unilateral.","- Excéntrico lento (fase negativa) → 3-4 segundos","- Concéntrico rápido (fase de elevación) → 1-2 segundos","- Utilice un peso más ligero con mayores repeticiones para controlar.","- Aumente el ángulo de descenso a 30-45° para una mayor activación de los pectorales inferiores.","- Mantenga la palma de la mano hacia adentro (pronación neutra o ligera).","- Repita hasta el número deseado de repeticiones (8-15 repeticiones es un buen rango).","- Bloquear el codo: mantenga una ligera flexión para evitar tensión en las articulaciones.","- Girar el torso: mantenga el núcleo comprometido para mantener la estabilidad.","- Hipertrofia (crecimiento muscular) → 3-4 series de 8-12 repeticiones","- Resistencia y estabilidad → 3 series de 12-15 repeticiones","- Utilice un ritmo excéntrico lento (4-5 segundos) para un mayor daño muscular.","- Súper serie con press declinado con mancuernas para aumentar la intensidad."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('388749c5-c0de-4e80-babe-388749c50000', 'Extensión de tríceps unilateral en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Cable-One-Arm-Overhead-Triceps-Extension.gif', '{"### Paso 1: Configuración y posición inicial","- Conecte una sola manija a la polea baja de una máquina de cable.","- Párese con los pies separados a la altura de los hombros y agarre el asa con una mano.","- Baje lentamente la manija hasta la posición inicial, manteniendo el control en todo momento.","- Utilice un peso de ligero a moderado para centrarse en la forma adecuada y la contracción muscular.","- Aléjese de la máquina y levante la manija por encima de su cabeza, manteniendo el codo doblado y cerca de la cabeza.","- Mantenga un movimiento controlado en lugar de sacudir el peso.","- No arquees la zona lumbar; Involucre su núcleo para lograr estabilidad.","### Paso 2: Ejecución","- Extienda el brazo enderezando el codo hasta que el brazo esté completamente extendido por encima de la cabeza.","- Aprieta tus tríceps en la parte superior del movimiento.","- Apresurarse en el movimiento sin el control adecuado.","### Errores comunes a evitar","- Ensanchar el codo en lugar de mantenerlo cerca de la cabeza.","- Usar demasiado peso, lo que lleva a una forma inadecuada y un rango de movimiento reducido.","- Involucre su núcleo y mantenga una columna neutral durante todo el ejercicio.","- Repita de 3 a 4 series de 10 a 15 repeticiones antes de cambiar de brazo.","### Consejos para una forma adecuada","- Mantenga el codo fijo en su lugar para evitar utilizar el impulso.","- Mantenga su muñeca neutral para evitar tensiones.","- Inclinarse hacia atrás, lo que aleja la tensión del tríceps."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('192f39f7-c0de-4e80-babe-192f39f70000', 'Curl de bíceps con mancuernas', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/dumbbell-scot-curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('03265ba5-c0de-4e80-babe-03265ba50000', 'Ejercicio en polea', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Cross-Cable-Face-Pull.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2441b5eb-c0de-4e80-babe-2441b5eb0000', 'Extensión de tríceps de pie con barra', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Standing-Barbell-Triceps-Extension.gif', '{"### Paso 1: Configuración y posición inicial","- Sostenga una barra con un agarre por encima de la cabeza (con las palmas hacia adelante), colocando las manos más cerca que el ancho de los hombros.","- Utilice un peso moderado para garantizar la forma adecuada y evitar lesiones.","- Usar peso excesivo, lo que lleva a una mala forma y a un mayor riesgo de lesiones.","- Párese a la altura de los hombros y mantenga los pies firmemente plantados para mantener el equilibrio.","- Baja la barra hasta que tus antebrazos queden paralelos al suelo o ligeramente más bajos.","- Presione la barra hacia arriba extendiendo los codos hasta que los brazos estén completamente estirados.","- Repita de 3 a 4 series de 8 a 12 repeticiones, manteniendo el control durante todo el movimiento.","- Levante la barra por encima de su cabeza, extendiendo completamente los brazos mientras mantiene los codos cerca de la cabeza.","### Paso 2: Ejecución","- Baje la barra lentamente detrás de su cabeza doblando los codos.","- Acelerar el movimiento, reduciendo la tensión muscular y la eficacia.","- No bajar la barra del todo, limitando el rango de movimiento del ejercicio.","- Mantenga una posición neutral de la cabeza manteniendo la barbilla ligeramente metida.","- Muévete lentamente y con control, especialmente en la fase de descenso.","### Errores comunes a evitar","- Mantenga la parte superior de los brazos inmóviles y evite extender los codos hacia afuera.","### Consejos para una forma adecuada","- Mantenga su núcleo comprometido para evitar arquear la espalda baja.","- Mantenga los codos cerca de la cabeza para maximizar la activación de los tríceps.","- Ensanchar los codos hacia afuera, lo que reduce el compromiso de los tríceps y aumenta la tensión en los hombros.","- Arquear la zona lumbar, lo que genera una tensión innecesaria en la columna."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3d784173-c0de-4e80-babe-3d7841730000', 'Remo', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/shotgun-row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2c8f65ee-c0de-4e80-babe-2c8f65ee0000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Elbow-Reverse-Push-Up.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5c39d0e4-c0de-4e80-babe-5c39d0e40000', 'Press de pecho unilateral con mancuerna', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Dumbbell-One-Arm-Reverse-Grip-Press.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2caee4eb-c0de-4e80-babe-2caee4eb0000', 'Press de pecho declinado en máquina', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Smith-Machine-Decline-Bench-Press.gif', '{"- Coloque el banco declinado Coloque un banco declinado debajo de la máquina Smith, alineando la barra con la parte inferior del pecho.","- Coloque un banco declinado debajo de la máquina Smith, alineando la barra con la parte inferior del pecho.","- Ajuste la barra Asegure la barra a una altura que le permita alcanzarla cómodamente con los brazos extendidos mientras está acostado en el banco.","- Asegure la barra a una altura que le permita alcanzarla cómodamente con los brazos extendidos mientras está acostado en el banco.","- Cargue la barra Agregue las placas de peso deseadas, asegurándose de que estén distribuidas uniformemente en ambos lados.","- Agregue las placas de peso deseadas, asegurándose de que estén distribuidas uniformemente en ambos lados.","- Posición inicial Acuéstese en el banco de descenso y asegure los pies debajo de las almohadillas del banco. Sujete la barra ligeramente más ancha que el ancho de los hombros, con las palmas hacia adelante. Retire la barra extendiendo los brazos completamente y colocándola sobre la parte inferior del pecho.","- Acuéstese en el banco de descenso y asegure sus pies debajo de las almohadillas del banco.","- Agarre la barra un poco más separada que el ancho de los hombros, con las palmas hacia adelante.","- Empuja la barra de regreso a la posición inicial extendiendo completamente los brazos.","- Topes de seguridad: Configure siempre los topes de seguridad, especialmente al levantar pesos pesados.","- Ángulo de banco incorrecto: utilizar un ángulo de descenso demasiado pronunciado o demasiado superficial puede reducir la eficacia del ejercicio.","- Sobrecargar la barra: el uso de peso excesivo puede comprometer la forma y aumentar el riesgo de lesiones.","- Asegure los topes de seguridad Coloque los topes de seguridad a un nivel que evite que la barra baje demasiado, protegiéndolo en caso de falla.","- Presione la barra hacia arriba Empuje la barra hacia atrás a la posición inicial extendiendo completamente los brazos. Concéntrese en apretar los músculos del pecho en la parte superior del movimiento.","- Involucre su núcleo: mantenga sus abdominales contraídos para mantener la estabilidad en el banco de descenso.","- Movimiento controlado: evite dejar que la barra caiga demasiado rápido; controlar tanto la fase de descenso como la de elevación.","- Establece los topes de seguridad a un nivel que impida que la barra baje demasiado, protegiéndote en caso de fallo.","- Retire la barra extendiendo los brazos completamente y colocándola sobre la parte inferior del pecho.","- Baje la barra Doble lentamente los codos para bajar la barra hacia la parte inferior del pecho. Mantenga las muñecas rectas y los codos ligeramente extendidos, formando un ángulo de 45 grados con el torso.","- Doble lentamente los codos para bajar la barra hacia la parte inferior del pecho.","- Concéntrate en apretar los músculos del pecho en la parte superior del movimiento.","- Repetir Realice de 8 a 12 repeticiones durante 3 a 4 series, manteniendo el movimiento controlado en todo momento.","- Realice de 8 a 12 repeticiones durante 3 a 4 series, manteniendo el movimiento controlado en todo momento.","- Ruta de la barra: baje la barra hasta la parte inferior del pecho y presiónela hacia arriba sin bloquear los codos.","- Agarre adecuado: asegúrese de que su agarre sea firme pero no demasiado apretado para reducir la tensión en la muñeca.","### Errores comunes","- Codos ensanchados demasiado anchos: Los codos ensanchados demasiado aumentan el riesgo de tensión en los hombros.","- Mantenga las muñecas rectas y los codos ligeramente extendidos, formando un ángulo de 45 grados con el torso.","### Consejos para una forma adecuada","- Saltarse las paradas de seguridad: No configurar las paradas de seguridad puede ser peligroso, especialmente cuando se levantan objetos pesados.","- Alineación inadecuada de la barra: Colocar la barra demasiado alta en el pecho desvía la atención de la parte inferior del pecho."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('14e5d199-c0de-4e80-babe-14e5d1990000', 'Ejercicio unilateral con pesa rusa / kettlebell', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/03/One-Arm-Kettlebell-Snatch-exercise.gif', '{"Párate con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas y la pesa rusa colocada en el suelo entre tus pies. Tus caderas deben estar ligeramente inclinadas hacia atrás y tu espalda debe estar recta.","Posición inicial: Párate con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas y la pesa rusa colocada en el suelo entre tus pies. Tus caderas deben estar ligeramente inclinadas hacia atrás y tu espalda debe estar recta.","Agarre la pesa rusa: baje con una mano y agarre firmemente el mango de la pesa rusa. Tu palma debe estar mirando hacia tu cuerpo.","Rotación: cuando la pesa rusa alcance la altura de los hombros, gire la mano para que la palma quede hacia arriba.","Inicie el movimiento: con un movimiento fluido, conduzca a través de sus caderas y piernas para generar energía. Mientras haces esto, simultáneamente levanta la pesa rusa de manera explosiva, usando el impulso para levantarla hacia tu hombro.","Bloqueo: una vez que la pesa rusa alcance la altura de los hombros, bloquee el brazo por encima de la cabeza extendiendo completamente el codo.","Baje la pesa rusa: invierta el movimiento bajando la pesa rusa a la posición inicial con control. Mantenga su núcleo comprometido y su espalda recta durante todo el movimiento.","Repetir: realice el número deseado de repeticiones en un brazo antes de cambiar al otro brazo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('24f9d17c-c0de-4e80-babe-24f9d17c0000', 'Remo unilateral', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/One-Arm-Landmine-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3e250471-c0de-4e80-babe-3e2504710000', 'Dominadas unilateral', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Weighted-One-Arm-Pull-up.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2fdf43ba-c0de-4e80-babe-2fdf43ba0000', 'Jalón al pecho en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Cable-Crossover-Lat-Pulldown.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('68b6c9e5-c0de-4e80-babe-68b6c9e50000', 'Plancha', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Front-Plank-With-Arm-And-Leg-Lift.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('036e8c5e-c0de-4e80-babe-036e8c5e0000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Inchworm.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('17e66f36-c0de-4e80-babe-17e66f360000', 'Fondos', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Korean-Dips.gif', '{"- Agarre las barras con un agarre neutral (las palmas hacia adentro).","- Siente el estiramiento en tu pecho y hombros en la posición inferior.","- Busque una estación de barras paralelas o barras para fondos de un ancho cómodo (un poco más ancho que el ancho de los hombros).","- Levanta las piernas detrás del cuerpo, manteniéndolas rectas (en lugar de dobladas hacia adelante como en los fondos tradicionales).","- Fase de descenso (excéntrica) Baje lentamente el cuerpo hacia abajo, permitiendo que los hombros se desplacen ligeramente detrás de las barras. Mantenga los codos pegados al torso para evitar una tensión excesiva. Baje hasta que los hombros estén al mismo nivel o ligeramente por debajo de los codos. Sienta el estiramiento en el pecho y los hombros en la posición inferior.","- Baje lentamente su cuerpo hacia abajo, permitiendo que sus hombros se desplacen ligeramente detrás de las barras.","- Baje hasta que sus hombros estén al nivel de los codos o ligeramente por debajo.","- Fase de prensado (concéntrica) Empújate hacia arriba de manera explosiva, activando tus pectorales, tríceps y hombros. Mantén un movimiento controlado, evitando el balanceo o el impulso. Extiende completamente los brazos en la parte superior mientras mantienes la tensión en los músculos.","- Extienda completamente los brazos en la parte superior mientras mantiene la tensión en los músculos.","- Empújate hacia arriba de manera explosiva, activando tus pectorales, tríceps y hombros.","- Mantenga su núcleo comprometido y su cuerpo ligeramente inclinado hacia adelante.","- Mantenga los codos pegados al torso para evitar una tensión excesiva.","- Mantenga un movimiento controlado, evitando balanceos o impulsos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('426ea4a9-c0de-4e80-babe-426ea4a90000', 'Extensión de tríceps con banda de resistencia', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Resistance-Band-Reverse-Hyperextension.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('286dd5c7-c0de-4e80-babe-286dd5c70000', 'Ejercicio con banda de resistencia', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Resistance-Band-Toe-Touch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7f093517-c0de-4e80-babe-7f0935170000', 'Giro ruso acostado', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/weighted-lying-twist.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('44852e94-c0de-4e80-babe-44852e940000', 'Press de hombros sentado con banda de resistencia', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Resistance-Band-Seated-Shoulder-Press.gif', '{"El press de hombros sentado con bandas de resistencia es una alternativa al press de hombros con mancuernas. Dado que las bandas no crean impulso, sus repeticiones con bandas no desgastarán la columna ni las articulaciones. Aunque este ejercicio se centra en los músculos delanteros de los hombros, es un movimiento útil que a menudo se utiliza para fortalecer la parte superior del cuerpo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1ae8f281-c0de-4e80-babe-1ae8f2810000', 'Fondos', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Straight-Bar-Dip.gif', '{"- Agarre la barra Agarre la barra con un agarre por encima de la cabeza, un poco más ancho que el ancho de los hombros.","- Agarre la barra con un agarre por encima de la cabeza, un poco más ancho que el ancho de los hombros.","- Push Back UpExtiende los brazos para volver a la posición inicial, manteniendo el core tenso para mantener el equilibrio.","- Extiende los brazos para volver a la posición inicial, manteniendo el core tenso para mantener el equilibrio.","- Ancho de agarre: ajuste el ancho de su agarre para encontrar una posición cómoda que minimice la tensión en la muñeca.","- Encuentre una barra resistente Utilice una barra de dominadas o cualquier barra horizontal a la altura del pecho.","- Utilice una barra de dominadas o cualquier barra horizontal a la altura del pecho.","- Levántate Salta o empuja hacia arriba para que tus brazos estén completamente extendidos y tu cuerpo esté por encima de la barra.","- Salta o empuja hacia arriba para que tus brazos estén completamente extendidos y tu cuerpo esté por encima de la barra.","- Baje su cuerpo Inclínese ligeramente hacia adelante, doblando los codos para bajar el pecho hacia la barra. Mantenga los codos cerca de los costados para apuntar a los tríceps y el pecho.","- Inclínese ligeramente hacia adelante, doblando los codos para bajar el pecho hacia la barra.","- Rango completo de movimiento: bájese hasta que sus hombros estén debajo de sus codos para una activación máxima.","- Balancear el cuerpo: utilice movimientos controlados para evitar perder el equilibrio o reducir la activación muscular.","- Deténgase en BottomLower hasta que sus hombros estén debajo de sus codos o hasta donde su movilidad lo permita sin molestias.","- Baja hasta que tus hombros queden por debajo de tus codos o hasta donde tu movilidad te lo permita sin molestias.","- Repetir Realice de 8 a 12 repeticiones durante 2 a 3 series, según su nivel de fuerza.","- Realice de 8 a 12 repeticiones durante 2 a 3 series, según su nivel de fuerza.","- Inclínese ligeramente hacia adelante: esto involucra el cofre de manera más efectiva.","### Errores comunes","- Mantenga los codos cerca de los costados para apuntar a los tríceps y el pecho.","### Consejos para una forma adecuada","- Involucre su núcleo: apriete los músculos centrales para mantener la estabilidad y evitar el balanceo.","- Movimientos controlados: evite utilizar el impulso; Concéntrese en repeticiones lentas y deliberadas.","- Codos ensanchados: Dejar que los codos se ensanchen puede tensar los hombros y reducir el compromiso de los tríceps.","- Profundidad insuficiente: No bajar lo suficiente reduce la efectividad del ejercicio.","- Posición del cuello: Mantenga el cuello en posición neutra; no lo estire hacia adelante ni lo deje caer excesivamente.","- Uso excesivo del impulso: evite rebotar en la parte inferior del movimiento."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('011c9fe3-c0de-4e80-babe-011c9fe30000', 'Curl de bíceps con barra', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Barbell-Curl-On-Arm-Blaster.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('27bc5657-c0de-4e80-babe-27bc56570000', 'Curl martillo', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Arm-Blaster-Hammer-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6ccf03be-c0de-4e80-babe-6ccf03be0000', 'Curl de bíceps con mancuernas', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Dumbbell-Curl-On-Arm-Blaster.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('164b5d91-c0de-4e80-babe-164b5d910000', 'Estiramiento de rodillas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Kneeling-Hip-Flexor-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('50814605-c0de-4e80-babe-508146050000', 'Estiramiento de pie', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Standing-one-arm-chest-stretch.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7fd01c3b-c0de-4e80-babe-7fd01c3b0000', 'Estiramiento de pie', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Standing-Quadriceps-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('28be43ff-c0de-4e80-babe-28be43ff0000', 'Ejercicio sobre pelota de estabilidad', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/swiss-ball-rollout.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3f28bf10-c0de-4e80-babe-3f28bf100000', 'Ejercicio sobre pelota de estabilidad', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Weighted-Side-Bend-on-stability-ball.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('52e60d72-c0de-4e80-babe-52e60d720000', 'Ejercicio con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Dumbbell-Pullover-On-Stability-Ball.gif', '{"- Siéntese sobre una pelota de estabilidad y camine lentamente con los pies hacia adelante hasta que la parte superior de la espalda y los hombros estén apoyados, con las caderas levantadas en posición de puente.","- Involucre los músculos del pecho y la espalda para llevar la mancuerna a la posición inicial.","- Usar demasiado peso: esto puede comprometer la forma y provocar lesiones.","- Seleccione una mancuerna de peso moderado que permita un movimiento controlado.","- Sostenga la mancuerna con ambas manos, colocándola directamente sobre su pecho con los brazos extendidos.","- Mantenga una ligera flexión de los codos mientras baja lentamente la mancuerna detrás de la cabeza con un movimiento controlado.","- Baje el peso hasta que sus brazos estén alineados con sus orejas o sienta un estiramiento cómodo en su pecho y dorsales.","- Realice un rango completo de movimiento, pero evite bajar demasiado la mancuerna para evitar tensiones innecesarias en los hombros.","- Acelerar el movimiento: Un ritmo lento y controlado asegura una adecuada activación muscular.","- Mantenga las caderas levantadas en posición de puente para mantener la activación del núcleo.","- Evite doblar excesivamente los codos para asegurarse de que el movimiento siga siendo un jersey y no una extensión de tríceps.","- Controla el peso durante todo el movimiento para evitar que el impulso se apodere de ti.","### Errores comunes a evitar","- Repita de 10 a 15 repeticiones, manteniendo el control y la respiración adecuados en todo momento.","### Consejos para una forma adecuada","- Mantenga una columna neutral y active su núcleo para lograr estabilidad.","- Dejar caer las caderas: esto reduce el compromiso y la estabilidad del núcleo.","- Extender demasiado los hombros: ir demasiado hacia atrás puede generar una tensión innecesaria en las articulaciones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4a1f5967-c0de-4e80-babe-4a1f59670000', 'Sentadilla sobre pelota de estabilidad', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Exercise-Ball-Wall-Squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('70cb8a54-c0de-4e80-babe-70cb8a540000', 'Flexiones de pecho declinado sobre pelota de estabilidad', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/stability-ball-decline-push-ups.gif', '{"- Elija la pelota de estabilidad adecuada Utilice una pelota de estabilidad correctamente inflada que soporte su peso sin tambalearse excesivamente.","- Utilice una pelota de estabilidad adecuadamente inflada que soporte su peso sin tambalearse excesivamente.","- Ponte en posición: Coloca el balón detrás de ti y arrodíllate en el suelo. Coloque las manos separadas al ancho de los hombros en el suelo en una posición de flexión.","- Coloca la pelota detrás de ti y arrodíllate en el suelo. Coloque las manos separadas al ancho de los hombros en el suelo en una posición de flexión.","- Eleve sus pies Coloque sus pies o espinillas sobre la pelota de estabilidad. Ajuste su posición para que su cuerpo forme una línea recta desde la cabeza hasta los talones.","- Coloque los pies o las espinillas sobre la pelota de estabilidad. Ajuste su posición para que su cuerpo forme una línea recta desde la cabeza hasta los talones.","- Mantén la posición brevemente en el punto más bajo sin que tu pecho toque el suelo.","- Empuje hacia arribaPresione con las palmas de las manos para regresar a la posición inicial mientras mantiene el control sobre la pelota de estabilidad.","- Presione con las palmas para volver a la posición inicial mientras mantiene el control sobre la pelota de estabilidad.","- Ajuste la ubicación de la pelota: coloque la pelota más cerca de sus pies para mayor dificultad o cerca de sus rodillas para mayor estabilidad.","- RepetirRealiza el número deseado de repeticiones con movimientos lentos y controlados.","- Realiza el número deseado de repeticiones con movimientos lentos y controlados.","- Baje el pecho Doble los codos para bajar el pecho hacia el suelo, manteniendo el núcleo comprometido y el cuerpo alineado.","- Doble los codos para bajar el pecho hacia el suelo, manteniendo el núcleo comprometido y el cuerpo alineado.","- Acelerar el movimiento: Muévase lentamente para mantener el equilibrio y el control.","- Deslizamiento de la pelota: utilice una superficie antideslizante o realice el ejercicio cerca de una pared para mayor seguridad.","### Errores comunes","- Haga una pausa en la parte inferior. Mantenga brevemente en el punto más bajo sin dejar que su pecho toque el suelo.","### Consejos para una forma adecuada","- Involucre su núcleo: mantenga sus abdominales contraídos para mantener la estabilidad y evitar la flacidez de las caderas.","- Movimientos lentos: evite apresurarse; céntrese en repeticiones fluidas y deliberadas para maximizar la efectividad.","- Columna Neutral: Mantenga la cabeza alineada con la columna durante todo el ejercicio.","- Colocación inadecuada de las manos: asegúrese de que sus manos estén directamente debajo de sus hombros para brindar apoyo.","- Caderas caídas: Involucre sus glúteos y su núcleo para mantener su cuerpo recto."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('720de171-c0de-4e80-babe-720de1710000', 'Ejercicio sobre pelota de estabilidad', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/V-Up-Down-with-Stability-ball.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0d30833b-c0de-4e80-babe-0d30833b0000', 'Flexiones de pecho sobre pelota de estabilidad', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/stability-ball-push-up.gif', '{"- Coloque una pelota de estabilidad en el suelo frente a usted.","- Colóquese en una posición de tabla alta, colocando ambas manos sobre la pelota separadas aproximadamente al ancho de los hombros.","- Vuelve a subir a la posición inicial, extendiendo completamente los brazos.","- Extiende las piernas detrás de ti, manteniendo el cuerpo en línea recta desde la cabeza hasta los talones. Involucre su núcleo para mantener la estabilidad.","- Haga una pausa por un momento cuando su pecho esté justo encima de la pelota.","- Realice de 8 a 15 repeticiones durante 3 a 4 series.","- Baje lentamente el pecho hacia la pelota doblando los codos, manteniéndolos en un ángulo de 45 grados con respecto al cuerpo.","- Controla el movimiento para maximizar la activación muscular y evitar que la pelota ruede.","- Respire adecuadamente: inhale mientras desciende y exhale mientras vuelve a subir.","- Dejar que las caderas se doblen: esto reduce el compromiso del core y puede tensar la zona lumbar.","- Acelerar el movimiento: esto reduce la efectividad y aumenta la inestabilidad.","### Errores comunes a evitar","- Usar una pelota demasiado pequeña o demasiado inflada puede dificultar demasiado el equilibrio y aumentar el riesgo de lesiones.","### Consejos para una forma adecuada","- Mantenga su núcleo comprometido para evitar que la zona lumbar se hunda.","- Mantenga una columna neutra y evite arquearse excesivamente.","- Mantenga los codos ligeramente doblados en lugar de ensancharlos para proteger sus hombros.","- Colocar las manos demasiado juntas limita el equilibrio y aumenta la tensión en las muñecas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5589bc28-c0de-4e80-babe-5589bc280000', 'Press de pecho unilateral', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Lever-One-Arm-Chest-Press.gif', '{"Ajuste la máquina Configure la altura del asiento de modo que el mango se alinee con la mitad del pecho.","Ajuste la altura del asiento de modo que el mango se alinee con la mitad del pecho.","Elige el PesoSelecciona un peso que te permita realizar el ejercicio con la forma adecuada.","Posiciónese Siéntese erguido con la espalda apoyada en la almohadilla y los pies apoyados en el suelo.","Agarre el mango Agarre la palanca con una mano mientras el otro brazo descansa sobre su muslo o costado."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('15881d14-c0de-4e80-babe-15881d140000', 'Flexiones de pecho con balón medicinal', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Push-Up-Medicine-Ball.gif', '{"Elija un balón medicinal estable Utilice un balón medicinal que proporcione un agarre firme y que no ruede excesivamente.","Ponte en posición Coloque el balón medicinal en el suelo y adopte una posición de tabla alta con una mano sobre el balón y la otra en el suelo.","Alineación del cuerpo Mantenga el cuerpo recto desde la cabeza hasta los talones, involucrando el núcleo y los glúteos para lograr estabilidad."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('664938be-c0de-4e80-babe-664938be0000', 'Ejercicio sobre pelota de estabilidad', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Exercise-Ball-Frog-Crunch.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('23ce6187-c0de-4e80-babe-23ce61870000', 'Ejercicio con pesa rusa / kettlebell', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Kettlebell-Clean-and-Jerk.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('73065a8e-c0de-4e80-babe-73065a8e0000', 'Curl de piernas sobre pelota de estabilidad', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/leg-curl-on-stability-ball.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7faacc67-c0de-4e80-babe-7faacc670000', 'Press de pecho de rodillas con pesa rusa / kettlebell', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Half-Kneeling-One-Arm-Kettlebell-Press.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('33ce1e28-c0de-4e80-babe-33ce1e280000', 'Sentadilla con pesa rusa / kettlebell', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/kettlebell-goblet-squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1509ed67-c0de-4e80-babe-1509ed670000', 'Remo', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Lever-Reverse-T-Bar-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5bbfaaba-c0de-4e80-babe-5bbfaaba0000', 'Remo inclinado con pesa rusa / kettlebell', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Kettlebell-Bent-Over-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5232df6b-c0de-4e80-babe-5232df6b0000', 'Peso muerto con pesa rusa / kettlebell', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/kettlebell-deadlift.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('278f1c3d-c0de-4e80-babe-278f1c3d0000', 'Extensión de tríceps sobre pelota de estabilidad', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Exercise-Ball-Supine-Triceps-Extension.gif', '{"- Seleccione un par de mancuernas con un peso manejable.","- Siéntese sobre una pelota de ejercicios y camine con los pies hacia adelante hasta que la parte superior de la espalda y los hombros estén apoyados en la pelota.","- Involucra tus tríceps y extiende tus brazos hacia la posición inicial.","### Paso 1: configuración y posicionamiento","- Sostenga una mancuerna en cada mano y extienda los brazos hacia arriba del pecho.","### Paso 2: Ejecución","- Baje las mancuernas doblando los codos, manteniéndolos cerca de la cabeza.","- Baje las pesas detrás de su cabeza con un movimiento controlado.","- Involucre su núcleo y glúteos para mantener la estabilidad.","- Repita para las repeticiones deseadas, manteniendo el núcleo contraído para mantener el equilibrio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('01dfa91d-c0de-4e80-babe-01dfa91d0000', 'Press de pecho declinado con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Dumbbell-Decline-One-Arm-Hammer-Press.gif', '{"- Ajuste un banco inclinado a aproximadamente 15 a 30 grados.","- Asegure sus pies debajo de las almohadillas del banco para mantener la estabilidad.","- Sostenga una mancuerna en una mano con un agarre neutral (las palmas hacia adentro).","- Coloque la mancuerna al nivel de los hombros con el codo doblado a 90 grados.","- Baje lentamente la mancuerna hasta la posición inicial, asegurando un control total.","- Comience con un peso moderado: concéntrese en la técnica antes de aumentar la resistencia.","- Usar peso excesivo: puede comprometer la forma y provocar lesiones.","- Mantenga su núcleo apretado y la espalda baja apoyada contra el banco.","- Presione la mancuerna hacia arriba en línea recta hasta que su brazo esté completamente extendido.","- Realice repeticiones iguales en ambos lados para mantener el equilibrio muscular.","- Utilice un rango completo de movimiento: extienda y baje completamente la mancuerna para lograr un compromiso óptimo del pecho.","- Permitir que la mancuerna se desplace hacia afuera: reduce el compromiso del pecho y aumenta la tensión en los hombros.","- Mantenga el núcleo comprometido: ayuda a prevenir la rotación y estabiliza el movimiento.","### Errores comunes a evitar","- No involucrar el núcleo: puede causar inestabilidad y reducir la efectividad del ejercicio.","- Evite la rotación excesiva y mantenga la mano que no trabaja apoyada en el torso o en el banco como apoyo.","- Mantenga un ritmo constante para mantener la tensión en la parte inferior del pecho y los tríceps.","- Complete las repeticiones deseadas en un brazo antes de cambiar al otro.","### Consejos para una forma adecuada","- Mantenga un ritmo controlado: evite apresurarse en las repeticiones para maximizar la activación muscular.","- Evite arquear la espalda: mantenga la columna neutra para evitar tensiones innecesarias.","- Presionar demasiado rápido: limita la participación de los músculos y aumenta el riesgo de lesiones.","- Saltarse los calentamientos: no preparar los hombros y los tríceps puede provocar molestias."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('63a66f9a-c0de-4e80-babe-63a66f9a0000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Bench-Pike-Push-up.gif', '{"- Coloque un banco, una caja o una plataforma resistente frente a usted.","- Coloque los pies en el banco con las manos en el suelo, ligeramente más separadas que el ancho de los hombros.","- Mire ligeramente hacia adelante para mantener una posición neutral del cuello.","- Empuja con las palmas de las manos para estirar los brazos y volver a la posición inicial.","- Coloque sus manos correctamente: las manos deben estar ligeramente más anchas que el ancho de los hombros.","- Doble el cuerpo según la altura de la mesa de café y mantenga las caderas erguidas.","- Apunte a un ángulo de 90 grados en los codos a medida que su cabeza se acerque al suelo.","- Mantenga los hombros comprometidos y controle el movimiento en todo momento.","- Doble los codos y baje la cabeza hacia el suelo con un movimiento controlado.","- Muévase lentamente y con control: no apresure el movimiento para evitar lesiones.","- Respire adecuadamente: inhale mientras baja, exhale mientras presiona hacia arriba.","- Acelerar el movimiento: puede provocar una mala forma y una disminución del compromiso muscular.","### Errores comunes a evitar","- Dejar caer las caderas: reduce la activación del hombro y lo convierte en una flexión regular.","- No bajar lo suficientemente profundo: limita la efectividad; Apunte a una flexión del codo de 90 grados.","- Mantenga su núcleo comprometido y evite arquear la espalda baja.","- Repita hasta el número deseado de repeticiones.","- Principiantes: tres series de cinco a ocho repeticiones.","- Intermedio: tres o cuatro series de ocho a doce repeticiones.","- Avanzado: cuatro series de quince repeticiones o más","### Consejos para una forma adecuada","- Mantenga las caderas elevadas: mantenga las caderas elevadas y la parte superior del cuerpo en línea recta para apuntar eficazmente a los hombros durante el ejercicio.","- Involucre su núcleo: mantenga los abdominales contraídos para estabilizar el cuerpo.","- Colocar las manos demasiado abiertas: puede reducir el compromiso de los hombros y causar tensión.","- Arquear la parte baja de la espalda: indica un compromiso deficiente del núcleo y puede provocar lesiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('64a57b6d-c0de-4e80-babe-64a57b6d0000', 'Ejercicio de pie', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Standing-Toe-Touches.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('69c4fa06-c0de-4e80-babe-69c4fa060000', 'Ejercicio acostado con banda de resistencia', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Band-Lying-Hip-External-Rotation.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('288cd6f4-c0de-4e80-babe-288cd6f40000', 'Ejercicio de pie', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Standing-Side-Toe-Touching.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4768ddc9-c0de-4e80-babe-4768ddc90000', 'Jalón al pecho', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Full-Range-Of-Motion-Lat-Pulldown.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('32489a0b-c0de-4e80-babe-32489a0b0000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Ski-Step.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('56ff47ab-c0de-4e80-babe-56ff47ab0000', 'Ejercicio con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Dumbbell-Split-Jump.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('20bd7222-c0de-4e80-babe-20bd72220000', 'Sentadilla con barra', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Barbell-Bench-Front-Squat.gif', '{"Coloque un banco detrás de usted y cargue una barra en una posición frontal sobre sus hombros.","Párese erguido con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera.","Comienza el descenso empujando la cadera hacia atrás y flexionando las rodillas, bajando hasta que los glúteos toquen ligeramente el banco.","Conduce con los talones para volver a la posición de pie mientras mantienes el torso erguido.","Haga una breve pausa en el contacto sin sentarse del todo, manteniendo la tensión en las piernas.","Apoye su núcleo, mantenga el pecho erguido y retraiga los omóplatos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('253bc3ab-c0de-4e80-babe-253bc3ab0000', 'Zancadas con barra', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Barbell-Curtsey-Lunge.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('667e0e66-c0de-4e80-babe-667e0e660000', 'Ejercicio con banda de resistencia', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Banded-Step-up.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('692da982-c0de-4e80-babe-692da9820000', 'Press de hombros', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Lever-Shoulder-Press-Hammer-Grip.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('424eea14-c0de-4e80-babe-424eea140000', 'Sentadilla con barra', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Barbell-Split-Squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('138896e7-c0de-4e80-babe-138896e70000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Weighted-Push-up.gif', '{"- Configuración: Comience en una posición de flexión tradicional con las manos ligeramente más separadas que el ancho de los hombros y los pies juntos o separados al ancho de las caderas.","- Press Up: Empuje con las palmas de las manos para extender los brazos y volver a la posición inicial.","- Mala distribución del peso: colocar el peso demasiado alto o demasiado bajo en la espalda puede provocar un desequilibrio.","- Usar demasiado peso: comience con una resistencia ligera y progrese gradualmente para evitar lesiones.","### Guía paso a paso","- Agregue peso: Pídale a un compañero que coloque una placa de peso en la parte superior de su espalda o use un chaleco con peso para una distribución uniforme. Asegúrese de que el peso sea estable y no se mueva durante el movimiento.","- Repetir: realice el número deseado de repeticiones manteniendo la forma adecuada.","- Involucre su núcleo y glúteos para una mejor estabilidad.","- Fase de descenso: baje lentamente el pecho hacia el suelo doblando los codos hasta que alcancen un ángulo de 90 grados.","- Rango de movimiento limitado: no bajar correctamente puede dificultar la participación de los músculos.","- Controla el movimiento en lugar de apresurarte en las repeticiones.","- Asegúrese de que el peso esté colocado de forma segura sobre su espalda para evitar el desequilibrio.","- Utilice un observador o un chaleco con peso si entrena solo.","- Engage Core: apriete el core, apriete los glúteos y mantenga el cuerpo recto desde la cabeza hasta los talones.","### Consejos para una forma adecuada","- Mantenga la columna neutra y evite arquear o hundir la zona lumbar.","- Apresurarse en las repeticiones: moverse demasiado rápido reduce la activación y eficacia de los músculos.","### Errores comunes a evitar","- Caderas caídas: un compromiso central débil puede provocar una mala postura y un mayor riesgo de lesiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('607413f4-c0de-4e80-babe-607413f40000', 'Giro ruso sentado en polea', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Cable-Seated-Cross-Arm-Twist.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7f3010b5-c0de-4e80-babe-7f3010b50000', 'Estiramiento', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/All-Fours-Squad-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('08fc8b1e-c0de-4e80-babe-08fc8b1e0000', 'Estiramiento', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2023/03/Wrist-Ulnar-Deviator-And-Extensor-Stretch.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('53277b09-c0de-4e80-babe-53277b090000', 'Ejercicio con barra', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/Barbell-Glute-Bridge-Two-Legs-on-Bench.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5d1925c9-c0de-4e80-babe-5d1925c90000', 'Estiramiento', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2023/03/reverse-Wrist-Stretch.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2792de1f-c0de-4e80-babe-2792de1f0000', 'Ejercicio con mancuernas', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Dumbbell-Burpees.gif', '{"Sostenga una mancuerna en cada mano, de pie con los pies separados al ancho de los hombros.","Sostenga una mancuerna en cada mano, de pie con los pies separados a la altura de los hombros.","Póngase en cuclillas y coloque mancuernas: bájese hasta ponerse en cuclillas mientras sostiene las mancuernas a los costados.","Posición de plancha: Coloque las mancuernas en el suelo frente a usted y salte o retroceda los pies hasta la posición de plancha, manteniendo el cuerpo en línea recta.","Coloque las mancuernas en el suelo frente a usted y salte o retroceda los pies hasta la posición de tabla, manteniendo el cuerpo en línea recta.","Saltar o dar un paso adelante: salte o dé un paso con los pies hacia las manos y regrese a la posición en cuclillas.","Salta o retrocede con los pies hacia las manos y vuelve a la posición en cuclillas.","Ponte de pie y presiona: levántate explosivamente desde la posición en cuclillas y presiona las mancuernas sobre tu cabeza.","Levántese explosivamente desde la posición en cuclillas y presione las mancuernas sobre su cabeza.","Repetir: Regrese a la posición inicial y repita la secuencia durante el número deseado de repeticiones.","Posición inicial: Sostenga una mancuerna en cada mano, de pie con los pies separados al ancho de los hombros.","Flexiones (opcional): Realice una flexión manteniendo la espalda recta. Este paso es opcional pero puede incluirse para un desafío adicional.","Baje a una posición en cuclillas mientras sostiene las mancuernas a los costados."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('64e057bf-c0de-4e80-babe-64e057bf0000', 'Curl de bíceps', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Lever-Biceps-Curl.gif', '{"Sujete el peso (mancuerna, barra o polea) con un agarre supino (palmas hacia arriba).","Mantenga los pies separados al ancho de los hombros y las rodillas ligeramente flexionadas.","Coloque los codos pegados a los costados del torso y mantenga la espalda recta.","Manteniendo inmóvil la parte superior de los brazos, flexione los codos y eleve la carga hacia los hombros.","Apriete fuertemente los bíceps en el punto de máxima contracción por un segundo.","Baje el peso de forma controlada y lenta hasta extender completamente los brazos.","Evite balancear la espalda o mover los hombros hacia adelante para ayudarse.","Mantenga las muñecas firmes y rectas durante todo el recorrido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1d7e8e2d-c0de-4e80-babe-1d7e8e2d0000', 'Sentadilla con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Dumbbell-Jump-Squat.gif', '{"Párese erguido con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano a los costados.","Apoye su núcleo y bájese hasta ponerse en cuclillas, manteniendo el pecho hacia arriba y la espalda en posición neutral.","Explota hacia arriba, saltando del suelo lo más alto que puedas mientras sostienes las mancuernas.","Aterriza suavemente sobre las puntas de tus pies, e inmediatamente vuelve a ponerte en cuclillas para la siguiente repetición.","Repita las repeticiones, manteniendo el control tanto durante el despegue como durante el aterrizaje."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3140200f-c0de-4e80-babe-3140200f0000', 'Press de hombros', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Lever-Reverse-Shoulder-Press.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4353f081-c0de-4e80-babe-4353f0810000', 'Elevaciones laterales acostado con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/03/Dumbbell-Lying-Rear-Lateral-Raise.gif', '{"La elevación lateral trasera acostada con mancuernas es un ejercicio que se utiliza para fortalecer los músculos posteriores y laterales del hombro y los grupos de músculos más pequeños adjuntos a ellos. Levantar demasiado peso en este movimiento puede no ser saludable, hacer el ejercicio con pesas livianas y con muchas repeticiones puede ser más beneficioso para los músculos deltoides y del manguito rotador."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('110401fc-c0de-4e80-babe-110401fc0000', 'Giro ruso de pie en máquina', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Standing-Twist-Machine.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('03202615-c0de-4e80-babe-032026150000', 'Elevaciones laterales acostado con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Side-Lying-Rear-Delt-Dumbbell-Raise.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('57b20b97-c0de-4e80-babe-57b20b970000', 'Curl de piernas de rodillas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Lever-Kneeling-Leg-Curl-.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('791f56fd-c0de-4e80-babe-791f56fd0000', 'Fondos', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Scapula-Dips.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('29f29481-c0de-4e80-babe-29f294810000', 'Elevaciones frontales inclinado con barra EZ', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Incline-Front-Raise.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('54447402-c0de-4e80-babe-544474020000', 'Ejercicio sentado en máquina', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Seated-Crunch-Machine.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('73c67147-c0de-4e80-babe-73c671470000', 'Dominadas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2023/06/L-Pull-Up.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('526ed7a0-c0de-4e80-babe-526ed7a00000', 'Ejercicio sentado', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Seated-Toe-Touches.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7f9bc6b3-c0de-4e80-babe-7f9bc6b30000', 'Dominada supina', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/03/Chin-Up.gif', '{"La dominada es un ejercicio de cadena cerrada que trabaja casi todos los grupos de músculos de la parte superior del cuerpo y proporciona tanto hipertrofia como fuerza con el peso corporal. El ejercicio de dominadas se centra en los músculos de la espalda y los bíceps. Es uno de los ejercicios más eficaces para desarrollar y fortalecer los músculos de la espalda y las alas.","Desempeña un papel importante en el aumento de la potencia y la fuerza del cuerpo: dado que las dominadas son un ejercicio compuesto, trabaja los músculos de la parte superior del cuerpo en perfecta armonía. El ejercicio de dominadas realizado con el peso corporal favorece la fuerza general del cuerpo y la fuerza central. Proporciona un cuerpo más fuerte y sólido.","Aumenta la fuerza de agarre: Cuando sostienes un objeto en tu vida diaria, te permite agarrarlo con más firmeza. Por ejemplo; Puedes sentir esto incluso al abrir un frasco.","Las dominadas fortalecen tus brazos: si no puedes hacer el ejercicio de dominadas, esto probablemente sea una indicación de que tus brazos están débiles. Brazos y muñecas trabajan activamente en todo tipo de dominadas. La fuerza de los brazos aumenta más cada vez que levantas el peso corporal. Aumentar el número de dominadas significa el desarrollo y fortalecimiento de tus brazos.","Proporciona beneficios cardiovasculares: las dominadas aumentan el ritmo cardíaco. Cuando este tipo de ejercicio se realiza rápidamente y sin períodos de descanso entre ellos, proporciona un excelente entrenamiento cardiovascular además de la capacidad de desarrollar fuerza.","Cuando se trata de ejercicios compuestos, uno de los mejores ejercicios que me viene a la mente es probablemente el movimiento de dominadas. La principal diferencia entre dominadas y dominadas es cómo se agarra la barra. En este ejercicio, las palmas miran hacia el cuerpo. Las dominadas pueden ser un movimiento más fácil para los principiantes que las dominadas.","Desarrolla los músculos de las alas: Es eficaz para trabajar y moldear las partes del cuerpo, que se encuentran en las partes superiores derecha e izquierda y que se denominan músculos de las alas. Si quieres un cuerpo cónico en V, puedes hacerlo con un movimiento de dominadas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('742df0ec-c0de-4e80-babe-742df0ec0000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2023/06/Swing-360.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('307108f5-c0de-4e80-babe-307108f50000', 'Elevaciones frontales con barra', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Barbell-Front-Raise-Twist.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7a87de0d-c0de-4e80-babe-7a87de0d0000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Duck-Walk.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2f3700cd-c0de-4e80-babe-2f3700cd0000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Zercher-Squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('44cb83b7-c0de-4e80-babe-44cb83b70000', 'Press de hombros con pesa rusa / kettlebell', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/11/Kettlebell-Shoulder-Press.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0e449862-c0de-4e80-babe-0e4498620000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/burpees.gif', '{"Quema de calorías: debido a su naturaleza de alta intensidad, los burpees pueden ayudar a quemar una cantidad significativa de calorías en un corto período de tiempo. Esto los hace beneficiosos para quienes buscan perder peso o mantener un peso saludable.","Desarrollo de fuerza: los burpees requieren que te muevas de una posición de tabla a una sentadilla y luego saltes, incorporando fuerza tanto en la parte superior como en la inferior del cuerpo. Esto ayuda a desarrollar fuerza y ​​resistencia muscular con el tiempo.","No se requiere equipo: Los burpees se pueden realizar solo con el peso del cuerpo, lo que los convierte en un ejercicio conveniente y accesible que se puede realizar en cualquier lugar sin necesidad de equipo.","Aptitud cardiovascular: los burpees elevan el ritmo cardíaco rápidamente, proporcionando un entrenamiento cardiovascular eficaz. Esto ayuda a mejorar su salud cardiovascular, resistencia y resistencia.","Entrenamiento de cuerpo completo: los burpees involucran múltiples grupos de músculos, incluidos el pecho, los brazos, los hombros, el core, los glúteos y las piernas. Esta activación integral lo convierte en un ejercicio que ahorra tiempo para trabajar varios grupos de músculos simultáneamente.","Agilidad y coordinación mejoradas: Los movimientos dinámicos involucrados en los burpees mejoran la agilidad y la coordinación, a medida que pasas rápidamente por diferentes posiciones.","Fitness funcional: Los movimientos de los burpees imitan las actividades cotidianas, lo que los hace valiosos para desarrollar el fitness funcional. Esto puede mejorar su capacidad para realizar las tareas diarias con facilidad.","Eficiente en el tiempo: Los burpees son un ejercicio que ahorra tiempo y se pueden incluir en rutinas de entrenamiento en intervalos de alta intensidad (HIIT), proporcionando un entrenamiento efectivo en un período corto.","Impulso metabólico: la naturaleza intensa de los burpees puede elevar su metabolismo, lo que lleva a una mayor quema de calorías incluso después de haber terminado su entrenamiento. Esto se conoce como efecto afterburn o consumo excesivo de oxígeno post-ejercicio (EPOC).","Versatilidad: los burpees se pueden modificar para adaptarse a diferentes niveles de condición física. Los principiantes pueden comenzar con variaciones básicas y progresar gradualmente a versiones más desafiantes a medida que mejoren su fuerza y ​​resistencia."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1c4e7276-c0de-4e80-babe-1c4e72760000', 'Ejercicio con barra', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Barbell-Rollout.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('68a2f605-c0de-4e80-babe-68a2f6050000', 'Giro ruso', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Landmine-Twist.gif', '{"El giro de minas terrestres es un ejercicio de fortalecimiento del núcleo que trabaja los oblicuos y los abdominales que llegan hasta la zona lumbar. Los oblicuos son los músculos que conectan los dorsales y estos músculos ayudan a flexionar o rotar la parte superior del cuerpo. Dirigido a los músculos oblicuos, este ejercicio ayuda a aumentar la fuerza y ​​la estabilización de los músculos centrales."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2b6ac0e0-c0de-4e80-babe-2b6ac0e00000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/frog-crunch.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3a26e9ad-c0de-4e80-babe-3a26e9ad0000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/Single-Arm-Push-up.gif', '{"- Posiciónese Asuma una posición de flexión con los pies ligeramente más separados que el ancho de los hombros para mayor estabilidad.","- Asuma una posición de flexión con los pies ligeramente más separados que el ancho de los hombros para mayor estabilidad.","- Coloque una mano detrás de la espalda Coloque la mano de apoyo debajo del pecho, ligeramente desplazada hacia la línea media de su cuerpo.","- Coloque su mano de apoyo debajo de su pecho, ligeramente desplazada hacia la línea media de su cuerpo.","- Empuje hacia arribaPresione a través de su palma para regresar a la posición inicial.","- Presione con la palma de la mano para volver a la posición inicial.","- Involucre su núcleo para evitar la rotación del torso o la flacidez de las caderas.","- Repetir Realice el número deseado de repeticiones en un lado, luego cambie al otro brazo.","- Realice la cantidad deseada de repeticiones en un lado, luego cambie al otro brazo.","- Mantenga una línea recta del cuerpo: mantenga su cuerpo alineado desde la cabeza hasta los talones durante todo el movimiento.","- Elija una superficie estable Realice el ejercicio sobre una superficie plana y no resbaladiza para garantizar el equilibrio.","- Realice sobre una superficie plana y no resbaladiza para garantizar el equilibrio.","- Baje su cuerpo Doble el codo para bajar el pecho hacia el piso, manteniendo el cuerpo alineado. Involucre su núcleo para evitar la rotación del torso o la flacidez de las caderas.","- Doble el codo para bajar el pecho hacia el suelo, manteniendo el cuerpo alineado.","- Involucre su núcleo: apriete sus abdominales para evitar que sus caderas se doblen o se tuerzan.","- Movimientos controlados: Evite apresurarse; Concéntrese en movimientos suaves y deliberados.","- Comience con progresiones: domine variaciones más fáciles antes de intentar la flexión completa con un solo brazo.","### Errores comunes","- Descuidar el compromiso central: un núcleo débil puede conducir a una forma inadecuada y una eficacia reducida.","- Haga una pausa en la parte inferior. Mantenga brevemente en el punto más bajo para maximizar la activación muscular.","- Mantenga brevemente en el punto más bajo para maximizar la activación muscular.","### Consejos para una forma adecuada","- Postura amplia para mayor estabilidad: Mantenga los pies lo suficientemente anchos para proporcionar equilibrio.","- Rotar el torso: Evite que los hombros o las caderas se tuerzan; manténgase pegado al suelo.","- Arqueando la parte baja de la espalda: mantenga los glúteos comprometidos para evitar la hiperextensión.","- Acelerar el movimiento: tómate tu tiempo para mantener el control y centrarte en las repeticiones de calidad.","- Rango de movimiento desigual: asegúrese de que ambos brazos tengan la misma profundidad y esfuerzo para un desarrollo equilibrado."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('46b6ad46-c0de-4e80-babe-46b6ad460000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Reverse-Hack-Squat.gif', '{"Entre en la máquina de sentadillas de cara a las almohadillas y coloque los hombros debajo de los reposahombros.","Coloque los pies ligeramente hacia adelante y separados a la altura de las caderas sobre la plataforma para los pies.","Apoye su núcleo y agarre las manijas laterales.","Desenganche la máquina levantándose ligeramente y soltando el seguro.","Conduce sobre tus talones para volver a la posición superior. Repita para las repeticiones deseadas.","Baje el cuerpo doblando las rodillas y las caderas hasta que los muslos queden al menos paralelos a la plataforma para los pies."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2bac8fed-c0de-4e80-babe-2bac8fed0000', 'Ab rollout con rueda', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Ab-Wheel-Rollout.gif', '{"El ejercicio de despliegue de la rueda abdominal es un ejercicio eficaz ya que trabaja todos los músculos de la parte superior del cuerpo, especialmente los flexores de la cadera y los músculos centrales. En comparación con los ejercicios abdominales tradicionales como abdominales o abdominales, los ejercicios con rodillo abdominal son más desafiantes y efectivos.","El ejercicio de despliegue de Ab Wheel es un movimiento compuesto. Esto significa que activa varios grupos de músculos a la vez. El despliegue de la rueda abdominal puede brindarle un mejor entrenamiento abdominal que los ejercicios de flexión tradicionales, permitiéndole desarrollar abdominales más fuertes y definidos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('40b54ce5-c0de-4e80-babe-40b54ce50000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/09/High-Knees-against-wall.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('38fde23c-c0de-4e80-babe-38fde23c0000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Push-Up-Plus.gif', '{"- Posición inicial: Comience en una posición de tabla alta, con las manos separadas al ancho de los hombros y directamente debajo de los hombros. Mantenga el cuerpo en línea recta desde la cabeza hasta los talones, involucrando el núcleo y los glúteos.","- Comience en una posición de tabla alta, con las manos separadas al ancho de los hombros y directamente debajo de los hombros.","- Empujar hacia arriba: Empújese hacia atrás hasta la posición inicial de tabla.","- Empújate de nuevo hasta la posición inicial de tabla.","- Reiniciar: Regrese a la posición neutral de la tabla y repita.","- Regrese a la posición de tabla neutral y repita.","- Mantenga un movimiento controlado, manteniendo los codos en un ángulo de 45 grados con respecto al torso.","- Protracción escapular: una vez en la parte superior, extienda los brazos un poco más redondeando la parte superior de la espalda y alejando los omóplatos entre sí. Mantenga la posición durante un segundo para sentir el compromiso del serrato anterior.","- Una vez arriba, extiende los brazos un poco más redondeando la parte superior de la espalda y separando los omóplatos.","- Fase de descenso: baje lentamente el pecho hacia el suelo doblando los codos. Mantenga un movimiento controlado, manteniendo los codos en un ángulo de 45 grados con respecto al torso.","- Baje lentamente el pecho hacia el suelo doblando los codos.","- Movimiento controlado: concéntrese en un ritmo lento y controlado para maximizar la activación muscular.","- Respiración: exhale mientras empuja hacia arriba y extiende la escápula; Inhala mientras bajas.","- Mantenga la alineación: evite dejar que las caderas se hundan o se levanten durante el movimiento.","### Errores comunes","- Saltarse la prolongación: no agregar la protracción escapular anula el beneficio principal del ejercicio.","- Mantenga su cuerpo en línea recta desde la cabeza hasta los talones, involucrando su núcleo y glúteos.","- Mantenga presionado por un segundo para sentir el compromiso en su serrato anterior.","### Consejos para una forma adecuada","- Involucre su núcleo: mantenga su núcleo apretado para evitar un arqueo excesivo en la zona lumbar.","- Caderas caídas: Esto compromete la integridad de la tabla y aumenta el riesgo de tensión en la espalda baja.","- Ensanchamiento del codo: Permitir que los codos se ensanchen excesivamente puede estresar los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('138bdaa8-c0de-4e80-babe-138bdaa80000', 'Ejercicio con pesa rusa / kettlebell', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Kettlebell-Thruster.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2354f512-c0de-4e80-babe-2354f5120000', 'Sentadilla con barra', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/front-squat.gif', '{"Coloque la barra en una rejilla para sentadillas a la altura del pecho y colóquese debajo de ella con la barra apoyada sobre los hombros y la clavícula.","Cruza los brazos sobre la barra o utiliza un agarre limpio con los codos apuntando hacia adelante y el pecho a la altura.","Da un paso atrás y párate con los pies separados a la altura de los hombros y los dedos ligeramente hacia afuera.","Conduce con los talones para volver a la posición de pie mientras mantienes la tensión central y la postura.","Desciende hasta que tus muslos queden paralelos al suelo o ligeramente por debajo.","Apoye su núcleo y comience el movimiento doblando las caderas y las rodillas simultáneamente.","Baje hasta ponerse en cuclillas mientras mantiene los codos en alto y el torso erguido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2eee6ed3-c0de-4e80-babe-2eee6ed30000', 'Ejercicio unilateral con mancuerna', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/One-Arm-Dumbbell-Snatch.gif', '{"El arranque con mancuernas con un brazo es un ejercicio funcional diseñado para aumentar la fuerza en la parte superior e inferior del cuerpo. Este ejercicio ayuda a desarrollar tu coordinación y explosividad y fortalece tus hombros, espalda baja, isquiotibiales, glúteos y dorsales."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('42b0e553-c0de-4e80-babe-42b0e5530000', 'Prensa de piernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Single-Leg-Press.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5f54301e-c0de-4e80-babe-5f54301e0000', 'Zancadas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Landmine-Lunge.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1d2f13c8-c0de-4e80-babe-1d2f13c80000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2023/07/wall-supported-handstand-push-up.gif', '{"- Coloque las manos separadas a la altura de los hombros en el suelo, a una distancia de entre 6 y 12 pulgadas de la pared.","- Ponte en posición de parada de manos, manteniendo el núcleo contraído y las piernas rectas.","- Involucra tus hombros, tríceps y core para regresar a la posición inicial.","- Involucre sus glúteos y piernas: ayuda con el equilibrio en la posición de parada de manos.","- Activa el core con agarres en plancha y flexiones en pica.","- Apoye los talones ligeramente contra la pared para apoyarse.","- Baja hasta que tu cabeza toque ligeramente el suelo o una colchoneta.","- Mantén los brazos rectos y los hombros activos en la parte superior.","- Realice estiramientos de muñeca, hombros y tríceps para aumentar la movilidad.","- Doble los codos y baje la cabeza hacia el suelo con un movimiento controlado.","- Respire adecuadamente: inhale mientras baja, exhale mientras empuja hacia arriba.","- Depender demasiado de la pared: puede crear inestabilidad y dificultar el progreso hacia las flexiones de brazos independientes.","- Mantenga el control durante todo el movimiento para evitar el desequilibrio.","- Utilice movimientos controlados: evite apresurarse para mantener la fuerza y ​​el control.","### Errores comunes a evitar","- Arquear la zona lumbar: provoca una mala alineación y aumenta el riesgo de lesiones.","- Abrir demasiado los codos: ejerce una tensión innecesaria sobre los hombros.","- Mantenga los codos en un ángulo de 45 grados para proteger sus hombros.","### Consejos para una forma adecuada","- Mantenga un núcleo apretado: ayuda a estabilizar su cuerpo y previene el arqueamiento.","- Mantenga los codos en un ángulo de 45 grados: reduce la tensión en los hombros.","- No controlar el descenso: caer demasiado rápido puede tensar el cuello y los hombros.","- Saltarse los calentamientos: no preparar los hombros y las muñecas puede provocar molestias y lesiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('05d1f7ac-c0de-4e80-babe-05d1f7ac0000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Vertical-Mountain-Climber.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4db16b1c-c0de-4e80-babe-4db16b1c0000', 'Estiramiento de pie', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/05/Standing-Hamstring-Stretch.gif', '{"- Posición inicial: Párese erguido con los pies juntos o separados a la altura de las caderas y los brazos relajados a los lados.","- Mantenga la posición: permanezca en el estiramiento durante 20 a 30 segundos, respirando profundamente y evitando rebotes.","- Regresar al inicio: enrolle lentamente vértebra por vértebra hasta que esté de pie nuevamente. Repita con la otra pierna.","- Bisagra en las caderas, no en la parte baja de la espalda, para evitar tensiones y asegurar un estiramiento adecuado.","- Exhala mientras te inclinas hacia adelante para liberar la tensión muscular.","- Inclínese hacia adelante: lleve la pierna derecha un paso hacia adelante. Gire lentamente las caderas y baje el torso hacia las piernas. Deje que sus brazos cuelguen o alcancen los dedos de los pies.","- Realice sobre una superficie plana para un mejor equilibrio y control.","### Errores comunes","- Bloquear las rodillas: puede generar una tensión excesiva en las articulaciones y reducir la efectividad del estiramiento.","- Redondear la espalda agresivamente: reduce el estiramiento de los isquiotibiales y corre el riesgo de sufrir tensión en la columna.","- Apoye y alinee: Involucre ligeramente su núcleo y mantenga una columna neutral mientras se prepara para girar hacia adelante.","- Fase de estiramiento: Mantenga las rodillas rectas o ligeramente flexionadas (si es necesario). Relaja tu cuello y deja que tu cabeza cuelgue libremente.","### Consejos para una forma adecuada","- Mantenga las rodillas suaves si su flexibilidad es limitada para evitar tirar de los tendones.","- Evite redondear demasiado la parte superior de la espalda; apunte a una extensión larga de la columna.","- Contener la respiración: restringe la relajación y puede elevar la tensión.","- Rebotes o sacudidas: aumenta el riesgo de lesiones y no es apropiado para estiramientos estáticos.","- Esforzarse demasiado: el estiramiento debe ser intenso pero nunca doloroso."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3f8914ce-c0de-4e80-babe-3f8914ce0000', 'Extensión de piernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Single-Leg-Extension.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('083146ae-c0de-4e80-babe-083146ae0000', 'Prensa de piernas en máquina', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Smith-Machine-Leg-Press.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7f037215-c0de-4e80-babe-7f0372150000', 'Elevaciones laterales con banda de resistencia', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Band-Front-Lateral-Raise.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('19ceb4ca-c0de-4e80-babe-19ceb4ca0000', 'Peso muerto', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Trap-Bar-Deadlift.gif', '{"Coloque la barra de trampa en el suelo y cárguela con las placas de peso deseadas. Entre en la barra de trampa de modo que esté parado en el centro, con las manijas a cada lado de usted. Sus pies deben estar separados al ancho de las caderas y los dedos de los pies deben apuntar hacia adelante o ligeramente hacia afuera.","Coloque la barra trampa en el suelo y cárguela con las placas de peso deseadas.","Tus pies deben estar separados a la altura de las caderas y los dedos de los pies deben apuntar hacia adelante o ligeramente hacia afuera.","Párese completamente erguido con las caderas y las rodillas bloqueadas, manteniendo la columna neutra.","Configuración: Coloque la barra de trampa en el suelo y cárguela con las placas de peso deseadas. Entre en la barra de trampa de modo que esté parado en el centro, con las manijas a cada lado de usted. Sus pies deben estar separados al ancho de las caderas y los dedos de los pies deben apuntar hacia adelante o ligeramente hacia afuera.","Entra en la barra trampa para quedarte en el centro, con las manijas a cada lado.","Agarre: Doble las caderas y las rodillas para bajar el cuerpo. Mantenga la espalda recta y el pecho erguido. Bájese y agarre las manijas de la barra trampa con ambas manos, asegurándose de que las palmas estén una frente a la otra. Sus manos deben colocarse aproximadamente al nivel de las caderas o ligeramente más abajo.","Baje y agarre las manijas de la barra trampa con ambas manos, asegurándose de que las palmas estén enfrentadas.","Bajar: para bajar la barra trampa, invierta el movimiento. Primero empuje las caderas hacia atrás y luego doble las rodillas. Baje la barra suavemente hasta el suelo, asegurándose de que no choque ni rebote.","Para bajar la barra trampa, invierta el movimiento. Primero empuja las caderas hacia atrás y luego dobla las rodillas.","Tus manos deben estar colocadas aproximadamente al nivel de las caderas o ligeramente más abajo.","Empuja los talones y levántate, extendiendo las caderas y las rodillas simultáneamente. Mantén la espalda plana y evita arquearla.","Mientras levantas la barra trampa, mantenla cerca de tu cuerpo. Tus brazos deben colgar hacia abajo desde tus hombros.","Levantamiento: Apoye su núcleo para mantener una columna estable. Empuje con los talones y levántese, extendiendo las caderas y las rodillas simultáneamente. Mantenga la espalda plana y evite curvarla. Mientras levanta la barra trampa, manténgala cerca de su cuerpo. Sus brazos deben colgar hacia abajo desde sus hombros. Párese completamente erguido con las caderas y las rodillas bloqueadas, manteniendo una columna neutral.","Repetir: Realice la cantidad deseada de repeticiones para su entrenamiento.","Realice el número deseado de repeticiones para su entrenamiento."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1e484e8a-c0de-4e80-babe-1e484e8a0000', 'Press de pecho de pie con banda de resistencia', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Band-Standing-Chest-Press.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2092989c-c0de-4e80-babe-2092989c0000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/shrimp-squats.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4d0cb94b-c0de-4e80-babe-4d0cb94b0000', 'Elevación de pantorrillas sentado', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2021/10/Weighted-Seated-Calf-Raise.gif', '{"- Configuración: siéntese erguido en un banco con una mancuerna apoyada sobre los muslos, justo por encima de las rodillas.","- Posición del pie: Coloque las puntas de los pies sobre una plataforma elevada con los talones colgando del borde. Mantenga los pies separados a la altura de los hombros.","- Posición inicial: Sujeta la mancuerna de forma segura con las manos. Mantenga su núcleo apretado y su torso erguido.","- Utilice una toalla o almohadilla debajo del peso si siente molestias en los muslos.","- Usar demasiado peso: Reduce el control y aumenta el riesgo de lesiones.","- No ocupar la primera posición: perderse la contracción que maximiza el crecimiento.","- Repetir: realice el número deseado de repeticiones de forma controlada y deliberada.","- Concéntrese en la contracción total y en un fuerte apretón en la parte superior de cada repetición.","### Errores comunes","- Levante los talones: presione las puntas de los pies para levantar los talones lo más alto posible, apretando las pantorrillas en la parte superior.","- Baje lentamente: baje los talones hasta que estén justo debajo de la plataforma para sentir un estiramiento profundo en las pantorrillas.","- No rebotes: utiliza movimientos lentos y controlados en todo el rango.","- Acortar el rango de movimiento: Limita la activación muscular; asegúrese de levantar y estirar completamente.","- Permitir que el peso se mueva o se tambalee: distrae del movimiento y afecta la forma.","- Pausa en la parte superior: mantenga la contracción máxima durante 1 a 2 segundos para una activación máxima.","### Consejos para una forma adecuada","- Mantenga las rodillas dobladas a 90 grados durante todo el ejercicio para aislar el sóleo.","- Asegúrese de que la mancuerna esté estable sobre sus muslos para evitar que ruede o se desequilibre.","- Moverse demasiado rápido: el impulso reduce la eficacia y aumenta la tensión en las articulaciones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('640ed3a0-c0de-4e80-babe-640ed3a00000', 'Ejercicio en polea', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/90-Degree-Cable-External-Rotation-.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0184edd2-c0de-4e80-babe-0184edd20000', 'Ejercicio en polea', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2023/06/Cable-Shoulder-90-degrees-Internal-Rotation.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('293069bb-c0de-4e80-babe-293069bb0000', 'Ejercicio', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2023/02/pendulum.gif', '{"Párate junto a una superficie estable, como una mesa o silla, y coloca tu mano sobre ella para apoyarte.","Deje que el brazo del lado que desea estirar cuelgue libremente.","Doble ligeramente las rodillas e inclínese hacia adelante, manteniendo la espalda recta.","Comience con pequeños cambios y aumente gradualmente el rango de movimiento a medida que se sienta más cómodo.","Realice el movimiento de balanceo durante unos 10 a 15 segundos.","Mueva suavemente el brazo hacia adelante y hacia atrás como un péndulo, permitiéndole moverse de manera natural y relajada.","Cambia de lado y repite el ejercicio con el otro brazo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('400f6648-c0de-4e80-babe-400f66480000', 'Curl de piernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Towel-Leg-Curl.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('267eb3d7-c0de-4e80-babe-267eb3d70000', 'Press de pecho con pesa rusa / kettlebell', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Kettlebell-Chest-Press-on-the-Floor.gif', '{"- Configuración: Acuéstese boca arriba con las rodillas dobladas y los pies firmemente plantados en el suelo. Sostenga una pesa rusa en cada mano con un agarre neutral (las palmas una frente a la otra).","- Sostenga una pesa rusa en cada mano con un agarre neutral (con las palmas una frente a la otra).","### Guía paso a paso","- Acuéstese boca arriba con las rodillas dobladas y los pies firmemente plantados en el suelo.","- Presione las pesas rusas hacia arriba hasta que sus brazos estén completamente extendidos.","- Fase de prensado: Presiona las pesas rusas hacia arriba hasta que tus brazos estén completamente extendidos. Mantén el movimiento controlado y evita bloquear los codos.","- Fase de descenso: baje lentamente las pesas rusas hasta que la parte superior de sus brazos toque el suelo. Mantenga la tensión en el pecho y los tríceps durante todo el movimiento.","- Baje lentamente las pesas rusas hasta que la parte superior de sus brazos toque el suelo.","- Mantenga la tensión en el pecho y los tríceps durante todo el movimiento.","- Repetir: Realice el número deseado de repeticiones manteniendo la forma adecuada.","- Posicionamiento: Mantenga los codos doblados en un ángulo de aproximadamente 45 grados con respecto al torso. Asegúrese de que la parte superior de sus brazos descanse sobre el piso y que sus muñecas estén alineadas con los codos.","- Mantenga los codos doblados en un ángulo de aproximadamente 45 grados con respecto al torso.","- Asegúrese de que la parte superior de sus brazos descanse sobre el piso y que sus muñecas estén alineadas con sus codos.","- Mantenga el movimiento controlado y evite bloquear los codos.","- Realice el número deseado de repeticiones manteniendo la forma adecuada."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('501dcab8-c0de-4e80-babe-501dcab80000', 'Press de pecho unilateral con pesa rusa / kettlebell', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/One-Arm-Kettlebell-Chest-Press-on-the-Bench.gif', '{"- Configuración: Acuéstese en un banco o en el piso con las rodillas dobladas y los pies firmemente plantados. Sostenga una pesa rusa en una mano, manteniendo la muñeca recta y la palma hacia adelante.","- Acuéstese sobre un banco o en el suelo con las rodillas dobladas y los pies firmemente plantados.","- Posición inicial: Presione la pesa rusa directamente sobre su pecho, bloqueando su codo. Asegúrese de que la pesa rusa descanse contra la parte posterior de su antebrazo para mayor estabilidad.","- Fase de prensado: empuja la pesa rusa hacia la posición inicial en línea recta. Exhala mientras presionas hacia arriba y mantienes el control durante todo el movimiento.","- Empuja la pesa rusa hacia la posición inicial en línea recta.","- Posición de los hombros: Mantenga los omóplatos retraídos y presionados contra el banco o el suelo.","- Mal agarre: Un agarre débil puede provocar inestabilidad y reducir la seguridad del ejercicio.","- Sostenga una pesa rusa en una mano, manteniendo la muñeca recta y la palma hacia adelante.","- Presione la pesa rusa directamente sobre su pecho, bloqueando su codo.","- Concéntrese en controlar el descenso para activar los músculos estabilizadores.","- Agarre estable: asegúrese de que el mango de la pesa rusa permanezca estable y seguro en su mano.","- Fase de descenso: baje lentamente la pesa rusa hacia el pecho, manteniendo el codo en un ángulo de 45 grados con respecto al torso. Concéntrese en controlar el descenso para activar los músculos estabilizadores.","- Baje lentamente la pesa rusa hacia su pecho, manteniendo el codo en un ángulo de 45 grados con respecto al torso.","- Exhala mientras presionas hacia arriba y mantienes el control durante todo el movimiento.","- Acelerar el movimiento: realizar el ejercicio demasiado rápido puede comprometer la forma y reducir la efectividad.","- Movimiento controlado: Evite apresurarse; controlar tanto la fase de descenso como la de elevación.","- Respiración: Inhala mientras bajas la pesa rusa y exhala mientras la vuelves a subir.","### Errores comunes","- Asegúrese de que la pesa rusa descanse contra la parte posterior de su antebrazo para mayor estabilidad.","- Cambiar de brazo: complete las repeticiones deseadas y luego cambie al otro brazo.","- Complete las repeticiones deseadas y luego cambie al otro brazo.","### Consejos para una forma adecuada","- Mantenga su núcleo apretado: Involucre su núcleo para evitar que su torso se tuerza o arquee.","- Arquear la espalda: Arquear la zona lumbar reduce el compromiso central y aumenta el riesgo de lesiones.","- Ensanchamiento del codo: Permitir que el codo se ensanche excesivamente puede estresar la articulación del hombro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('27f5929b-c0de-4e80-babe-27f5929b0000', 'Press de pecho declinado con barra', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/03/Decline-Barbell-Bench-Press.gif', '{"- Configuración: Ajuste un banco declinado en un ángulo de 15 a 30 grados. Acuéstese y asegure los pies debajo de las almohadillas para los pies para mantener la estabilidad.","- Ajuste un banco inclinado a un ángulo de 15 a 30 grados.","- Agarre y posicionamiento: Agarre la barra con un agarre por encima de la cabeza, con las manos ligeramente más separadas que el ancho de los hombros. Saque la barra y sosténgala con los brazos completamente extendidos sobre el pecho.","- Agarre la barra con un agarre por encima de la cabeza, con las manos un poco más separadas que el ancho de los hombros.","- Utilice un observador si levanta pesos pesados ​​para garantizar la seguridad.","- Ancho de agarre inadecuado: un agarre demasiado estrecho o demasiado ancho puede limitar la eficacia y provocar tensión en la muñeca o el hombro.","- Levantar demasiado peso y demasiado pronto: comience con un peso moderado para perfeccionar su forma antes de aumentar la resistencia.","###","### Guía paso a paso","- Acuéstese y asegure sus pies debajo de las almohadillas para mantener la estabilidad.","- Retire la barra y sosténgala con los brazos completamente extendidos sobre el pecho.","- Fase de descenso: baje lentamente la barra hacia la parte inferior del pecho, manteniendo los codos en un ángulo de aproximadamente 45 grados. Baje hasta que la barra toque ligeramente el pecho sin rebotar.","- Baje lentamente la barra hacia la parte inferior del pecho, manteniendo los codos en un ángulo de aproximadamente 45 grados.","- Fase de prensado: empuja la barra hacia arriba con un movimiento controlado hasta que tus brazos estén completamente extendidos. Involucra tu pecho, hombros y tríceps para completar el levantamiento.","- Empuja la barra hacia arriba con un movimiento controlado hasta que tus brazos estén completamente extendidos.","- Exhala mientras presionas hacia arriba e inhala mientras bajas la barra.","- Acelerar el movimiento: baje y presione la barra con control para maximizar la participación de los músculos.","- Falta de rango completo de movimiento: no bajar la barra hasta el pecho reduce la efectividad del ejercicio.","- Baja hasta que la barra toque ligeramente tu pecho sin rebotar.","- Involucre su pecho, hombros y tríceps para completar el levantamiento.","- Mantenga el compromiso central para estabilizar su cuerpo durante todo el movimiento.","- Repetir: Realiza de 3 a 5 series de 6 a 12 repeticiones, dependiendo de tus objetivos de entrenamiento.","- Realiza de 3 a 5 series de 6 a 12 repeticiones, dependiendo de tus objetivos de entrenamiento.","### Consejos para una forma adecuada","- Mantenga las muñecas rectas y evite doblarlas excesivamente para evitar lesiones.","- Evite hacer rebotar la barra contra su pecho, ya que esto reduce la efectividad y aumenta el riesgo de lesiones.","- Arquear la espalda excesivamente: Mantenga la columna neutra para evitar tensión en la zona lumbar.","### Errores comunes a evitar"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('554552ac-c0de-4e80-babe-554552ac0000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Single-Leg-Hip-Thrust-Jump.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5f3dd021-c0de-4e80-babe-5f3dd0210000', 'Estiramiento', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Foam-Roller-IT-iliotibial-Band-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('47a84a50-c0de-4e80-babe-47a84a500000', 'Estiramiento', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Roll-Upper-Back.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6af3655a-c0de-4e80-babe-6af3655a0000', 'Ejercicio', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Roll-Rhomboids.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('52429dfc-c0de-4e80-babe-52429dfc0000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Foam-Roller-Glutes.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('59256a67-c0de-4e80-babe-59256a670000', 'Press de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/07/Wide-Grip-Barbell-Bench-Press.gif', '{"- Configuración: Acuéstese en una estación de press de banca con los pies firmemente plantados en el suelo. Coloque los ojos directamente debajo de la barra antes de quitarla.","- Coloque sus ojos directamente debajo de la barra antes de quitarla.","- Sujete la barra a una distancia mayor que la anchura de los hombros (aproximadamente 1,5 a 2 veces el ancho de los hombros).","- Fase de press: empuja la barra hacia arriba hasta la posición inicial, extendiendo completamente los brazos. Concéntrate en contraer el pecho en la parte superior del movimiento.","- Empuja la barra hacia arriba hasta la posición inicial, extendiendo completamente los brazos.","### Guía paso a paso","- Acuéstese sobre una estación de press de banca con los pies firmemente plantados en el suelo.","- Agarre y posicionamiento: Sujete la barra a una distancia mayor que el ancho de los hombros (aproximadamente 1,5 a 2 veces el ancho de los hombros). Mantenga las muñecas rectas y asegúrese de que la barra se asiente cómodamente en sus palmas.","- Baje lentamente la barra hacia la parte media e inferior del pecho mientras mantiene los codos en un ángulo de aproximadamente 75 grados.","- Concéntrate en contraer el pecho en la parte superior del movimiento.","- Retire la barra: enganche la parte superior de la espalda y el core, luego presione la barra para sacarla del soporte. Sostenga la barra con los brazos completamente extendidos sobre el pecho.","- Involucra la parte superior de la espalda y el core, luego presiona la barra para sacarla de la rejilla.","- Mantenga las muñecas rectas y asegúrese de que la barra quede cómodamente en sus palmas.","- Fase de descenso: baje lentamente la barra hacia la parte media e inferior del pecho mientras mantiene los codos en un ángulo de aproximadamente 75 grados. Mantenga el control y evite que la barra rebote en el pecho.","- Mantenga el control y evite hacer rebotar la barra en su pecho.","- Repetir: Realiza de 3 a 5 series de 6 a 12 repeticiones, dependiendo de tus objetivos de entrenamiento.","- Realiza de 3 a 5 series de 6 a 12 repeticiones, dependiendo de tus objetivos de entrenamiento.","- Sostenga la barra con los brazos completamente extendidos sobre su pecho."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('65c849dc-c0de-4e80-babe-65c849dc0000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Foam-Roller-Quads.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0a125f30-c0de-4e80-babe-0a125f300000', 'Zancadas en máquina', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Smith-Machine-Lunge.gif', '{"Ajuste la barra de la máquina Smith a una altura adecuada. Debe colocarse aproximadamente al nivel del pecho o de los hombros. Cargue una cantidad adecuada de peso en la barra.","Ajuste la barra de la máquina Smith a una altura adecuada. Debe colocarse aproximadamente a la altura del pecho o de los hombros.","Párese con los pies separados a la altura de las caderas, de espaldas a la máquina Smith. Colóquese de manera que la barra descanse sobre la parte superior de la espalda y los hombros.","Colocación del pie: Da un paso hacia adelante con un pie, asegurándote de que esté a una distancia cómoda de la máquina Smith. La distancia dependerá de la longitud de tu propia zancada. Mantén los pies en posición dividida, con un pie hacia adelante y el otro hacia atrás.","Da un paso adelante con un pie, asegurándote de que esté a una distancia cómoda de la máquina Smith. La distancia dependerá de tu propia longitud de zancada.","Empujar hacia atrás: Empuje con el talón del pie delantero para volver a la posición inicial. Continúe alternando piernas durante el número deseado de repeticiones.","Empuja con el talón de tu pie delantero para volver a la posición inicial.","Configuración: Ajuste la barra de la máquina Smith a una altura adecuada. Debe colocarse aproximadamente al nivel del pecho o de los hombros. Cargue una cantidad adecuada de peso en la barra.","Movimiento de estocada: Baje el cuerpo doblando ambas rodillas, asegurándose de que la rodilla delantera esté directamente encima del tobillo y la rodilla trasera apunte hacia el suelo. Trate de bajar la rodilla trasera hacia el suelo sin dejar que se toque. Mantenga el torso erguido y mantenga una línea recta desde la cabeza hasta las caderas.","Posición inicial: Párese con los pies separados a la altura de las caderas, de espaldas a la máquina Smith. Colóquese de manera que la barra descanse sobre la parte superior de la espalda y los hombros.","Mantenga los pies en una postura dividida, con un pie hacia adelante y el otro hacia atrás."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('529365dd-c0de-4e80-babe-529365dd0000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Foam-Roller-Upper-Back.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('00b59235-c0de-4e80-babe-00b592350000', 'Ejercicio unilateral', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/One-Arm-Push-Ups-With-Support.gif', '{"- Configuración: Busque un banco resistente, una caja o una superficie elevada para apoyarse. Colóquese en una posición de flexión con los pies ligeramente más separados que el ancho de los hombros para mantener el equilibrio.","- Busque un banco, una caja o una superficie elevada resistente como apoyo.","- Colóquese en una posición de flexión con los pies ligeramente más separados que el ancho de los hombros para mantener el equilibrio.","- Colocación de la mano: Coloque el brazo de trabajo firmemente en el suelo, alineado con el pecho. Coloque la mano de apoyo en el banco o en una superficie elevada.","- Coloque su brazo de trabajo firmemente en el suelo, alineado con su pecho.","- Coloque su mano de apoyo sobre el banco o superficie elevada.","- Extiende tu brazo completamente y regresa a la posición inicial.","- Depender demasiado del brazo de soporte: el brazo de trabajo debería hacer la mayor parte del trabajo.","### Guía paso a paso","- Involucre su núcleo y glúteos para mantener la alineación del cuerpo.","- Fase de prensado: Empuje a través del brazo que trabaja, manteniendo el core apretado para mantener la estabilidad. Extienda el brazo completamente y regrese a la posición inicial.","- Repeticiones y series: Realice de 3 a 4 series de 6 a 12 repeticiones por lado, dependiendo de su nivel de condición física.","- Fase de descenso: Involucre el núcleo y los glúteos para mantener la alineación del cuerpo. Baje lentamente el cuerpo hacia el suelo mientras mantiene los codos en un ángulo de 45 grados.","- Baje lentamente el cuerpo hacia el suelo mientras mantiene los codos en un ángulo de 45 grados.","- Empuje a través de su brazo de trabajo, manteniendo su núcleo apretado para mantener la estabilidad.","- Controla el movimiento para evitar utilizar el impulso.","- Involucre su núcleo para evitar que sus caderas se caigan.","- Reduzca gradualmente el apoyo para avanzar hacia una flexión completa con un brazo.","### Errores comunes a evitar","- Realiza de 3 a 4 series de 6 a 12 repeticiones por lado, dependiendo de tu nivel de condición física.","### Consejos para una forma adecuada","- Mantenga su cuerpo en línea recta desde la cabeza hasta los talones.","- Mantenga un patrón de respiración constante durante todo el ejercicio.","- Dejar caer las caderas: Mantenga una línea recta del cuerpo para evitar la tensión en la parte baja de la espalda.","- Encogerse de hombros: Mantenga los hombros bajos y comprometidos.","- Apresurarse en las repeticiones: concéntrese en movimientos lentos y controlados para una máxima activación muscular.","- No cambiar de lado: Entrena ambos brazos de manera uniforme para evitar desequilibrios musculares."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6049a896-c0de-4e80-babe-6049a8960000', 'Ejercicio sentado', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Seated-Scapular-Retraction-Exercise.gif', '{"Ayuda a reducir el dolor en el hombro y el cuello.","mejora tu postura","Aumenta el rango de movimiento (ayuda a aumentar su capacidad de alcanzar)","Aumenta tu resistencia para mantener ciertas posiciones por más tiempo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('09f1b881-c0de-4e80-babe-09f1b8810000', 'Estiramiento', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Foam-Roller-Lat-Stretch.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2bb2662b-c0de-4e80-babe-2bb2662b0000', 'Estiramiento', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Foam-Roller-Inner-Thigh-Adductor-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('42dc034c-c0de-4e80-babe-42dc034c0000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Foam-Roller-Plantar-Fasciitis.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3611c540-c0de-4e80-babe-3611c5400000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Foam-Roller-Hamstrings.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('04acb09f-c0de-4e80-babe-04acb09f0000', 'Ejercicio', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Roll-Front-Shoulder-and-Chest-Lying-on-Floor.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('78c195fb-c0de-4e80-babe-78c195fb0000', 'Estiramiento', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Rotator-Cuff-Stretch.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('440c2927-c0de-4e80-babe-440c29270000', 'Estiramiento', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Reverse-Shoulder-Stretch.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('59ade31a-c0de-4e80-babe-59ade31a0000', 'Ejercicio acostado', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Lying-Upper-Body-Rotation.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('76dd2ca0-c0de-4e80-babe-76dd2ca00000', 'Dominadas supinas unilateral', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/One-Arm-Chin-Up.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('28949cb2-c0de-4e80-babe-28949cb20000', 'Estiramiento', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/90-90-Hip-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
