INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('09f84281-c0de-4e80-babe-09f842810000', 'Dominadas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Behind-The-Neck-Pull-up.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('72d57bf8-c0de-4e80-babe-72d57bf80000', 'Jalón al pecho unilateral en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Cable-One-Arm-Pulldown.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('187cb743-c0de-4e80-babe-187cb7430000', 'Giro ruso', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Bicycle-Twisting-Crunch.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('29d61e37-c0de-4e80-babe-29d61e370000', 'Ejercicio declinado con barra', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Barbell-Decline-Bent-Arm-Pullover.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('760ad846-c0de-4e80-babe-760ad8460000', 'Ejercicio', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Foam-Roller-Calves.gif', '{"siéntese en el suelo con las piernas extendidas y coloque un rodillo de espuma horizontalmente debajo de las pantorrillas.","Apoye la parte superior del cuerpo: coloque las manos en el suelo detrás de usted y levante ligeramente las caderas para que su peso se traslade al rodillo de espuma.","Configuración: siéntese en el suelo con las piernas extendidas y coloque un rodillo de espuma horizontalmente debajo de las pantorrillas.","Aplique presión: para aumentar la presión, cruce una pierna sobre la otra para colocar más peso en la parte inferior de la pantorrilla.","Comience a rodar: ruede lentamente desde la parte inferior de la pantorrilla (justo encima del tobillo) hasta la parte superior (debajo de la rodilla) utilizando pequeños movimientos hacia adelante y hacia atrás.","Apunte a los puntos gatillo: si encuentra un punto sensible o tenso, haga una pausa y manténgalo presionado durante 10 a 20 segundos hasta que se reduzca la tensión.","Repita: continúe rodando durante 20 a 40 segundos por pierna, cambiando de lado según sea necesario."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('48d83b5a-c0de-4e80-babe-48d83b5a0000', 'Peso muerto', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Stiff-Leg-Deadlift.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1e9e842f-c0de-4e80-babe-1e9e842f0000', 'Ejercicio de rodillas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Kneeling-Back-Rotation-Stretch.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3beee09a-c0de-4e80-babe-3beee09a0000', 'Ejercicio con banda de resistencia', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Resistance-Band-Foot-External-Rotation.gif', '{"- Configuración: Siéntese en un banco o silla con las rodillas dobladas a 90 grados y los pies apoyados en el suelo.","- Colocación de la banda: coloque una banda de resistencia alrededor de ambos pies, creando una tensión de ligera a moderada entre ellos.","- Regresar bajo control: Lleve lentamente el pie a la posición inicial sin dejar que la banda se rompa.","- Gire el pie de trabajo: gire lentamente el pie de trabajo hacia afuera, moviéndolo contra la resistencia de la banda. Sólo deben moverse el pie y el tobillo; evite el movimiento de la rodilla o la cadera.","- Pausa al final del rango: Mantenga la posición de rotación externa durante 1 a 2 segundos para la activación.","- Repetir: realice la cantidad deseada de repeticiones y luego cambie al otro lado.","- Mantenga quietas la pierna y la rodilla; aísle el movimiento únicamente al tobillo y al pie.","- Comience con una resistencia ligera, centrándose en el movimiento controlado y la participación de los músculos.","- No apresure el movimiento: cuanto más lento, más eficaz será para la activación muscular.","- Permitir que los dedos dominen el movimiento en lugar de rotar todo el pie/tobillo.","- Mantenga una postura erguida para apoyar la alineación de la columna durante la posición sentada.","- Respire constantemente para ayudar a mantener la estabilidad central y la relajación.","### Errores comunes","- Mover la rodilla o el muslo en lugar de aislar el tobillo.","- Anclar el pie opuesto: Mantenga un pie inmóvil para anclar la banda, presionándola contra el piso para mayor estabilidad.","### Consejos para una forma adecuada","- Realizar repeticiones rápidas o entrecortadas, reduce la efectividad y corre el riesgo de sufrir tensión.","- Usar una resistencia excesiva de la banda que compromete la forma y el control.","- Descuidar la fase de retorno: la parte excéntrica es clave para el fortalecimiento."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('31be02fc-c0de-4e80-babe-31be02fc0000', 'Ejercicio', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Serratus-Wall-Slide-With-Foam-Roller.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4a7019f4-c0de-4e80-babe-4a7019f40000', 'Ejercicio declinado', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Decline-Close-Grip-Bench-To-Skull-Crusher.gif', '{"- Ajuste un banco inclinado a un ángulo moderado (alrededor de 15 a 30 grados).","- Asegure sus pies debajo de las almohadillas de soporte para mayor estabilidad.","- Elija un peso adecuado utilizando una barra o barra de curl EZ.","### Paso 2: Posición inicial","- Recuéstese en el banco de descenso mientras sostiene la barra con un agarre firme (al ancho de los hombros o un poco más estrecho).","- Presione la barra hacia arriba hasta la posición inicial, concentrándose en el compromiso de los tríceps.","- Una vez en la posición superior de la prensa, cambie a la trituradora de cráneo doblando los codos y bajando la barra hacia la frente.","- Extiende tus brazos nuevamente a la posición inicial y repite el movimiento.","### Paso 1: configurar el equipo","- Extiende tus brazos completamente, manteniendo la barra directamente sobre tus hombros.","### Paso 3: realice el press de banca con agarre cerrado","- Baje la barra lentamente hasta la parte inferior del pecho mientras mantiene los codos cerca del cuerpo.","### Paso 4: transición al triturador de calaveras","### Paso 5: mantener el control y repetir","- Realiza de 8 a 12 repeticiones por serie, asegurando movimientos controlados.","- Involucre su núcleo y mantenga los codos doblados para mantener el control.","- Mantenga los codos inmóviles y evite ensancharlos.","- Concéntrate en la activación del tríceps durante todo el ejercicio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('21ef3f75-c0de-4e80-babe-21ef3f750000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Cross-Body-Push-up_Plyometric.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4a767529-c0de-4e80-babe-4a7675290000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Dead-Bug.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1e5e989c-c0de-4e80-babe-1e5e989c0000', 'Elevación', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Wall-Supported-Arm-Raises.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7efeca57-c0de-4e80-babe-7efeca570000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/Isometric-Pull-Up.gif', '{"Agarre una barra de dominadas con las manos separadas a la altura de los hombros y las palmas hacia afuera o hacia usted.","Cuelga libremente con los brazos completamente extendidos y los pies alejados del suelo.","Mantenga esta posición durante 20 a 60 segundos o el mayor tiempo posible con buena forma.","Involucre ligeramente los hombros (evite encogerlos por completo).","Mantenga el núcleo tenso y las piernas rectas o ligeramente dobladas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('600c1f9c-c0de-4e80-babe-600c1f9c0000', 'Elevación', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Backhand-Raise.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4eb4d816-c0de-4e80-babe-4eb4d8160000', 'Curl martillo con mancuernas', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Dumbbell-Preacher-Hammer-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('553643ee-c0de-4e80-babe-553643ee0000', 'Curl predicador con mancuernas', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Two-dumbbell-preacher-curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('021e659f-c0de-4e80-babe-021e659f0000', 'Curl predicador alterno con mancuernas', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Dumbbell-Alternate-Preacher-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5c4a37e0-c0de-4e80-babe-5c4a37e00000', 'Press de pecho sentado con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Dumbbell-Seated-Cuban-Press.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('386f9843-c0de-4e80-babe-386f98430000', 'Curl de bíceps unilateral con mancuerna', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/One-Arm-Prone-Dumbbell-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7e7d66c2-c0de-4e80-babe-7e7d66c20000', 'Giro ruso sentado en polea', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Seated-Cable-Twist.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('52689dec-c0de-4e80-babe-52689dec0000', 'Press de hombros de rodillas en polea', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Kneeling-Cable-Shoulder-Press.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5aad77a4-c0de-4e80-babe-5aad77a40000', 'Dominadas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/Isometric-Pull-Up.gif', '{"Agarre la barra de dominadas con las manos separadas a la altura de los hombros y las palmas hacia afuera (pronación).","Tire hacia la posición deseada (arriba, media o casi abajo).","Mantenga la posición activando la espalda, los brazos y los músculos centrales.","Baje con control o bájese con seguridad si está fatigado.","Repita para varias series, según su objetivo de entrenamiento.","Mantenga una postura quieta sin balancearse ni moverse durante 10 a 30 segundos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3022ddf5-c0de-4e80-babe-3022ddf50000', 'Ejercicio de rodillas en polea', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Cable-Kneeling-Pull-Through.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0c694e5a-c0de-4e80-babe-0c694e5a0000', 'Encogimiento de hombros', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Dip-Shrugs.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4f69b411-c0de-4e80-babe-4f69b4110000', 'Zancadas con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Dumbbell-Goblet-Curtsey-Lunge.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7a6bcebb-c0de-4e80-babe-7a6bcebb0000', 'Zancadas en polea', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Cable-Lunge.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('23471a57-c0de-4e80-babe-23471a570000', 'Sentadilla en polea', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Cable-Front-Squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('11859f6d-c0de-4e80-babe-11859f6d0000', 'Press de pecho declinado', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Lever-Decline-Chest-Press.gif', '{"- Ajuste la máquina: ajuste la altura del asiento de modo que las manijas se alineen con la parte inferior del pecho cuando esté sentado. Ajuste el respaldo para brindar el soporte adecuado.","- Ajuste la altura del asiento de modo que las manijas se alineen con la parte inferior del pecho cuando esté sentado.","- Ajuste el respaldo para brindar el soporte adecuado.","- Establezca su posición: siéntese con la espalda firmemente contra la almohadilla y los pies apoyados en el piso. Agarre las manijas con un agarre neutral o en pronación (según el diseño de la máquina). Mantenga los codos en un ángulo de 45 grados para reducir la tensión en los hombros.","- Siéntese con la espalda firmemente apoyada en la almohadilla y los pies apoyados en el suelo.","- Agarre las manijas con un agarre neutral o en pronación (según el diseño de la máquina).","- Inhala y baja lentamente el peso hasta la posición inicial.","- Ajuste la altura del asiento correctamente para apuntar eficazmente a la parte inferior del pecho.","- Posición incorrecta del asiento: si el asiento está demasiado alto o bajo, puede desviar el énfasis de la parte inferior del pecho.","- Uso de peso excesivo: Levantar demasiado peso puede comprometer la forma y aumentar el riesgo de lesiones.","### Guía paso a paso","- Controle el descenso: inhale y baje lentamente el peso hasta la posición inicial. Asegúrese de que los músculos del pecho estén completamente comprometidos durante todo el movimiento.","- Asegúrese de que los músculos de su pecho estén completamente comprometidos durante todo el movimiento.","- Presione el peso: exhale y empuje las manijas hacia adelante con un movimiento controlado hasta que sus brazos estén completamente extendidos. No bloquee los codos en la parte superior del movimiento.","- Exhala y empuja las manijas hacia adelante con un movimiento controlado hasta que tus brazos estén completamente extendidos.","- No bloquees los codos en la parte superior del movimiento.","- Confiar en el impulso: el uso de un movimiento controlado maximiza la participación de los músculos y reduce el riesgo de lesiones.","- Repita para las repeticiones deseadas: Realice de 3 a 4 series de 8 a 12 repeticiones, dependiendo de sus objetivos de entrenamiento.","- Utilice un rango completo de movimiento, pero evite bloquear los codos en la parte superior.","### Errores comunes a evitar","- Mantenga los codos en un ángulo de 45 grados para reducir la tensión en los hombros.","- Realiza de 3 a 4 series de 8 a 12 repeticiones, dependiendo de tus objetivos de entrenamiento.","### Consejos para una forma adecuada","- Mantenga un ritmo controlado para maximizar la activación muscular y evitar el impulso.","- Mantenga la espalda firmemente contra la almohadilla para evitar tensiones en la zona lumbar.","- Involucre su núcleo y mantenga los hombros hacia abajo para evitar una tensión excesiva en los deltoides frontales.","- Descuidar la respiración adecuada: exhalar en la prensa e inhalar en el descenso ayuda a mantener la estabilidad central.","- Bloquear los codos: bloquear completamente los codos reduce la tensión en el pecho y aumenta la tensión en las articulaciones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('76ee8d95-c0de-4e80-babe-76ee8d950000', 'Curl de bíceps alterno con barra', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Barbell-Alternate-Biceps-Curl.gif', '{"Sujete el peso (mancuerna, barra o polea) con un agarre supino (palmas hacia arriba).","Mantenga los pies separados al ancho de los hombros y las rodillas ligeramente flexionadas.","Coloque los codos pegados a los costados del torso y mantenga la espalda recta.","Manteniendo inmóvil la parte superior de los brazos, flexione los codos y eleve la carga hacia los hombros.","Apriete fuertemente los bíceps en el punto de máxima contracción por un segundo.","Baje el peso de forma controlada y lenta hasta extender completamente los brazos.","Evite balancear la espalda o mover los hombros hacia adelante para ayudarse.","Mantenga las muñecas firmes y rectas durante todo el recorrido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('47399ed0-c0de-4e80-babe-47399ed00000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/4-Point-Tummy-Vacuum-Exercise.gif', '{"Comience con las manos y las rodillas: Colóquese en el suelo sobre las manos y las rodillas, con las muñecas directamente debajo de los hombros y las rodillas debajo de las caderas.","Colóquese en el suelo sobre manos y rodillas, con las muñecas directamente debajo de los hombros y las rodillas debajo de las caderas.","Respire profundamente: Inhale profundamente por la nariz, expandiendo el diafragma.","Inhala profundamente por la nariz, expandiendo tu diafragma.","Exhale mientras tira del ombligo hacia la columna: mientras exhala, contraiga los músculos abdominales y tire del ombligo hacia la columna. Imagínese levantando sus órganos abdominales y empujando su ombligo hacia arriba y hacia adentro.","Mientras exhala, contraiga los músculos abdominales y tire del ombligo hacia la columna. Imagínese levantando sus órganos abdominales y empujando su ombligo hacia arriba y hacia adentro.","Mantener la contracción: Mantener la contracción durante unos segundos mientras se continúa respirando normalmente. Concéntrese en mantener la tensión en los músculos abdominales profundos.","Mantenga una columna neutra: mantenga la espalda recta y el cuello en una posición neutra. Evite arquear o redondear excesivamente la espalda.","Mantenga la espalda recta y el cuello en posición neutra. Evite arquear o redondear excesivamente la espalda.","Mantenga la contracción durante unos segundos mientras continúa respirando normalmente. Concéntrese en mantener la tensión en los músculos abdominales profundos.","Suelta y repite: Relaja la contracción e inhala. Repita el proceso durante varias repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('335d0d8a-c0de-4e80-babe-335d0d8a0000', 'Postura de yoga', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Fish-Pose-Matsyasana.gif', '{"- Comience en posición reclinada: Acuéstese boca arriba con las piernas extendidas y los brazos apoyados al lado de su cuerpo.","### Instrucciones paso a paso","- Acuéstese boca arriba con las piernas extendidas y los brazos apoyados al lado de su cuerpo.","- Coloque las manos debajo de las caderas: deslice las manos con las palmas hacia abajo debajo de las nalgas para obtener apoyo. Mantenga los codos juntos y enganchados.","- Deslice las manos con las palmas hacia abajo debajo de las nalgas para obtener apoyo.","- Presione con los antebrazos y los codos para levantar la parte superior del pecho hacia el techo.","- Levante el pecho: presione a través de los antebrazos y los codos para levantar la parte superior del pecho hacia el techo. Deje que la cabeza caiga suavemente hacia atrás, con la corona tocando ligeramente el suelo.","- Libere la postura: exhale, baje lentamente el pecho y lleve la cabeza hacia la colchoneta. Retire las manos de debajo de las caderas y relájese en Savasana.","- Retire las manos de debajo de las caderas y relájese en Savasana.","- Colapsar los hombros: levante activamente el pecho para maximizar los beneficios de apertura del corazón.","- Deje que su cabeza caiga suavemente hacia atrás, con la corona tocando ligeramente el suelo.","- Exhala, baja lentamente el pecho y lleva la cabeza hacia la colchoneta.","- Involucre su núcleo para evitar una tensión excesiva en la parte baja de la espalda.","- No fuerce la cabeza hacia atrás; déjela caer naturalmente, manteniendo la comodidad en el cuello.","- Respire profundamente para mejorar el estiramiento y mejorar la expansión pulmonar.","- Mantenga los codos juntos y comprometidos.","- Mantenga la postura: respire profundamente y mantenga la postura durante 15 a 30 segundos (o más para una práctica restaurativa).","- Respire profundamente y mantenga la respiración durante 15 a 30 segundos (o más para prácticas restaurativas).","### Consejos para una forma adecuada","- Mantenga las piernas activas apuntando los dedos de los pies o presionándolos suavemente contra la colchoneta.","- Arqueando la parte baja de la espalda: evite la compresión excesiva involucrando su núcleo.","- Contener la respiración: mantenga una respiración profunda y constante para mejorar la relajación.","- Modifique con accesorios si tiene molestias en el cuello o la espalda.","### Errores comunes a evitar","- Forzar el cuello: mantenga el peso distribuido uniformemente entre los antebrazos, no sobre la cabeza."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('20b6439d-c0de-4e80-babe-20b6439d0000', 'Remo inclinado con barra', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2023/02/Wide-Grip-Barbell-Bent-Over-Row-Plus.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('16edad73-c0de-4e80-babe-16edad730000', 'Sentadilla de rodillas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/02/Bodyweight-Kneeling-Sissy-Squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7bc67574-c0de-4e80-babe-7bc675740000', 'Remo inclinado con barra', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2023/02/Wide-Grip-Alternate-Barbell-Bent-Over-Row-Plus.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4d0fd44c-c0de-4e80-babe-4d0fd44c0000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/02/Box-Jump-1-to-2.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1d179544-c0de-4e80-babe-1d1795440000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/02/trap-bar-jump-squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4d01bccc-c0de-4e80-babe-4d01bccc0000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/02/Box-Jump-2-to-1.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('202245d1-c0de-4e80-babe-202245d10000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/02/Box-Jump-to-Pistol-Squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('31c0d2eb-c0de-4e80-babe-31c0d2eb0000', 'Press de pecho unilateral con barra', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Barbell-One-Arm-Floor-Press.gif', '{"- Coloque una barra cargada en el suelo con un peso ligero.","- Agarre la barra con una mano en un agarre neutral o por encima de la manga.","- Use su mano libre para ayudar a levantar la barra a su posición si es necesario.","### Paso 1: configuración","- Acuéstese con el cuerpo perpendicular a la barra, con la barra colocada por encima de un hombro.","- Doble ligeramente las rodillas o mantenga las piernas extendidas para aumentar el desafío central.","### Paso 2: Ejecución","- Presione la barra hacia arriba extendiendo el brazo, asegurándose de que la barra permanezca equilibrada y alineada sobre su hombro.","- Haga una breve pausa en la parte superior, manteniendo la muñeca apilada sobre el codo y la barra centrada.","- Mantenga el codo cerca del costado durante el descenso.","- Complete las repeticiones deseadas, luego cambie de brazo y repita.","- Baja lentamente la barra hasta que tus tríceps toquen ligeramente el suelo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('665f6487-c0de-4e80-babe-665f64870000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/02/Single-Leg-Box-Jump.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1aaf47a9-c0de-4e80-babe-1aaf47a90000', 'Aperturas de pecho en polea', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Incline-Cable-Fly.gif', '{"El ejercicio de vuelo con cable inclinado te ayudará a desarrollar pectorales completamente definidos. Es uno de los mejores ejercicios que debes hacer si quieres tener un músculo superior del pecho definido y más definido.","En ejercicios de musculación centrados en la parte superior del cuerpo o la parte superior del pecho, se suele utilizar como movimiento final al final del ejercicio después de realizar movimientos como press de banca con barra o mancuernas.","Las investigaciones muestran que realizar un vuelo con cable inclinado con un ángulo de banco de 30 y 45 grados es lo mejor para la parte superior del pecho. Para obtener la mejor eficiencia del movimiento de press inclinado con mancuernas, debes ajustar el banco en un ángulo de 30 a 45 grados y sentir que los músculos de la parte superior del pecho están trabajando."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('384b46d4-c0de-4e80-babe-384b46d40000', 'Postura de yoga', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Bow-Yoga-Pose.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7c438dab-c0de-4e80-babe-7c438dab0000', 'Curl de muñeca', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Weighted-Wrist-Curl.gif', '{"Siéntate en un banco con las rodillas dobladas y los pies planos.","Sostenga una placa de pesas verticalmente (agarre del aro) en una mano usando un agarre neutral, con el pulgar hacia arriba.","Apoye el antebrazo sobre el muslo, permitiendo que la muñeca cuelgue un poco más allá de la rodilla.","Deje que la placa baje lentamente extendiendo la muñeca hacia abajo.","Vuelva a doblar la placa hacia arriba, flexionando la muñeca mientras mantiene el antebrazo quieto.","Haga una breve pausa en la parte superior, luego repita de 10 a 15 repeticiones lentas y controladas por brazo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1c00042b-c0de-4e80-babe-1c00042b0000', 'Press de hombros', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Plate-Loaded-Shoulder-Press.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('71843e5f-c0de-4e80-babe-71843e5f0000', 'Ejercicio de rodillas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/Kneeling-T-spine-Rotation.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('56a799a7-c0de-4e80-babe-56a799a70000', 'Plancha', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/11/Side-Plank-Oblique-Crunch.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('76774149-c0de-4e80-babe-767741490000', 'Ejercicio de pie con barra', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Standing-Barbell-Rollout.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0b644451-c0de-4e80-babe-0b6444510000', 'Estiramiento', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/11/Reverse-Chest-Stretch.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4a956d87-c0de-4e80-babe-4a956d870000', 'Remo con balón medicinal', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/Medicine-Ball-Sit-up-Throw.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('48dec130-c0de-4e80-babe-48dec1300000', 'Postura de yoga', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/cat-cow.gif', '{"Esta sencilla postura potencia tu cerebro y mejora la concentración, la coordinación y la estabilidad mental. La postura del gato vaca mejora la circulación sanguínea entre las vértebras de la columna y ayuda a aliviar el dolor de espalda y el estrés. Mejora la postura y el equilibrio.","El estiramiento gato-vaca ayuda a aliviar el estrés causado por los cólicos menstruales, el dolor lumbar y la ciática. El movimiento también estira los músculos de las caderas, la espalda, el abdomen, el pecho y los pulmones. Masajea y estimula los órganos del abdomen, como los riñones y las glándulas suprarrenales."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('32a78106-c0de-4e80-babe-32a781060000', 'Estiramiento', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Single-Heel-Drop-Calf-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('53377a77-c0de-4e80-babe-53377a770000', 'Estiramiento sentado', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Seated-Straight-Leg-Calf-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7fc4060b-c0de-4e80-babe-7fc4060b0000', 'Estiramiento', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Lunging-Straight-Leg-Calf-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('51d5571c-c0de-4e80-babe-51d5571c0000', 'Estiramiento', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Foot-and-Ankles-Stretches.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('22fb97c8-c0de-4e80-babe-22fb97c80000', 'Estiramiento', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Posterior-Tibialis-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6551b73f-c0de-4e80-babe-6551b73f0000', 'Ejercicio de pie', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Standing-Dorsiflexion.gif', '{"- Posición inicial: Párese erguido con los pies separados a la altura de las caderas y los brazos relajados a los lados o colocados sobre las caderas.","- Coloque los pies: mantenga los talones firmemente plantados en el suelo, con el peso corporal distribuido uniformemente.","- Pausa en la parte superior: Mantenga la posición superior durante 1 a 2 segundos, sintiendo la contracción a lo largo de la parte delantera de la espinilla.","- Repita: realice de 10 a 20 repeticiones según su objetivo, concentrándose en la activación y el equilibrio.","- Involucra activamente los músculos de las espinillas en lugar de depender del impulso.","- Utilice una pared o superficie para mantener el equilibrio si es necesario, especialmente al empezar.","- Levante los dedos de los pies: levante activamente el antepié y los dedos de los pies hacia arriba del suelo, tirando de ellos hacia las espinillas. Tus talones deben permanecer bajos.","- Baje lentamente: lleve los dedos de los pies y el antepié al suelo con control.","- Levante los dedos de los pies lo más alto posible sin forzar ni levantar los talones.","- Controla el descenso, no dejes que los dedos de tus pies caigan.","### Errores comunes","- Inclinarse hacia atrás para ayudar al levantamiento con impulso.","- Levantar los talones: esto anula el efecto del entrenamiento de dorsiflexión.","### Consejos para una forma adecuada","- Mantenga el cuerpo erguido; evite inclinarse hacia atrás para engañar al rango.","- Acelerar las repeticiones: esto reduce el control y el reclutamiento muscular.","- Usando solo el dedo gordo del pie, active todo el antepié para una activación equilibrada.","- Actuar descalzo sobre suelos duros puede resultar incómodo; use un tapete si es necesario."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('64f0a4dd-c0de-4e80-babe-64f0a4dd0000', 'Estiramiento de pie', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Standing-Wall-Calf-Stretch.gif', '{"- Configuración: Párese frente a una pared, aproximadamente a un brazo de distancia. Coloque las manos en la pared a la altura de los hombros.","- Colocación del pie: Coloque un pie ligeramente hacia adelante con los dedos contra la pared.","- Ajuste la distancia a la pared para mayor comodidad e intensidad.","- Paso atrás: mueva una pierna detrás de usted, manteniendo los dedos apuntando hacia adelante y el talón firmemente apoyado en el suelo.","- Siente el estiramiento: inclínate suavemente hacia la pared hasta que sientas un estiramiento a lo largo de la parte inferior de la pantorrilla y el tendón de Aquiles.","- Cambiar de lado: Repita en la pierna opuesta. Realiza 2 o 3 rondas por lado.","- El movimiento debe ser lento y controlado, sin rebotes.","### Errores comunes","- El talón se levanta del suelo: reduce la eficacia del estiramiento.","- Enderezar la rodilla: desplaza el estiramiento hacia el gemelo en lugar del sóleo.","- Mantenga: mantenga el estiramiento durante 20 a 30 segundos, respirando profundamente.","### Consejos para una forma adecuada","- Mantenga el talón firmemente plantado para maximizar el estiramiento.","- Evite dejar que la rodilla colapse hacia adentro; Síguelo sobre los dedos de los pies.","- Mantenga una postura erguida para evitar tensiones en la zona lumbar.","- Forzar la rodilla hacia adelante puede causar molestias en la articulación del tobillo.","- Torcer el pie: reduce la participación de los músculos específicos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2ecaf73a-c0de-4e80-babe-2ecaf73a0000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Feet-and-Ankle-Rotation.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6eeab898-c0de-4e80-babe-6eeab8980000', 'Estiramiento', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Calves-Stretch-Static-Position.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('23e7bc86-c0de-4e80-babe-23e7bc860000', 'Estiramiento de pie', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Standing-Toe-Up-Achilles-Stretch.gif', '{"- Configuración: Párese frente a un escalón, plataforma o superficie elevada.","- Posición del pie: Coloque la punta de un pie en el borde del escalón y el otro pie un paso atrás, manteniendo el talón firmemente en el suelo. Mantenga los dedos de los pies apuntando hacia adelante.","- Inclínese hacia adelante: cambie el peso de su cuerpo hacia el pie elevado hasta que sienta un estiramiento a lo largo del tendón de Aquiles y la parte inferior de la pantorrilla.","- Cambiar de lado: Repita en la pierna opuesta.","### Errores comunes","- Doble ligeramente la rodilla: esto aumenta la concentración en el sóleo y al mismo tiempo estira el tendón de Aquiles.","- Doble ligeramente la rodilla para enfatizar el sóleo; manténgalo recto para una mayor afectación de los gastrocnemios.","- Dejar que el talón se levante: Elimina la tensión del tendón de Aquiles y la pantorrilla.","- Estiramiento excesivo: puede tensar el tendón de Aquiles; mantenlo suave.","- Mantenga el estiramiento: manténgalo durante 20 a 30 segundos, respirando profundamente.","### Consejos para una forma adecuada","- Mantenga el talón hacia abajo para mantener la eficacia del estiramiento.","- Mantenga el torso erguido para evitar tensión en la zona lumbar.","- Evite inclinarse excesivamente; aplique un estiramiento suave y controlado.","- Contener la respiración: Respirar profundamente ayuda a que los músculos se relajen.","- Alineación incorrecta de los dedos: los dedos deben apuntar hacia adelante para obtener el máximo beneficio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('40e7ba35-c0de-4e80-babe-40e7ba350000', 'Estiramiento de pie', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Standing-Toe-Flexor-Stretch.gif', '{"- Coloque el pie: Párese frente a la pared y coloque los dedos del pie que desea estirar contra ella.","- Avance: mueva suavemente su peso hacia adelante hasta que sienta un leve estiramiento en la pantorrilla o el tendón de Aquiles.","- Configuración: dirígete a una pared.","- Mantenga el estiramiento: mantenga la posición durante 30 segundos, respirando profundamente durante todo el ejercicio.","- Cambiar de lado: repita con el otro pie.","- Comience cerca de la pared y aumente gradualmente la distancia con el tiempo para obtener mayores ganancias de movilidad.","- Permita que la rodilla se desplace hacia adelante pero sin colapsar hacia adentro.","### Errores comunes","- El talón se levanta del suelo: reduce la eficacia del estiramiento.","- Dedos de los pies inclinados hacia afuera: cambia la mecánica del estiramiento.","- Anclar el talón: Mantenga el talón firmemente plantado en el suelo.","### Consejos para una forma adecuada","- Mantenga el talón hacia abajo en todo momento para garantizar un estiramiento adecuado de la dorsiflexión.","- Mantenga el movimiento lento y evite los rebotes.","- Estiramiento excesivo: puede provocar tensión en el tendón de Aquiles.","- Inclinarse con las caderas en lugar de doblar la rodilla reduce la participación de la dorsiflexión."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('51afb6c8-c0de-4e80-babe-51afb6c80000', 'Estiramiento', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Single-Leg-Calves-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4d63f24a-c0de-4e80-babe-4d63f24a0000', 'Sentadilla con barra', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/Barbell-Jump-Squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5886fc43-c0de-4e80-babe-5886fc430000', 'Elevaciones frontales con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Chest-Supported-Dumbbell-Front-Raises.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('48380914-c0de-4e80-babe-483809140000', 'Estiramiento', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Crouching-Heel-Back-Calf-Stretch.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7568a3e0-c0de-4e80-babe-7568a3e00000', 'Estiramiento de pie', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Standing-Gastrocnemius-Calf-Stretch.gif', '{"Párate frente al banco: Colócate frente a un banco, caja o plataforma elevada.","Coloque su pie: doble la rodilla y coloque el talón de un pie en el banco.","Sostenga los dedos de los pies: use una mano para agarrar los dedos de los pies.","Mantener la posición: Mantenga el estiramiento durante 20 a 30 segundos, respirando constantemente.","Doble ligeramente las caderas: inclínese un poco hacia adelante para lograr un mejor equilibrio.","Estiramiento: Extienda la rodilla doblada para realizar el estiramiento, luego tire suavemente los dedos de los pies hacia usted para estirar los músculos de la pantorrilla.","Cambiar de lado: Repita con la otra pierna."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('51778e9a-c0de-4e80-babe-51778e9a0000', 'Remo unilateral con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/One-Arm-Dumbbell-Upright-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('293a3046-c0de-4e80-babe-293a30460000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Leg-Scissors.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('597619f8-c0de-4e80-babe-597619f80000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Side-Bent.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7eb39c20-c0de-4e80-babe-7eb39c200000', 'Postura de yoga', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Double-Pigeon-Pose.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7ecbebc3-c0de-4e80-babe-7ecbebc30000', 'Press de pecho unilateral', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Single-Arm-Arnold-Press.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('454a0cbb-c0de-4e80-babe-454a0cbb0000', 'Press de pecho con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Dumbbell-Z-Press.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3c8e5a6b-c0de-4e80-babe-3c8e5a6b0000', 'Press de pecho con pesa rusa / kettlebell', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2023/06/Kettlebell-Clean-and-Press.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('69e9e865-c0de-4e80-babe-69e9e8650000', 'Estiramiento sentado', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Seated-Piriformis-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('211de87e-c0de-4e80-babe-211de87e0000', 'Elevación en polea', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/cable-y-raise.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('20ab9ede-c0de-4e80-babe-20ab9ede0000', 'Ejercicio', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/handstand-holds.gif', '{"- Parada de manos independiente: Ponte en posición de parada de manos y mantén el equilibrio sin ayuda.","- Coloque las manos en el suelo separadas a la altura de los hombros.","- Involucra tus hombros, core y glúteos para estabilizar la posición.","- Equilibre haciendo pequeños ajustes manuales si es necesario.","- Coloque los hombros sobre las manos: garantiza estabilidad y equilibrio.","- Descuidar la fuerza de la muñeca: las muñecas débiles pueden tener dificultades para soportar el peso corporal.","- Parada de manos asistida por la pared: frente a una pared, patee y use la pared para mantener el equilibrio.","- Levanta una pierna mientras mantienes el core apretado y los brazos rectos.","- Si pierde el equilibrio, meta la barbilla y gire hacia adelante para evitar lesiones.","- Entrene contra una pared primero: genera confianza y resistencia antes de pasar a la parada de manos independiente.","- Estire y movilice las muñecas, los hombros y el core.","- Realice planchas, flexiones de brazos y encogimientos de hombros para activar músculos clave.","- Baje una pierna a la vez hasta el suelo.","- Utilice los dedos para mantener el equilibrio: presionar el suelo con las yemas de los dedos ayuda a controlar el movimiento.","### Errores comunes a evitar","- Arquear la espalda baja: puede provocar pérdida del equilibrio y tensión en la columna.","- Doblar los brazos: reduce la estabilidad y aumenta el riesgo de colapso.","- Mantenga las piernas rectas y los dedos de los pies en punta.","- Concéntrese en la respiración lenta y controlada para mantenerse relajado.","### Consejos para una forma adecuada","- Mantenga su núcleo comprometido: evita que la espalda baja se arquee y mantiene la alineación.","- Apunte los dedos de los pies y apriete los glúteos: ayuda a mantener una línea recta.","- No involucrar al núcleo: conduce a problemas de alineación y equilibrio deficientes.","- Patear demasiado fuerte: aumenta la posibilidad de caerse."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('50e71443-c0de-4e80-babe-50e714430000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/handstand-walk.gif', '{"- Comience en una posición de flexión con los pies contra la pared.","### 2. Practica cambiar de peso","- Realizar parada de manos asistida por la pared durante 30 segundos.","- Tener suficiente fuerza en los hombros, movilidad de las muñecas y estabilidad central.","### 1. Comience con un paseo por la pared","- Mantenga la posición de parada de manos para controlar el equilibrio.","- Mientras está parado de manos, practique cambiar el peso de una mano a la otra para imitar el movimiento de caminar.","- Suba lentamente los pies por la pared mientras mueve las manos hacia la pared.","### 3. Utilice un observador o un tapete de seguridad","- Haz que un compañero te ayude o practica sobre una superficie blanda para evitar caídas.","### 4. Iniciar la caminata","- Comience inclinándose ligeramente hacia adelante, dejando que el impulso lo guíe.","- Mantenga una parada de manos independiente durante al menos 10 a 15 segundos","- Evite las prisas; Tome pasos pequeños y controlados para mantener el equilibrio.","- Avanza una mano a la vez, manteniendo la tensión central.","-","### 5. Céntrese en los pasos controlados"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('61da8978-c0de-4e80-babe-61da89780000', 'Ejercicio acostado', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Lying-Toe-Touches.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('336b8e43-c0de-4e80-babe-336b8e430000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Pike-Push-Up-Between-Chairs.gif', '{"- Coloque dos sillas o plataformas resistentes separadas un poco más que el ancho de los hombros.","- Coloque sus manos sobre las sillas y coloque sus pies en el suelo.","- Mire ligeramente hacia adelante para mantener una posición neutral del cuello.","- Empuja con las palmas de las manos para estirar los brazos y volver a la posición inicial.","- Asegúrese de que las sillas sean estables y no se muevan durante el movimiento.","- Doble los codos y baje la cabeza entre las sillas con un movimiento controlado.","- Baje lo más profundo posible mientras mantiene la forma adecuada.","- Involucre sus hombros y tríceps para completar el movimiento.","- Mantenga las caderas elevadas para que su cuerpo forme una V invertida.","- Mantenga su núcleo apretado y evite arquear la espalda baja.","- Repita hasta el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4b955568-c0de-4e80-babe-4b9555680000', 'Ejercicio', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Climbing-Monkey-Bars.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1674fb03-c0de-4e80-babe-1674fb030000', 'Giro ruso', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Supine-Spinal-Twist.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('295beb6e-c0de-4e80-babe-295beb6e0000', 'Sentadilla con barra', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Barbell-Pin-Squat.gif', '{"Coloque los imperdibles en una rejilla eléctrica justo debajo de la posición inferior de la sentadilla frontal. Coloca la barra sobre los alfileres.","Pase por debajo de la barra, asumiendo una posición frontal con los codos en alto y el pecho erguido.","Apoye su núcleo y coloque los pies separados al ancho de los hombros con los dedos ligeramente hacia afuera.","Conduce hacia arriba a través de tus talones, levantando la barra de los pasadores hasta que alcances una posición de pie completamente.","Baje la barra bajo control nuevamente sobre los pasadores para completar una repetición. Haga una breve pausa antes de la siguiente repetición.","Repita durante la cantidad deseada de repeticiones, manteniendo un núcleo fuerte y una postura erguida."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('189944b8-c0de-4e80-babe-189944b80000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Heel-Touch-Side-Kick-Squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('23b2c713-c0de-4e80-babe-23b2c7130000', 'Elevaciones laterales alterno con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Alternate-Dumbbell-Lateral-Raise.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('54b49e47-c0de-4e80-babe-54b49e470000', 'Estiramiento', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Back-Slaps-Wrap-Around-Stretch.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('03d72bbd-c0de-4e80-babe-03d72bbd0000', 'Remo', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2023/08/Reaction-Ball-Throw-Agility-Ball-Drill-.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2fbd5d3b-c0de-4e80-babe-2fbd5d3b0000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/ATG-Split-Squat.gif', '{"Párese en una postura larga y dividida con un pie hacia adelante y el otro extendido detrás de usted.","Presione con el pie delantero para volver a la posición inicial.","Configuración Párese en una postura dividida larga con un pie hacia adelante y el otro extendido detrás de usted. Mantenga el talón delantero plano sobre el suelo y el talón trasero elevado, descansando sobre los dedos de los pies.","Ejecución Comience el movimiento doblando ambas rodillas, bajando las caderas hacia abajo. Permita que la rodilla delantera se mueva hacia adelante sobre los dedos de los pies, manteniendo el talón firme. Simultáneamente, deje que la rodilla trasera caiga hacia abajo y hacia atrás, sintiendo un estiramiento a través de los flexores de la cadera. Vaya tan profundo como su movilidad lo permita mientras mantiene una buena postura. Presione con el pie delantero para regresar a la posición inicial. Repita de 8 a 12 repeticiones por pierna, manteniendo el control en todo momento.","Comience el movimiento doblando ambas rodillas y bajando las caderas hacia abajo.","Permita que su rodilla delantera avance sobre los dedos de los pies, manteniendo el talón apoyado en el suelo.","Al mismo tiempo, deje que la rodilla trasera caiga hacia abajo y hacia atrás, sintiendo un estiramiento a través de los flexores de la cadera.","Mantenga el talón delantero plano sobre el suelo y el talón trasero elevado, apoyado sobre los dedos de los pies.","Llega tan profundo como tu movilidad te lo permita manteniendo una buena postura."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('05b43cae-c0de-4e80-babe-05b43cae0000', 'Ejercicio con mancuernas', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2023/06/Dumbbell-Floor-Wipers.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
