INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('13b1e738-c0de-4e80-babe-13b1e7380000', 'Extensión de tríceps', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Hip-Extension-On-Bench.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
