INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0d5831b5-c0de-4e80-babe-0d5831b50000', 'Curl de piernas de pie en máquina', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Standing-Single-Leg-Curl-Machine.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('07cb5ab0-c0de-4e80-babe-07cb5ab00000', 'Aperturas de pecho con banda de resistencia', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Banded-Thigh-Fly.gif', '{"Con control, vuelve a juntar las piernas hasta la posición inicial.","Abre lentamente las piernas hacia afuera contra la resistencia de la banda.","Haga una pausa cuando sienta un estiramiento profundo en la parte interna de los muslos.","Repita de 10 a 15 repeticiones para tres series."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2566bf8c-c0de-4e80-babe-2566bf8c0000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Pistol-Squat-to-Box.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4aee1155-c0de-4e80-babe-4aee11550000', 'Ejercicio con banda de resistencia', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2023/06/Banded-Shoulder-External-Rotation.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7cf39b9e-c0de-4e80-babe-7cf39b9e0000', 'Ejercicio con banda de resistencia', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2023/06/Banded-Shoulder-Adduction.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('51e88327-c0de-4e80-babe-51e883270000', 'Extensión de tríceps con banda de resistencia', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2023/06/Banded-Shoulder-Extension.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7288de24-c0de-4e80-babe-7288de240000', 'Ejercicio con banda de resistencia', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2023/06/Banded-Shoulder-Flexion.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('73450f38-c0de-4e80-babe-73450f380000', 'Ejercicio', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Single-Knee-To-Chest-Stretch.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5c1d0d20-c0de-4e80-babe-5c1d0d200000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Frog-Pump.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('74980d9c-c0de-4e80-babe-74980d9c0000', 'Peso muerto', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Landmine-Deadlift.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7e0be57b-c0de-4e80-babe-7e0be57b0000', 'Remo', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/t-bar-rows.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5bfe0af4-c0de-4e80-babe-5bfe0af40000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2023/04/1-2-Stick-Drill-Plyometrics.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4b653aa9-c0de-4e80-babe-4b653aa90000', 'Patada de tríceps en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Low-Cable-Tricep-Kickback.gif', '{"- Coloque una empuñadura monomando en la polea inferior de una máquina de cable.","- Seleccione un peso de ligero a moderado para mantener el control.","- Párese frente a la máquina de cable, sujetando el mango con una mano.","- Regrese lentamente a la posición inicial, manteniendo la tensión en los tríceps.","### Paso 1: configuración","- Da un paso atrás y gira las caderas para que tu torso quede ligeramente inclinado hacia adelante.","### Paso 2: Ejecución","- Extienda el brazo hacia atrás, enderezando completamente el codo mientras mantiene la parte superior del brazo inmóvil.","- Aprieta tus tríceps en la parte superior del movimiento.","- Repita el movimiento durante el número deseado de repeticiones antes de cambiar de brazo.","- Mantenga el codo cerca del torso y dóblelo en un ángulo de 90 grados.","### Repeticiones y Series:","- Principiantes: 3 series de 10 repeticiones por brazo","- Intermedio: 3 a 4 series de 12 repeticiones por brazo","- Avanzado: 4 series de 15 repeticiones por brazo"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4fba0899-c0de-4e80-babe-4fba08990000', 'Curl de bíceps con banda de resistencia', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Band-Biceps-Curl.gif', '{"Sujete el peso (mancuerna, barra o polea) con un agarre supino (palmas hacia arriba).","Mantenga los pies separados al ancho de los hombros y las rodillas ligeramente flexionadas.","Coloque los codos pegados a los costados del torso y mantenga la espalda recta.","Manteniendo inmóvil la parte superior de los brazos, flexione los codos y eleve la carga hacia los hombros.","Apriete fuertemente los bíceps en el punto de máxima contracción por un segundo.","Baje el peso de forma controlada y lenta hasta extender completamente los brazos.","Evite balancear la espalda o mover los hombros hacia adelante para ayudarse.","Mantenga las muñecas firmes y rectas durante todo el recorrido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('03901507-c0de-4e80-babe-039015070000', 'Sentadilla con pesa rusa / kettlebell', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Kettlebell-front-squat.gif', '{"Párese con los pies separados a la altura de los hombros, sosteniendo una pesa rusa en cada mano en la posición frontal cerca de la clavícula.","Conduce sobre tus talones para volver a la posición inicial. Repita para el número deseado de repeticiones.","Desciende hasta que tus muslos queden al menos paralelos al suelo, manteniendo el pecho hacia arriba y la espalda plana.","Empuje las caderas hacia atrás y doble las rodillas para ponerse en cuclillas.","Mantenga los codos doblados y las muñecas neutrales mientras ejercita su núcleo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('570c326e-c0de-4e80-babe-570c326e0000', 'Remo sentado en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Single-Arm-Twisting-Seated-Cable-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('27ead194-c0de-4e80-babe-27ead1940000', 'Jalón al pecho con banda de resistencia', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Band-Alternating-Lat-Pulldown.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('29b68bbf-c0de-4e80-babe-29b68bbf0000', 'Remo con banda de resistencia', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Band-Alternating-Low-Row-with-Twist.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('56ba4419-c0de-4e80-babe-56ba44190000', 'Remo de pie en polea', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Cable-Twisting-Standing-high-Row.gif', '{"Este ejercicio, realizado con máquina de cables o banda de resistencia, es un ejercicio compuesto que trabaja todos los músculos de la espalda.","El movimiento de rotación en este ejercicio hace que trabajen muchos grupos de músculos. A medida que gira su cuerpo, sus piernas toman más fuerza de sus glúteos para sostener su cuerpo. Mientras tanto, permite que trabajen los músculos de la cadera, los aductores y muchos grupos de músculos más pequeños y profundos. Mientras está de pie, tanto la rotación de la columna como la rotación de la cadera contribuyen a la rotación del cuerpo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('367160bc-c0de-4e80-babe-367160bc0000', 'Press de pecho inclinado con banda de resistencia', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Band-Alternate-Incline-Chest-Press-.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('040d815f-c0de-4e80-babe-040d815f0000', 'Ejercicio con banda de resistencia', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Band-Skull-Crusher.gif', '{"- Acuéstese sobre una superficie plana (como un banco, una colchoneta o el piso) con la cabeza colocada cerca del punto de anclaje.","- Agarre la banda con ambas manos, manteniendo las palmas hacia arriba.","- Extiende tus brazos nuevamente a la posición inicial, apretando tus tríceps en la parte superior.","### Paso 1: configuración","- Asegure una banda de resistencia a un punto de anclaje resistente cerca del suelo.","- Extienda los brazos hacia arriba para que haya una ligera tensión en la banda.","### Paso 2: Ejecución","- Doble los codos lentamente y lleve las manos hacia la frente.","- Una vez que tus manos estén cerca de tu cabeza, haz una pausa y siente el estiramiento de tus tríceps.","- Mantenga la parte superior de los brazos inmóviles; solo deben moverse los antebrazos.","- Repita para el número deseado de repeticiones.","### Repeticiones y Series:","- Principiantes: 3 series de 10 repeticiones","- Intermedio: 3 a 4 series de 12 repeticiones","- Avanzado: 4 series de 15 repeticiones"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('213e7218-c0de-4e80-babe-213e72180000', 'Press de hombros unilateral con banda de resistencia', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Band-Single-Arm-Shoulder-Press.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2e5501a3-c0de-4e80-babe-2e5501a30000', 'Ejercicio sentado con banda de resistencia', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Band-Seated-Hip-External-Rotation.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('667a5771-c0de-4e80-babe-667a57710000', 'Ejercicio sentado con banda de resistencia', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Band-Seated-Hip-Internal-Rotation.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('299e58ba-c0de-4e80-babe-299e58ba0000', 'Remo sentado con banda de resistencia', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Band-Seated-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('560ad5ef-c0de-4e80-babe-560ad5ef0000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Landmine-Squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1e93d934-c0de-4e80-babe-1e93d9340000', 'Curl martillo con mancuernas', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Single-Dumbbell-Spider-Hammer-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('58da5729-c0de-4e80-babe-58da57290000', 'Press de pecho con mancuernas', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Dumbbell-Tate-Press.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6385cd2c-c0de-4e80-babe-6385cd2c0000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/08/barbell-rack-pull.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('41495cf5-c0de-4e80-babe-41495cf50000', 'Remo con barra', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Barbell-Pendlay-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7800e34d-c0de-4e80-babe-7800e34d0000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Fire-Hydrant.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('299aa4ff-c0de-4e80-babe-299aa4ff0000', 'Extensión de tríceps declinado con mancuernas', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Decline-Dumbbell-Triceps-Extension.gif', '{"- Acuéstese en un banco inclinado con los pies asegurados debajo de las almohadillas para los pies.","- Sostenga una mancuerna en cada mano con un agarre neutral (con las palmas una frente a la otra).","- Invierte el movimiento extendiendo los codos y presionando las mancuernas hasta la posición inicial.","### Configuración","- Extienda los brazos completamente por encima del pecho con una ligera flexión de los codos.","### Ejecución","- Mientras mantiene la parte superior de los brazos perpendicular al suelo, doble los codos lentamente para bajar las mancuernas hacia los lados de la cabeza.","- Baje hasta que sienta un estiramiento profundo en el tríceps.","- Mantenga los codos fijos en su lugar y no permita que se abran hacia afuera.","- Repita hasta obtener el número deseado de repeticiones.","### Repeticiones y series","- Principiantes: 3 series de 8 a 10 repeticiones","- Intermedio a avanzado: 3 a 4 series de 10 a 15 repeticiones"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('17a58444-c0de-4e80-babe-17a584440000', 'Estiramiento', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Piriformis-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6785a7af-c0de-4e80-babe-6785a7af0000', 'Elevación', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Step-up.gif', '{"El paso hacia arriba con elevación de rodillas es un ejercicio eficaz para la parte inferior del cuerpo que apunta a las caderas, los cuádriceps y los isquiotibiales. Los ejercicios con peso corporal son muy buenos para desarrollar músculos y fuerza, además de mejorar la coordinación y la condición física.","Subir con elevación de rodillas es un ejercicio adecuado para principiantes. Puede ayudar a fortalecer los músculos de las piernas, tensar los músculos de la cadera y quemar calorías para perder peso."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('59619416-c0de-4e80-babe-596194160000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2023/07/Handstand-Push-ups-Between-Benches.gif', '{"- Coloque dos bancosColoque dos bancos resistentes o paralelos separados al ancho de los hombros. Asegúrese de que haya suficiente espacio para que su cabeza descienda entre los bancos.","- Coloque dos bancos resistentes o paralelas separados a la altura de los hombros.","- Encuentre un soporte de pared estable cerca de una pared resistente que apoye sus pies.","- Párese cerca de una pared resistente que apoye sus pies.","- Colocación de las manos Coloque las manos de forma segura en cada banco, asegurando un agarre firme para evitar resbalones.","- Coloque sus manos de forma segura en cada banco, asegurándose de un agarre firme para evitar resbalones.","- Patada para hacer el pino Patada contra la pared, manteniendo el core apretado y las piernas rectas. Asegúrate de que tu cuerpo esté alineado en una posición neutral.","- Empuje hacia arriba Involucre sus hombros y tríceps para presionar hacia atrás a la posición inicial. Mantenga una posición del cuerpo recta, evitando arquear excesivamente.","- Involucra tus hombros y tríceps para volver a la posición inicial.","- Coloque las manos al ancho de los hombros para mantener una mecánica de presión adecuada.","- Asegúrese de que haya suficiente espacio para que su cabeza descienda entre los bancos.","- Patea contra la pared, manteniendo el core apretado y las piernas rectas.","- Asegúrese de que su cuerpo esté alineado en una posición neutral.","- Mantenga una posición del cuerpo recta, evitando arquearse excesivamente.","- Repita para las repeticiones deseadas Realice de 3 a 5 series de 4 a 10 repeticiones, según el nivel de fuerza.","- Baje el cuerpo Doble los codos lentamente y bajo control hasta que la cabeza se mueva por debajo del nivel de las manos. Mantenga los codos en un ángulo de 45 grados para reducir la tensión en los hombros.","- Doble los codos lentamente y bajo control hasta que su cabeza se mueva por debajo del nivel de sus manos.","- Baje lentamente para maximizar la activación muscular y evitar lesiones.","- Realice de 3 a 5 series de 4 a 10 repeticiones, según el nivel de fuerza.","- Involucre su núcleo para mantener su cuerpo alineado y evitar arquearse.","- Utilice un observador o tapetes cuando aprenda por seguridad.","### Errores comunes a evitar","- Dejar que la parte baja de la espalda se arquee: un compromiso débil del core puede provocar una mala forma y lesiones.","- Bajar demasiado rápido: el control es clave para la participación y la seguridad de los músculos.","- Mantenga los codos en un ángulo de 45 grados para reducir la tensión en los hombros.","### Consejos para una forma adecuada","- Mantenga los codos en un ángulo controlado para reducir la tensión en los hombros.","- Colocar las manos demasiado separadas: la colocación inadecuada de las manos reduce la eficiencia de la presión.","- No calentar los hombros: aumenta el riesgo de lesiones.","- Depender demasiado de la pared: si bien la pared ayuda con el equilibrio, inclinarse excesivamente limita el aumento de fuerza."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('35b8178c-c0de-4e80-babe-35b8178c0000', 'Ejercicio de pie', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/STANDING-KNEE-HUGS.gif', '{"El propósito de abrazar las rodillas es estirar las piernas y los glúteos. Este ejercicio también estirará los músculos isquiotibiales y cuádriceps.","Antes de comenzar con el entrenamiento de piernas, puedes aplicar este ejercicio después de los ejercicios de calentamiento para estirar las piernas. De este modo, los músculos de las piernas se volverán más flexibles ante las lesiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2598a2a5-c0de-4e80-babe-2598a2a50000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/SNAP-JUMPS.gif', '{"Los saltos rápidos se dirigen a los músculos abdominales, los músculos de la cadera y los flexores de la cadera y también trabajan los muslos, los tendones de las rodillas, los cuádriceps y los hombros.","Los saltos rápidos son un ejercicio pliométrico. Los ejercicios pliométricos son movimientos aeróbicos explosivos que aumentan la velocidad, la rapidez y la potencia y trabajan todo el cuerpo.","Los saltos rápidos son beneficiosos para la salud porque combinan el acondicionamiento cardiovascular con el trabajo de fuerza. Dado que los saltos rápidos elevan su frecuencia cardíaca, también pueden mejorar su condición cardiovascular."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('31a9a277-c0de-4e80-babe-31a9a2770000', 'Estiramiento de rodillas', 'Piernas', '', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('102aecad-c0de-4e80-babe-102aecad0000', 'Ejercicio con barra', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/12/Barbell-Glute-Bridge.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('49a77ff3-c0de-4e80-babe-49a77ff30000', 'Extensión de tríceps en polea', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Cable-Hip-Extension.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5aa95818-c0de-4e80-babe-5aa958180000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2023/07/kipping-handstand-push-up.gif', '{"- Encuentre una pared resistente Utilice una superficie plana y estable que pueda soportar su peso corporal.","- Utilice una superficie plana y estable que pueda soportar su peso corporal.","- Colocación de las manos Coloque las manos a la altura de los hombros, a una distancia de entre 6 y 12 pulgadas de la pared.","- Coloque las manos a la altura de los hombros, a una distancia de entre 6 y 12 pulgadas de la pared.","- Ponte en posición de parada de manos Ponte en posición de parada de manos, manteniendo el core comprometido y los pies juntos.","- Ponte en posición de parada de manos, manteniendo el núcleo enganchado y los pies juntos.","- Explota hacia arriba con un impulso de piernas Extiende las piernas con fuerza mientras empujas con los brazos al mismo tiempo. Usa el impulso para impulsar tu cuerpo de regreso a la posición inicial.","- Utilice el impulso para impulsar su cuerpo de regreso a la posición inicial.","- Baje a la posición inferior Baje su cuerpo bajo control hasta que la parte superior de su cabeza toque ligeramente el piso o una colchoneta. Mantenga los codos en un ángulo de 45 grados para proteger los hombros.","- Baja tu cuerpo bajo control hasta que la parte superior de tu cabeza toque ligeramente el suelo o una colchoneta.","- Inicie el Kip. Cuando llegue a la posición inferior, lleve las rodillas hacia el pecho en una posición doblada.","- Cuando llegue a la posición inferior, lleve las rodillas hacia el pecho en una posición doblada.","- Extiende las piernas con fuerza mientras empujas con los brazos al mismo tiempo.","- Utilice un tapete para proteger la cabeza: un tapete acolchado debajo de la cabeza ayuda a reducir el riesgo de impactos y lesiones.","- Bloqueo en la parte superior Extienda completamente los codos y mantenga una posición firme de parada de manos antes de repetir el movimiento.","- Extienda completamente los codos y mantenga una posición fuerte de parada de manos antes de repetir el movimiento.","- Sincronización de Kip ineficiente: si el impulso de las piernas no está sincronizado con el empuje, el movimiento se vuelve menos efectivo.","- Riesgo de compresión del cuello y la columna: una mala forma o un arqueo excesivo pueden generar tensión en la columna cervical. Utilice siempre movimientos controlados y considere colocar algo acolchado debajo de la cabeza.","- No es ideal para obtener pura fuerza: si el objetivo es la fuerza máxima, las HSPU estrictas, las flexiones de brazos o los press de hombros son mejores opciones.","- Involucre su núcleo: un núcleo apretado mejora el equilibrio y evita arquearse excesivamente.","- Conduce explosivamente con las caderas: maximiza la potencia coordinando el impulso de tus piernas y caderas con la prensa de brazos.","### Errores comunes a evitar","- No controlar la fase de descenso: caer demasiado rápido aumenta el riesgo de lesiones en la cabeza y el cuello.","- Ampliar la zona lumbar: un núcleo débil conduce a una mala postura y a una reducción de la eficiencia de la presión.","- Depender demasiado del impulso: si bien dar kipping reduce la fatiga, depender completamente del impulso limita las ganancias de fuerza.","- Mantenga los codos en un ángulo de 45 grados para proteger los hombros.","### Consejos para una forma adecuada","- Controle el descenso: evite caer demasiado rápido para reducir la tensión en el cuello y los hombros.","- Mantenga una colocación constante de las manos: las manos demasiado lejos o demasiado cerca de la pared pueden provocar inestabilidad y pérdida de control.","- Colocar las manos demasiado abiertas o demasiado cerca: la colocación incorrecta de las manos puede provocar una mecánica de presión inestable.","### Consideraciones y precauciones","- Requisito de estabilidad del hombro: las personas que carecen de estabilidad o fuerza en el hombro deben dominar primero las HSPU estrictas antes de incorporar los kipping para evitar lesiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('797a34c4-c0de-4e80-babe-797a34c40000', 'Ejercicio en polea', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Cable-Hip-Abduction.gif', '{"El foco de este ejercicio está en el glúteo medio y el glúteo menor que se encuentra debajo. Si el objetivo es fortalecer y dar forma a la cadera (glúteos superiores y externos), entonces las abducciones de cadera con cable son una excelente opción."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1ca720a3-c0de-4e80-babe-1ca720a30000', 'Elevación inclinado con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Bent-Over-Dumbbell-Rear-Delt-Raise-With-Head-On-Bench.gif', '{"El levantamiento del deltoides trasero inclinado con mancuernas y la cabeza apoyada en el banco es un ejercicio de pesas libres que se dirige principalmente a los hombros traseros. Es un ejercicio eficaz que puedes incluir en tu programa para aislar los músculos posteriores del hombro y fortalecer los músculos del manguito rotador."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('42f44e9b-c0de-4e80-babe-42f44e9b0000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Donkey-Kicks.gif', '{"El músculo principal que involucra la patada de burro es el glúteo máximo. Es uno de los mejores ejercicios sin equipo que puedes incluir en tus entrenamientos para tensar y tonificar los glúteos, mejorar la movilidad de la cadera y fortalecer la zona lumbar."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1fa1462d-c0de-4e80-babe-1fa1462d0000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/High-Knee-Run.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('78b7872b-c0de-4e80-babe-78b7872b0000', 'Elevaciones laterales', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Side-Plank-Leg-Raises.gif', '{"Los levantamientos de piernas en plancha lateral son un ejercicio básico simple pero eficaz que le ayuda a desarrollar estabilidad y fuerza en todo el cuerpo.","Los levantamientos de piernas en plancha lateral desarrollan el núcleo, los oblicuos, las piernas, las caderas y los hombros. También es un ejercicio corporal que favorece el aumento de resistencia y fuerza.","El levantamiento de piernas en plancha lateral trabaja más del 40 por ciento de los músculos superiores e inferiores de la espalda. En este ejercicio, los músculos centrales se contraen isométricamente para proteger la columna lumbar de las fuerzas de rotación y flexión. Mantener estos músculos fuertes puede ayudar a reducir el riesgo de sufrir una lesión en la espalda."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5bf1ecbb-c0de-4e80-babe-5bf1ecbb0000', 'Ejercicio con banda de resistencia', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Band-Pushdown.gif', '{"- Configuración Asegure una banda de resistencia a un punto de anclaje elevado, como una puerta o una barra de dominadas. Párese frente al punto de anclaje y sostenga la banda con ambas manos usando un agarre neutral o en pronación. Coloque los pies separados al ancho de los hombros y mantenga las rodillas ligeramente dobladas.","- Párese frente al punto de anclaje y sostenga la banda con ambas manos usando un agarre neutral o en pronación.","- Coloque los pies separados a la altura de los hombros y mantenga las rodillas ligeramente dobladas.","- Posición inicial Acerque los codos a los costados con los antebrazos paralelos al suelo. Las manos deben estar cerca del nivel del pecho y la parte superior de los brazos inmóviles durante todo el ejercicio.","- Regrese lentamente a la posición inicial con control.","- Exhala mientras presionas hacia abajo e inhala mientras regresas a la posición inicial.","- Asegure una banda de resistencia a un punto de anclaje elevado, como una puerta o una barra de dominadas.","- Acerque los codos a los costados con los antebrazos paralelos al suelo.","- Tus manos deben estar cerca del nivel del pecho y la parte superior de tus brazos inmóviles durante todo el ejercicio.","- EjecuciónPresione la banda hacia abajo extendiendo los codos hasta que los brazos queden rectosApriete los tríceps en la parte inferior del movimientoRegrese lentamente a la posición inicial con controlRepita durante el número deseado de repeticiones","- Aprieta tus tríceps en la parte inferior del movimiento.","- No permita que sus hombros se eleven o se doblen hacia adelante.","- Involucre su núcleo para evitar el movimiento excesivo del cuerpo.","- Dejar que la tensión en la banda se afloje durante el movimiento.","- Presione la banda hacia abajo extendiendo los codos hasta que los brazos queden rectos.","- Muévase lenta y deliberadamente para mantener una tensión constante en la banda.","### Errores comunes","- Permitir que los codos se separen del torso.","- Usar impulso o balanceo del cuerpo para presionar la banda hacia abajo","- Repetir hasta el número deseado de repeticiones.","### Consejos para una forma adecuada","- Mantenga los codos pegados a los costados para aislar completamente los tríceps.","- Redondear los hombros o extender demasiado las muñecas","- Inclinarse demasiado hacia adelante o hacia atrás"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4de9a3bd-c0de-4e80-babe-4de9a3bd0000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Double-Crunches.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4e8c2434-c0de-4e80-babe-4e8c24340000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Sit-ups.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7f43d0e9-c0de-4e80-babe-7f43d0e90000', 'Plancha', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Reverse-Plank-Kicks.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4c8b753d-c0de-4e80-babe-4c8b753d0000', 'Estiramiento', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/INNER-THIGH-SIDE-STRETCH.gif', '{"El grupo de aductores se encuentra en el interior de la pierna y está formado por el pectíneo, el aductor corto, el aductor largo, el aductor mayor y el gracilis. La mejor manera de mantener estos músculos relajados y flexibles es incluyendo estiramientos dinámicos en tu calentamiento y estiramientos estáticos en tu rutina de vuelta a la calma. Estirar los aductores con regularidad puede mejorar su flexibilidad y rendimiento, y también prevenir lesiones y rigidez.","El estiramiento dinámico previo al entrenamiento mejora la circulación, prepara los músculos para el movimiento y aumenta temporalmente su rango de movimiento."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0b1e7d71-c0de-4e80-babe-0b1e7d710000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/High-Knee-Skips_Cardio.gif', '{"Puedes utilizar este ejercicio tanto como calentamiento dinámico antes de entrenar como añadirlo a tu rutina de entrenamiento cardiovascular para quemar grasa.","Los saltos de rodilla altos apuntan a los músculos oblicuos, de las piernas, de la cadera y de los flexores de la cadera y también trabajan los muslos, los tendones de las rodillas, los cuádriceps y los hombros.","Los saltos con las rodillas altas son un ejercicio pliométrico. Los ejercicios pliométricos son movimientos aeróbicos explosivos que aumentan la velocidad, la rapidez y la potencia y trabajan todo el cuerpo.","Los saltos son beneficiosos para la salud porque combinan el acondicionamiento cardiovascular con el trabajo de fuerza. Dado que los saltos elevan tu frecuencia cardíaca, también pueden mejorar tu condición cardiovascular."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6cf60cd7-c0de-4e80-babe-6cf60cd70000', 'Aperturas de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Butterfly-Stretch.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('19486e47-c0de-4e80-babe-19486e470000', 'Plancha', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/PLANK-KNEE-TO-ELBOW.gif', '{"Plancha de rodilla a codo es un ejercicio cardiovascular y de fortalecimiento central eficaz. Puede ayudarle a fortalecer y desarrollar los músculos de la parte superior e inferior del cuerpo.","Al ser un movimiento multifuncional, este ejercicio se dirige no solo a los músculos abdominales sino también a la columna y los glúteos. Plank fortalece y tonifica todo el cuerpo, mejora la postura y el equilibrio, reduce la grasa corporal y puede ayudar a acelerar el metabolismo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('258753c2-c0de-4e80-babe-258753c20000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Half-Wipers.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('118fe751-c0de-4e80-babe-118fe7510000', 'Plancha', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Plank-Leg-Lift.gif', '{"El levantamiento de piernas en plancha es un ejercicio eficaz que aumenta la estabilidad en las zonas de la columna, el core y la cadera al proporcionar una contracción isométrica. Puedes agregarlo a tus entrenamientos para dar forma y fortalecer los músculos de la cadera, el tronco y las piernas.","Como movimiento multifuncional, el levantamiento de piernas en plancha no solo apunta a los músculos abdominales sino también a la columna y la cadera. El levantamiento de piernas en plancha fortalece y tonifica todo el cuerpo, mejora la postura y el equilibrio, reduce la grasa corporal y puede ayudar a acelerar el metabolismo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('140205b2-c0de-4e80-babe-140205b20000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Skater.gif', '{"El ejercicio del patinador es un ejercicio cardiovascular pliométrico que implica saltar en un patrón que cambia el peso del cuerpo de un lado a otro para crear una zancada de patinaje. Si bien aumenta principalmente la potencia de las piernas, se considera un entrenamiento dinámico para todo el cuerpo, ya que también trabaja el core, el glúteo medio y los aductores de las articulaciones de la cadera.","El patinador es un ejercicio adecuado para principiantes. Puede ayudar a fortalecer los músculos de las piernas, tensar los músculos de la cadera y quemar calorías para perder peso.","El ejercicio del patinador se clasifica como un ejercicio aeróbico eficaz que ayuda a fortalecer el corazón y aumentar la fuerza y ​​resistencia muscular. También le ayuda a mejorar su rendimiento físico general, incluida la fuerza, la velocidad, la condición física y la flexibilidad."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2f02cb3d-c0de-4e80-babe-2f02cb3d0000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Long-Arm-Crunch.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3488c06a-c0de-4e80-babe-3488c06a0000', 'Plancha abdominal', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/plank.gif', '{"No redondees ni dobles la espalda. Mantenga su pelvis en una posición neutral.","Baje los omóplatos, activando los músculos dentados anteriores y las partes inferiores de los músculos trapecios.","Mantenga la columna neutra; participar en la “estabilización abdominal” tirando de los músculos abdominales.","No se encorve ni se encorve. Mantenga el pecho plano y los omóplatos planos.","No contengas la respiración. Respira libre y naturalmente."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6bbb4e81-c0de-4e80-babe-6bbb4e810000', 'Giro ruso', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Russian-Twist.gif', '{"Siéntate en el suelo con las rodillas dobladas y los pies apoyados en el suelo.","Junte las manos frente a usted o sostenga una pesa o un balón medicinal con ambas manos. Esto añade resistencia al ejercicio.","Gira el torso hacia un lado, llevando el peso o las manos al lado de la cadera. Mantenga su núcleo comprometido durante todo el movimiento.","Regrese al centro y luego gire hacia el otro lado.","Inclínese ligeramente hacia atrás para que la parte superior de su cuerpo forme una V con sus muslos. Mantenga la espalda recta y active los músculos centrales.","Repita el movimiento de torsión de lado a lado durante el número deseado de repeticiones o tiempo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5e23ad2e-c0de-4e80-babe-5e23ad2e0000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Jackknife-Sit-ups.gif', '{"Trabaja todos los músculos abdominales: el ejercicio de abdominales en navaja se dirige al recto abdominal y a los músculos oblicuos. Son una excelente manera de tensar los abdominales inferiores y ayudarlo a obtener abdominales marcados. Es un ejercicio beneficioso para perder grasa y tonificar ya que tiene un efecto intenso sobre los músculos oblicuos.","Mientras fortaleces tus músculos abdominales, también fortaleces tus flexores de cadera. Cuando te sientas completamente y levantas las piernas hacia las manos, los flexores de la cadera se activan y ayudan. Esto es excelente para trabajar los abdominales inferiores y los flexores de la cadera. Fortalecer su núcleo le ayudará tanto con los deportes como con las actividades diarias. Además, los V-ups fomentan una buena postura y te ayudan a practicar la extensión de la columna."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('00004ff7-c0de-4e80-babe-00004ff70000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Flutter-Kicks.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6a306ecf-c0de-4e80-babe-6a306ecf0000', 'Zancadas con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/09/dumbbell-forward-leaning-lunge.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('21390f7e-c0de-4e80-babe-21390f7e0000', 'Sentadilla con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/09/Dumbell-Pistol-Squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('19cb342a-c0de-4e80-babe-19cb342a0000', 'Ejercicio de pie', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/09/standing-side-bend.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('620f5bac-c0de-4e80-babe-620f5bac0000', 'Press de pecho inclinado', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Incline-Close-Grip-Bench-Press.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4dbb5451-c0de-4e80-babe-4dbb54510000', 'Curl de bíceps', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Z-Bar-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5e9f6323-c0de-4e80-babe-5e9f63230000', 'Curl de muñeca', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Reverse-Wrist-Curl.gif', '{"Es un ejercicio muy eficaz para mejorar la musculatura del antebrazo y la muñeca. Si fortaleces las muñecas y los antebrazos podrás levantar más peso mientras realizas otros ejercicios.","La razón por la que no puede levantar el peso del cuerpo puede deberse a la debilidad de las muñecas y los brazos. Agregar ejercicios de muñeca y antebrazo a su programa de entrenamiento creará flexores de muñeca fuertes."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('77da76d8-c0de-4e80-babe-77da76d80000', 'Curl de muñeca', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/barbell-Wrist-Curl.gif', '{"Es un ejercicio muy eficaz para mejorar la musculatura del antebrazo y la muñeca. Si fortaleces las muñecas y los antebrazos podrás levantar más peso mientras realizas otros ejercicios.","La razón por la que no puede levantar el peso del cuerpo puede deberse a la debilidad de las muñecas y los brazos. Agregar ejercicios de muñeca y antebrazo a su programa de entrenamiento creará flexores de muñeca fuertes."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4ba6680e-c0de-4e80-babe-4ba6680e0000', 'Zancadas con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/09/Dumbell-reverse-lunge.gif', '{"Párate erguido con los pies separados a la altura de las caderas y el core comprometido.","Empuja con el pie delantero para volver a la posición inicial.","Sostenga una mancuerna en cada mano, con los brazos completamente extendidos a los lados y las palmas hacia adentro.","Da un paso con una pierna hacia atrás y baja el cuerpo doblando ambas rodillas hasta que la rodilla trasera quede justo por encima del suelo.","Mantenga el torso erguido y el talón delantero apoyado en el suelo mientras desciende.","Repita con la pierna opuesta, alternando o completando todas las repeticiones en un lado."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5e70ba80-c0de-4e80-babe-5e70ba800000', 'Ejercicio en máquina', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/HiP-ABDUCTION-MACHINE.gif', '{"Es eficaz para el desarrollo de los músculos de la cadera y los músculos internos y externos del muslo. La máquina Abduktor es popular entre las mujeres porque permite influir activamente en la forma de la cadera. Puedes incluirlo en tus programas de entrenamiento para moldear y tensar los músculos de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('25974b9a-c0de-4e80-babe-25974b9a0000', 'Remo con barra', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/barbell-uprightrow.gif', '{"El remo vertical con barra es un ejercicio de la parte superior del cuerpo que se dirige predominantemente al trapecio y los deltoides, que son responsables de agregar ancho a los hombros. Por lo general, se realiza utilizando una barra estándar o una barra EZ.","El remo vertical con barra es uno de los ejercicios efectivos para construir trampas más grandes, pero también es un movimiento en el que es fácil cometer errores. Una de las formas más sencillas de asegurarse de que su forma sea óptima es evitar el uso de barras que sean demasiado pesadas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('429c4792-c0de-4e80-babe-429c47920000', 'Patada de tríceps inclinado', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Bent-Over-Triceps-Kickback.gif', '{"- Párate con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano.","- Desde esta posición inicial, extiende los antebrazos hacia atrás estirando los codos.","- Regrese lentamente a la posición inicial doblando los codos.","###","### Configuración","- Gire las caderas y doble ligeramente las rodillas, manteniendo la espalda plana y el pecho erguido.","- Deje que sus brazos cuelguen naturalmente, luego levante los codos para que la parte superior de sus brazos quede paralela a su torso. Tus codos deben permanecer cerca de tus costillas.","### Ejecución","- Concéntrate en apretar los tríceps en la parte superior del movimiento.","- Haga una pausa breve en extensión completa sin bloquear los codos.","- Repita para el número deseado de repeticiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('66808fad-c0de-4e80-babe-66808fad0000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Bodyweight-Bulgarian-Split-Squat.gif', '{"- Párese a unos dos pies frente a un banco o plataforma resistente.","- Extienda el pie trasero hacia atrás y coloque la parte superior del pie sobre el banco.","- Presione con el talón delantero para volver a la posición inicial.","### Paso 1: configuración y posicionamiento","### Paso 2: Ejecución","- Baje la rodilla trasera hacia el suelo doblando la rodilla delantera.","- Desciende hasta que tu muslo delantero quede paralelo al suelo o ligeramente por debajo.","- Mantenga el pecho erguido y el núcleo comprometido.","- Repita para las repeticiones deseadas antes de cambiar de pierna."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2992edcc-c0de-4e80-babe-2992edcc0000', 'Press de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Hammer-Press.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1c8e4ca6-c0de-4e80-babe-1c8e4ca60000', 'Press de pecho en máquina', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Chest-Press-Machine.gif', '{"La máquina de press de pecho es un ejercicio preferido por los principiantes ya que se centra en todos los músculos pectorales y proporciona una mayor estabilidad. Dirigido a los pectorales, tríceps y deltoides, el ejercicio con máquina de prensa de pecho ayuda a desarrollar la fuerza de la parte superior del cuerpo y aumentar la masa muscular."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4e14129f-c0de-4e80-babe-4e14129f0000', 'Extensión de piernas sentado con banda de resistencia', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Seated-Banded-Leg-Extension.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('289cffbf-c0de-4e80-babe-289cffbf0000', 'Plancha', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Side-Plank-Knee-to-Elbow-.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('55c115ad-c0de-4e80-babe-55c115ad0000', 'Sentadilla con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/dumbbell-sumo-squat.gif', '{"Párese con los pies más anchos que el ancho de los hombros y los dedos apuntando ligeramente hacia afuera.","Sostenga una mancuerna verticalmente con ambas manos, dejándola colgar entre sus piernas.","Desciende hasta que tus muslos queden paralelos al suelo, manteniendo las rodillas alineadas con los dedos de los pies.","Empuja los talones para levantarte y aprieta los glúteos en la parte superior.","Involucre su núcleo y mantenga su pecho erguido mientras dobla las rodillas y baja las caderas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6de55714-c0de-4e80-babe-6de557140000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/Suspended-Ab-Fall-out.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5e00c3b6-c0de-4e80-babe-5e00c3b60000', 'Press de pecho con barra', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Barbell-Floor-Press.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2b360a1e-c0de-4e80-babe-2b360a1e0000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/TRX-Mountain-Climber.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('20a435c8-c0de-4e80-babe-20a435c80000', 'Peso muerto', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/zercher-deadlift.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('696772a5-c0de-4e80-babe-696772a50000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Supported-Pistol-Squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7a9b5ea3-c0de-4e80-babe-7a9b5ea30000', 'Aperturas de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Landmine-Floor-Chest-Fly.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('301c28f9-c0de-4e80-babe-301c28f90000', 'Ejercicio con barra', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/thruster.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4c3e9607-c0de-4e80-babe-4c3e96070000', 'Ejercicio con banda de resistencia', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Triceps-Extension-with-Resistance-Bands.gif', '{"Agarre las asas o los extremos de la banda con un agarre neutral, con las palmas una frente a la otra.","Regrese lentamente a la posición inicial bajo control, resistiendo el tirón hacia arriba.","Ancle una banda de resistencia de forma segura sobre el marco de una puerta o barra de dominadas.","Empuje las manijas hacia abajo, extendiendo los brazos hasta que estén completamente estirados sin bloquear los codos.","Haga una pausa en extensión total para apretar los tríceps.","Da un paso atrás ligeramente para crear tensión en la banda. Mantenga los codos sujetos a los costados y el pecho erguido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7bec0a7e-c0de-4e80-babe-7bec0a7e0000', 'Ejercicio con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Dumbbell-Pull-Through.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7c9d77c2-c0de-4e80-babe-7c9d77c20000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/jefferson-squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('45df0196-c0de-4e80-babe-45df01960000', 'Elevación de pantorrillas', 'Pantorrillas', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Single-Leg-Donkey-Calf-Raise.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0a5cbc34-c0de-4e80-babe-0a5cbc340000', 'Extensión de tríceps acostado con barra EZ', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/EZ-Bar-Lying-Close-Grip-Triceps-Extension-Behind-Head.gif', '{"Colóquese en la posición adecuada según la variante (de pie para polea, acostado para press francés o sentado).","Alinee las manos con la resistencia y mantenga el abdomen contraído para estabilizar el cuerpo.","Fije los codos cerca de la cabeza o de los costados del cuerpo.","Extienda completamente los codos empujando o presionando la resistencia de forma explosiva.","Sienta la contracción en la parte posterior del brazo al completar la extensión.","Regrese lentamente a la posición inicial flexionando los codos, sintiendo el estiramiento del tríceps.","No abra los codos hacia afuera durante el movimiento.","Evite utilizar el impulso del cuerpo o de los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('652b415e-c0de-4e80-babe-652b415e0000', 'Press de pecho declinado', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/01/Decline-hammer-press.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('52871580-c0de-4e80-babe-528715800000', 'Extensión de tríceps unilateral', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Cable-One-Arm-High-Pulley-Overhead-Tricep-Extension.gif', '{"Colóquese en la posición adecuada según la variante (de pie para polea, acostado para press francés o sentado).","Alinee las manos con la resistencia y mantenga el abdomen contraído para estabilizar el cuerpo.","Fije los codos cerca de la cabeza o de los costados del cuerpo.","Extienda completamente los codos empujando o presionando la resistencia de forma explosiva.","Sienta la contracción en la parte posterior del brazo al completar la extensión.","Regrese lentamente a la posición inicial flexionando los codos, sintiendo el estiramiento del tríceps.","No abra los codos hacia afuera durante el movimiento.","Evite utilizar el impulso del cuerpo o de los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5901a645-c0de-4e80-babe-5901a6450000', 'Ejercicio con agarre inverso con barra', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Barbell-Reverse-Grip-Skullcrusher-1.gif', '{"- Acuéstese sobre un banco con los pies apoyados en el suelo.","- Sujete una barra recta o EZ con un agarre por encima del ancho de los hombros.","- Una vez que alcance una curva de 90 grados o un poco más profunda, presione la barra hacia la posición inicial extendiendo los codos.","- Comience con los brazos extendidos, sosteniendo la barra directamente sobre sus hombros.","- Manteniendo la parte superior de los brazos perpendicular al banco, doble lentamente los codos para bajar la barra hacia la frente o justo encima de ella.","- Mantenga los codos doblados y estacionarios durante todo el movimiento.","- Evite dejar que la barra se desplace hacia su pecho o cara.","- Baje la barra con un movimiento controlado para mantener la tensión y evitar lesiones.","- Exhala mientras presionas la barra hacia arriba e inhala mientras la bajas.","- Dejar que las muñecas se doblen hacia atrás, lo que reduce el control y corre el riesgo de sufrir tensión.","### Errores comunes","- Permitir que los codos se ensanchen excesivamente.","- Usar impulso o hacer rebotar la barra en la frente","- Repita para el número deseado de repeticiones.","### Consejos para una forma adecuada","- Mantenga los codos cerca de la cabeza para evitar la afectación de los hombros.","- Mantenga las muñecas rectas y estables durante todo el levantamiento.","- Bajar la barra hacia el pecho en lugar de hacia la frente, lo que desvía el énfasis del tríceps.","- Usar demasiado peso y comprometer el rango de movimiento o la forma."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0f95970c-c0de-4e80-babe-0f95970c0000', 'Curl de bíceps con agarre inverso con barra EZ', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Cable-Reverse-Grip-EZ-bar-Biceps-Curl.gif', '{"Sujete el peso (mancuerna, barra o polea) con un agarre supino (palmas hacia arriba).","Mantenga los pies separados al ancho de los hombros y las rodillas ligeramente flexionadas.","Coloque los codos pegados a los costados del torso y mantenga la espalda recta.","Manteniendo inmóvil la parte superior de los brazos, flexione los codos y eleve la carga hacia los hombros.","Apriete fuertemente los bíceps en el punto de máxima contracción por un segundo.","Baje el peso de forma controlada y lenta hasta extender completamente los brazos.","Evite balancear la espalda o mover los hombros hacia adelante para ayudarse.","Mantenga las muñecas firmes y rectas durante todo el recorrido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('728609b9-c0de-4e80-babe-728609b90000', 'Extensión de espalda acostado con barra', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Barbell-Lying-Back-of-the-Head-Tricep-Extension.gif', '{"- Acuéstese sobre un banco plano, con los pies apoyados en el suelo.","- Sujete una barra EZ o una barra recta con un agarre en pronación al ancho de los hombros (con las palmas hacia abajo).","- Involucre los tríceps para presionar la barra de regreso a la posición inicial sin mover los hombros ni ensanchar los codos.","- Arquear la espalda baja o moverse en el banco","- Comience con los brazos completamente extendidos, sosteniendo la barra directamente sobre sus hombros.","- La parte superior de tus brazos debe permanecer estacionaria y perpendicular al suelo.","- Baje la barra tan atrás como le resulte cómodo, idealmente hasta que esté al nivel o ligeramente por debajo de la altura del banco.","- Mantenga los codos estables y cerca de la cabeza durante todo el movimiento.","- Manteniendo los codos apuntando hacia arriba y pegados a la cabeza, doble lentamente los codos para bajar la barra formando un arco detrás de la cabeza.","- Baje la barra con un movimiento lento y controlado para maximizar el estiramiento.","- Utilice un observador si levanta objetos pesados ​​o si es nuevo en el movimiento.","- Concéntrese en moverse solo en la articulación del codo para evitar utilizar el impulso.","- Evite dejar que la barra se desplace demasiado hacia atrás, lo que puede tensar los hombros.","### Errores comunes","- Ensanchando los codos hacia afuera, reduciendo el aislamiento del tríceps.","- Usar peso excesivo y acortar el rango de movimiento.","- Repita para las repeticiones deseadas.","### Consejos para una forma adecuada","- Permitir que la barra caiga directamente hacia la cara en lugar de detrás de la cabeza.","- Hacer rebotar la barra fuera de la posición estirada en lugar de controlar el movimiento."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0abfe0dc-c0de-4e80-babe-0abfe0dc0000', 'Extensión de tríceps acostado en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Cable-Rope-Lying-on-Floor-Tricep-Extension.gif', '{"Colóquese en la posición adecuada según la variante (de pie para polea, acostado para press francés o sentado).","Alinee las manos con la resistencia y mantenga el abdomen contraído para estabilizar el cuerpo.","Fije los codos cerca de la cabeza o de los costados del cuerpo.","Extienda completamente los codos empujando o presionando la resistencia de forma explosiva.","Sienta la contracción en la parte posterior del brazo al completar la extensión.","Regrese lentamente a la posición inicial flexionando los codos, sintiendo el estiramiento del tríceps.","No abra los codos hacia afuera durante el movimiento.","Evite utilizar el impulso del cuerpo o de los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1120f149-c0de-4e80-babe-1120f1490000', 'Ejercicio', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Bodyweight-Skull-Crushers.gif', '{"- Busque una barra estable (como una máquina Smith, una rejilla para sentadillas o barras paralelas).","- Ajuste la altura de la barra según su nivel de fuerza: las barras más altas son más fáciles y las barras más bajas aumentan la dificultad.","- Párese frente a la barra, sujétela con un agarre por encima del ancho de los hombros y retroceda a una posición de tabla diagonal.","- Empuja tus tríceps, extendiendo los codos para volver a la posición inicial.","### Paso 1: configuración","### Paso 2: Fase de descenso","- Doble los codos y baje la cabeza hacia la barra.","- Baja bajo control hasta que tu frente esté justo por encima de la barra.","- Mantenga el cuerpo recto desde la cabeza hasta los talones, involucrando el núcleo y los glúteos.","- Mantenga los codos cerca del cuerpo para maximizar la activación de los tríceps.","- Repita para las repeticiones deseadas, manteniendo la forma adecuada en todo momento.","### Paso 3: Fase de prensado"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2780034e-c0de-4e80-babe-2780034e0000', 'Extensión de tríceps acostado con mancuernas', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Alternating-Lying-Dumbbell-Triceps-Extension.gif', '{"Extiende el brazo de regreso a la posición inicial contrayendo el tríceps.","Acuéstese en un banco con una mancuerna en cada mano. Extienda ambos brazos rectos sobre el pecho, con las palmas una frente a la otra. Mantenga los codos pegados al torso.","Ejecución: Baje una mancuerna doblando el codo, llevándolo hacia la oreja o al nivel del hombro. Mantenga la parte superior del brazo inmóvil y perpendicular al suelo. Extienda el brazo hacia la posición inicial contrayendo el tríceps. Repita en el lado opuesto, alternando los brazos en cada repetición. Complete las repeticiones prescritas para ambos brazos.","Extienda ambos brazos rectos sobre su pecho, con las palmas una frente a la otra.","Baje una mancuerna doblando el codo, llevándolo hacia la oreja o al nivel del hombro. Mantenga la parte superior del brazo inmóvil y perpendicular al suelo. Extienda el brazo hacia la posición inicial contrayendo el tríceps. Repita en el lado opuesto, alternando los brazos en cada repetición. Complete las repeticiones prescritas para ambos brazos.","Baje una mancuerna doblando el codo y acercándolo al nivel de la oreja o del hombro.","Inhala mientras bajas la mancuerna.","Repita en el lado opuesto, alternando brazos en cada repetición.","Respiración: Inhale mientras baja la mancuerna. Exhale mientras extiende el brazo hacia arriba.","Mantenga la parte superior del brazo fija y perpendicular al suelo.","Inhale mientras baja la mancuerna. Exhale mientras extiende el brazo hacia arriba.","Exhala mientras extiendes el brazo hacia arriba."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('04f407bf-c0de-4e80-babe-04f407bf0000', 'Extensión de tríceps acostado en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Cable-Lying-Triceps-Extension.gif', '{"Colóquese en la posición adecuada según la variante (de pie para polea, acostado para press francés o sentado).","Alinee las manos con la resistencia y mantenga el abdomen contraído para estabilizar el cuerpo.","Fije los codos cerca de la cabeza o de los costados del cuerpo.","Extienda completamente los codos empujando o presionando la resistencia de forma explosiva.","Sienta la contracción en la parte posterior del brazo al completar la extensión.","Regrese lentamente a la posición inicial flexionando los codos, sintiendo el estiramiento del tríceps.","No abra los codos hacia afuera durante el movimiento.","Evite utilizar el impulso del cuerpo o de los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7cf4400d-c0de-4e80-babe-7cf4400d0000', 'Ejercicio unilateral', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Side-One-Arm-Reverse-Pushdown.gif', '{"Párese perpendicular a la máquina de cable, con el hombro izquierdo alineado con la máquina.","Agarre el mango con la mano derecha, con la palma hacia arriba (agarre en supinación), formando un ángulo de 90 grados frente a su cuerpo. Esta posición le sirve como punto de partida.","Coloque los pies separados a la altura de los hombros, las rodillas ligeramente dobladas y mantenga una postura estable.","Inhale mientras regresa lentamente a la posición inicial, resistiendo el tirón del peso y manteniendo un movimiento controlado.","Involucre sus músculos centrales para lograr estabilidad y mantenga su torso erguido durante todo el movimiento.","Exhale y comience el ejercicio extendiendo el brazo derecho hacia abajo, empujando el mango hacia el suelo.","Concéntrate en contraer completamente los tríceps en la parte inferior del movimiento mientras mantienes el control.","Repita hasta el número deseado de repeticiones en un brazo antes de cambiar al otro brazo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('59a1bf5e-c0de-4e80-babe-59a1bf5e0000', 'Extensión de tríceps en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Cable-Crossover-Triceps-Extension.gif', '{"- Coloque ambas poleas en la posición más alta en una máquina de cruce de cables.","- Párese en el centro de la máquina y agarre un mango en cada mano con un agarre neutral (con las palmas hacia abajo o ligeramente hacia adentro).","- Vuelva lentamente a la posición inicial bajo control, resistiendo la tensión del cable.","- Bloquee los codos en posición durante toda la serie para evitar la asistencia de los hombros.","- Conecte manijas en D individuales a cada cable.","- Da un paso ligeramente hacia adelante con un pie para mantener el equilibrio e inclínate hacia adelante a la altura de las caderas para alinear los brazos en diagonal con los cables.","- Comience con los codos doblados y los brazos colocados hacia afuera aproximadamente a la altura de la cabeza.","- Concéntrese en apretar completamente en la parte inferior y estirar completamente en la parte superior de cada repetición.","- Mientras mantiene los codos fijos en su lugar y la parte superior de los brazos inclinada hacia adelante, extienda ambos brazos hacia abajo y ligeramente hacia adentro frente a su cuerpo.","- No deje que los brazos se desplacen demasiado detrás de la cabeza, lo que puede generar tensión en los hombros.","- Inclinarse excesivamente hacia atrás y convertirlo en un movimiento lateral.","### Errores comunes","- Dejar que los codos se abran o se muevan durante la extensión.","- Usar demasiado peso y comprometer el rango de movimiento","- Apriete el tríceps en extensión completa con las manos cerca de la altura de la cadera o delante de los muslos.","- Repita para las repeticiones deseadas.","### Consejos para una forma adecuada","- Mantenga una ligera inclinación hacia adelante para mantener una tensión constante en los tríceps.","- Mantenga una columna neutra y evite inclinarse o encogerse de hombros excesivamente.","- No controlar la parte excéntrica de la repetición.","- Empezando con las manos demasiado bajas, reduciendo el estiramiento en la cabeza larga."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3d28c563-c0de-4e80-babe-3d28c5630000', 'Extensión de tríceps acostado con barra', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Barbell-Lying-Close-grip-Triceps-Extension.gif', '{"Colóquese en la posición adecuada según la variante (de pie para polea, acostado para press francés o sentado).","Alinee las manos con la resistencia y mantenga el abdomen contraído para estabilizar el cuerpo.","Fije los codos cerca de la cabeza o de los costados del cuerpo.","Extienda completamente los codos empujando o presionando la resistencia de forma explosiva.","Sienta la contracción en la parte posterior del brazo al completar la extensión.","Regrese lentamente a la posición inicial flexionando los codos, sintiendo el estiramiento del tríceps.","No abra los codos hacia afuera durante el movimiento.","Evite utilizar el impulso del cuerpo o de los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('68af9786-c0de-4e80-babe-68af97860000', 'Extensión de tríceps de rodillas en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Kneeling-Cable-Triceps-Extension.gif', '{"Sujete una cuerda o una barra recta a una polea alta. Arrodíllese unos metros frente a la máquina de cable, de espaldas a ella. Sujete las manijas con ambas manos y llévelas detrás de la cabeza. Los codos deben estar doblados, apuntando hacia arriba, con la parte superior de los brazos cerca de las orejas. Mantenga la espalda recta y el core enganchado.","Sujete las asas con ambas manos y llévelas detrás de la cabeza.","Regrese lentamente a la posición inicial con control.","Configuración: Sujete una cuerda o una barra recta a una polea alta. Arrodíllese unos metros frente a la máquina de cable, de espaldas a ella. Sujete las manijas con ambas manos y llévelas detrás de la cabeza. Los codos deben estar doblados, apuntando hacia arriba, con la parte superior de los brazos cerca de las orejas. Mantenga la espalda recta y el core enganchado.","Conecte una cuerda o una barra recta a una polea alta.","Extiende los brazos hacia adelante y ligeramente hacia arriba enderezando los codos.Aprieta los tríceps en la parte superior del movimiento.Vuelve lentamente a la posición inicial con control.Repite durante el número de repeticiones deseadas.","Aprieta el tríceps en la parte superior del movimiento.","Ejecución:Extiende los brazos hacia adelante y ligeramente hacia arriba enderezando los codos.Aprieta los tríceps en la parte superior del movimiento.Vuelve lentamente a la posición inicial con control.Repite durante el número de repeticiones deseadas.","Respiración: Inhale durante la fase excéntrica (de descenso). Exhale mientras extiende y presiona las manijas hacia adelante.","Mantenga la espalda recta y el core comprometido.","Repita para el número deseado de repeticiones.","Inhale durante la fase excéntrica (de descenso). Exhale mientras extiende y presiona las manijas hacia adelante.","Exhala mientras extiendes y presionas las manijas hacia adelante."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1843af79-c0de-4e80-babe-1843af790000', 'Elevación', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/07/Glute-Ham-Raise.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('58a893af-c0de-4e80-babe-58a893af0000', 'Ejercicio en polea', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/V-bar-Pushdown.gif', '{"- Configure la máquina de cable: conecte la barra en V a la polea alta. Ajuste la pila de pesas a un nivel de resistencia apropiado.","- Párese erguido y agarre la barra: mire hacia la máquina de cable y agarre la barra en V con ambas manos usando un agarre neutral, con los codos pegados a los costados.","- Coloque su cuerpo: mantenga el pecho erguido, el núcleo reforzado y los pies separados a la altura de los hombros. Inclínese ligeramente hacia adelante para estabilizar su cuerpo.","- Controle el retorno: permita que la barra regrese lentamente a la posición inicial sin dejar que los codos se desplacen hacia adelante. Mantenga la tensión en los tríceps en todo momento.","- Usar el impulso: balancear el torso o usar el peso corporal reduce la participación de los músculos y aumenta el riesgo de lesiones.","- Ubicación incorrecta del agarre: Mantener la barra en V demasiado cerca o demasiado abierta puede afectar la comodidad de la muñeca y la activación del tríceps.","- Mantenga los codos apretados: sus codos deben permanecer cerca de los costados durante todo el movimiento para aislar completamente los tríceps.","- Refuerza tu núcleo: involucra tu núcleo y tus glúteos para evitar usar el impulso o inclinarte hacia atrás.","- Empuje la barra hacia abajo: presione la barra hacia abajo extendiendo los codos y manteniendo la parte superior de los brazos inmóviles. Aprieta los tríceps en la parte inferior del movimiento.","- Utilice un rango completo de movimiento: extiéndase completamente en la parte inferior y vuelva a estar bajo control para una activación máxima.","- Exhala al empujar: exhala mientras presionas la barra hacia abajo e inhala mientras regresas a la cima.","### Errores comunes","- Codos ensanchados: esto reduce la tensión en los tríceps y puede trasladar la tensión a los hombros.","### Consejos para una forma adecuada","- Evite la flexión de muñecas: mantenga las muñecas rectas y neutrales durante todo el movimiento.","- Medias repeticiones: No extender completamente o regresar por debajo del máximo limita la efectividad.","- Bloquear agresivamente: chasquear los codos en la parte inferior puede causar molestias en las articulaciones con el tiempo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('751b39ab-c0de-4e80-babe-751b39ab0000', 'Press de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/02/Barbell-Reverse-Close-grip-Bench-Press.gif', '{"Acuéstese en un banco con los pies firmemente plantados en el suelo. Colóquese debajo de un soporte para barra y ajuste la barra para que esté a una altura cómoda y al alcance de su brazo.","Acuéstese sobre un banco con los pies firmemente plantados en el suelo.","Colóquese debajo de un soporte para barra y ajuste la barra para que esté a una altura cómoda y al alcance de la mano.","levante la barra del soporte y sosténgala directamente sobre su pecho con los brazos completamente extendidos.","Configuración: Acuéstese en un banco con los pies firmemente plantados en el suelo. Colóquese debajo de un soporte para barra y ajuste la barra para que esté a una altura cómoda y al alcance de su brazo.","Agarre y colocación de las manos: Levante y agarre la barra con ambas manos usando un agarre por debajo, también conocido como agarre supinado. Esto significa que las palmas de las manos deben mirar hacia la cabeza y los dedos deben estar alrededor de la barra.","Posición inicial: levante la barra del soporte y sosténgala directamente sobre su pecho con los brazos completamente extendidos.","Levante la barra del soporte y sosténgala directamente sobre su pecho con los brazos completamente extendidos.","Inhala y baja la barra hacia tu pecho de forma controlada. Mantenga los codos cerca del cuerpo mientras baja la barra. Baje la barra hasta que toque su pecho o se acerque a él, mientras mantiene un ligero arco en la zona lumbar.","Ejecución: Inhala y baja la barra hacia tu pecho de forma controlada. Mantenga los codos cerca del cuerpo mientras baja la barra. Baje la barra hasta que toque su pecho o se acerque a él, mientras mantiene un ligero arco en la zona lumbar.","Inhala y baja la barra hacia tu pecho de forma controlada. Mantenga los codos cerca de su cuerpo mientras baja la barra.","Baja la barra hasta que toque tu pecho o se acerque a él, manteniendo un ligero arco en la zona lumbar.","Fase de empuje: Exhala y empuja la barra hacia arriba hasta la posición inicial extendiendo los brazos. Concéntrate en usar tus tríceps para realizar el movimiento.","Repetir: Realice el número deseado de repeticiones manteniendo la forma y el control adecuados."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('09d45c02-c0de-4e80-babe-09d45c020000', 'Press de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Wide-Grip-Reverse-Bench-Press.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5f079909-c0de-4e80-babe-5f0799090000', 'Estiramiento de pie', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/06/Standing-Wide-Knees-Adductor-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('540bc3c0-c0de-4e80-babe-540bc3c00000', 'Estiramiento', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/06/Sitting-Wide-Leg-Adductor-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('179c14e2-c0de-4e80-babe-179c14e20000', 'Estiramiento de pie', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/06/Standing-Wide-Leg-Adductor-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('765f945c-c0de-4e80-babe-765f945c0000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/TRX-Pistol-Squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6b023b92-c0de-4e80-babe-6b023b920000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/06/Knee-Circles.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5cc63bfb-c0de-4e80-babe-5cc63bfb0000', 'Postura de yoga', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Parsva-Balasana-Thread-the-Needle-Pose.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('45470fc8-c0de-4e80-babe-45470fc80000', 'Giro ruso sentado en polea', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Cable-Seated-Twist-on-Floor.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6962647c-c0de-4e80-babe-6962647c0000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Half-Cross-Crunch.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('065c89d8-c0de-4e80-babe-065c89d80000', 'Pájaro / Vuelos posteriores inclinado con banda de resistencia', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/Resistance-Band-Bent-Over-Rear-Delt-Fly.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('509ccb2e-c0de-4e80-babe-509ccb2e0000', 'Ejercicio unilateral con pesa rusa / kettlebell', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/One-Arm-Kettlebell-Swing.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('28b04540-c0de-4e80-babe-28b045400000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2021/02/Straddle-Planche.gif', '{"- Comience en una posición de flexión con las manos ligeramente hacia afuera para comodidad de la muñeca.","- Depender del impulso para llegar a la posición en lugar del control.","- Incline su cuerpo hacia adelante mientras contrae los glúteos, el core y los cuádriceps.","- Mantenga la posición el mayor tiempo posible con control, luego regrese al inicio.","- Prolonga los omóplatos empujando el suelo.","- Poco a poco, levante los pies del suelo mientras extiende las piernas hacia afuera hasta quedar a horcajadas.","- Involucre todo su núcleo para evitar la flacidez en las caderas.","### Errores comunes","- Doblar los codos y no mantener el bloqueo del brazo.","- Mantenga una línea recta desde los hombros hasta los pies mientras equilibra su cuerpo horizontalmente.","### Consejos para una forma adecuada","- Mantenga los brazos completamente bloqueados para evitar tensión en los codos.","- Concéntrese en la respiración lenta para mantener el control y el equilibrio.","- Dejar que las caderas caigan por debajo del nivel de los hombros.","- Arquear la espalda baja debido a una activación débil del core"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('13443eea-c0de-4e80-babe-13443eea0000', 'Aperturas de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Butterfly-Sit-up.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3d04fd9f-c0de-4e80-babe-3d04fd9f0000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2021/01/hip-circles.gif', '{"Párese erguido con las manos en las caderas, las piernas estiradas y los pies separados a la altura de los hombros.","Continúe la rotación de regreso a la posición inicial con un movimiento suave y controlado.","Comience a rotar las caderas lentamente en el sentido de las agujas del reloj. Mantenga la espalda recta."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5d14bb97-c0de-4e80-babe-5d14bb970000', 'Estiramiento de pie', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Standing-Reverse-Shoulder-Stretch.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0697a59d-c0de-4e80-babe-0697a59d0000', 'Plancha', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/Side-Plank-Rotation.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('69600c01-c0de-4e80-babe-69600c010000', 'Sentadilla con banda de resistencia', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/Resistance-Band-Overhead-Squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('25de5798-c0de-4e80-babe-25de57980000', 'Press de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Trx-Chest-Press.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('58e40a1b-c0de-4e80-babe-58e40a1b0000', 'Ejercicio con balón medicinal', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/06/Medicine-ball-Overhead-Slam-exercise.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('469e05d2-c0de-4e80-babe-469e05d20000', 'Fondos', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/04/Reverse-Dips.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1358a9b2-c0de-4e80-babe-1358a9b20000', 'Remo con balón medicinal', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/06/Supine-Medicine-Ball-Chest-Throw-exercise.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0780ecf7-c0de-4e80-babe-0780ecf70000', 'Extensión de tríceps de pie', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/11/Lever-Standing-Hip-Extension.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3971606d-c0de-4e80-babe-3971606d0000', 'Remo con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/11/Dumbbell-Seal-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('453f85e2-c0de-4e80-babe-453f85e20000', 'Aperturas de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Trx-Chest-Flyes.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('11baaad0-c0de-4e80-babe-11baaad00000', 'Ejercicio con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/11/Dumbbell-Straight-Arm-Pullover-knees-at-90-degrees.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('25230cdf-c0de-4e80-babe-25230cdf0000', 'Ejercicio', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2023/01/wall-ball.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('155e39ca-c0de-4e80-babe-155e39ca0000', 'Curl de bíceps con barra', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Barbell-Drag-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0faf32f7-c0de-4e80-babe-0faf32f70000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Kicks-Leg-Bent.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('62343cf7-c0de-4e80-babe-62343cf70000', 'Estiramiento de rodillas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Kneeling-Leg-Out-Adductor-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3ffd4498-c0de-4e80-babe-3ffd44980000', 'Ejercicio', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/Hell-Slide.gif', '{"Este movimiento simple y relativamente suave es un buen ejercicio para mejorar la fuerza y ​​la movilidad de los músculos de la cadera y la pelvis. Recuerda siempre realizar la misma cantidad de repeticiones para cada pierna."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('317bda62-c0de-4e80-babe-317bda620000', 'Ejercicio', 'Abdomen', '', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('79eb3c7e-c0de-4e80-babe-79eb3c7e0000', 'Estiramiento', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2021/01/Doorway-chest-and-sshoulder-stretch.gif', '{"Párese frente a una puerta abierta.","Da un pequeño paso hacia adelante, inclinando suavemente el peso de tu cuerpo hacia el estiramiento.","Levanta los brazos y coloca las manos en el marco de la puerta.","Deberías sentir un estiramiento en el pecho y la parte delantera de los hombros.","Da un paso atrás lentamente para liberar el estiramiento.","Mantenga el estiramiento durante 15 a 30 segundos, mientras mantiene un patrón de respiración relajado.","Repita el estiramiento durante 2 o 3 series."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1fa3c20f-c0de-4e80-babe-1fa3c20f0000', 'Ejercicio con banda de resistencia', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Resistance-Band-Pull-Apart.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('58f62608-c0de-4e80-babe-58f626080000', 'Postura de yoga', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/12/Happy-Baby-Pose.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
