INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('458210cf-c0de-4e80-babe-458210cf0000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/One-Leg-Push-Up.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1e636559-c0de-4e80-babe-1e6365590000', 'Flexiones de pecho con pesa rusa / kettlebell', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Kettlebell-Deep-Push-Up.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('59a7ec97-c0de-4e80-babe-59a7ec970000', 'Ejercicio con balón medicinal', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Medicine-Ball-Crunch.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7ed32347-c0de-4e80-babe-7ed323470000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Finger-Push-up.gif', '{"Comience en una posición de flexión: comience en una posición de flexión con las palmas de las manos en el suelo, los dedos apuntando hacia adelante y el cuerpo en línea recta.","Coloque las yemas de los dedos: levante lentamente las palmas del suelo y equilibre su peso sobre las yemas de los dedos, manteniendo las muñecas rectas. Cambie su peso hacia las yemas de los dedos, asegurándose de que las palmas ya no toquen el suelo.","Empuje hacia arriba: una vez que su pecho esté cerca del suelo, empuje hacia atrás hasta la posición inicial estirando los brazos.","Repetir: repita el ejercicio durante la cantidad deseada de repeticiones, asegurándose de mantener la forma adecuada durante todo el movimiento.","Baja el cuerpo: Doble lentamente los codos y baje el cuerpo hacia el suelo, manteniendo el cuerpo en línea recta."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7a6228e1-c0de-4e80-babe-7a6228e10000', 'Ejercicio en máquina', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/09/Smith-Machine-Hip-Thrust.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0f9f7891-c0de-4e80-babe-0f9f78910000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Archer-Push-Up.gif', '{"- Comience en una posición de flexión amplia: comience en una posición de flexión con las manos colocadas más anchas que el ancho de los hombros. Gire los dedos ligeramente hacia afuera.","- Empuje hacia atrás hacia la cima: conduzca a través del brazo de trabajo para regresar a la posición inicial, luego repita en el mismo lado o en lados alternos.","###","- Cambie su peso hacia un lado: baje el pecho hacia el brazo que trabaja, doblando el codo mientras el brazo opuesto permanece extendido y recto.","- Mantenga el otro brazo recto: a medida que desciende, su brazo extendido debe permanecer recto y actuar como una viga de soporte, deslizándose hacia afuera por el suelo.","- Controla el descenso: Muévete lenta y deliberadamente para maximizar el tiempo bajo tensión.","- Alcance un rango completo de movimiento: baje hasta que su pecho casi toque la mano del lado de trabajo mientras mantiene su núcleo apretado y la espalda plana.","- Respire rítmicamente: inhale mientras baja y exhale mientras presiona hacia arriba.","- Refuerza tu núcleo: contrae tus abdominales para mantener una línea recta desde la cabeza hasta los talones.","### Errores comunes","- Rotar el torso: Girar durante el empujón reduce el efecto unilateral y tensa la columna.","### Consejos para una forma adecuada","- Mantenga las caderas cuadradas: mantenga la alineación para evitar girar el torso.","- Mantenga activo el brazo extendido: no lo deje flácido. Mantenga la tensión para el equilibrio y la estabilidad.","- No bajar lo suficiente: las repeticiones superficiales reducen las ganancias de fuerza y ​​pierden el estiramiento completo.","- Ritmo desigual: Apresurarse en las repeticiones de un lado puede crear desequilibrios de fuerza.","- Dejar que las caderas se hunda: Las caderas caídas pueden comprometer el compromiso central y provocar tensión en la espalda baja.","- Doblar el brazo de soporte: Mantenga recto el brazo que no funciona para garantizar una mecánica adecuada."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6bd8984f-c0de-4e80-babe-6bd8984f0000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Planche-Push-Up.gif', '{"- Comience con una posición de plancha completa: comience con el cuerpo paralelo al suelo, los brazos rectos, los hombros extendidos y los pies alejados del suelo. Mantén todo tu cuerpo rígido.","- Protracción inadecuada del hombro: Sin una posición escapular adecuada, el ejercicio se vuelve inestable e inseguro.","- Bajar bajo control: doble lentamente los codos para bajar el pecho más cerca del suelo, manteniendo la posición del cuerpo recto. No dejes caer tus caderas.","- Mantenga la tensión de todo el cuerpo: durante todo el movimiento, mantenga los glúteos, los abdominales y los cuádriceps contraídos para mantener una línea recta y horizontal.","- Prolonga los hombros: empuja activamente los hombros hacia adelante para estabilizar las escápulas y proteger la articulación del hombro.","- Presione hacia arriba: una vez que su pecho se acerque al piso, empuje con las palmas y estire los codos para volver a la posición de plancha completa.","- Controla el tempo: Realiza el movimiento lentamente y con control para evitar compensaciones de impulso.","- Permitir que las caderas se doblen: Dejar que las caderas caigan rompe la forma y genera una tensión innecesaria en la columna.","- Saltarse progresiones: intentar hacer flexiones en plancha completa sin dominar los pasos anteriores puede provocar lesiones.","- Mire ligeramente hacia adelante: mire hacia adelante para mantener la alineación y el equilibrio del cuello.","- Calienta bien: asegúrate de que tus muñecas, hombros y núcleo estén completamente activados antes de intentarlo.","### Errores comunes","- Mantenga los codos cerrados: a medida que desciende, asegúrese de que los codos permanezcan doblados hacia el torso. Esto protege sus articulaciones y mantiene el movimiento eficiente.","### Consejos para una forma adecuada","- Mantenga el núcleo apretado: contraiga los abdominales y la espalda baja para evitar que las caderas caigan durante la flexión.","- Doblar las rodillas: mantenga las piernas estiradas y juntas para mantener la alineación de todo el cuerpo.","- Codos ensanchados: Los codos que apuntan hacia afuera pueden aumentar la tensión en los hombros y reducir la eficiencia mecánica."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2a6d1278-c0de-4e80-babe-2a6d12780000', 'Aperturas de pecho con banda de resistencia', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/09/Resistance-Band-Alternating-Chest-Fly.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('03dd770b-c0de-4e80-babe-03dd770b0000', 'Ejercicio con pesa rusa / kettlebell', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/09/Kettlebell-Figure-8.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1ec82204-c0de-4e80-babe-1ec822040000', 'Ejercicio con banda de resistencia', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/09/Resistance-Band-Hip-Thrust.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0f825c07-c0de-4e80-babe-0f825c070000', 'Ejercicio con banda de resistencia', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/09/Resistance-Band-Hip-Thrusts-on-Knees.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5f7ce6e2-c0de-4e80-babe-5f7ce6e20000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Knuckle-Push-Up.gif', '{"Comience en una posición estándar de flexión de brazos con las manos ligeramente más separadas que el ancho de los hombros. En lugar de colocar las palmas de las manos en el suelo, cierre los puños con las manos, con los nudillos hacia abajo y los pulgares fuera de los puños.","Comience en una posición de flexión estándar con las manos ligeramente más separadas que el ancho de los hombros.","Empuje su cuerpo hacia atrás a la posición inicial estirando los brazos mientras sigue usando los nudillos como apoyo.","Posición inicial: Comience en una posición estándar de flexión de brazos con las manos ligeramente más separadas que el ancho de los hombros. En lugar de colocar las palmas de las manos en el suelo, cierre los puños con las manos, con los nudillos hacia abajo y los pulgares fuera de los puños.","En lugar de colocar las palmas de las manos sobre el suelo, forme puños con las manos, con los nudillos hacia abajo y los pulgares fuera de los puños.","Baje su cuerpo hacia el suelo doblando los codos mientras mantiene los puños en contacto con el suelo.","El ascenso: Empuje su cuerpo hacia la posición inicial estirando los brazos mientras sigue usando los nudillos como apoyo. Extienda completamente los codos sin bloquearlos en la parte superior del movimiento.","Extiende completamente los codos sin bloquearlos en la parte superior del movimiento.","Repetir: Realice múltiples repeticiones de flexiones de nudillos, concentrándose en mantener una buena forma en todo momento.","El descenso: Baje el cuerpo hacia el suelo doblando los codos mientras mantiene los puños en contacto con el suelo. Mantenga el cuerpo en línea recta desde la cabeza hasta los talones, manteniendo la forma adecuada de flexión.","Mantenga su cuerpo en línea recta desde la cabeza hasta los talones, manteniendo la forma adecuada de flexión."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('71b28056-c0de-4e80-babe-71b280560000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Bosu-Ball-Push-Up.gif', '{"### Posición inicial:","- Coloque la bola Bosu con el lado de la cúpula hacia abajo en el suelo.","- Coloque las manos en la plataforma plana, ligeramente más separadas que el ancho de los hombros.","- Posición inferior: bájese hasta que su pecho esté cerca o toque ligeramente la pelota Bosu.","- Empujar hacia arriba: presione con las manos para enderezar los codos y regrese a la posición inicial. Mantenga su núcleo comprometido y sus movimientos controlados.","- Coloque las manos en el suelo y los pies sobre la pelota Bosu para un desafío alternativo.","- Extienda las piernas detrás de usted en una posición de flexión estándar, asegurándose de que su cuerpo forme una línea recta desde la cabeza hasta los talones.","- Involucre su núcleo para mantener la estabilidad.","### Consideraciones importantes:","### Ejecución:","- Bajar: Doble lentamente los codos, bajando el pecho hacia la pelota Bosu mientras mantiene el control y la alineación.","- Movimientos controlados: realice el ejercicio de forma lenta y deliberada, evitando el impulso o las repeticiones apresuradas.","- Realiza flexiones con las rodillas en el suelo para reducir la intensidad.","- Equilibrio: La pelota Bosu introduce inestabilidad, así que concéntrate en mantener el equilibrio y el control. Los principiantes pueden comenzar con una colocación más amplia de las manos para mayor estabilidad.","- Posición de la muñeca: asegúrese de que sus muñecas estén directamente debajo de los hombros para reducir la tensión y mejorar la alineación de las articulaciones.","- Repetición: Repita hasta el número deseado de repeticiones.","- Compromiso central: mantenga su núcleo activado durante todo el ejercicio para evitar que las caderas se caigan y mejorar la estabilidad.","- Alineación del cuerpo: Mantenga una línea recta desde la cabeza hasta los talones. Evite arquear la espalda o dejar caer las caderas.","### Progresión y modificaciones:"}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('56980680-c0de-4e80-babe-569806800000', 'Elevaciones laterales con pesa rusa / kettlebell', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/09/Kettlebell-Lateral-Raise.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5e440599-c0de-4e80-babe-5e4405990000', 'Curl de bíceps con mancuernas', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/09/Dumbbell-Finger-Curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('14bc7778-c0de-4e80-babe-14bc77780000', 'Peso muerto con barra', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/09/Barbell-Single-Leg-Deadlift.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4c46d151-c0de-4e80-babe-4c46d1510000', 'Peso muerto con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/09/Dumbbell-Single-Leg-Deadlift.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5069a596-c0de-4e80-babe-5069a5960000', 'Remo con mancuernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/01/dumbbell-renegade-row-1.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('006f1c5b-c0de-4e80-babe-006f1c5b0000', 'Press de pecho inclinado con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Dumbbell-Reverse-Grip-30-Degrees-Incline-Bench-Press.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2342ed21-c0de-4e80-babe-2342ed210000', 'Curl de bíceps con barra', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/close-grip-barbell-curl.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('34441018-c0de-4e80-babe-344410180000', 'Extensión de piernas sentado con banda de resistencia', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Seated-Leg-Extension-with-Resistance-Band.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('581b8b7c-c0de-4e80-babe-581b8b7c0000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Pendulum-Squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('69119104-c0de-4e80-babe-691191040000', 'Dominadas con banda de resistencia', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/band-assisted-pull-up.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('07257c63-c0de-4e80-babe-07257c630000', 'Ejercicio con banda de resistencia', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Good-Morning-With-Resistance-Band.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1671eb11-c0de-4e80-babe-1671eb110000', 'Ejercicio sentado en máquina', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/Seated-Ab-Crunch-Machine.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6644f812-c0de-4e80-babe-6644f8120000', 'Sentadilla con mancuernas', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/10/dumbbell-bench-squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0ad5d90d-c0de-4e80-babe-0ad5d90d0000', 'Ejercicio con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Dumbbell-Windmill.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4288cc45-c0de-4e80-babe-4288cc450000', 'Ejercicio con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Dumbbell-Iron-Cross.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
