INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('61b286ab-c0de-4e80-babe-61b286ab0000', 'Press de pecho inclinado', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Incline-Landmine-Press.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3533a955-c0de-4e80-babe-3533a9550000', 'Estiramiento de pie', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Supported-One-Leg-Standing-Hip-Flexor-And-Knee-Extensor-Stretch.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0c3e7f4b-c0de-4e80-babe-0c3e7f4b0000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Box-pistol-Squat.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3870b3a0-c0de-4e80-babe-3870b3a00000', 'Sentadilla', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Squat-mobility-Complex.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6f788889-c0de-4e80-babe-6f7888890000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/Cobra-Push-up.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('31751574-c0de-4e80-babe-317515740000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/Shoulder-Tap-Push-up.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('69922c02-c0de-4e80-babe-69922c020000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/06/Assault-AirBike.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('70ceaa62-c0de-4e80-babe-70ceaa620000', 'Curl de bíceps unilateral en polea', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/06/Single-Arm-Reverse-Grip-Cable-Bicep-Curl.gif', '{"Sujete el peso (mancuerna, barra o polea) con un agarre supino (palmas hacia arriba).","Mantenga los pies separados al ancho de los hombros y las rodillas ligeramente flexionadas.","Coloque los codos pegados a los costados del torso y mantenga la espalda recta.","Manteniendo inmóvil la parte superior de los brazos, flexione los codos y eleve la carga hacia los hombros.","Apriete fuertemente los bíceps en el punto de máxima contracción por un segundo.","Baje el peso de forma controlada y lenta hasta extender completamente los brazos.","Evite balancear la espalda o mover los hombros hacia adelante para ayudarse.","Mantenga las muñecas firmes y rectas durante todo el recorrido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('450456e8-c0de-4e80-babe-450456e80000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/Weighted-Vest-Push-up.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0dac8e3b-c0de-4e80-babe-0dac8e3b0000', 'Curl de bíceps unilateral en polea', 'Bíceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/06/One-Arm-Cable-Bicep-Curl.gif', '{"Sujete el peso (mancuerna, barra o polea) con un agarre supino (palmas hacia arriba).","Mantenga los pies separados al ancho de los hombros y las rodillas ligeramente flexionadas.","Coloque los codos pegados a los costados del torso y mantenga la espalda recta.","Manteniendo inmóvil la parte superior de los brazos, flexione los codos y eleve la carga hacia los hombros.","Apriete fuertemente los bíceps en el punto de máxima contracción por un segundo.","Baje el peso de forma controlada y lenta hasta extender completamente los brazos.","Evite balancear la espalda o mover los hombros hacia adelante para ayudarse.","Mantenga las muñecas firmes y rectas durante todo el recorrido."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('452a52f1-c0de-4e80-babe-452a52f10000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/06/Recumbent-Exercise-Bike.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1edd168a-c0de-4e80-babe-1edd168a0000', 'Fondos', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/07/Ring-Dips.gif', '{"- Coloque los anillos a la altura del pecho: ajuste los anillos de gimnasia para que cuelguen al nivel del pecho y estén bien sujetos.","- Monte los anillos: salte o dé un paso en una posición de apoyo, con los brazos rectos, el cuerpo erguido y los anillos cerca de los costados.","###","- Empuje hacia arriba: presione con las palmas y estire los brazos para volver a la posición inicial, bloqueando la parte superior mientras mantiene los anillos cerca.","- Dejar que los anillos se salgan: Permitir que los anillos se alejen del cuerpo aumenta la inestabilidad y puede provocar una mala forma o lesiones.","- Perder la tensión central: Dejar que las caderas se hundan o las piernas se balanceen compromete el equilibrio y la eficacia.","- Descienda por debajo del nivel del anillo: baje hasta que los hombros caigan justo debajo de los codos, manteniendo la tensión en el pecho y los brazos.","- No profundizar lo suficiente: no bajar por debajo del paralelo limita el rango de movimiento y reduce la activación muscular.","- Acelerar el movimiento: utilizar el impulso reduce el desarrollo de la fuerza y ​​aumenta el riesgo de error.","- No bajar lo suficiente, limitando el rango de movimiento y la efectividad.","- Usar el impulso, en lugar de movimientos controlados para el compromiso muscular.","- Codos ensanchados: Los codos excesivamente ensanchados ejercen una tensión innecesaria en las articulaciones de los hombros.","### Errores comunes a evitar","- Inclinarse demasiado hacia adelante, lo que hace que la atención se centre en el pecho en lugar de en los tríceps.","- Bájate con control: dobla los codos e inclínate ligeramente hacia adelante mientras bajas el pecho entre los anillos. Mantenga los codos en un ángulo de aproximadamente 45 grados.","- Ensanchando los codos hacia afuera, reduciendo la activación de los tríceps y aumentando el riesgo de lesiones.","- Bloquear los codos, lo que puede generar una tensión excesiva en las articulaciones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('27e60e19-c0de-4e80-babe-27e60e190000', 'Flexiones de pecho', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/Suspended-Push-Up.gif', '{"- Configure su entrenador de suspensión: ajuste las correas o anillos TRX de modo que las manijas cuelguen justo por encima del suelo a la altura de la espinilla.","- Ponte en posición de flexión: coloca las manos en las manijas o anillos, luego camina con los pies hacia atrás para formar una tabla. Tus brazos deben estar completamente extendidos, con las muñecas debajo de los hombros.","###","- Empuje hacia arriba: Conduzca a través de las palmas de las manos para volver a la posición superior, extendiendo completamente los codos mientras mantiene estables las anillas o correas.","- Controla tu descenso: Muévete lenta y deliberadamente para no perder el equilibrio.","- Baje el pecho: doble los codos para bajar el pecho entre las manijas, manteniéndolas en un ángulo de 45 grados con respecto al torso.","- Estabiliza las correas: Intenta evitar que las asas o anillas se separen durante el movimiento.","- Perder alineación: Permitir que las manos se eleven demasiado o bajen demasiado afecta la tensión y la forma.","- Apresurar la repetición: los movimientos rápidos reducen el control y aumentan el riesgo de lesiones.","### Errores comunes","- Dejar que las correas se separen: esto crea inestabilidad y desplaza la carga de manera incorrecta.","- Caderas caídas: un compromiso central débil puede provocar que la zona lumbar colapse.","- Apoye su núcleo: mantenga la columna neutra, las caderas niveladas y los glúteos comprometidos para resistir el balanceo.","### Consejos para una forma adecuada","- Mantenga su núcleo apretado: evite el balanceo fortaleciendo sus abdominales y glúteos durante todo el movimiento.","- Alinee sus muñecas y codos: mantenga los codos en una trayectoria de 45 grados para proteger sus hombros.","- Mantenga la tensión corporal: Mantenga una línea recta desde la cabeza hasta los talones sin caer en las caderas.","- Encogerse de hombros: esto provoca una mala mecánica y tensión en los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('182c96de-c0de-4e80-babe-182c96de0000', 'Elevación unilateral', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/Single-Arm-Raise-Push-up.gif', '{"- Ponte en posición de flexión: comienza en una tabla alta con las manos debajo de los hombros, los pies un poco más anchos de lo habitual para mantener el equilibrio y el cuerpo en línea recta.","###","- Ensancha tus pies: una postura más amplia mejora el equilibrio durante el apoyo con un solo brazo.","- Involucre su núcleo: contraiga sus abdominales y glúteos para mantener una posición de tabla fuerte.","- Utilice movimientos controlados: evite movimientos bruscos al levantar la mano para mantener la estabilidad.","- Bájese: realice una flexión de brazos estándar, bajando el pecho hacia el suelo mientras mantiene los codos en un ángulo de 45 grados.","- Press Back Up: empuja con las palmas de las manos para volver a la parte superior del movimiento, manteniendo el core apretado.","- Levante un brazo: en la parte superior, levante una mano del suelo y extiéndala hacia adelante, hacia un lado o ligeramente por encima, según su nivel de habilidad.","- Mire un poco hacia adelante: mantener el cuello neutral favorece la alineación y la postura de la columna.","### Errores comunes","- Dejar que las caderas giren: Rotar o hundir las caderas reduce el desafío central y el entrenamiento de estabilidad.","- Encogerse de hombros: perder tensión en la cintura escapular durante la elevación puede provocar una mala alineación.","- Mantenga brevemente: haga una pausa de uno o dos segundos mientras mantiene el cuerpo rígido, luego regrese la mano al suelo y repita del otro lado.","### Consejos para una forma adecuada","- Mantenga su cuerpo cuadrado: evite rotar las caderas o los hombros durante la elevación del brazo.","- Arqueando la zona lumbar: mantenga el core comprometido para evitar la extensión lumbar.","- Levantar el brazo demasiado rápido: los levantamientos repentinos del brazo pueden desequilibrar y reducir el control.","- Trayectoria inconsistente del brazo: Levantar el brazo demasiado o en diferentes direcciones en cada repetición puede reducir la efectividad."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('69b35df5-c0de-4e80-babe-69b35df50000', 'Flexiones de pecho con mancuernas', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/Close-grip-Dumbbell-Push-Up.gif', '{"- Configure su mancuerna: coloque una mancuerna en posición vertical en el piso de modo que el mango quede vertical y sea fácil de agarrar con ambas manos. Una mancuerna hexagonal o de goma es lo mejor para la estabilidad.","- Agarre el mango: Sostenga el mango con ambas manos, apilándolas de forma segura alrededor del centro. Coloque sus pulgares alrededor de la parte superior para mayor control.","- Extiende a la posición de tabla: da un paso con los pies hacia atrás para que tu cuerpo forme una línea recta desde la cabeza hasta los talones, con los hombros apilados directamente sobre la mancuerna.","- Agarre seguro: envuelva sus manos firmemente alrededor del mango de la mancuerna para mayor estabilidad.","###","- Empuje hacia arriba: presione a través de la mancuerna para volver a la posición superior, extendiendo completamente los codos mientras mantiene estable la mancuerna.","- Utilice una mancuerna estable: elija una mancuerna con una base plana para evitar que ruede o se incline.","### Errores comunes","- Baje el cuerpo: doble los codos y manténgalos cerca de las costillas mientras baja el pecho hacia las manos. Mantenga su núcleo apretado para evitar hundirse.","- Elección de mancuernas inestables: el uso de mancuernas redondas aumenta el riesgo de vuelco.","- Ensanchar los codos: reduce la concentración del tríceps y tensa la articulación del hombro.","- Dejar caer las caderas: un control deficiente del núcleo puede provocar tensión en la espalda baja.","### Consejos para una forma adecuada","- Mantenga los codos cerca: mantenga una trayectoria estrecha para enfatizar los tríceps y proteger los hombros.","- Apoye su núcleo: contraiga sus abdominales y glúteos para evitar la flacidez de la cadera o el arco de la espalda.","- Muévete con control: baja y empuja con repeticiones lentas y controladas para una mejor activación muscular.","- Repeticiones parciales: no bajar completamente limita la participación de los músculos y el rango de movimiento.","- Acelerar el movimiento: las repeticiones rápidas pueden alterar la alineación y el control."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('51439c21-c0de-4e80-babe-51439c210000', 'Elevaciones frontales sentado con mancuernas', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/06/Dumbbell-Seated-Alternate-Front-Raises.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('46a2b08f-c0de-4e80-babe-46a2b08f0000', 'Curl de muñeca con barra', 'Antebrazos', 'https://fitnessprogramer.com/wp-content/uploads/2022/06/Barbell-Reverse-Wrist-Curl-Over-a-Bench.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1f8710eb-c0de-4e80-babe-1f8710eb0000', 'Ejercicio acostado', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/06/Side-Lying-Hip-Adduction.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('11fcf86b-c0de-4e80-babe-11fcf86b0000', 'Flexiones de pecho con balón medicinal', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/08/Single-Arm-Push-Up-on-Medicine-Ball.gif', '{"- Coloque un balón medicinal firme en el suelo y arrodíllese junto a él. Utilice una pelota antideslizante de tamaño mediano a grande como apoyo.","- Coloque una mano directamente encima de la pelota, con los dedos extendidos para agarrarla y la muñeca apilada debajo del hombro.","- Extiende ambas piernas hacia atrás formando una tabla. Coloque los pies ligeramente más anchos que el ancho de las caderas para mantener el equilibrio.","- Coloque el brazo que no trabaja detrás de la espalda, con la palma apoyada ligeramente en la parte baja de la espalda o en el glúteo opuesto.","- Empuja hacia arriba a través de la pelota para regresar a la posición superior sin dejar que tu cuerpo gire o gire.","###","- Baje el pecho lentamente, doblando solo el brazo que trabaja. Mantenga el codo metido hacia adentro y el cuerpo alineado desde la cabeza hasta el talón.","- Amplíe su postura: una base de apoyo más amplia ayuda a equilibrar la carga.","- Involucre todo su núcleo: evita que el torso gire o se hunda.","- Las caderas se tuercen o rotan: esto indica una pérdida de control central y movimiento compensatorio.","- Usar una pelota demasiado pequeña: una pelota pequeña o inestable hace que la preparación y la ejecución sean inseguras.","- Utilice un balón medicinal firme: los balones blandos o blandos aumentan la inestabilidad y el riesgo.","- Comience con elevación si es necesario: use una inclinación para reducir la carga durante las fases de aprendizaje.","### Errores comunes","- Ensanchar el codo: desplaza la tensión al hombro y disminuye la activación del tríceps.","### Consejos para una forma adecuada","- Bajar bajo control: Evite estrellarse; El descenso lento y uniforme fortalece.","- Profundidad inadecuada: no bajar completamente limita el compromiso y el alcance muscular.","- Depender del impulso: las sacudidas o los rebotes reducen el control y aumentan el riesgo de lesiones."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4cc0a82d-c0de-4e80-babe-4cc0a82d0000', 'Elevaciones laterales unilateral con mancuerna', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/06/Dumbbell-Single-Arm-Lateral-Raise.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('015ca13b-c0de-4e80-babe-015ca13b0000', 'Ejercicio', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/06/Side-Hip-Abduction.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('673e4314-c0de-4e80-babe-673e43140000', 'Remo con balón medicinal', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2023/09/Medicine-Ball-Overhead-Throw.gif', '{"Párese con los pies separados a la altura de los hombros, frente a una pared resistente o a un compañero.","Coloque el balón medicinal sobre su cabeza con los codos doblados hacia atrás.","Sostenga el balón medicinal con ambas manos, sujetándolo firmemente."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('36cc43d7-c0de-4e80-babe-36cc43d70000', 'Elevaciones laterales acostado', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/06/Side-Lying-Feet-Raise.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('778bb0fd-c0de-4e80-babe-778bb0fd0000', 'Ejercicio unilateral con balón medicinal', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2024/06/One-Arm-Medicine-Ball-Slam.gif', '{"Párese con los pies separados a la altura de los hombros y sostenga el balón medicinal con una mano por encima de la cabeza.","Coge el rebote y vuelve a la posición inicial.","Golpea el balón medicinal firmemente contra el suelo frente a ti.","Realice el ejercicio con ambos brazos para asegurar un desarrollo muscular equilibrado.","Asegúrese de que su torso permanezca erguido y evite inclinarse hacia atrás excesivamente."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2a55cfc1-c0de-4e80-babe-2a55cfc10000', 'Remo de pie con banda de resistencia', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Straight_Back-back-standing-row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('663d8861-c0de-4e80-babe-663d88610000', 'Postura de yoga', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Dhanurasana-Rocking-Bow-Pose.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('603bc0b6-c0de-4e80-babe-603bc0b60000', 'Peso muerto con banda de resistencia', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Single-stiff-leg-deadlift.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('680cb30e-c0de-4e80-babe-680cb30e0000', 'Giro ruso con banda de resistencia', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Twist-down-up.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('18fdbce6-c0de-4e80-babe-18fdbce60000', 'Giro ruso con banda de resistencia', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Twist.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('5a626d1b-c0de-4e80-babe-5a626d1b0000', 'Giro ruso sentado con banda de resistencia', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Seated-twist.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('26644798-c0de-4e80-babe-266447980000', 'Ejercicio con banda de resistencia', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Pull-through-Hips.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('674b8e4f-c0de-4e80-babe-674b8e4f0000', 'Ejercicio con banda de resistencia', 'Otros', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Rear-Drive.gif', '{"Adopte una posición cómoda y estable con la espalda recta.","Prepare la carga o resistencia de forma segura.","Active los músculos del core para mantener la estabilidad.","Realice el movimiento principal de forma controlada y con buena técnica.","Mantenga una contracción muscular en el punto de mayor esfuerzo.","Regrese lentamente a la posición inicial sintiendo el estiramiento.","Ajuste el peso de acuerdo a su capacidad física.","Consulte con un profesional si siente dolor o incomodidad excesiva."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('1bac19f9-c0de-4e80-babe-1bac19f90000', 'Press de pecho de pie con banda de resistencia', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Standing-incline-chest-press.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('33d3119e-c0de-4e80-babe-33d3119e0000', 'Ejercicio', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Swing-Gymstick.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
