INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('56303b38-c0de-4e80-babe-56303b380000', 'Extensión de piernas de pie con banda de resistencia', 'Piernas', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Standing-leg-extension.gif', '{"Colóquese en la máquina o posicione los pies a la anchura de las caderas.","Mantenga la espalda recta y el abdomen contraído.","Asegure que las rodillas estén alineadas con la punta de los pies.","Flexione las rodillas y caderas descendiendo el cuerpo de forma controlada.","Empuje con fuerza a través de los talones para volver a la posición inicial.","Evite hiperextender o bloquear las rodillas en el punto más alto.","Mantenga siempre el talón apoyado firmemente.","No permita que las rodillas colapsen hacia adentro."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('197a73bb-c0de-4e80-babe-197a73bb0000', 'Press de pecho', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Side-Bend-Press.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2d0c3370-c0de-4e80-babe-2d0c33700000', 'Remo unilateral', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Standing-Single-Arm-Upright-Row.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('76969f3b-c0de-4e80-babe-76969f3b0000', 'Extensión de tríceps de pie', 'Tríceps', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Standing-Triceps-Extension.gif', '{"Colóquese en la posición adecuada según la variante (de pie para polea, acostado para press francés o sentado).","Alinee las manos con la resistencia y mantenga el abdomen contraído para estabilizar el cuerpo.","Fije los codos cerca de la cabeza o de los costados del cuerpo.","Extienda completamente los codos empujando o presionando la resistencia de forma explosiva.","Sienta la contracción en la parte posterior del brazo al completar la extensión.","Regrese lentamente a la posición inicial flexionando los codos, sintiendo el estiramiento del tríceps.","No abra los codos hacia afuera durante el movimiento.","Evite utilizar el impulso del cuerpo o de los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('07904199-c0de-4e80-babe-079041990000', 'Elevación de piernas de pie con banda de resistencia', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Standing-Leg-Raise.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4c6b4f44-c0de-4e80-babe-4c6b4f440000', 'Extensión de piernas', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Single-Leg-Reverse-Hyperextension.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('43a9898d-c0de-4e80-babe-43a9898d0000', 'Ejercicio de pie con balón medicinal', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2023/08/Standing-Medicine-Ball-Chest-Pass.gif', '{"Párese con los pies separados a la altura de los hombros. Sostenga el balón medicinal con ambas manos al nivel del pecho, con los codos doblados y apuntando hacia afuera. Coloque el balón cerca de su pecho, manteniendo un agarre firme.","Coloque la pelota cerca de su pecho, manteniendo un agarre firme.","Repetir: Después de atrapar la pelota, restablece tu posición inicial y repite el movimiento durante el número deseado de repeticiones.","Configuración: Párese con los pies separados a la altura de los hombros. Sostenga el balón medicinal con ambas manos al nivel del pecho, con los codos doblados y apuntando hacia afuera. Coloque el balón cerca de su pecho, manteniendo un agarre firme.","Sostenga el balón medicinal con ambas manos a la altura del pecho, con los codos doblados y apuntando hacia afuera.","Ejecución: Comience fortaleciendo su núcleo y activando los músculos de la parte inferior del cuerpo. Empuje la pelota con fuerza lejos de su pecho usando ambas manos simultáneamente. Mientras extiende los brazos, extienda completamente los codos pero sin bloquearlos. El objetivo es soltar la pelota de una manera controlada, impulsándola hacia adelante explosivamente. Continúe con el movimiento de sus brazos y asegúrese de que sus muñecas permanezcan rectas durante todo el movimiento.","Empuja la pelota con fuerza lejos de tu pecho usando ambas manos simultáneamente.","Comience fortaleciendo su núcleo y activando los músculos de la parte inferior del cuerpo. Empuje la pelota con fuerza lejos de su pecho usando ambas manos simultáneamente. Mientras extiende los brazos, extienda completamente los codos pero sin bloquearlos. El objetivo es soltar la pelota de una manera controlada, impulsándola hacia adelante explosivamente. Continúe con el movimiento de sus brazos y asegúrese de que sus muñecas permanezcan rectas durante todo el movimiento.","Mientras extiende los brazos, extienda completamente los codos, pero no los bloquee.","El objetivo es soltar el balón de forma controlada, impulsándolo hacia adelante de forma explosiva.","Continúe con el movimiento de su brazo y asegúrese de que sus muñecas permanezcan rectas durante todo el movimiento.","Recepción: A medida que la pelota se aleja de usted, lleve rápidamente las manos hacia el pecho. Prepárese para atrapar la pelota mientras rebota hacia usted. Atrape la pelota antes de que toque el suelo, absorba el impacto doblando ligeramente los codos y flexionando los hombros.","A medida que la pelota se aleja de ti, rápidamente lleva las manos hacia el pecho.","Prepárate para atrapar la pelota mientras rebota hacia ti.","Atrapa la pelota antes de que toque el suelo, absorbe el impacto doblando ligeramente los codos y flexionando los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('4ebfb7b6-c0de-4e80-babe-4ebfb7b60000', 'Ejercicio de pie', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Standing-Side-Bend.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
