INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('26a0576e-c0de-4e80-babe-26a0576e0000', 'Giro ruso', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Down-to-Up-Twist-Gymstick.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('3cb381db-c0de-4e80-babe-3cb381db0000', 'Aperturas de pecho con banda de resistencia', 'Pecho', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/High-Chest-Fly-With-Resistance-Band.gif', '{"Túmbese en el banco (plano, inclinado o declinado) apoyando firmemente la espalda, cabeza y pies.","Sujete la barra o mancuernas con las manos separadas a un ancho ligeramente mayor que el de los hombros.","Retraiga las escápulas (junte los omóplatos) y mantenga el abdomen firme.","Descienda la carga de manera controlada hacia la parte media del pecho (esternón).","Empuje el peso hacia arriba de forma explosiva extendiendo los brazos sin llegar a bloquear los codos por completo.","Sienta la contracción en los pectorales al final del ascenso.","Mantenga los pies siempre apoyados en el suelo para mayor estabilidad.","No rebote la barra en el pecho al descender."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('464ad564-c0de-4e80-babe-464ad5640000', 'Remo inclinado', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Bent-Over-Row-Gymstick.gif', '{"Sujete el agarre (barra, mancuerna o polea) manteniendo una postura erguida.","Alinee las rodillas y mantenga la espalda con su curvatura natural.","Active el core y estabilice los hombros hacia abajo.","Tire de la resistencia hacia su cuerpo (abdomen o pecho) guiando el movimiento con los codos.","Junte los omóplatos al final del tirón y sostenga la contracción muscular un instante.","Extienda los brazos lentamente para regresar al punto de inicio.","Evite tironear con la espalda baja o balancear el torso.","Concéntrese en jalar con los dorsales y no únicamente con la fuerza de los brazos."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6a79f4c6-c0de-4e80-babe-6a79f4c60000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2022/05/Bicycle-Crunch-Gymstick.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7b470615-c0de-4e80-babe-7b4706150000', 'Ejercicio', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2015/07/The-Box-Jump.gif', '{"Colóquese en el equipo de cardio (cinta, elíptica, escaladora, etc.) o en una posición libre de pie.","Ajuste los parámetros del dispositivo o prepare su cronómetro.","Mantenga una postura erguida y la vista al frente.","Inicie el movimiento dinámico a un ritmo moderado para calentar.","Incremente la velocidad o resistencia según su plan de entrenamiento.","Mantenga una respiración rítmica y constante durante todo el tiempo de ejecución.","Mantenga la hidratación adecuada antes y durante la actividad.","Monitoree su frecuencia cardíaca para mantenerse en su zona de entrenamiento objetivo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('2b89773b-c0de-4e80-babe-2b89773b0000', 'Plancha', 'Abdomen', 'https://fitnessprogramer.com/wp-content/uploads/2015/06/Plank-Jacks-Extended-Leg.gif', '{"Recuéstese sobre la colchoneta o colóquese en suspensión.","Fije la zona lumbar contra el suelo o estabilice la cadera.","Coloque las manos suavemente al lado de la cabeza o mantenga los brazos estirados.","Contraiga el abdomen elevando los hombros o las piernas de manera controlada.","Exhale completamente durante la máxima contracción abdominal.","Regrese lentamente a la posición inicial manteniendo la tensión en el core.","No tire del cuello con las manos.","Concéntrese en la flexión de la columna y no de la cadera."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('0c85457a-c0de-4e80-babe-0c85457a0000', 'Ejercicio', 'Hombros', 'https://fitnessprogramer.com/wp-content/uploads/2015/07/Battle-Rope.gif', '{"Sujete las mancuernas, barra o polea manteniendo una posición erguida y estable.","Active el core para proteger la espalda baja.","Mantenga los codos en un ángulo seguro (plano escapular).","Eleve el peso de manera controlada (hacia el frente, los lados o arriba según el ejercicio).","Llegue al punto máximo del recorrido de forma controlada.","Descienda lentamente manteniendo la tensión en los deltoides.","No encoja los hombros hacia las orejas durante la elevación.","Utilice un peso que le permita controlar la bajada sin balanceo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7dee5e41-c0de-4e80-babe-7dee5e410000', 'Cinta de correr / Caminadora', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/06/Treadmill.gif', '{"Súbase a la cinta de correr apoyando los pies en los rieles laterales.","Sujete la llave de seguridad e insértela en el panel de control y engánchela en su ropa.","Seleccione el programa de entrenamiento o la velocidad inicial.","Comience a caminar a un ritmo lento para calentar los músculos.","Incremente gradualmente la velocidad hasta trotar o correr según su nivel.","Mantenga una zancada natural y los hombros relajados.","Evite mirar constantemente a sus pies para no perder el equilibrio.","Mantenga el cuerpo hidratado durante sesiones largas."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('6af1e495-c0de-4e80-babe-6af1e4950000', 'Máquina escaladora / Escaladora', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/08/Stairmaster.gif', '{"Súbase a los pedales de la máquina escaladora sujetándose de las barras de soporte.","Configure el nivel de velocidad o resistencia deseado.","Mantenga la espalda recta y el abdomen contraído.","Comience a dar pasos de forma constante, empujando los pedales hacia abajo.","Mantenga un ritmo constante que eleve su frecuencia cardíaca.","Apoye el pie completo en cada escalón para distribuir bien la carga.","Evite recargarse excesivamente sobre los pasamanos laterales.","Mantenga una postura erguida durante todo el ejercicio."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('068526a1-c0de-4e80-babe-068526a10000', 'Bici elíptica', 'Cardio', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Elliptical-Trainer.gif', '{"Súbase a los pedales de la elíptica y sujete los brazos móviles.","Mantenga la vista al frente y la espalda recta.","Inicie el pedaleo suavemente para encender la consola.","Empuje los pedales de manera elíptica moviendo los brazos en sincronía.","Mantenga la fuerza repartida entre el empuje de las piernas y el jalón de los brazos.","Aumente la resistencia o inclinación para mayor esfuerzo.","No despegue los talones de los pedales para evitar sobrecargar las pantorrillas.","Mantenga los hombros relajados."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('33424340-c0de-4e80-babe-334243400000', 'Bicicleta estática', 'Cardio', '', '{"Ajuste el sillín de la bicicleta a la altura de su cadera.","Siéntese en el sillín y coloque los pies en los pedales, asegurando las correas.","Sujete el manillar manteniendo la espalda ligeramente inclinada y el abdomen firme.","Comience a pedalear de forma constante sintiendo la resistencia adecuada.","Mantenga una respiración rítmica y evite rebotar en el asiento.","Incremente la resistencia o realice intervalos de velocidad.","Mantenga las rodillas apuntando hacia el frente en todo momento.","No extienda completamente las piernas en la parte más baja del pedaleo."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;
INSERT INTO public.exercises (id, name, category, gif_url, tips, is_custom, user_id) VALUES ('7adc0122-c0de-4e80-babe-7adc01220000', 'Pullover en polea alta', 'Espalda', 'https://fitnessprogramer.com/wp-content/uploads/2021/04/Straight-Arm-Pulldown.gif', '{"Coloque una barra recta o cuerda en la polea alta.","Sujete el agarre con las palmas mirando hacia abajo, dé un paso atrás y flexione levemente las caderas.","Mantenga los brazos casi estirados (codos con flexión mínima) y el torso inclinado hacia adelante.","Tire de la barra hacia abajo hacia sus muslos describiendo un arco, contrayendo fuertemente los dorsales.","Mantenga los brazos firmes y use la fuerza de la espalda para mover el peso.","Regrese lentamente al punto de inicio permitiendo que la polea estire los dorsales por completo.","Evite flexionar y extender los codos para no involucrar al tríceps.","Mantenga la espalda recta y no encoja los hombros."}'::text[], false, null) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, gif_url = EXCLUDED.gif_url, tips = EXCLUDED.tips;